insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-01-18','TERESA FENIA DEPENDENCIA, S.C. J-06605703 616-91 70 82 COMIENZA A PRESTAR EL SERVICIO DESDE EL 1 DE ENERO FENIA (FELISA) 616917082','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2023-01-18','-Amalia : escribo email a Carla ,TS de Ctro penitenciario retomando el tema del traslado que ya se trató con Beatriz. Buenos días , este asunto lo estuve viendo con tu compañera Beatriz . Por nuestra parte hice la consulta a dependencia y me indicaron que para poder solicitar traslado de expediente , se especifica en el modelo que tiene que tener un domicilio de forma permanente en la Comunidad de traslado. En este caso José no tiene domicilio de forma permanente en Extremadura , puesto que lleva años en Ctros. Penitenciarios y su última residencia fue Andalucía que es donde se le valoró por dependencia. No tengo ningún tf. de dependencia en Andalucía que sería donde te podrían aclarar algo más , quizás por internet puedas encontrar algún email. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2023-01-18','-Amalia : escribo email a Carla ,TS de Ctro penitenciario retomando el tema del traslado que ya se trató con Beatriz. Buenos días , este asunto lo estuve viendo con tu compañera Beatriz . Por nuestra parte hice la consulta a dependencia y me indicaron que para poder solicitar traslado de expediente , se especifica en el modelo que tiene que tener un domicilio de forma permanente en la Comunidad de traslado. En este caso José no tiene domicilio de forma permanente en Extremadura , puesto que lleva años en Ctros. Penitenciarios y su última residencia fue Andalucía que es donde se le valoró por dependencia. No tengo ningún tf. de dependencia en Andalucía que sería donde te podrían aclarar algo más , quizás por internet puedas encontrar algún email. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-01-18','Amalia : escribo a Rosa y a ctutelar: Buenos días Rosa , estamos recibiendo tus email con diversas peticiones económicas. Sentimos decirte que hasta que no se regularice todo lo relacionado con herencias y cuentas en común que tienes con Blas no podemos autorizar nada . No sabemos con qué dinero podrías contar . Estamos en contacto con tus hijos que se están encargando de esas gestiones. Por lo tanto , hay que esperar a que esté todo zanjado y podremos hacer un nuevo presupuesto . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-01-18','Amalia : escribo a Rosa y a ctutelar: Buenos días Rosa , estamos recibiendo tus email con diversas peticiones económicas. Sentimos decirte que hasta que no se regularice todo lo relacionado con herencias y cuentas en común que tienes con Blas no podemos autorizar nada . No sabemos con qué dinero podrías contar . Estamos en contacto con tus hijos que se están encargando de esas gestiones. Por lo tanto , hay que esperar a que esté todo zanjado y podremos hacer un nuevo presupuesto . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2023-01-18','e: MARIA LUZ ROMERO FURONES >marialuz.romerof@salud-juntaex.es> Enviado el: martes, 17 de enero de 2023 8:39 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: COMUNICACIÓN DE FUGA DE PACIENTE Por la presente comunicamos que el paciente Miguel Gamero Gómez se fugó el día de ayer de este Centro Sociosanitario de Mérida, desde las 6 hasta las 7 y media de la tarde, tras realizar previa comunicación vía telefónica a Policia Nacional y Policía Local. Para que conste y surta los efectos oportunos. Un atento saludo. María Luz Romero Furones Médico Somático Centro Socio Sanitario de Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2023-01-18','TERESA Informamos que la tutelada Carmen Asensio García será ingresada el día 23 de Enero por la tarde en el Hospital Universitario de Badajoz para ser intervenida de cateterismo. Estará acompañada por una cuidadora de confianza dedicada a los acompañamiento hospitalario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2022-11-17','miguel, envío email al notario de Coria: Buenos días, necesitaría confirmar si ha recibido el email y si está correcto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2022-12-20','miguel, envío email al notario de Coria: Buenos días, seguimos a la espera que nos confirmen si podemos acercarnos a firmar la ratificación. Por favor, indíquenos que documentación necesitan y si es posible denos cita antes de que finalice el año.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2022-11-17','miguel, contestación del notario de Coria: Buenas tardes, Miguel. Disculpe no haberle respondido, debí, al menos, acusar recibo. Es mucha documentación y voy poco a poco, tomando nota según avanzo, déjeme unos días más y le respondo con todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-01-18','En mi humilde opinión lo más urgente que hacer ahora mismo es el tema de la herencia de Blas a mi madre, por varios aspectos a tener en cuenta: 1- por el crédito que ellos dos pidieron a nombre de Blas en CaixaBank y de los que quedan por pagar 5000€, hasta que no lo "herede" no vamos a saber en qué situación está eso realmente. 2- porque el coche no va a poder pasar a mi madre hasta que sea heredado por ella, pues está a nombre de Blas 3- porque se ha solicitado una prórroga para gestionar la herencia so pena de que si a 31 de Marzo no se finalizan los trámites, probablemente multen a mi madre desde Hacienda (o algo así le ha comentado el abogado). Finalmente creo que estos temas con costes menores tales como la gestión de los duplicados de la documentación del vehículo podrían salir de los 45€ semanales que se le da a ella, ahora que no tiene más gastos que los personales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-01-18','miguel, recibo email de la abogada Rocio Gracian: Buenos días Miguel, Me confirman en el Juzgado que NO admiten video conferencia, por lo que Damián se tiene que desplazar a Málaga para declarar. Te estoy llamando al mòvil que me facilitaste pero está apagado. Por favor, llámame en cuanto puedas porque quiero comentarte algo importante de cara al juicio. *************************************************** Envío email a la parte social y a la económica: Buenos días, conforme veréis en el email de debajo necesito me confirméis si hay dinero y si alguien puede acompañar a Damian a juicio en Málaga el 2-2-23. La abogada no ha logrado que el juzgado acepte la videoconferencia conforme podéis leer en el email de debajo. Decidme algo entre hoy y mañana para comunicarlo a la abogada. ****************************************************** Hablo con la abogada Rocio Gracián y traslado la conversación vía email a la parte social y económica: Hola, en relación al procedimiento de desahucio del lunes que viene en Málaga: Acabo de hablar con la abogada Rocío Gracián. Me confirma que ayer tuvo una reunión por videoconferencia con Damian y el David?, el director del Centro… Parece ser que Damian ha mantenido conversaciones con los inquilinos, pero las ha borrado, llamadas y wasap…no se sabe quién miente y quién dice la verdad. Hay dos audios en el tlfno de Damian donde se acusan mutuamente de deberse dinero, no queda claro, cuánto, causa de la deuda, quién a quién, desde cuándo... Le dijo a la abogada hace pocos días que por error telefoneó al inquilino y le colgó y éste le llamó pero él no se lo cogió y que estaba muy nervioso. Decía que iba a borrar el teléfono para que no le volviese a suceder. En definitiva, que el juicio es el lunes día 23-2-23 y que ya ha hablado ella con Damian, y éste ponía excusas, tipo le duele algo o está nervioso o no quiere ir. Su prima Alicia se ha comprometido, según dice la abogada a recogerle en la estación de autobuses de Málaga el lunes. En principio no se dice que tenga que asistir la Ctaex. Problema que hay: desde el confinamiento del Covid en 2020 el Gobierno ha Decretado la prohibición de desahucio en alquileres que constituyan residencia habitual, cuando haya escasez de rentas como es este caso. La última renovación de la prohibición de desahucio por el Gobierno es de diciembre de 2022 por lo que hasta el 30-6-2023 sigue vigente. Y en este caso los inquilinos eran matrimonio (hoy separados y el exmarido que pagaba el alquiler ya no vive allí, sólo ella con su madre (la cual quiere hacer un nuevo contrato de alquiler con Damian, y que como sabéis con la nueva ley los alquileres son ya de 5 años) La propuesta que va a hacer la abogada es como van a ser insolventes, es llegar a un acuerdo (si Damian consiente) consistente en que en junio de 2023 la inquilina, sus hijos y la madre de ella, abandonen voluntariamente la vivienda y a cambio no paguen nada. No obstante es muy probable que les interese más no aceptar ese acuerdo ya que habría que interponer nueva demanda de procedimiento de desahucio, aplicable a partir de junio, con lo que alargarían más meses su alquiler sin pagar nada, porque se declararan casi con seguridad insolventes. En conclusión: que Damian vaya en el bus (no creo que necesite acompañante, rectifico de email anterior) y como digo al llegar a Málaga le esperará su prima Alicia. El juicio no pinta bien porque Damián cambia de opinión como sabemos continuamente, por lo que ya le he dicho que aproveche cuando esté allí Damian para que le haga un nuevo poder apud acta para cuando tenga que interponer nuevo procedimiento de desahucio, y vuelta a empezar… ******************************************** contestación de Amalia: Buenos días , con respecto al acompañamiento no creo que haya nadie que se pueda ir a Málaga . Ni Damián tiene ninguna discapacidad para que necesite ser acompañado. ****************************************************** contestación de Oscar: Económicamente puede disponer de dinero si lo necesitara para un acompañamiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-01-18','miguel, me llama por teléfono el abogado de la otra parte, Rafael Santos 924-242814, y le explico que estoy pendiente de confirmación por la notaria. Me comenta que llamará de nuevo para decirselo a la notaria de Coria. Envío nuevo email al notario de la notaria de Coria: Buenas tardes, necesitamos ratificar lo antes posible la herencia mencionada en emails anteriores. Si es tan amable necesitamos si lo ve todo correcto nos indique día y hora para ir a ratificar y qué documentos originales hay que aportar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2023-01-18','miguel, hablo por tlfno con la notaria de Herrera del Duque y me comenta Sergio que hoy nos envían la factura para abonarla y posterior envío de la declaración de herederos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-01-18','Ana: Envío correo a Alberto y Óscar, secc. ecca.: "En relación a JUAN GREGORIO LOZANO VALLE, he recibido llamada de la Beatriz Pavón, Directora de la Residencia de Garrovillas de Alconétar, preguntando cómo se abonará la mensualidad del mes pasado. Como sabéis, en el banco habían bloqueado la cuenta nueva y el ingreso de la pensión lo derivaron directamente a la cuenta antigua, de la que el hijo volvió a sustraer el dinero, generándole deuda de la primera mensualidad de la plaza residencial (el recibo lo ha sido devuelto por no haber dinero en la cuenta nueva). Ya le dije que cuando comience a sanearse se le haría una propuesta de abonos periódico para ir saldando la deuda (770€/mes), pero ya pregunta cuándo comenzará a pagarse y en qué cuantías mensuales… ¿Podríais hacerle una propuesta, una vez hayáis podido hacer cuentas al respecto? El teléfono de Beatriz es: 619 55 31 89 y su correo: beapavonguerra@hotmail.com Por otra parte, dice que va a pasar otros gastos relativos a: Etiquetado de ropa, podología y peluquería, con un coste total de algo más de 47€ (no llega a 48€). Os informo también, para que podáis añadir a vuestros cálculos en ficha, los costes de peluquería, que son 5€ y de podología 10€. No sabemos exactamente aún con que periodicidad lo necesitará, pero en otros casos son meses alternos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2023-01-18','Ha fallecido la abuela de Daniel Montaño.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-01-20','Ana: Tras hablar con Gema, Directora Res. Municipal de Cedillo - Grupo Asoma (639694905), e intercambiar correos con Toni-Futuez. Acordamos finalmente que Gloria, cuando le cuadre en agenda, acompañe en taxi a Ramón a retirar su asignación y de vuelta al centro. *El taxi se abonará mediante transferencia desde aquí para que le cunda más el efectivo y haga los menos viajes posible a su pueblo." ······························································································································································································· En relación a la reparación de la cubierta del edificio, Miguel, A. Jurídico CTAEX, escribe: "...La semana que viene lo hablamos con su exmujer y ponemos en marcha el arreglo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-01-20','Ana: Llamo a Pilar Martín, TS ESM-CC (54612) para preguntar cuándo tiene la próxima cita Joaquina e intentar adelantarla por los signos de posible descompensación, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-01-19','Ana: Correo de Miguel, A. Jurídico CTAEX, de ayer: ", necesito me indiquéis, si llegado el caso de que le condenen, si es posible permutar la pena por cumplimiento de internamiento en un centro concreto. Como sabéis no ha acudido a las citaciones con el forense y la abogada como veréis indica que tampoco ha logrado contactar con él… El primer documento adjunto es la citación para el 2-2-23, los demás es internamiento involuntario solicitado al nº6 CC, que es dónde se está conociendo del supuesto delito de agresión sexual. Y los otros dos son la comunicación de amparo que hicimos a nuestro juzgado (al que rendimos cuentas anuales y comunicaciones, el jzdo nº2 CC) y la apertura de procedimiento de internamiento involuntario iniciado por el jzdo nº2 CC… Ambos procedimientos de agresión sexual del jzdo nº6 CC, donde se instruyó (actualmente en la Audiencia Provincial, donde va a ser resuelto) y el procedimiento de internamiento involuntario del juzgado nº 2 CC (donde no se ha presentado en reiteradas ocasiones a las citaciones del forense)" ··························· Mi respuesta: "En su día, se solicitó desde aquí el internamiento no voluntario en centro adecuado. Dado el perfil de Saturnino, y en base a su estado en dicha fecha, el único centro adecuado era el C. Sociosanitario. ····· No obstante, a día de hoy, si no hay descompensación psicopatológica, no tiene demasiado sentido solicitar que ingrese en este tipo de plazas que además pueden ser necesarias para otra personas. En todo caso, si finalmente tuviera que cumplir condena, podría proponerse el C. Psiquiátrico Penitenciario de Sevilla, pues en Extremadura no existe ninguno de estas características."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-01-19','TERESA actitud verbalmente violenta con la compañera, y estamos limitando el contacto de forma preventiva, y por otro lado está la incompetencia absoluta (por no llamarlo de otro modo) de su trabajador social, que parece no entender bien la función que tiene el y la que tiene la comisión. Pero lo llamaremos para que le pueda comunicar esto de los reintegros a Tomás, te explico ahora y detallo, estas circunstancias que han acontecido los ultimos dias. Hace unos dias, se ha recibido una llamada de Tomás insultándonos y amenazas de muerte y circunstancias que son muy graves, también reclama que le devolvamos su dinero. Se ha preguntado quién era (aunque sabíamos que era él) y no ha contestado, simplemente ha seguido amenazando e insultando. Acto seguido ha colgado el teléfono. Se ha llamado al TS, Jesús Carramiñana, para ponerlo en su conocimiento, le ha sorprendido esta actitud de Tomás hacia nosotros, aunque comenta que no considera que llegue a ser peligroso. Jesús asegura que ha hablado con la Comisión y le han dicho que van a llevar el caso de Tomás a los juzgados para un ingreso involuntario. Se sospecha que Jesús ha sido la persona que ha facilitado nuestro número de teléfono a Tomás, ya que nosotros no se lo hemos facilitado en nigún momento al usuario y es la única persona con quien Tomás tiene contacto y relación. Además, a nosotros en ningún momento se nos ha facilitado el número de Tomás, primero porque supuestamente Tomás no tenía teléfono y después porque supuestamente Tomás nunca lo atiende porque suele tenerlo apagado. Dadas las circunstancias, consideramos que lo mejor es tomar distancia con el caso de Tomás por el momento. Así se le ha comunicado a Jesús. Esta información se pondrá en conocimiento de la Policía Local de Zafra, sumando la información de las intervenciones que hemos podido realizar hasta ahora, para que tengan conocimiento, ya que, además los propios vecinos se quejan continuamente de este tipo de conductas anticívicas y agresivas de Tomás. El viernes se recibe una llamada del Ayuntamiento de Zafra con respecto a Tomás Carvajal. La persona al teléfono comenta que Jesús Carramiñana (TS) ha facilitado nuestro teléfono porque, según él afirma, somos los tutores de Tomás y nos piden responsabilidades por ello. Se le explica a esta persona que eso no es así, que nosotros hacemos el seguimiento a los tutelados de la Comisión a través de un convenio, pero que ni siquiera pertenecemos a la misma y mucho menos somos los tutores de Tomás a nivel personal. Esta persona se disculpa y comenta que Jesús les había dado esta información pero que entienden que es él quién debe trabajar con Tomás como su TS. Además le explicamos que, debido a que se han recibido amenazas vía telefónica de Tomás, por el momento se va a tomar cierta distancia con este caso, de modo preventivo. Se le explica que si necesitan cualquier cosa a nivel administrativo, se pongan e contacto directo con la Comisión en los teléfonos que aparecen en la web de la misma, pero que ya se está trabajando con el caso, en lo relativo a los ingrsos que puede retirar, y que sabemos que Jesús ha contactado con la misma en más de una ocasión vía email, y que tenemos constancia de ello porque él mismo nos lo ha dicho. Esta persona asegura que no tenia conocimiento de ello. Como te comento, ya no es solo lo complejo que puede llegar a ser este caso, tanto a nivel social como a nivel sanitario, sino que es hay muy poca colaboración con su ts que es la unica persona que es digamos su referencia, o la colaboración no es eficaz,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-01-19','Ana: Tras llamar a Paco Ortés, Empresas Ortés (638 712 004): Envío correo a los A. Jurídicos - CTAEX: "En relación a JULIÁN RAMÓN CIVANTOS FERNÁNDEZ, si recordáis, estaba pendiente una obra en la cubierta del edificio en que vive, cuyo coste se debía asumir por parte de la Comunidad de Propietarios. En su día, me comuniqué varias veces con Paco, el albañil y empresario que iba a encargarse, Construcciones Ortés (638 712 004), y que estaba en contacto con el resto de propietarios y el ayuntamiento para los permisos necesarios. Como podéis leer en la Intranet, a fecha de 26/05/20, Paco me dijo que “que en cuanto finalice otra obra que está realizando en otro sitio arreglarán la cubierta del edificio. Ya ha hablado con dos de los dueños (uno de ellos es el arquitecto) y están de acuerdo.” Pero ni las obras se llevaron a cabo ni hemos vuelto a saber nada… Tras varios intentos, hasta hoy no he conseguido volver a hablar con él, y me dice que hay un propietario que se niega a pagar y por eso no se hizo. *Dice que habló con uno de vosotros (Ángel o Miguel) al respecto en su día. No sé si llegasteis a contactar con alguien o emprender alguna acción, no lo pongo en pie. La cuestión es, ¿qué requerimiento o acciones legales podemos emprender desde aquí, para que la Comunidad de Propietarios se haga cargo de estas reparaciones que afectan directamente a su vivienda y sin las cuáles ha vuelto a tener que salir de su casa e ingresar en centro residencial por riesgo de derrumbe e importantes goteras? Ya es la segunda vez, cuando el problema de origen está en la cubierta del edificio, no en su casa en sí. Decidme cuando podáis, y si lo consideráis, nos reunimos." ······························································································································································································· Correo de Ángel, A. Jurídico: "Si los daños tienen su origen en la cubierta del edificio, se trata de un elemento común que afecta a todos los propietarios, su reparación es obligatoria, no siendo ni siquiera necesario el consentimiento de los mismos para llevar a cabo los trabajos necesarios para repararla. En cuanto a los daños sufridos en la vivienda de Julián, si los mismos han sido producidos por la cubierta, la reparación corresponde a la comunidad de propietarios, él incluido, conforme a su cuota de participación del edificio"','2');
