insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-01-19','TERESA Me han llamado de Unicaja. Se están planteando cerrarle la cuenta ya que les insulta cada vez que va. Le he convencido de que aguanten un poco con el tema de la tarjeta. Se la voy a solicitar, a ver si da resultado. En cuanto esté, tendrá que ir la trabajadora social con él a recogerla (o Futuex).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANO'and apellido2='ARROYO'),'2023-01-19','TERESA ENVIO POR REGISTRO PIA VINCULADA DE RESIDENCIA Y PRESTACION DE SERVICIO ENVIO CAMBIO DE PENSION AL INSS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-01-19','TERESA sigue insistente diciendo "preparme los papeles que me voy", "que tiene poco dinero" "que alli no hay dinero" la visita le vino bien, hablaron con la policia para que le tranquilizara al respecto de su casa, pero no obstante está muy insistente. No entiende que no hay mas dinero, que le dan 1.50 eu diarios, pero al parecer le parece poco. En frente del centro hay un bar, esto es un punto negativo, aunque no le dan alcohol. Ya no participa practicamente en ningun taller y solo quiere irse. No saben desde el centro el tiempo que aguantará, que creen que va a ser dificil convencerlo y que aguante tiempo tranquilo. Nosotros habiamos pensado verlo ahora de una forma mas intensa, e ir cada dos semanas o cosa asi, esperemos que no decida marcharse. Por esto, quiza no es el mejor momento para sacarle el tema de la casa, y que si decide irse, hay que contar con un plan B, que mientras no haya un ingreso involuntario, tendria que ser volver a la casa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-12-12','TERESA está muy complicada la situación no solo por las conductas de Marta, sino por la familia de su pareja. Alomejor todas estas circunstancias, redundan en comenzar a valorar la posibilidad de solicitar un internamiento judicial para ella, porque al final está en una situación social, vulnerable. Exponemos lo averiguado en ese seguimiento, para vuestra valoracion;: En el encuentro con María en Peñalsordo, nos expone la conversación que mantuvo con Felisa (suegra de Marta) en la que expresaba su malestar por ciertas conductas de Marta: salidas a horas poco frecuentes de la vivienda en la que reside con su pareja, para verse con un chico de Cabeza del buey que ahora reside en Peñalsordo y trabaja en una carnicería del mismo pueblo. Toda la situación es algo complicada, según las versiones de cada uno: Felisa, su hijo (pareja de Marta) y la propia Marta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2023-01-19','Ana: Remito correo a Ana Arrufat Rosset, Enfermera de la Casa Familiar Virgen de la Montaña (enfermeriacf-caceres@cruzblanca.org): "Adjunto remito las solicitudes para incorporación en el Programa para pacientes con necesidades asistenciales especiales, relativas a: - Alberto Molano Iglesias - Alejandro Montero Vázquez - Antonio Tejada Fernández Firmados digitalmente por el Presidente de la CTAEX"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2023-01-19','na: Remito correo a Ana Arrufat Rosset, Enfermera de la Casa Familiar Virgen de la Montaña (enfermeriacf-caceres@cruzblanca.org): "Adjunto remito las solicitudes para incorporación en el Programa para pacientes con necesidades asistenciales especiales, relativas a: - Alberto Molano Iglesias - Alejandro Montero Vázquez - Antonio Tejada Fernández Firmados digitalmente por el Presidente de la CTAEX"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-01-19','na: Remito correo a Ana Arrufat Rosset, Enfermera de la Casa Familiar Virgen de la Montaña (enfermeriacf-caceres@cruzblanca.org): "Adjunto remito las solicitudes para incorporación en el Programa para pacientes con necesidades asistenciales especiales, relativas a: - Alberto Molano Iglesias - Alejandro Montero Vázquez - Antonio Tejada Fernández Firmados digitalmente por el Presidente de la CTAEX"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-01-19','Ana: Correo de Estrella Durán, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es): comunica que Mª Montaña YA HA INGRESADO en el CSS. Y solicita información y documentos. ··············· Mi respuesta: "Adjunto: - Testimonio de Sentencia y nombramiento - Testimonio de la firmeza del mismo - Testimonio de aceptación del cargo - Informe social del IMAS (En éste, básicamente hace mención a lo que la propia Montaña relata… no creo que te sirva de mucho, yo me quedé más/menos igual…) La vivienda a la que hace mención la TS en el informe, la tiene en propiedad (100% suya), no en alquiler. Percibe una PNC, cuyo importe este año ascenderá a 484,61 €. No contamos con Certificado de PNC, sólo hemos podido consultarlo y contrastar con los movimientos bancarios. Por cierto, de esta PNC le retienen todo los meses 100€ en concepto de manutención por maternidad. Sus cuentas a fecha de inventario estaban mal, tenía 3 abiertas, dos de ellas en negativo y la otra con un saldo de 118€. Te adjunto también: - Certificado del Catastro De momento no disponemos de más información. Si vosotras averiguáis más cositas, ya nos vais diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-01-19','Ana: Correo de Icíar, secc. ecca.: "Te cuento, he hablado con la compañía que suministra el agua en la casa de Alcuescar y tiene todos los recibos del año pasado sin pagar, la deuda es de 249,10 €, ya le he dicho a la chica que no sé cuándo lo vamos a poder abonar, pero, claro, hasta entonces no se cursa la baja del suministro. En Unicaja me han dicho que, probablemente, la semana próxima estará desbloqueada la nueva cuenta para que le pueda entrar la pensión"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-01-19','Amalia : Hablo con Sandra ( 924241414) , le han cogido hachís en el centro para venta y consumo. Lo van a expulsar unos días y solicita extra para hostal. Le explico que sólo intervenimos en la esfera económica con él a espera de la revisión de sentencia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-01-19','miguel, contestación de Angel a la parte social: Buenos días, compis, Si los daños tienen su origen en la cubierta del edificio, se trata de un elemento común que afecta a todos los propietarios, su reparación es obligatoria, no siendo ni siquiera necesario el consentimiento de los mismos para llevar a cabo los trabajos necesarios para repararla. En cuanto a los daños sufridos en la vivienda de Julián, si los mismos han sido producidos por la cubierta, la reparación corresponde a la comunidad de propietarios, él incluido, conforme a su cuota de participación del edificio . Algún vecino realiza las funciones de administrador de la finca? Puedes facilitarme teléfonos de los vecinos? Conmigo no hablaron de este caso. ******************************************************* miguel, contesto a la parte social y a Angel: Buenos días, recuerdo que no tenían constituida comunidad de propietarios y que tras pedir a futuex la identificación y contacto de los vecinos, dicha información, que yo sepa nunca la remitieron. Por otro lado con el único que llegué a hablar una vez fue el tal Paco Ortes, quien no me concretó nada y dio ya largas en aquel verano del 2021. No entiendo por otro lado que siempre haya 2 o 3 presupuestos y aquí sólo sea uno y de un profesional que el tiempo ha demostrado que no responde. Si queréis nos reunimos y vemos qué se puede hacer. Adjunto lo único que sé de este asunto y que tengo subido a la intranet: 1-7-21: Con respecto a la segunda cuestión en relación al arreglo de la vivienda, veo en los antecedentes y la respuesta que se le dio al juzgado (cuando nos requirió para informásemos acerca del estado de salud del tutelado) que se lleva arreglando su vivienda al menos desde el 2019…por lo que indica Futuex parece que es la cubierta del edificio lo que esta mal…Si es un elemento común al edificio el arreglo corresponde a la comunidad de vecinos que independientemente de haberse constituido tienen que arreglarla y pagarla según la cuota de participación que tengan en el edificio, lo cual pueden comprobarlo en nota simple (finca matriz del registro de la propiedad) o bien en la escritura de división horizontal…Dicha documentación debe tenerla el presidente o la asesoría… En esta cuestión no entramos porque nosotros al representar únicamente al tutelado sólo nos encargaremos de abonar previo presupuesto el importe que a él le corresponda. Dependerá del importe que cueste el arreglo que al tutelado corresponda, el que tengamos que solicitar al juzgado o no los gastos extraordinarios… 2-7-21:Envío email a Tony de Futuex: 2.-En cuanto a la vivienda: necesito nos remitáis información de quién ejerce en el edificio funciones de presidente (pagos y contratación de limpieza del edificio, etc) Caso de que nadie realice dichas funciones, necesitaremos identificación de cada propietarios del edificio para ponerlo en manos de un abogado. Asimismo necesitamos actualización del presupuesto de arreglos. Cualquier duda nos dices a Ana y a mí. 16-7-21: llega presupuesto de la obra. Quedo a la espera que Toni de Futuex nos remita quién es el presidente de la Comunidad o a quién dirigirnos para que hagan la obra. 5-8-21: Tal y como se solicitó, se ha intentado investigar y recabar datos sobre los propietarios del bloque de Ramón Civantos, se creyó que lo más oportuno sería hacerlo a través del registro de la propiedad, por lo que se acudió, en compañía del tutelado, a solicitar nota simple de cada vivienda y así conocer a nombre de quién figura cada vivienda; se adjunta (en documento a parte) toda la información conseguida. 6-8-21: mi contestación a Toni (Futuex), Ana Ts, y Alberto: 2.-Desperfectos en el tejado del edificio de la vivienda donde reside el tutelado. Corre prisa el arreglo de la misma. Es necesario identificar a todos los vecinos (sólo nos remites la nota simple de los del bajo derecha). No necesitamos notas simples, únicamente los nombres y apellidos de cada vecino y con qué vivienda se corresponden. He intentado hablar de nuevo sin éxito con Paco Ortes (la empresa que hará la reforma), lo seguiré intentando. Él quedó también en hablar con los vecinos y darles el mes de julio de plazo para que nos dijeran si iban o no a arreglar el tejado. Aunque decían que no podían arreglarlo hasta que no se constituyeran en comunidad, ya le dije yo que eso no es necesario porque la cuota de participación de cada vecino en cuanto a los gastos que tendrán que soportar para el arreglo del tejado viene reflejada en el nº de finca registral de la finca matriz (también pueden verlo en la escritura de división horizontal de cuando se dividió por viviendas el bloque). En definitiva que por favor Toni, indicadnos lo antes posible (ya que este tutelado vive en condiciones insalubres en esa vivienda) quiénes son el resto de vecinos. Por nuestra parte, si a Paco Ortes no le han confirmado que asumen la deuda el resto de vecinos y comienzan los arreglos, procederemos a nombrarle un abogado para que interponga la correspondiente demanda en el juzgado (para lo cual nos pedirán identificar pisos y vecinos propietarios del mismo, siendo esta la información que Toni y no sé si Paco Ortes nos deberán facilitar). 7-9-21: llega email de Toni para Ana y para mi: Buenas de nuevo, se adjunta también documentación requerida por el area juridica de la comisión: En cuanto a la vivienda, a continuación, se detallan los datos de los propietarios del resto de viviendas del bloque, que si se encontraban detallados en las notas simples facilitadas por el registro de la propiedad. En la nota adjunta se detalla pormenorizdamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-01-19','-Amalia , desde ESM se le va a solicitar derivación a CRR . Adjunto email de Futuex : Desde el programa de apoyo social comunitario, realizamos nota para informar sobre la consulta de revisión en psiquiatría que tuvo Francisco el día pasado lunes, 9 de enero de 2023. Fue su primera consulta con la psiquiatra Virginia Gajardo (llevaba años sin ninguna revisión), la profesional consultó a Francisco su situación personal y médica. Además de corroborar los datos con las profesionales del programa, que le acompañamos a la consulta. Durante la entrevista analizó la situación de emergencia social en la que se encuentra (sin vivienda, sin medios para cocinar, para asearse…) por lo que decidió derivarle al CRR de Mérida, indicando en el informe que es un ingreso urgente por emergencia social. Francisco cree que desde diputación o la Junta le arreglarán su vivienda, pero lo único que han podido hacer del ayuntamiento es declarar su vivienda en ruinas y cabe la posibilidad de arreglarla con alguna subvención, pero solamente habilitándola como nave. Ante esta situación Francisco accede trasladarse al CRR (firmando la solicitud) hasta que pueda regresar a su domicilio. En archivo adjunto enviamos informe de seguimiento y la aceptación de la derivación a recursos residenciales comunitarios de Salud Mental (esta solicitud está firmada por Francisco y debe firmarse también por sus tutores legales). Una vez firmada nos piden que se envíe a la trabajadora social de Salud Mental (Esperanza Gallego). Hoy ha llamado también para indicar que necesitaria algún informe social, y que si se ha iniciado solicitud de dependencia, que es necesario al parecer también. Creemos que seria más cómodo, que hablaras directamente con ella, para el tema de los informes sociales,. Correo electrónico: esperanza.gallego@salud-juntaex.es En cuanto a tratamiento médico mantiene la misma pauta de inyectable trimestral y zyprexa de 15mg (0-0-1).','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-01-19','-Amalia , desde ESM se le va a solicitar derivación a CRR . Adjunto email de Futuex : Desde el programa de apoyo social comunitario, realizamos nota para informar sobre la consulta de revisión en psiquiatría que tuvo Francisco el día pasado lunes, 9 de enero de 2023. Fue su primera consulta con la psiquiatra Virginia Gajardo (llevaba años sin ninguna revisión), la profesional consultó a Francisco su situación personal y médica. Además de corroborar los datos con las profesionales del programa, que le acompañamos a la consulta. Durante la entrevista analizó la situación de emergencia social en la que se encuentra (sin vivienda, sin medios para cocinar, para asearse…) por lo que decidió derivarle al CRR de Mérida, indicando en el informe que es un ingreso urgente por emergencia social. Francisco cree que desde diputación o la Junta le arreglarán su vivienda, pero lo único que han podido hacer del ayuntamiento es declarar su vivienda en ruinas y cabe la posibilidad de arreglarla con alguna subvención, pero solamente habilitándola como nave. Ante esta situación Francisco accede trasladarse al CRR (firmando la solicitud) hasta que pueda regresar a su domicilio. En archivo adjunto enviamos informe de seguimiento y la aceptación de la derivación a recursos residenciales comunitarios de Salud Mental (esta solicitud está firmada por Francisco y debe firmarse también por sus tutores legales). Una vez firmada nos piden que se envíe a la trabajadora social de Salud Mental (Esperanza Gallego). Hoy ha llamado también para indicar que necesitaria algún informe social, y que si se ha iniciado solicitud de dependencia, que es necesario al parecer también. Creemos que seria más cómodo, que hablaras directamente con ella, para el tema de los informes sociales,. Correo electrónico: esperanza.gallego@salud-juntaex.es En cuanto a tratamiento médico mantiene la misma pauta de inyectable trimestral y zyprexa de 15mg (0-0-1).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2023-01-20','Ana: Llamo a Pilar Martín, TS ESM-CC (54612) para preguntar cuándo tiene la próxima cita Joaquina e intentar adelantarla por los signos de posible descompensación, pero no obtengo respuesta.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-01-19','Tema tf: respuesta del hijo : La actuación bajo mi punto de vista debería ser la misma que hemos indicado hasta ahora, si ella no me deja su móvil para bloquear el acceso a Internet durante este mes de Enero, yo cancelaría los recibos de LOWI a sus cuentas y yo me encargaría de darle una SIM para SOLO llamadas. Me consta que Carmen, la trabajadora social, apoya esta medida también, son muchos años intentando que deje de sufrir de prodigalidad por esta adición.','2');
