insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2023-01-19','Tal y como hemos hablado por teléfono, adjunto te remito el justificante de registro y una captura de pantalla de la documentación que se envió con fecha 09/06/22. Así, se le puede reconocer a Miguel Gamero la retroactividad del complemento del 50% desde que tenía reconocido el Grado I de dependencia. Hasta ahora.','2');
