insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-01-19','Tras el correo recibido por el padre, se ha decidido darle un reintegro de 120€ semanales con efecto inmediato. Las transferencias al centro en concepto de cuota y de gastos personales se anularon a finales de diciembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-01-20','Ana: Envío correo de Alicia Cordón, Psicóloga PP.SS. Almendralejo (psicologia.pisosalmendralejo@grupo5.net / 674 35 51 64): preguntando por la adaptación de Fco. Les comunico que si todo va bien, pasaré el expdte. a mi compañera Teresa para seguimiento. ·································· Respuesta de Alicia: "Ahora mismo Francisco Cacho se encuentra relativamente estable. Presenta a veces una actitud un poco complicada, pero se adapta a las normas por ahora. El caso de Francisco será revisado por SEPAD ya que grupo 5 presenta un periodo de adaptación de 30-45 días y no pasó dicho periodo debido a todos los hechos que sucedieron. Sin embargo, hasta que se valore desde el SEPAD, seguirá aquí hasta nuevo aviso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-01-20','Ana: Envío correo-respuesta a A. Jurídicos, con motivo de la herencia que tienen que hacer de la madre de Antonia: "...en la página 9 de la rendición anual de 2022, tienes certificado bancario con los datos de la madre (nombre, apellidos, DNI e IBAN) Le queda, que yo sepa, un hermano, José Manuel Bravo Patilla, con DNI 06.994.233-W y teléfono de contacto 627 359 136. A quién, si no me equivoco, llamasteis alguno en 2021 en relación a la Declaración de Herederos. Por si necesitáis hablar con él de nuevo. Ya le he pedido a Cristina, Educadora de la Asoc. Vera, donde reside Antonia, que si tienen alguno de los documentos que mencionas en el expediente, nos lo facilite. O al menos información sobre dónde falleció su madre para poder solicitar al registro civil el Certificado de Defunción."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2023-01-20','TERESA Buenos días! Supuestamente según las vecinas, es amigo, porque lo han visto con el con anterioridad y que sepamos si estaba voluntariamente en la casa, lo único raro es que entró para coger sus maletas , al no estar Barto allí, y en lugar de salir al no estar el dueño de la casa pues se quedô, pero fueron las propias vecinas de Barto quien abrieron voluntariamente la puerta de la casa con llave. recibió una llamada de Antonia Morán (TS de los SSB de Almendralejo) comentando que ayer recibió una llamada de la presidenta de la comunidad de vecinos de Barto diciendo que aún sigue en su casa el supuesto amigo de Barto. Antonia comenta que si nos enterásemos del nombre y apellidos de esta persona o nos llegase alguna información por parte de algún vecino se lo comuniquemos y, si este señor fuera usuario de los SSB, ellos podrían mediar para que abandone la casa de Barto voluntariamente. Se le comenta a la ts que la información de que hay una persona en casa de Barto ya se remitió a la Comisión y que, además nos llegaron llamadas de algunas vecinas muy nerviosas y se les dijo que nosotros no podemos hacer nada con respecto a este tema (como ir a la casa o algo así, hasta que no esté el tutelado alli de nuevo) Según las propias vecinas es amigo de Barto porque lo han visto con él y además tenía su equipaje en la casa. Ellas mismas le abrieron la puerta con llave para que recogiera sus cosas y se fuera, pero se quedó allí. Se le comentó a las vecinas que si tenían algún problema lo pusieran en conocimiento de la policía, ya que no sabemos quién es esta persona y la policía es quien sabe qué hacer y tiene la autoridad para por otro lado se recibio6, una llamada de la UHB de Mérida para comunicarnos que Barto está mejor pero sigue muy inestable y con ideas muy delirantes, aseguran que creen que deberá seguir una semana más allí. Cuando se acerque el momento de darle el alta y si hay alguna otra novedad se pondrán en contacto con nosotros, tal vez podemos llamar a la unidad y si ven conveniente comentarle algo que lo hagan , no?','2');
