insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-02-06','Ana: Toni me remite por mail Informe de seguimiento del día 30, en dicho informe incluyen una tabla de gastos aprox. fijos mensuales del matrimonio y propuesta de aportación económica con la que consideran debe bolaborar Desideria. Se valorará con Pedro, Jefe de Secc. CTAEX, y Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-01-20','Amalia . gestiones que está averiguando su hijo, Sobre los otros temas que comentas: Teléfono. Le voy a dar dos opciones: a) Que me deje limitar su móvil para que sólo pueda usar programas y enlaces "seguros" para evitar que compre o b) cancelar su teléfono y poner solo llamadas de LLAMAYA Seguro. Voy a hablar con una amiga de Catalana que muy probablemente le va a ofrecer un seguro muy bueno por casi la mitad de precio. Dinero. En cuanto bloqueemos su acceso a Internet estoy seguro de que ella va a tener menos gastos, también cuando consigamos que dé más gatos, de momento van 2 que hemos podido colocar. Testamento. En este tema sí que necesitamos una respuesta más o menos rápida para poder gestionar todo con los abogados, por favor revisad el correo "Presupuesto gestiones Herencia Blas Ródenas González" que os envié el día 20/12/2022. En la página 2 del documento adjunto se señalan las condiciones de pago para iniciar los procedimientos. Pido a seccion eco abonar lo del testamento','2');
