insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN LUIS'and edp.apellido1='ANTONIO'and apellido2='REMEDIOS'),'2023-01-20','El paciente Juan Luis Antonio Remedios está percibiendo desde el día 01/07/22 una PNC por jubilación con una cuantía mensual de 484,61€. Tiene reconocida una discapacidad psíquica del 76% desde el día 02/08/05 y con fecha 25/02/09 se le reconoce un grado III nivel 2 de dependencia. Tiene 66 años cumplidos. Envié un email a PNC preguntando si cumplía los requisitos para solicitar el complemento del 50% del importe de la pensión no contributiva que está percibiendo. Me ha llamado Adela (Jefa de Negociado de PNC) y me ha dicho que el paciente no cumple los requisitos, por un lado, por haber cumplido ya los 65 años y, por otro lado, porque cuando se solicitó la PNC por invalidez no se presentó la resolución del grado de dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2023-01-20','TERESA Adjunto el testamento donde heredaría un 25% de los bienes del hermano pero no dispone de dinero para afrontar el pago de 28.000€ Entiendo que la solución pasaría por vender algún bien que fuera de pleno dominio de ella pero en cualquier caso tendríamos que encontrar un abogado de pago que quisiese cobrar una vez finalizado el expediente. Tiene ahorrado unos 2.000€ y mensualmente parece ser que no le sobra casi nada. He escrito a la de la asesoría abajo indicada para que me diga posibles soluciones como aplazamiento, fraccionamiento…pero que de nada sirven al no disponer de dinero mensualmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PECO'and apellido2='CARRANZA'),'2023-01-20','Ana: Conversación con Anabel Galván, nueva TS de la Mancomunidad de Vegas Altas - Ayto. Madrigalejo (924 354 002 / 672 614 686 / ssbmadrigalejo2@gmail.com): a Isabel no le dan su asignación en el banco, dicen que "falta una firma" (problemas de la fusión de Unicaja y Liberbank). ··········· *Lourdes, Secc. Ecca., enviará nueva autorización al banco.','2');
