insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2023-01-20','Ana: Pilar Cerrillo, TS Centros Mayores Ciudad Jardín (calidad@grupociudadjardin.com) nos remite el CERTIFICADO actualizado DE PENSIÓN DE SUIZA. *Guardo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-01-20','Ana: Llamada de Doroteo (609 928 621): Acudió a su cita en el Juzgado, dice que le hicieron muchas preguntas. ············ Se encuentra bien en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-01-20','Ana: Llamada de Manuel Domínguez, Padre de Manuel (611 690 154): me informa de acudió con su hijo al médico del "CEDEX" (ECA) y que le ha prescrito unas pastillas para dejar de fumar. ··· *Acudirán a la farmacia para que desde la misma remitan al ctutelar@ la prescripción médica y el precio del tratamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-01-20','Ana: Óscar, Secc. Ecca., me informa de que Manuel ha vuelto a retirar dinero sin autorización, dejando la cuenta a 0 en el mes de diciembre. Ahora sólo tiene 100€ en cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-01-20','Ana: Llamo a Pilar Martín, TS ESM-CC (54612): no obtengo respuesta. ···································································································································································································· Correo-respuesta de Toni-Fututex: "PUes mira el otro dia, se le conseguió ver, despues de varios intentos, y todo bien, te detallo el seguimiento: Después de un par de intentos de contacto con Ventura, el 17 de Enero, se consigue que acepte el seguimiento a pesar de insistir en que no tenía tiempo, incluso llega a buscar a la educadora y esperarla porque se retrasa por una consulta médica con otro tutelado, hecho que en otras intervenciones no había ocurrido (no hubiera esperado). Se le comenta que el día 27, de este mes, se tiene la cita para el PADDI, que se solicitó, acepta ir encantado. Se planifica cómo hacer el desplazamiento y se le explica dónde está y cómo se quedará con él, señala que bajará en autobús, pues es la línea 2 y la conoce bien… Se le dice que tiene que llevar el certificado de discapacidad que le proporcionó Julia, establece que lo tiene que buscar, por lo que se pauta que lo busque y si no lo encuentra se indicará para ir a ver a Julia, trabajadora social de la Peña del Cura, para solicitarle que se lo vuelva a sacar, ya que sin dicho documento no pueden hacer la intervención en el PADDI. Ventura acepta todo sin problema alguno"','2');
