insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2023-01-23','RAMIREZ JUAREZ, JONATHAN: NO LE PODEMOS SUBIR ASIGNACIÓN....TEN EN CUENTA QUE A PARTE DE HABERSE LLEVADO TODO SU SALDO CUANDO ESTUVO FUERA DE LA CARCEL, LOS EMBARGOS SE ESTÁN LLEVANDO TODO LO DEMÁS (ENTENDEMOS QUE DERIVADO DE DEUDAS X MULTAS O SENTENCIAS). CRITERIO CTAEX: TEN EN CUENTA QUE DEBERIAMOS DE GENERARLE UN AHORRO MÍNIMO...AUNQUE ESE AHORRO SE LO LLEVEN LOS EMBARGOS, ES UNA DEUDA QUE VAMOS AMORTIZANDO Y QUE NO TENDRÁ QUE SOPORTAR EN EL FUTURO CUANDO SALGA DE LA CARCEL (SALVO QUE SIGA GENERANDO ESA DEUDA CON SUS ACTUACIONES.','2');
