insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-01-23','El usuario Crístofer Figueroa Rastrollo al final de la mañana de ayer ingresó en la Unidad de Psiquiatría del Hospital Universitario de Badajoz. Por ahora no tenemos ninguna información más. Si hubiese alguna novedad te lo comunicaríamos. Un saludo, Iris Calero - Trabajadora Social​ Centro Ntra. Sra. de la Luz - Asprodis (Instituto Secular Hogar de Nazaret) Avda. Godofredo Ortega y Muñoz Nº 3 Badajoz. Tfno. 924237551. Correo: trabajadorasocial@centronuestrasrad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-01-23','El usuario Crístofer Figueroa Rastrollo al final de la mañana de ayer ingresó en la Unidad de Psiquiatría del Hospital Universitario de Badajoz. Por ahora no tenemos ninguna información más. Si hubiese alguna novedad te lo comunicaríamos. Un saludo, Iris Calero - Trabajadora Social​ Centro Ntra. Sra. de la Luz - Asprodis (Instituto Secular Hogar de Nazaret) Avda. Godofredo Ortega y Muñoz Nº 3 Badajoz. Tfno. 924237551. Correo: trabajadorasocial@centronuestrasrad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-01-23','Amalia, buenos días. Mi hijo Alberto después de salirse del centro Asociación de voluntarios del camino a la vida y estar ocho o diez días a todo trapo y tocar fondo, ha decidido ingresar en el otro centro (MARANATA) de La Puebla. esperamos que dure mucho tiempo, al menos, hasta que salga la decisión de la jueza por el quebrantamiento de la condena, y que pueda ser el último centro donde tenga que ir. El importe del centro es de 250 euros/mes, pero se ha comprometido pagarlo él con los 120 euros semanales. Esperemos que lo cumpla. Nos pondriamos en contacto contigo caso de producirse algún cambio. Que tengas un buen fin de semana. Saludos cordiales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-01-23','Ana: En relación al correo de Alberto, jefe secc. ecca.: "HE VISTO UNA ANOMALIA EN LOS INGRESOS DEL TUTELADO: OBSERVA EL MES DE ABRIL DE 2022...EL IMPORTE NO SE CORRESPONDE CON EL RESTO DE PAGOS (QUE TIENEN UNA PERIODICIDAD PERFECTA E IMPORTE IDÉNTICO)" ················· Llamo al SEPE (927 74 89 65). Seguramente sea porque no haya renovado a tiempo la demanda de empleo. ··· No obstante me dicen que no me pueden facilitar información por teléfono, y que lo consulte por escrito a: dp10.ratel@sepe.es ················ Envío la consulta: "En relación al subsidio que viene percibiendo D. JOSÉ MANUEL MORENO CARLOS, con DNI 07005095P, cuyo cargo de curador ostenta la Comisión Tutelar de Adultos de Extremadura, mis compañeros de las sección económica han detectado una anomalía en los ingresos del subsidio por desempleo que viene percibiendo, correspondiente a abril de 2022, mes en el que le ingresaron 169,84€ en lugar de los 463,21€ habituales. ¿Podrían anclarnos a qué se debe esta diferencia?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-01-23','miguel, email de Rocio Gracian (abogada) por el juicio celebrado hoy en Málaga: Buenos días Miguel He conseguido un acuerdo con los demandados y se acaba de celebrar el juicio en el que hemos solicitado el Auto de homologación del mismo. Los términos del acuerdo son que deben en abandonar la vivienda antes del 30 de junio con condonación de la renta adeudada. En caso de incumplimiento se revoca la condonación y se procederá al lanzamiento obligatorio sin opción a acogerse a posibles futuras prórrogas legales. Creo que es lo mejor que podíamos conseguir. Cuando me notifiquen el Auto te lo traslado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-01-23','miguel, email de Rocio Gracian (abogada) por el juicio celebrado hoy en Málaga: Buenos días Miguel He conseguido un acuerdo con los demandados y se acaba de celebrar el juicio en el que hemos solicitado el Auto de homologación del mismo. Los términos del acuerdo son que deben en abandonar la vivienda antes del 30 de junio con condonación de la renta adeudada. En caso de incumplimiento se revoca la condonación y se procederá al lanzamiento obligatorio sin opción a acogerse a posibles futuras prórrogas legales. Creo que es lo mejor que podíamos conseguir. Cuando me notifiquen el Auto te lo traslado ****************************************************** Lo reenvío a la parte social y económica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-01-23','miguel, email de Rocio Gracian (abogada) por el juicio celebrado hoy en Málaga: Buenos días Miguel He conseguido un acuerdo con los demandados y se acaba de celebrar el juicio en el que hemos solicitado el Auto de homologación del mismo. Los términos del acuerdo son que deben en abandonar la vivienda antes del 30 de junio con condonación de la renta adeudada. En caso de incumplimiento se revoca la condonación y se procederá al lanzamiento obligatorio sin opción a acogerse a posibles futuras prórrogas legales. Creo que es lo mejor que podíamos conseguir. Cuando me notifiquen el Auto te lo traslado ****************************************************** Lo reenvío a la parte social y económica: Buenos días, adjunto debajo email de la abogada. Hoy era el juicio por desahucio, al cual se ha llegado a un acuerdo porque hasta junio continúa la prórroga del gobierno a la prohibición de desahucios. A cambio de que abandonen voluntariamente la vivienda en junio, no pagarán los meses que restan hasta entonces. Parece ser que no estaba claro quién debía dinero a quién ni cuánto ya que Damian y los inquilinos se acusaban mutuamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-01-23','Ana: En relación a la aportación que tiene que hacer Javier al Piso supervisado, Paula, TO CRR (tocupacional.crrplasencia@grupo5.net), confirma que la han incluido en la asignación mensual: "estaría incluido el presupuesto para comprar la comida en el piso en la cantidad mensual mencionada. En la actualidad ponen entre 160 y 180 Euros mensuales (según el número de semanas del mes principalmente)." ····························································································································································································· *Confirmo a Paula, TO CRR-Plas, que se aprueba la asignación mensual y el extra anual (1.700 €) que proponen para este 2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-01-23','Ana: En relación a la aportación que tiene que hacer al Piso supervisado, Paula, TO CRR (tocupacional.crrplasencia@grupo5.net), confirma que la han incluido en la asignación mensual: "estaría incluido el presupuesto para comprar la comida en el piso en la cantidad mensual mencionada. En la actualidad ponen entre 160 y 180 Euros mensuales (según el número de semanas del mes principalmente)." ········································································ *Confirmo a Paula, TO CRR-Plas, que se aprueba la asignación mensual y el extra anual (900€) que proponen desde el centro para este 2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-01-11','Ana: Conversación con Paula, TO CRR: han decidido conceder a Carmen una prueba de estancia en el Piso Supervisado. Se irá a lo largo del mes de febrero. Ella se muestra muy contenta, tiene ganas de probar. *Saben que Carmen necesita muchos apoyos, pero tiene mucho deseo de autonomía y creen que se va a esforzar. **Si no funciona, gestionarán el regreso a plaza en CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-01-11','Ana: Conversación con Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): Ya han propuesto en firme a Javier para el piso supervisado. Seguramente la semana que viene ya se traslade. ···· Por otra parte, Javier solicita irse de vacaciones una semana en abril o mayo. Nos confirmarán fecha desde el CRR (ya han contemplado el gasto que supondría en el extra anual). Quiere ir a una localidad de Gerona. ··· De hecho dice que en el futuro le gustaría trasladarse a vivir allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-01-23','Ana: Tras valoración por parte de la secc. ecca., confirmo a Paula, TO CRR-Plas, que se aprueba la asignación mensual y el extra anual que proponen desde el centro. *Siendo finalmente este último de 1.300€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-03-17','Ana: Envío correo a Alberto y Estrella, Secc. Ecca.: "Buenas, de nuevo, Estrella y Alberto, Estrella: En relación al SEGURO DE DECESOS, cuando puedas, por favor, confírmame que se le está cobrando a ella ya su póliza. Antes la tomadora era su madre, Benita (628 887 928), pero ésta me ha llamado para confirmar si lo paga ya a Carmen, pues ella dice haberla quitado ya. Ya se habló de este asunto en su día, pero a día de hoy no lo pongo en pie. Por otra parte, Alberto; Benita dice que su nieto de 19 años, que vive con ella (hijo de Carmen), al que se ha ayudado económicamente en otras ocasiones, se ha quedado sin empleo y ella actualmente va mal económicamente. Por lo que pide que durante unos 2 – 3 meses Carmen Ayude a su hijo dándole unos 300 € al mes (prevé que volverá a trabajar después de este periodo). Si no recuero mal, Carmen ya le pasa algo de dinero todos los meses a sus dos hijos. Míralo cuando puedas y si quieres lo hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-01-20','Ana: Correo de Toni-Futuex, con seguimiento realizado en enero. ···· Guardo en el expte. en PDF. ············ En relación a Jesús, Felisi expresa que "no siente que él la quiera como ella a él" y manifiesta querer salir de la casa de los padres de Jesús, pero no quiere volver a su casa de La Nava, quiere quedarse a vivir en El Casar, pues allí "alli tiene arraigo, tiene grupo de amigas, y se siente integrada... incluso dice que si no puede optar a una vivienda social alli". ····· Por estos motivos no termina de aceptar la limpieza de su vivienda. ················ Contesto a Toni insistiendo en la necesidad de hacer la limpieza, por salubridad. Y pido que en la próxima visita le acompañen a hablar con la TS en relación a las posibilidades reales de acceder a una vivienda social en El Casar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-01-23','TERESA EMAIL TS PEÑALSORDO Buenos días , soy María , la Trabajadora Social de Peñalsordo , está conmigo Felisa Gómez Rubio y me esta comentando que Marta Rivera Nuñez , se fue el viernes por la mañana al colegio y no volvió mas , llamó por teléfono a su hijo y le dijo que ya no volvía más con ellos .Lo que pongo en su conocimiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-01-24','Ana: Envío correo a Toni-Futuex, solicitando que constaten si dejé que el cerrajero del seguro arreglara la cerradura. Si no fue así, que le apoyen para pedir presupuesto de cerrajero y proceder al arreglo. ······················································································································································································································································· Llamo varias veces a Pilar Martín, TS ESM-CC (54612): no obtengo respuesta.','2');
