insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-01-24','Ana: Correo de Leire Sanz Gay, TS - Centro de Mayores Ciudad Jardín Cánovas (t.socialcanovas@grupociudadjardin.com): "Me acaba de informar la Directora que se han llevado a Josefa esta noche al Hospital, ya que nos respondía a estímulos, cuando tenga más información, te voy diciendo."','2');
