insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-01-24','Ana: Hablo con José Luis Abad, Director de la Oficina de Información Telemática de Cáceres (927 748 943): Como el subsidio se ingresa a mes vencido, el ingreso de abril de 2022 corresponde a la mensualidad de marzo. La cuantía es mucho menor porque se olvidó de renovar la demanda de empleo. Se dio de alta a posteriori y calculan el porcentaje. ········ *Me informa también que en diciembre le ha vuelto a pasar lo mismo, en el mes de febrero percibirá sólo 149,60€. ······ **La próxima renovación de la demanda la tiene el día 13 de abril. ··············· Informo a Alberto, Jefe Secc. Ecca. CTAEX, al respecto y pido a Paula, TO del CRR-Plas. que por favor estén pendiente desde el centro de cada renovación para que no vuelva a sucederle. ·································································································································································································· En cuanto a la pensión, no sabemos con seguridad si puede tener derecho a P. Contributiva de Jubilación, para ello, debería haber cotizado antes de cumplir 65 años, 38 años y 6 meses. *La otra opción, es que llegado los 67 años, hubiera cotizado 15 años, siendo 2 de ellos (consecutivos o no) en los últimos 15. ·················· Intento contactar por teléfono sin éxito. ····· *Envío correo a Registro (oac.merida.san@juntaex.es): "Adjunto los siguientes documentos, relativos a D. José Manuel Moreno Carlos, cuyo cargo ostenta la CTAEX: - Oficio-solicitud de Informe de Vida Laboral - Testimonio de firmeza auto de nombramiento - Acuerdo de Aceptación del cargo Para remitirlos por SIREX" a la Dirección Provincial del INSS en CC. ························ Recibo Justificante del registro en SIREX. ·· Guardado en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2023-01-24','Uno de nuestros residentes CRISTÓBAL CASQUERO GARCÍA se encuentra desde anoche ingresado en el Hospital Universitario de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2023-01-24','miguel, llamo a la abogada por la diligencia recibida por el jzdo nº3 de Navalmoral de Cáceres, y me comenta que el ofrecimiento de acciones no tiene importancia y que es meramente informativo. Me comenta que el fiscal le indicó que lo iniciara de oficio. También me dice que el jzdo de Navalmoral nº3 se va a declarar incompetente en favor de Valencia de Alcantara porque la tutelada actualmente reside en Santiago de Alcantara (Cáceres)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2023-01-24','miguel, email de Inés: Miguel he conseguido hablar con el Juzg nº 1 de Zafra. Ha enviado a Servic. Jurídicos nuevo señalamiento para reconocimiento del Forense en relación a Maria Murillo Delgado., ante la imposibilidad que tiene esta mujer para desplazarse, se envía también las claves de acceso para la asistencia mediante videollamada (me preguntan si va a estar acompañada, se supone que hay que llamar a Futuex para que lo haga). Aquí no se ha recibido aun la notificación, imagino que Serv Jurídicos lo hará en breve, porque el señalamiento es el próximo dia 8 de febrero de 2023, a las 12:45 h. ******************************************************** Reenvío email a la parte social Tere y Maite: Hola Tere, adjunto email de debajo de Inés. Parece ser que Maria Murillo alegando que no tenía forma de desplazarse al juzgado no acudió al reconocimiento médico. Le dicen a Inés que la han dado nueva cita 8-2-23 a las 12:45h Dicha citación la han debido de enviar a abogacía, con lo que Inés llamará para reclamarla. La cuestión es que dicha cita será por videoconferencia con Maria por lo que debería acompañarla alguien en dicha videoconferencia, no sabemos si futuex o alguna trabajadora social del SSB de Monesterio… Por tanto debes organizar lo necesario para que Maria se conecte ese día. Los códigos si tiene problema se lo diremos con tiempo al juzgado para que se lo hagan llegar a ella o a quién la acompañe. Ya digo que es necesario asegurarnos que ese día se conecta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-01-24','miguel, llamo a su hermano José Manuel (627-359136 tlfno de su jefe). No tiene forma de contactar con nosotros ni por email ni tfno propio. Le comento los trámites a realizar con la herencia de la madre y le explico que vaya a una gestoria o a la notaria y me diga con quién hablar para el trámite de la misma','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-01-24','miguel, llamo a la exmujer Mª Eugenia (655-861802) y quedo con ella en llamarla mañana para que me dé el tlfno de la vecina que está organizando el arreglo del tejado del edificio, Eva Perez Escarmena. Parece ser que el vecino que no quiere pagar el arreglo es el del 1º, del cual solo conocemos el apellido Tomatito. Tras consultar las notas simples que me remitió Toni de Futuex de Julio de 2021 compruebo que no coinciden los actuales titulares registrales con los que realmente ocupan las viviendas: Bajo la Abogada Eva Perez Escarmena (titular real su hno y su esposa) Otro Bajo hay una Farmacia (titulares herederos de Gonzalo Plasencia (fallecido) y su esposa Mª Luisa Prieto Rodriguez. Han dejado unos 8 hijos) Piso 1º vive Tomatito (desconocemos su nombre), es el que se niega a pagar. En su nota simple está a nombre de una empresa Baralia Gestoria de Empresarios SL cif B86139078','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-01-24','-LLama Emi , ayer se marchó del hostal y durmió en casa de Antonio. Dice que hoy la ha echado y se ha ido con Miguel Angel a D. Benito. Dice que debe en el hostal una comida de 11€ y 2€ de un desayuno de otro dia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-01-24','Ana: Correo de Verónica, TS del SSASB de Moraleja (s.sociales2@moraleja.es): "Soy Verónica Alfonso, la trabajadora social del Ayuntamiento de Moraleja, te he estado llamando en relación a la plaza residencial que solicitó Pilar Díez Santiago en la Residencia de Mayores “San Blas” de Moraleja. Hay una plaza disponible, y nos dice la Secretaria del Ayuntamiento que si informamos de la conveniencia podría adjudicársele a Pilar, pero ahora , cuando las compañeras del Progama de Atención a Familias se lo han planteado les dice que no quiere ingresar. No sabemos muy bien como proceder, si no te importa llamarme cuando tengas un momento te lo agradecería." ····················· Llamo a Verónica (927 14 10 14): Me informa de que estuvo 2 semanas en diciembre pidiendo al Programa de Familia, ingresar en residencia. Aún no había plazas disponibles. El día de Nochebuena hubo posibilidad de que Pilar cenara y pernoctara en la misma sin coste para ella. Aceptó encantada y así lo hizo. ····· A raíz de esa noche, su concepto de la residencia ha cambiado, dice que hay personas muy mayores y que ya no se quiere ir a vivir allí. ····· No tiene conciencia de su nivel de dependencia. *Ahora piden que por favor no la obliguen a ingresar. ····················· Verónica, TS, tiene un dilema, pues siendo tan joven, lo ideal es que pudiera continuar en su casa con los apoyos oportunos, pero la realidad es que las condiciones en las que está, no son las más óptimas. ···· Puesto que ellas son las que conocen la trayectoria, así como la situación actual puesto que llevan años interviniendo con ella, *acordamos que el viernes, tendrá una reunión de equipo con el Programa de Familia para aunar criterios y tomar una decisión. ························· *Según el fallo de la sentencia, podríamos proceder al ingreso involuntario en centro adecuado, si fuera necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2023-01-24','Ana: Llamada de Aida (671 50 72 21): Dice que lleva más de un mes mala con un resfriado importante. Ha pedido nueva cita a su MAP, Dr. Luis Prieto pues continúa con mucha tos y mucosidades. Le han dado para el próximo jueves. ·········· Según dice, debido a este catarro lleva más de un mes sin acudir al gimnasio, y no ha podido suspender el servicio de formar puntual por no poder prever que le iba a durar tanto. ············· Dice que Gloria, Ed. de Futuex, le está agobiando, pues le propone acordar con el gimnasio acudir quincenalmente o alguna forma similar, si no va asistir de forma continuada, pues no puede abonarlo para no aprovecharlo. **Ella dice que lo necesita de verdad y no puede dejarlo, pues desde que asiste está mejor de la lumbalgia. ·········· Le recuerdo que Gloria está haciendo su trabajo y mira por ella y por el uso adecuado de sus recursos. ················· *David, profesional del gimnasio, enviará al ctutelar@ nueva propuesta y presupuesto para confirmar la continuidad en el servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-01-24','Ana: correo de Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Ayer hice entrevista a Montaña para abrir historia social y me dijo que quería solicitar los mínimos vitales, supongo que esas cuestiones tienen que pasar primero por la CTA"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-01-25','Amalia: Buenos días , elaboro yo el Plan de intervención de este señor que reside en Valdeobispo. Sección Eco : Óscar , te llamo por tf para concretar algunos datos. Lo más urgente es facilitar para que pueda retirar 100€ semanales . No tiene seguro decesos , tiene 51 años , habría que hacerle alguno. Necesito saber qué dinero tiene en cuenta . Recibe comida y cena de la R. Mayores , por la que se abonan 200€ al mes , podéis comprobar si se están cargando o hay deudas ? Veo en su expediente , una factura de fontanería pendiente de pago . Percibe una pensión de incapacidad , con la subida de este año tiene que rondar cerca de los 800€. Sección jurídica : Tiene pendiente la herencia de la madre . Era enfermera , tienen un chalet que él dice ser de la madre . Son 4 hermanos , uno trabaja en el Hospital de Plasencia y los otros 2 residen fuera de España. El padre vive en Cáceres , es médico . Enrique reside en una vivienda que el abuelo hizo para él , pero no tiene escrituras , ni consta como propietario . Teme perderla y verse en la calle . Empezamos con este caso que va a ser de los complicados , tiene 51 años , enfermedad mental y consumo . otras acciones que voy a iniciar : -Derivación a Futuex . -Control sanitario con ESM y adherencia a tto. -Activar PIA , solicitar ayuda a domicilio o asistente personal -Mantenimiento en domicilio , no quiere centros , tiene un perro del que no quiere separarse . Varios ingresos en CSS Plasencia.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-01-25','Amalia: Buenos días , elaboro yo el Plan de intervención de este señor que reside en Valdeobispo. Sección Eco : Óscar , te llamo por tf para concretar algunos datos. Lo más urgente es facilitar para que pueda retirar 100€ semanales . No tiene seguro decesos , tiene 51 años , habría que hacerle alguno. Necesito saber qué dinero tiene en cuenta . Recibe comida y cena de la R. Mayores , por la que se abonan 200€ al mes , podéis comprobar si se están cargando o hay deudas ? Veo en su expediente , una factura de fontanería pendiente de pago . Percibe una pensión de incapacidad , con la subida de este año tiene que rondar cerca de los 800€. Sección jurídica : Tiene pendiente la herencia de la madre . Era enfermera , tienen un chalet que él dice ser de la madre . Son 4 hermanos , uno trabaja en el Hospital de Plasencia y los otros 2 residen fuera de España. El padre vive en Cáceres , es médico . Enrique reside en una vivienda que el abuelo hizo para él , pero no tiene escrituras , ni consta como propietario . Teme perderla y verse en la calle . Empezamos con este caso que va a ser de los complicados , tiene 51 años , enfermedad mental y consumo . otras acciones que voy a iniciar : -Derivación a Futuex . -Control sanitario con ESM y adherencia a tto. -Activar PIA , solicitar ayuda a domicilio o asistente personal -Mantenimiento en domicilio , no quiere centros , tiene un perro del que no quiere separarse . Varios ingresos en CSS Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2023-01-23','miguel, llega físicamente escrituras originales de acta de notoriedad de declaración de herederos de Agustin (hijo de la tutelada). Lo escaneo y reenvío a la abogada Estefanía: Te adjunto acta de notoriedad de Agustin (hijo de Alfonsa Montalban). Por fin ha llegado. Si quieres hablamos para poner en marcha la herencia. Recuerda que tendremos que plantear la autorización judicial de aprobación de la herencia cuando se firme y de la venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-01-25','Ana: Cumplimento y subo al portafirmas digital nueva COMUNICACIÓN de DATOS BANCARIOS al INSS - *Nueva entidad bancaria IBERCAJA. ······················· *Lo remito al registro (oac.merida.san@juntaex.es), para registrar la solicitud en SIREX y remitirlas a la Dirección Provincial del INNS - CC. ················ Me envían justificante de REGISTRO - Expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-01-12','Ana: Maribel, TS Secc. Discapacidad, me entrega copia de la Resolución de Plaza en RAE, en el Centro Plena Inclusión de Zafra. *Ya lo han comunicado al CSS, se pondrán en contacto para organizar el traslado. ············ *Escaneo y guardo la resolución en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-01-16','Ana: Recibimos resolución del IMAS, relativo al Servicio Municipal de Cáterin solicitado. *Ventura quedó en lista de espera. ··········· No obstante este servicio finalizó a fecha de 31/12/22.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-01-25','Ana: Envío correo a Julio y Amalia, CTAEX: "Te comunico nuevo cambio de domicilio, para que, cuando puedas, procedas al cambio en la base de datos. MIGUEL ÁNGEL RAMOS ANDRÉS Nuevo centro: Comunidad Terapéutica La Garrovilla Avda. Luis Jacinto Ramallo García, s/n 06800 Mérida, Badajoz Telf. 924 33 51 00 Amalia, te pongo en copia para avisarte de que cuando supere el periodo de adaptación, pasará a tu zona para seguimiento. No obstante, en este caso, estoy pendiente de modifiquen la legislación para solicitar de nuevo la PNC. Es el primer caso, de mi zona, al menos, que no tiene derecho a PNC ni a PFHC, porque no llega al 65% de discapacidad y no se asimilan las MEDIDAS JUDICIALES DE APOYO A PERSONAS CON DISCAPACIDAD a las antiguas Incapacitaciones y por tanto no entran en la excepción para el cobro de dichas prestaciones. *Tenemos los correos que envió Ángel al respecto, a ver qué pasa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-12-15','Ana: Recibimos RESOLUCIÓN, del SS.TT., Serv. de PRESTACIONES, DENEGANDO la solicitud de PNC, por no reunir los requisitos exigidos: NO alcanza el 65% de discapacidad. ········· Con la nueva legislación no está "incapacitado" para poder acogerse a la excepción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-01-25','miguel, me llama José Manuel Rubio (Fiscal de Plasencia) para preguntar como están las gestiones de aceptación del cargo. Le indico que han llegado físicamente y por email providencia del juzgado preguntandonos si ya estamos ejerciendo el cargo de curador. Le comento que sí y que se ha contestado en ese sentido al juzgado. Pero su llamada es en relación a la necesidad urgente de necesidad de disponibilidad económica por parte del curatelado representativo. Lo comento con Oscar, el cual me informa de palabra y me reenvía email para enviar al Fiscal de Plasencia: Buenas tardes Miguel. Enrique tiene cuenta en Caixabank de Montehermoso (Pl. de Moron, 11), de donde saca semanalmente 50€. Esta limitación de reintegro debe provenir del representante legal que aparece en su cuenta, su hermano Ricardo (11781468V). En cuanto tuvimos conocimiento de en qué entidad financiera tenía domiciliada su pensión, en este caso Caixabank, se envió escrito para la inclusión de José Vicente como representante legal a la sucursal de Montehermoso el 17 de enero, con acuse de recibo el 20 de enero. No hemos recibido respuesta (se adjunta escrito y acuse de recibo). Al mismo tiempo se envió a atención al cliente de Caixabank la misma solicitud, obteniendo como respuesta el escrito que se adjunta, donde aparecen como representantes legales de D. Enrique su madre fallecida y su hermano. Se limitan a darnos la información solicitada, sin incluir al Director Gerente como representante legal en su cuenta bancaria. Al no poder actuar directamente con la oficina por no obtener respuesta, vamos a enviar mañana 26 de enero una autorización de reintegro semanal de 100€, a ver si nos hacen caso y se lo facilitan al curatelado (hecho bastante improbable). Una cantidad superior sería inviable, ya que tiene gastos mensuales domiciliados (catering, luz, teléfono,…). En cualquier caso, teniendo catering de comida y cena domiciliado, con 50€ semanales ha estado viviendo desde junio, fecha en la que falleció su madre, y no ha habido problema; ahora mismo dispone del mismo dinero que antes de ser curatelado por la Comisión y de aceptar el cargo. Si antes no tenía problemas, ahora debería ser igual. Se está tramitando la apertura de una cuenta bancaria en Unicaja, única oficina que hay en Valdeobispo, para domiciliarle la pensión y controlar más eficazmente su situación económica. Por último, sería conveniente hacerle constar al Fiscal que, sistemáticamente, tanto Caixabank como otras entidades financieras hacen caso omiso a nuestros requerimientos, desobedeciendo así las resoluciones judiciales e impidiendo realizar nuestra labor. ********************************************************** mi contestación: Buenas tardes José Manuel, me comenta el compañero de la parte económica que en breve tendrán abierta una cuenta en Unicaja (antes Liberbank) desde donde vienen trabajando con otros curatelados. En el email de debajo de mi compañero puedes ver los inconvenientes que están encontrando con Caixabank. Me comenta de palabra que es posible que hasta Marzo no pueda estar solucionado. También me indica que su antiguo tutor, su hermano que creo trabaja en el Hospital de Plasencia, le tiene autorizado para que saque 50 euros, lo cual hace todas las semanas. Adjunto también la documentación acreditativa de las gestiones que están realizando para tu constancia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-01-25','miguel, llamo conforme me comprometí ayer con Mª Eugenia 665861802 (exmujer), para que me dé el tlfno de la abogada (Eva Perez Escarmena 649-555601)que está tramitando el tema del arreglo del tejado. Pregunto a Oscar el dinero de que dispone actualmente el tutelado: A día de hoy tiene 56.313,52 €. Llamo a la abogada sin éxito, la llamaré mañana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-01-24','Ana: Correo de Paula, TO CRR: "Anoche volvió hacer una ingesta de objetos por lo que ha requerido quedarse en el hospital, por la posible necesidad de intervención en las próximas horas para la extracción de alguno de estos objetos. Así mismo, os adjunto el documento de consentimiento informado para extracción dentaria para Isabel Cano, tenía cita para el lunes próximo y por si acaso sería necesario contar con el documento para que pudiera acudir al dentista."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-01-25','Ana: reenvío a los A. Jurídicos - CTAEX, el CERTFICADO DE ÚLTIMAS VOLUNTADES relativo al marido de Desideria, remitido por Coaficoex-Seguros. ································································································································································································ Correo de Ángel, Asesor Jurídico CTAEX: "En el certificado de últimas voluntades, indica que Ángel Pérez Manzano, estaba casado con una tal Isabel Irade Gurruchaga….."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-01-25','-Amalia , contacto con la TS Mª Puerto Paniagua Martín. Trabajadora social" >ssb5@mancomunidadvalledelalagon.es> Enviados: Lunes, 16 de Enero 2023 8:39:06 Asunto: RE: CASO ENRIQUE SANTOS GARCÍA-PUENTE DE VALDEOBISPO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2023-01-26','TERESA Teresa, te paso el teléfono del centro de salud. Para que puedas hablar con Fátima, su médica de primaria. 924562493. Como tú has hablado con juzgado, sabes en los términos que te lo han pedido,... Si que te digo que él está más apagado, hoy me explicaba la auxiliar que apenas se levanta del sillón. aunque puede andar, está flojo. Una duda, el ingreso involutario sigue adelante, no?? la duda es que sea mas urgente o menos, pero se puede hacer ingreso, no?? Porque es insostenible mantenerlo así en su domicilio, teniendo en cuenta la parte social. Cualquier persona en su circunstancia sanitaria se puede mantener en su entorno si tiene red de apoyo, pero el es inviable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-01-25','Ana: Correo de Paula, TO, CRR-Plas: "hoy ha recibido el alta hospitalaria Concepción Fernández."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-01-25','Ana: Respuesta de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Comentarte que Isabel Cano continúa ingresada en la unidad de agudos. El objetivo es apoyar el tratamiento para la expulsión por vía natural de los objetos ingeridos pues, parece ser que en esta ocasión pueden existir complicaciones debido a las características de los objetos (parece ser que son lápices que se han astillado) y a su situación (la operación para extracción tendría muchísimos riesgos por lo que se van a intentar otras opciones primero, aunque sin descartar que pueda ser necesaria una intervención quirúrgica de urgencia)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-01-26','Ana: Remito a los A. Jurídicos CTAEX, el Certificado de Matrimonio del Registro Civil, en el que consta que se casó con Ángel Pérez Manzano. ···································································································································································································· Llamo a Maite, cuñada de Desideria (943 11 61 93): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-01-26','Ana: Correo de Leire Sanz Gay, TS - Centro de Mayores Ciudad Jardín Cánovas (t.socialcanovas@grupociudadjardin.com): "ME COMUNICAN LAS COMPAÑERAS QUE HAN MANDADO AYER A JOSEFA A GERIATRIA Y QUE ESTA CON INSUFICIENCIA RESPIRATORIA. TE VOY INFORMANDO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='PEREZ'and apellido2='DIAZ'),'2023-01-26','TERESA ME ESCRIBE ANA INFORMADO DE LO SUCEDIDO EN LA VIVIDNDA DE BADAJOZ Cuando llegamos la tapa del contador estaba en el suelo, pensamos que se había caído con el aire. Entramos y nos encontramos con esa “cosa de plástico” en el suelo que después comprobamos que es una “pestaña” de los dos fusibles que tiene el contador…quizás la tiraran para saber si la alarma saltaba. Al entrar comprobamos que no había luz, la alarma enchufada, los fusibles del contador de dentro de la casa correctamente… pero no había luz…por lo que nos fuimos aver lo de la tapa caída y nos dimos cuenta que faltaban los dos “plomos” La alarma tenía batería externa que habrá durado unos días pero ya estaba desactivada…con lo cual quizás tengan intención de volver este fin de semana de nuevo . En Badajoz llamé a policía local, me dijeron que no podían hacer nada a menos que hubiera un intento real de ocupación y que pusieran la denuncia los hermanos aquí en zafra. Ayer por la tarde en el cuartel de Zafra nos dijeron que la teníamos que haber puesto allí en Badajoz…uffff…y que no había nadie para recoger denuncia, que fuéramos hoy por la mañana…eso haremos…te enviaremos copia. Con respecto al seguro de hogar, yo también te iba a preguntar lo mismo…si lo tenían…desde que están con nosotros no se ha vuelto a pagar, con lo cual…anulado….y si vosotros no lo habéis hecho, pues no tiene. Por último, en cuanto se pueda restablecer alarma yo creo que hay que cambiar los datos de contacto que se dieron y dar los vuestros y alguno de aquí quizás, no crees? SOLICITI A FUTUEX CONTACTE CON ELECTRICISTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEANDRO'and edp.apellido1='PEREZ'and apellido2='DIAZ'),'2023-01-26','TERESA ME ESCRIBE ANA INFORMADO DE LO SUCEDIDO EN LA VIVIDNDA DE BADAJOZ Cuando llegamos la tapa del contador estaba en el suelo, pensamos que se había caído con el aire. Entramos y nos encontramos con esa “cosa de plástico” en el suelo que después comprobamos que es una “pestaña” de los dos fusibles que tiene el contador…quizás la tiraran para saber si la alarma saltaba. Al entrar comprobamos que no había luz, la alarma enchufada, los fusibles del contador de dentro de la casa correctamente… pero no había luz…por lo que nos fuimos aver lo de la tapa caída y nos dimos cuenta que faltaban los dos “plomos” La alarma tenía batería externa que habrá durado unos días pero ya estaba desactivada…con lo cual quizás tengan intención de volver este fin de semana de nuevo . En Badajoz llamé a policía local, me dijeron que no podían hacer nada a menos que hubiera un intento real de ocupación y que pusieran la denuncia los hermanos aquí en zafra. Ayer por la tarde en el cuartel de Zafra nos dijeron que la teníamos que haber puesto allí en Badajoz…uffff…y que no había nadie para recoger denuncia, que fuéramos hoy por la mañana…eso haremos…te enviaremos copia. Con respecto al seguro de hogar, yo también te iba a preguntar lo mismo…si lo tenían…desde que están con nosotros no se ha vuelto a pagar, con lo cual…anulado….y si vosotros no lo habéis hecho, pues no tiene. Por último, en cuanto se pueda restablecer alarma yo creo que hay que cambiar los datos de contacto que se dieron y dar los vuestros y alguno de aquí quizás, no crees? SOLICITI A FUTUEX CONTACTE CON ELECTRICISTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-01-26','Ana: Correo de Verónica Alfonso, TS del SSASB de Valle de Árrago - Moraleja (s.sociales2@moraleja.es): "Buenos días Ana, hemos estado hablando mis compañeras y yo de la posibilidad de ingreso involuntario de Pilar en centro residencial. Si a vosotros os parece bien, y teniendo en cuenta que en este momento ella se niega a ingresar voluntariamente, creemos que lo ideal sería mantenerla en lista de espera y cuando le toque, por orden de entrada, el ingreso en el centro, volveríamos a planteárnoslo, así contamos con un poco más de tiempo para intentar convencerla. Pero ahora tenemos otro problema. Pilar pesa 119 Kg. y su auxiliar, de la carga de peso durante los meses que lleva trabajando con ella, empieza a tener problemas de espalda, todas coincidimos en que si Pilar se apoyara en un andador cuando salen a pasear, o cuando la compañera la asea, sería mucho más fácil; pero Pilar se niega a pagar, de su dinero asignado un andador. ¿Cabría la posibilidad de que compráramos uno y os mandáramos la factura para que la Comisión gestione el pago mediante transferencia bancaria directamente a la ortopedia? Espero tu respuesta," ······························ Mi respuesta: "Me parece buena decisión. Como te decía, vosotras sois las que mejor la conocéis a ella, su situación actual y su trayectoria. No obstante, siempre queda la posibilidad de, en caso de empeorar la situación y considerarse necesario, adelantar el ingreso como emergencia social y de forma involuntaria si fuera preciso. En cuanto al andador, enviad al ctutelar@salud-juntaex.es , a la atención de la sección económica, presupuesto de la ortopedia (si fueran posible dos mejor que uno), para su valoración y aprobación. Si es viable económicamente, no habrá problemas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-01-26','Ana: Envío correo-respuesta a Mª Paz Casado Rabasot, Psicóloga UHDAC (mariapaz.casado@salud-juntaex.es): "La D-Gerente de Plena Inclusión Zafra es Lola Ortega. El número de teléfono del centro es: 924 56 30 92. En caso de no poder hablar con ella, puedes preguntar por Ana Arroyo, Educadora Social." ································································································································································································· Correo de Estrella Durán (estrella.duranc@salud-juntaex.es): "Reme viene diciendo hace tiempo que quiere hacerse un tatuaje, he preguntado por aquí en varios sitios a ver si los hacían de henna no permanentes y nada. Nos estamos planteando hacérselo de verdad, el único inconveniente que veíamos era que tenía que llevar apósito una noche, pero nos comentan compañeros que se los han hecho, que ni siquiera una noche, que lavándolo bien con agua y jabón neutro y secándolo bien con gasa, luego crema se cura bien. Que os parece. El precio son unos 40 euros." ················ Planteo a Estrella, que si Remedios tiene suficiente capacidad para comprender los riesgos que supone hacerse un tatuaje (infecciones principalmente) y lo asume podría hacérselo. ···· Finalmente se decide que se promoverá que pueda hacerse uno de henna, cuando esté en el centro de Plena Inclusión. Y si le gusta, quiere y puede permitírselo, que se lo haga de vez en cuando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2023-01-26','Ana: Envío correo al Programa de Familias Tajo-Salor (programafamilia@tajosalor.es): "Quería preguntaros por un nuevo expediente que se aceptó por la CTAEX en septiembre de 2022. Los compañeros solicitaron de oficio al SSASB, Informe Social, al Ayto,. pero no hemos obtenido respuesta. Tampoco nos envían certificado de pensiones del INSS, acabo de llamar y es que a su nombre tampoco hay nada. Sí que me informan que la Unidad de Convivencia ha tenido reconocido y aprobado el Ingreso Mínimo Vital, a nombre de su madre. Es todo lo que sabemos hasta ahora, pues desde el Juzgado nos enviaron la sentencia “pelada y mondada”. No sé si vosotras habréis intervenido con esta familia y, en tal caso, agradeceríamos que nos remitieseis informe para poder elabora el inventario y comenzar la intervención, pues al no recibir más información lo tenemos parado. Se trata de SANTIAGO PAJARES TALAVERA, de Arroyo de la Luz. Sé, por el compañero del INSS, que convive con la madre, Mª Josefa Talavera, y su hermano, Alexander, menor que él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2023-01-24','Ana: Según la sentencia, se trata de una Curatela Asistencial, "en aras a la realización de apoyo o supervisión sobre los actos complejos relativos a sanidad , economía , régimen jurídico y administrativo" ············· En la esfera de la salud, el fallo especifica que requiere apoyo en: "HABILIDADES SOBRE LA SALUD: -Para consentimiento de tratamiento médico . -Para consentimiento de intervenciones quirúrgicas. - Para complementar actuación sobre su estado de salud y medicación pautada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-01-26','Ana: Envío correo a Eva Álvarez, TS Plena Inclusión Montijo - Proyecto Mi casa (trabajadorasocialco@plenainclusionmontijo.org): "Adjunto los siguientes documentos relativos a CRISTOFER MONTERO VÁZQUEZ, firmados digitalmente por el Presidente de la CTAEX: - CONVENIO DE PRÁCTICAS NO LABORALES EN EMPRESA - SOLICITUD DEL SERVICIO DE HABILITACIÓN FUNCIONAL Por cierto, nos parece muy buena iniciativa la de las prácticas no laborales, eso sí, habría estado bien que nos hubieseis informado al respecto con algo de antelación. En cuanto a la solicitud de HF, pues registrarlo vosotras como teníais previsto y si requieren alguna otra documentación, pues que nos la pidan. No obstante, cuando os sea posible, enviarnos igualmente el informe de psiquiatría." ··························· Correo-respuesta de Eva Álvarez: "Tienes razón al respecto de lo de informar con lo de las prácticas. En verdad estamos probando con él todo lo que se nos puede ir ocurriendo que le beneficie, porque realmente le cuesta muchísimo enganchar con cualquier cosa. Te voy informando conforme vaya sabiendo más."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-01-26','Ana: Hablo con Estrella Durán, TS CSS, y, en ausencia de Alberto, autorizo a la compra de ropa (40€). Envío correo a la sección ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-01-26','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com) con sentencia de los dos últimos juicios. En ambas sentencias, a pesar de los hecho probados de los delitos leve por maltrato/lesiones, ABSUELVEN a Adrián por presentar Discapacidad Intelectual leve "que le impide tener suficiente juicio crítico..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-01-27','-Email de TS del ESM, queda todo gestionado para la solicitud de plaza en CRR por emergencia social : Hola buenos días ,ya mande ayer a la comisión la solicitud ,no puse grado de dependencia porque lo desconocía, puse el numero de expediente con la que se registro y que me fue facilitado por TS del Oliva ,ya comprobaran el grado ellas de oficio o si me llaman como para otros caso yo se lo indico . en cuanto a la cita no te preocupes ya he puesto en el informe que antes la imposibilidad de un traslado se realiza con información, tanto de la TS de los SSB de la Oliva ,como con documentos mandados por vosotros . seguimos en contacto y ya te informo cuando reciba la resolución .puse en la solicitud las preferencia de sitio como me indicastes Merida ,olivenza ,Caceres ,plasencia .seguimos en contacto . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='SANDEZ'and apellido2='MAMAJON'),'2023-01-27','Se comunica a esa Comisión Tutelar de Adultos que el interno Manuel Sández Mamajón ingresado en este Centro Socio Sanitario y tutelado por esa comisión , será trasladado al Hospital de Mérida en fecha 26 de enero de 2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2023-01-30','miguel, envío email a Teresa Muelas y Amelia: Buenos días, el viernes 27-1-2023 he firmado la ratificación de la herencia de Brihuega, ante el notario Don Gonzalo Fernández Pugnaire de Mérida con número de protocolo 80. Entiendo que Teresa ya puede iniciar los trámites judiciales para solicitar la aprobación de la herencia y la autorización de la venta, cuyas condiciones serán a precio superior al valor de la tasación que habrá de realizarse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2023-01-27','iguel, envío email a Teresa Muelas y Amelia: Buenos días, el viernes 27-1-2023 he firmado la ratificación de la herencia de Brihuega, ante el notario Don Gonzalo Fernández Pugnaire de Mérida con número de protocolo 80. Entiendo que Teresa ya puede iniciar los trámites judiciales para solicitar la aprobación de la herencia y la autorización de la venta, cuyas condiciones serán a precio superior al valor de la tasación que habrá de realizarse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-01-30','Maite: la situación de Marta en Pelñalsordo ha empeorado en las últimas semanas. Ha habido acgresión por parte de su novio. Se ha ido a vivir con su madre a Cabeza del Buey. Desde FUTUEX envian mail informando del seguimiento realizado: Buenas tardes, el pasado martes se realizó seguimiento en Cabeza del Buey a Marta Rivera, a consecuencia de las graves circunstancias que se habian producido con el novio en Peñalsordo, os contamos mas detallas las gestiones realizadas: Se realiza visita presencial a Plena Inclusión Cabeza del Buey, según estaba planificado, para recoger información en relación a la situación de Marta Rivera Núñez. El viernes 20 de enero, Marta comunica que ha sido agredida con violencia por su pareja en Peñalsordo, muestra un golpe en la zona femoral izquierda (muslo externo) y que ha recibido varios golpes en la cabeza. Desde Plena Inclusión se le acompaña al centro de salud donde se activa el protocolo de violencia de género y se valoran, mediante exploración, sus lesiones causadas. Desde allí mismo se traslada aviso a la guardia civil, aunque Marta de poner denuncia personalmente, algo que no pudo hacer al encontrarse cerrado el cuartel. Desde la comisión tutelar, en comunicación vía telefónica el mismo viernes, se autoriza a que Marta, que ya ha expuesto que No regresa a Peñalsordo ante la situación ocurrida, se marche con su madre, que dice acogerla de buen grado, antes que su hija se vea en la calle o viviendo con su otra hermana (Estefanía) en una vivienda propiedad de la familia materna. En la visita, Marta acude al despacho de la trabajadora social con su madre (Carmen). Ella nos comenta que ha pasado un fin de semana algo más tranquila y que no ha recibido llamadas ni de su suegra o su expareja. Pero, para sorpresa de los presentes, su tema de conversación en relación a lo que ella expuso el viernes, ahora su preocupación es: que le retiren cuanto antes los 100 euros a su suegra, que le entreguen a su madre esa ayuda, pero mayor asignación. Y por qué motivo no puede ser autorizada a salir en los diferentes reportajes que se hacen en centro, como si ella no saliera, de propia voluntad en redes sociales. Y también protestaba porque no puede salir sola cuando hay descanso en centro ocupacional (le da casa mas prioridad a estas demandas, que a la agresión, entendible en el contexto de su nivel de capacidad intelectual) Se le explica que el motivo que nos ha llevado a esta reunión es otro más grave, que implica terminar de gestionar varios asuntos muy importantes: Como seria poner la denuncia ante la guardia civil que el viernes no se hizo. No se pudo realizar por encontrarse el puesto de la guardia civil cerrado, con ella acudimos a poner la denuncia, algo que no se ha podido realizar ya que el cuartel se encuentra cerrado. Se nos informa que hasta turno de tarde no se abre, pues están realizando controles fuera de la población. Por tanto, queda pendiente de poner dicha denuncia, aunque observamos que marta no muestra mucha preocupación. Ella ya está en Cabeza del Buey que era algo que venía demandando. Nos indicaron que se haria en los proximos dias que abra, damos por hecho, que la habran acompañado desde el centro, pero nos aseguramemos si ha sido asi. Empadronamiento en el ayuntamiento. Que se adjunta Darse de alta en centro de salud y nueva asignación de médico. Se realizó en este seguimiento. Solicitar reunión con la trabajadora social para protocolo a seguir por violencia de género. (No nos pudo atender la del centro de salud) Comprar nueva tarjeta móvil y romper la que ahora tiene. Que se realizó y se adjunta el número. Acudimos a una tienda para adquirir nuevo número de móvil (624243103). En el centro se ha procedido a realizar el cambio y romper la anterior. Dar de baja a su perro en el veterinario de Cabeza del Buey. (se lo queda su expareja en Peñalsordo). Nos indicó que irian la madre y ella, en proximos dias. Y poder planificar, mediante autorización de la comisión, ir a Peñalsordo para recoger su ropa y objetos personales. Esto está pendiente en función de lo que se decida desde la comisión. Marta sigue insistiendo que se anule el ingreso económico de colaboración a su suegra (100 euros) y que se haga a partir de febrero a su madre, para ayuda en los gastos mensuales, pero que 100 euros es poca cantidad, que deben de subir dicha asignación. Le explicamos que solicitar subida, no es para que su madre le entregue a Ella para gastos, pues sus gastos de bolsillo están cubiertos y se le van entregando semanalmente. Algo que no acepta de buen grado, pues se queja de poca cantidad y de nuevo, desea salir sola por el pueblo, en horario del centro. Le exponemos que ahora es el momento menos indicado, que debe salir con su madre o con monitores durante un tiempo, para evitar cualquier encuentro con su expareja. El 14 de diciembre estuvo, acompañada desde centro ocupacional, a consulta de planificación familiar. De manera voluntaria solicitó y ya se le ha puesto un implante subcutáneo, de duración tres años. Su próxima revisión será anual, en enero de 2024. Está pendiente citación a psiquiatría, una vez se ha dado traslado de infanto- juvenil a adultos. Tanto Marta, como el propio centro, exponen la necesidad de recoger su ropa y objetos personales que han quedado, tanto en casa de su suegra como en caso de su expareja. Que es algo que urge, ya que no tiene nada y su madre y hermana le están prestando cosas.La convivencia con su madre, de momento, son solo unos días los que lleva, está siendo normalizada, pero con los antecedentes ocurridos, (la pareja de su madre) que sigue residiendo en la misma vivienda, no se descarta posibles conflictos. Lo mismo si viviera con su hermana Estefanía, en la otra vivienda familiar, persona con una vida desorganizada. Ya que Marta, necesita tener normas y apoyo diario, alejarse de situaciones conflictivas, que es lo que ha estado viviendo últimamente. Se planificar para las proximas semanas otro seguimiento. Si no hablamos, buen finde!!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-01-30','TERESA Se realiza visita presencial a Plena Inclusión Cabeza del Buey, según estaba planificado, para recoger información en relación a la situación de Marta Rivera Núñez. El viernes 20 de enero, Marta comunica que ha sido agredida con violencia por su pareja en Peñalsordo, muestra un golpe en la zona femoral izquierda (muslo externo) y que ha recibido varios golpes en la cabeza. Desde Plena Inclusión se le acompaña al centro de salud donde se activa el protocolo de violencia de género y se valoran, mediante exploración, sus lesiones causadas. Desde allí mismo se traslada aviso a la guardia civil, aunque Marta de poner denuncia personalmente, algo que no pudo hacer al encontrarse cerrado el cuartel. Desde la comisión tutelar, en comunicación vía telefónica el mismo viernes, se autoriza a que Marta, que ya ha expuesto que No regresa a Peñalsordo ante la situación ocurrida, se marche con su madre, que dice acogerla de buen grado, antes que su hija se vea en la calle o viviendo con su otra hermana (Estefanía) en una vivienda propiedad de la familia materna. En la visita, Marta acude al despacho de la trabajadora social con su madre (Carmen). Ella nos comenta que ha pasado un fin de semana algo más tranquila y que no ha recibido llamadas ni de su suegra o su expareja. Pero, para sorpresa de los presentes, su tema de conversación en relación a lo que ella expuso el viernes, ahora su preocupación es: que le retiren cuanto antes los 100 euros a su suegra, que le entreguen a su madre esa ayuda, pero mayor asignación. Y por qué motivo no puede ser autorizada a salir en los diferentes reportajes que se hacen en centro, como si ella no saliera, de propia voluntad en redes sociales. Y también protestaba porque no puede salir sola cuando hay descanso en centro ocupacional (le da casa mas prioridad a estas demandas, que a la agresión, entendible en el contexto de su nivel de capacidad intelectual) Se le explica que el motivo que nos ha llevado a esta reunión es otro más grave, que implica terminar de gestionar varios asuntos muy importantes: Como seria poner la denuncia ante la guardia civil que el viernes no se hizo. No se pudo realizar por encontrarse el puesto de la guardia civil cerrado, con ella acudimos a poner la denuncia, algo que no se ha podido realizar ya que el cuartel se encuentra cerrado. Se nos informa que hasta turno de tarde no se abre, pues están realizando controles fuera de la población. Por tanto, queda pendiente de poner dicha denuncia, aunque observamos que marta no muestra mucha preocupación. Ella ya está en Cabeza del Buey que era algo que venía demandando. Nos indicaron que se haria en los proximos dias que abra, damos por hecho, que la habran acompañado desde el centro, pero nos aseguramemos si ha sido asi. Empadronamiento en el ayuntamiento. Que se adjunta Darse de alta en centro de salud y nueva asignación de médico. Se realizó en este seguimiento. Solicitar reunión con la trabajadora social para protocolo a seguir por violencia de género. (No nos pudo atender la del centro de salud) Comprar nueva tarjeta móvil y romper la que ahora tiene. Que se realizó y se adjunta el número. Acudimos a una tienda para adquirir nuevo número de móvil (624243103). En el centro se ha procedido a realizar el cambio y romper la anterior. Dar de baja a su perro en el veterinario de Cabeza del Buey. (se lo queda su expareja en Peñalsordo). Nos indicó que irian la madre y ella, en proximos dias. Y poder planificar, mediante autorización de la comisión, ir a Peñalsordo para recoger su ropa y objetos personales. Esto está pendiente en función de lo que se decida desde la comisión. Marta sigue insistiendo que se anule el ingreso econó