insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-01-30','Maite: he comunicado a la sección eco que se suspenda la transferencia mensual de 100€ que se hacía a la suegra de Marta. Ya lo ha hecho Oscar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2023-01-30','TERESA Me llama la tecnico PIA Mariu 20219, para preguntar si ATi se ha casado pues esta viendo su expediente y para el estudio económico necesita saber este dato Me confirma Olga la ts del pueblo que se ha casado el día 23 de enero. Vamos a intentar convencerle para que acepten la vinculada de ayuda a domicilio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2023-01-27','TERESA he llamado a Ildelfonso, le he explicado muy brevemente que desde el ayuntamiento no se le puede conceder nada de lo que plantea, por superar los límites económicos. Le comento que le ingresais 650 € más todos los gastos relacionados con la vivienda,... y me comenta que así es, pero que por el "litigio" vais a dejar de pagarlo... le indico que eso no será así, que seguirá ingresando cantidades similares ... y me dice; "ALBRICIAS" (a voces) . He tenido que buscar en google lo que significa, jiiii. Se ha quedado más tranquilo. Comenta que esos 650 € de enero, lo han usado para la boda. Ahora me ha llamado el párroco para comentarme que ha ido a pedir dinero a la parroquia y a caritas. No para este hombre. Y si se han casado, me lo han confirmado, el 23/01/2023. Y ha tenido de testigo a dos personas del pueblo. Solo te lo comento para confirmar lo que hemos hablado. Ahora surge otro problema, ella cobra PNC y debe de comunicar el cambio de circunstancia en 1 mes, lo trataré con ella la semana que viene. ya cuando hayan cobrado y esté más tranquilo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2023-01-30','TERESA TERESA: NO ES POSIBLE SUBIR LA ASIGNACIÓN EN EL IMPORTE QUE SE PRETENDE YA QUE EL SALDO ANUAL SERÍA NEGATIVO EN -1.000 €. X TANTO: • SUBIMOS ASIGNACIÓN SEMANAL EN 10 €, DE FORMA QUE PASARÁ A 60 €/SEMANA (260 €/MES). • TE RECUERDO 2 CUESTIONES: o TIENES EL LÍMITE ANUAL DE 745 €/MES...A DÍA DE HOY SÓLO QUEDAN 630 €. o ESTAMOS COMPROBANDO LOS CONSUMOS MENSUALMENTE....SI SUPERAN LOS 75 €/MES MINORARÁ EL LÍMITE ANUAL EN ESOS IMPORTES. OSCAR: SUBIMOS REINTEGRO SEMANAL A 60 €/SEMANA A PARTIR DE 06/02/2022','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2023-01-30','TERESA Jose maría esta muy flojo, apenas se levanta del sillon y creemos que ni se acuesta. tiene el orinal al lado del sillón, la mitad de las veces se le cae el orinal,... en fin, esperemos que no tarde mucho las gestiones, ya me cuentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-01-30','TERESA informarte que a Tomas lo han ingreso en unidad de psiquiatria de Hospital de Llerena. Por lo visto ha entrado en centro de salud insultando a psiquiatras. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2023-01-30','TERESA SE TRASALDA M ANTONIA AL HOSPITAL SANTIAGO DE ZAFRA OCUAPNDO PLAZA PRIVADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-01-31','Ana: Recibimos Cédula de Citación para otro juicio por delitos leves para el día 28/03/23 a las 12:30 h. Citan a la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-01-31','miguel, email del notario de los Santos, jaduro@despacho.notariado.org : Buenos días, Miguel. ¿Sabes si ya se han ratificado por parte del SEPAD las dos escrituras de Compraventa de MARÍA ISABEL MORENO FOLLARAT, firmadas el pasado 15 de diciembre?, cuyas copias simples te envié al día siguiente. Mientras no recibamos las ratificaciones, no podemos presentar las escrituras de Compraventa en el Registro de la Propiedad para su inscripción. ************************************************** Llamo al juzgado de Villafranca 1, me dicen que se lo dieron al procurador el 9-1-23 (testimonio emitido el 23-12-22). ***************************************************** Llamo al Procurador Pedro Redondo Miranda, Pedro Redondo Miranda >predondo@badajoz.cgpe.net>, 924 52 47 57, Mientras ratificamos las ventas porfavor dígale a D. Angel Garcia Calle que agilice la solicitud de subsanación de la escritura de herencia indicada por el notario Don Carlos Duro Fernández, y cualquier duda que hable directamente con él. ********************************************************** Envío email al notario de los Santos de Maimona, Don Carlos Duro Fernández: Buenos días Don Carlos, acabo de recibir el testimonio. Voy a agilizar las dos ratificaciones de venta. Como puede ver en el email que adjunto debajo, he indicado al procurador que hable con el abogado para agilizar la subsanación. ***************************************************** Tras enviar la documentación a José Luis de la notaria de Mérida, me pide el certificado literal de nacimiento, y tras solicitarlo via online (mediante certificado electrónico), en el mismo compruebo que no hace mención de la identificación del procedimiento judicial y de quién ejerce el cargo de tutor por lo que envío email al registro civil de zafra, registrocivil.zafra@justicia.es: Buenos días, tras solicitar certificado de nacimiento, en el que no figura el procedimiento de incapacitación, ni quién ejerce el cargo de tutor. Solicito nos remitan certificado de nacimiento de la tutelada por esta Comisión Tutelar de Adultos Doña Isabel Moreno Follarat, donde conste que está tutelada conforme el procedimiento de incapacitación 56/2001 del juzgado de 1º instancia e instrucción nº1 de Villafranca de los Barros, y que dicha tutela está siendo ejercida por la Comisión Tutelar de Adultos de la Junta de Extremadura. El motivo es por exigencia de la notaria de Mérida del notario Don Gonzalo Fernández Pugnaire, siendo la finalidad la firma de venta de inmuebles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-01-24','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Comentarte que han influido varias circunstancias a la hora de que ocurra esta situación, en una ocasión fue problema de agenda por nuestra parte, en otra dificultades de José Manuel para movilizarse fuera del recurso. De hecho íbamos a comentaros precisamente la opción de ver la valoración del CADEX por si era posible solicitar la PNC. Hace poco ha sido valorado por dependencia y de hecho se está haciendo una valoración más exhaustiva de determinados síntomas a nivel cognitivo que se observan y que dificultan la intervención y evolución en el CRR. Cada vez es más difícil atender a José Manuel de la manera que él necesita desde nuestro recurso. De hecho se está valorando también la elección posible de residencia de mayores en relación a la consecución de grado II. Creo recordar que hablamos también de la situación de la tutela de José Manuel, puesto que era un poco especial, la semana pasada nos dijeron desde el dependencia que estaban intentando ponerse en contacto con la hermana para que le ayudara a elegir residencias. Comenté a mis compañeras la situación especial de José Manuel, en la que en caso de necesitar "apoyos" por estar "en crisis" sería la comisión de tutela quien ejercería esa función, aunque esto no quita que su hermana pueda ayudarle, por el vínculo y la importancia que para José Manuel tiene ésta, a elegir las que más le interesaran. Aparte de que nosotras mismas podemos ofrecer nuestro apoyo si así lo requiere. Lamentamos lo que ha ocurrido respecto a la demanda de empleo, se solucionó en cuanto se detectó. Desde el SEXPE no entendían las dificultades de José Manuel para ir a sellar y mostraron muchas reticencias a nuestro acompañamiento a la hora de entrevistarle y rellenar documentación, hasta que vieron sus dificultades. Aún así es importante poder valorar como apuntas y nosotras habíamos pensado también, poder solicitar otro tipo de ingresos que puedan compatibilizar más con su situación actual, puesto que no dependerían de un externo o de sus condiciones en el momento para poder percibir la cantidad correspondiente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-01-31','Ana: Envío correo-respuesta al correo de Paula del día 24: "Con respecto a este asunto, decirte que hasta que no sepamos si a José Manuel le puede corresponder una Pensión Contributiva, no vamos a renunciar al Subsidio por Desempleo, pues si finalmente le correspondiera, una vez cumplida la edad tendría mayores ingresos y 14 pagas en lugar de 12. Y para ello requiere seguir cotizando (con el subsidio cotiza a la Seguridad Social) Por ello, la semana pasada estuve intentando, vía teléfono, conseguir información del INSS, sobre el tiempo cotizado por José Manuel, pero los intentos y las múltiples llamadas fueron en vano. Así pues, envié un escrito a la Dirección Provincial del INSS solicitando nos remitan un Informe de Vida Laboral, pues telemáticamente nosotros no tenemos acceso. En cuanto la recibamos y podamos constatar si le corresponde o no, decidimos si solicitar la PNC, pues es su caso, excepcionalmente, le correspondería."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-01-27','Ana: Soraya comunica a Maite que Aarón ingresará próximamente en la UHDAC. Aún no se sabe fecha exacta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-01-31','Ana: Subo al portafirmas digital SOLICITUD DE VALORACIÓN INICIAL DE DEPENDENCIA. ···························· Envío a Cruz Merino, TS de la Mancomunidad Tajo-Salor (cruzmerino@tajosalor.es), el Cdo. Actualizado de la Pensión de Jubilación, que nos han remitido desde el INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-01-31','Ana: Llamada de Doroteo (609 928 621): se le han roto dos muelas y tienen que hacerle también una endodoncia. Ha tenido cita en una clínica dental de Alcuéscar, peo dice que le han dado un presupuesto muy caro y quiere pedir otros en otras clínicas dentales en Cáceres. El día 6 podrá ir con trasporte del Centro a que le vean y le faciliten presupuestos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-01-31','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "volvemos a contactar para rectificar fechas de salida de Julia Morón, disculpadnos. Me confirman las compañeras que finalmente será del 2 al 6 de Febrero."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-01-30','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "comentaros que Julia ha planificado salir al domicilio familiar del 2-5, ella deseaba irse y hemos negociado el número de días para tratar de facilitar una mejor experiencia en el domicilio. Si por vuestra parte no hay problema, se irá el martes y volverá el domingo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-02-01','Ana: Envío correo a Alberto, jefe secc. ecca.: "En relación a José Manuel Romero Mediavilla, he acordado con él, que se le dará este mes 15€ para abonar la tarjeta del autobús con el compromiso por su parte, a cambio, de asistir a la Entidad de Salud Mental Feafes-Extremadura. Si este mes lo incumple y no asistiera con regularidad, no se le dará los próximos meses." ······································································································································································································ Correo de Toni-Futuex con seguimiento: "Desde la visita presencial, está todavia más demandante e incluso violento. En todo momento, José Manuel, demanda mayor asignación, ya que lo que retira cada quince días, se lo gasta casi en su totalidad en tabaco, con lo cual ya no hay dinero para nada más. ... Así es su día a día, demandando dinero constantemente, acude, sin citas, a centro de salud, a salud mental, o realiza llamadas constantes. ... Unos días nos comunica que tiene cita con trabajadora social ante la solicitud de una vivienda social más adaptada (ya que vive en un piso cuarto sin ascensor) y con sus 138 kilos y siendo gran fumador, le dificulta físicamente. Otros días, solicita salir de Cáceres y obtener plaza en algún centro, pues ya no soporta ni a su hijo ni a su hermano. O que le echan del video club, suele ir todos los días, por lo que nos explica, la mayoría sin dinero, y no le pueden dejar las películas prestadas. Ante este hecho, reacciona con mucha violencia verbal, hasta el punto de que tuvimos que colgar la llamada. ... En el día de hoy, miercoles 01 de febrero, expone y demanda un extra de 15 euros para tarjeta de bono bus y así poder participar en el programa de actividades que organiza Feafes-Extremadura programa de integración social, en la zona llamada del embarcadero y allí José Manuel dice que tiene que desplazarse en bus urbano, (esto es cierto que para ir necesitaria bus..." ····· Guardo correo en PDF en el expdte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-02-01','Ana: Nos comunican desde la UPA que han acordado con Plena Inclusión Zafra, que el cambio de recurso se realice de forma progresiva, para una mejor adaptación de Reme.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-02-01','-Amalia : Escribo a los jefes de sección sobre este caso: Buenos días , el tema del ingreso se está demorando demasiado ,yo ya he advertido del peligro que supone que Alejandro continúe en su casa , tanto para él como para sus familiares y vecinos . No termina de ingresar en la UHDAC , que se ha valorado el recurso más idóneo y sigue en lista de espera. El tema económico , en mi opinión habría que intentar subir la asignación y darle una de las extras si es posible . No sé como estarán sus cuentas actualmente , puede que ésto no sea viable porque se pagan multas . Pero desde luego , lo que pide la familia de la totalidad de los ingresos no se le puede dar . Si no están conformes que acudan al juzgado como ya se les ha planteado en innumerables ocasiones. También pueden asumir ellos el cargo y podrían decidir sobre todos esos aspectos. Se lo derivo también a Alberto para que lo puedan valorar. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2023-02-01','Ana: Correo de Ángel, A. Jurídico: "Me ha llamado Marisa, una antigua compi que tuvimos en la Comisión y que se fue a Cáceres. Trabaja en mútiples, donde también esta José Moreno Moyano. Va todos los días a hablar con ella para pedir cualquier cosa que necesita de la Comisión. En este caso es el estado en el que se encuentra la habitación del Hotel Palacete Alameda, de Cáceres, donde vive. Como ves en las fotos, tiene muchas humedades. También comenta que la calefacción solo se la ponen de 3 a 6 de la tarde y pasa mucho frío." ····················· Reenvío correo a Toni-Futuex, y solicito que hagan seguimiento a la mayor brevedad. Que comuniquen la necesidad de poner más horas la calefacción y ver opciones de mejora o cambio de habitación. En caso de no ser posible, comenzar a buscar otro alojamiento alternativo. ····················· Correo de Toni, al parecer José lleva semanas solicitando irse a vivir a un piso de alquiler. *Dado los antecedentes no consideramos que sea lo más recomendable. *Guardo el correo de seguimiento en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-02-01','-Amalia : Escribo a los jefes de sección sobre este caso: Buenos días , el tema del ingreso se está demorando demasiado ,yo ya he advertido del peligro que supone que Alejandro continúe en su casa , tanto para él como para sus familiares y vecinos . No termina de ingresar en la UHDAC , que se ha valorado el recurso más idóneo y sigue en lista de espera. El tema económico , en mi opinión habría que intentar subir la asignación y darle una de las extras si es posible . No sé como estarán sus cuentas actualmente , puede que ésto no sea viable porque se pagan multas . Pero desde luego , lo que pide la familia de la totalidad de los ingresos no se le puede dar . Si no están conformes que acudan al juzgado como ya se les ha planteado en innumerables ocasiones. También pueden asumir ellos el cargo y podrían decidir sobre todos esos aspectos. Se lo derivo también a Alberto para que lo puedan valorar. Un saludo','1');
