insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-01-31','Ana: Envío a Julio, Aux. Adtvo. CTAEx, SOLICITUD de Valoración de Dependencia, para solicitar traslado de centro junto al Informe Social (Anexo IV), el Informe de Salud (Anexo II) e Historia Clínica Resumida, para que registre en SIREX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-02-01','-Amalia : Emi deja el CRR de forma voluntaria , conlleva la pérdida de la plaza en Olivenza. Se ha ido a vivir con Miguel Angel a Don Benito. Se le cambia la autorización bancaria para que saque los 78€ semanales allí. Hola Raquel, como ya habéis presentado la propuesta para perdida de plaza, que está pendiente de valorar por la Comisión, al haberse marchado voluntariamente del recurso, si hubiese firmado la renuncia ya estaría, pero como no ha sido así, contamos desde hoy 15 días, sino regresa se le da de baja por ausencia prolongada no justificada. De todas formas, aunque regrese voluntariamente, vuestra propuesta será estudiada. Es decir, ahora puede perder la plaza por dos vías, la aceptación de la propuesta por la Comisión o por ausencia prolongada. Si hay novedades nos vais informando. Saludos,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-02-01','Ana: Correo de Alberto, jefe secc. ecca.: "ABONAMOS LO QUE NOS RESTA PARA LA EDICIÓN DEL LIBRO DE CEFERINO, TAL Y COMO NOS INDICA EL CORREO DE LA EDITORIAL QUE NOS REMITE ÁNGEL."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-02-01','-Amalia : Emi deja el CRR de forma voluntaria , conlleva la pérdida de la plaza en Olivenza. Se ha ido a vivir con Miguel Angel a Don Benito. Se le cambia la autorización bancaria para que saque los 78€ semanales allí. Para el mes que viene pasa a la zona de Tere , ya avisada . La derivo tb a Futuex . Pido a Julio cambio en la base. Hola Raquel, como ya habéis presentado la propuesta para perdida de plaza, que está pendiente de valorar por la Comisión, al haberse marchado voluntariamente del recurso, si hubiese firmado la renuncia ya estaría, pero como no ha sido así, contamos desde hoy 15 días, sino regresa se le da de baja por ausencia prolongada no justificada. De todas formas, aunque regrese voluntariamente, vuestra propuesta será estudiada. Es decir, ahora puede perder la plaza por dos vías, la aceptación de la propuesta por la Comisión o por ausencia prolongada. Si hay novedades nos vais informando. Saludos,','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-01-26','Ana: Guardo en el expdte. digital, el informe de alta del Serv. de Psiquiatría remitido por Paula, TO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-01-30','Ana: Óscar confirma que ya han hecho la autorización general al CSS, para que puedan retirar el efectivo que pueda necesitar Desideria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-02-01','-Amalia : Emi deja el CRR de forma voluntaria , conlleva la pérdida de la plaza en Olivenza. Se ha ido a vivir con Miguel Angel a Don Benito. Se le cambia la autorización bancaria para que saque los 78€ semanales allí. Para el mes que viene pasa a la zona de Tere , ya avisada . La derivo tb a Futuex . Pido a Julio cambio en la base. Hola Raquel, como ya habéis presentado la propuesta para perdida de plaza, que está pendiente de valorar por la Comisión, al haberse marchado voluntariamente del recurso, si hubiese firmado la renuncia ya estaría, pero como no ha sido así, contamos desde hoy 15 días, sino regresa se le da de baja por ausencia prolongada no justificada. De todas formas, aunque regrese voluntariamente, vuestra propuesta será estudiada. Es decir, ahora puede perder la plaza por dos vías, la aceptación de la propuesta por la Comisión o por ausencia prolongada. Si hay novedades nos vais informando. Saludos,','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-02-01','Ana: envío correo a Alberto, Óscar, Ángel y Miguel - CTAEx: Os reenvío correo del C. Sociosanitarios, con documento relativo a una DERRAMA que hay que abonar a la comunidad de vecinos de su vivienda. ······································································································································································································ Comunico a Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es): que desde la secc. ecca. ya enviaron la autorización gral. para retirada de efectivo para Desi, mientras ésta resida en el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='TORES'and apellido2='NUÑEZ'),'2023-01-30','Ana: Correo de Mª Victoria Clemente, TS CSS (victoria.clemente@salud-juntaex.es); " Con fecha de ayer fue trasladado al HVP el Paciente Julián Torés Núñez. Según el médico de guardia de este CSS su estado , ayer, no revestia gravedad, hoy aún no tenemos información de su evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-01-31','Ana: Correo de Leire Sanz Gay, TS - Centro de Mayores Ciudad Jardín Cánovas (t.socialcanovas@grupociudadjardin.com): "VIENE DE ALTA EL DÍA 27 DE ENERO, A SU LLEGADA HEMODINAMICAMENTE ESTABLE PERO CON DOLORES,SE NIEGA A COMER, ESTÁ CON BATIDOS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-01','Ana: Me comunica Óscar, secc. ecca., que ha hablado con Francisco, Agente Financiero de la Sucursal Bancaria de Alcuéscar de la Entidad Unicaja, le ha dicho que cree que Saturnino está descompensado, ya ha montado más de un escándalo en la sucursal a lo largo de las dos últimas semanas, ayer no estaba él y se la formó a la compañera, ésta llegó a pasar miedo. Le van a prohibir la entrada. Sólo le dejarán entrar los lunes para su retirada de asignación semanal (50€). ···· Por su actitud, que ha cambiado radicalmente, cree que ha vuelto a consumir. ········· Fco. dice que no quiere denunciar ni activar el 112. ·············· Lo comunico a Toni de Futuex, para que hagan visita de seguimiento y entrevisten también a las personas referentes en el pueblo. Además de consultar a la Policía y a la TS por si fueran conocedores de otros incidentes en la localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-02-01','TERESA CONFORME A LA NUEVA SITUACIÓN DE DIEGO (X EL CAMBIO DE LA AYUDA A DOMICILIO), SE PROPONE SUBIR LA ASIGNACIÓN MENSUAL: • ACTUALMENTE TIENE 280 €/QUINCENA (560 €/MES) • CON LOS EXTRAS HABITUALES QUE SE LE CONCEDEN LA ASIGNACIÓN MENSUAL REAL ALCANZA LOS 600 €/MES. . QUE TE PARECE SI LE DAMOS 330 €/QUINCENA (660 €/MES)??? . PLANTEATE LA OPCIÓN DE ABONARLE SEMANALMENE: EN ESTE CASO SERÍAS 153 €/SEMANA...ESTO LO DECIDES TU (PROBABLEMENTE CONSEGUIRÍAMOS QUE SOLICITASE MENOS EXTRAS)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-01-27','Ana: Correo de Pilar Martín, TS ESM-CC: "paciente tutelado por vosotros, Juan José Bergantiño Gónzalez, me propone solicitar PS, ahora se encuentra en CRR. (Caso que el psiquiatra lo considere me llamas para ver como lo gestionamos)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-02-01','Ana: Envío correo de Pilar Martín, TS ESM-CC (pilar.martinp@salud-juntaex.es): "...pasó del CRR de Badajoz al Piso Supervisado de Cáceres en verano de 2020. Pero, debido a los problemas de la entidad que lo gestionaba (FEAFES CÁCERES), como sabéis el piso se cerro y por eso lleva este tiempo en el CRR de Cáceres. ¿Se va a abrir un piso nuevo en esta localidad? Si es así, por nuestra parte no hay problemas, además podría firmarlo él solo (eso sí, habrá que tener el cuenta, entiendo yo, el criterio técnico del CRR, sobre su evolución y autonomía)."','2');
