insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-02-01','Ana: Correo a Pilar Martín, TS del ESM-CC: "...aprovecho para consultarte sobre otro expediente: JOAQUINA MAYORAL PIZARRO, ¿podrías decirme cuándo tiene la próxima cita de Psiquiatría y si no es próxima en fecha, cómo podríamos intentar adelantarla? Me comunica la compañera del SSASB de referencia (Miajadas) que muestra signos de posible descompensación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-01-27','Ana: Correo de Óscar, secc. ecca. a la farmacia de la localidad (ltemplado_1607@hotmail.com): "Necesitaríamos saber si el coste del tratamiento es de 198€ mensuales, ya que en ese caso no tiene disponibilidad económica para llevar a cabo el mismo."','2');
