insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-02-02','Ana: correo de Isabel, le dieron el alta ayer. ········ Con respecto a las cuestiones que plantea (asignación, extra, compra de móvil y salida a Trujillo) le remito a las profesionales del CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2023-01-30','Ana: Correo de Sheila Rodríguez, Directora del CRR-CC (crr@grupociudadjardin.com): "Os escribimos para informar sobre la última incidencia en relación a Juan Mario San Román Blasco. El pasado viernes 27 de enero contactó con nosotros el personal de psiquiatría de la UME para transmitirnos que habían abordado con Juan Mario una nueva estancia de unos días en el centro. Desde el CRR se les transmite las dificultades de Juan Mario mostradas en el último permiso recibido y desde el conocimiento del paciente, de la patología, de sus dificultades y sus potencialidades, consideramos precipitado un nuevo permiso con pernocta en el CRR, considerando que el último fue a fecha de 5 de enero de 2023, teniendo que regresar de vuelta antes de tiempo, el día 6 de enero de 2023, tras el incidente ocurrido que requirió incluso atención médica. A pesar de esto, desde la UME se continua insistiendo en la salida de Juan Mario. Al no llegar a ningún acuerdo entre los dos recursos, desde la UME plantean una próxima llamada. Transmitiros nuestra preocupación al respecto por las posibles incidencias/consecuencias que pueda tener en Juan Mario una salida planificada de manera precipitada con las limitaciones de manejo que presenta la estructura del CRR, sin que exista una estabilización en la persona y con dificultades de control de impulsos de escasa planificación a corto/medio plazo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-02-01','Ana: Correos de Leyre Sanz, TS - Centros de Mayores Ciudad Jardín Cánovas (t.socialcanovas@grupociudadjardin.com / 927 223 221): "ME ACABA DE LLAMAR UNA DE LAS SOBRINAS DE MARIA JIMNEZ PICON, CARMEN JIMENEZ QUE VIVE AQUI Y VIENE A VISITARLAS. SU TELEFONO ES 639503536, PARA QUE EL DIERA EL DNI PARA DAR DE BAJA A LA LINEA DE TELEFONO DE CASA DE MARIA E ISABEL ,QUE ESTÁ PAGANDO TODOS LOS MESES 48 EUROS, ESTA COMO TITULAR EN LA LINEA MARIA LE COMENTADO QUE ME PONÍA NE CONTACTO CON LA COMISIÓN TUTELAR PARA VER COMO PROCEDER A DAR DE BAJA A LA LINEA EN EL 10004." ········ "LES HAN DEBIDO DE LLAMAR DE 1004 Y LE HAN DICHO QUE LA LINEA ESÁ DESFASADA, NO SE EL CASO,SERÍA DARLE DE BAJA PARA QUE NO SIGA PAGANDO." ················· Lo comunico a la sección ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2023-02-02','-Amalia : intenta sacar dinero sin autorización en el pueblo , se le deniega. Coordinado todo con el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2023-02-02','-Amalia : intenta sacar dinero sin autorización en el pueblo , se le deniega. Coordinado todo con el centro.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2023-02-02','-Amalia : Caso nuevo , a falta de inventario empiezo a intervenir . Contacta conmigo el centro La luz , solicitan que se quede en la plaza Madex allí . Segunda está hablando ya con Soraya , tenemos que apoyar esto. Desde menores , tutores hasta ahora del chico ,se ha pedido .Tiene pasado CADEX y dependencia , le han dado perfil RAL . Prestación : percibe PFHC de menores , me van a enviar solicitud PNC para que yo termine de cumplimentar y gestionar . Tuvo AF pero la familia renunció aunque mantienen contacto con él. Pido al centro toda la documentación , lo que más urge es el Nº de cuenta para autorizar a J. Vicente y poder gestionar la pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-02-02','Ana: Óscar, secc. ecca, me comunica que le siguen ingresando la prestación ecca. de Dependencia, en la cuenta antigua (la compartida con su hermana) a pesar de haber registrado la comunicación de cambio de cuenta en abril de 2022. ··········· Dado que ahora, con la fusión de Liberbank y Unicaja, el CCC es otro, pedirá un nuevo alta de terceros y volveremos a registrar comunicación a la Unidad de Prestaciones Económicas. ································································································································································································ Correo de Óscar, secc. ecca., en relación a la línea de teléfono: "Procedemos a solicitar la baja."','2');
