insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-02-02','-Amalia , el caso pasa a mi zona , seguimiento con Eva de P.Inclusión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-02-02','Ana: Una vez recibido el Informe de Salud pendiente, envío a Julio, Aux. Advto. de la CTAEX: "Remito, para registrar en SIREX, SOLICITUD DE VALORACIÓN DE DEPENDNECIA, relativa para MARTÍN QUIRÓS BERROCAL. Adjunto también los siguientes documentos para incluir con la solicitud: - Informe de Salud - Testimonio de Sentencia de Incapacitación y nombramiento - Testimonio de Aceptación del Cargo de Tutor" ················· *Julio confirma el registro en SIDEX. ······························································································································································································· Correo de Cruz Merino, TS de la Mancomunidad Tajo-Salor (cruzmerino@tajosalor.es): "Martín es de Piedras Albas (yo también soy la trabajadora social de este pueblo), aunque es residente en la residencia de Alcántara y tiene una vivienda de su propiedad en el municipio. Como hace muchos años que está institucionalizado, la vivienda se ha ido deteriorando por abandono. Este invierno a raíz de la lluvia, se ha caído (desprendido) un trozo de pared en el patio de la vivienda contigua y se ha procedido a iniciar una declaración de ruinas de la vivienda. Me lo comentó el alcalde el lunes y hoy me ha hecho llegar la notificación que adjunto. En estos casos no sé cómo se procede respecto a este tutelado (yo le dije al alcalde que os lo comunicaría, para que los servicios jurídicos de la Comisión tuviese conocimientos de esta situación). Si hay que hacer algo, ya me dices y si puedo ayudar pues nos ponemos mano a ello." ·················· Indico a Cruz que no podemos abrir el documento que adjunta y pido que lo envíe de nuevo a ser posible formato PDF.','2');
