insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='DELGADO'and apellido2='BERROCAL'),'2023-02-02','Ana: Conversación con Esther Trejo, TS de Alcuéscar y Aldea del Cano (927 383 125 / tsocial7@mancomunidadsierrademontanchez.es): Le informo que estamos pendiente de la firmeza de la sentencia. Se solicitó el día 11/11/22, pero el Jdo. no nos la la remitido aún. *Volverán a reiterar la solicitud de la misma. ·································································································································································································· El Sr. reside en los PISOS TUTELADOS de Aldea del Cano. Pero está cada día peor de salud y con menos autonomía. Quieren solicitarle nueva valoración de dependencia. *Le digo que mientras la sentencia no sea firme, puede firmar él mismo la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-02-03','Ana: Sigue ingresada, cree que le darán el alta entre hoy o el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-02-03','Ana: Guardo en el expediente el Informe Médico de Alta de la UHB que me remite Paula, TO CRR.: Dada la "estabilidad clínica", proceden al "alta con vigilancia domiciliaria", a pesar de objetivar "cuerpos extraños pequeños que no presentaba en rx de hace dos días por lo que presumiblemente se lo ha comido durante el ingreso", por lo que no descartan "ingestas de más objetivos".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-03','Ana: Llamada de Esther, TS SSASB Alcuéscar (927 383 125), ha recibido llamada de la Policía Local, comunicando que le han dicho que Saturnino lleva uno días "alterado" y que va por la calle con un cuchillo amenazando a la gente. Aunque ellos no lo han presenciado... Dado que ha visto en el expediente que está a cargo de la CTAEx, me lo pone en conocimiento. *Acordamos que volverá a hablar con la policía para pedir que estén pendiente para que puedan constatar hecho así, intervenir si fuera necesario y realizar informe/parte policial. ······ Indico la importancia de activar el 112 ante estas situaciones. ········ Y que desde el Gabinete Técnico de la CTAEx necesitaríamos informes en que consten los hechos para poder comunicarlo al Jdo. y solicitar internamiento involuntario si fuera preciso. ·········································································································································································································· Correo de Esther Trejo, TS SSASB Alcuéscar (tsocial7@mancomunidadsierrademontanchez.es) al final de la mañana: "Te escribo por el caso que hemos estado esta mañana hablando: SATURNINO MIGUEL SALGADO JIMENEZ. He realizado visita con policias locales, no nos ha querido abrir, se encuentra atrincherado en su vivienda, la puerta que da a las escaleras para acceder a la puerta de la vivienda se encuentra cerrada. Nos ha echado , no mantien discurso , y falta de higiene, y conducta agresiva. En conversación con la mujer del primo que ostenta el bar que se encuentra al lado del domicilio de Saturnino, nos informa que lleva dos días sin comer, que lleva alrededor de un mes muy alterado, agitado y se enfanda por cualquier motivo con agresividad verbal. Que la medicación no se la toma y que le parece que la consume como si fuera sustancias adictivas. He hablado con una de las hermanas, se encuentra también alterada, porque expresa que va a a pasar algo, no sólo con respecto a él sino con terceros, y se está convirtiendo en una alarma social. No he podido contactar con el centro médico para que me informara de su estado. NO sé si me podrías facilitar la resolución de comisión tutelar. Y por último que me indicaras la manera a proceder. Emitiré informe para Comisión Tutelar de los sucesos acontecidos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2023-02-02','Ana: Llamada de Mª Jesús Salas, familiar de Florencia (686 658 354): Comunica que el hermano de Florencia, de 87 años, tiene cada vez más dificultades, por eso ella le ayuda, no tiene más familiares. *Le han acompañado a Losar de la Vera, a la sucursal bancaria de Santander, donde al parecer ambos hermanos tienen una cuenta abierta (se desconocía en la CTAEx) para retirar efectivo, pero le han dicho que cuenta está bloqueada, puesto que el DNI de su hermana que les consta, está caducado desde 2010. ············ Pide que facilitemos el documento a la entidad bancaria para que puedan desbloquearla. ·················································· *Lo comunico a Óscar, secc. ecca., para que puedan pedir información al banco y hacer las gestiones oportunas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-02-01','Maite: He hablado con MArta. Me ha dicho que se encuentra bien.Y que está bien conviviendo con su madre. Esta mañana ha estado hbalando Julian , Guardia Civil de Cabeza del Buey, sobre la presunta agresión de su exnovio. Mas tarde Miguel ha contactdo con él para aclarar si hbaía puesto denuncia. No lo ha hecho pero él iba a a dar parte al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2023-02-02','Maite: el padre de Juan José habló con Ana para decirle que quiere pedir traslado pq Juan José le manifiesta que no quiere estar en INCLUSIVES, y el plantea que está lejos de su localidad y sólo va a casa una vez al més.También dice que Juanjo no quiere continuar en el taller de panadería del centro ocupacional. He hablado con Maribel , directora de la residencia de INCLUSIVES, para contrastar la información. Me dice que Juan JOsé está muy bien en el centro. Tiene amigos y hace muchas actividades. Salen solos por el pueblo sin problema. De hecho a veces expresa que no queire ir a casa. Marible me comenta que ha hablado con el padre en varias ocasiones pq cuando Juanjo va a casa tiene horarios desordenados( se levanta a las 5 de la tarde), no desayuna, no come, y no se toma la medicación. El padre alega que cuando va a casa está de vaciones y tiene que descansar. He quedado con Maribel en que van a hablar con Juan José para ver qué quiere hacer e´l y si quiere cambiar a otro tallle en el servicio de CO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-02-03','Ana: Lourdes, Aux. Adtvo. Secc. Ecca., me informa de que a José Manuel le han pasado un recibo de FinetWork Fibramovil, aunque supuestamente él lo canceló todo. *Lo ha devuelto. ·········· Hablo con José Manuel, ya lo sabía, insiste en que él lo devolvió. Le tranquiliza saber que se ha devuelto. ··············· Cuenta que ayer vino a Mérida y dio una vuelta por aquí. Acudió al CRR, pero dice que no le recibieron como él esperaba. ····· Le comunico que Virginia, Ed. Futuex, se incorpora ya la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2023-02-03','Ana: Subo al portafirmas digital la solicitud de valoración de dependencia por empeoramiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-02-03','Ana: Correo de Ceferino: "No quiero la controladora ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-02-03','Ana: Cruz, TS, me envía el documento de DECLARACIÓN DE RUINA de su vivienda de Piedras Albas. ························ Lo reenvío a los A. Jurídicos-CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2023-02-03','Resumen situación de Carmen: Actualmente ingresada en la R.M . de la Coronada . Los tf de contacto 924028778- corto de la Dtra. 20239 En los meses previos se organizó el internamiento involuntario con el 112 , posterior traslado a R.M , visita a domicilio con delegada tutelar y propietario del piso para recoger su ropa y dejar todo cerrado. Va adaptándose a la R.M. , a medida que su evolución lo permita se le podrá asignar algo de dinero. No se le da nada aún por evitar que se fugue de la residencia a su casa como es su deseo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2023-02-03','Ana: Llamo a Mª Ángeles, Aux. de SAD (675 264 255), en relación a los presupuestos y facturas que han remitido. Corresponde a la ropa, que ya le han entregado, le hacía falta y lo hablé yo previamente con la Auxiliar de SAD para que le acompañara a la tienda. *El cerrojo es de la puerta de casa, que está fatal. ······· El presupuesto de Electrocash corresponde a lavadoras, que necesita cambiarla, pues ha dejado de funcionar. ································································································································· Reenvío los presupuestos a Alberto, Jefe de la sección económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MAURO'and apellido2='PEREZ'),'2023-02-02','EXITUS El centro nos informa de su fallecimiento acaecido el 02/02/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-02-03','Ana: correo de Estrella, TS CSS: "Me dice Desideria que mañana sábado tiene otra reunión de la Comunidad de Vecinos, quiere asegurarse de que se ha abonado la derrama y la cuota mensual..." ·················· Mi respuesta: "En relación a este asunto, decirte que aún no se ha abonado nada. Acabo de hablar con la presidenta de la comunidad de vecinos para aclarar las notas que llevó Desi. Los Jurídicos revisarán todo la semana que viene y en cuanto den visto bueno la sección económica abonará. La reunión de vecinos me dice que es HOY no mañana. Por favor, decírselo a Desi, y que no se preocupe, que he hablado con la Presidenta y no le van a poner ningún problema."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2023-02-03','Maite: se autorizó un gasto de 480 € para ropa ( que ya han comprado). Un pago de 200€ que habia adelantado el centro y una asignación mensual de 280 €. Hoy he hablado con su trabajadora social de referencia, Elsa. Me ha dicho que Mercedes está más tranquila pero sigue con sus delirios.Hemos quedado en que en Abril pediremos informe de evolución. Opina que no está para vivir sola en domicilio. Le he explicado su trayectoria y todo lo que se ha trabajado con élla y los problemas que presenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-02-03','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "me acaban de informar que el lunes le dan el alta a Felisa si su estado es el actual."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-02-06','Ana: Llamada de Felisi (722 494 033): Ya fue a hablar con la TS del Casar y ésta le ha dicho que lo que quiere solicitar del cambio de vivienda social es muy difícil y podrías tardar muchísimos años. Así que lo ha pensado bien y quiere arreglar a su casa y volver a la misma. *El chico de la empresa de la limpieza le dijo que seguramente habrá que cambiar la lavadora y el frigorífico, pues no funcionan y "están para tirarlo" (dice que ya tienen casi 20 años). *También quiere comprar unas fundas para los sofás y cambiar la cortina de la cocina que está "llenita de grasa". ·········· Por otra parte, una vez que se vuelva a Navas del Madroño, le gustaría continuar con sus clases en Arroyo de la Luz, pues en Navas no hay. *Con apoyo del programa de familia va a comprar la tarjeta de transporte. ············· Pido a Futuex, mediante mail, que intenten agilizar las gestiones para retomar la limpieza y acondicionamiento de la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2023-02-06','tf Paco 691507827. Está llamando tanto a mí como a la sección eco para que se le de autorización para sacar más dinero . Se le ha dado autorización al dtor. para que saque y se lo administren desde allí , no hay más dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-02-06','Ana: Envío correo a Alberto, Óscar, Miguel, Ángel y Maite CTAEX: "El viernes a última hora, hablé con Raquel, Presidenta de la Comunidad de Vecinos (648 61 98 93). Me informa que la vivienda de Desideria (la que compró su marido y es su vivienda habitual desde entonces), se deben los tres últimos meses de 2022 de la Comunidad más el mes de enero de este año. El precio hasta enero es de 15€/mes. *A partir de febrero, según se ha acordado en la reunión de propietarios, la cuota de la comunidad asciende a 25€/mes. Anteriormente, de este pago se hacía cargo Ángel, difunto esposo de Desi, la presidenta no sabe decirme si lo ingresaba en caja o cómo lo abonaba. *No obstante han cambiado de entidad bancaria, anoto el número para domiciliar el pago o hacer transferencia, como estiméis en la sección ecca.. ES90 3001 0053 0853 2001 8737 “Comunidad de propietarios C/Tomás del Barco, nº4. Vivienda 4ºB” **A parte, debe también una derrama de 250 € (ésta es la cuantía que corresponde por vivienda) y que, según me informa, hay que ingresarlo antes de abril. *Si necesitáis más aclaraciones, podéis llamar al número de la presidenta arriba indicado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-02-06','email del viernes a última hora del CRR : Buenas tardes, Soy Melania, Terapeuta Ocupacional del CRR de Olivenza. Os escribo para trasmitiros lo último acontecido con Emilia Morales para que tengáis constancia de ello. Hasta el momento, sabéis que Emilia está en Don Benito desde hace días. Hace aproximadamente una hora, he recibido una llamada de Teresa de Futuex para informarme que Emilia la había llamado verbalizando que Habían vuelto a detener a Miguel Ángel y que este había pasado de nuevo a disposición judicial y había pasado la noche en el calabozo. También verbaliza que ella no se encuentra bien. Tras ello, me dispongo a llamar a Emilia para preguntarle que tal y ver qué es lo que ella me comenta y tras mi llamada me verbaliza un poco lo mismo, de manera muy desorganizada, sin saber ponerme en pie realmente que es lo que ha ocurrido pero el contenido que me trasmite es el mismo que a Teresa: que Miguel Ángel ha pasado la noche en el calabozo porque lo han vuelto a detener y que ella no se encuentra bien , que tiene ciática y dolor en una pierna porque se ha caído y porque ha tomado más pastillas de lo normal. Le aconsejo que por favor, llame al 112 ya que es la única manera que tengo de ayudarla y casualmente , cuando está hablando conmigo, llegan los sanitarios a su casa. Me pasan con la médica y le informo un poco de la situación y de cómo noto a Emilia, pidiéndole que necesitaría acudir a urgencias porque la noto muy desorganizada. Esta me comenta que la valorará pero que sí que la derivará a urgencias. Simplemente es para que seáis conocedores de la situación y de mi intervención desde el centro. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-02-06','email del viernes a última hora del CRR : Buenas tardes, Soy Melania, Terapeuta Ocupacional del CRR de Olivenza. Os escribo para trasmitiros lo último acontecido con Emilia Morales para que tengáis constancia de ello. --------------------------------------- escrito de hoy : Buenas tardes, Pues lo último que sabemos de Emi es que ha pasado el fin de semana en casa de Miguel Ángel, no llegó a ingresar y ha llamado en varias ocasiones al centro durante el fin de semana y durante el día de hoy y se le ha dado apoyo en todo lo necesario y en todo lo que nos ha demandado. La última vez que hablé con ella ha sido hace una hora aprox. y estaba mucho más tranquila que el viernes. Nos comenta que nadie de la comisión se ha puesto en contacto con ella y no expresa deseos de volver al centro. Un saludo Hasta el momento, sabéis que Emilia está en Don Benito desde hace días. Hace aproximadamente una hora, he recibido una llamada de Teresa de Futuex para informarme que Emilia la había llamado verbalizando que Habían vuelto a detener a Miguel Ángel y que este había pasado de nuevo a disposición judicial y había pasado la noche en el calabozo. También verbaliza que ella no se encuentra bien. Tras ello, me dispongo a llamar a Emilia para preguntarle que tal y ver qué es lo que ella me comenta y tras mi llamada me verbaliza un poco lo mismo, de manera muy desorganizada, sin saber ponerme en pie realmente que es lo que ha ocurrido pero el contenido que me trasmite es el mismo que a Teresa: que Miguel Ángel ha pasado la noche en el calabozo porque lo han vuelto a detener y que ella no se encuentra bien , que tiene ciática y dolor en una pierna porque se ha caído y porque ha tomado más pastillas de lo normal. Le aconsejo que por favor, llame al 112 ya que es la única manera que tengo de ayudarla y casualmente , cuando está hablando conmigo, llegan los sanitarios a su casa. Me pasan con la médica y le informo un poco de la situación y de cómo noto a Emilia, pidiéndole que necesitaría acudir a urgencias porque la noto muy desorganizada. Esta me comenta que la valorará pero que sí que la derivará a urgencias. Simplemente es para que seáis conocedores de la situación y de mi intervención desde el centro. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-02-06','email del viernes a última hora del CRR : Buenas tardes, Soy Melania, Terapeuta Ocupacional del CRR de Olivenza. Os escribo para trasmitiros lo último acontecido con Emilia Morales para que tengáis constancia de ello. --------------------------------------- escrito de hoy : Buenas tardes, Pues lo último que sabemos de Emi es que ha pasado el fin de semana en casa de Miguel Ángel, no llegó a ingresar y ha llamado en varias ocasiones al centro durante el fin de semana y durante el día de hoy y se le ha dado apoyo en todo lo necesario y en todo lo que nos ha demandado. La última vez que hablé con ella ha sido hace una hora aprox. y estaba mucho más tranquila que el viernes. Nos comenta que nadie de la comisión se ha puesto en contacto con ella y no expresa deseos de volver al centro. Un saludo Hasta el momento, sabéis que Emilia está en Don Benito desde hace días. Hace aproximadamente una hora, he recibido una llamada de Teresa de Futuex para informarme que Emilia la había llamado verbalizando que Habían vuelto a detener a Miguel Ángel y que este había pasado de nuevo a disposición judicial y había pasado la noche en el calabozo. También verbaliza que ella no se encuentra bien. Tras ello, me dispongo a llamar a Emilia para preguntarle que tal y ver qué es lo que ella me comenta y tras mi llamada me verbaliza un poco lo mismo, de manera muy desorganizada, sin saber ponerme en pie realmente que es lo que ha ocurrido pero el contenido que me trasmite es el mismo que a Teresa: que Miguel Ángel ha pasado la noche en el calabozo porque lo han vuelto a detener y que ella no se encuentra bien , que tiene ciática y dolor en una pierna porque se ha caído y porque ha tomado más pastillas de lo normal. Le aconsejo que por favor, llame al 112 ya que es la única manera que tengo de ayudarla y casualmente , cuando está hablando conmigo, llegan los sanitarios a su casa. Me pasan con la médica y le informo un poco de la situación y de cómo noto a Emilia, pidiéndole que necesitaría acudir a urgencias porque la noto muy desorganizada. Esta me comenta que la valorará pero que sí que la derivará a urgencias. Simplemente es para que seáis conocedores de la situación y de mi intervención desde el centro. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2023-02-06','Ana: Envío coreo-e a Julio, Aux. Adtvo. CTAEX: "Adjunto, para su registro en SIREX, la siguiente documentación relativa a MARÍA SALVADORA CHAVES MENDOZA: - Solicitud de Valoración de Dependencia - Revisión por empeoramiento - Informe de Salud - Sentencia de Incapacitación y Nombramiento y Acuerdo de Aceptación del cargo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN RAMON'and edp.apellido1='SALAZAR'and apellido2='FERNANDEZ'),'2023-02-06','Se comunica a esa Comisión Tutelar del adulto que el interno Juan Ramón Salazar Fernández, ingresado en este centro y tutelado por esa Comisión, ha sido trasladado al hospital de Mérida en fecha 5 de febrero de 2023. ------------------------ Finalmente, un conductor ha llevado en mano los 210€ al hermano de Juan Ramón Salazar, ya que como acordamos por teléfono, serían unos 30€ diarios. Hasta ahora. Mérida, 5 de febrero de 2023. Médico Somático : María Luz Romero Furones','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN RAMON'and edp.apellido1='SALAZAR'and apellido2='FERNANDEZ'),'2023-02-06','Se comunica a esa Comisión Tutelar del adulto que el interno Juan Ramón Salazar Fernández, ingresado en este centro y tutelado por esa Comisión, ha sido trasladado al hospital de Mérida en fecha 5 de febrero de 2023. Mérida, 5 de febrero de 2023. Médico Somático : María Luz Romero Furones','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-02-06','Mayte: Acabo de hablar con Soraya y MªLuz. Emi no puede entrar en el CRR de Don Benito porque uno de los requisitos es tener grado de dependencia y no lo tiene. Soraya plantea la posibilidad de derivación a piso supervisado, Mª Luz y Raquel dicen que podríamos probar, quizá funcionase.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2023-02-06','TERESA te adjunto resolución de la plaza con la dirección exacta de la R.M . de la Coronada . Los tf de contacto 924028778- corto de la Dtra. 20239 .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-02-06','Ana: Llamada de la Enfermera del ESM (53622): está allí José Manuel, ha llamado al 112 diciendo que estaba muy nervioso y necesitaba que le inyectaran algo. Le han llevado al C. Salud de Nuevo Cáceres. *Le han inyectado un Trankimazin. ············ Pone el manos libres, para que hable con José Manuel. Demanda que le autoricemos dinero para comprar un teléfono nuevo, porque ha vendido el que tenía y el que usa ahora no tiene WhatsApp. Dice que lo ha vendido para comprarse tabaco y latas de Redbull. *Su hermano aún le tiene guardado parte del dinero de la asignación que retiró la semana pasada para tabaco. ············ Le recuerdo que desde la Secc. Ecca. no están autorizados más extras hasta marzo. ··············· Cuando sale de la consulta vuelve a llamar con la misma demanda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-02-06','Ana: Envío a registro (oac.merida.san@juntaex.es): "Adjunto los siguientes documentos relativos a JULIÁN RAMÓN CIVANTOS FERNÁNDEZ, cuyo cargo ostenta la Comisión Tutelar de Adultos, para remitir por registro a la Dirección Provincial del INSS: - Oficio solicitando Certificado Actualizado de Pensión - Testimonio de Auto de Nombramiento - Testimonio de Aceptación del Cargo de Tutor" ······································································································································································································· Correo-e de Mª José Acosta Domínguez, TS de Mancomunidad Integral Sierra de San Pedro (mjacosta@mancomunidadsierrasanpedro.com) "Hola Ana, he hablado con Pilar la Trabajadora Social de Valencia de Alcántara. El señor era beneficiario del Servicio de Ayuda a Domicilio por Convenio SEPAD y Ayuntamiento. Pilar ya está informada de que el señor quiere quedarse en la residencia de Cedillo. Me dice que hablará con Gloria para valorar si es definitiva la decisión para darlo de baja en la ayuda a domicilio del convenio, para no darlo de baja y que luego regrese y entonces no pueda tener este servicio. Mientras tanto yo te remito la solicitud de Revisión PIA para ponerlo en lista de espera para la plaza en Cedillo. No procede ahora solicitar Revisión de Grado. Cualquier cosa me informas, estamos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-06','Ana: llamada de Mª Carmen, TS del HSPA (56283): Me informa que el sábado 4 ingresaron a Saturnino en la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-02-03','miguel, hoy he firmado la ratificación de las dos compraventas con protocolo 120 de Don Gonzalo Fdez Pugnaire en Mérida. Envío email a Carlos Duro, notario de Santos de Maimona','2');
