insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-02-07','Ana: Envío a REGISTRO (oac.merida.san@juntaex.es): "Adjunto remito Oficio-Solicitud de CERTIFICADO ACTUALIZADO DE PENSIÓN NO CONTRIBUTIVA, relativo a D. COSTI ALEXANDRU RIZEA, cuyo cargo ostenta la Comisión Tutelar de Adultos, para remitirlo por REGISTRO a: CONSEJERÍA DE IGUALDAD, POLÍTICAS SOCIALES Y CONCILIACIÓN Delegación Territorial de Málaga Servicio de Gestión Económica de Pensiones Avda. Manuel Agustín Heredia, 26 29001 – Málaga MÁLAGA Buzón: A01035475" ························································································································································································································· Remito correo a Carmen Sánchez, Directora de la Fundación Autismo Sur (direccionhogares@autismosur.es / teayudamos@autismosur.es): "Adjunto remito Declaración Responsable de Usuario de Centro, relativa a COSTI ALEXANDRU RIZEA, firmada digitalmente por el Presidente de la Comisión Tutelar de Adultos de Extremadura. En cuanto al Certificado Actualizado de Pensión, no lo tenemos, lo he solicitado a la Delegación Territorial de Málaga, en cuanto lo recibamos os lo hago llegar. Aprovecho para preguntarles qué tal continúa Alex. Ante cualquier otra cuestión, no duden en volver a contactar." ································ Respuesta de Carmen Sánchez, Directora General de la Fundación Autismo Sur (direccionhogares@autismosur.es / 608 633 099): "Respecto a Costi, se le acaba de realizar una analítica para seguimiento de tensión arterial, y estamos a la espera de resultado. Su vida es normal e integrado con sus compañeros y trabajadores..... Estamos esperado cita para actualizar su pasaporte, hay que ir a Sevilla con él, para realizar la gestión. Cualquier cosa te informamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-02-07','Ana: Guardo justificante de registro de solicitud del Cdo. P. Jubilación en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2023-02-07','Maite: con fecha 26 de enero , la sección de acceso a recursos de discapacidad nos ha notificado la adjudicación de plaza por traslado en el centro APROSUBA-3 de badajoz. Estamos a la espera del ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-03','Ana: correo de Esther Trejo, TS SSASB Alcuéscar (tsocial7@mancomunidadsierrademontanchez.es): "Te escribo por el caso que hemos estado esta mañana hablando: SATURNINO MIGUEL SALGADO JIMENEZ. He realizado visita con policias locales, no nos ha querido abrir, se encuentra atrincherado en su vivienda, la puerta que da a las escaleras para acceder a la puerta de la vivienda se encuentra cerrada. Nos ha echado , no mantien discurso , y falta de higiene, y conducta agresiva. En conversación con la mujer del primo que ostenta el bar que se encuentra al lado del domicilio de Saturnino, nos informa que lleva dos días sin comer, que lleva alrededor de un mes muy alterado, agitado y se enfanda por cualquier motivo con agresividad verbal. Que la medicación no se la toma y que le parece que la consume como si fuera sustancias adictivas. He hablado con una de las hermanas, se encuentra también alterada, porque expresa que va a a pasar algo, no sólo con respecto a él sino con terceros, y se está convirtiendo en una alarma social. No he podido contactar con el centro médico para que me informara de su estado. NO sé si me podrías facilitar la resolución de comisión tutelar. Y por último que me indicaras la manera a proceder. Emitiré informe para Comisión Tutelar de los sucesos acontecidos."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-07','Ana: conversación telefónica con Esther, TS Alcuéscar (927 384 002): me comunica que el viernes por la tarde, Saturnino acudió al bar de su primo donde amenazó a un hombre con un cuchillo. ········ Luego se fue a su casa y se atrincheró en el tejado. Tuvieron que intervenir la Guardia Civil y los Bomberos. Después lo trasladaron a Urgencias del HSPA de CC. ·················· Comunico a Toni-Futuex el ingreso en UHB y los incidentes del viernes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2023-02-07','Ana: Envío correo-e a Toni-Futuex: "En relación a JOSÉ MORENO MOYANO, nos ha enviado un presupuesto de un “radiador – convector”, para la habitación, pero no sé si habéis llegado a hablar con la Directora del Hotel. Necesitamos saber si realmente es necesario comprarlo. Por nosotros, sabiendo que pasa frío, si puede asumirlo (creo que sí) no habrá problema, pero si finalmente le pusieran más horas la calefacción, quizá no sería necesario. Cuando podáis, por favor, informarnos al respecto para darle respuesta y autorizar o no la compra."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2023-02-07','Ana: Correo de Pilar Cerrillo, TS de la Res. Ciudad Jardín (calidad@grupociudadjardin.com): "la forense ha hecho hoy una video llamada para valorar a Carlos. No hace falta trasladarlo al juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2023-02-07','Ana: Tras hablar con Estrella, CTAEx, y con Gloria, Directora de los PP.TT. de Almoharín (600 51 84 93 / glomama2009@hotmail.com), le remito correo-e a ésta última: "Tal y como acabamos de hablar, te remito adjunta la autorización de retirada de efectivo relativa a Mª Jesús Criado Rodríguez, cuyo cargo ostenta la Comisión Tutelare de Adultos de Extremadura. Mi compañera Estrella, ha acordado con el personal de la sucursal bancaria, que mañana le llamará para aclarar este asunto. Como te he dicho, cuando Gloria, la Educadora del Programa de Apoyo Comunitario de Futuex, no pueda acudir a acompañarla, ella puede ir perfectamente sola al banco a retirar el dinero sin que Gloria tenga que llamar la banco para dar su conformidad. En lo relativo a otras cuestiones que Mª Jesús pueda necesitar comprar a lo largo del año (por ejemplo: ropa u otros artículos que se salgan del llamado “gasto de bolsillo”) podéis remitir solicitud con su correspondiente presupuesto a la siguiente dirección: ctutelar@salud-juntaex.es Ante cualquier cuestión, no dudes en contactar, bien por esta vía o al número que aparece en la firma, que es el mío directo." ································································································································································································· Hablo con José Aº Pulido Pulido, TS de los PPTT de Almoharín (927 38 62 24), con respecto al Informe Social para la rendición de 2022, dice que no ha recibido el oficio solicitándolo. Pide que se lo vuelvan a enviar, a su atención a través de registro. ······· Se lo comunico a Óscar, Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2023-02-08','-Email de Eva : Pues creo que nos hemos adelantado un poco, pues como habíamos recibido la notificación de que Cris sólo tiene curatela representativa en la esfera económica, pues ella misma ha solicitado el cambio de nombre y sexo en registro civil. Hemos llevado el último informe que le dio el endocrino. Han mandado a Badajoz el escrito, pues allí es donde está registrada. En cuanto tengan respuesta nos dice la persona encargada de registro civil. Con respecto a las pruebas de las oposiciones, hemos enviado una fotocopia de su D.N.I. que teníamos aquí, además de un certificado que hicieron en registro civil donde dice que está es proceso de cambio de sexo. Cualquier duda me comentas. Un abrazo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-02-08','llega email de Toni de Futuex: Buenas Teresa, que tal? Le he escrito a Ana, sobre un tema de Felisa, la madre de Aitor, lo que hemos sabido de este, ya que se intento verlos la pasada semana.. la cosa está fata, como suponiamos. Te cuento: Se coordinó con el programa de familia de la Mancomunidad de Trujillo y se mantiene reunión previa al intento de visita con Aitor. Las profesionales de dicho programa comentan el trabajo que están llevando a cabo con el tutelado y las dos chicas con las que convive, una es Mireia la novia y la otra se una conocida de centro de menores (Nesia) , supuestamente. Señalan que hacen compra los lunes, después de haber elaborado un menú para la semana, en el que median para que sea equilibrado y variado, pues sino sólo comen comida elaborada y con muchas calorías. Los martes por la tarden acuden a la vivienda a enseñarles a cocinar algunos platos, la semana pasada hicieron lentejas, este martes no se llevó a cabo, pues al entrar en la vivienda, la cocina estaba llena de residuos, muy sucia, maloliente e incluso con excrementos de perro… Indicaron que era insostenible estar allí, no podían aguantar el olor, aparte que no había modo de sacar la comida y cocinar… Estas profesionales cuentan que le llevaron ropa y mantas, pues están sin nada para calentarse, a pesar de tener luz, no tienen ningún radiador, por lo que proponen que se pueda hacer un ingreso extra para comprar uno en el Leclerc; se le dice que se comunicará a la CTAEX, es cierto que con las temperaturas que se están teniendo, no es nada adecuado estar sin algún medio para calentarse. La casa está ocupada, por Nesia parace ser.. y ahora por ellos dos. El mismo día, como se menciona, también les llevaron ropa, ya que los tres se estaban poniendo la ropa de Neisa, la compañera del centro de menores de Aitor y quien es “dueña” de la casa, que realmente está ocupada, pero ella estaba allí primero. Señalan que están muy sucios, Aitor va hasta sin calcetines, la piel se le ve sucia y desprenden un olor de llevar tiempo sin asearse… cuando vivia en centros o con la madre, si que cuidaba su higiene y mantenia hábitos saludables. Nos comentaron también, al parecer, iba a ir a darse de alta en el sexpe y solicitó retomar los seguimientos en salud mental, se les dice que esto último es muy importante, ya que a saber el tiempo que lleva sin tomarse la medicación y, además, consumiendo de forma activa… Se intenta visitar a Aitor, pero ya les había advertido a las profesionales del programa de familia que no iba a estar en casa ni miércoles, ni jueves, que tenía que salir a hacer cosas. Se intenta a la hora de comer, pero no están… nos suena un poco, a que no les apetece, que se les visite. Se observa el barrio y la entrada de la casa… se adjunta a continuación, como era de esperar, en un ambiente nada adecuado. Comenta que hasta el momento acepta los seguimientos y tiene un comportamiento adecuado con el programa de familia, alguna alteración por querer incluir vino en la compra, por querer comprar otros alimentos ya elaborados…, pero indican que acaba cediendo, no ocurre lo mismo con Mireia, novia de Aitor, quien tiene mucho carácter y es muy exigente. Como se puede prever esta situación seguramente no se alargue porque no acabarán bien, las profesionales del programa de familia señalan que Mireia y Neisa discuten bastante, como era de esperar…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='CORDERO'and apellido2='QUINTERO'),'2023-02-08','EXITUS Fallecida el 08/02/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-02-08','Buenas tardes Amalia. Pues un pco lo mismo es la informacion que hemos ido obteniendo nosotras;: La pasada semana al recibir comunicación de que Miguel Ángel, su pareja, ya estaba en libertad, una vez cumplida su condena, Emilia, VOLUNTARIAMENTE, decidió irse con él a Don Benito (a la vivienda de Miguel Ángel). Ella cuenta que él la ha engañado, prometiéndole regalarle ropa y que ya tenía trabajo. Con fecha miércoles 01 de febrero 2023, comunica, que debe de realizar su retirada de efectivo el viernes 03. Y que Miguel Ángel ha sido detenido de nuevo por la policía y está en comisaría, dice que, por un delito de hace tiempo, cuya causa no estaba archivada y tiene de condena varios meses. Ella se queda en la vivienda. Con fecha del viernes 03 febrero, contacta de nuevo con el CRR y con este equipo de apoyo social comunitario de Badajoz, para comunicar que ha retirado su asignación 78 euros, pero que se encuentra muy mal. Verbaliza diferentes situaciones, mezclando ideas sin tener claro qué ha podido ocurrir: que se ha caído de la cama, que se ha tomado un blíster de quetiapina, que si estaba Miguel Ángel, que ha llamado al centro de salud para que la vea su médico de urgencias. etc. Con el CRR, hemos podido comprobar que un equipo de centro de salud del Pilar (Don Benito)se ha desplazado a la vivienda y ha confirmado que estaba en situación de derivarla a urgencias de psiquiatría, pero solo ha sido cuestión de horas, ya que el fin de semana estaba de regreso en la vivienda en Don Benito, más tranquila , sin verbalizar ganas de regresar a su plaza. Hoy lunes 06 de febrero, demanda ayuda, ya que comenta que se ha gastado su asignación y hasta el viernes no tiene para comer. Que se encarga ella de colocar su pastillero y tomar la pauta de medicación y que se queda allí en Don Benito. Aunque Emilia, como sabemos, es muy inestable emocionalmente, con periodos de tristeza y ansiedad, así como irritabilidad, pasando del llanto a la euforia con mucha facilidad. Desde el CRR, nos comunican que ha perdido su plaza, algo que han comunicado ya al Sepad, pero que ellos le brindan ayuda telefónica para cualquier duda en estos momentos. Intentaermos verla alli, en Don Benito, en las próximas semanas, a ver que nos encontramos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-02-08','Ana: Llamada de Pepi, madre de Juanjo (626 198 616), muy descompuesta, con mucha necesidad de hablar, se queja y pregunta por varias cuestiones: Herencia del padre de Juanjo, venta de la vivienda que deja en Herencia el padre a Juanjo y su hermana, compra de zapatillas para Juanjo (Presupuesto de diciembre, y que no nos había enviado desde Futuex hasta ayer a las 14:59h)... ······· Pediré a Toni-Futuex, que intensifiquen el seguimiento y que vuelvan a abordar con él la posibilidad de contratar cáterin (él hasta ahora se ha negado) y que traten de enviar antes los propuestos y peticiones de extras. ············· *Consulto a los compañeros jurídicos sobre los trámite de la herencia y venta del piso que van a heredar Juanjo y su hermana de su difunto padre. ···················· *Paso el presupuesto a la sección económica para que se abone y se dé aviso a Futuex sobre cuándo pueden ir a recoger los productos a la tienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-02-07','Ana: correo de Toni-Futuex a las 15h, con presupuesto de noviembre: "Después de ir a la retirada de asignación correspondiente, Juan José solicita un extra, se pone nervioso y bastante apagado y triste, comenta que se le ha dejado sin nada toda la Navidad, que está haciendo las cosas bien y, además después de haber visto el extracto, que se adjunta, el comprueba que tiene algo de ahorro ahora, por lo que puede abarcar para la compra de las zapatillas y la sudadera que es lo que viene demandando y tener algo más, en este caso ya para rebajas. Se adjunta el extracto. El e-mail de la oficina, en el que caso que se apruebe autorizarle algo extra, es el siguiente: buzon7130@unicaja.es Además, ha retomado la actividad de la universidad, por lo que se considera que podria ser pertinente, reforzarle de algun modo, esta coducta. Normalmente retira 67€, por lo que podría sacar si lo estimais conveniente algo más.. y poder asi, trabajar con el, asi, otras cosas, pues ya se está negando a que se le contrate un catering y a los seguimientos médicos, tuvo consulta en salud mental, no avisó y tampoco acudió. Al parecer, la semana pasada y la anterior estuvo bastante bajo de ánimo, se comprueba que es cierto, pues al revisar los tickets de compra ha comprado cerveza y vino. Seria tal vez positivo, si se considera viable, el poderle autorizar un poquito mas o una retirada extra que le pudiera de algun modo incentivar y el tema de la ropa deportiva, que pasó hace algun tiempo." ····················· **El presupuesto NO lo habían enviado antes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-02-08','miguel, email de Ana:Buenas, compis, ¿sabéis si hay alguna resolución judicial nueva con respecto a Julia Morón? Es que me dicen desde el CRR, que al parecer la madre ha recibido algo del Juzgado y no sabe muy bien qué es. Cree que es sobre el juicio por violencia doméstica. Ya me decís, si sabéis algo o si podéis preguntar. Por otra parte, resolverme una duda, porfa, ¿en este caso se llegó a solicitar internamiento involuntario? Resulta que se ha ido unos días a casa y ahora no quiere volver al centro y, seguimos considerando que en su casa no puede vivir. **************************************************** Mi contestación: Hola, no se pidió nada, únicamente comunicamos al juzgado en contestación al requerimiento sobre qué recursos íbamos a dar a la tutelada…que está indicada en la intranet 16-12-21: remito al juzgado contestación a la providencia donde nos preguntaban por el recurso que se le va a dar a la tutelada. Le contesto vía fax al jzdo nº1 Coria donde desde la Sección de Salud Mental DUE(Unidad de Programas Asistenciales) nos comunican que la tutelada ha sido derivada por el ESM de Coria para acceso a recurso Residencial de Salud Mental (CRR) por emergencia social, teniendo entrada de la derivación el el Sepad a fecha de 26-11-21, estando pendiente de valoración por al Comisión de Valoración de recursos de Salud Mental. Faltan algunos datos en el expediente para la valoración que ya están tramitando. Entiendo que ese requerimiento que pidió el juzgado debió deberse a que le buscásemos un recurso (al final entró en CRR y pendiente de la comisión de valoración, según veo en la intranet…). Por tanto no pedimos internamiento involuntario porque entró en CRR… Ana, intenta que te remitan el documento del juzgado que dicen que les ha llegado para que salgamos de duda. Si hay que plantear internamiento involuntario en centro, necesitaría que recabases informes médicos y sociales aconsejando el tipo de recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-02-08','Ana: Correo de Cruz Merino, TS: "Me ha llamado una vecina de Juan Gregorio para comentarme lo siguiente. Le habían llamado de Santa Lucia para saber si había alguna causa por la que se devolvía el recibo de Juan, (el teléfono de esta vecina era el que estaba como contacto en la póliza de seguros de decesos). La devolución puede ser que tenga que ver con el cambio de número de cuenta bancaria donde lo tenía domiciliado y la apertura de una nueva cuenta. Le comentaron que volverían a pasar el recibo con fecha de 25 de febrero para evitar que se quede sin cobertura. El importe es de 34,17€,por lo que me ha comentado. El teléfono de contacto que le facilitaron es el 927215311, para llamarles en horario de 8:30 a 15:00 por si hubiese que realizar alguna gestión al respecto." ······························ Según indicación de Alberto, jefe secc. ecca., lo reenvío a Estrella para que averigüe lo que ha pasado y lo ponga al día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-02-08','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Informaros de que la persona usuaria Consuelo Nevado Pacheco se encuentra ingresada en la UHB por desestabilización de su patología de base. Os iremos informando de su evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-02-08','Ana: Llamo a Pilar Martín, TS ESM-CC (54612): confirma que finalmente Doroteo tiene cita el día 10 de febrero a las 13 h. en Psiquiatría con la Dra. Mabel Rubio. ··································· *Llamo a Julia, Coordinadora Casa de la Misericordia (615 62 86 80), para comunicárselo. Ya habían conseguido hablar ellos con Psiquiatría, le han cambiado la medicación, pero Doroteo es reacio a tomársela y anoche se negó también a tomar la de rescate. *Acudirán el viernes a la cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-02-08','Ana: Envío correo a Alberto y Óscar, Secc. Ecca: "En relación a SERGIO SOLANILLA LUJÁN, nos plantean desde el centro CASA DE LA MISERICORDIA que aporte un 75% de sus ingresos, contando también las pagas extras que percibe. A parte habrá que darle asignación para tabaco y le asignan 1€/día para café. A mí me parece bien. Por favor, podéis confirmarle a JULIA, Coordinadora de Centro (615 62 86 80 // casadelamisericordia.alcuescar@gmail.com), cuanto le ingresan este año, que no tenemos el Certificado Actualizado, y por tanto la cuantía exacta que aportará? La necesitan para reflejarla en el contrato del centro que me tiene que enviar. Recordar que ingresó en este recurso a fecha de 6/01/23 y que desde entonces no se ha abonado aún nada. Eso sí, él llevaba dinero de bolsillo de la cuenta peculio cuando salió de prisión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-02-08','Ana: Tras conversación con Paula, TO CRR-Plas (682 704 401), envío correo a Toni-Futuex: "En relación JULIA MORÓN HERNÁNDEZ, comunicar que fue de visita a la casa familiar y tenía que haber vuelto el lunes día 6 al CRR, pero se niega a regresar. *Gloria, Educadora, está al corriente, pues así me lo ha dicho Paula, Terapeuta Ocupacional del centro. Os solicitamos que retoméis el seguimiento en el domicilio a la mayor brevedad y trabajéis con ella la idea del retorno al recurso. Y, si notáis signos de descompensación psicopatológica, no los hagáis constar en un informe, pues quizá hay que notificarlo al Juzgado. Yo mañana intentaré contactar con SSASB y el Centro de Salud, por si pudieran acercarse a visitarla. De hecho hay una medicación que no la está tomando porque hay escasez y no se la han podido dispensar en la farmacia." ·································································································································································································· Envío correo a los A. Jurídicos CTAEx: "¿sabéis si hay alguna resolución judicial nueva con respecto a Julia Morón? Es que me dicen desde el CRR, que al parecer la madre ha recibido algo del Juzgado y no sabe muy bien qué es. Cree que es sobre el juicio por violencia doméstica. Ya me decís, si sabéis algo o si podéis preguntar. Por otra parte, resolverme una duda, porfa, ¿en este caso se llegó a solicitar internamiento involuntario? Resulta que se ha ido unos días a casa y ahora no quiere volver al centro y, seguimos considerando que en su casa no puede vivir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-08','Ana: Llamada de Mª Carmen, TS del HSPA (56283): me facilita el contacto de la Dra. María Gía. - Psiquiatra HSPA (56832 // Control: 56826), pues al parecer le ha llamado un Comandante de la Guardia Civil comunicando que no den el alta a Saturnino sin avisarles previamente, pues cuando salga tiene que ingresar en prisión. ······································································································· Envío mail a Toni-Futuex: "La nueva de hoy es que un comandante de la Guardia Civil, ha llamado al hospital y le ha dicho a la Psiquiatra que les avise antes de que le vayan a dar el alta porque tiene que ingresar en Prisión. De momento nosotros no tenemos documento al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-02-08','Ana: Correo de Sonia BerNabé, TS ASINDI (trabajosocial@asindi.e.telefonica.net): "me ha llamado Estrella para comunicarnos, que si puede ser, Aaron Rosado ingresará el miércoles 15 de Febrero. Voy a ver con los compañeros si disponemos de vehículo y se puede organizar todo para ese día. Una vez que tengamos la fecha cerrada y esté próxima se lo diremos a él y, con profesionales puede ir preparando la ropa y sus enseres. Por otro lado, la comunicación con su familia (primas, tías,...) me estoy planteando adelantarle la noticia para que pueda irse a verlos este fin de semana porque creo que les costará más ir a Plasencia a verle. ¿Qué te parece?" ··············· Confirmo que nos parece bien la visita si a la familia le viene bien y pido que nos confirmen la fecha de ingreso cuando la sepan con seguridad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2023-02-09','-Email de 2020. Buenas tardes. Comunicaros a los 2 que D. FRANCISCO RAMOS MORGADO, el que trabaja las fincas de la tutelada ya ha ingresado los 300€ que le debía de los últimos 3 años. El año que viene, en teoría, ingresará otros 100 €. No sirve de nada. Nada más efectuado el ingreso de los 300 €, se actualica la cuenta que ya estaba en número rojos, y pasan recibos pendienes (seguro, oar...). Esta situación es de besugos. No podemos funcionar así a nivel bancario. Dentro de 4 días va a volver a estar en negativo. Amalia: creo que el centro debe hacerse cargo del seguro de deceso o dejar de pagarlo si ellas, las monjas, se van a hacer cargo del entierro. Amalia: los impuestos no se me ocurre como podemos pagarlos. O el centro hace una transferencia o es imposible. Amalia: ropa...como puedes ver, imposible si queremos pargar durante un poco más de tiempo, impuestos y seguro deceso. Venta: como dice Ángel, aunque tengamos autorización, eso no quiere decir que vayamos a poder vender. Todo indica que el valor e interés de las fincas es mínimo (el hombre que le trabaja las fincas, le ha manifestado a Ángel su falta de interés x hacerse con ellas). Hablamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2023-02-09','-Email de 2020. Buenas tardes. Comunicaros a los 2 que D. FRANCISCO RAMOS MORGADO, el que trabaja las fincas de la tutelada ya ha ingresado los 300€ que le debía de los últimos 3 años. El año que viene, en teoría, ingresará otros 100 €. No sirve de nada. Nada más efectuado el ingreso de los 300 €, se actualica la cuenta que ya estaba en número rojos, y pasan recibos pendienes (seguro, oar...). Esta situación es de besugos. No podemos funcionar así a nivel bancario. Dentro de 4 días va a volver a estar en negativo. Amalia: creo que el centro debe hacerse cargo del seguro de deceso o dejar de pagarlo si ellas, las monjas, se van a hacer cargo del entierro. Amalia: los impuestos no se me ocurre como podemos pagarlos. O el centro hace una transferencia o es imposible. Amalia: ropa...como puedes ver, imposible si queremos pargar durante un poco más de tiempo, impuestos y seguro deceso. Venta: como dice Ángel, aunque tengamos autorización, eso no quiere decir que vayamos a poder vender. Todo indica que el valor e interés de las fincas es mínimo (el hombre que le trabaja las fincas, le ha manifestado a Ángel su falta de interés x hacerse con ellas). Hablamos. ----------------------------------- De: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Enviado: lunes, 26 de octubre de 2020 11:38 Para: ALBERTO MARTIN ROSETE >alberto.martinr@salud-juntaex.es> Asunto: RE: GUERRERO ZAMBRANO ANDREA: AUTORIZACIÓN VENTA PROPIEDADES. Hola , esto ya se habló con el centro ( JUana) son ellos los que pagan ese seguro , desconozco cómo lo organizaron. saludos','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2023-02-09','TERESA EMAIL OLGA TS El día 2 de febrero acompañé a Jose María al forense, por videoconferencia. El forense que le toque lo conozco, Después hablé con él por teléfono, para aclarar algunas dudas y comentar algunos aspectos que con Jose María delante no quise hacer. ¿Tenéis alguna noticia del proceso?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2023-02-09','Buenos días , con respecto a las gestiones desde la parte social y según lo acordado en la reunión , os indico : -He hablado con la R.M. , os confirmo que siguen abonando el seguro de decesos como se acordó en 2020 y podéis ver en el email que ha recuperado Alberto . ( esa gestión la hizo Juana ) -He contactado con el vecino que ha presentado las quejas por desperfectos. Le he indicado que no tiene liquidez para sufragar los gastos y que si está interesado en la compra de la vivienda contacte con nosotros. -He contactado con SSASB en la misma línea , si hay alguna persona interesada en la compra que nos informen . Saludos.','2');
