insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2023-02-09','Ana: Correo de Ángel, A. Jurídico CTAEx: "Hablé con Pilar Cerrillo, para decirle que hemos solicitado al Juzgado que a la citación del 22/5/23 se realice a través de videoconferencia desde el centro, tal y como hicieron con la del 15/2, del reconocimiento por el médico forense."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-02-09','Ana: Correo de Alberto, jefe secc. ecca.: "ANA/OSCAR: COMO MÁXIMO SE PUEDE AUTORIZAR: • ASIGNACIÓN 70 €/MES. • GASTOS FARMACIA 20 €/MES • A CENTRO Y TUTELADO DEBE QUEDARLES CLARO QUE NO HAY GASTOS EXTRAS. OSCAR: HABLAS CON CENTRO...LES INFORMAS SOBRE INGRESOS Y SOBRE COMO DISTRIBUIMOS EL COSTE Y COMO LO ABONAMOS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PECO'and apellido2='CARRANZA'),'2023-02-09','Ana: envío a Anabel, TS SSASB (ssbmadrigalejo2@gmail.com) certificado de pensión actualizado (Revalorización).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-02-09','-Email de Mª Angeles del CSS Qué tal? Sebastián Paredes Dicha acaba de ser valorado y ha obtenido un Grado III de dependencia. Desea solicitar plaza pública en centro de atención residencial para personas mayores. Antes de enviarte la Aceptación PIA de Servicios para que la firme el gerente, quiero informarme de qué residencias son más adecuadas para el paciente. Preguntaré a la Sección de Mayores directamente. De todas formas, por favor, si sabes de algún centro residencial que disponga de médico las 24 horas, dímelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-02-09','Ana: Correo de José Luis, hermano de José Manuel, adjuntando presupuesto de TV (se le compró una en octubre de 2022). ···· Mi respuesta: "Tal y como hemos explicado ya a tu hermano en numerosas ocasiones, no puede mandar presupuestos hasta marzo, pues no se le va a autorizar ninguno hasta esa fecha. Él lo sabe perfectamente y conoce los motivos de esta decisión. Así mismo, como bien sabrás, casa semana hace una petición distinta: teléfono móvil, sofás, encimera y cocina, televisión, cambio de piso, irse a vivir a Olivenza, irse a vivir a Malpartida…. Como sabes la intervención es muy difícil con él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2023-02-06','Ana: Me comunica Mª Ángeles, Aux. de SAD, que reclaman una factura de fontanería pendiente, de cuando le arreglaron a Felipe la cisterna del WC. ·························· Llamo a Adina (644 962 893), de la empresa de Fontanería Bohollo. *La factura pendiente es de 2020 y asciende a 21,80€. ······ La remitirá por correo-e al ctutelar@','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2023-02-08','vista para el procedimiento de revisión de medidas de apoyo en el juzgado nº1 de Zafra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2023-02-08','vista para el procedimiento de revisión de medidas de apoyo en el juzgado nº1 de Zafra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2023-02-09','miguel, recibo email de Toni de Futuex (reenviado por Tere): Lo de Maria fue bien, se acudió al domicilio en Monesterio y se ha llevó a cabo la videoconferencia con los juzgados de Zafra para la cual estaba citada. El médico forense le ha realizó la entrevista pertienente y María ha contestado a todo, se ha mostrado afable y participativa en todo momento. Las preguntas eran las típicas, para comprobar mas o menos su grado de competencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-02-09','Ana: Correo de Óscar a Julia, Casa de la Misericordia: "Se remite documento para domiciliación de los gastos de farmacia. En cuanto a las cuestiones planteadas en otro de los correos: • Los ingresos de Sergio son 572,30€*14 pagas. Esto hace un total de 667,68€ al mes con las pagas extras, con lo que la aportación al centro será de 501€ que se realizarán mediante transferencia mensual. • En cuanto a los gastos personales, se realizará una transferencia de 70€ mensuales a la cuenta del centro para que se lo administréis, ya que él tiene cuenta en Ibercaja y en Alcuéscar no hay oficina de esta entidad. Esta cuantía será objeto de revisión semestralmente, teniendo los gastos de farmacia u otros gastos imprevistos que le cargaran en su cuenta (embargos, multas...). En cualquier caso, esta sería la cantidad máxima de la que puede disponer en la actualidad y no sería posible autorizarle ningún extra. Si os parece, para evitar gastos en comisiones, realizamos una transferencia mensual por ambos conceptos; necesitaría que nos enviarais el número de cuenta donde realizar el ingreso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-02-09','Ana: Correo de Yessica, TS Comedor - Caritas (ydearriba@caritasplasencia.org): "Te adjunto foto de la dirección en la que vive actualmente y un número de cuenta, para que, según me informa, le enviéis 200€ para el alquiler de la habitación. Me comenta que ya os ha informado." ········· *Ángel Félix lo habló con Maite, Jefa Secc. hace unos días. ················ Reenvío correo a Alberto y Óscar, Secc. Ecca. y a Julio para que cambie el domicilio en la Base de Datos. ············ Por mi parte, si es viable, ok al alquiler. ····························· *Los A. Jurídicos exponen la inseguridad jurídica que supone hacerlo así, por tanto se decide hacerle reintegro en lugar de abonar mediante transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-09','Ana: Llamo a la Dra. María Gía. - Psiquiatra HSPA (56832 // Control: 56826): Me comunica que recibió llamada del Sargento Campos, de la Guardia Civil de Alcuéscar (Nº Directo: 665 61 39 35 // 927 12 00 78 // 661 90 12 53). Le han dicho que tienen una orden de ingreso en prisión al alta. Les avisarán cuando llegue el momento. ··········· En cuanto al estado de Saturnino, ingresó con una descompensación psicóticas, el fin de semana ha estado muy agitado y agresivo. Le han mantenido con contención mecánica. ···· El martes ya se la pudieron quitar, aunque con mucha mediación. Pero ayer, tras protagonizar un nuevo episodio de heteroagresividad hacia una profesional, fruto de su descompensación, de nuevo tuvieron que aplicar contención mecánica. ··· Le están poniendo heparina (anticoagulante). ·········· *En inicio, su planteamiento clínico, a no ser que mejorase mucho, es el de derivarle a UME. Pero dada la situación, con la orden judicial, no sabe si legalmente es posible. ····························· Facilito los datos de la Guardia Civil a Miguel, A. Jurídico, para que se ponga en contacto con el Sargento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-02-09','Ana: Llamo a Marta, TS SSASB Cilleros (927 51 20 37 / tsocial@ayuntamientodecilleros.es): no se encuentra hoy en el ayto. Acude L,X y V. ····· La llamo a Coria (927 5080 00). ·································· Envío un mail a Paula, TO CRR: "En relación a Julia Morón Hdez, informarte que ayer solicité a Futuex que retomen el seguimiento en el domicilio, le expuse la situación actual y la necesidad que aborden con ella la necesidad de retorno a vuestro recurso. E incluso, si notasen signos de descompensación psicopatológica que nos lo hagan constar en un informe. En cuanto a al Centro de Salud que le corresponden, es el Hoyos, en su pueblo no hay, y desde allí no se desplazan a no ser que haya realmente una urgencia que atender y no es el caso. Por otra parte, he hablado con la TS de Cilleros, ya sabía, por la hermana de Julia, que está allí. Mañana acudirá a visitarla." ························· Correo-respuesta de Paula, TO CRR: "desde aquí se le ha enviado la medicación que no encontraba en la farmacia de su pueblo, así como confirmamos que tiene cita con SM, con la gestora de caso el día 16 de febrero. Desde el SEPAD nos dicen que dispone de un plazo de 15 días desde la fecha que debería haber vuelto para hacerlo. En caso contrario se tramitaría salida del recurso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2023-02-10','-Amalia , queda cuadrado el presupuesto en la R.M: conforme a sus ingresos y el copago de la plaza en torno a 772 , se le han autorizado 180€ gastos de bolsillo al mes . Él pedía 300 pero eso no hemos aceptado. El director ha sacado ya 500€ para no ir cada mes al banco y de ahí se lo va a administrar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2023-02-10','Buenos días, conforme la sentencia de incapacitación y nombramiento, correspondiente al procedimiento de tutela nº 251/02 del juzgado de Villafranca nº1, que la Comisión Tutelar acepto el 4-10-2005, no puede testar..”con privación al incapacitado de la facultad de testar y del derecho de sufragio activo”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-10','miguel, me informa Ana que el guardia civil Campo del puesto de Alcuescar 927-120078; 665613935;661901253 le ha comentado que tutelado está ingresado en la UHB y una vez que salga lo llevarán a cumplir pena en la cárcel. La psiquiatra le ha dicho a Ana que ha tenido al menos dos compensaciones ya estando ingresado en la UHB, y no descarta enviarlo a ESM. Mi contestación: Buenos días Ana, acabo de hablar con el guardia civil del puesto de Alcuescar, Campos. Me confirma que el motivo por el que lo detendrán cuando salga del hospital es por orden de la Audiencia Provincial, donde cree que ya hay sentencia por el delito de agresión sexual que instruyó el juzgado de 1º instancia e instrucción nº6 de Cáceres y que ha resuelto dicha Audiencia Provincial. Inés, he intentado sin éxito hablar con la Audiencia Provincial. Necesitamos que solicites vía Lexnet tanto al jzdo nº6 de Cáceres como a dicha Audiencia Provincial sentencia del referido procedimiento penal por el delito arriba indicado. De todas formas intenta hablar con dicha Audiencia por si te lo pueden agilizar. Adjunto actuaciones tanto de la Audiencia como del Jzdo nº6 de Cáceres para cuando rellenes los datos del Lexnet','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2023-02-10','miguel, envío email a Amalia: Buenos días, me ha llamado el tutelado para pedir que le ayudemos en su traslado de la cárcel de Madrid a Badajoz. Comenta que está cumpliendo 8 años por robo y que sale en 2024. Le he pedido el teléfono de su abogada porque comenta que ya tiene solicitado su traslado a Badajoz. Hablo con la abogada (Olivia 691236633) que me comenta que el tutelado es un buen hombre pero con una patología que le provoca ser impulsivo y hacer cosas como lo que le ha llevado a la cárcel (el robo de 5€ en casa de sus tíos, que al denunciarlo y por robar en casa habitada la pena va de 2 a 5 años, unido a los delitos anteriores le dan para una larga temporada en la cárcel) Ella pidió al juzgado el cumplimiento de la sentencia condenatoria en centro adecuado, pero se lo denegaron. Ahora está en enfermería de la cárcel y le da por hacer tonterías como comerse unas pilas… Parece ser que el forense también dictaminó que estaba bien, motivo por el cual la sentencia le ha perjudicado en exceso. Me confirma que está pendiente de que le den el traslado a la cárcel de Badajoz y que cree que no tardará mucho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-02-10','Ana: Envío a Ángel, A. Jurídico, Informe Social para revisión de medidas judiciales de apoyo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-02-13','Ana: Correo de Julia Durán, TS Hogar Peña del Cura (julia.duranm@salud-juntaex.es): "tras conversación con Ventura , todas las deficiencias de su vivienda observadas en la visita domiciliaria, así como el arreglo de la cerradura de la puerta de entrada , están todas subsanadas. Estoy a la espera de recibir el informe medico de Atención Primaria para que solicitarle el Servicio de teleasistencia previa autorización de esa Comisión"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-02-10','Ana: Correo de Estrella, TS del, CSS-Plas: "El servicio de Terapia Ocupacional del centro, ha puesto en marcha un programa de radio que se emite todos los jueves en la SER. Quieren que participe Reme, supongo que tenéis que darnos algún permiso...." ················ Lo reenvío a los Asesores Jurídicos CTAEx. ··························· Respuesta de Miguel, A. Jurídico a Estrella, TS CSS: "Buenos días Estrella, si Reme comprende y consiente dicha participación no hará falta realizar solicitud conforme se venía haciendo antes de la aplicación de la nueva Ley 8/2021, de 2 de junio, por la que se reforma la legislación civil y procesal para el apoyo a las personas con discapacidad en el ejercicio de su capacidad jurídica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-02-13','TERESA somos Teresa y Eli del PAF de Trujillo, el viernes a última hora nos llamo Mirella y Aitor comentandonos que han discutido con Neixa y que tienen que dejar la casa el lunes. Me comentan algo , relacionado con una paga que cobra Aitor por su trabajo. Me gustaría comentaros este tema, porque no lo entiendo. Van a buscar casa de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-02-13','Ana: Correo de Alicia Cordón, Psicóloga Piso Supervisado de Almendralejo (psicologia.pisosalmendralejo@grupo5.net / 674 35 51 64): "Os comunico la renuncia voluntaria del usuario Francisco Cacho Garrido. Os adjunto documento firmado. Se le hace entrega de medicación personal y del dinero custodiado por el centro. Firma un documento de dicha entrega. Nos comunica que tiene ya sitio de estancia, aunque no nos especifica nada más." En la renuncia, él mismo escribe: "No me encuentro a gusto con tanta gente, yo esperaba algo más tranquilo y hay 7 personas en el piso" ·················· Pregunto a Alicia sobre si hay algún motivo más para su renuncia. ················· Respuesta de Alicia: "Él ha firmado la baja voluntaria. Se ha establecido con él unas cuantas horas por si quería pensarlo mejor pero estaba muy decidido a firmarlo. Últimamente, iba en aumento conductas de desafío, principalmente relacionadas con el dinero y dice que no aguantaba dicha situación. Ya comenzaba a pedir prestado dinero a compañeros y a comprar objetos que no podía pagar en el momento y los dejaba en fianza. No sabemos muy bien la cantidad de dichos objetos ni el dinero que debe." ··················· *Envío a los A. Jurídicos CTAEx, la RENUNCIA A LA PLAZA para que lo comuniquen al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2023-02-09','Ana: Correo de Óscar, Secc. Ecca., a Isabel Pino: "- La factura de ropa se abonará en los próximos días. - Se acepta el gasto en cerrajería. Ruego envíen la factura, contestando a este correo, en la que se indique un número de cuenta donde realizar la transferencia. - Se acepta la compra de la lavadora por 319€. Ruego envíen la factura, contestando a este correo, en la que se indique un número de cuenta donde realizar la transferencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2023-02-13','Ana: Conversación con Mª Ángeles, Aux. de SAD (675 264 255): Nos enviará ella las distinta facturas al ctutelar@ para agilizar. ············ Correo de Mª Ángeles: pedro69mariangeles64@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2023-02-13','Buenos días , alguna vez creo que habéis visitado a CONCEPCION ALEJANDRO DIAZ , cuando ha estado en CRR . Ahora vive con su madre en La Cañada en Badajoz , en C/ Fermín Barba , 34 . Su tf. 671356692 Cuando podáis hacéis una visita para ver cómo se encuentra. De momento está tranquila y bien , con adherencia a tto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-02-13','Ana: Se autoriza, con el dinero que tienen en el centro, la compra de una afeitadora y ropa, para antes de ingresar el UHDAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-02-13','Oscar envía email a unicaja: Buenos días. Nuevamente, a pesar de nuestro correo del 14 de noviembre de 2022, el pasado viernes 10 de febrero, el tutelado de referencia volvió a sacar dinero sin autorización, en concreto 850€, con el grave perjuicio económico que ello le conlleva y el desequilibrio mental consecuente. Rogamos no se vuelva a repetir esta situación ******************************************************* Contestación de la oficina 7130: Buenos días Oscar, en relación a la conversacion telefónica mantenida esta mañana contigo, quiero manifestaros que, sin que sirva de justificación, el cliente mantiene una actitud muy beligerante y amenzadora cuando accede a nuestras oficinas y no le permitmos reintegrar sin autorización, creando un clima muy desagradable entre clientes y empleados. Es por ello, que no es de extrañar que en alguna sucursal hayan accedido a efectuar el reintegro a fin de que cesase su comportamiento agresivo. Tal y como hemos hablado, creo que no tenemos que tolerar este tipo de comportamiento, por la imagen ante nuestros clientes, así como por nuestros propios compañeros. Creo que deberíamos elevar estas situaciones ante quien proceda, para tratar de evitarlo en lo sucesivo. ************************************************* envío de email por Oscar a la parte social y juridica: Os reenvío correo de la oficina de Unicaja de José Manuel, por si podemos hacer algo. Según me ha comentado por teléfono, si sigue en esta actitud, le cerrarán la cuenta ********************************************************* Envío de Alberto a la parte social y juridica: AREA JURÍDICA: EN MI OPINIÓN DEBERIAMOS COMUNICAR ESTA CUESTIÓN AL JUZGADO YA QUE ES MUY PROBABLE QUE ESTO TERMINE DE MALA MANERA....AVISO A POLICIA, CIERRE REPENTINO DE CUENTA, CON LO QUE ESTO VA A CONLLEVAR (UNA ESPIRAL EN LA QUE NO SE LE VA A PODER ATENDER, EMPERORAMIENTO DE SU COMPORTAMIENTO...YA LO HEMOS VISTO EN OTRAS OCASIONES CON OTROS TUTELADOS). OSCAR: X FAVOR, SI AREA JURÍDICA ESTÁ DE ACUERDO CON LO PROPUESTO, SOLICITA A LA ENTIDAD FINANCIERA QUE NOS ENVIEN ESA QUEJA, SI LO VEN OPORTUNO, DE FORMA MÁS DETALLADA Y OFICIAL...Y LES INDICAS QUE ES PARA COMUNICARLO AL JUZGADO. OSCAR: LE INDICAS A LA ENTIDAD FINANCIERA QUE, SI LO CONSIDERAN OPORTUNO, DEBEN LLAMAR A LA POLICÍA (CON INDEPENDENCIA DE QUE NOS AVISEN A NOSTROS).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-02-13','Ana: Correo de Estrella, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Tenéis algún certificado de defunción de Ángel Pérez Manzano, pareja de Desi por ahí, para que me lo envíes. Es que tienen un contrato con Yoigo y quiere darle de baja, estamos trabajando con ella para que acceda a comprar tarjeta prepago para el móvil...." ················ Le envío el Cdo. de Defunción de Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-02-09','Ana: Correo de Anabl Gil, TS del SSASB Miajadas (servicios.sociales@miajadas.org // 927 901 238): "Adjunto algunas fotos relacionadas con la acumulación de comida, comida en mal estado y medicamentos en la basura correspondiente a JOAQUINA MAYORAL PIZARRO, igualmente tras su registro te enviaré un pequeño informe social sobre su situación, considero que la permanencia de Joaquina en su domicilio se hace insostenible y a nivel comunitario no tenemos capacidad para garantizar su bienestar, con lo que seria necesario efectuar las gestiones pertinentes para su ingreso involuntario en centro residencial que pueda garantizar su bienestar." ····································· *Guardo fotos en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-02-13','Ana: En el Informe Social para la Rendición Anual, Anabel, TS, expone la valoración de las necesidades de apoyo que Joaquina precisa para la administración de su presupuesto, para el aseo (ni se ducha ni permite que la Aux. de SAD, le ayude a ello a pesar de habérsele adaptado el baño), para la alimentación (aunque ha contratado servicio de cáterin, en numerosas ocasiones no consume la comida que le llevan), para la toma de medicación (suspende los tratamientos bajo su propio criterio), para el descanso (duerme en un sofá y no descansa adecuadamente, habiéndole salido úlceras en las piernas). "Necesita supervisión y apoyo en todas las AVD relacionadas con la protección de su salud, así como la que respecta a su relación con el entorno, administración del presupuesto, así como ayuda física relacionada con su movilidad." "Considero necesario ingreso involuntario en centro residencial que favorezca su protección y garantice su bienestar a través de hábitos de vida saludable...", "...a nivel comunitario los recursos que podemos poner a su disposición son insuficientes para garantizar su bienestar" ··································································································································································································· Envíaré a los A. Jurídicos y a Maite - CTAEx, imágenes de la vivienda, Informe de alta terapéutica del CRR e Informe Social del SSASB para que soliciten internamiento involuntario al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-02-13','Ana: Cumplimento y subo al portafirmas digital el Contrato Residencial de la Casa de la Misericordia. ···················· Envío correo a Julia, Coordinadora de la misma (casadelamisericordia.alcuescar@gmail.com): "Adjunto los siguientes documentos relativos a SERGIO SOLANILLA LUJÁN: - Póliza de su Seguro de Decesos - Contrato de ingreso en vuestro centro firmado digitalmente por el Presidente de la CTEAx Por cierto, he hablado con Julia, madre de Sergio, me comunica que éste el sábado le dijo que se quería marchar de vuestro recurso, ¿os ha verbalizado algo así? ¿cómo lo veis? Decidme si consideráis procedente que hablemos desde aquí con él. Julia me ha facilitado su número de móvil. Ante cualquier otra cuestión, no dudéis en contactar." ························· Nº de Sergio: 640 654 897. ······························································································································································································· Respuesta de Julia, Coord. Casa Misericordia: "Gracias por la documentación. Sergio no me ha dicho nada y por el momento su conducta en la casa es buena. Me lo ha comentado su madre. Estamos pendientes y te digo si esnecesario que intervengaís."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-02-13','Ana: Correo de Alberto, Jefe Secc. Ecca: "ANA: OK, MODIFICACMOS ASIGNACIÓN + ANA: CONFIRMALE A LOURDES A PARTIR DE CUANDO DEBEMOS DARLE LOS 200 € • 290 € PRIMERA SEMANA DE CADA MES • 90 € X SEMANA EL RESTO DE SEMANAS DE CADA MES. ANA: AUNQUE A NIVEL ECO ESTE BIEN, LOS EXTRAS DEBE DE RESTRINGIRLOS....ESE FUE EL MOTIVO DE SUBIRLE EL REINEGRO HACE TIEMPO A 90 €/SEMANA. LOURDES: CUANDO ANA TE CONFIRME MOMENTO MODIFICAMOS REINTEGRO PERMANENTE (HE HECHO BORRADOR EN EL EXPEDIENTE A FALTA DE INCLUIR EFECTO Y MODIFICAR NOMBRE BANCO). • CABE POSIBILIDAD DE QUE, TAL Y COMO HEMOS HABLADO, HAYA QUE HACER UN REINTEGRO PUNTUAL ESTE MES." ··································································································································································································· Ana: Tras hablar con Ángel Félix (643 622 174), envío correo a Lourdes, Alberto, Maite y Ángel - CTAEx: "Acabo de hablar con Ángel Félix, finalmente cree que no se va a quedar más tiempo en esa casa, así pues, se le hará el reintegro puntual de 200€ para abonar este mes. Lourdes, como hemos hablado, si puedes, hazlo para que pueda retirarlo este miércoles, por favor. De cara a los siguientes meses, quiere encontrar un alquiler “regularizado”, ya sea en Plasencia o en otro pueblo de los alrededores. Cuando nos confirme así procederemos. La opción de los 200€ a primeros de mes en concepto de “alojamiento” sigue abierta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-02-13','Ana: Correo de Ceferino, al ctutelar@: "Buenos días Ana podríais enviar ya mis extras anuales? Ya que Paula tarda mucho en reunirse con vosotros por favor contestarme a este email gracias un saludo" ························· Mi respuesta: "Como ya te he explicado, en varias ocasiones, estamos a la espera de la reunión con las profesionales del centro, pues ese era el acuerdo. Pongo en copia a Paula y Carolina para que estén al corriente." ········································ Correo de Paula, TO CRR: "como acordé con Ceferino estamos demorando la reunión acerca de los extras algunas semanas, de modo que pueda poner en práctica acciones dirigidas a evidenciar su compromiso y responsabilidad frente a su proyecto de vida: "ser confiable en cuanto a las decisiones que tomo porque me hago cargo de lo que implican, los beneficios y las consecuencias de esas decisiones, tanto si son acertadas como si no lo son". La idea es que tenga la oportunidad de poner en valor sus habilidades y compromiso para poder obtener, a través de los extras anuales, objetos que le ayudarán a conseguir sus objetivos. Y poder distinguir la idea de conseguir algo (un objeto) como resultado a conseguir algo como medio para una meta. Este es el motivo principal de la demora. En los próximos días, procederemos a realizar una propuesta de fecha de reunión, posiblemente virtual, para poner sobre la mesa todas estas cuestiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2023-02-14','Ana: Envío correo a Marta Custodio, TS de CRM Los Molinos de Montehermoso (mcustodiob24@hotmail.com): "Adjunto el Certificado de Pensión relativo a FLORENCIA SIMÓN MARTÍN. En cuanto al cobro del servicio de traslado al médico, me confirman desde la sección económica, que podéis hacer el cargo en cuenta (dado que tenéis la autorización SEPA) y con que nos remitáis la factura por el servicio a la atención de la sección económica a la siguiente dirección ese suficiente: ctutelar@salud-juntaex.es Aprovecho para preguntarte cómo sigue Florencia. Ya me dices cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-02-14','Ana: en relación al correo-e de Beatriz, Res. Garrovillas de Alconétar (beapavonguerra@hotmail.com), solicitando el Cdo. de pensión de Juan Gregorio, le envío correo: "El Certificado actualizado como tal, no nos lo han enviado desde el INSS, voy a solicitarlo, pues no nos ha llegado con las revalorizaciones. En cuanto me lo remitan, te lo hago llegar. La cuantía creo que te la dijo Icíar. Por cierto, aprovecho para comunicarte el nuevo número de cuenta que se le ha abierto en la entidad IBERCAJA: E S 0 9 2 0 8 5 4 5 1 1 9 6 0 3 3 2 5 4 1 2 3 1, a ver si con esta otra entidad dejamos de tener problemas. *Me comunican mis compañeras de la sección económica que, por favor, no le paséis ningún cargo por aquí hasta que le ingresen la pensión. Suponemos que el lunes día 27 ya podréis hacerlo." ································································································································································································ Envío a registro (oac.merida.san@juntaex.es) oficio-solicitud de certificado actualizado de pensión al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-02-14','-Amalia : Plan de intervención inicial finalizado : -la comida y cena se la traen a casa desde la residencia. -se le da una autorización de 100€ semanales. -Se le ha hecho una transferencia de la cuenta de la Caixa a la nueva que se le ha abierto en el pueblo en UNICAJA. -Se le ha cambiado la pensión de Incapacidad Pte a la nueva cuenta de Unicaja. -Se ha indicado seguimiento a FUTUEX . -Sin red social ni familiar de apoyo . Vive su padre y hermanos pero no tienen contacto. -Con bastante autonomía a nivel físico y social , sabe utilizar los recursos y pide ayuda cuando lo necesita . Visita con bastante frecuencia a la TS del SSASB. -Paso el caso a la zona de Ana .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-02-14','-Amalia : Plan de intervención inicial finalizado : -la comida y cena se la traen a casa desde la residencia. -se le da una autorización de 100€ semanales. -Se le ha hecho una transferencia de la cuenta de la Caixa a la nueva que se le ha abierto en el pueblo en UNICAJA. -Se le ha cambiado la pensión de Incapacidad Pte a la nueva cuenta de Unicaja. -Se ha indicado seguimiento a FUTUEX . -Sin red social ni familiar de apoyo . Vive su padre y hermanos pero no tienen contacto. -Con bastante autonomía a nivel físico y social , sabe utilizar los recursos y pide ayuda cuando lo necesita . Visita con bastante frecuencia a la TS del SSASB. -Paso el caso a la zona de Ana .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2023-02-14','PROPUESTA (PENDIENTE DE TU OPINIÓN Y DE LO QUE HABLES CON CENTRO): ESO SÍ...EL CENTRO SE TIENE QUE COMPROMETER A QUE NO HAYA DEMANDAS X PARTE DE LA TUTELADA AYUDÁNDOLA EN LA GESTIÓN. ASIGNACIÓN: ENTRE 480 Y 500 €/MES 1 EXTRA EN JUNIO Y OTRO EN DICIEMBRE X 450 € CADA UNO NO SE AUTORIZARÁ NI UN SÓLO EXTRA DURANTE TODO EL AÑO Y PARA NINGÚN CONCEPTO. GASTOS EXTRAORDINARIOS QUE HUBIERA QUE ASUMIR MINORARÁN EL IMPORTE DE LOS REINTEGROS MENSUALES Y DE LOS ASOCIADOS A LAS PAGAS EXTRAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2023-02-14','PROPUESTA (PENDIENTE DE TU OPINIÓN Y DE LO QUE HABLES CON CENTRO): ESO SÍ...EL CENTRO SE TIENE QUE COMPROMETER A QUE NO HAYA DEMANDAS X PARTE DE LA TUTELADA AYUDÁNDOLA EN LA GESTIÓN. ASIGNACIÓN: ENTRE 480 Y 500 €/MES 1 EXTRA EN JUNIO Y OTRO EN DICIEMBRE X 450 € CADA UNO NO SE AUTORIZARÁ NI UN SÓLO EXTRA DURANTE TODO EL AÑO Y PARA NINGÚN CONCEPTO. GASTOS EXTRAORDINARIOS QUE HUBIERA QUE ASUMIR MINORARÁN EL IMPORTE DE LOS REINTEGROS MENSUALES Y DE LOS ASOCIADOS A LAS PAGAS EXTRAS.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2023-02-14','TERESA HABLO CON CATI DE PLENA INCLSUION BADAJOZ SE PLANIFICA TRASLADO PARA EL DIA 23 DE FEBRERO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2023-02-14','Adjunto nueva autorización semanal de 120€ para el tutelado D. Bartolomé Alba Gragera, a partir del próximo 30/01/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2023-02-14','TERESA SE OBSERVA UN CARGO EN CUENTA REALTIVO A UN COCHE ME DICEL A TS DEL CENTRO Pues si es el mismo que la última vez que le pasó, era un ex cuñado suyo, que era pareja o marido de su hermana Esther, y creo recordar que es primo... (tienen ahí un lío de familia...). Lo que no se si es el mismo vehículo o han comprado otro nuevo, porque no te puedes fiar de ellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2023-02-14','Adjunto nueva autorización semanal de 120€ para el tutelado D. Bartolomé Alba Gragera, a partir del próximo 30/01/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-02-14','Muy buenos días Amalia, Te adjunto la última información sobre Emi ya comentada con el SEPAD. Emi se presentó el viernes sobre las 13:30h, quedándose el fin de semana en el centro. En el tiempo transcurrido, los compañeros reflejan muestras de agitación, labilidad emocional, faltas de respeto, amenazas con volverse a ir, cambios de opinión… hasta que, finalmente, ayer domingo (en el turno de mañana), solicitó que se le diera la medicación de todo el día y del lunes por la mañana, comunicando que se iba con Antonio (amigo/compañero sentimental de Olivenza) y que hoy irían a Badajoz a que él cobrara. Ha dejado aquí sus enseres. Acaba de llegar al centro y con intención de quedarse unos días, por el momento. Me pregunta qué ha donde va a irse. No sé si tenéis ya pensado o gestionado algo. Hoy me dice que ella a Don Benito no, por si Miguel Ángel viene a por ella, pero que la idea de Málaga con la especialidad de TLP le parece estupenda… Ya sabemos que esto es ambivalente y su criterio no es estable, pero por comentarlo. Entiendo que desde la Comisión valoraréis lo más adecuado para ella. Desde el SEPAD ya se está gestionando la pérdida de plaza. Ya nos decís lo que sea. Cualquier cosa en la que podamos ayudar, nos lo hacéis saber. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2023-02-14','Ya tuvimos un hilo hace unos días sobre los pagos a Hacienda de Ceferina (Miguel: no podías hablar con tu contacto en Hacienda porque estaba de baja) La de 2022 ya se la haremos desde aquí. 2020 y 2021 las pagaremos conforme lleguen las complementarias con su correspondiente sanción y/o recargo. Cuando esté al día de pagos y le hayamos solucionado todas las cuestiones pendientes, ya solicitarán los sobrinos la curatela para “cuidarla como se merece”.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-02-14','Ana: Tras llamada de Javier (624 109 525), envío correo a Toni-Futuex: "En relación a JAVIER AGUDO CUMPLIDO, como te comenté ya ha pasado a piso supervisado. Acabo de hablar con él y está contento, al menos de momento. Me dice que tras la limpieza de su domicilio, gestión en la que apoyasteis, aún no se le han devuelto las llaves de su vivienda y quiere que se las devuelvan. He aprovechado para decirle que pronto comenzarán a visitarle desde el programa de apoyo comunitario y ya aprovecharán para devolvérsela, pues entiendo que las tendrá alguna de las compañeras, no? Ya me confirmas. Por cierto, el apoyo/seguimiento por parte de las compañeras le parece bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2023-02-14','Ana: Llamo a Toni-Futuex: el viernes Gloria acudió con José al hotel. Constata que la humedades de la habitación, aunque ya no están tan mal, no está arregladas aún. Y al parecer sólo conectan 3h las calefacción por la tarde. ····· Van a acompañarle a buscar algún alojamiento alternativo de los que le gustó y no había disponibilidad en su día, por si hubiera alguna habitación libre ahora. ····· ······················ *Correo de José: dice que se ha comprado un radiador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-02-14','Ana: Llamada de Doroteo, pide extra para invitar a los compañeros de centro por su cumpleaños. ··············· Envío correo a la secc. ecca. (ctutelar@): "En relación a DOROTEO DÍAZ CERRO, comunicaros que ha llamado para solicitar 40 € por su cumpleaños (3/03/23), para invitar a churros en el centro. Por mi parte si es viable, ok. Entiendo que lo más sencillo sería realizar una autorización para retirada de efectivo cuando se aproxime la fecha. Eso sí, en caso de aprobarse, por favor, comunicar a Julia, Coordinadora de la Casa de la Misericordia (casadelamisericordia.alcuescar@gmail.com) que se aprueba a tal fin y qué día podrá ir a retirarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-02-14','Ana: Envío correo a Carmen Sánchez, Directora de la Fundación Autismo Sur (direccionhogares@autismosur.es / teayudamos@autismosur.es): "Adjunto documento sobre REVALORIZACIÓN DE LA PNC relativa a COSTI ALEXANDRU RIZEA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-02-10','Ana: Recibimos certificado de cuantías percibidas en el ejercicio 2022, de la Dirección Gral. de Personas Mayores, Participación Activa y Soledad no deseada de la Junta de Andalucía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-02-15','Ana: Correo de Julián Álvarez Delgado - Gerente de COCEMFE (gerencia@cocemfecaceres.org / 927 23 90 28): "Desde COCEMFE Cáceres les hacemos llegar informe médico en el cual se indica la situación clínica sufrida por Tomás el domingo 11-2-2023. Tomás sufrió una caída al sujetarse de una silla eléctrica de un compañero de residencia. Se avisó al PAC que lo derivó al H.U.C. Tomás se encuentra bien a día de hoy pero requiere tratamiento odontológico para tratar incisivo partido. Solicito permiso para poder contactar con odontólogo y que Tomás sea revisado. Para cualquier pregunta al respecto del suceso acaecido, no duden en ponerse en contacto con nosotros." ················ Se autoriza la asistencia a odontólogo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-02-15','Ana: Correo de Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es): "tengo que hablarte de Francisco Cacho Garrido, por su solicitud de alta en los PS. He hablado con él y sigue opinando que no quiere volver, ahora se encuentra en el albergue de emergencias en Cáceres. Por ahora me dice Raquel de la Comisión que aguantaran unos días hasta que le quiten, pero solo unos días. Ya hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2023-02-15','Ana: Correo de Estrella, TS CSS-Plas: "Se le ha prescrito a Yolanda Caldera un andador de 4 ruedas para que pueda salir a la calle con seguridad. Te informo para que nos deis el visto bueno al gasto." ································· Tras hablar con ella, le escribo: "En relación a tu correo, y tal y como hemos acordado mediante conversación telefónica, dado que YOLANDA CALDERA MARTÍN necesita el andador y la Terapeuta considera que el del presupuesto de los 105 € es adecuado, doy mi visto bueno a la compra del mismo. Pongo en copia a Albero y Óscar, Secc. Ecca. No obstante, por favor, remitir los dos presupuestos y la factura, una vez comprado, a la atención de la secc. ecca. al ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='LOPEZ'and apellido2='PILARES'),'2023-02-14','EXITUS Fallecida el 14/02/2023. Se transcribe correo remitido por el centro informando del óbito: "Buenos días Teresa. Ayer por la tarde-noche falleció la tutelada Dª María López Pilares, en la Residencia de Mayores "Felipe Trigo". Debido a las horas, para todas las gestiones con el seguro (OCASO), funeraria y demás gestiones relacionadas con el fallecimiento me encargué yo, así aparezco como solicitante. Por expreso deseo de la tutelada, será enterrada en el cementerio de Badajoz, en el mismo nicho que su madre. El entierro es mañana a la 9:00 de la mañana. Está todo organizado. Nieves"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-02-15','Maite: han llamado desde la UHDAC, han hablado con Ana, para decir que Aarón está allí, va a ingresar y nos piden la autorización de ingreso involuntario. Se pidió en 2021 y no lo tenemos. Miguel habló con el juzgado en junio de 2022 y habían archivado el expediente. Una vez consultada la instrucción que define y regula la UHDAC, comprobamos que no lo recoge como requisito de ingreso. Hablamos con Rosa, personal de administración del socisanitario de Plasencia. Le explicamos la situación, con la intención que desde allí lo comuniquen al juzgado para que este se ratifique y nos dice que se hará así.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2023-02-16','Ana: Correo de día 13 al ctutelar@ de Mónica Muriel, Educadora del P.S. Plasencia (educacion.pisosplasencia@grupo5.net): "soy Mónica Muriel, educadora de referencia del piso supervisado de Plasencia. Anteriormente contactaba con vosotros/as Paula, terapeuta ocupacional del C.R.R., pero de ahora en adelante seré yo quien os contacte por asuntos relacionados a las personas que viven en el piso (actualmente Javier Agudo Cumplido y Félix Franco Jiménez, y en los próximos días también Carmen Solana Chanclón). Respecto a Félix, la pasada semana tuvo cita con la trabajadora social del Equipo de Salud Mental y se abordó la derivación a un recurso de mayores, expresando deseo de residir en un piso de mayores. En esta cita acordaron que tras cumplir 64, en marzo, se iniciarán los trámites. Respecto al precio, mencionó la TS que sería de unos 600€ aproximadamente y me pidió que contactara con vosotros por si hubiera algún tipo de dificultad económico con respecto a Félix." ···················· Mi respuesta: "Con respecto a Félix Franco, precisamente Paula me dijo ayer, en conversación mantenida por otros asuntos, que Félix ha rechazado plaza en un piso, ¿es así? De todas formas, si se van a hacer los trámites a partir del mes que viene, está bien, lo importante es que encuentre recurso antes de los 65 o, como mucho, antes de superar esta edad, pues, como sabéis, podría quedarse “en la calle” por superar la edad para vuestro recurso. En cuanto al precio de la plaza, no tendría problema en abonarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2023-02-16','Ana: En relación a la llamada de ayer del Call Center para dar cita para valoración de Dependencia desde el equipo de Mérida (les consta sólo la dirección del representante legal), envío a Julio, Aux. Advto. CTAEX, para que registre en SIREX la Comunicación de variación de datos para hacer constar la dirección de Antonia (CSS-Plas.).','2');
