insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2023-02-16','Por una parte, ayer se puso en contacto con Segunda una trabajadora social del Hospital donde se encuentra ingresado CRISTOBAL CASQUERO GARCÍA. Según me dice, están preparando la documentación necesaria para poder solicitar plaza en CASA VERDE con intención de que allí se siga trabajando su rehabilitación neurológica. Una vez solicitado, en dicho centro evaluarán el caso, y decidirán si cumple los requisitos para poder ser derivado. Han acordado con Segunda que mañana a la 13:00 deberá acudir al hospital para firmar la solicitud en calidad de guardadora de hecho. ¿Segunda podría firmar dicha solicitud? o sería necesario que os la enviáramos a vosotros?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2023-02-16','Por una parte, ayer se puso en contacto con Segunda una trabajadora social del Hospital donde se encuentra ingresado CRISTOBAL CASQUERO GARCÍA. Según me dice, están preparando la documentación necesaria para poder solicitar plaza en CASA VERDE con intención de que allí se siga trabajando su rehabilitación neurológica. Una vez solicitado, en dicho centro evaluarán el caso, y decidirán si cumple los requisitos para poder ser derivado. Han acordado con Segunda que mañana a la 13:00 deberá acudir al hospital para firmar la solicitud en calidad de guardadora de hecho. ¿Segunda podría firmar dicha solicitud? o sería necesario que os la enviáramos a vosotros?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-02-16','Buenos días , comunicarte la decisión que se ha tomado con respecto al móvil , tenéis que darlo de baja ,se dejará de pagar . Se le sube la asignación de 45 a 50€ semanales para que con esos 20€ al mes pueda realizar el prepago para el móvil . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-02-16','Buenos días , comunicarte la decisión que se ha tomado con respecto al móvil , tenéis que darlo de baja ,se dejará de pagar . Se le sube la asignación de 45 a 50€ semanales para que con esos 20€ al mes pueda realizar el prepago para el móvil . ------------------------ De Angel : Buenos días, En el testamento nada se dice del vehículo, no hay documentación, como bien dice ella. En cualquier caso, ¿ella puede conducir? En el correo de más abajo habla de un duplicado de permiso de circulación. ¿De ella? ¿Duplicado de la ficha técnica? ¿Sabemos qué tratamiento médico y psicofarmacológico recibe? Seguramente ahí podríamos obtener información y posible limitación para conducir. Reitero que Mª. Rosa no es la heredera, los herederos son la hija de Blas y las hijas de Mª. Rosa. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-02-16','Buenos días , comunicarte la decisión que se ha tomado con respecto al móvil , tenéis que darlo de baja ,se dejará de pagar . Se le sube la asignación de 45 a 50€ semanales para que con esos 20€ al mes pueda realizar el prepago para el móvil . ------------------------ De Angel : Buenos días, En el testamento nada se dice del vehículo, no hay documentación, como bien dice ella. En cualquier caso, ¿ella puede conducir? En el correo de más abajo habla de un duplicado de permiso de circulación. ¿De ella? ¿Duplicado de la ficha técnica? ¿Sabemos qué tratamiento médico y psicofarmacológico recibe? Seguramente ahí podríamos obtener información y posible limitación para conducir. Reitero que Mª. Rosa no es la heredera, los herederos son la hija de Blas y las hijas de Mª. Rosa. --------------------------- Buenos días, Mª. Rosa está curatelada en la esfera patrimonial, estamos para ASISITIRLA, es decir, para firmar junto a ella cualquier documento que afecte a su patrimonio, como es esta herencia. Tras estudiar el caso, personalmente veo algunos aspectos delicados. La hoja de encargo la firma solo Mª. Rosa, cuando deberían firmarla también los herederos (hijas), además, hay algunos aspectos no detallados: No incluye gastos de desplazamientos, suplidos, honorarios de procurador, cualquier trámite distinto se minutará aparte. Blas, en el testamento, lega a Mª. Rosa 1/3 de libre disposición y el usufructo universal y vitalicio y nombra herederos a la hija adoptada por él (Mª. Rosa Ródenas Serrano) y las 2 hijas de Mª. Rosa (Dulce Nombre Mª y José Manuel Escribano Serrano). Por otro lado, hay un embargo de Eos de 5.000 euros, con La Caixa? No tenemos información/documentación. Al parecer están pendientes que los hijos les faciliten información al respecto. Con respecto al vehículo, no hay documentación. Antes de abonar los 1.028 euros de la hoja de encargo, creo que deberíamos aclarar todos estos aspectos con el despacho de Abogados para indicarles todas estas circunstancias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-02-16','Ana: Envío correo a Rosa Bravo, Advto. CSS-Plas.: "Adjunto documentos de: - Compromiso Formal de la UHDAC - Autorización expresa Relativos a AARÓN ROSADO ALARCÓN. Ambos firmados digitalmente por el Presidente de la CTAEx por delegación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-02-16','Ana: Envío correo-respuesta a Estrella, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Mi compañero Óscar va a remitiros autorización general para que podáis retirar dinero para gastos de bolsillo de la cuenta de UNICAJA. No se ha hecho con anterioridad porque no tenía dinero en cuenta, es más, en la del BBVA tiene múltiples deudas con el propio banco y la de UNICAJA la tenía en negativo… No podrá disponer de mucho dinero al mes, en principio, como mucho 100, y en función de como se vaya subsanando ya iremos viendo." ··································································································································································································· Subo al portafirmas digital la Solicitud de Cambio de Datos Bancarios que remitiré a PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-02-16','Ana: envío correo a REGISTRO (oac.merida.san@juntaex.es): "Adjunto los siguiente documentos, a nombre de Soledad Esteban Iglesias, cuyo cargo ostenta la CTAEx - Oficio-solicitud de certificado actualizado de pensión - Testimonio de Auto de nombramiento y aceptación del cargo Para remitir a la dirección provincial del INSS de Cáceres"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2023-02-16','Ana: Envío correo a Amalia: "Buenos días Amalia, Me han convocado a una subcomisión de valoración de caso del área de salud de Mérida, que tendrá lugar el 24 de febrero, relativa a MIGUEL GAMERO GÓMEZ, puesto que en la de 2019 estuve yo, al llevar yo los expedientes de las personas a cargo de la CTAEx que residían en Zaragoza. A mí no me importaría estar, si se considerara conveniente, pero entiendo, que dado que ya hace años que llevas tú el expediente, lo lógico sería que asistieras tú. Pongo con copia a Cristina del Villar, para que esté al corriente, y a Maite, en calidad de Jefa de Sección."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-02-16','Ana: Pido a Jorge Morán, Jefe de Ud. de Prestaciones Eccas. SEPAD, los Modelos 50 para abonar los cobros indebidos por la Prestación Ecca. para cuidados en el Entorno Familiar. Hemos recibido la carta (2ª reclamación, pero no los modelos 50, al parecer se los entregaron a un tal "Jacinto Glez. Carrero". ······················· *Se los entrego a Óscar, Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-02-17','Ana: Envío correo-e a Julio, CTAEx: "Adjunto, para su registro en SIREX, los siguiente documentos relativos a Mª MONTAÑA GONZALEZ ROLO: - Solicitud de cambio de datos bancarios para el cobro de la PNC - Modelo para alta de terceros Para remitir al Servicio Territorial de Cáceres" ······································································································································································································· Llamo a Laura Domínguez, TS IMAS - CC (927 21 23 35 y la ext. 4417): El año pasado le concedieron los mínimos vitales, 750€ en total para abonar las facturas de luz y agua. Pero el año pasado se les acabó el crédito muy pronto (septiembre). ····· Este año no ha salid todavía. ···· *Ha conseguido que "le protejan" las facturas de la luz. De agua no ha sido posible, pero los padres han abonado la deuda de agua. *No obstante, se muestran preocupados por este asunto. ······················· *Acordamos que en cuanto salga la convocatoria de este año, me enviará la solicitud para la firma del Presidente CTAEx y registrar la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2023-02-17','miguel, llama la cuñada de la tutelada Rebeca Gallego comentando que va a reenviarnos email del abogado que está tramitando la herencia del hermano de la tutelada porque necesita una serie de documentación porque van a demandar a la mujer de su tío. Afirma cuestiones inconexas como que hemos hablado con el hijo de la tutelada (y que desde le Ctaex se le ha ofrecido el que él herede y él renuncia a la misma). Quedamos pendiente de que a ctutelar reenvíe ese email. Recordemos que la tutelada no dispone de capacidad económica para el pago del impuesto de sucesiones... ***************************************************** email reenviado por Rebeca Gallego >rebecagallego27@gmail.com> : adjunta la diligencia del juzgado nº1 Coria, procedimiento DIH Division de Herencia 26/2023, requiriendo sentencia de incapacitación y nombramiento a la Ctaex Esto es lo que nos pide el Juzgado: que aportemos documentación que pruebe que tu tía está incapacitada y tutelada por la Junta . *************************************************** Mi contestación al abogado José Lomo José Lomo >joselomo@lomoabogados.com>, 923-211680 Buenos días, adjunto la información requerida por el juzgado. Comentarle que Emilia no dispone en este momento de capacidad económica para contratar sus servicios, ni para afrontar otros gastos, motivo por el cual cualquier gasto que le corresponda a ella deberá detraerse del haber que pueda corresponderla de la masa hereditaria. Le llamaremos en próximos días al 923-211680 para informarnos más concretamente, de los pormenores de los trámites a realizar y del activo y pasivo que componen la masa hereditaria ******************************************************* contestación de José Lomo Carasa: Buenos días de nuevo , De acuerdo con lo que nos indicas. A tu disposición para lo que precises. Te mantendré informado de la marcha del procedimiento, con independencia de que os notifiquen la demanda. Un saludo, José Lomo Carasa Abogado Brocense 12, 2º H. 37002 Salamanca Tel.: 923 21 16 80 www.lomoabogados.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2023-02-17','miguel, llama la cuñada de la tutelada Rebeca Gallego comentando que va a reenviarnos email del abogado (Jesús Lomo) que está tramitando la herencia del hermano de la tutelada porque necesita una serie de documentación porque van a demandar a la mujer de su tío. Afirma cuestiones inconexas como que hemos hablado con el hijo de la tutelada (y que desde le Ctaex se le ha ofrecido el que él herede y él renuncia a la misma). Quedamos pendiente de que a ctutelar reenvíe ese email. Recordemos que la tutelada no dispone de capacidad económica para el pago del impuesto de sucesiones...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-02-17','miguel, llama Pedro de la Gestoria que está tramitando la herencia (927-421270) y me confirma que van a dejar la documentación en la notaria de Plasencia de Gomez Moro (Marta) 927-427147. Ello sólo tramitarán la liquidación del Impuesto de Sucesiones y herencia en notaria. Mandara email para que le firme el representante de la Ctaex la autorización para los trámites, presupuesto que cobraran, e información de un par de abogados para que desde la Ctaex pidamos presupuesto para el trámite judicial de autorización de aceptación y aprobación de herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-02-17','Ana: Llevo a REGISTRO la DECLARACIÓN ANUAL DE PNC para remitir a la Delegación Territorial de Inclusión Social, Juventud, Familias e Igualdad de Málaga.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-17','Ana: Correo de Mª Carmen, TS HSPA-CC (mariac.rodriguez@externos.salud-juntaex.es): "Buenos días, tras la conversación telefónica mantenida ayer te informo de: • La talla de ropa interior es la M. • El número de pie para las zapatillas de estar por casa es el 40. Informa la psiquiatra Dra. María García que su pretensión a nivel médico es enviar al paciente a la UME, pero no se puede cumplir condena en este centro. Rogamos cambio de medida y que fuese consultado, de nuevo, con su asesoría jurídica por si fuese posible permuta de pena. Ante cualquier duda ponerse en contacto con Dra. María García. recordarles que la semana que viene el paciente será altable." ································································································································································································· Reenvío correo a A. Jurídicos: "Os reenvío correo de Mª del Carmen, TS del Hospital San Pedro de Alcántara. Subrayo en amarillo. ¿Es posible solicitar que cumpla la pena en el C. Sociosanitario? Ya me decís cuando podáis. Hay que dar respuesta lo antes posible, pues sino la semana que viene la Psiquiatra le dará el alta." ································································································································································································ Envío correo a Toni: "En relación a SATURNINO MIGUEL SALGADO JIMÉNEZ, nos solicitan en el hospital que le llevemos zapatilla de estar por casa, ropa interior (boxes y calcetines) así como una bolsa de aseo (cepillo de dientes, pasta, desodorante y colonia) • La talla de ropa interior es la M. • El número de pie para las zapatillas de estar por casa es el 40. Intentad llevárselo lo antes posible, pues seguramente esté allí sólo hasta la semana que viene (no nos han concretado fecha). Podéis ir a alguna tienda/supermercado que ya os conozcan y que remitan directamente la factura por mail a ctutelar@salud-juntaex.es , para que lo abonen mediante transferencia y así agilizarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-02-17','Ana: Envío correo a Julio CTAEx: "Adjunto los siguientes documentos relativos a MARÍA JIMÉNEZ PICÓN, para remitir a la Gerencia Territorial de Cáceres, - Comunicación de variación de datos bancarios para el cobro de la prestación económica vinculada al servicio de Dependencia - Alta de terceros"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2023-02-17','Ana: Llamo a María, T. Soc. del C.M. Sierra de San Pedro (673 31 54 39): para solicitar informe social actualizado e informes médicos sobre su estado de salud, para remitir al Jdo., pues lo requieren para la revisión de las Medidas Judiciales de Apoyo, pero NO OBTENGO RESPUESTA. ············ Llamo al centro (927 383 258), hablo con Modesto, Adtvo. y me facilita los dos correos para que los solicite por esta vía (administracion@centrodemayoressierradesanpedro.es / serviciossociales@centrodemayoressierradesanpedro.es). ············ *Les remito el correo solicitando informes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-02-17','Ana: Llamada de José Manuel, dice que se encuentra mal, tuvo que ir al PAC y le han dicho que tiene una infección respiratoria, le han recetado antibióticos. ·············· Hoy ha acudido al ESM-CC, la Psiquiatra le ha dicho que por qué no se va a un centro y él le ha explicado que Pilar Martín le ha dicho que ha agotado todas las posibilidades de RR de Salud Mental. ···· El día 23 de febrero, tiene cita telefónica con su MAP, Dra. Obdulia. ··············· *Al final de la conversación dice que pensándolo bien no quiere ir a un centro. ··············· Quiere vivir solo en una casa baja. ·········· Esperará a la cita en Vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-02-17','Ana: Francisco Casco Araujo, Asesor Técnico, de la Dirección Provincial de la TGSS CC (francisco.casco@seg-social.es / 927 62 00 63) nos remite el Cdo. de Vida Laboral solicitado. ············ Guardo en el expdte. digital. ·········· Ha estado de alta de forma efectiva en el Sist. Seg.Soc.: 24 años, 1 mes y 21 días. ··················· *Cuando cumpla los 65 años no contará con la cotización suficiente para la percepción de la P. de Jubilación, pero a los 67 años sí. ······ *En principio, decidimos mantener a José Manuel con el Subsidio, pues a partir de los 67 años mejoraría considerablemente su situación económica. ························································································································································································· Envío correo a Paula, TO, y Carolina, Psicóloga, CRR: "En relación a José Manuel Moreno Carlos, comunicarte que hemos recibido ya su VIDA LABORAL. En teoría, tiene tiempo cotizado suficiente y reúne los requisitos para poder solicitar la Pensión de Jubilación a los 67 años. No obstante, para asegurarnos de que todo está bien, y de la cuantía que le corresponderá (que en principio será la mínima y que dobla la de la PNC) sería interesante pedirle cita y que le acompañaseis desde el centro (o en su defecto desde el Programa de Apoyo Comunitario que gestiona FUTUEX) para que nos lo confirmen. Por teléfono intenté consultarlo cuando llamé, pero no facilitan esta información por esta vía. Y ahora he intentado pedir cita a través de la Web, pero da error la página. De todas formas, piden su número de teléfono y correo electrónica además del nombre y DNI. Por lo que queríamos pediros que le ayudéis a pedir cita a través de la Web y a ser posible le acompañéis a la misma llegado el momento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2023-02-20','Le han comunicado a Segunda que está previsto que el próximo martes día 22 de febrero Cristóbal sea trasladado al centro Hospital Casaverde situado en Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-02-20','Ana: envío email a Estrella, TS CSS, informando de la conversación mantenida el viernes con Laura, TS IMAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-02-07','Ana: Correo de Estrella, TS CSS (estrella.duranc@salud-juntaex.es): "Hemos acordado en reunión de unidad, que vaya Desi a casa de pase el fin de semana. Yéndose el viernes y regresando el lunes con Terapeuta y conmigo, que iremos a su casa a recogerla y a supervisar qué tal le ha ido esos días en domicilio, si ha tomado la medicación, si lo ha hecho correctamente, qué ha comido, etc. No sé si te comenté que hemos empezado en el Área de Plasencia, un Programa Asertivo-Comunitario, y hemos incluido en él a Desi, con lo que iremos de vez en cuando a su domicilio a hacer intervención con ella. No obstante, nos gustaría que las profesionales de Futuex, vinieran más veces al domicilio con objeto de tener más supervisión...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-02-20','Ana: Envío correo-e a Estrella, TS CSS (estrella.duranc@salud-juntaex.es): " ¿Qué tal fue la estancia de Desideria el fin de semana anterior en su casa? Con respecto al seguimiento de FUTUEX, puedo solicitar que intensifiquen el seguimiento, pero entiendo, por la petición, que la idea es darle el alta pronto a Desi, ¿es así? Nosotras habíamos pensado en la posibilidad (que no sé si aún existe) de que, al alta, la mantuvieseis en régimen de hospitalización parcial, como hacíais con ella y Ángel antes de la pandemia, para que tuviese más y mejor seguimiento por parte de Psiquiatría también. Confírmame no obstante, fecha aproximada de alta para que pueda indicárselo a la Coordinadora de Futuex."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2023-02-20','Ana: Correo de Marta Custodio, TS de CRM Los Molinos de Montehermoso (mcustodiob24@hotmail.com): "Primero daros las gracias por hacernos llegar el certificado de su pensión y en segundo lugar os adjuntamos la factura por acompañamiento. Florencia se encuentra bien, se relaciona únicamente con su madre, y con un compañero que era muy caballeroso con ella pero le concedieron una plaza pública en su ciudad y se ha tenido que ir. Con el resto, compañeros y trabajadores es muy educada pero no quiere participar en los talleres y actividades que desde el centro proponemos. La terapeuta ocupacional también la anima a sus terapias tanto grupales como individuales pero nada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-02-20','confirman a Inés el jzdo de Mérida nº1 DT 5 lEY 8/21 409/2022 que se ha inhibido a favor del jzdo de Trujillo nº1 procedimiento (pendiente de identificar por la letrada del juzgado, que no lo ha visto) con registro 140-23','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-02-20','Ana: Correo de Paula, TO, CRR-Plas (tocupacional.crrplasencia@grupo5.net): "Hola Ana, confirmarte que ayer Julia Morón firmó, con fecha del 21 de Febrero la salida del recurso. Lo hemos hecho así para garantizar el plazo del que hablamos de los 15 días." ··································································································································································································· Mi respuesta: "Gracias por informar. Antes vino Raquel, compañera de la Secc. de Salud Mental para comunicárnoslo también… es una pena la verdad, pierde, por propia voluntad, un recurso que necesita… ¿Sería posible que nos hicieseis, aunque fuera un breve informe en que detalléis cómo se han producido los hecho y, bajo vuestro criterio técnico, indiquéis también si consideráis que debe estar atendida en un recurso? Consideramos que debemos comunicar al Juzgado esta situación y que Julia no deber regresar al domicilio familiar, donde no cuenta con los apoyos psicológicos, terapéuticos ni sociales que precisa. Por favor, adjuntar también el alta. Informaros que, aparte de a vosotras, también pediremos Informe Social, a la Trabajadora Social de referencia, sobre las condiciones en las que se haya el domicilio y las relaciones familiares. Muchas gracias de nuevo por la colaboración." ························ Respuesta de Paula, TO: "cuando tengamos el informe os lo remitimos. Os adjunto el pdf con el Alta firmada, para que lo tengáis por adelantado." ············ Guardo el documento de Alta firmado por Julia en el expdte. digital. ······························································································································································································· Envío correo a Marta, TS de Cilleros (tsocial@ayuntamientodecilleros.es): "… tenemos que comunicar al Juzgado esta situación. Ya he pedido al CRR el Informe del Alta y queríamos pedirte, que por favor, en cuanto te sea posible nos remitas, al menos, breve informe de la visita a domicilio que hiciste para adjuntarlo también a nuestro escrito."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-02-20','Ana: Correo de Paula, TO CRR-Plas: "Hola Ana, comentarte que Isa se va, como estaba planificado desde hoy hasta el viernes a Trujillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2023-02-20','Ana: Llamada de Jairo, quiere retomar la búsqueda activa de empleo para poder irse a vivir en un futuro de forma independiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-02-17','Ana: correo del Programa de Familia, Mancomunidad Tajo-Salor (programafamilia@tajosalor.es): "Nos está llamando Felisi de manera insistente porque está muy angustiada ya que tiene un lumbago y tiene que seguir cuidando de Manolin. Por lo que solicita volver a su casa de manera inmediata, pero necesita un taxi para llevar todas sus cosas. Además sabemos por Gloria , que le hacen falta muchos enseres en su casa, como menaje y mantas. Ella se quiere ir el lunes porque se encuentra muy mal en casa de sus suegros. Por lo que proponemos que organicemos el viaje cuanto antes, y las cosas que le faltan en casa podemos hacer compra en tiendas de Navas si vosotros después autorizáis el pago." ················· Se organizará el traslado la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-02-22','Ana: correo del Programa de Familia, Mancomunidad Tajo-Salor (programafamilia@tajosalor.es): "Necesita un taxi para hacer el traslado y llevar sus cosas." ······················· Mi respuesta: "¿Podríais gestionarle uno de confianza vosotras? Después de se abonará mediante transferencia. En este caso, dado que es urgente, a no ser que os digan un precio desproporcionado, no hará falta que nos envíe el presupuesto de forma previa para su autorización. Como os digo, si es un precio razonable, con que nos hagáis llegar (ya sea el taxista directamente o a través vuestra) la factura será suficiente." ········································ Nuevo correo del Programa de Familia: "Hemos hablado con un taxi de Casar de Caceres, Manolo Castela, 649 426 007. La llevará mañana a las 9,30. El precio será unos 40 eros. Nos dará factura a nosotras y luego te la remitimos" ···················· Nuevo correo del Prog. Familia: "Mañana te hacemos un listado de todo lo que necesita. Hoy Felisi , de su dinero , se ha gastado 71 euros en menaje par la cocina, pero era necesario que llevara algo para poder cocinar mañana cuando llegue. Respecto a ropa de cama, electrodomésticos y demás te decimos mañana que es necesario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-02-22','Ana: Correo de Óscar, Secc. Ecca., a Toni-Futuex, en relación a la ropa solicitada: "Ya se ha realizado la transferencia de la ropa deportiva de Juan José González Carrero. Puede pasar a recogerla por la tienda a partir de mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-02-22','Ana: correo-respuesta de Marta, TS de Cilleros (tsocial@ayuntamientodecilleros.es) en relación a la petición del informe: "Perfecto Ana, te lo intentare enviar el viernes que no tengo atención al públicos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-02-22','Ana: Correo-respuesta de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "Todavía no se ha hablado de alta, pero sí, como bien dices, queremos que venga a Hospitalización parcial, para seguimiento de la Psiquiatra y también queremos meterla en el Programa Asertivo Comunitario que vamos a comenzar próximamente.... El fin de semana que estuvo en casa fue bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-02-22','Ana: Correo de Cruz Merino, TS de la Mancomunidad Tajo-Salor (cruzmerino@tajosalor.es): "Te mando este correo con los adjuntos que señalan el inicio de expediente de ruina de la casa de Martín Quirós Berrocal de Piedras Albas. Me lo han asignado a mí desde el Ayuntamiento para que os lo hiciera llegar a la Comisión. Yo en estos casos no sé cómo se procede. Este señor sigue residiendo en la residencia de San Pedro de Alcántara, en Alcántara y según me comentan en el ayto esta casa objeto de este expediente, está alquilada (me imagino que sin contrato oficial ni nada por el estilo) como almacén por un señor del pueblo y le abona 50€/mes, que según refiere le ingresa en el banco (esto lo desconocíamos hasta este mes de febrero y no sabemos si sigue ingresando el dinero mensualmente)." ························ Lo reenvío a los A. Jurídicos - CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-02-22','Ana: Correo de Óscar, secc. ecca., al CSS-Plas: "Se envía autorización general de centros para realizar reintegros para gastos personales de Aaron Rosado Alarcón"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-02-22','Ana: Correo de Óscar, secc. ecca., al CSS-Plas: "Se envía autorización general de centros para realizar reintegros para gastos personales de... y Montaña González Rolo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-02-22','Ana: Correo de Óscar, secc. ecca.: "Ya están dados de baja los suministros de la vivienda de María." ················································································································································ Correo de Leire Sanz, TS de la Res. Ciudad Jardín (t.socialcanovas@grupociudadjardin.com): "Hoy se ha puesto en contacto conmigo una de la sobrinas de María Jiménez, Carmen , la que me llamo que quería darles de baja a linea, que quería saber si se estaban las dos hermanas tuteladas, le comunicado que solo María, quería hablar ella con vosotros porque , dice que ha hablado con su tías y que querían hacer testamento(que lo tendrán hecho de antes) cosa que desconozco. una para la otra porque la casa era de María, . Si quieres ponerte en contacto con ella, se llama Carmen 639503536, dice que le han vuelto a llamar 15 día después lo de la línea de teléfono y que ella les ha dicho, que la comisión tutelar les daba de baja." ······························ Mi respuesta: "En relación a los suministros de luz y teléfono, me han confirmado precisamente esta mañana, desde la sección económica, que ambos están ya dados de baja. Con respecto al testamento, lo comunico ahora a los compañeros Asesores Jurídicos, que son quienes llevan estas cuestiones. Por otra parte, aprovecho para comunicarte que desde la residencia, le están pasando a María por su cuenta (la que está ella sola) los gastos de su hermana Isabel. Estos deberían pasarlos por la otra cuenta, por la que está Isabel también, que es donde le ingresan su pensión. Agradecería que lo transmitieses a quien corresponda para que hagan el cambio y dejen de cobrárselo a ella." ······························ Envío correo de Leire, TS, a A. Jurídicos. ················ Respuesta de Ángel - A. Jurídico: "Con respecto a la sobrina que mencionas, Carmen, en la sentencia de incapacitación de María, se indica que los únicos familiares que se conocían entonces eran dos sobrinos, los cuales no comparecieron, a pesar de haber sido citados hasta en dos ocasiones, no constando que tuvieran relación con María (ignoro si Carmen es uno de esos dos sobrinos). Por este motivo nos nombraron curadores. Llama la atención que esta sobrina pregunte si sus tías están tutelada, después de año y medio que se le dictaron las medidas de apoyo. ¿Sabemos si María quiere otorgar testamento? Sería interesante que se le preguntase, bien nosotros o en el mismo centro. En cualquier caso, la llamo y la informo del procedimiento a seguir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-02-22','Ana: Correo de Ángel, A. Jurídico: "En relación a este asunto, ha pasado a instancia judicial, citándome para que asista al Juicio el día 30/3/23. Voy a proponer como testigos a la Presidenta de Fremar, María Isabel Villa Naharro, que nos comunicó este asunto por correo electrónico y también a Pilar, la Directora de la Residencia, que según comentabas, también te llamó por teléfono. Necesito que nos faciliten: • En relación con María Isabel Villa Naharro, su DNI-NIF. • En relación con Pilar, sus apellidos y DNI-NIF." ······························································································································································· Llamo a María Isabel Villa Naharro, Presidenta de la Asociación Femar (609 74 87 22), me facilita su DNI. ················· Llamo a Pilar, Directora de la Res. (639 585 489): dice que ella no ha visto nada, lo que sabe es lo que le dijo Isabel y otras trabajadoras de la Residencia. Hablará con ellas para ver si hay alguien que haya visto la ropa tendida/luz encendida, y esté dispuesta a declarar. ············· Comunico ambas cosas a Ángel, A. Jurídico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-20','Ana: Correo de Miguel, A. Jurídico CTAEx, a Carmen Lucas, Abogada de Saturnino (mlucasduran@icac.es): "Buenos días Carmen, adjunto la sugerencia que nos remite el Defensor del Pueblo. Entendemos que coincide con el email que nos remitió la psiquiatra. Desconocemos si hay ya sentencia o no. Nos comentó la guardia civil que están esperando que le den el alta del centro de hospitalización breve para llevarlo a la cárcel en cumplimiento con este procedimiento. Paralelamente le teníamos iniciado un procedimiento de internamiento involuntario en el jzdo nº2 de Cáceres, y que no salió adelante porque nunca ha asistido a las citaciones que el forense le ha ido haciendo… Dos cuestiones necesitamos nos aclares: -Ha finalizado el procedimiento y hay sentencia? -Es posible permutarle la pena de cárcel por su cumplimiento en centro adecuado?(centro socio sanitario?)" ······························································································································································································· Llamada de Mª Carmen, TS del HSPA (56283): Le informo sobre el correo remitido por A. Jurídico a la abogada de Saturnino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2023-02-22','TERESA EMAIL PLENA INCLSION Te escribo referente a Juana. Hoy como sabes, a las 13 horas tiene cita en el juzgado para la revisión de medidas. Yo no quería decírselo hasta esta mañana porque se pone nerviosa. Ella esta mañana ya lo sabía porque su hermana Gema la había avisado, diciéndole que iba a venir una abogada a hablar con ella. Como la información de su hermana no estaba clara, la he llamado. Gema, me dice efectivamente, que la abogada la ha avisado de que hoy Juana tenia que ir sola al juzgado, la familia no podía acompañarla, la abogada iba en representacion y pretendía que su hermana fuese sola también y nosotros tampoco acompañemos. Le he explicado que acompañarla si la íbamos a acompañar y que otra cosa es que a quien vean sea a ella, nosotros no intervenimos. En eso Juana insiste mucho también que ella debe estar sola. La hermana dice que quieren que su hermana vuelva a casa y solo venga a centro ocupacional porque la ven muy poco. Le he hecho reflexionar de “las condiciones” que ponen cuando Juana va a casa de que lleve comida o le demos dinero para los gastos de la casa y la comida (hoy pedía que se llevara los tuppers de comida hecha de aquí) y de lo poco viable que es esto teniendo la pequeña pensión de Juana. A este respecto, la hermana dice no saber desde hace años, cuanto cobra su hermana y cuanto “ se queda el colegio” (el centro). Le he explicado que ese tema es cuestión de sus tutores, y que aquí se aporta el 75% de su pensión. La situación que tiene en casa, en La Parra, es que el padre está enfermo, y las hermanas y el hermano se turnan para cuidarlo. Los padres estaban separados, por problemas grandes de convivencia, por lo que el padre vive en un domicilio distinto al familiar. En este último, vive el hermano menor, quien no trabaja habitualmente y tiene problemas con la bebida y padece depresión. (dicho por Juana hoy: Mi hermana me ha dicho que mi hermano se ha fundido el paro de 700 euros en cubatas, y dice que no sabe si es mejor que me vaya a casa otra vez o me quede con aquí tal y como está el panorama”) y las hermanas van todos los fines de semana, para atender la casa y llevarle comida al hermano. Juana en las ultimas semanas, ha hecho muchas preguntas acerca de la pensión que tiene, y sobre el día en el que fallezca su padre, si la pensión de su padre pasa a ella… También dice que su padre le habla de muy malos modos refiriéndose a que ella está aquí y pasa de todo. Juana dice que a ella le da miedo quedarse con su padre por las noches por si le pasa algo, La verdad, que esta mañana he podido hablar con Juana tranquilamente, está calmada, me ha pedido tomarse tila antes de ir al juzgado, pero naaadaaa que ver con los nervios y las formas a las que nos tenía acostumbrados años atrás. Le he explicado que este proceso está para escucharla y escuchar toda las partes y el juez pueda valorar lo que es mejor para ella. Que es muy importante que ella esté calmada, y que cuenta realmente y con sinceridad cuál es su situación tanto en el centro como en su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-02-20','AMALIA : envío email a FUTUEX . os paso informe social de este caso nuevo , el Plan de Intervención lo haré yo y luego se lo pasaré a Ana que es de la zona de Cáceres para seguimiento. Solicito incorporación a nuestro programa conjunto , visitas a domicilios , SSASB y Centro de Salud. Vamos a verificar la situación de este señor .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2023-02-07','TERESA Hoy se ha acompañado a Barto a la cita con psiquiatría que tenía en el centro de salud de Almendralejo, desde el alta de la unidad la pasada semana, a pesar de que se le ve mucho más tranquilo, sigue con alguna idea delirante, como que es policía secreta. Se llega al centro de salud, Barto le dice a su psiquiatra, Eduardo, que no quiere tomarse la medicación, charla con él y llegan a un acuerdo, Barto va a tomarse la medicación siguiendo el tratamiento, y el día 22 irá a ponerse el inyectable, si no cumpliera el trato, y el doctor Eduardo lo viera muy inestable el próximo día 22, lo mandaría a ingresar a Mérida de nuevo, Barto acepta. Se acude con él a retirar la medicación y el inyectable. Desde que le dieron el alta aún no había ido a la farmacia a por las medicinas del tratamiento. Asegura que va a tomarse el tratamiento adecuadamente. Se le acompaña a casa y nos presenta a Victorino que acaba de fregar el suelo, se muestra afable y tranquilo con nosotros. Comenta que Victorino le ayuda a limpiar la casa y suele hacer de comer, y por tanto se está alimentando bien. Victorino es el supuesto okupa, pero que esta ahi con el consentimiento de Barto y para el, es su amigo y compañero (dice que si era amigo del padre o lo que sea). No sabemos si le paga algo por estar o se ocupa de las tareas de la casa y comida y con eso se equilibran. Se ha hablado con Barto acerca del tema de consumo de alcohol y otras drogas, asegura que no toma nada de esto porque sabe que le perjudica y él quiere estar en forma. Nos despedimos hasta la próxima se le visitará/acompañará el 22 al inyectable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-02-16','Ana: Envío correo a A. Jurídicos y Maite - CTAEx: "Como sabéis, a Joaquina Mayora Pizarro, Curatela para la Salud, procedieron a darle el alta en el CRR de Mérida el pasado mes de noviembre de 2022. Adjunto informe del centro. Pues bien, en la intranet tenéis anotaciones sobre todos los contactos que he mantenido con los distintos profesionales así como con su hija, y sobre los intentos de seguimiento por parte del Programa de Apoyo Comunitario gestionado por Futuex y los cuáles no acepta. Así mismo, hay anotados indicios de descompensación a nivel psicopatológico. A parte de esto, en el hilo del correo, podéis leer lo que nos indica la TS de referencia del SSASB de Miajadas e imágenes de su domicilio. Adjunto también el Informe Social que hemos recibido del SSASB y en el que se expone la necesidad de ingreso involuntario en centro residencial y los apoyos que precisa. En mi opinión hay que solicitarlo al Juzgado a la mayor brevedad" ··························· *Respuesta de Miguel - A. Jurídico: "Perfecto comienzo a preparar la solicitud de internamiento involuntario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-02-16','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): con respecto al próximo ingreso en UHDAC: "...preguntarte si el trámite de Felisa está en marcha porque a mi compañera le insistieron mucho en que es importante que el ingreso se realice con esta autorización judicial." ············································· Reenvío consulta a A. Jurídicos con copia a Maite: "...Pero con respecto a FESLISA BRUNO SAAVEDRA, cuyo ingreso en UHDAC, está previsto que sea pronto, le he dicho que iba a preguntaros, pues en el expediente no encuentro tampoco autorización de internamiento. Lo que sí sé es que ella ya ingresó en diciembre de 2029 en la UHDAC." ························ Respuesta de Miguel, A. Jurídico: "no hay solicitado internamiento involuntario para ella porque ya estaba internada en cumplimiento de la sentencia penal que la impusieron en 2021 y que debe tener cumplida. Lo único que le pidió el juzgado a Sonia del CSS es que comunicara al juzgado periódicamente si continuaba interna en el centro la medicación que tomaba. Si la dan de alta habría que comenzar un nuevo procedimiento judicial de solicitud de internamiento involuntario"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-02-23','Buenos días, María Rosa A partir del próximo lunes 27 de febrero su asignación semanal pasará de 45 € a 50 €. Este aumento, que ya ha sido comunicada a su banco, viene a cubrir los 20 €/mes que le supondrá la recarga de su teléfono móvil con tarjeta prepago. El reintegro lo tendrá que hacer desde su propia cuenta que tiene en Ibercaja y cuya única titular es usted misma, es decir, la ccc ES44 2085 4505 140330349227. Un saludo Comisión Tutelar de Adultos Junta de Extremadura','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-23','Ana: Recibimos "Informe sobre sucesos acontecidos" emitido por Esther, TS del SSASB-Alcuéscar. ·· Narra los hechos previos al ingreso en UHB. ········· Guardo en el expdte. digital. ···································································································································································································· Envío correo a Mª Carmen, TS HSPA-CC (mariac.rodriguez@externos.salud-juntaex.es): "Tal y como me solicita mi compañero Miguel, Asesor Jurídico de la CTAEx, te reenvío el correo de la Abogada de Saturnino Miguel Salgado Jiménez, para que por favor, se lo hagas llegar a la Dra. María Gía., Psiquiatra de la UHB, ya que yo no dispongo de su correo electrónico. Como podéis ver en el hilo del correo, solicitan INFORME DE PSIQUIATRÍA, para poder presentarlo como prueba en el juicio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2013-06-03','Se recibe llamada de Mª Cielo informando que Diego casi no va al Centro de Rehablitación y que quizá sería mejor que acuda por las tardes al Centro de Ocio. Quería poner en conocimiento a la CTA esta decisión pero observa el problema que no sabe si hay autobuses por las tardes de Fuente del Maestre a Zafra y viceversa y también por el problema de quién se encargaría de acompañarlo en el bus en el caso que lo hubiera. Me habla de Pilar su cuidadora (647407464)y me pongo en contacto con ella. Cuenta que se pasa el día tumbado sin querer hacer nada y que mañana tiene cita con el psiquiatra. Quedo en comunicarme con el psiquiatra y que llamará para darme su nombre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2023-02-23','TERESA ENVIO REVISION PIA PARA SOLICITAR PLAZA PUBLICA YA QUE ACTUALENTE OCUPA PLAZA PIRVADA EN EL HOSPITAL SANTIAGO DE ZAFRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-02-23','Ana: Envío correo a Verónica, TS del Ayto. de Moraleja (s.sociales2@moraleja.es): "...En relación a Pilar Díez Santiago, me comunica el compañero de la sección económica que por fin tienen accesos a sus cuentas. Cuando podáis remitir la factura del andador con el numero de cuenta, se abonará a mayor brevedad. Por otra parte, me dice, que siguen sin domiciliarle el cobro del cáterin, ya habló con Tino, director de la residencia, y le ha enviado varios correos al respecto al respecto, pero aún nada. ¿Podríais aclararnos cómo lo está abonando o si está generando deuda? y/o mediar para que se haga efectiva la domiciliación bancaria?" ······································· Respuesta de Verónica: "Acabo de hablar con Tino, me dice que ya hace tiempo que envió a la Comisión un alta de terceros que le solicitasteis, y que estaba a la espera de saber cómo tiene que hacer los cobros, si le pagáis directamente, o cómo hacerlo. Acaba de decirme que llamará al técnico con el que habló en su día para aclararlo. En cuanto a los pagos, me confirma que efectivamente no sabe cuál es el importe, porque le he pillado fuera de la resi, pero que sí que tiene deuda generada. Si veis que no os llama vuelve a decírmelo e insisto." ········ Se lo comunico a Óscar, secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-02-23','TERESA RECIBO LLAMDA DEL PRIMO DE TOMAS ME CONFIRMA QUE YA LE HAN DADO EL ALTA Y QUE LO VA A ACOMPAÑAR A HACER COMPRAS Y LO QUE NECESITE LE PASO EL TELFONO A FUTUEX PARA VER SI AHORA PUEDEN RETOMAR LAS VISITAS DE LA MANO DE SU PRIMO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN RAMON'and edp.apellido1='SALAZAR'and apellido2='FERNANDEZ'),'2023-02-23','EXITUS El óbito tuvo lugar el 23/02/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISMAEL'and edp.apellido1='CORDERO'and apellido2='PARRA'),'2023-02-14','TERESA ENVIO CAMBIO DE PENSIONES A NUEVA CUENTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-02-07','TERESA Ayer se hizo un seguimiento presencial a Maria Jesus Cruz Esperilla. Pinta regular, en resumen, su intención es irse a vivir con su pareja (al que conoce hace menos de un mes) a principios de marzo, manteniendo el presupuesto económico que tiene fijado en casa de su tía, pero en este caso según ella, para compartir gastos con este novio. Detallando más la información obtenida tras el seguimiento: M.ª Jesús afirma que a principios de marzo se va a vivir con su pareja. Dice que le da igual lo que le digamos, que lo va a hacer. Llevan juntos menos de un mes, pero pasa la mayor parte del tiempo en el piso de su pareja. El chico reside solo en un piso de alquiler a menos de 5 min andado a la casa de Manola, tía de M.ª Jesús. El alquiler, según indica M.ª Jesús, son 300 euros/mes, por lo que tendría que asumir mensualmente 150 euros + luz + agua + gastos de alimentación. Actualmente, ella tiene estipulada una asignación económica mensual de 400 euros/mes que retira personalmente en su entidad bancaria, de los cuales, 300/310 euros entrega a su tía por la manutención. Ella quiere mantener ese presupuesto fijado, pero para vivir con su pareja. Lo tiene decidido, se marcha del piso de su tía a principios de marzo. Se','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-02-07','TERESA Pues hoy se ha hecho lo de recoger la ropa, le tenian como 14 o 15 bolsas de basura, muchas cosas sucias y mal estado, dos maletas rotas.. etc. En fin, un despróposito todo. Porque le han ido a llevar la denuncia por violencia la guardia civil a la casa de la ex pareja, pero al parecer Marta, no ha dejado de tener contacto telefónico con el.. no para de llamarlo. Asique ahora la ex suegra, dice que va a tenre que denunciarla a ella por acosar a su hijo.. Los profesionales del derecho que le han asignado tambien le han dicho que no puede mantener contacto con el, que no se el ocurra (pero ella pues lo está haciendo). Estaba hoy además Marta, en una actitud muy beligerante y a la defensiva, como suele estar, pero gritando que está empezando a estar "mal" en la casa de la madre, porque no soporta a la pareja de esta y empieza a no querer estar alli... asique una locura todo, la verdad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2023-02-23','Ana: Llamada de Pepi, Responsable Res. de Mayores de Madroñera (605 903 129): Juan ingresó en la residencia por emergencia social, su vivienda no reunía condiciones de habitabilidad y llego con total falta de higiene y deshidratación. ······ Según informe médico de la Dra. Elena (MAP), presenta Deterioro Cognitvo (*Me lo enviará cuando pueda). ······· Juan es una persona problemática, miente mucho y en más de una ocasión se han visto obligados a llamar a la Guardia Civil. ···· Tiene una sobrina con la que no se lleva bien. ······ No sabe si tiene seguro de decesos, intentará averiguarlo preguntando en Ocaso y Santa Lucía, pues son las aseguradoras que hay en el pueblo. ·················· Juan "tiene obsesión con el dinero", al parecer vende plantas por el pueblo. Y cada día les plantea por escrito alguna cuestión nueva, como por ejemplo: "que le van a llamar para trabajar", "que le han ofrecido comprar una finca", "que ha comprado dos casas"... ································································································································································································ Tras hablar con Eloy, envío correo a Eloy, TS SSASB Madroñera (ssb079@gmail.com), y a Pepi, Responsable de la Res.de Mayores - Madroñera (residenciagrupovesta@gmail.com): "Tal y como hemos acordado, os remito el TESTIMONIO DEL AUTO JUDICIAL DE PROVISIÓN DE MEDIDAS JUDIALES DE APOYO relativo a JUAN GARCÍA SÁNCHEZ, para que ambos podáis leerla, tenerla en los respectivos expedientes y hacerle entrega al propio Juan de una copia para que pueda leerla. Así podréis también, aunque sea por escrito, aclararle las dudas que le puedan surgir. Como hemos comentado, es importante que él entienda que tanto vosotros desde vuestra posición, como nosotros desde el Gabinete Técnico y equipo administrativo de la CTAEx, estamos para ayudarle y que debemos cumplir el mandato judicial. Gracias a ambos por la colaboración e implicación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-02-23','Ana: envío correo a Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "En relación REMEDIOS CHAVES MASERO, nos han comunicado desde Plena Inclusión Zafra que el ingreso en su centro tendrá lugar el día 28 de febrero. Entendemos que, al igual que en otras ocasiones, el traslado se llevará a cabo en ambulancia, ¿verdad? Por favor, confirmárnoslo cuando os sea posible."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2023-02-22','Ana: Llamada de Eloy, TS SSABS Madroñera (927 31 91 92): Ha recibido el oficio-solicitud de Informe Social y documentación para conformar el Inventario. ········ Juan es soltero, está sordo y no tiene relación con familiares. ··········· Ingresó en residencia en plaza de "validos" en Madroñera. Percibe una PNC, por lo que abona por la plaza algo más de 200€. ············ Es un señor bastante problemático, ya ha protagonizado varias incidencias en la residencia y ha acusado de distinta cosas a profesionales de la misma. De hecho, una tarde, tras un acompañamiento al domicilio acusó a la Directora, Pepi, de haberle robado 35.000€. ············ Su cuenta bancaria la tiene en UNICAJA BANCO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2023-02-23','Buenas , adjunto facturas de esta semana. Casquero ha dejado el hospital y ha pasado ayer al Centro Casa Verde . Se va a hacer acompañamiento para sacarlo fuera del recinto 3h el sabado y 3 h el domingo máximo con personal del Centro La Luz .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2023-02-23','Ana: Tras hablar con Isabel, hermana de Mateo, envío correo a Alberto y Estrella, Secc. Ecca.: "He recibido llamada de ISABEL RUANO MORENO (625 799 153), hermana de MATEO RUANO MORENO. Me comunica que ella lleva muchos años abonando un Seguro de Decesos que contrató para su hermano en Santa Lucía. El número de la póliza es: 1436092, es algo que hizo ella sin decírselo a ningún familiar, ni al propio Mateo. Dice que ella está mayor y enferma y no sabe cuánto tiempo le quedará, por lo que nos facilita esta información para, si es posible, continuar abonando el seguro desde la cuenta del propio mateo domiciliando el pago. Dice que abona al mes unos 34,50€. Estrella, si Alberto da el Ok, ¿podrías, por favor, llamar a Santa Lucía para que nos remitan copia de la póliza y, si es viable, domiciliar el pago para darle continuidad?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-02-23','Buenos días Raquel: Te informamos en relación a la situación de Emilia, para diferenciar dos aspectos diferentes. Por un lado, en relación a la plaza que ocupa en el CRR de Olivenza, ella aún es usuaria del recurso. Su caso está pendiente de estudio por la Comisión de Valoración en la próxima reunión que celebren, donde se va a estudiar la propuesta de Baja del recurso, por los incumplimientos, incidencias, ausencias voluntarias, no adherencia a las intervenciones rehabilitadoras, etc. Se determinará si se da de Baja del recurso, con pérdida de la plaza de manera definitiva o no. Es importante que si en estos días anteriores a la celebración de esta reunión, Emilia vuelva a ausentarse de manera no autorizada o provocara algún incidente grave, desde la Dirección Técnica nos lo comuniques y se convocaría una reunión de manera extraordinaria para valorar la pérdida de la plaza. Por otro lado, y de forma independiente, está la posibilidad de canalización a centro específico en otra comunidad (en este caso sería un centro de Málaga) que depende de la valoración y estudio de parte del S.E.S, que es quien hace estas derivaciones. Es un proceso que conlleva una tramitación y unos requisitos, que según nos informan no es algo ni inmediato ni rápido. Nos estamos informando con el SES y cuando tengamos más datos iremos diciendo. Cualquier cosa nos dices, muchas gracias Raquel! Saludos!!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='CASARES'and apellido2='MARISCAL'),'2023-02-23','Buenos días, soy Gema Benítez coordinadora de los Servicios Sociales Residenciales del Ayuntamiento de Alburquerque. Recientemente nos han adjudicado 6 plazas públicas en la R.M. Los Baldíos, como Prudencio tiene reconocido un grado III, creemos que lo más conveniente para él, es solicitar una de esas plazas. Les adjunto la solicitud de reactivación de PIA para que me la devuelvan firmada si están de acuerdo con solicitar el recurso. Muchas gracias, un saludo. Amalia : envío PIA firmado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2023-02-23','Se recibe email de la TS del Centro La Luz: Comunicarte que ayer miércoles día 22, se produjo el traslado en ambulancia de Cristóbal Casquero García al centro de rehabilitación neurológica Hospital Casaverde situado en Mérida. Lo acompañaron el Coordinador de Residencia Felipe y una cuidadora. Me dice Felipe, que en el Centro le dijeron que Cristóbal para su recuperación va a necesitar una silla de rueda con ciertas características que están pendiente de indicarnos. Necesitamos saber si una vez que nos digan cómo debe ser la silla, si podemos proceder a su compra. Entiendo que habría que solicitar presupuesto de la misma, que deis el visto bueno y realizar su compra, pero al estar en Mérida, por agilizar el proceso necesitaríamos poder contar ya con vuestra autorizació','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-02-23','Ana: Llamada de José Manuel. El día 28 tiene cita para hacerse una analítica de sangre y consulta con su MAP. ············· Hoy dice que se quiere ir a vivir a Olivenza, que le busque una casa allí... Por otra parte pide irse una semana de vacaciones, dice que necesita salir de Cáceres, que se va a liar, porque le vendió un móvil a uno que aún no se lo ha pagado y le ha amenazado ya. ················ Quiere ir a un centro, pero no a residencia de mayores. Pregunta por el nuevo CRR de Don Benito. ·· Le recuerdo que para estos recursos la derivación se hace desde Salud Mental. ·················· Su hija no le habla y está cansado de su hijo. Quiere hacer testamento, para, según dice, "dejarles lo menos posible porque no se lo merecen". ······························································································································································································· Envío correo a Ángel y Miguel, A. Jurídicos: "En relación a JOSÉ MANUEL ROMERO MEDIAVILLA, dice que quiere hacer testamento. En su sentencia no veo que ponga que no pueda. En tal caso, ¿cuál sería el modo de proceder?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-02-22','Ana: Llamada de , Madre de Jesús Manuel (657 947 818): Le ha llamado su hijo, le ha dicho que no se encuentra bien en la en su casa y quiere irse a otra vivienda de alquiler. ··········· Le concedieron una vivienda social hace muchos años, antes de separarse, pero después se quedó en ella su exmujer. ··········· El hijo pide más dinero. Le explico que se ha negociado con él recientemente desde la secc. ecca., le han subido la asignación a 75€/semana, además de darle 2 extras en Verano y Navidad, pero a cambio no puede solicitar más extras. ············· En cuanto a la vivienda, solicitaré a Futuex, que si es posible, le apoyen en la búsqueda de otro piso de similar coste. ···· Le recuerdo a la madre, que al igual que hace en otras ocasiones, puede hacer sus peticiones directamente a la CTAEx, a través de mail y teléfono, como suele hacer, en lugar de marearla a ella utilizándola de intermediaria. ································································································································································································ Escribo a Toni-Futuex, solicitando que le ofrezcan apoyo para la búsqueda de nuevo piso de alquiler de similar coste.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-02-23','Ana: Correo de Beatriz, Directora Res. (beapavonguerra@hotmail.com): "Juan Gregorio necesita una maquinilla de afeitar, la que trajo se ha roto y no tiene arreglo." ····························································· Mi respuesta: "Para este tipo de cuestiones, debéis de remitir a la atención de la secc. ecca. (ctutelar@salud-juntaex.es) , un presupuesto y nº de cuenta bancaria del establecimiento donde lo compréis (si pudiera ser más de un presupuesto mejor, sino no pasa nada). Cuando den el ok, se abonará mediante transferencia bancaria y podréis retirar el artículo de la tienda."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-02-20','Amalia : es un caso nuevo , con respecto al tema económico habría que incluir a J. Vicente en sus cuentas. Se le da una asignación de 50€ a la semana que retira del banco , vamos a mantenerlo así . Habría que pedir al banco que se mantenga como hasta ahora , que no le pongan trabas para seguir retirándolo mientras se realizan las gestiones necesarias. Desde el aspecto social , voy a empezar a trabajar en el caso , solicitan desde el SSASB internamiento involuntario en residencia , pero quiero asegurarme de que esa es la mejor propuesta para él . Domicilian en la cuenta comida y cena a domicilio .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-02-23','Ana: Envío correo a Leire Sanz, TS Res.: "¿sería posible que desde la Residencia, la directora y tú, habléis con María para preguntarle directamente si ella quiere otorgar testamento? Los Asesores jurídicos me indican que es necesario conocer directamente si este es su deseo, no porque así lo diga la sobrina."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-02-24','Ana: ante el correo de Ángela, sobrina de Arturo (aplaterorocha@gmail.com), preguntando por el traslado de su tío a la residencia de Campillo de Llerena y sobre la revisión de grado de dependencia que se solicitó, contesto: "La realidad es que nosotros no tenemos potestad para agilizar estos trámites, no depende de nosotros. En cuanto a la revisión del grado, según la normativa, la administración tiene 3 meses para realizarla, así pues, en principio hay que tener paciencia y esperar. Por otra parte, no sé las plazas disponibles que habrá en esa residencia llegado el momento, que es otra cuestión a tener en cuenta, pues tiene que coincidir que haya plaza libre y que le corresponda por lista de espera ingresar, una vez que se le haya revisado y aprobado el traslado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-02-24','Ana: En relación a la Solicitud de Abogacía de Informes para la Revisión de las Medidas de Apoyo, envío correos a: Julia Durán, TS Hogar Peña del Cura (julia.duranm@salud-juntaex.es), y Guadalupe Cortés, TS SAD-IMAS CC (guadalupe.cortes@ayto-caceres.es) solicitándoles Informe Social. ···················· *Solicito también Informe de Seguimiento del Programa de Apoyo Comunitario a Toni-Futuex. ··································································································································································································· Consulto a Pilar, TS ESM CC (54612), si a Ventura se le está haciendo seguimiento por parte del Equipo: No consta atención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-02-24','Ana: Correo de Icíar, secc. ecca. CTAEx: "Termino de comprobar la cuenta de Juan Gregorio y no le ha entrado la pensión, esto es el cuento de nunca acabar. La cuenta de Unicaja ya está cancelada con lo que solo tiene la de Ibercaja, y si no le ha entrado la han podido enviar de nuevo a la otra, que ya no existe. No sé si podrías comprobarlo." ······························ Llamo a Ignacio, Jefe Secc. P. Jubilación - INSS (927 62 00 62), varias veces: No obtengo respuesta. ··············· Llamo a Control de Pensiones (927 62 00 29), Esther, me comunica que tenían tantas solicitudes acumuladas que no les ha dado tiempo a todas y, cómo no, la de este hombre se ha quedado para atrás…. Ya lo tiene localizado. Como no habían hecho efectivo el cambio, el ingreso se ha ordenado a la cuenta de Unicaja, la misma en la que le ingresaron el mes pasado… Como les llegará devuelto, se ha anotado ya hacer el ingreso en la cuenta nueva de Ibercaja. Y, en teoría, hoy mismo hará el cambio para que la nómina del mes que viene se lo ingresen en la nueva cuenta. ················ Se lo comunico a Icíar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-02-24','Ana: Correo-respuesta de Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Con ambulancia no es conveniente que lo hagamos, primero porque es más caro y segundo porque se quejan los conductores de llevar equipaje, entonces intentaremos llevarla con el coche del centro...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-02-24','Ana: correo de Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Te escribo porque pedimos a la madre de Montaña que le trajera gafas graduadas y no se las ha traído (aunque ella dice que con las de casa ya no veía bien..). La estoy llamando de nuevo y no me coge móvil. Y le hacen mucha falta para los talleres de terapia ocupacional, no sé si puede económicamente comprarse unas..." ··············· Solicito que remitan presupuesto de una o dos ópticas, los precios de las gafas varía mucho en función de la graduación, reducciones, tipo de cristales...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2023-02-24','Ana: Correo de Modesto, Adtvo. Res, Sierra de San Pedro (administracion@centrodemayoressierradesanpedro.es): con Informes Médico y Social. ·············· Lo guardo en el expdte. y lo reenvío a los Asesores Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2023-02-24','TERESA SOLICITO POR ESCIRITO INFORME SOICAL PARA TRAMITAR DEPENDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-02-24','Ana: Cumplimento y subo al portafirmas la SOLICITUD DE REVISIÓN PIA, solicitando Plaza Pública de residencia o Prestación vinculada al SAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-02-24','Ana: Correo de Marta, TS de Cilleros (tsocial@ayuntamientodecilleros.es): "Ana te adjunto el informe junto con la minuta de salida" ··············· Guardo el Informe de Seguimiento en el Expdte. Digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-02-27','Ana: Remito a Julio, Aux. CTAEx, SOLICITUD DE REVISIÓN PIA (cambio de recurso de SAD a SAR o vinculada al SAR), firmada por D-Gerente, para darle registro en SIREX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='SORIANO'and apellido2='LEAL'),'2023-02-27','Ayer le dieron el alta hospitalaria a Javi. El lunes te mando los recibís de los acompañamientos hospitalarios que ha recibido esta semana porque ya no me da tiempo a prepararlos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-09-03','Ana: Correo de Marta, TS SSASB Cilleros (tsocial@ayuntamientodecilleros.es): "Hola buenos días Ana, te adjunto el informe médico del ingreso que tuvo Julia recientemente y te adjunto una captura de pantalla que hice al consultar su estado en la tarjeta de transporte"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-02-07','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Hola Ana, comentarte que Julia Morón se fue a casa y estaba previsto que regresara el día 6 pero no lo hizo. Intentamos durante el día de ayer hablar con ella pero se negaba a coger el teléfono. Hoy por fin, a través de su madre y con el altavoz del teléfono hemos conseguido comunicar con ella y realizar un acuerdo según el cual ella volvería mañana por la mañana en el autobús de las 8.30 horas para tratar de realizar los pasos oportunos y de la manera adecuada para comunicaros su deseo de abandonar el CRR y volver a casa. La madre se muestra con cierta ambivalencia, aunque colaboraba con la idea de que volviera y a ella en la conversación le decía que debía volver al CRR. El acuerdo para la vuelta pasa porque podamos tener una conversación Julia, vosotros y nosotras en la que ella pueda exponer esta situación y podamos pensar en alguna alternativa (si continúa queriendo dejar el CRR alguna que evite que se exponga a abandonar el centro de cualquier forma). Antes de nuestra conversación "a tres bandas" hablaríamos con su madre también para que aclare a Julia (aunque sepamos su ambivalencia) si es o no real la posibilidad de vuelta al domicilio. No sé si finalmente logrará volver mañana, espero que lo haga y que así demuestre ese pequeño cambio e intención de hacer las cosas de forma más organizada. En cualquier caso si podemos hablar antes para hablar más profundamente de la situación y buscar opciones sería estupendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2023-02-27','Ana: Envío correo a Ángel: "En relación a MATEO RUANO MORENO, ¿hay alguna novedad en relación a la pensión de alimentos que se sigue pasando a sus hijos?? Si no es así, ¿podéis consultarlo y volver a insistir, solicitarlo de nuevo o lo que proceda?" ···························································································································································································· En cuando al Seguro de Decesos, me confirman desde la secc. ecca., que se podrá seguir abonando el que contrató su hermana. *Estrella ha hablado con el seguro y dado el domicilio actual, el precio disminuye 6€/mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-02-27','TERESA tema de bombona de momento solucionado, alguien les ha dejado una placa de inducción y cocinan en ella. Tenemos otro problema, el DNI, de Aitor ha caducado hoy, no podemos tramitar ni la tarjeta sanitaria, ni asignar médico, ni pedir cita para psicólogo, psiquiatra, ni planificación. Os voy a pedir una fotocopia de su dni para ver si nos hacen el favor, pero no sé si podremos. por otro lado la policia nacional no viene hasta abril para hacer los dni y no sabemos ni el día. En este caso si tendríais que acompañarle, sus tutores o futuex. Contarnos como podemos hacerlo, y si habría que acercarse a Cáceres a hacer el DNI. La estufa os mandaremos el presupuesto en esta semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2023-02-27','Ana: Envío correo a Modesto y María, TS (administracion@centrodemayoressierradesanpedro.es / serviciossociales@centrodemayoressierradesanpedro.es): "Como veis en el hilo del correo, desde el juzgado necesitan saber si Tomasa puede asistir físicamente a Juzgado llegado el momento de la valoración, y, en tal caso, si sería posible que se le acompañara desde el centro o con alguna persona de confianza a la que se le podría abonar el acompañamiento (aportando Declaración Jurada con número de cuenta). Si fuera preciso, podríais solicita los servicios de un taxi de ahí del pueblo o los alrededores (también se abonaría mediante transferencia bancaria desde la cuenta de Tomasa)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-02-27','Ana: Correo de Eva Álvarez, TS Plena Inclusión Montijo (trabajadorasocialco@plenainclusionmontijo.org): "Adjunto remito consentimiento informado del proyecto Mi Casa, para que lo firmen para Adrián Ortigosa Fuentes" ············· Mi respuesta: "Tras hablarlo con Miguel, Asesor Jurídico, nos indica que el documento que enviáis, dado que tiene que entenderlo y aceptarlo también Adrián, se lo entreguéis también a él y os aseguréis de que entienda cada apartado antes de marcar la cruz en las correspondientes casillas y de firmarlo. Una vez cumplimentado y firmado por él, nos lo enviáis escaneado para que lo firme también el Presidente de la CTAEx como Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-27','Ana: Correo de Toni-Futuex: "Buenos días Ana, adjunto para su abono mediante transferencia factura zapatillas de estar en casa y ppto de ropa interior del tutelado Saturnino Miguel Salgado Jiménez, es presupuesto porque en la tienda, decian que no podian hacer factura hasta recibir el dinero, pero se han entregado ya los productos a la educadora y está pendiente el abono. Se lo ha llevado ya al hospital el otro dia, lo que no encontramos para pago por trasferencia fue lo uqe solicitaban de aseo.." ················· Lo reenvío a la secc. ecca. para que en cuanto puedan procedan al abono. ··············· *Óscar, secc. ecca., me confirma que la ropa la abonaron la semana pasada, pues lo remitieron directamente desde la tienda. ··· Abonará las zapatillas. ·························································································································································································································································· Correo de Mª Carmen, TS UHB (mariac.rodriguez@externos.salud-juntaex.es), remitiendo el coreo de la Psiquiatra, Marí : "Como psiquiatra de referencia yo no puedo realizar un informe pericial ni un peritaje en un juicio, nosotros hacemos solo valoraciones clínicas. ". ················ Tras hablarlo con Miguel, Asesor Jurídico, respondo a Mª Carmen y a María, Psiquiatra (maria.gomezma@salud-juntaex.es): "Me dice el compañero Asesor Jurídico, que en tal caso, por favor, María emita informe con su valoración clínica para remitírsela a la Abogada. Mañana si quieres hablamos de nuevo, pues ahora no me va a ser posible llamaros a ninguna de las dos, disculpad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-02-27','Maite: he solcitado informe social al centro , requerido desde abogacía para la revisión de sentencia de Josefa. Buenos días Leire, Soy Maite Gómez, compañera de Ana Matamoros en la CTAEx. Necesitamos que nos enviéis informe social para la revisión de sentencia de Josefa Sánchez Díaz, considerando sus necesidades de apoyo. Muchas gracias. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-02-23','Ana: correo del Programa de Familia, Mancomunidad Tajo-Salor (programafamilia@tajosalor.es): "Buenos días Ana, te envío la factura de una compra con cosas básicas para Felisi: sábanas, mantas… Poco a poco tendrá que ir comprando más cosas porque le han tirado todo pero de momento para empezar… Te envío también el presupuesto de 2 colchones de la tienda de Navas en las que los venden. Imagino que necesitaréis otro presupuesto pero tendrá que ser en Cáceres o en otro sitio. Te voy a enviar otro correo con algunas fotos que hemos hecho de la limpieza de la casa (aquí no me caben porque ocupan mucho) para que tengas constancia porque yo creo que con el dinero que han cobrado podrían haberla dejado bastante mejor. Se las he enviado a la compañera de FUTUEX que va a hablar con la empresa. Sería importante comprar un frigorífico nuevo porque el que tiene, aparte de insalubre creemos que no funciona el congelador. Se lo hemos dejado enchufado para que lo pruebe. Iba a probar también la lavadora y el microondas a ver si funcionan. Te voy contando" ················· Reenvío presupuesto a las secc. ecca. ·························· Mi respuesta: "Tengo una duda, ¿la factura de la “compra básica” ya está abonada? El presupuesto de los colchones lo paso ahora mismo, entiendo que esto y es urgente, si dan el visto bueno en la sección económica no haría falta enviar más. Con respecto a la limpieza… viendo las fotos, como tú bien dices, podían haberla hecho mejor… A ver qué le dicen a las compañeras de Futuex. Con respecto a la compra de frigorífico, y si es necesario, otros electrodomésticos, puedo pedir a la coordinadora de FUTUEX que las compañeras pidan presupuestos, pero tendríais que confirmarme de cuáles hacen falta. Muchas gracias de nuevo por vuestra labor e implicación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-02-28','Ana: Correo-respuesta de Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Hoy se va de alta Remedios Chaves a Plena Inclusión Zafra" ······································································································································································································· Correo de Ana Arroyo Montaño, Ed. Soc. de Plena Inclusion Zafra (social@plenainclusionzafra.org): "Te escribo para informarte de que Remedios ha llegado hoy a la entidad. El viaje lo ha hecho muy bien, dormida, aquí se encuentra bien aunque algo nerviosa, propio del día que es. Te adjunto documentación que necesitamos tener firmada. En principio es el pacto de asistencia, protocolo para la administración de la medicación y protección de datos. Si se me olvida algo en los días sucesivos vamos viendo. Me han hecho entrega de sus pertenencias, documentación (DNI y tarjeta sanitaria) y de la cantidad de 192.61 € Disculpa por la tardanza, ha llegado más tarde de la hora prevista y no he podido hacerlo antes como me hubiera gustado. Esperemos que la adaptación sea buena, vamos a poner todo lo que está a nuestro alcance para que así sea. Seguimos en contacto Un saludo PD: van en Word por si hubiera que rectificar algún dato referido al representante legal. gracias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2023-02-28','-Amalia : se registra PNC , falta modelo alta 3º que se enviará posteriormente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2023-02-28','-Amalia : se registra PNC , falta modelo alta 3º que se enviará posteriormente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2023-02-28','Amalia : Hablo con PNC , queda extinguida desde 1 febrero . No hay que enviar la declaración anual . Hay cobro indebido de unos 2000€ que hay que devolver ,si no llega el requerimiento en un par de semanas se lo pido por email. La orfandad es de 502€/14 meses. No ha solicitado PFHC la familia ni él . De momento no pido más , llega para cubrir gastos . Tampoco interesa que tenga más liquidez estando en un centro que no hay copago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-02-22','Ana: Correo de Carmen Jiménez, sobrina de María (majisix@gmail.com) al ctutelar@ a través del buzón de contacto salud-extremadura... dirigido a los A. Jurídicos: "Soy Carmen Jimenez Sixto con DNI 06983148A. Sobrina carnal de María Jiménez Picón y de Isabel Jimenez Picón , hermanas de mi difunto padre Francisco Jimenez Picón Están en una residencia de Caceres desde hace ya bastante tiempo pues no se pueden valer por ellas mismas debido a su avanzada edad. Me interesaría saber que grado de dependencia tienen por la junta de Extremadura , pues en Ciudad Jardin , residencia donde residen , me dicen que están tuteladas por la junta , pero no sé el grado y me interesaría saberlo Muchas gracias y saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-02-28','Ana: conversación con Leire, TS Ciudad Jardín de CC (927 24 44 21): Las sobrinas hicieron una visita la semana pasada a María y su hermana Isabel, y las alteraron mucho al contarles que su vivienda había sido ocupada. Quisieron sacarlas de la residencia con la intención, según decían, de llevarlas a poner la denuncia... Desde la Residencia no se lo permitieron, le dijeron que dado que María estaba a cargo de la CTAEx, tenían que consultarlo primero. ··········· Desde la Dirección del Centro les han prohibido la entrada por alterar la convivencia y el bienestar de las resientes. ·················· *Les indico que desde la CTAEx, para empezar, ya se ha puesto la denuncia. Y con respecto a sacarlas, sin que haya una comprobación de que actúan de buena fe, no se permitirán las salidas. Podrán visitarla en la residencia, siempre y cuando no la alteren ni perjudiquen de ninguna mañanera, pues en tal caso, no se consentirá tampoco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2023-02-22','Ana: Correo de Mónica, Ed. PPSS (educacion.pisosplasencia@grupo5.net): "Es cierto lo que te comentó Paula sobre el rechazo de Félix a una plaza a un piso de mayores, me enteré de esta información al acompañarle a la cita con la TS de Salud Mental. En esta cita se hizo completamente consciente de la edad tope para estar en el recurso y de la importancia de cambiar a uno de mayores. Te iré informando cuando se inicien los trámites."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-02-28','Ana: Con respecto al correo de Mónica, Ed. PP.SS. (educacion.pisosplasencia@grupo5.net): "En los últimos días ha dado diferentes informaciones sobre una conversación mantenida contigo y después con FUTUEX. Según él me cuenta, se puso en contacto contigo para pedirte las llaves de su casa (de la que, según tengo entendido, no se encuentra habitable, no sé si esta información es correcta) y tú le comentaste que desde FUTUEX se pondrían en contacto para traérselas y así hacerle un seguimiento. Tras esto, a los pocos días relata que le llaman de FUTUEX para quedar con él pero no lo consiguen por no encontrar el piso supervisado... Te comento todo esto para contrastar información y, sobretodo, si fuera posible, ser conocedora de cuando tendría lugar ese encuentro con FUTUEX, o cómo coordinarme con ellos." ············· Llamo a Toni-Futuex y contesto a Mónica: "He hablado con Toni, la coordinadora del Programa de Apoyo Comunitario. Para la coordinación contigo, me dicen que Gloria, la educadora se pondrán en contacto contigo. Con respecto al día que había quedado con Javier, por lo visto ella fua al Piso y le abrió la puerta otro compañero. Era Javier el que no estaba ese día en el piso, no sé si se le olvidó o se lio con la fecha o qué pasó. Te confirmarán a ti nueva fecha de visita."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2023-02-28','miguel, envío a Inés para su remisión por lexnet para la revisión de medidas de apoyo: Buenos días, adjunto para que remitas al jzdo de 1º instancia e instrucción nº6 de Cáceres, procedimiento DT 5 Ley 8/21, procedimiento nº 797/2022, vía Lexnet los informes social-médico y económico referente a la tutelada, junto con el requerimiento que nos remitieron. Pon un oficio e incluye lo siguiente: En contestación al requerimiento que realizaron a esta Comisión Tutelar Adultos, se adjunta los informes económico y social médico de la tutelada, y se les informe que nos comunican desde Residencia de Mayores Sierra de San Pedro, de Casas de Don Antonio (Cáceres), es contraproducente la asistencia de la tutelada a la citación que se realice desde el Juzgado debido a que a parte de las dificultades físicas para moverse, se une la desorientación que se produciría, motivo por el cual desde el centro se solicita que les faciliten desde el juzgado los datos de conexión por videoconferencia para que la tutelada pueda asistir por videoconferencia ************************************************ Modesto 673-315551 de la Residencia de Mayores Sierra de San Pedro me llama para comunicarme que no es comunicarme que no es aconsejable que vaya a la vista la tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2023-02-28','Ana: Paso a Julio, Aux. CTAEx, la ACEPTACIÓN PIA de Servicio de ATENCIÓN RESIDENCIAL, firmada y sellada por el Presidente de la CTAEX para que lo registre por SIREX a la Gerencia Territorial de CC del SEPAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2023-02-27','EXITUS El fallecimiento tuvo lugar en la madrugada del 28/02/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-02-28','Ana: Correo de María, Programa de Familia (programafamilia@tajosalor.es): "La factura de la “compra básica” no está abonada, nos dijo Virginia (Futuex) que le acompañásemos a comprar lo necesario y os enviásemos la factura, que se haría una transferencia a la tienda. También decirte que tendrá que comprar cacerolas y más cosas pero bueno, cuando vosotros consideréis. Ayer fue con Virginia a Cáceres a ver los electrodomésticos, pedir presupuestos y demás. Otra cosa importante, Jesús ha salido de prisión y se ha ido a vivir con ella a Navas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-02-28','Ana: Llamada de Guadalupe, TS del IMAS: Pide que el informe social se lo solicitemos mejor de forma oficial. ··············· Redacto oficios y remito a Julio, Aux.CTAEx, para remitir por SIREX a Julia Durán, TS Hogar Peña del Cura. y otro a la Oficina de Atención al Ciudadano (oac.merida.san@juntaex.es) ···· Me remiten justificante de SIREX-SIR. Guardo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2023-02-28','-Amalia: Hacemos visita a domicilio . Averiguamos que Petra ha estado ingresada en hospital y David ha sacado 2000€ de una cuenta en la que tenían ahorros. Ese dinero lo ha ahorrado la madre , se decide quitar de titular a David. Se le va a cargar el seguro de decesos por transferencia tras darle de baja al cargo por David.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-02-28','Ana: Llamo a la Dra. María Gía. - Psiquiatra HSPA (56832 // Control: 56826): me indica que a nivel conductual Saturnino está mejor, pero psicopatológicamente no está estable ni se prevé que lo vaya a estar en un tiempo razonable de hospitalización en la UHB. Por lo que sigue planteando el traslado a la UME. ·················· Emitirá Informe Médico con valoración clínica, que remitiremos a la Abogada aunque no tenga valor pericial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2023-02-28','-Amalia: Hacemos visita a domicilio . Averiguamos que Petra ha estado ingresada en hospital y David ha sacado 2000€ de una cuenta en la que tenían ahorros. Ese dinero lo ha ahorrado la madre , se decide quitar de titular a David. Se le va a cargar el seguro de decesos por transferencia tras darle de baja al cargo por David.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2023-02-28','Ana: Correo de Ángel, A. Jurídico: "En relación con María Teresa Nevado Martín, no veo en su expediente certificado del cadex con su discapacidad. Sabes si lo tiene reconocido? Es para incluirlo en la Declaración del Impuesto de Sucesiones." ················· En nuestra base de datos y en nuestro expediente (papel y digital) no consta nada. No obstante, las compañeras de la secc. discapacidad consultan en la App. del CADEX y sí está valorada con un 65%. ························ Pido a Julio que solicite el Cdo. de Discapacidad y el Dictamen Técnico al CADEX-CC y, una vez recibido, se lo remita a Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-02-28','Buenos días , reenvío su email a la sección económica de esta Comisión , que decide sobre esos aspectos. Pero le adelanto que con respecto a internet y tf valorarán un pto. que se presente de prepago y pueda abonar con su reintegro. A partir del día 1 de marzo podrá hacer reintegros de 300€ quincenales , 600€ al mes . El desahucio de su vivienda no creemos que tarde ya mucho , comentó usted que iba a hablar con sus hermanos la opción de ayudarla económicamente para pagar un alquiler . Con su pensión no puede cubrir vivienda , manutención , suministros.. No hemos recibido respuesta aún. Me comentan los compañeros que existen unos recibos del OAR de una vivienda en Torremayor de la que no es propietaria , en C/ 1º de Mayo , 4 , por alcanterillado y basura . Tenéis información sobre ésto ? . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-02-16','Ana: correo de Toni-Futuex: "finalmente se ha presentado alli, con Ana Benavente, era cita con enfermeria al parecer, pero no le podian atender y la ha visto Ana Benavente. Luego se han ido para CRR para firmar la renuncia. La compañera ha ido, sospecha, que igual el padre tiene algo que ver porque nunca se ha metido en nada ni ha aparecido a nada de esto y ahora estaba alli con ella y con la madre. La madre explica que tiene que estar en un centro, a pesar de todo... El padre como que se quejaba que en el centro tiene mucha libertad que puede salir y estar toda la noche por ahi.. (como si en casa no..) . Al parecer ahora está con un chico del centro, Julia, y está ilusionada con esa relación por lo que no cuadra mucho que no quiera volver y no volver a verlo, da la sensación por como se producía el padre, que en parte ha tenido algo que ver para sacarla de ahi., porque censuraba y negaba el hecho de que Julia pudiese tener una relacion y que eso no podia tolerar. Asique una hipotesis es que el padre haya intentado que no este, para de alguna forma evitar que este con este chico o que salga mas ... pero obviamente sabemos que en casa, pues salia todavia mucho mas y tenia conductas mucho mas problematicas. Se tiene la sospecha que este hombre ha podido ejercer violencia contra su madre, y posiblemente contra Julia. Se desprende de ahi, que la actitud de Julia, ante sus exigencias, sean de sumisión. Ella estaba un poco ausente, no parece tener que ver con una situción de descompensación, ademas no han objetivado nada en centro de salud, pero no podemos afirmar si realmente es la decisión que hubiera tomado de no estar influida por su familia. El caso es que ha firmado, no sabemos si se podra hacer algo o esto significara que ya pierde la plaza."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-02-28','Ana: Solicito Informe de Seguimiento del Programa de Apoyo Comunitario a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-02-28','Ana: Correo de Ana Arroyo Montaño, Ed. Soc. de Plena Inclusion Zafra (social@plenainclusionzafra.org): "Te escribo para informarte de que Remedios ha llegado hoy a la entidad. El viaje lo ha hecho muy bien, dormida, aquí se encuentra bien aunque algo nerviosa, propio del día que es. Te adjunto documentación que necesitamos tener firmada. En principio es el pacto de asistencia, protocolo para la administración de la medicación y protección de datos. Si se me olvida algo en los días sucesivos vamos viendo. Me han hecho entrega de sus pertenencias, documentación (DNI y tarjeta sanitaria) y de la cantidad de 192.61 € Disculpa por la tardanza, ha llegado más tarde de la hora prevista y no he podido hacerlo antes como me hubiera gustado. Esperemos que la adaptación sea buena, vamos a poner todo lo que está a nuestro alcance para que así sea. Seguimos en contacto Un saludo PD: van en Word por si hubiera que rectificar algún dato referido al representante legal. gracias"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-03-01','Ana: Comunico a Mª del Sol Tafur, TS ESM y E.C.A.- Trujillo y La Cumbre (53418 // mariasoledad.tafur@salud-juntaex.es): que el cargo de Mª Guadalupe ya ha sido aceptado. ················································································· Guardo en el expdte. las imágenes de la vivienda que envió Marisol, TS, en su día. ····································································································································································································· En el AUTO de Medidas Judiciales de Apoyo, en su PARTE DISPOSITIVA, "María Guadalupe requiere de representación para tomar decisiones de contenido económico, y de gestión de patrimonio, para efectuar donaciones, para tomar o dar dinero a préstamo, para administrar los ingresos que percibe en concepto de pensión, para efectuar disposiciones de dinero en efectivo o de otra forma, o para manejar cantidades de dinero superiores a 100 euros al mes... así como para la toma de decisiones en lo referido al ámbito de la salud, entendido a título de ejemplo como elementos a integrar en el ámbito de la salud: manejo y toma de medicamentos, seguimiento de tratamientos médicos o farmacológicos, decisión respecto a los tratamientos médicos necesarios (incluidos los internamientos o ingresos cuando sean recomendados por especialistas facultativos), pautas alimenticias; y requiere de asistencia para el desarrollo de las actividades básicas de la vida, como es el aseo, alimentación, y vestido." ..."SE AUTORIZA INGRESO en CENTRO o PISO adecuado." ······································································································································································································· Reenvío a Maite, Jefa Secc. CTAEx y Marisol, TS ESM, el correo enviado el 29 de noviembre, para retomar gestiones con Soraya Masa y el Dr. Miguel Medina, Psiquiatra: "El Juzgado aún no nos ha enviado la firmeza, por lo que aún no se ha aceptado el cargo por la CTAEX. Inés va a reclamarla de nuevo al Juzgado. Pero me ha vuelto a llamar la TS del ESM y la situación es cada vez más crítica… la extrema delgadez, la escasa e inadecuada alimentación, su TMG, la falta de conciencia de enfermedad, la no toma de la medicación y las pésimas condiciones de habitabilidad de la vivienda, hacen temer por su integridad e incluso por su vida, pues no creen que pudiera pasar del invierno en esas condiciones. El Psiquiatra, Miguel Medina, está dispuesto a intentar el internamiento en UHB y posterior derivación a UME, para que pueda estabilizarla, pero pide la condición de que a su salida del C. Sociosanitario tenga asignada plaza en Recurso Residencial. Hemos planteado la posibilidad de convocar una Subcomisión para valorar el caso y tomar decisiones. Por si puedes comentarlo con Soraya."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-02-14','Ana: Correo-e de Mª del Sol Tafur, ESM y E.C.A.- La Cumbre (mariasoledad.tafur@salud-juntaex.es): "Hola Ana, te reenvío unas fotos que me hace llegar el Servicio social del Ayuntamiento de La Cumbre. Es la casa de Dª Guadalupe Gil Cabello, se ha caído el tejado, la situación es bastante crítica. Con la medicación seguimos como hasta ahora, viene a Trujillo para la medicación inyectable cuando le toca (la trae una ambulancia), pero para la medicación oral no hay control. Con el reciente incidente ocurrido, la situación va peor. Por favor insisto en que se tomen medidas sobre su internamiento. La última vez que contactamos por teléfono quedamos pendiente de que nos avisarais para poder enviar los informes de salud mental que en su día, enviamos al Juzgado para pedir medidas de apoyo para ella. No dudes en llamarme para cualquier cosa. En Trujillo estoy los martes y jueves (53509). En ECA Miajadas los lunes y viernes (53433). En COPF Miajadas los miércoles (53418)." ················· Le informo que la CTAEx aún no tiene aceptado ningún cargo, pues no hemos recibido la firmeza. *Desde la Secc. Jurídica han vuelto a pedirla al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-03-01','miguel, Inés llama al jzdo nº2 de Montijo, procedimiento ITR 360/22 para preguntar por el expediente de solicitud de internamiento involuntario del que no sabemos nada, y le comentan que el juez va a resolver que no es competente en febrero, que nos lo van a notificar próximamente. La solicitud se hizo el 26-7-22.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-03-01','Ana: Envío correo a Toni-Futuex: "Ángel, Asesor Jurídico, nos comunica que desde Abogacía General de la Junta de Extremadura ha vuelto a llamar insistiendo en la urgencia de contar con los Informes de Ventura, para incorporarlos al expediente de revisión de las medidas judiciales de apoyo. Agradeceríamos que intentaseis agilizarlo y enviárnoslo a la mayor brevedad." ··················· Toni responde que el lunes lo enviará. Antes no les va a ser posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-03-01','Amalia . contrato hostal Ana tf 924311113en Merida por 4 noches . Se irá con la asignación semanal de 78 €','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2023-03-01','miguel, envío email a la parte social y económica: Buenos días, como sabéis el tutelado quiere la remoción del cargo y nombrar a otra persona. Estos días tras hablar con él, me indicó que alguien había suplantado su identidad y que aparte del procedimiento de incapacitación del año 2018 había dos procedimientos más. Tras confirmarlo con el jzdo nº1 de Montijo me dijo que el primero de esos procedimiento es de 2019 y se corresponde cuando la Ctaex solicitó que la curatela pasara a tutela y el segundo procedimiento es una revisión de su sentencia conforme la nueva ley 8/21 de medidas de apoyo. El juzgado en poco tiempo nos remitirá la documentación que haya en el expediente de ambos procedimientos. Hoy me han vuelto a llamar desde el jzdo nº1 de Montijo para decirme que Bartolomé ha ido al notario y ha firmado el nombramiento de curador a otra persona, y que ha saltado cuando ha sido comunicado al registro civil. Tras dar traslado del mismo al juez éste ha invalidado dicho documento y nos lo enviarán. Parte económica, os comunico este incidente por si os pide dinero para pagar la notaria…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-03-01','Amalia . contrato hostal Ana tf 924311113en Merida por 4 noches . Se irá con la asignación semanal de 78 €','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-03-01','Buenos días , he recibido llamada de asociación de Montijo , Puerta a la Esperanza .603477048 Ha ido Justa a solicitar ayuda por el tema del desahucio. No le he facilitado información sobre la usuaria por protección de datos y porque ha empezado diciendo que es amigo de su hijo el abogado. Tiene dudas sobre si iniciar con el banco un proceso para evitar el desahucio y promover un un alquiler social que no sabe si conseguirá. Ha hablado con SSASB y le han indicado que no consideran que esta señora pueda estar viviendo sola mucho tiempo más . Quería asegurarse de que desde la Junta se le dará algún recurso , y asegura que ella se niega a eso. Miguel , tenemos respuesta del internamiento involuntario que solicitamos al juzgado ?? ********************************************** Buenos días, precisamente esta mañana ha hablado Inés con el jzdo nº2 de Montijo ya que estaba solicitado dicho internamiento involuntario desde julio de 2022 y le han comentado que en próximos días nos resolverán negativamente el mismo al declararse incompetentes, lo cual recurriríamos ya que el juzgado competente es del lugar donde reside la tutelada, que es precisamente Montijo. Vamos a esperar a que llegue esa resolución y en qué se fundamenta para como digo recurrirla. Sería posible en caso extremo solicitar su ingreso en centro por emergencia social?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2023-03-01','Ana: Recibimos RESOLUCIÓN DE REVISIÓN de GRADO DE DEPENDENCIA. SE LE RECONOCE GRADO I. ·············· Archivo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-03-01','Ana: Corro de Ana Arroyo Montaño, Ed. Plena Inclusión Zafra (social@plenainclusionzafra.org): "Durante la noche ha estado algo inquieta, lógico para ser la primera noche. Ahora mismo la acabo de ver y está contenta y con ganas de hacer cosas. Me comentan las compañeras, que le hacen falta toda clase de productos de higiene, ropa interior y pijamas pues no traía. Si te parece, vamos tirando del dinero que ha traído y después vemos como seguimos haciendo ese tema. Ella económicamente que tal está?? Se agradece mucho el apoyo por vuestra parte" ·································································································································································································· Mi respuesta a Ana, Ed. Plena Inclusión: "Como decíamos esta mañana, esperemos que se vaya adaptando poco a poco. De entrada me parece muy buena señal que se mostrara contenta y con ganas de hacer cosas. En cuanto a su situación económica, he solicitado a los compañeros de la sección económica, valga la redundancia, que actualicen su ficha y me digan cómo va. Supongo que el modo de pago será el mismo que el de los otras personas a cargo de la CTAEx que residen en vuestro recurso. Si queréis, en relación a esta cuestión, desde vuestro departamento de administración de pueden ponerse en contacto al respecto con mis compañeros de la sección económica en la dirección habitual: ctutelar@salud-juntaex.es indicando el importe que le corresponde abonar por su plaza y el modo en que deben hacer el pago (no sé si es cargo en cuenta, transferencia periódica o cuál). Con respecto a las cosas que necesita, me parecer perfecto que utilicéis el dinero que lleva. Una vez que están actualizadas las cuentas se podría acordar una asignación para gastos de bolsillo. Ya nos diréis cuantía aproximada que consideráis que puede necesitar y lo vamos viendo según sus posibilidades económicas. Por último, adjunto los documentos que me remitiste ya firmados por el Vicepresidente de la CTAEx: - Protocolo de mediación - Protección de datos - Pacto de Asistencia Ante cualquier no dudéis en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-03-01','Ana: Correo de Miguel, A. Jurídico: "mientras esperamos la contestación de la valoración que te tienen que enviar para remitirlo a la abogada (para el posible acuerdo de permuta de cárcel por cumplimiento de pena en centro), paralelamente teníamos solicitado al juzgado nº2 de Cáceres el internamiento involuntario, que si recuerdas se quedó atascado porque él no asistía a las citaciones con el forense. Pues la buena noticia es que nos comunica el juzgado que ya le ha visto el forense y que dan traslado al Ministerio Fiscal para que alegue lo que crea antes de que resuelva el juez. Si llega pronto esa resolución judicial sobre internamiento involuntario, la uniré al informe que me des (de la psiquiatra) y se lo enviaré a la abogada, a ver si con eso logramos que cumpla la pena en un centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-03-01','Ana: Envío correo-e a Toni-Futuex: "¿sabemos algo de las rejas que estaban pendiente de poner en la vivienda de Felisi? Supongo que el presupuesto que nos enviaron habrá que actualizarlo, pues ya tiene varios meses. Cuando podáis, por favor, intentad hablar con el profesional correspondiente y agilizar estos trámites, para que lo hagan lo antes posible, por favor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-03-01','Ana: Correo de Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "En relación a Aarón Rosado, nos pide poder contactar con una prima llamada Juli, nos gustaría saber más de esta persona, y si vosotros consideráis que es positivo para él, ese contacto..." ···························· Mi respuesta: "no hay ningún inconveniente en que mantenga el contacto con su prima Julia y con sus otros dos primos: Adrián y Ramón. De hecho, estando en el centro, de vez en cuando iban a visitarlo e incluso a veces se lo llevaban a comer al pueblo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-03-01','Ana: Correo de Estrella, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Te informo respecto a Desideria, va a pasar a Hospitalización Parcial, vendrá los lunes y jueves. Por ahora no acepta el Programa Asertivo-Comunitario por lo que, como ya te dije, sería conveniente que el personal de Futuex viniera un par de días al menos, al mes para supervisar su estado...a ser posible, que esos días no sean ni lunes ni jueves..." ································ Envío correo a Toni-Futuex: "En relación a DESIDERIA BARBERO BUENO , solicitaros que por favor, se intensifique las visitas de seguimiento a su domicilio, desde el Programa de Apoyo Comunitario, pues pasa ya a HOSPITALIZACIÓN PARCIAL y comenzará a estar ya sola en su casa. Lo ideal sería que, como mínimo, se le visiten 3 veces al mes, si pudiera ser más mejor, y a ser posible, que no sean ni lunes ni jueves, pues serán los días que ella acudirá al CSS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-03-02','Ana: Toni envía correo con el último seguimiento de Felisi. Comunica que Jesús ha salido de prisión y se ha ido a vivir con ella. Envía también presupuestos de electrodomésticos. ··············· Guardo correo en el expediente digital. ·············· Reenvío presupuestos, indicando las preferencias de Felisi, a la secc. ecca. (cutelar@)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-03-01','-Amalia : registro PIA a la sección de Badajoz, servicio de prevención de las situación de dependencia , apoyo personal , alojamiento .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-03-01','-Amalia : registro PIA a la sección de Badajoz, servicio de prevención de las situación de dependencia , apoyo personal , alojamiento .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-03-02','RAQUEL BENITEZ MURIEL >RBENITEZ@caseresidencial.es> Enviado: miércoles, 1 de marzo de 2023 11:52 Para: Maria Luz Madrigal Gonzalez >maria.madrigalg@salud-juntaex.es>; Eva Paredes Santiago >eva.paredes@salud-juntaex.es>; Raquel Gomez Aparicio >raquel.gomeza@salud-juntaex.es> Cc: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es>; Maria Teresa Gomez Martin >maria.gomezma@salud-juntaex.es>; Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: Emilia expulsión Muy buenos días a todas, Tras hablar con Raquel y posteriormente con Amalia, damos paso a la expulsión temporal de Emilia como repercusión por lo sucedido el fin de semana. Esta se llevará a cabo desde mañana jueves a primera hora hasta el domingo incluido, volviendo el lunes por la mañana. Tanto a nivel económico como de estancia quedan tratados directamente entre Emi y Amalia vía telefónica. Lo mismo con la medicación, ya preparada. La propia Emilia nos ha enseñado su cartilla, donde hemos visto su capacidad de ahorro como para mantenerse durante varios meses hasta que se decida otra vía o plaza para ella. Desde el CRR estamos desbordados. Rogamos que por favor no se demore más la solicitud de pérdida de plaza. Si hoy ocurre algún tipo de desajuste, se llamará al 112 como comentamos, aunque dudamos que ello termine a ingreso. Igualmente, lo haremos así si fuese necesario. No tengo el correo se Soraya, por favor, trasladadle la información si lo contempláis necesario. Muchas gracias, espero feedback de ser recibido. Un abrazo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2023-03-02','Ana: Correo de Amor López Serradilla (amor.lopez@aspacecaceres.es) al ctutelar@: "Hemos recibido la resolución mediante correo postal del material ortoprotésico tramitado. En ella la cual adjunto en este mail, se le abonará en su cuenta la cantidad de 3898,29€ Esta cantidad, tal y como sabe Ana pertenece a la ortopedia que le ha suministrado la silla de ruedas y todas las adaptaciones necesarias, por lo que rogaría por favor se haga la transferencia en el menor tiempo posible ya que al ser tanta la necesidad de Santiago Eduardo se hizo en dos facturas, una primera ya abonada y esta segunda que esperabamos la resolucion mencionada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-02-07','Ana: correo de Toni-Futuex: "mañana, se habia previsto realizar la limpieza de la casa.- El grupo sifu mantenia el mismo presupuesto, que habia dado inicialmente, asique se acordó con ellos, y se comenzaria mañana. Estamos ultimando con Felisi como hacer el desplazamiento, ya que en bus va a ser un poco complicado, por los horarios, pues vamos a intentar concertarle un taxi. Finalmente la idea más óptima es que vaya en bus, y a la vuelta hacia el casar, regrese en taxi , que le saldria por unos 30/35 eu (para pagar por transferencia). Ya que si creemos que es pertinente que ella este presente, para las cosas que se consideren tirar o no tirar, porque si no estuviera a la larga esto va a ser peor. Estaria también la compañera, y creo que las del programa de familia, con las que nos tendremos que coordinar porque ellas pidieron algunos presupuestos de algunas cosas tambien. Mañana también le cambian un cristal que habia pagado ella, (con el dinero retirado) y creo que esta es la persona tambien de la cerrajeria, preguntaremos. Esta super convencida en regresar a Navas, por ahora, creemos que porque está "aleccionada" por el novio, que le insiste en que cuando el salga, se van a ir los dos a Navas de nuevo. Nos consta la manipulación que ejerce sobre ella y es complicado poder intervenir en eso más allá de como lo hacemos todo el mundo. Nos ha dicho algo de las retiradas, de más dinero o no se.. pero como saca con tarjeta monedero, pues entendemos que eso, es la cantidad asignado desde la comisión como siempre. Se constatara lo del frigo como dices, y se pedira presupuesto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-03-03','Ana: en relación al correo-e pendiente de Eva Álvarez, TS (trabajadorasocialco@plenainclusionmontijo.org): "Estamos viendo la posibilidad de que la familia de Adrián pueda venir a verlo con visita controlada. Estaría bien que vinieran a Montijo un día y tomarse algo con ellos, acompañados de un monitor de la vivienda. Imagino que así se ha hecho en otras ocasiones, si no es así me puedes decir cómo se ha hecho?" ································· respondo: "Acabo de leerlo y me parece bien la propuesta que hacéis. De momento todas las visitas supervisadas y en función de lo que vayáis observando y constando en dichas visitas, vamos viendo, pues como ya os informamos cuando ingresó en vuestro recurso, con la familia ha habido numerosas incidencias, no es una familia bien estructurada y la influencia sobre Adrián no es buena, así que reitero, de momento con supervisión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-03-03','Ana: Guardo en el Expdte. digital el último Informe de Psiquiatría de fecha 17/12/22, emitido por la Dra. Guadalupe Espárrago Llorca, en que propone le deriven de nuevo a Habilitación Funcional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2023-03-03','Ana: Solicito INFORME SOCIAL, a Programa de Familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2023-03-03','miguel, Teresa Muelas (abogada) ya ha presentado la demanda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2023-03-03','miguel, Teresa Muelas (abogada) ya ha presentado la demanda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2023-03-03','Ana: Recibimos carta informativa de ASPACE, con información a la subida del copago de la plaza residencia, que en 2023 ascenderá a 545,19€/mes. ··································································································································································································· Correo-respuesta de Amor, TS ASPACE, a mi correo de ayer: "Santi esta genial, cada dia mas mayor, mas adaptado y con mayor participación en alguna de las actividades sobre todo en aquellas beneficiosas para él como son las salidas y paseos que realiza. Lo de la ropa continua igual.... Cuando puedas Ana por favor me confirmas que habeis realizado la transferencia a la ortopedia, el procedimiento se alargó dos años y es mucho dinero no crees?" ··············· Confirmo que el lunes la compañera de secc. ecca. hará la transferencia a la ortopedia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-03-03','Ana: Correo de Leire Sanz, TS de la Res. Ciudad Jardín (t.socialcanovas@grupociudadjardin.com): "Perdona que me vuelva a poner en contacto contigo, pero debido a los acontecimiento acaecidos ayer, me pongo en contacto nuevamente contigo, para comunicarte que AYER se ha puesto en contacto el Juzgado nº 1 con la RESIDENCIA DEL PARQUE DEL PRINCIPE, para comunicarnos que hay una DENUNCIA EN EL JUZGADO, por parte de los sobrinos de Cáceres contra los sobrinos de ANDALUCIA, pero el problema es que citan como TESTIGOS a Isabel y a MARIA Jimenez Picón. Hoy se va a poner en contacto el TUTOR LEGAL de MARÍA con la Directora del Centro. Ayer han estado nuevamente la sobrina de Cáceres solicitando copia DNI de María y se le ha dicho que no se le entrega. Tambien se le ha informado que el tema de la casa esta en manos de los asesores jurídicos de la COMISION TUTELAR, podríais contactar con el Juzgado." ············· *Lo reenvío a los A. Jurídicos, con copia a Leiry y a la residencia. ····························· Respuesta de Ángel, Asesor Jurídico: "En relación con María Jiménez Picón, en el caso que haya sido citada por el Juzgado, por favor, remítanos la citación judicial." ······················· Respuesta de Leire, TS: "NO TENEMOS CITACIÓN JUDICIAL,HA SIDO MEDIANTE LLAMADA TELEFONICA A LA DIRECTORA DEL CENTRO AYER VINIERON LOS SOBRINOS( CARMEN Y ACOMPAÑANTE) PARA LLEVARSE A ISABEL , LA HERMANA DE MARIA PARA HACER UN PODER NOTARIAL Y SE LA LLEVARON LES PONGO EN CONOCIMIENTO, PORQUE EN LA CUENTA FIGURAN LAS DOS HERMANAS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-03-03','Ana: Envío correo a Leire Sanz, TS: "En relación la petición de Informe Social, que te realizó Maite, compañera y Jefa de Sección de la CTAEx, me dicen los compañeros Asesores Jurídicos que les dicen que es urgente. ¿Podrías agilizarlo, por favor?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-03-02','Ana: Correo-e de Mª del Sol Tafur, ESM y E.C.A.- La Cumbre (mariasoledad.tafur@salud-juntaex.es): "Te remito los informes que en su día envíamos a Fiscalía referidos a Dª María Guadalupe. Respecto a la situación a partir de la fecha del segundo informe, ya te he comentado en correos varios cómo han ido aconteciendo los hechos ( derrumbamiento del tejado, ahora se está viniendo abajo otra parte de la vivienda ). Te llamo para comentarte lo que me ha transmitido Miguel, Psiquiatra."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2023-03-06','El cambio a Ibercaja lo hemos hecho desde aquí. Está el alta de terceros en su carpeta con oficio de salida para PNC. Supongo que se lo pasarías a Julio para que lo hiciera. Esa cuenta es la única que controlamos de ella. Si os parece, podemos empezar a intervenir e imponerle una limitación mensual de reintegro. Ya me decís. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2023-03-06','El cambio a Ibercaja lo hemos hecho desde aquí. Está el alta de terceros en su carpeta con oficio de salida para PNC. Supongo que se lo pasarías a Julio para que lo hiciera. Esa cuenta es la única que controlamos de ella. Si os parece, podemos empezar a intervenir e imponerle una limitación mensual de reintegro. Ya me decís. Un saludo.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-03-06','miguel, llega email de Eva Perez (tlfno 649-555601) Buenos días , la constructora no acaba de enviar presupuesto. La semana pasada solicitamos el proyecto para que otra constructora pudiese presupuestar, pero los hermanos Plasencia no acaban de remitir el proyecto. ************************************************* Me llama por tlfno para explicarme que la construcotra no acaba de darle el presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE RAMON'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2023-03-06','miguel, me llama la abogada Eva Perez Eva Perez (tlfno 649-555601) del caso de Civantos Fernandez ( la de la casa en declaración ruinosa), que también está llevando la herencia de la hermana fallecida del tutelado, Rosa. Me comenta que va a hacer la liquidación de impuesto de sucesiones y que aunque no aparecen bienes de ella, sí que los tenía ya que ambos tienen un par de casas en muy malas condiciones de sus padres. Cuando tenga la información necesaria se pondrá en contacto con nosotros para hacer la correspondiente herencia y de las autorizaciones judiciales para aceptar-aprobar la herencia, previo presupuesto que le pediremos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='POZAS'and apellido2='GOMEZ'),'2023-03-06','Ana: Envío a Rosa Bravo, Adtvo. del CSS-Plas (rosamaria.bravop@salud-juntaex.es): Consentimiento Informado para Anestesia firmado por el D. Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-03-06','TERESA el viernes no acudió a la cita con la psicóloga y no le abrió la puerta a la monitora que va a su casa; comenta que no necesita nada de nosotros y que quiere el alta del CRPS (montó una buena). El miércoles hable con ella y estaba contenta con la intervención a domicilio; el viernes ya no quería ninguna intervención. Dejaremos unos días par ver si se calma y luego intentaré hablar con ella, porque ahora no está muy receptiva; no se que le habrá pasado, solo sé que el viernes estaba en su casa otra vez Toni.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-03-06','TERESA´ Comentaros que Marta hoy ha asistido al curso que esta haciendo y después no sabemos dónde ha ido. Intento mentirnos diciendo que su hermana necesitaba que se quedara con los niños pero la he llamado y como nos imaginabamos, eso no era así. La hemos llamado pero no ha contestado. También me comenta una compañera que habla con chicos por las noches, en concreto me habla de una conversación en la que se envían fotos, Marta sale en las fotos en la cama y en sujetador (la compañera solo vio esta foto). Nosotros no lo hemos hablado con ella porque no la hemos visto aun pero consideramos que son actos bastante serios. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2023-03-06','TERESA En su expediente quedo las llaves a espera que diga el juzgado. La información que se le dijo a su prima fue que tenía que hablar con juzgado, así que perfecto. Gracias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-03-06','Ana: Envío correo a A. Jurídicos - CTAEx: "Adjunto el INFORME SOCIAL solicitado para la REVISIÓN DE LAS MEDIDAS JUDICIALES DE APOYO relativas a JOSEFA SÁNCHEZ DÍAZ"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-03-06','Ana: Llamo a Julia Durán, TS del Centro de Mayores - "Hogar" Peña del Cura de CC (22032): No obtengo respuesta. ······························································································································································································· Tras recibir Informe Social de Julia Durán, TS del CM Peña del Cura, se lo reenvío a los A. Jurídicos CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-03-06','Ana: Tras recibir llamada de Ángel Félix (643 622 174), envío correo a Alberto, Jefe Secc. Ecca., con copia a Maite, Jefa CTAEx: "En relación a ÁNGEL FÉLIX MAILLO SANTIBAÑEZ, dos cuestiones: - Hoy es su cumpleaños y solicita un extra en tal concepto. No dice cuánto. No sé cómo está su situación económica. Si pudiera ser, supongo que entre 50 – 60€ estaría bien. - En cuanto a la búsqueda de vivienda, dice que aún no ha encontrado ningún sitio de alquiler en el campo o algún pueblito, como era su intención. De momento sigue en “casa de un amigo”. Plantea que se le vuelva a realizar autorización para este mes de 200€ para contribuir con los gastos. Mi propuesta es, mientras que no encuentre otro alojamiento y con contrato, que se le haga una autorización permanente mensual de 200€ en concepto de Alojamiento. Ya me dices si es factible. Por favor, cuanto esté confirmado, que le llame alguna compi, si es posible, para confirmarle la cuantía y fecha de retirada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-03-06','Ana: correo de Ángel, A. Jurídico CTAEx.: "Con respecto a la vivienda, presentamos denuncia ante policía de Mérida, que dio traslado a la policía de Cáceres. En visita girada al domicilio, me indican que allí ya no hay ocupas. Van a remitirnos al correo de Comisión el Informe. Por otro lado, me ha vuelto a llamar una de las sobrinas, Carmen, por un lado quiere plantear asumir ella el cargo de curador de María y por otro lado, Isabel, le ha firmado un poder para que pueda actuar en su nombre. Me pidió datos de la cuenta de María, pero no se los he facilitado. Esta señora no me ofrece mucha confianza." ······························································································································································································ Correo de Ángel, A. Jurídico CTAEx: "Os reenvío el Informe de la Policía de Cáceres, en el que nos indican que en la vivienda de las hermanas, no hay ocupas." ············· *Ángel lo envía también a Leire, TS Residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-03-06','miguel, escalona envía a ctutelar la autorización de internamiento involuntario en UME del tutelado. Lo envío a Ana para su conocimiento y remito a la abogada Carmen Lucas: Buenos días Carmen, el juzgado nº2 de Cáceres autoriza al internamiento involuntario en centro adecuado de Saturnino. Sería posible que lo comentes con el juzgado nº6 de Cáceres o el Ministerio Fiscal? Si nos autorizan daríamos la orden de su internamiento y de esa forma se cumplirían los deseos de todas las partes Quedo a la espera de tu respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-03-06','miguel, Inés enviará vía lexnet informe social y económico (junto a movimientos bancarios) para el procedimiento de revisión de medidas, conforme petición que hizo el juzgado nº6 de Caceres, procedimiento DT 5 Ley 8/2021 proced 737/2022','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-03-06','miguel, Inés envía hoy las alegaciones que he hecho al ayto de Piedras Albas en relación al expediente de Declaración de ruina legal de inmueble Nº 19/2023','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-03-06','Incidencias Emi durante la salida de fin de semana al hostal Ana : Emi, aún no ha regresado al centro. Hemos estado en contacto con ella todo el fin de semana y la hemos notado bastante desorganizada. Desde el Hostal nos han comentado que su comportamiento ha sido correcto y adecuado durante su estancia allí pero verbalizaban preocupación por Emilia porque la habían visto pedir dinero por no disponer del mismo. Ha asistido al centro de salud en alguna ocasión este fin de semana pero finalmente no la han quedado ingresada en el hospital. Acabo de hablar con ella por teléfono y me comenta que no tiene dinero para poder regresar al centro. Partiendo de la problemática que Emi presenta con el dinero y que además tenía que costearse todos los gastos de comida y demás de su asignación… no le queda nada de dinero para regresar a Olivenza. Llamadla por teléfono y hablad con ella para dar solución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-03-07','Ana: En relación al correo de Isabel: "Hola Ana te quería preguntar una cosa yo estoy tutelada o tengo la curatela ??? Espero tu respuesta y aver si pronto puedo manejar yo mi dinero un saludo y buenos dias" ··························· Mi respuesta: "Buenos días Isabel, Según tu sentencia, la Comisión Tutelar de Adultos ejerce una tutela para regir tu persona y tus bienes. Aunque la legislación ha cambiado y ya no se contempla el término “tutela”, hasta que en el Juzgado no revisen tu sentencia, y aunque puedas llamarlo ya Curatela, todavía hay que actuar de la misma manera que hasta ahora, teniendo en cuenta tus deseos y preferencias, como intentamos hacer, pero velando por tu bienestar y la protección de tu patrimonio (en este caso dinero). Pongo en copia a Paula y Carolina, pues estoy segura que si tienes dudas con respecto a algo de lo que te he tratado de explicar, ellas te lo aclararán mejor de manera presencial. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2023-03-03','-Amalia , asisto a Comisión junto con Mayte . Se propone Comunidad Terapeutica , o valorar algún recurso publico fuera de la CAE . Volverán a proponer otra subcomisión con lo que se haya podido obtener. No hay cambios en el expediente , sólo cpto. de ATP de PNC , pasa a percibir 726€ -Van a ingresarle 1453€ de atrasos de ese cpto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-03-07','Ana: Llamo a Pilar, Directora de la Res. FEMAR (639 585 489): en relación a la previsión del tratamiento del fisio, no nos llegó a enviar nada porque éste cogió la baja por paternidad, por lo que tampoco ha vuelto a recibir tratamiento. ··· Como se va a incorporar ya, le va a preguntar y nos enviará un correo al respecto. ··· Si bien es cierto, Valentina tiene cada día más dificultades: no puede ponerse los calcetines, el otro día fueron de excursión a la ermita del pueblo y no consiguieron subirla al coche... ······································· Por otra parte, Valentina no tiene asignación de gastos de bolsillo y las botellas de agua y caramelos que de vez en cuanto pide, se lo pagan ellas. Me enviará propuesta con cuantía aproximada y nº de cuenta pues se haría mediante transferencia a FEMAR. ··········· Además, necesitan que una modista le coja los bajos de os pantalones que se han comprado. Nos indicará el coste también en el correo. ··············································· En cuanto a las pequeñas propiedades que me habló del padre, me facilita los datos del mismo para que solicitemos información registro de la propiedad. ··············· Envío correo a los A. Jurídicos: "En relación a VALENTINA FERNÁNDEZ TREJO, la directora de la Residencia, me plantea hacer consulta al REGISTRO DE LA PROPIEDAD, para averiguar qué propiedades conserva. Dice que la cerca, seguro, pero que la cuadra no sabe si el padre la vendería en su día. ¿Vosotros tenéis acceso o podéis solicitarlo? La única heredera es Valentina. Los datos del padre son: JUAN FERNÁNDEZ GÓMEZ. DNI: 75993318F" ·························· Respuesta de Ángel: "Tenemos certificación catastral a nombre del padre y aparecen 2 propiedades. Una es en la que están los ocupas (tenemos el juicio este mes). Habría que hacer la herencia primero, para poner a nombre de Valentina las propiedades y luego venderlas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-03-07','Ana: Correo de Ana Sánchez (anatdelat@hotmail.com) al ctutelar@: "Adjunto la factura de unas cositas que ha comprado la usuaria Isabel Muñoz Melchor para proceder a su pago" ···················· Lourdes, secc. ecca., responde que la próxima vez, deben remitir con carácter previo presupuesto para ser aprobado por la sección económica antes de proceder a la compra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-03-07','Ana: Envío correo a Alberto, Miguel, Ángel, y Maite, CTAEx: "Acabo de hablar con Arancha, Directora de la Residencia, sobre varias cuestiones, con respecto a este correo y con respecto al anterior que me enviaste, Alberto: - El concepto del cargo en cuenta “IMPUESTO COMUNIDAD AUTÓNOMA” corresponde al Abono de la plaza de Sociosanitaria, tipo T3 de Isabel, hermana (no es una deuda). Es plaza pública y este tipo de plaza tiene un coste distinto, no es el 75% de los ingresos. - La PNC de Isabel se destina al abono de la plaza - Isabel no comenzó a percibir la PNC hasta septiembre de 2020. Hasta entonces la única que ingresaba dinero era María y de hecho, al principio de ingresar las dos, María abonaba también la plaza de Isabel hasta que a ésta le concedieron la PNC, se la solicitaron estando ya en el centro. - Por tanto, la mayor parte del dinero que hay en la cuenta compartida, corresponde a María, quién ha velado/cuidado siempre de su hermana. - Con el poder notarial que firmó Isabel (aún presentando deterioro cognitivo…) temen que vayan a sacar/trasferir el dinero… La directora propone que se haga traspaso a la nueva cuenta de María e incluso que se quite de esa cuenta a María. *A ella le llamó un notario a primera hora, en base a la cita que tenía, y le explicó la situación de Isabel (ingresó en el centro de forma involuntaria y presenta deterioro). Como se ve, que con éste notario no consiguieron lo que querían, se fueron a otro, ante el que firmó el poder. **Les he propuesto que lo notifiquen todo a Fiscalía. Pues los sobrinos quieren ir hoy a la Residencia con el poder a pedir el DNI de Isabel. Creo que con esto respondo a tu última pregunta Alberto, yo sacaría el dinero de ahí YA. A ver qué dicen Ángel y Miguel, pero no debemos demorarnos." ············································ **Desde la secc. ecca. traspasan 40.000€ a la cuenta en la que está sola María.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-03-07','Ana: envío correo a Sheila, Directora del CRR (crr@grupociudadjardin.com): "Comunicarte que ya he cumplimentado y puesto para la firma del Representante Legal la Solicitud de Valoración de Dependencia para revisión del grado de Martín. Pero seguimos a la espera del Informe de salud y demás informes médicos que acrediten su empeoramiento para poder presentarlos junto a la solicitud. Por favor, cuando os sea posible, hacédmelos llegar. Por otra parte, aprovecho para solicitaros que nos remitáis escaneado, el DNI actualizado de Martín así como su tarjeta sanitaria, para cumplimentar su expediente." ····································· *Guardo en el expediente digital la Solicitud REVISIÓN DEL GRADO DE DEPENENCIA por empeoramiento firmada digitalmente por el Presidente de la CTAEx. ····· En espera de los informes médicos para poder darle registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-03-07','-AMALIA: Sñor de 78 años , vive solo en Ahigal . La propia sentencia autoriza internamiento en R.M. He solicitado a la TS del SSASB I.social del decreto para pedir la plaza por emergencia. Necesitaría R.M . asistidos. No tiene solicitado ni dependencia , la TS lo va a iniciar y me enviará informes médicos. Ya he pedido a Futuex que realicen la visita. Quedo pendiente de estos trámites para pedir la plaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-03-07','-AMALIA: Sñor de 78 años , vive solo en Ahigal . La propia sentencia autoriza internamiento en R.M. He solicitado a la TS del SSASB I.social del decreto para pedir la plaza por emergencia. Necesitaría R.M . asistidos. No tiene solicitado ni dependencia , la TS lo va a iniciar y me enviará informes médicos. Ya he pedido a Futuex que realicen la visita. Quedo pendiente de estos trámites para pedir la plaza.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2023-03-07','Buenos días, solicitan desde el SEPAD la documentación que falta para la solicitud de admisión en centros enviada para Iván Mesa Candil. Falta : informe social , cdo. empadronamiento , , informe médico . Cuando tengáis todo ello me lo podéis remitir para registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='NUÑEZ'and apellido2='NAJARRO'),'2023-03-07','Maite: Nos han comunicado desde la sección de discapacidad la adjudicaicón de plaza en INCLUSIVES de Antonio. He hablado con Pilar, técnico de menores para informarla. He intentado hablar con Guadalupe , directora del CAM de Villanueva pero no he podido. Pilar me ha dicho que lo ha hecho élla. También he contactado con Oscar, trabajador social del CEE donde acude Antonio. El ingreso será la semana que viene. Se pondrán de acuerdo los dos centros para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-03-07','Ana: correo de Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es): "Hola ya he remitido tal como quedamos la solicitud de CRR por emergencia social, para firmar la parte vuestra como tutores y ser más ágil habla con Eva ellos ya tienen el expediente. En principio al ser un centro abierto lo mando con la aceptación del paciente y la firma nuestra. Por cierto, me dice José Manuel que le llames."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-03-08','Ana: correo de Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es): "Ana en la Comisión de Valoración me dicen que seguramente no se puede valorar el caso de José Manuel en la reunión de mañana, pero es una realidad que no puede estar en un 4º piso sin ascensor y además será progresivo el empeoramiento, ahora bien, tenemos el riesgo de terceros según he hablado con vivienda. Bueno ya vamos hablando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-03-07','miguel, envío email a Rosa Bravo Pacheco del CSS de Plasencia: Buenos días Rosa, estamos preparando la herencia de una antigua residente vuestra, hoy fallecida Modesta Garcia Piñero, madre de nuestra tutelada Flora Gutierrez Garcia. En su día no dejó testamento, por lo que necesitamos para poder hacer dicha herencia de Modesta Garcia Piñero, que dos testigos que declaren conocer a Modesta, puedan acercarse a la notaria de Plasencia para firmar la correspondiente declaración de herederos. También necesito que mires en vuestro expediente y me digas los datos de contacto de las hermanas: yo tengo estos dos contactos dos hermanas, Modesta y Juana María Gutiérrez García y teléfonos 673972619 y 938606605, pero no me los cogen… Los datos de contacto de la persona de la notaria a la que voy a solicitar hacer dicha Declaración de Herederos es: María del Pilar López González Oficial de Notaria (Escrituras y Pólizas) Notaría Jiménez-Mancha Avda. Alfonso VIII, nº 27 Pt-1 10.600 Plasencia (Cáceres) Tfo 927.41.14.47 Fax 927.42.14.99 Confírmame cuanto antes que podemos contar con esos dos testigos para lo cual ya os avisamos o bien la notaria o bien yo de la fecha de firma. Indícame también teléfono de contacto de sus hermanas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-03-07','Ana: Estrella, Secc. Ecca, me confirma que a Juan Gregorio ya le han pasado por su cuenta (Ibercaja) el Seguro de Decesos de Santa Lucía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-03-07','Ana: Reenvío a Ángel y Miguel, A. Jurídicos CTAEx, Informe de Seguimiento de Futuex, para la Revisión de las Medidas Judiciales de Apoyo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2022-12-21','Amalia : se hace el cambio del Nº cuenta en pensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2022-12-21','Amalia : se hace el cambio del Nº cuenta en pensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-03-07','miguel, envío email a Ana tras la conversación con Rosa del CSS: Por otro lado de Saturnino me ha dicho Rosa que tiene ordenes de ingreso involuntario de Saturnino. Ya le he explicado que la abogada está a la espera que le enviemos contestación de la psiquiatra. Me ha dicho que ella mantiene contacto con la psiquiatra, así que la voy a enviar el auto no firma de internamiento involuntario del jzdo nº2 de Cáceres, a expensas de lo que resuelva el juzgado nº6 de Cáceres sobre el delito de agresión sexual. La idea es que se lo remita a la psiquiatra (aunque no sé si ella lo refrendará o no) La firmeza de dicho auto de internamiento será para final de mes, por lo que a principios de Abril pediremos la firmeza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-03-07','miguel, envío email a Ana de la conversación con Rosa del CSS: Hola Ana, acabo de hablar con Rosa del Css de Plasencia, quien me confirma que no hay problema para los dos testigos para la declaración de herederos que necesitamos hacer de Modesta para preparar su herencia. Me comenta que ellas no tienen más datos de las hermanas, que no tuvieron contacto con la tutelada y solo aparecieron al fallecer para preguntar por la casa y la herencia. Me dice que han intentado conseguir otros teléfonos de contacto para lo cual han hablado con el CRR de Plasencia (no sé si me ha dicho con el director) y que les dicen que no les pueden facilitar ningún dato porque el CSS no son los tutores de Flora. Por tanto necesito que hables con quien corresponda del CRR y que te aclaren si tienen alguna otra forma de contactar con las dos hermanas de Flora (y si los teléfonos que tenemos son o no correctos…673972619 y 938606605) para tramitar la herencia de su madre Modesta. ************************************************* Envío email a la notaria de Plasencia mplgonzalez@despacho.notariado.org (lugar de fallecimiento de Modesta,su madre):','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-03-08','Ana: Llamada de Felisi, ya le han puesto las rejas. Está disgustada con como le dejaron la casa su hijo y la pareja. El perro se lo ha quedado su suegra, ya no lo quiere. Ahora tiene 2 canarios que "cantan muy bien". ·············· Me cuenta que ya está viviendo Jesús con ella. De momento está percibiendo el subsidio, pero no está haciendo nada ahora. ·············· Aún no le han enviado la tarjeta del autobús, las compañeras del Progr. de Familia se lo acercarán cuando llegue. ············· Le han dicho que ahora en la Nava del Madroño hay "clases para aprender a leer y a escribir".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-03-07','Ana: Llamada de Mercedes, TS del SSASB Trujillo (927 659 391): Explica que Aitor y su pareja están en la calle desde ayer, pues les han echado de la casa en la que estaban viviendo de okupas. *Nos remitirá Informe a Teresa y a mí comunicándolo. ···················· Teresa envía el Informe a los A. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-03-08','Ana: Correo de ayer de Laura Domínguez Gómez, TS del IMAS (laura.dominguez@ayto-caceres.es): "Buenos días Ana!! Ayer vinieron lo padres de Montaña por aqui con las facturas de energía eléctrica que tenía pendientes, y me sorprendí al ver que no tiene bono social. Vosotros se lo podeis solicitar desde ahi?? Si quereis si me dais autorización yo misma lo puedo solicitar, más que nada, por el descuento y por que esté protegida antes posibles cortes de suministro." ··············· Mi respuesta: "Pues yo también me he sorprendido al leer tu correo. Nosotras desde aquí no podemos solicitarlo. Por supuesto, desde el Gabinete Técnico de la CTAEx, te autorizamos para realizar la gestión. Si necesitas que el Presidente de la CTAEx, como su representante legal, firme algún documento, no dudes en remitírmelo. Seguimos en contacto." ········································ Nuevo correo de Laura, TS: "vale. Lo solicito. Hoy justo han vuelto los padres de Montaña con carta de aviso de corte, intentaremos pararlo desde aqui. También traian carta de la PNC , de declaración individual de ingresos. La verdad que on se muy bien en este caso quien tiene que firmar eso, si vosotros o ella. Me han dicho que venia Montaña este fin de semana de permiso, y les he dicho que lo firme ella, pero por tenerlo claro para otras gestiones." ············ Le indico que la Declaración Jurada de PNC, debe firmarlo el Representante Legal, que si pueden nos lo hagan llegar. ··································································································································································································· Correo de Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Comunico que Montaña González Rolo va de pase con la familia desde mañana jueves al sábado día 11."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-03-07','miguel, recibimos diligencia de ordenación donde el jzdo nº6 Cáceres nos comunica que va a inhibirse a favor del Jzdo Decano de Trujillo por ser el competente, al ser el lugar donde actualmente reside.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-03-08','miguel, Teresa me remite informe social del Ayto de Trujillo, para que lo remita al jzdo competente ya que Aitor se encuentra en la calle. Reenvío por email a Inés el informe remitido por el Ayto de Trujillo a Tere, para su comunicación al jzdo nº6 de Cáceres: envía al juzgado nº6 de Cáceres vía Lexnet esta documentación y pon un oficio que contenga “ se adjunta informe del ayuntamiento de Trujillo a efectos de su incorporación al expediente que desde este juzgado remitirán por inhibición al juzgado Decano de Trujillo, a los efectos oportunos”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2023-03-08','Buenos días Soraya, Recibida toda la información. La traslado al equipo que gestiona el Programa Saguaro y la Comunidad Terapéutica (entidad Asociación Apatyrs). La directora de los programas, Mercedes Barquero (psicóloga) se pondrá en contacto con Carmen Franco. Esperemos que entre todas podamos favorecer el progreso de la persona beneficiaria. Saludos cordiales, Mª del Pilar Morcillo Sánchez Secretaria Técnica de Adicciones. Servicio Extremeño de Salud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-08','Ana: Tras conversación con Puerto Paniagua Martín, TS del SSASB de la Mancomunidad Valle del Alagón (927 122 413 // 927 44 82 50), me remite correo-e (ssb5@mancomunidadvalledelalagon.es): "Buenos días de nuevo: como quedamos telefónicamente, adjunto remito solicitud para el SAD de Valdeobispo, la documentación necesaria es: copia DNI, informe médico, certificado convivencia, certificado pensión INSS, reconocimiento grado discapacidad y/o dependencia, autorización y solicitud. Para el caso de Enrique, como ya lo tengo todo en el expediente de él, solo necesitaría la solicitud firmada y la autorización, el informe médico se lo pido yo a la médica de cabecera de Valdeobispo (Susana) Por favor registrarlo por ventanilla y vamos coordinándonos... El coste del servicio son 1,80€ la hora de SAD." ······················· Paso a Alberto la Autorización Bancaria. ········ Cumplimento y subo al portafirmas digital la Solicitud del SAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2023-03-08','Amalia , terminado plan de intervención , correcta adaptación a la R.M. , derivo el caso para seguimiento a Tere.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-03-13','TERESA Sentimos el tema de las facturas. Tenemos un problema con ellos, supuestamente mañana se tienen que ir de la casa, no sabemos donde van a irse a vivir y querían a toda costa que hiciesemos hoy la compra. les hemos dicho que hasta que no estén situados en una vivienda no se hace la compra porque creemos que esa comida se la quiten los marroquíes que están allí. Mañana os mantendremos informadas. Han llegado a esa vivienda 4 marroquíes más y creemos que va a ser un guetto. FACILITO INFOMRE DE SITUACION ACTUAL A MIGUEL PARA QUE LO COMUNIQUE AL JUZGADO DE TRUJILLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2023-03-08','TERESA PNC: 484,61 X 14 CENTRO: 363,46 X 12 + ASIGNACIÓN: 170 X 12 + OTROS GASTOS: VARIAN PERO DE POCA CUANTÍA: 533,46 X 12 + VARIABLES. EN OTRAS OCASCIONES SE LEDABA 100 € A EL DE ASIGNACIÓN Y 70 € AL PADRE DE MANUTENCIÓN. X SUPUESTO, LA SITUACIÓN ECO DE DAVID ES POSITIVA DEBIDO A LOS CONTRATOS QUE DE VEZ EN CUENDO TIENE...ES ALGO QUE NO SE PUEDE PREVER NI EN SU DURACIÓN NI EN SU CUANTÍA....ESO PODRÍA ACLARARLO ÚNICAMENTE EL CENTRO. TERE: NO SE SI LE VALDRÁ CON ESA PROPUESTA DE 70 €/MES...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2023-03-08','Ana: Envío correo a Eloy, TS SSASB (ssb079@gmail.com) y Pepi, Responsable Residencia (residenciagrupovesta@gmail.com): "Me pongo en contacto con vosotros a petición de mi compañera Icíar, encargada de conformar el inventario de JUAN GARCÍA SÁNCHEZ. Me dice que para completar el Inventario y poder remitirlo al Juzgado, sólo le falta el Informe Social del Trabajador Social de referencia y proximidad. Eloy, agradecería que nos lo hicieseis llegar lo antes posible, pues nos finaliza el plazo que concede el Juzgado. Adjunto el oficio que se remitió en su día a la Residencia solicitándolo. Quedamos a la espera."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-03-08','TERESA Ayer se recibió una llamada de Manolo (primo de Tomás Carvajal) comentado que estaba con él yendo al banco y que nos llamaría hoy para acompañarnos a hacerle una visita. Hoy se ha llamado a Manolo que comentaba que no nos podía acompañar pero que consideraba que podíamos acercanos a verlo, se le ha explicado que ya se habían recibido llamadas telefónicas de Tomás en tono amenazante, Manolo ha explicado que es algo común, pero que Tomás nunca llega a hacer nada. Se ha acudido al domicilio de Tomás, nada más vernos por la ventana ha salido de casa diciendo que o nos íbamos de allí o nos mataba, obviamente, nos hemos ido de inmediato. Se ha llamado a Manolo para contárselo y explica que Tomás le había llamado diciéndole que nos había echado de allí. Se confirma que Tomás sigue igual, no quiere recibir nuestra visita y por el momento se vuelve a tomar distancia con este caso debido a razones más que obvias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-03-08','TERESA telefono PAF Trujillo: Eli y Teresa: 927323315','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-03-09','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "En relación a FELISA BRUNO SAAVEDRA, me comunican que la han propuesto para los pisos del PROYECTO MI CASA. Pero necesitan que elaboréis un informe sobre la evolución desde que está en vuestro centro y que por favor, no os centréis sólo en los aspectos negativos, sino, que destaquéis también sus intereses, motivaciones y aquellas cuestiones positivas que se puede reforzar así como otros objetivos que creáis se podrían conseguir con un abordaje más individual y personalizado. Hay que tener en cuenta que las características de estos recursos y la ratio de los mismos pueden resultar muy favorecedores para perfiles como el de Felisa. Por cierto, me indican que es urgente y que necesitan tenerlo para mañana, disculpa la premura."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2023-03-09','Ana: Llamada de Eloy, TS SSABS Madroñera (927 31 91 92): mañana o el lunes nos enviará el Informe Social así como la documentación pertinente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2023-03-09','TERESA ME ESCRIBRE MERCEDES LA TRABAJADORA SOCIAL DEL CENTRO PARA COMUNICARME QEU EL PADRE DE DAVID LA ESTA PRESIONANDO PORQUE TIENE DEUDAS Y QUIERE QUE DAVID LE DE DINERO TRASLADO LA CUESTION A LA PARTES SOCIAL Y ECO Y SE DECIDE PASAR EN CONCETPO DE MANUNTENCION LA CANTIDAD DE 70€ YA QUE DAVID PASA EN EL DOMICLIO FAMILAIR VARIOS DIAS A LA SEMANA SE INTENTA CONTACTAR CON EL PADRE PEOR NO COGE EL TELFONO (651628831) LE COMUNCIO A MERCEDES LA TS DEL CENTRO LA DECISION TOMADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-03-09','Ana: Correo de Leire Sanz, TS de la Res. Ciudad Jardín (t.socialcanovas@grupociudadjardin.com): "Me pongo en contacto contigo para comunicarte que vamos ha mandar desde la Dirección del Centro, un informe al juzgado nº 1 donde tiene el ITR Isabel Jiménez Picón, para informarle de lo ocurrido con los familiares." ··················· Hablo con ella por teléfono, nos ha enviado a correo por lo que pueda afectar a su hermana María. ······ En cuanto la situación ecca. le explico los últimas gestiones que se han hecho desde la sección económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-03-09','Ana: Correo de Isabel: "Buenos días Ana anoche tuvo un atercado con una compañera de CRr se llama Marimar se está metiendo entre la relación de Cefe y mia y la di una patada en la escayola y la tiré un cenicero pero no la di en ningún lado y me ha puesto una denuncia qué hago no quiero estar aquí me gustaría irme a vivir con mi madre o con mi pareja y me ha dicho Paula que hable que sanción tengo que a lo mejor me voy para socio y yo allí no quiero ir porque estoy bien" ······················· Escribo a Paula y Carolina, CRR, para preguntar al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-03-09','Ana: Recibimos CERTIFICADO ACTUALIZADO DE PENSIÓN.','2');
