insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-09','Ana: Respondo al correo de Alberto: "Trato de averiguar lo del contrato de telefonía y propongo cambio a tarjeta de prepago. Entiendo que todos los gastos son de él, vive solo y no cuenta con más apoyos familiares ni de ningún tipo. En relación al contrato de Wifi, lo hemos estado valorando Maite y yo, y consideramos que podemos probar, a ver qué tal se maneja y si se mantiene el gasto en esa cuantía. Si va todo bien dejarlo así, pero en el momento que lleguen facturas disparatadas o lo use para contratar/comprar otros artículos/servicios sin autorización, se procede a dar de baja. En cuanto a la C/ La burreras, 3, es su domicilio… no sé de qué se tratará dicho impuesto Icíar." ······························································································································································································ Envío correo a Toni-Futuex: "En relación a ENRIQUE SANTOS GARCÍA-PUENTE, comunicarte que ya continúo yo con el expediente. Informarte también que estoy tramitando SERVICIO DE AYUDA A DOMICILIO MUNICIPAL. No sé exactamente cuándo podrá comenzar el servicio. Por otra parte, no sé si ya habéis realizado la primera visita. Al parecer tiene contrato de telefonía móvil, y como sabéis, el jefe de la sección económica no quiere que tengan contrato. ¿Podrías explicárselo a Enrique y apoyarle para el cambio de contrato a Tarjeta Prepago?? En cuanto al cargo que le hacen en cuenta de “WIFEX: SERVICIOS INFORMATICOS”, imaginamos que se trata de contrato de Wifi, pero no estamos seguros. ¿Podríais por favor verificar que es así? Nosotras le hemos propuesto a Alberto, que mientras el gasto (21€) y uso sean adecuados, mantenérselo. Pero n el momento que el gasto sea desmesurado o contrate/compre algún servicio/producto sin el consentimiento por parte de la CTAEx, se procederá a dar de baja. Por favor, trasmitírselo también, que le quede bien claro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-03-09','Ana: Tras hablar con Carmen, TS de Vivienda CC (927 00 14 52), envío correo a Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es): "Acabo de hablar con Carmen, compañera de Vivienda. Como te comentó a ti ayer, considera que el perfil de José Manuel no es adecuado ni para Vivienda Social ni tan siquiera para Vivienda de Alquiler. Tanto por el entorno en que están ubicadas las viviendas sociales (su forma de ser y de actuar, así como la problemática que genera, habría que sumarla a la problemática de los barrios en que están ubicadas estas viviendas), como por la alarma social que puede generar y el riesgo para terceros, como tú bien dices, en barrios más normalizados. Considera que generará conflicto donde quiera que vaya y que precisa de supervisión y atención diaria. Expresa: “Lo que necesita es estar en un centro”. Ya le he explicado las dificultades que encontramos para ello, y que la solicitud de CRR seguramente la vayan a denegar. Por otra parte, sabes que la ayuda al alquiler, se la ingresarían muchos meses después de solicitarla. No obstante, tal y como ya hemos hablado, la solución a la problemática de José Manuel, no pasa por que viva en un piso de alquiler y como sabes rechazó el tratamiento de Revital, recurso que también resultaría insuficiente." ································ OTRA INFORMACIÓN FACILITADA POR CARMEN, TS VIVIENDA: "José Manuel ya tuvo una vivienda social, al separarse de Lourdes, su ex-mujer, ésta se quedó a vivir allí con los hijos. Pero en 2009, José Manuel demostró que Lourdes se ya no vivía en esa vivienda, pues se había ido a vivir con una nueva pareja. El Juez se la asignó de nuevo a él y estuvo allí viviendo hasta que se vio obligado a renunciar a vivir en dicha vivienda por los problemas que generó. Tenía a todo el bloque amenazado con que iba a volar el edificio con una botella de butano. ······················· Carmen le ha dicho que por qué se quiere ir a vivir a otro sitio, con lo tranquilo que es su barrio. Él dice que los vecinos no le quieren. Al preguntarle por qué, responde que por su comportamiento. ······························ *Tienen que salir las AYUDAS DE VULNERABILIDAD, él a priori reúne requisitos, pero en principio no es la solución.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-03-09','Ana: Tras hablar con Carmen, TS de Vivienda CC (927 00 14 52), envío correo a Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es): "Acabo de hablar con Carmen, compañera de Vivienda. Como te comentó a ti ayer, considera que el perfil de José Manuel no es adecuado ni para Vivienda Social ni tan siquiera para Vivienda de Alquiler. Tanto por el entorno en que están ubicadas las viviendas sociales (su forma de ser y de actuar, así como la problemática que genera, habría que sumarla a la problemática de los barrios en que están ubicadas estas viviendas), como por la alarma social que puede generar y el riesgo para terceros, como tú bien dices, en barrios más normalizados. Considera que generará conflicto donde quiera que vaya y que precisa de supervisión y atención diaria. Expresa: “Lo que necesita es estar en un centro”. Ya le he explicado las dificultades que encontramos para ello, y que la solicitud de CRR seguramente la vayan a denegar. Por otra parte, sabes que la ayuda al alquiler, se la ingresarían muchos meses después de solicitarla. No obstante, tal y como ya hemos hablado, la solución a la problemática de José Manuel, no pasa por que viva en un piso de alquiler y como sabes rechazó el tratamiento de Revital, recurso que también resultaría insuficiente." ································ OTRA INFORMACIÓN FACILITADA POR CARMEN, TS VIVIENDA: "José Manuel ya tuvo una vivienda social, al separarse de Lourdes, su ex-mujer, ésta se quedó a vivir allí con los hijos. Pero en 2009, José Manuel demostró que Lourdes se ya no vivía en esa vivienda, pues se había ido a vivir con una nueva pareja. El Juez se la asignó de nuevo a él y estuvo allí viviendo hasta que se vio obligado a renunciar a vivir en dicha vivienda por los problemas que generó. Tenía a todo el bloque amenazado con que iba a volar el edificio con una botella de butano. ······················· Carmen le ha dicho que por qué se quiere ir a vivir a otro sitio, con lo tranquilo que es su barrio. Él dice que los vecinos no le quieren. Al preguntarle por qué, responde que por su comportamiento. ······························ *Tienen que salir las AYUDAS DE VULNERABILIDAD, él a priori reúne requisitos, pero en principio no es la solución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-03-09','Ana: Correo de Ceferino (ceferinomariscalcrespo64@gmail.com): "Buenos días quisiera comprarme la PlayStation 5 con el FIFA 23 me la custodiarían los monitores también me tendría que comprar un monitor para poder ver la pantalla. Me comprometo a ir a los talleres que me digan no más de tres gracias pero esta vez la consola la van a tener los monitores y yo le voy a dar un uso y después se la entregó a los monitores gracias por favor quiero comprarme la PlayStation 5 con el FIFA 23 por favor contéstame a este correo"','2');
