insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-03-10','Ana: envío correo a Mª Carmen, TS del HSPA (mariac.rodriguez@externos.salud-juntaex.es): "Tal y como acabamos de acordar, te remito el testimonio de la Sentencia y aceptación del cargo relativa a SATURNINO MIGUEL SALGADO JIMÉNEZ, para que puedas facilitárselo a la Psiquiatra."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-03-06','¡Buenos días! Adjunto remito solicitud de plaza pública en residencia de mayores de Sebastián Paredes Dicha. Ya la he registrado. Voy a grabar dicha solicitud en Rosetta. Hasta ahora. M.ª Ángeles Galindo Barrena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-03-10','En relación con María Jiménez Picón, me ha llamado Alfredo Barca Durán (alfredobarca@icac.es 654194986), Abogado de una de las sobrinas de las hermanas (María del Carmen Jiménez Sixto). Van a solicitar la Remoción para que asuma la curatela. Al mismo tiempo, me ha pedido información a cerca de los 40.000 euros que retiramos de la cuenta conjunta. No le he facilitado nada. Os lo comento para que lo sepamos todos y estemos preparados para cuando nos den traslado desde el Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2022-12-19','-Amalia : recibo varias llamadas de Enrique desde el mes pasado , está a la espera de ser tutelado por la CTAAEX . Le urge el tema económico. Vuelvo hablar con él, ya es firme la sentencia y abordaré este caso. Le pido información sobre su situación socioeconómica y familiar.','2');
