insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-03-13','Ana: Envío correo a Alberto, Óscar, Maite y Julio, CTAEx: "En relación a Julia Morón Hernández, regresó al domicilio familiar el mes pasado. Puesto que no ha consentido en regresar al centro y ya firmó el Alta Voluntaria, ha perdido la plaza. Por lo que vuelve a residir con sus padres. Aclaro y solicito varias cuestiones: - Puesto que parecía definitiva su permanencia en el CRR, solicité el cambio de pensión de PFHC a PNC (el primer pago que consta en PNC, corresponde a diciembre de 2022). Pero ahora que de nuevo reside en su domicilio, no puede percibir PNC, por ser incompatible con los ingresos de la unidad de convivencia… *Tengo que volver a solicitar el cambio. Os iré avisando de esto. - Alberto: Habrá que volver a concederles un dinero mensual, en conceptos de, por un lado, manutención a los padres y gastos de bolsillo para ella por otro. Antes de ingresar en el recurso se le hacía transferencia a la madre de 230 h/mes, de los cuales 200 eran para manutención y 30 para ella. Ahora, tanto una como la otra piden más porque se han encarecido los precios de todo. Yo entiendo que es normal, pero habrá que autorizarlo en función de la PFHC, que volverá a cobrar (453,30 € x 12). Desde la Secc. Social proponemos una subida total de 70€ más, de modo que para Julia sean 50€ para gastos de bolsillo y 250€ para manutención. Si no lo ves bien Alberto, nos dices. Julio, por favor, cambia de nuevo el domicilio en la Base de Datos (si se puede… si no, pues no pasa nada) C/ LANCHA CRISTAL, 61 C.P.: 10895 – CILLEROS (CÁCERES)" ································································································································································································································· Llamo a Marta, TS SSASB Cilleros (927 51 20 37 / tsocial@ayuntamientodecilleros.es): Julia Madre, también es perceptora de PNC, la semana pasada le llevaron al despacho la declaración anual. *Este año pasado no comunicaron el cambio de domicilio de Julia, pues continúa apareciendo en la declaración anual como conviviente sin ingresos. ··················· Tanto Marta, TS, como yo, comunicaremos las variaciones a PNC, comunicando la fecha de alta voluntaria del CRR (21/02/23). ······························································································································································································································· Llamo varias veces a PNC, tanto a Mérida como a Cáceres, pero no obtengo respueta. ············ **Subo al portafirmas la comunicación de variaciones a PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-03-13','miguel, me llama Sara Lozano Valades (629-116101; sarita_pei@hotmail.com, y tlfno trabajo 924-805077 para indicarme que en la notaria de Don Benito (Rafa) se está gestionando una herencia (creo de su abuela) Doña Isabel Diaz Rodriguez. Envío email a Rafa y a ella: Buenos días Rafa, como estás?. Me ha llamado Sara Lozano Valadés en relación con la herencia que estás tramitando de Doña Isabel Diaz Rodriguez. La Comisión Tutelar de Adultos ostenta la Curatela judicial de Doña Isabel Valadés Diaz que creo es la hija de la fallecida. Necesito saber qué necesitas para enviártelo. A parte de remitirme el borrador cuando lo tengas preparado, me tienes que confirmar si necesitas autorización judicial para la aceptación de la herencia y la asistencia y firma de la curatelada Doña Isabel Valadés Diaz, al tratarse de una curatela judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-03-13','miguel, me llama Sara Lozano Valades (629-116101; sarita_pei@hotmail.com, y tlfno trabajo 924-805077 para indicarme que en la notaria de Don Benito (Rafa) se está gestionando una herencia (creo de su abuela) Doña Isabel Diaz Rodriguez. Envío email a Rafa y a ella: Buenos días Rafa, como estás?. Me ha llamado Sara Lozano Valadés en relación con la herencia que estás tramitando de Doña Isabel Diaz Rodriguez. La Comisión Tutelar de Adultos ostenta la Curatela judicial de Doña Isabel Valadés Diaz que creo es la hija de la fallecida. Necesito saber qué necesitas para enviártelo. A parte de remitirme el borrador cuando lo tengas preparado, me tienes que confirmar si necesitas autorización judicial para la aceptación de la herencia y la asistencia y firma de la curatelada Doña Isabel Valadés Diaz, al tratarse de una curatela judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-03-13','miguel, Ana me reenvía email del CRR Plasencia (Paula): Ana, te confirmo que podemos tener la reunión el próximo jueves como proponíais. Respecto al contacto con las hermanas de Flora, he tenido oportunidad de hablar con una de ellas. Les he facilitado vuestro número y correo electrónico para que puedan contactar. Querían estar ambas presentes pero era complicado por las mañanas con sus horarios, por lo que sugerí que os contactaran por mail para poder acordar una reunión telefónica. El teléfono fijo de Modesta no está operativo actualmente, pero el móvil era el que os facilitamos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2023-03-13','TERESA TRAS CONVERSACION TELEFONICA CON M JESUS DE ORFANDAD 924216167 ACORDAMOS ENVIARLE POR EMAIL MARIA-JESUS.MORO@SEG.SOCIAL.ES LA SOLICITUD DE ORFANDAD YA QUE NO SABE PORQEU NO ESTA GRABADO Y SI LE PERTENECE LA ORFANDAD HAY QUE CAMBIAR LA PNC A PF PARA QUE SEAN COMPATIBLE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-03-13','miguel, Ana me reenvía email del CRR Plasencia (Paula): Ana, te confirmo que podemos tener la reunión el próximo jueves como proponíais. Respecto al contacto con las hermanas de Flora, he tenido oportunidad de hablar con una de ellas. Les he facilitado vuestro número y correo electrónico para que puedan contactar. Querían estar ambas presentes pero era complicado por las mañanas con sus horarios, por lo que sugerí que os contactaran por mail para poder acordar una reunión telefónica. El teléfono fijo de Modesta no está operativo actualmente, pero el móvil era el que os facilitamos *********************************************** Recibo email a Ana Ts y Rosa Bravo del CSS PLasencia, el email de la notaria de Plasencia: Buenos días Ana, pongo en copia a Rosa. Me ha remitido el email de debajo la notaria. No sé si podríais facilitar o indicarme quién puede darnos la documentación que viene debajo mplgonzalez@despacho.notariado.org: Buenos días Miguel. Para el Acta de herederos haría falta también: - Certificado de defunción del marido de la causante (para acreditar que estaba viuda). - Libro de Familia de la causante (para acreditar quienes son sus descendientes, si no tuvieran el libro de familia necesitaríamos certificado de matrimonio de la causante y su esposo y certificados de nacimiento de sus hijos. - Datos personales de los hijos. - Fotocopia del DNI de la causante. Entiendo por lo que me indicas en tu email que todos los hijos viven. A la firma, comparecería una de las hijas, o la Junta en representación de la hija tutelada?? ***************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-03-10','Ana: Correo de Paula, TO-CRR: "Tanto Isa como su compañera tuvieron un día bastante complicado por circunstancias ajenas al motivo de su conflicto. Durante el mismo ambas se insultan. Isa ante un insulto que la daña especialmente pasa a una acción física, que aunque no tiene mayores consecuencias, es importante y no se puede pasar por alto. Hablamos con ambas personas y apoyamos para que identifiquen sus conductas agresivas (verbales y físicas, en el caso de Isa), que entiendan la gravedad y el daño que hacen estas conductas tanto a ellas mismas, como a las personas de su entorno y, finalmente se les proporciona la oportunidad de "restaurar" el daño que se han hecho a través de apoyos en la vida cotidiana de una a la otra. Por la importancia de las conductas, se les entrega un documento en el que se informa acerca de las posibles consecuencias si se repiten las conductas y se especifica a Isa que, de aparecer de nuevo, se valorará, una posible expulsión o la idoneidad de su perfil de cara a la permanencia en CRR (puesto que sumaría conductas agresivas a todas las otras conductas por las que se mantiene en el límite de perfil de CRR). Isabel asume su parte de responsabilidad y acepta las medidas dispuestas (elige determinadas acciones para restaurar el daño a su compañera), y se compromete a intentar buscar otras alternativas de afrontamiento. Con todo ello se da por concluido el incidente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-03-10','Ana: Correo de Mercedes, TS SSASB Trujillo (ssbase.trujillo@salud-juntaex.es) a última hora: "Acabo de tener en el despacho a Mireia, la pareja de Aitor. Me dice que se van hoy a Badajoz. Cáritas les va a pagar el billete. Ella se irá a casa de sus abuelos, que viven allí y, por lo visto, Aitor intentará obtener una plaza en el Centro de Acogida de Emergencia que creo que Cáritas tiene allí. No sé si esta será la última información de ellos o si el lunes seguirán aquí. Pero de momento es lo que sé. Acaba de irse del despacho."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-03-13','TERESA Me dice que se van hoy a Badajoz. Cáritas les va a pagar el billete. Ella se irá a casa de sus abuelos, que viven allí y, por lo visto, Aitor intentará obtener una plaza en el Centro de Acogida de Emergencia que creo que Cáritas tiene allí. No sé si esta será la última información de ellos o si el lunes seguirán aquí. Pero de momento es lo que sé. Acaba de irse del despacho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-13','Ana: Envío a REGISTRO (oac.merida.san@juntaex.es): "En representación de D. ENRIQUE SANTOS GARCÍA-PUETE, cuyo cargo de Curador Representativo ostenta la CTAEx, adjunto la siguiente documentación para remitir por registro al AYUNTAMIENTO DE VALDEOBISPO: - SOLICITUD DE SERVICIO DE AYUDA A DOMICLIO MUNICIPAL - AUTORIZACION DE DOMICILIACIÓN BANCARIA - TESTIMONIO DE ACEPTACIÓN DEL CARGO / MEDIDAS JUDICIALES DE APOYO - DNI REPRESENTANTE LEGAL - DECRETO NOMBRAMIENTO COMO DIRECTOR GERENTE SEPAD - RESOLUCION DELEGACIÓN DE COMPETENCIAS – PRESIDENTE DE LA COMISIÓN TUTELAR"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-03-13','Ana: Correo de Eva Álvarez, TS (trabajadorasocialco@plenainclusionmontijo.org): "Adjunto remito la notificación que hemos recogido en el juzgado de Adri. Como ves la condena es continuar con el tratamiento psiquiátrico. Tu sabes si ya lo comenzó allí? Sabes si la psiquiatra de aquí será la que lleve a cabo ese tratamiento? Aún falta por recoger otra notificación que, imagino, será igual que la de hoy." ··············· Mi respuesta: "Adrián Ortigosa Fuentes ya lleva varias ejecutorias con el mismo fallo condenatorio... Así que ya empezó a cumplir los anteriores allí. Y sí, son los Psiquiatras de referencia de los ESM los que tiene que estar pendiente de que asiste a las citaciones y cumple el tratamiento. *Por vuestra parte, en el recurso, aseguraros de la que la medicación oral la está tomando con regularidad (que me consta que esto lo hacéis en lo pisos y centros) No obstante, pongo en copia a mi compañero Miguel, Asesor Jurídico, por si tuviera que aclarar/añadir algo más."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2023-03-13','Ana: Correo de Estrella Durán, TS CSS-Plas.: "Hoy se ha ido de alta al CRR, Juan Mario San Román Blasco."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2023-03-07','REVISIÓN MEDIDAS DE APOYO Con f/ 07/03/2023 se procede a aceptar el cargo de Curador Representativo. El mismo figurará en el base roja como 09/CR/2010. En el expte. físico figurarán los n.º de expte. 09/C/2010 Y 09/CR/2010.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2023-03-14','Ana: Llamo a Mª José Polo, TS SSASB de Zarza de Granadilla (664 018 209): Me informa de que ayer se pusieron en contacto tanto el hijo como el exmarido de Florencia. Del hijo no había vuelto a saber nada desde que se fue del pueblo hace entorno a dos años. Dudan que haya cambiado, considera que ninguno de los dos están bien. Le preguntaron dónde estaba Florencia, pero no les facilitó la información. ···· No le parece mal permitir una visita supervisada y en función de cómo vaya autorizar que siga visitándola o todo lo contrario. ··························· Llamo a Marta Custodio (660 858 095 nº personal / 927 51 72 02 Oficina): Acordamos darle una oportunidad, podrá realizar una visita supervisada, no conocemos el interés real ni si es legítimo. ········ En el momento que su visita perjudique mínimamente a Florencia, se prohibirán las mismas. ···································································································································································································· Correo de Marta Custodio (mcustodiob24@hotmail.com): "Hola de nuevo, ya he hablado con el hijo y en principio le había extrañado que tuviera que ser supervisada pero hemos quedado en que me volverá a llamar cuando se sienta preparado. Ahora sí, me ha preguntado por cómo se encuentra su madre y su abuela. Le ha gustado saber que ambas están juntas. Ya si viene te cuento más,"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2023-03-13','Ana: Correo de Marta Custodio, TS de CRM Los Molinos de Montehermoso (mcustodiob24@hotmail.com): "Me pongo en contacto con ustedes para hacerles saber el hijo de Florencia Simón Martín. Este chico (Marco Antonio Andrade Simón) me ha manifestado su necesidad de ver a su madre pero previamente quería saber cómo proceder en estos casos y si está autorizada dicha visita."','2');
