insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='NUÑEZ'and apellido2='NAJARRO'),'2023-03-13','Maite: Maribel Rivera, directora de la residencia de INCLUSIVES, ha llamado para informar sobre el ingreso de Antonio. Será el próximo jueves 16 de febrero. Mañana martes, irá con su profesor del colegio y algunos compañeros para conocer el centro. Tendrán una reunión con los padres de Antonio para informarles de todo lo relacionado con su estancia en la residencia. También les dirán que va a cambiar el régimen de salidas a domicilio de Antonio; cuando va a casa de los padres, Antonio y su hermana Carla ( está en el centro de menores Pedro de Valdivia de Villanueva)duermen en la misma habitación, y esto empieza a ser un problema dada la situación de efervescencia sexual de Antonio. de momento van a plantear que los padres lo visiten en Villanueva. He contactado con Adela psicóloga del programa de familia de Zurbarán (682665200) para informarla sobre la decisión respecto a las visitas de Antonio al domicilio familiar.','2');
