insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-03-14','Ana: Envío correo-e a Julio, Aux. Adtvo. CTAEx: "Cuando puedas, envía porfa esta COMUNICACIÓN DE VARIACIONES, relativa a JULIA MORÓN HERNÁNDEZ, por registro al SERVICIO DE PRESTACIONES SOCIALES, Dirección Gral. De Servicios Sociales, Infancia y Familias. En la última página, debajo de todo viene el número de buzón." ······················································································································································································································· Subo al portafirmas digital la SOLICITUD DE PFHC para la firma del D-Gerente. ······································· Envío a REGISTRO (oac.merida.san@juntaex.es): "En representación de JULIA MORÓN HERNÁNDEZ, cuyo cargo ostenta la Comisión Tutelar de Adultos, adjunto: - Solicitud de Prestación Familiar por Hijo a Cargo - Alta de Terceros Para remitir por registro a la DIRECCIÓN PROVINCIAL DEL INSS de Cáceres" ····················· Justificante de REGISTRO en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-03-14','Ana: Llamada de Mª del Sol Tafur, ESM y E.C.A.- La Cumbre (54509 // mariasoledad.tafur@salud-juntaex.es): Ella no quiere salir de su domicilio, pero la casa cada vez está en peores condiciones. ······· Desde los SSASB le han buscado plaza residencial en un centro del entorno. ····· El Psiquiatra dice que no hay criterio para ingreso en UME, pues no ha habido los ingresos necesarios previos en UHB. ····· Han conseguido que no beba alcohol, bebe cerveza sin. ·········· Me facilita el contacto de: Montaña, TS de SSASB La Cumbre (621 24 72 49) y Guadalupe, Alcaldesa, es también TS y se implica mucho. ······································································································································································································ Llamo a Montaña, TS de SSASB La Cumbre (621 24 72 49 / ssasbmancomunidadtrujillo@gmail.com)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2023-03-15','Ana: Una vez recibido el Cdo. de Discapacidad de Mª Teresa, se lo envío a Ángel, A. Jurídico, para incluirlo en la Declaración del Impuesto de Sucesiones. ·································· *Grado Discapacidad Reconocido 65%.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-01-18','Ana: Recibimos respuesta del INSS con información sobre la PENSIÓN DE JUBILACIÓN = 761,21 € X 14 pagas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2023-03-15','Ana: correo de Ángel, A. Jurídico, con respecto a mi consulta: "Con relación a Mateo Ruano Moreno no he vuelto a tener noticias, he perdido la cuenta de la cantidad de llamadas y correos que he realizado al habilitado de clases pasivas (Juan Gómez-Vascuniana). Dar con este hombre es casi imposible, nunca está. Cuando lo conseguí, ya le hice saber que por la Audiencia Provincial de Cartagena, dictó diligencia de ordenación en la que se decía literalmente que no existe orden alguna a la habilitación de clases pasivas para la retención. Hoy le he vuelto a llamar, no está, llega más tarde… Lo intento después de nuevo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-03-15','miguel, envío email a Ana y Maite, tras la conversación con la coordinadora del equipo de salud mental de la UHB Dra Mª José Gomez del Castillo, extensión 54606: Buenos días, me ha llamado la Coordinadora del equipo de salud mental del centro donde está el tutelado, Doctora Mª José Gomez del Castillo, extensión 54606, para comunicarnos que van a hacer una subcomisión y me ha pedido los datos de quién de la Ctaex asistirá, así que le he dado vuestros dos emails, para que os envíe la citación que será aproximadamente en 1 semana seguramente. En dicha subcomisión se valorará en cuál UME o centro se puede proponer para su ingreso al tutelado conforme ha resuelto el juzgado nº2 de Cáceres (que instamos desde la Ctaex y que os adjunto) Cuando tengáis el acta de la reunión de la subcomisión, con lo que resuelvan tendréis que enviármelo para remitírselo a la abogada para proponerle al Ministerio Fiscal (tal como ha pedido) la permuta de la pena de cárcel que pueda haber (del procedimiento de agresión sexual que estaba conociendo el Jzdo nº6 de Cáceres y que actualmente se está ya tramitando en la Audiencia Provincial de Cáceres, que es el competente para resolver)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-03-15','Ángel, Llamo hoy al Juzgado de Primera Instancia e Instrucción, nº 4, de Badajoz (924284255), en relación con el internamiento involuntario. El procedimiento es el número 1040/22. No han fijado señalamiento, debido a la huelga de los LAJ.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-03-15','Ana: en relación al correo de Julia Durán, TS Hogar Peña del Cura, envío correo a la secc. ecca.: "VENTURA GÓMEZ GARCÍA está pasando unos días en el Balneario de Baños de Montemayor, porque le concedieron el PROGRAMA DE BALNEARIOTERAPIA del IMSERSO que solicitamos, pero como aquí no enviaron la resolución ni nada de nada, no lo sabíamos… ahora, según me comunica la TS del Hogar Peña del Cura, le están reclamando el abono de la parte que le corresponda (tiene un copago). Tampoco sé cuánto le corresponde pagar… ¿Podríais por favor poneros en contacto con el Balneario para consultarlo y abonar lo que corresponda? Os paso los datos de contacto: 927 488 302/ info@balneariomontemayor.com / Avda. de las Termas, 51 10750 Baños de Montemayor / 632 36 91 18" ···································································································································································································· Guardo en el expdte. digital y remito a los A. Jurídicos, para la revisión de las Medidas Judiciales de Apoyo, el Informe Social del Servicio de Ayuda a Domicilio del IMAS, remitido por Guadalupe Cortés Terradillos, TS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-03-15','-Email desde el centro : Buenas Amalia. Aunque imagino que ya estarás informada, te escribo para comentarte cómo ha ido la citación de Juanjo Murillo en el día de hoy en el juzgado de familia para la revisión de sus medidas de apoyo. Tanto el abogado de Comisión Tutelar como fiscalía del ministerio fiscal consideran que Juanjo debe tener asignada una curatela asistencial que le proteja en los ámbitos de lo patrimonial, administrativo y de salud. Quedamos a la espera de la resolución del juez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-03-15','Ana: En relación al correo de Alberto en el que especifica una evolución negativa en el saldo de Flora y que es necesario recortar gastos, respondo con copia a Maite, Jefa Secc.: "Hemos estado viendo este expediente Maite y yo. Habrá que tratar todos los puntos que planteas en la reunión de mañana. No obstante, varias aclaraciones: - La Ayuda a Domicilio la necesita, pues en el CRR no prestan la atención que requiere para sus higiene/aseo personal principalmente. (En teoría en este centro deben ser autónomas para las Actividades Básicas de la Vida Diaria) - Ya tiene solicitada, por Dependencia, plaza pública en Residencia de Mayores, para el cambio de recurso. **Nos obstante, sería conveniente que ampliara las zonas o centros, pues sólo tiene pedido 2 y así es más difícil que le concedan plaza. - Según la sentencia, se trata de una incapacitación parcial, una tutela para regir sus bienes/patrimonio solamente. Por tanto, todas las gestiones con respecto a ese tipo de cuestiones tiene que hacerlos ella misma, con el apoyo si lo requiere, de las profesionales del recurso en el que reside. Si no se pueden asumir todos los gastos, mañana habrá que plantearles al centro en cuáles de ellos se puede recortar, según tú lo planteas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-03-13','TERESA Comunicaros que el viernes, Aitor y Mireia, se fueron a Badajoz, ella a casa de su abuela y Aitor a un centro de transeúntes de Caritas. el trámite lo realizó Caritas. No trabajamos el viernes por eso no os hemos podido avisar antes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-03-13','TERESA Se contacta con Aitor a través del teléfono de Mireia para coordinar la retirada de efectivo para la gestión de renovación del DNI (la semana anterior el programa de familias de Trujillo informa que no han retirado el efectivo autorizado para la gestión, también informa este servicio que no acudió al juicio para el que estaba citado como testigo). En conversación, Aitor explica que ya no está en Trujillo porque les han echado de la casa que estaban ocupando, actualmente según explica se encuentra en en el Centro de emergencia Social de Cáritas de Cáceres, concretamente en uno de reciente apertura (según se averigua después) en la calle Ríos Verdes, ubicada en casco antiguo de la ciudad. Se le transmite que en ese caso se cancelará la cita para la renovación del DNI a la espera de recibir indicaciones de la CTAEX y a la espera también de tener una dirección concreta para poder realizar el DNI. Él explica que lo necesita porque el anterior se lo dejó en Garrovillas (además de estar caducado recientemente), y se lo ha pedido la policía en varias ocasiones. No sabemos como proceder, porque ahora están en Cáceres, no sabemos por cuanto tiempo, si es razonable pedirle una nueva cita para renovación de DNI, sin tener dirección que poner.. es que no sabemos como proceder. Manifiesta también la necesidad de poder alquilar una vivienda y disponer de dinero en efectivo para cubrir sus necesidades, solicita que se le transmita a la comisión tutelar la urgencia de la necesidad de poder disponer de dinero en efectivo. Estamos otra vez, en la casilla, de salida, en una nueva ubicación. De forma paralela e independiente se recibe llamada de Felisa donde explica agobiada que no sabe qué hacer con las cosas que su hijo y Mireia se dejaron en su casa, explica que ellos le han dicho que debe entregarles la tv pero por el contrario la que ella tenía ha desaparecido de la vivienda, por lo que se la recomienda que no la entregue puesto que la suya no está, ella explica que Ana le ha dicho lo mismo por lo que se le insiste en esa idea, con respecto al resto de pertenencias se le recomienda que las guarde hasta que se encuentre una forma segura de entregárselas o se tome alguna decisión al respecto.','2');
