insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2023-03-07','REVISIÓN MEDIDAS DE APOYO Con f/ 07/03/2023 se procede a aceptar el cargo de Curador Representativo. El mismo figurará en el base roja como 09/CR/2010. En el expte. físico figurarán los n.º de expte. 09/C/2010 Y 09/CR/2010.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='GATO'and apellido2='LOZANO'),'2023-03-10','REVISIÓN MEDIDAS DE APOYO Con f/ 10/03/2023 se procede a aceptar el cargo de Curador Representativo. El mismo figurará en el base roja como 21/CR/1998. En el expte. físico figurarán los n.º de expte. 21/T/1998 Y 21/CR/1998.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-03-15','miguel,email de Maite: Hola compis, Respecto a lo que hemos hablado de la sentencia de Flora ( incapacitación parcial y tutela) ¿ podemos pedir la revisión de la sentencia ya, y así lo aclaramos?. **************************************************** contestación de Angel: Si nos urge podemos proponer la revisión nosotros y enviárselo a Abogacía para que lo presente en el Juzgado. Id elaborando un Informe Social y Económico, con una propuesta sobre las medidas de apoyo que precisa Flora. Podéis utilizar, si queréis, los modelos que utiliza Fiscalía *********************************************** mi contestación a la parte social y económica: Buenos días, en mi opinión debemos esperar a solicitar la revisión de sentencia. Parte económica: veo que en la rendición final hay una cuenta con más de 16.000€ hay que saber qué parte era de Modesta y cuál de Flora porque hay que separarlo para la adjudicación de la herencia. Necesitaré de sus dos cuentas bancarias que aparece en la rendición final: certificado de saldo a fecha de fallecimiento de Modesta y movimientos de la cuenta del último año a fallecer el 26-12-2020. Por tanto necesito movimientos de cuenta de 26-12-2019 y 26-12-2020. Acabo de lograr hablar con su hermana Modesta. Me confirma, son hijas del primer matrimonio con Don Pedro las 3 hermanas, y su padre falleció cree el 20-1-1967. Comenta que no había relación desde hacía más de 30 años, entiendo con su madre, porque con su hermana sí que hablan. Se fueron con 15 y 16 años de su casa y me comenta que tiene ya 60 años. Cuando habla con Flora, dice que nuestra tutelada Flora piensa que la vivienda de su madre está a a su nombre, y que ellas no quieren problemas. Ya le he comentado que no es cierto porque en catastro ella no tiene nada y su madre Modesta tenía el 100% del pleno dominio. Parece que la idea de Flora es donar algún día la casa (entiendo que inviable porque veo en el expediente problemas en la vivienda de diciembre 2022…y al fin y al cabo ella vivirá siempre en residencias) He quedado en reenviarle la documentación que me ha pedido la notaria de Plasencia, donde estamos empezando a montar el expediente para firmar la declaración de herederos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-03-15','miguel, envío a Modesta, email: modes.gutierrez@yahoo.es, tlfno 673972619(hermana de la tutelada) email de lo que pide la notaria de Plasencia (para la herencia de su madre): Buenas tardes, conforme conversación telefónica adjunto el email de la notaria y oficial que va a tramitar la declaración de herederos y posterior herencia de su fallecida madre. Como sabe la Junta de Extremadura, a través de la Comisión Tutelar de Adultos ejerció el cargo de tutor de su fallecida madre y actualmente ejerce el cargo de tutor de su hermana Flora. Esta Comisión está compuesta por un Gabinete Técnico de tres partes: una social, otra económica y otra jurídica con el que se ejerce el cargo de tutores o curadores (con la actual ley 8/21 curadores representativos o asistenciales) conforme dictan las sentencias judiciales de nombramiento, motivo por el cual desde esta Comisión se representa a su hermana Flora en la tramitación de esta Herencia y si fuera preciso posteriormente en una venta. Para ambos trámites desde esta Comisión tendremos que solicitar la correspondiente autorización judicial conforme impone el artículo 287 del Código Civil. Quedo a su disposición para cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-03-15','Ana: Recibo correo de Aurora, TS SSASB La Cumbre. ··················· Envío correo a Maite, Jefa CTAEx y Soraya Masa, Jefa Ud. PP.AA.: "Os reenvío correo de la compañera del SSASB de La Cumbre, en relación a Mª GUADALUPE GIL CABELLO. Este expediente, como sabéis, por fin se a podido aceptar el día 1 de marzo. Sí que estoy de acuerdo en que habría que visitarla, pero también estoy de acuerdo en que la mejor opción sería que pasara primero por UME para estabilización, pues según la compañera de Salud Mental está descompensada y no tiene conciencia de enfermedad. Además, es posible que así, después, acepte mejor el ingreso en otro recurso. Cuando queráis lo vemos, porque en el informe no especifica gran parte de la problemática que presenta (desnutrición, grandes problemas bucodentales, nula conciencia de enfermedad, ingesta de pastillas que no tiene prescritas, pide dinero y pastillas por las casas, la vivienda no reúne condiciones de habitabilidad, se está alimentando con potitos...) pero ella dice que está bien y de forma voluntaria no quiere ingresar. *Por cierto, no sé cómo plantean que abone 704€ de Piso Tutelado, si sus ingresos son 484,61€ de la PNC… Lo dicho, nos reunimos cuando queráis y lo vemos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-03-15','Ana: Reenvío a Miguel, Asesor Jurídico, INFORME DEL SERVICIO DE PSIQUIATRÍA - UHB, para que lo remita a la abogada. ··········· Al final del informe, la Psiquiatra expone en el plan: "Se recomienda continuar su ingreso en centro adecuado a su patología".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-03-16','Ana: Subo al portafirmas digital autorización de salida para Semana Santa a Miajadas del 2 - 9 de abril. ············ Pido confirmación de viabilidad a la sección ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2023-03-16','Ángel, En relación con la herencia del hermano y venta de inmueble, hablo con Susana Orts (susanaorts@gmail.com, 609280291), para que haga tasación de vivienda. Le facilito el teléfono de Clementina (608139784), cuñada de la hermana de Iluminada, porque tiene las llaves de la vivienda, para que le facilite el acceso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-03-16','miguel, recibo de Ana el informe de psiquiatra que estabamos esperando. Reenvío ese informe de la psiquiatra junto al auto de internamiento involuntario (no firme) a la abogada Carmen Lucas, carmen.lucas@lucasabogados.com mlucasduran@icac.es: Buenos días Carmen, nos remite la psiquiatra este informe para que te lo remitamos. Comentarte que según conversación telefónica que tuve ayer con la con la coordinadora del equipo de salud mental de la UHB Dra Mª José Gomez del Castillo, me indicó que van a hacer una reunión, “subcomisión de especialistas” que está organizando y será en pocos días. Esa reunión será para dictaminar a qué centro recomiendan su ingreso. Una vez que sea esa reunión, el acta que de allí salga nos la enviarán y te la enviaremos para la puedas presentar en el procedimiento de Saturnino. Dicha reunión es consecuencia del auto dictado por el juzgado nº2 de Cáceres, que adjunto, donde estiman la petición de esta Comisión de internamiento involuntario de Saturnino en la UME (Unidad de Media Estancia). Te adjunto además del informe dictado por la psiquiatra, el auto de internamiento involuntario del juzgado nº2 de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-03-16','miguel, recibo de Ana el informe de psiquiatra que estabamos esperando. Reenvío ese informe de la psiquiatra junto al auto de internamiento involuntario (no firme) a la abogada Carmen Lucas, carmen.lucas@lucasabogados.com mlucasduran@icac.es: Buenos días Carmen, nos remite la psiquiatra este informe para que te lo remitamos. Comentarte que según conversación telefónica que tuve ayer con la con la coordinadora del equipo de salud mental de la UHB Dra Mª José Gomez del Castillo, me indicó que van a hacer una reunión, “subcomisión de especialistas” que está organizando y será en pocos días. Esa reunión será para dictaminar a qué centro recomiendan su ingreso. Una vez que sea esa reunión, el acta que de allí salga nos la enviarán y te la enviaremos para la puedas presentar en el procedimiento de Saturnino. Dicha reunión es consecuencia del auto dictado por el juzgado nº2 de Cáceres, que adjunto, donde estiman la petición de esta Comisión de internamiento involuntario de Saturnino en la UME (Unidad de Media Estancia). Te adjunto además del informe dictado por la psiquiatra, el auto de internamiento involuntario del juzgado nº2 de Cáceres.','2');
