insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-03-16','miguel, tras la vista para comparecencia de la tutelada por el procedimiento de internamiento involuntario envío email a la parte social: Buenos días, acabo de asistir videoconferencia a la comparecencia de Justa, donde no me han dado paso de palabra con lo que no he podido explicar nada. Ella dice que ha pasado un bache pero que ya está bien, y lo que quiere es que la den un piso social y disponer de sus 750€ que dice que cobra de pensión (en la base roja aparecen 640,96€) A ver qué resuelve el juzgado nº1 de Montijo (recordad que estaba desde julio del año pasado en el jzdo nº2 de Montijo, a donde había llegado desde el jzdo Decano)…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2023-03-16','Ana: Recibimos RESOLUCIÓN DEL GRADO DE DEPENDENCIA. Le reconocen GRADO III.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-03-15','Ana: Correo de Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es) a Maite, Jefa Secc. y a mí: "Os escribo porque la Psicóloga de la unidad, me pide que os comunique, que en distintas entrevistas con Aarón Rosado Alarcón, éste ha manifestado su deseo de no volver a Asindi, argumentando que lo acosaban y que permanecía casi todo el día solo en su habitación.... También observamos en su expediente, que en experiencias previas en Pisos Supervisados su funcionamiento ha sido adecuado" ····························································································································································································· Respuesta de Maite: "Aarón permanecía solo en su habitación debido a sus continuas alteraciones de conducta, dado que agredía a profesionales y compañeros. En cuanto a la estancia en pisos , él estuvo en pisos de menores, a los que no puede volver. En cualquier caso, la posibilidad de que Aarón vuelva a ASINDI o cambie de recurso ( sería siempre recurso residencial ya que no tiene perfil para Vivienda Tutelada) se valoraría desde la Unidad de Programas Asistenciales."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-03-16','Ángel, Envío correo a compañeros: "Buenas, Me ha llamado la hermana de Manuel Contador (629785581), preocupada porque su hermano Manuel, cuando sale del CRR de Olivenza los fines de semana, va a Badajoz, antes se quedaba en un hotel, pero para ahorra gastos, ahora se queda en el piso que fuera de los padres, que según ella se encuentra en muy mal estado, desde que Manuel tiró por la ventana muebles, no hay cocina, el agua potable solo sale del baño… Al parecer antes se quedaba en la casa de la hermana, pero por enfermedad, ahora no puede hacerse cargo. El caso es que nos traslada su preocupación, por si pudiéramos evitar que Manuel se quedara en ese piso. Le he pedido que nos envíe correo y fotos del estado de la casa. ¿Sabéis algo? Gracias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-03-13','Ana: llamada de Sonia Bernabé, ASINDI (927 39 01 93): a Felisa irán a visitarla el día 27 de marzo del Proyecto Mi Casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-03-15','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Informar sobre el alta en la UHB de Cáceres de la persona usuaria Consuelo Nevado Pacheco en fecha 15.03.2023. Seguiremos informando de la evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2023-03-15','Ana: Correo de Sheila Rodríguez, Directora del CRR-CC (crr@grupociudadjardin.com): A continuación, indicamos algunas de las incidencias recogidas en estos días: 13/03/2023: Juan Mario llega al CRR a las 17:00. Entrega 43€, aunque en un albaran que trae, indica que de la UME sale con 85,40€. Se observa que tiene una conversación con un discurso incoherente, mezclando temas y sin finalizar las frases quedando estas a medias. En la cena, da 329 de glucosa. Se pone las unidades correspondientes de Novorapid. Al hacer la ronda en turno de noche, se encontraba pintando en la habitación, se le indica que lo deje y que se meta en la cama. Escuchamos trastear durante toda la noche en su habitación. Se ducha a las 5:00 horas. Baja a las 5:45 horas, se le recuerdan normas y horarios. 14/03/2023: Por la mañana, niveles de glucosa elevados, se pone insulina rápida. Sigue con conversaciones incoherentes. Valores altos de glucemia antes de la comida. Durante la cena conversación incoherente y mezclando diferentes temas sin conexión Por otro lado, Consuelo refiere en el día de ayer que "a Juan Mario le ha tocado dinero en las maquinas". Os iremos informando de su evolución tras el alta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-03-16','Ana: Subo al portafirmas digital Solicitud de Informe Médico por empeoramiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-03-16','miguel, envío email a la notaria de Plasencia mplgonzalez@despacho.notariado.org Buenos días, hay 3 herederas (hijas de la fallecida Modesta Garcia Piñero), una es nuestra tutelada Flora Gutierrez Garcia, las otras dos son Modesta y Juana Mª Gutierrez García, quienes viven en Barcelona. Los datos de contacto de Modesta (hija) son modes.gutierrez@yahoo.es, tlfno 673972619 He hablado con Modesta para informarla y no tienen documentación porque hace muchos años que no mantenían contacto con su madre. Adjunto la rendición final que se remitió desde la Comisión al juzgado, donde está la testamentaría, nº de cuentas e identificación del inmueble. Adjunto también la sentencia de incapacitación y nombramiento a la Comisión Tutelar del cargo de tutor de la hija Flora Gutierrez Garcia. No vamos a lograr hacernos con el libro de familia, por lo que no sé si o bien las hijas de Barcelona o bien online podrías recabar los certificados de nacimiento, matrimonio, defunción que necesites del registro civil. La fallecida Modesta Garcia Piñero se casó dos veces. Del primero quedó viuda de Don Pedro Gutierrez Brujera, padre de las tres herederas, que falleció el 20-1-1967 (según me dice su hija Modesta) Del segundo matrimonio con Don Juan Rincón Romano se casó en 1977 y se divorció en 1987 (adjunto certificado de partida de bautismo de la fallecida y certificado de matrimonio(tengo el original de Don Juan Rincón Romano y Doña Modesta Garcia Piñero del Registro Civil de Granollers) Por otra parte Rosa del Centro Socio Sanitario, me ha confirmado que tendría disponible dos testigos para firmar la declaración de herederos. Cualquier duda quedo a vuestra disposición.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-03-16','-Amalia . Alejandro ingresó ayer en la UHDAC , el psiquiatra no lo considera un recurso oportuno. Hago gestiones económicas que queda fijada así : AMALIA: EN CUANTO SE MODIFIQUE DE NUEVO LA SITUACIÓN NOS AVISAS. OSCAR: AUTORIZAMOS 150 €/MES GASTOS DE BOLSILLO ---HABLAS CON CENTRO Y QUE DECIDAN SI PREFIEREN AUTORIZACIÓN GENERAL O UNA PARTICULAR PARA PODER SACAR 150 €/MES DE GASTOS BOLSILLO (DE CUALQUIERA DE LAS MANERAS EL LÍMITE SON LOS 150 €/MES) OSCAR: MODIFICAMOS "YA" LA TRANSFERENCIA PERMANENTE A MADRE ALEJANDRO QUE PASARÁ A SER DE 500 €/MES, HASTA QUE SE MODIFIQUE DE NUEVO LA SITUACIÓN (NOS AVISARÁ AMALIA).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-03-17','Amalia , Futuex remite informe sobre el acompañamiento a UHDAC GESTIONES REALIZADAS: Tal como estaba programado para el miércoles 15 de marzo de 2023, se procede al acompañamiento de Alejandro Núñez Bono a la UHDAC en Plasencia, en taxi gestionado por este equipo de apoyo social comunitario de Badajoz, con visto bueno de la comisión tutelar. Cuando llegamos al domicilio, nos informa su madre que ha pasado la noche con un amigo, pero que ya bien de regreso. Cuando llega Alejandro, nos cuenta que viene en autobús desde Villanueva del Fresno, que ha pasado la noche en el domicilio de su novia, una chica que ha conocido vía Instagram el 6 de este mismo mes. Que está muy cansado ya que no ha dormido nada y espera que , al llegar al centro, le permitan acostarse. En todo el trayecto va tranquilo, sin hablar nada, tan solo nos dice que se despide de su casa por mucho tiempo. En la UHDAC nos recibe Estrella, trabajadora social, así como Mª Paz Casado, psicóloga clínica, doctor Pizarro psiquiatra en la UHDAC y UME y la terapeuta ocupacional. Lo primero que nos comunican es que, Alejandro ya fue rechazado dos veces por este centro, pues ellos entienden que no es perfil adecuado, pues es discapacidad limite y que tiene más autonomía que el resto de pacientes que está en la unidad. Es la idea que repiten, una vez que entra Alejandro en la sala de reunión y le realizan varias preguntas: El psiquiatra entiende que sufre síndrome amotivacional, debido al consumo de cannabis, de ahí su inactividad, apatía y nula colaboración. Pero que sabe que a una comunidad terapéutica no sería lo más adecuado, lo suyo en la UME. Le comentamos si, al rechazarle, las dos veces que ha sucedido, no han recomendado esta unidad, algo que no se ha hecho, tan solo que no daba perfil en ningún recurso. Le explicamos que, desde este equipo de apoyo social comunitario, que ha realizado sus apoyos, no hemos puesto nombre al recurso que debe ir, pero si recoger la información de que en su domicilio no existe voluntad de cambio, ni tampoco se dan las circunstancias para ello, ya que su madre no le puede ayudar en este proceso. Terminan por reconocer la necesidad de poner orden en su vida, dentro de un entorno muy estructurado y con apoyo diario y medidas estrictas , como mínimo al inicio de su estancia, aunque se encuentre con otros pacientes más vulnerables que él. Nos hacen entrega de tres documentos para hacer llegar a la comisión tutelar que se adjunta con esta nota: Registro de Pertenencias del paciente al entrar en la unidad. Autorización Expresa (firmar como tutores y devolver a la unidad) Compromiso Formal (firmar como tutores y devolver a la unidad) Se adjunta también, CITACIÓN POR INCIDENCIA, del juzgado de lo penal nº 1 de Badajoz, por motivo de incumplimiento de pena impuesta. Solo estuvo dos días realizando el servicio a la comunidad. Está citado el 28 de marzo a las 10:00 horas. Para informar que se encuentra ya en la UHDAC de Plasencia. *adjuntamos factura de taxi del traslado a Plasencia, con nº de cuenta para abonar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2023-03-17','Ana: Correo de Ana, Administraciones Parra (admon.parra@gmail.com) al ctutelar@: "Estamos intentando ponernos en contacto con usted en referencia a la humedad del techo que se encuentra en la vivienda 3ºD. Informarle que el seguro comunitario ha rehusado, por lo que vamos a solicitar presupuestos de reparación. Necesitaríamos que nos faciliten que días tienen disponible para poder coordinar los trabajos. Quedamos a la espera de su respuesta." ··························· Mi respuesta: "Supongo que lo que envía se refiere a la vivienda de Mª Jesús Criado Rodríguez, por favor, confírmenos que es así. En tal caso, antes de proceder a las obras, deben remitirnos presupuesto a nombre le la propia María Jesús. Y una vez dado el visto bueno por el Jefe de la Secc. Económica, podrán concertar fecha y coordinar los trabajos con la Educadora del Programa de Apoyo Comunitario, seguramente sea la misma persona que se ha encargado de este tipo de cuestiones con anterioridad. Procedo a contactar con la coordinadora de dicho programa para que se pongan en contacto con ustedes." ·································································································································································································· Reenvío el correo de la Administradora a Toni-Futuex, para que contacten con ella de cara a las reparaciones. ·············································· Nuevo correo de de Ana, Administraciones Parra (admon.parra@gmail.com) al ctutelar@: "Efectivamente, nos referimos a la vivienda de Mª Jesús Criado Rodríguez. Necesitamos que nos den acceso a la vivienda para que la empresa pueda ir a verlo y de esa manera mandarnos el presupuesto. Una vez tengamos el presupuesto se lo haremos llegar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-03-17','Ana: Envío correo a Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "Adjunto la Autorización de salida en Semana Santa a su pueblo. Me preguntan desde la Secc. Económica si lo hacen mediante transferencia o autorización de retirada de efectivo. Por favor, indícalo directamente al ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-03-17','Ana: Llamada de José Manuel, el miércoles se cayó en las escaleras. Le llevaron al HUC, le hicieron radiografía y le pusieron escayola en el brazo izquierdo desde el codo hasta la mano. Tenía que llevarla 10 días, tiene un traumatismo. Pero se la quitó ayer por la tarde. ·········· Ahora tiene la mano hinchada. ···· Ha ido a la MAP. Le han vendado desde el codo hasta la mano. ············ Tiene que ir el jueves a las 9:30 al C. Salud, a que le vean. ········· Le han recetado ibuprofeno para. ··························· Quiere venir para hablar con Alberto, Jefe Secc. Ecca, y conmigo sobre dinero, autorización para ropa y para comprar productos de limpieza. ······· Y sobre que quiere irse a una casa de alquiler. ···· La cita tendrá que ser M, J o V. ······················ Recuerda que quiere hacer testamento. Le indico que primero tiene que decirnos a qué Notaría quiere ir, para que los compañeros A. Jurídicos se pongan en contacto con la misma. ······························· En cuanto al Banco, le recuerdo que como vuelva a haber alguna incidencia por su parte, por pequeña que sea, le van a cancelar la cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-03-17','Ana: Llamo a Guadalupe Cortés Terradillos, TS, SAD-IMAS-CC (927 21 23 35, Ext. 4422), en relación a la solicitud del Serv. de TAD (Teleasistencia). El de carácter municipal es gratuito y en principio es el que planteamos solicitar. *Si no se lo concedieran se podría solicitar a través de la Ley de Dependencia, pues tiene Grado I. ············· *No obstante, cuando habló con Julia, acordaron que ésta se encargaría. ······································································· Llamo a Julia Durán, TS del Centro de Mayores - "Hogar Peña del Cura" de CC (22032): pero no obtengo respuesta.','2');
