insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-01-17','Ana: Recibimos del INSS, NOTIFICACIÓN con información actualizada de las pensiones que percibe Isabel: P. Orfandad: 239,50€ y PFHC: 453,30€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-03-16','Ana: Recibimos Informe Social IMAS-CC. LO emite Mª Begoña Majado, TS. En la VALORACIÓN Y PROPUESTA, dice textualmente: "Debido al grave riesgo por la situación de salud física y psicológica, a la soledad y a las barreras arquitectónicas en la vivienda, considero que el recurso más idóneo sería el ingreso en un CRR..." "...La adjudicación de viviendas sociales en Aldea Moret, no sería el recurso idóneo, debido a su situación psicopatológica de José Manuel"','2');
