insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-03-17','miguel, me llama el abogado de la herencia Rafael Santos, rsantosrex@pajueloabogados.com; 924-242814 y le aclaro que sigo pendiente que el notario de Coria me de fecha para firmar la ratificación. Le reenvío el último email que envié a la notaria de Coria','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-16','Ana: Llamada de Puerto, TS del SSASB de la Mancomunidad Valle del Alagón (927 122 413 // 927 44 82 50): le han concedido a Enrique el SAD Municipal - 2h/semana que comenzarán a prestarle la semana que viene. ··················· En cuanto al Servicio de Teleasistencia Domiciliaria, se valorará si se solicita también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-03-20','Ana: Llamada de Anabel, TS SSASB Miajadas (927 34 70 00 / Directo: 927 90 12 38): Pregunta por el procedimiento de solicitud de internamiento involuntario de Joaquina. *Informa también que la semana pasada tenía cita programada en el ESM-CC y no acudió a la misma. ··········· Le ha salido una úlcera en la pierna que le dificulta más la deambulación. ···· Está consiguiendo dinero de algún sitio, pero no saben de dónde. ···· A Cáritas no acude. *Su salud se está deteriorando. ···································································································································································································· Envío mail a A. Jurídicos: "En relación a JOAQUINA MAYORAL PIZARRO, ¿cómo va el procedimiento? ¿Miguel, llegaste a enviar la solicitud? Me comunican desde los SSASB que la situación sigue igual o peor y que la semana pasada tenía cita de seguimiento en Salud Mental de Cáceres y no se presentó? Voy a pedir al Equipo de Salud Mental que nos lo comuniquen por escrito. Dime cuando puedas, pues la compañera de Servicios Sociales espera una respuesta." ···················· Respuesta de Miguel: "estamos a la espera de confirmar con el juzgado nº1 de Mérida si hay o no resolución en la revisión de medidas de apoyo que está conociendo. Caso de que no se haya dictado resolución de dicho procedimiento, solicitaría el internamiento involuntario, pero para eso primero tengo que saber si está o no finalizada la revisión de medidas y cuáles se han impuesto." ················ Nuevo correo de Miguel, A. Jurídico: "Buenos días, al declararse incompetente el juzgado de Mérida nº1, tendríamos que solicitar el internamiento involuntario al de Trujillo ya que el competente" ········································································································································ Envío a Julio, Aux. CTAEx, oficio para que remita por REGISTRO - SIREX, al ESM solicitando INFORME DE PSIQUIATRÍA relativo a la última consulta programada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-03-20','Ana: La Secc. ecca., da ok a los 300€ para manutención y gastos de bolsillo. Se hará mediante transferencia periódica a la madre, como se venía haciendo antes del ingreso. ··········· También se aprueba la compra de teléfono móvil y una retirada de 200€ a partir de mañana, pues este mes de marzo no ha sacado dinero. ················ *La factura del verano pasado, que vuelven a enviar, no se abonará. Ya se le explicó a la tienda en su día, y se le había preavisado en ocasiones anteriores que si volvían a enviar facturas de gastos no aprobados previamente no se iban a pagar. *Se lo comunico a todo a Julia y su madre. Y le planteo que pueden ir abonando la deuda generada con la tienda poco a poco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-03-20','Amalia> Recibo llamada de su hermana M. Jose , le médico, quiere comentar algo relacionado con su hermano pero no a la TS , si no a su representante legal o algún superior . Le paso tf. de Mayte . Escribe Angel el compañero , ha recibido correo de su hna. Isabel , le comunica que no está de acuerdo en que su hermano salga de fin de semana a su casa familiar . Reenvía fotos de la casa y no reúne condiciones de habitabilidad . Escribo a CRR para que nos informen de estas salidas , que no han comunicado . Las mismas se hacían esporádicamente a un hostal de Badajoz y lo coordinaba Leonor la anterior terapueta que ya no está en CRR . María , la psicóloga me pide que la llame para informarme.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-03-20','Ana: Remito correo a Sheila, Directora del CRR (crr@grupociudadjardin.com): "Adjunto remito la Solicitud de Informe Médico relativa a MARTÍN HERNÁNDEZ MIRANDA, firmado por su representante legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2023-03-20','Ana: Envío correo a Paz Boticario, TS Cruz Blanca (et-caceres@cruzblanca.org): "Buenos días, Paz, ¿qué tal estáis? Comunicaros que hemos recibido la resolución positiva de la solicitud de inclusión en el programa para pacientes con necesidades asistenciales especiales. • Alejandro Montero Vázquez • Antonio Tejada Fernández • Alberto Molano Iglesias Adjunto todas las resoluciones de la Dirección Gral. De Salud Mental."','2');
