insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-03-20','Ana: Tras conversación con Javier Monago, Jefe Secc. de PNC - Gerencia Territorial CC (javier.monago@salud-juntaex.es), le remito Comunicación de Variaciones de PNC que se envió la semana pasada por Registro a la D.G. de SS.SS., Infancia y Familia.','2');
