insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-03-16','Ana: Correo de Eva Álvarez, TS Plena Inclusión Montijo (trabajadorasocialco@plenainclusionmontijo.org): "Adrián Ortigosa va a hacer un curso de competencia digital, de INSERTA de la ONCE, que tiene una duración de 10 días. Es una formación becada, con 9,8€/día. Necesitamos el número de cuenta para el ingreso de esta beca."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-03-20','Ana: Facilito a Eva Álvarez, TS Plena Inclusión Montijo (trabajadorasocialco@plenainclusionmontijo.org) el nº de cuenta y pongo en copia a Amalia, comunicando a ambas que el seguimiento de Adrián, a partir de ahora, ya lo hará Amalia, pues Adrián lleva ya más de dos meses en los pisos sin ocurrir incidencia alguna.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-03-20','Ana: Correo del viernes de Pilar Márquez, TS de Valencia de Alcántara (trabajadorasocial@valenciadealcantara.es): "Me pongo en contacto con ustedes, tal y como me ha sugerido Gloria de la Fundación - FUTUEX, para hablarle de un asunto sobre el tutelado D. Julián Ramón Civantos de esta localidad. En navidades decidió ingresar en la Residencia de Mayores del grupo Asoma de Cedillo , y a día de hoy permanece en ella. D. Julián Ramón era usuario del Servicio de Ayuda a Domicilio dentro del convenio suscrito por el SEPAD y este Ayuntamiento, por 45 horas mensuales, el tiempo pasa y su decisión de continuar en el centro es firme, no queríamos notificar su baja sin antes hablarlo con la comisión tutelar, es por este razón que nos ponemos en contacto con ustedes, necesitamos que puedan aclararnos si procedemos a su baja , con el fin de que el Sepad pueda mandarnos a otros usuarios que permanecen en la lista de espera." ······························································· Mi respuesta: "Pues hablé con Mª José Acosta, la compañera de la Mancomunidad Sierra de San Pedro, a principios de febrero. A su vez me dijo que ya había hablado contigo. Puesto que, como tú también indicas, su decisión de continuar en la residencia era firme, a finales de febrero, al no haber habido cambios, envié a Dependencia por Registro SOLICITUD DE REVISIÓN PIA (cambio de recurso de SAD a SAR o vinculada al SAR) y di por hecho que ya os lo habrían comunicado al Ayuntamiento. Disculpa por no haber caído en comunicártelo a ti directamente. Espero que no decida volver a su casa, al menos no en un breve espacio de tiempo. Primero porque la casa, muy a nuestro pesar, aún no está acondicionada. A ver si desde la Comunidad de Propietarios consiguen que se lleven a cabo las obras lo antes posible. Y segundo, porque él está algo más deteriorado y estando tan bien adaptado a la Auxiliar y al servicio en sí sería una pena que regresara sin tener dicho apoyo. Por otra parte, en la Residencia tiene cubiertas todas sus necesidades de atención y no está tan solo, por lo que consideramos que a día de hoy es el mejor recurso para él. Así, pues, respondiendo a tu pregunta, podéis proceder a darle de baja en el SAD."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-03-20','Ana: Correo de Óscar, Secc. Ecca., a Estrella Durán, TS del CSS-Plas: "Están pagados los atrasos y la cuota domiciliada. Estamos intentando cambiar la domiciliación de las facturas de luz y gas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-03-21','Ana: Una vez recibido el Informe de Salud, Índice de Barthel e Historia clínica resumida, envío a Julio, CTAEx todo junto con la SOLICITUD DE REVISIÓN DE GRADO DE DE DEPENDENCIA, así como aceptación del cargo de tutor y demás documentos del representante legal, para que le de REGISTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-03-21','Ana: En relación a los correos de ayer de Arantxa, Directora de la residencia (), en relación a la visita al centro de un Inspector de Policía, respuesta de Ángel, A. Jurídico: "Si como dicen han echado a la persona que había en la casa, caso resuelto. Si la denuncia sigue su curso, ya nos darán traslado desde el Juzgado competente. En cuanto al Abogado que se han buscado las sobrinas, ya hablé con él y van a solicitar la remoción del cargo que ejercemos, para que se quede una de las sobrinas con la curatela. En ese caso, ya nos darán traslado desde el Juzgado para que contestemos a la demanda."','2');
