insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-20','Ana: Recibimos resolución aprobatoria del SAD Municipal. Guardada en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-21','Ana: Llamo a Puerto, TS del SSASB, al Ayto. Valdeobispo (927 45 61 83): Finalmente solicitaremos TAD a través de la Ley de Dependencia. ··················· Nº de Enrique: 662 567 832. Cumplimento la Solicitud de Dependencia y lo subo al portafirmas digital. ·············· Remito a Julio, Aux. Adtvo. CATEx, para registre en SIREX: "- Solicitud de valoración de Dependencia para activación PIA – Solicitud de Servicio de Teleasistencia - Testimonio de Aceptación del Cargo de Tutor - DNI Presidente CTAEx - Decreto Nombramiento de Director Gerente - Resolución Delegación de competencias" ······························································································································································································· Llamo a Enrique (662 56 78 32 – 617 19 60 70), en relación a las facturas que nos remite Futuex. No sabemos si la del fontanero se ha abonado ya. Y para pedirle el contacto de su hermano para que se le pueda abonar por transferencia. Pero no obtengo respuesta.','2');
