insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='MULERO'and apellido2='SALGUERO'),'2023-03-21','TERESA SOLCIITO AL CENTRO QUE GESTIONE LA BAJA DE LA LINEA DE TEFNO LLAMANDO AL 1470 YA QUE ESTA GESTION SOLO PUEDE HACERLA LA PERSONA TITUTULAR DE LA LINEA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-03-21','Ana: Recibimos Cdo. actualizado de P. Jubilación de Clases Pasivas (Guardado en el expte. digital). Puesto que no nos cuadra el importe, escribo a Miguel Cillán, Jefe Secc. de Control de Pensiones del INSS-CC (angel-miguel.cillan@seg-social.es): "Hemos recibido certificado actualizado de la Pensión de Jubilación de Clases Pasivas, relativo a D. Julián Ramón Civantos Fernández, cuyo cargo ostenta la CTAEx, adjunto el documento. Pero el importe del mismo (2.076,11 €) no nos cuadra con el ingreso mensual que se le realiza en cuenta: 1.490,34 €. No sabemos si hay algún error o si le están reteniendo dinero por algún concepto que desconozcamos. ¿Podrías por favor aclarárnoslo?" ···················· Llamo a Control de Pensiones: Miguel Cillán se ha jubilado. ······· Me facilitan nº de Clases Pasivas de Madrid (Feli: 911 906 905): No obtengo respuseta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-03-21','Ana: Correo de Pilar Martín (pilar.martinp@salud-juntaex.es): "Buenos días Ana, respecto de José Manuel Romero Mediavilla me he informado que la reunión de la Comisión para el ingreso en CRR es en la próxima semana. Por otra parte, la enfermera de nuestro ESM ha realizado una nota en la que informa de : un mayor deterioro físico en los últimos meses, dificultad para llevar a cabo las ABVD y refiere dificultad para moverse, deambular, pues siente que se asfixia, y también dificultad para subir y bajar escaleras. Además de desorganización en cuanto a las citas médicas, tratamientos médicos, hábitos nocivos para la salud en cuanto a la alimentación, autocuidado, ingesta de bebidas energéticas y cafeína. Te lo expongo casi tal cual pone en su nota. José Manuel acepta CRR o ayuda al alquiler, o vivienda social que no sea en Aldea Moret, pero se niega al ingreso en crónicos del sociosanitario. Lo de dependencia lo he dejado por el momento hasta nueva cita con su MAP, al no reflejar al entender de Virginia y al mío la situación actual. Ha solicitado nueva cita. Por cierto, me dice José Manuel que tiene varias órdenes clínicas pendientes de cita con neumólogo y traumatólogo (con el de digestivo ha tenido cita, pero parece ser se niega a hacerse la colonoscopia, aunque en su familia parece ser hay varios antecedentes). Le he remitido al SAU y a ser posible que le acompañe Virginia de FUTUEX. Bueno ya me dices. Procura llamarme hoy porfa." ····················· Llamo a Pilar Martín (54612): La nota de enfermería se la entregará a Virginia, Ed. Futuex para que nos lo haga llegar. *Seguramente no le van a admitir en el CRR. ············· En relación a las citas pendientes con especialistas, acudirá con Virginia al SAU, del hptal.','2');
