insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-03-22','Ana: Llamada de Ana Benavente, TS ESM-Plas.: Está con Carmen en su despacho. Quieren solicitar la Tarjeta de Trasporte gratuita, pero la tasa de la tarjeta son 6,75€. *Le indico que puede abonarlo con la asignación mensual o el extra anual (360 € / 900€). ·············· Me enviará la solicitud firmada por Carmen para que la firme también el D. Gerente. ··································· *Subo al portafirmas digital la Solicitud de Subvención 100% para el fomento de la movilidad en el transporte público.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-22','Ana: Conversación con Puerto, TS del SSASB Valdeobispo de la Mancomunidad Valle del Alagón (927 122 413): *Mañana comienzan a prestarle el SAD. La Aux., Raquel (cambian cada 6 meses) acudirá los M - J de 11:00 - 12:00 h. ·································· En cuanto a las facturas, me confirma que la factura de fontanería ya la ha abonado Quique. ············ La de los electrodomésticos, que abonó su hermano Ricardo, no lo sabe. ········· Hoy no está en Valdeobispo y no tiene los datos de contacto. Mañana me lo enviará en un mail. ···················· Me informa que Quique tiene 4 hermanos: Ricardo "Richard", Radiólogo en el HVP-Plas., vive en Arenas de San Pedro, Mamen, vive en Tenerife, Nacho, que vive en Francia y Miguel Ángel, en EE.UU. ············· Su padre ere el Médico del pueblo. Ahora está jubilado y vive en CC. Nunca ha querido saber nada de su hijo. Su madre, era la Enfermera. ············· La casa en que vive Quique se la hizo su abuelo, el único que se preocupó siempre por él. La construyó en la misma finca de la casa de la madre, pero esta casa ahora la tiene separada por una cancela y cerrada por un candado para que Quique no acceda. Es la casa a la que van los hermanos cuando vienen de visita al pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-03-20','Ana: Llamada de Pilar Martín, TS ESM CC (54612): Me comunica que Miguel Ángel solicitó y firmó el Alta en la Comunidad Terapéutica "La Garrovilla" (ha permanecido allí del 25 de enero al 10 de marzo). ········· Ha vuelto a Cáritas, está pernoctando en el Albergue de Emergencias de Cáritas (el que sólo abre por las noches) y acude al Comedor Social a comer. ·························· Le han informado que TIENE VARIAS MEDIDAS EJECUTORIAS PENDIENTES Y SERVICIOS EN BENEFICIO DE LA COMUNIDAD ·························································· El inyectable sí se lo ha puesto. ···································································· Informaré a los A. Jurídicos CTAEx, para que lo comuniquen al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-03-22','-Amalia , estado de cuentas : De: MARIA LOURDES CORTES MARQUEZ >marialourdes.cortes@salud-juntaex.es> Enviado: martes, 21 de marzo de 2023 14:09 Para: ALBERTO MARTIN ROSETE >alberto.martinr@salud-juntaex.es> Asunto: PODÓLOGO Y EXTRA ROPA EMILIA MORALES TE MANDO EL EXCELL, PARA QUE LE ECHES UN VISTAZO, SALDO A MARZO 2022 7.439,35 EUR SALDO A MARZO 2023 8.054,22 EUR EMILIA TIENE UNA PNC 484,61€ Y UNA ASIGNACION SEMANAL DE 78€ Aunque tiene balance positivo, además de estos gastos fijos, tiene muchos gastos entre expulsiones, taxis, ropas y unas gafas… y además ha ido al podólogo sin pedir autorización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-03-22','-Amalia , estado de cuentas : De: MARIA LOURDES CORTES MARQUEZ >marialourdes.cortes@salud-juntaex.es> Enviado: martes, 21 de marzo de 2023 14:09 Para: ALBERTO MARTIN ROSETE >alberto.martinr@salud-juntaex.es> Asunto: PODÓLOGO Y EXTRA ROPA EMILIA MORALES TE MANDO EL EXCELL, PARA QUE LE ECHES UN VISTAZO, SALDO A MARZO 2022 7.439,35 EUR SALDO A MARZO 2023 8.054,22 EUR EMILIA TIENE UNA PNC 484,61€ Y UNA ASIGNACION SEMANAL DE 78€ Aunque tiene balance positivo, además de estos gastos fijos, tiene muchos gastos entre expulsiones, taxis, ropas y unas gafas… y además ha ido al podólogo sin pedir autorización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-03-22','-Amalia , recibo email SIVO Badajoz , Buenos días, Quería hacer una consulta sobre Antonia Remedios Lozano Muñoz, ha venido a Servicios Sociales recientemente con su hermana (su antigua curadora), según me comentan la curatela ya la ha asumido la Comisión Tutelar, y Antonia quiere irse de alquiler a un piso. La consulta es quién tiene que firmar ese contrato de alquier, la Comisión? y cómo habría que realizar la gestión. Gracias de antemano. Un saludo -- María Teresa Bermejo González Trabajadora Social SIVO Instituto Municipal de Servicios Sociales (Centro Social Suerte de Saavedra) C/ Vidal Lucas Cuadrado s/n 924 47 85 16 Ayuntamiento de Badajoz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-03-22','-Amalia , recibo email SIVO Badajoz , Buenos días, Quería hacer una consulta sobre Antonia Remedios Lozano Muñoz, ha venido a Servicios Sociales recientemente con su hermana (su antigua curadora), según me comentan la curatela ya la ha asumido la Comisión Tutelar, y Antonia quiere irse de alquiler a un piso. La consulta es quién tiene que firmar ese contrato de alquier, la Comisión? y cómo habría que realizar la gestión. Gracias de antemano. Un saludo -- María Teresa Bermejo González Trabajadora Social SIVO Instituto Municipal de Servicios Sociales (Centro Social Suerte de Saavedra) C/ Vidal Lucas Cuadrado s/n 924 47 85 16 Ayuntamiento de Badajoz','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-03-22','-Amalia , ante la insistencia desde la TS de la UHDAC con respecto al recurso previsto le envio la respuesta dada por Soraya. Buenos días , hemos preguntado a la Jefa de Unidad de Acceso a Recursos del SEPAD por el recurso previsto para Alejandro cuando proceda el alta de la UHDAC , nos comentan que se está gestionando. Para cualquier consulta relacionada con este aspecto tenéis que contactar con la mencionada Unidad . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-03-22','-Amalia , ante la insistencia desde la TS de la UHDAC con respecto al recurso previsto le envio la respuesta dada por Soraya. Buenos días , hemos preguntado a la Jefa de Unidad de Acceso a Recursos del SEPAD por el recurso previsto para Alejandro cuando proceda el alta de la UHDAC , nos comentan que se está gestionando. Para cualquier consulta relacionada con este aspecto tenéis que contactar con la mencionada Unidad . Un saludo. ------------------------- Remito esta información a TS UHDAC: Con respecto a dependencia , el estudio económico ya está hecho de octubre de 2022. El PIA se negociará al alta de su ingreso en UHDAC , que ya estaba solicitada cuando se valoró . El ingreso en UHDAC se acordó en subcomisión de casos donde participaron todos los recursos implicados. Te adjunto cdo. de discapacidad . Saludos .','2');
