insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-03-22','-Amalia . Recibido emial de Miguel . Esperaré a que sea firme para solicitar a la TS del SSASB informe social .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-03-22','-Email de Angel : Nos han nombrado curadores asistenciales. Hemos pedido la firmeza el 16/3/23. Que yo sepa, no ha llegado el testimonio, es pronto. Pongo en copia a Inés, por si supiera algo. El Auto de nombramiento dice que las medidas de apoyo que precisa esta persona son de carácter asistencial, son respecto del ámbito de la salud, para el seguimiento y supervisión en el ámbito médico y farmacológico, y de otro, respecto de los ámbitos económicos-jurídicos-administrativos y contractuales, en relación a la asistencia para la realización de los actos más complejos relacionados en el ART. 287 del CC (entre los que está un contrato de arrendamiento, y para la gestión de sus ingresos. Por lo tanto, ese contrato de alquiler, debe firmarlo, tanto ella, como la Comisión Tutelar de Adultos, una vez acetemos el cargo. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-03-21','Ana: Recibimos Informe emitido por Tania Mª Glez., TS Comunidad Terapéutica La Garrovilla, comunicando el ALTA VOLUNTARIA firmado por el propio Miguel Ángel. ················· Remito el documento a los A. Jurídicos CTAEx para que lo adjunten a la comunicación al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-03-22','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net) a la SECC. JURÍDICA: "nos ponemos en contacto con vosotros en relación a Flora Gutiérrez y a su deseo de poder testar. Como hablamos en la reunión on line con algunas compañeras y compañeros de la Comisión Tutelar, habíamos hace tiempo consultado la posibilidad de que Flora cumpliera uno de sus deseos desde que se incorporó al CRR que es el de poder hacer testamento y legar, a su fallecimiento, su patrimonio, a la asociación de ASPACE que la atendió cuando era niña (en el País Vasco). Inicialmente parecía que podía hacerlo únicamente solicitando cita con el Notario y que éste pudiera atestiguar que estaba en condiciones, pero comprobando vuestros compañeros la sentencia, aparecía expresamente la no posibilidad de testar. Nosotras nos habíamos puesto en contacto paralelamente con la notaría (el mismo día de la reunión) y desde allí nos dijeron que para hacer este proceso sería la Comisión Tutelar quién tendría que contactar con la notaría para determinar si puede o no hacerlo. En cualquier caso, con la nueva ley está pendiente de revisión, en la que podríamos aportar informes en relación a este deseo para que se pudiera valorar esta situación concreta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-03-22','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "el viernes a las 10:00 h, como te comenté, tenemos reunión profesionales y Felisa con profesionales del Proyecto Mi Casa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-03-22','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, te mando la propuesta de las visitas a la familia de los hermanos Justo y Roberto Hdez Castaño. Al final no fueron el día 17 y como este finde es la romería en Alcántara prefieren quedarse e irán en Semana Santa. Entonces el viaje del mes de marzo no se ha realizado. Digo propuesta porque aunque he tenido en cuenta las actividades previstas para esas fechas puede que nos surjan nuevas en los que ellos quieran participar. Le pasaré a la madre esta misma propuesta para que lo tenga en cuenta y realice la solicitud."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-03-22','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, te mando la propuesta de las visitas a la familia de los hermanos Justo y Roberto Hdez Castaño. Al final no fueron el día 17 y como este finde es la romería en Alcántara prefieren quedarse e irán en Semana Santa. Entonces el viaje del mes de marzo no se ha realizado. Digo propuesta porque aunque he tenido en cuenta las actividades previstas para esas fechas puede que nos surjan nuevas en los que ellos quieran participar. Le pasaré a la madre esta misma propuesta para que lo tenga en cuenta y realice la solicitud."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2023-03-22','Ana: Correo de Toni-Futuex, en relación a la reparación en la vivienda a través de Administraciones Parra: "lo he hablado esta mañana con la compañera, se iba poner en contacto con la administradora e intentar cerrarlo para la semana que viene, te voy contando"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2023-03-22','Ana: Correo de la Gema, Directora Res. Malpartida - Grupo Nexus Integral (gsanchez@nexusintegral.com): "HOLA, SOY GEMA SANCHEZ, Directora de la Residencia de Mayores de Malpartida de Cáceres. Os mando este correo en relación a nuestro residente D. León Leal. Ayer llamó a la entidad bancaria directamente para sacar dinero. La entidad bancaria que conoce las circunstancias de D. León le traslado que no podía ser. Ayer hablé con él y se enfado mucho diciéndome que él no llegaba con la asignación mensual y que necesita más dinero. Que intenta llamar a su tutora pero no consigue hablar con ella para explicarle que le suban la asignación mensual. Que es una persona libre y que puede irse de allí cuando quiera y que lo mismo puede hacer con su dinero. Conozco de sobra que se ha intentado subir su asignación, pero hoy continúa muy enfadado y me pide que me ponga en contacto con ustedes para que le deis una solución Podéis llamarme al 670381292" ······························ Llamo a Gema, puesto que León tiene una buena posición económica y hace buen uso del dinero (gastos de bolsillo: café, caramelos, invitación a compañeros de la residencia y cosas así´, que no le perjudican en ningún sentido), le pido que se reúnan con él y elaboren un presupuesto de gastos de bolsillo. ······· Una vez elaborado lo enviarán a la atención de la Secc. Ecca. al ctutelar@','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-03-22','Ana: Envío correo a la TS del SSASB (s.sociales2@moraleja.es) y al Programa de familia (pafmoraleja@mensajerospazex.es): "Me pongo en contacto con vosotras para reenviaros correo de mi compañero Óscar, en relación a los 6 Seguros de Vida y 1 seguro de Decesos que tenía firmados Pilar en el banco con anterioridad a la aceptación del cargo por parte de la CTAEx. *El compañero ha solicitado la anulación de los mismos. (Aclarar que aparte tiene otro seguro de decesos a mejor precio, no se queda descubierta). Pero desde la entidad bancaria nos solicitan que la propia Pilar acuda a la oficina de Moraleja, para firmar la baja de todos y cada uno de los contratos. Dados los antecedentes, desde la sección económica nos solicitan que acuda al banco acompaña, pues no se fían de que pueda volver a firma algún contrato nuevo de cualquier producto. ¿Sería posible que alguna de vosotras le acompañaseis a realizar dicha gestión? Y en tal caso, ¿podríais indicarnos el día que tendrá lugar este acompañamiento? Para que el compañero pueda comunicarlo a banco."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2023-03-22','Ana: Correo de Gema, Directora Res. Malpartida - Grupo Nexus Integral (gsanchez@nexusintegral.com): "HOLA, SOY GEMA SANCHEZ, Directora de la Residencia de Mayores de Malpartida de Cáceres. Os mando este correo en relación a nuestro residente D. León Leal. Ayer llamó a la entidad bancaria directamente para sacar dinero. La entidad bancaria que conoce las circunstancias de D. León le traslado que no podía ser. Ayer hablé con él y se enfado mucho diciéndome que él no llegaba con la asignación mensual y que necesita más dinero. Que intenta llamar a su tutora pero no consigue hablar con ella para explicarle que le suban la asignación mensual. Que es una persona libre y que puede irse de allí cuando quiera y que lo mismo puede hacer con su dinero. Conozco de sobra que se ha intentado subir su asignación, pero hoy continúa muy enfadado y me pide que me ponga en contacto con ustedes para que le deis una solución Podéis llamarme al 670381292" ······························ Llamo a Gema, puesto que León tiene una buena posición económica y hace buen uso del dinero (gastos de bolsillo: café, caramelos, invitación a compañeros de la residencia y cosas así´, que no le perjudican en ningún sentido), le pido que se reúnan con él y elaboren un presupuesto de gastos de bolsillo. ······· Una vez elaborado lo enviarán a la atención de la Secc. Ecca. al ctutelar@ ·························································································· Virginia, Ed. del Programa de Apoyo Comunitario - Futuex, le visita esporádicamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2023-03-22','Email del centro que derivo a juridicos. Adjunto remito resolución de revisión de medidas cautelares de Dña. Ceferina Amalia Torrado León. Gracias. Un saludo','2');
