insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2023-03-22','Buenos días, informo que mañana día 22 de marzo, la paciente Almudena Correyero Parejo se traslada al CRR de Mérida, dónde fue derivada desde este Centro. Si no supera el periodo de adaptación que es de un mes de duración, volverá al Centro Sociosanitario, a la plaza que ocupaba. Hasta ver como evoluciona este mes no se hacen cambios en las cuentas , se llevará dinero desde CSS Mérida Gracias. Un saludo.','2');
