insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='BARBERO'and apellido2='LOPEZ'),'2023-03-22','Buenos días Amalia El próximo jueves día 23 de marzo, desde el centro se tiene programada una salida a Badajoz, a la feria de los mayores.( IFEBA). Actividad en la que participará D. Pedro Barbero López. La salida esta prevista entre 10,30 y 11,00 h y la hora de regreso 18-18,30 h. Si necesitas alguna otra información o debemos aportar alguna documentación, por favor nos lo comunicas. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-03-22','Ana: Pido a Julio, Aux. CTAEx, que actualice domicilio en la Base de Datos: Calle Donoso Cortes, 12-1º Dcha 10100 – Miajadas (Cáceres) Teléfono: 669736411','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-03-23','Ana: Envío correo a Ana Benavente, TS ESM-Plas. (anamaria.benavente@salud-juntaex.es): "Adjunto Solicitud de Subvención 100% para el fomento de la movilidad en el transporte público, relativa a Mª Carmen Solana Chanclón, firmada digitalmente por el Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2023-03-23','Ana: Envío mail a Julio, Aux. CTAEx: "Adjunto, para su correspondiente registro, los siguientes documentos relativos a FÉLIX FRANCO JIMÉNEZ: - Comunicación de variación de domicilio habitual - No aceptación del PIA – Prestación Económica vinculada al Servicio de Ayuda a Domicilio Me indican que debe registrarse a: S.E.P.A.D Sección de Dependencia V Ctra. de Cáceres s/n. 10600 PLASENCIA BUZÓN de Registro Electrónico A11030404 A la Atención de Yolanda García Ramírez, Técnica PIA"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2023-03-23','Ana: Subo al portafirmas digital la SOLICITUD DE TRASLADO DE CENTRO, ya firmada por Félix. El traslado se solicita al nuevo CRR de Don Benito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-03-20','Ana: Llamada de Marisa, TS del CEDEX-Coria (70841): Manuel ha acudido a su despacho sin cita. Llevaba para enseñarle una SANCIÓN de 600 € por llevar cannabis. ············ Si la abona antes de 15 días, tendría que abonar la mitad. ············ Ella no lo ha escaneado ni se ha quedado con copia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-03-23','Ana: Envío correo a Alberto, Jefe Secc. Ecca, con copia a Maite, Óscar, Miguel y Ángel, CTAEx: "acabo de hablar con el padre de Manuel. Dice estar muy enfadado y quiere hablar con el Responsable de la Sección Económica. Nos culpabiliza de que su hijo pueda sacar, cada vez que quiera, el dinero que tiene en el banco y gastárselo en lo que no debe. Dice que algo se podrá hacer. *Le he indicado que el Jefe de la Sección Ecca. habitualmente no atiende al teléfono e insiste que entonces habrá algún otro responsable con el que se pueda hablar. Su teléfono es: 623 247 979 Quiere hacer su herencia, pero no sabe cómo hacer para que su hijo Manuel no tenga acceso al dinero que le quiere dejar, pues no quiere que lo malgaste. Sigue insistiendo en hablar con alguien también a este respecto. Además dice que le han dicho que “hay una ley por la que su hijo, dado sus bajos ingresos, no está obligado a pagar la multa” y que si no “pidamos que se lo cambien por trabajos a la comunidad”… *Me recuerda también que aún se debe una factura de 200€ de la farmacia. Entiendo que si queréis que el padre abone la deuda, tendréis que hablar desde la sección económica al respecto de todo lo demás que plantea."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2023-03-23','TERESA Te escribo referente a Josefa. Desde el servicio de residencia nos informan que ha estado recibiendo llamadas de Miguel, dice ser su pareja, y por lo que tenemos entendido es el padre de su hija, quien la maltrataba y llegó a tener orden de alejamiento sobre Josefa. Ella parece estar de acuerdo con esta relación, creemos que se ven cuando va Josefa a Valdeobispo, pero nosotros no sabemos si debemos o podemos facilitarla. Las últimas llamadas no se le han pasado a la espera de saber que podemos- debemos hacer, llegan a ser más de 50 llamadas Tenéis vosotros constancia de esa orden de alejamiento?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-03-23','TERESA Desde el equipo de apoyo social comunitario de Badajoz, planteamos la posibilidad de realizar dicha gestión mañana día 21 de febrero (ida) y regreso, el viernes 24 de febrero. (suponiendo que se minimizan riesgos de consumo de alcohol evitando el fin de semana, aunque sabemos que eso no tiene porque) Mañana 21 de febrero se esperaría a Pablo en su localidad (Zalamea Serena) para proceder a la retirada de dinero y efectuar la provisión de compra de alimentación y tabaco. Se calcula un presupuesto de 50/60 euros para provisión de gastos. El dinero será custodiado por el equipo de apoyo social comunitario para que Pablo no maneje dinero en efectivo debido al riesgo de consumo de alcohol. La vuelta al centro sería el viernes 24 de febrero. Desde el equipo de apoyo social comunitario se gestionaría el taxi para el regreso y se acudirá a su localidad dicho día para acompañarle hasta que le recoja el taxista, tal y como se efectúo el día del ingreso. Se propone esta gestión sin ser fin de semana para evitar ciertos riesgos entorno al posible consumo de alcohol. Existe alta probabilidad que rechace volver al centro, como sabemos. Hemos pensado que si adquiera un compromiso con el centro, de poder ir una vez al mes (por ejemplo ) a su pueblo, alomejor funciona.. por si lo pueden acordar con el, de este modo, A continuación, detallo datos para la autorización de retirada de dinero de la compañera del equipo que estara mañana alli con el: Sonia Núñez González con DNI 07255084 X','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-03-23','Ana: Llamo a Felisi (722 494 033): le comunico que el martes le llevarán los electrodomésticos de Electrocash, le llamarán antes, tiene su nº para contactar. ····· Lourdes, Secc. Ecca. se ha encargado de contactar con la tienda y abonará mediante transferencia. ········································· Dice que está preocupada por su hijo, no sabe dónde está. Le digo que esté tranquila, sabemos que está en Cáceres y que le están atendiendo y duerme en un Centro de Caritas y en el Comedor Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-03-23','Ana: Respuesta de Verónica Alfonso, TS del SSASB (s.sociales2@moraleja.es): "Hemos estado viendo en la reunión de equipo la posibilidad de acompañar a Pilar al banco nosotras, pero consideramos que lo ideal es que dadas las circunstancias, sea Gloria, la técnica de la Fundación Tutelar que supervisa su tutela quien la acompañe a esa gestión. No habría ningún problema en que si quedan en el banco, Amanda, la auxiliar de SAD la acompañe hasta allí para que Pilar no vaya sola. Si os es imposible que sea Gloria, u otra/o técnica/o de la Fundación quien la acompañe, dímelo y veríamos otras opciones." ·································································································································································································· Envío correo a Toni-Futuex: "En relación a PILAR DÍEZ SANTIAGO, os reenvío correo de mi compañero Óscar, en relación a los 6 Seguros de Vida y 1 seguro de Decesos que tenía firmados Pilar en el banco con anterioridad a la aceptación del cargo por parte de la CTAEx. *El compañero ha solicitado la anulación de los mismos. (Aclarar que aparte tiene otro seguro de decesos a mejor precio, no se queda descubierta). En el banco ya tiene todos los documentos preparados, pero desde la entidad bancaria nos solicitan que la propia Pilar acuda a la oficina de Moraleja, para firmar la baja de todos y cada uno de los contratos. Dados los antecedentes, desde la sección económica nos solicitan que acuda al banco acompaña, pues no se fían de que pueda volver a firma algún contrato nuevo de cualquier producto. ¿Sería posible que Gloria le acompañe realizar dicha gestión? Y en tal caso, ¿podríais indicarnos el día que tendrá lugar este acompañamiento? Para que el compañero pueda comunicarlo a la oficina bancaria." ································ Toni-Futuex: confirma que Gloria le acompañará el martes. ············· Lo comunico a Óscar, Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-03-23','-ASPACEBA 924224672 TF PATRICIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-03-23','-ASPACEBA 924224672 TF PATRICIA trabajadorasocial@aspaceba.org -Es sentencia provisional , el hermano le pegaba y en ASPACEBA donde iba a CO lo han quedado ingresado hasta que le den plaza definitiva. Le han dicho desde la sección de centros que pidan a la CTAEX el abono de la plaza a nivel privado , hemos aceptado cargo el día 2 de marzo y pasarán hasta final de mes . Le van adelantar algo de dinero de bolsillo que luego abonaremos . La sentencia es provisional . Todavía no estamos en las cuentas .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-03-23','Buenas tardes. Soy M.ª Loreto Ruiz Muñoz, Trabajadora Social del Equipo de Salud Mental de Valdepasillas, de Badajoz. Me pongo en contacto con su institución para comunicar que Alejandro Núñez Bono, tutelado por la Comisión Tutelar de Adultos, no acude a consultas de Salud Mental ni con el psiquiatra, Dr. Calderón, ni con enfermería (no poniéndose el inyectable). Las citas no presentadas son: 7-02-23: Enfermería. 23-02-23: Enfermería. 2-03-23: Psiquiatría. El Dr. Calderón cree que tiene como medida judicial, realizar tratamiento ambulatorio con el ESM. Les facilito los ciscos del Psiquiatra y la Trabajadora Social, por si necesitan ponerse en contacto con nosotros: Dr. Pablo Calderón López: 42855. M.ª Loreto Ruiz Muñoz: 42853. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2023-03-24','Ana: Envío correo a Sheila, Directora del CRR-CC (crr@grupociudadjardin.com), con copia a Mª Luz Madrigal y Eva Paredes, de la Secc. de Salud Mental: "Adjunto remito la SOLICITUD DE TRASLADO al CRR de Don Benito, relativa a FELIX FIGUEROA MARTÍN, firmada digitalmente por el Presidente de la CTAEx, como su Curador."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-03-24','-Amalia , paso a los juridicos el email de Loreto . Ellos han comunicado al jgdo. la ausencia del dia 23 de marzo por encontrarse ya ingresado en UDAC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-03-23','Ana: Correo de Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): "comentarte simplemente, a nivel de seguimiento, que Conchi sigue en la Unidad de Media Estancia y que nos informaban de que iba a empezar a ir a talleres de Terapia Ocupacional allí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-03-24','-Amalia , paso a los juridicos el email de Loreto .loreto.ruiz@salud-juntaex.es Ellos han comunicado al jgdo. la ausencia del dia 23 de marzo por encontrarse ya ingresado en UDAC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-03-23','Ana: Correo de Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): "Por otro lado, Isabel Cano tuvo una acción de autolesión, como respuesta a una situación que no supo manejar. Acordamos entonces con ella que retrasara las fechas de su salida a Trujillo (que ya os había informado serían a partir del 27. Ahora estamos negociando nuevas fechas, pero tratando de mantener más o menos, el número de días acordado. Entendiendo las dificultades por ser Semana Santa, pero también teniendo en cuenta que ella pueda responsabilizarse un poco de su falta de cuidado. Por ello aunque nos proponía que su madre desembolsara tres días más de alojamiento, hemos pensado que era excesivo. Os comentaremos los acuerdos a los que lleguemos y las nuevas fechas." ······················ Mi respuesta: "...ayer envío un correo que no quise contestar hasta hablar contigo. Decía que tú no la dejabas irse al pueblo… le acabo de contestar preguntando el motivo, si contesta te lo reenvío todo. Nos parece bien vuestra intervención al respecto de sus acciones. Y los días de más que pide estar, también nos parece excesivo. Además, me sorprende que la madre se haga cargo del gasto, cuando habitualmente se le hace una transferencia desde la cuenta de Isabel para que pueda ir a visitarla a Plasencia…" ···························· Correo-respuesta de Isabel: "Te voy a decir la verdad es porque el lunes me puse muy nerviosa tenía ansiedad y me ize un corte pero ya está todo solucionado me lo a puesto para la siguiente semana del 3 al 8 ya que el 7 no hay autobús"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2023-03-24','Ana: Correo de Rosana, Directora de la Residencia Balcón de Extremadura (balconextremadura@grupociudadjardin.com): "necesitaremos para el 31 de Marzo 2023 acompañamiento para consulta de Mateo Ruano Moreno que tiene en Salud mental, el traslado seria en Ambulancia, no se que posibilidades tenemos." ······························· Confirmo a Rosana que el acompañamiento lo harán desde el Programa de Apoyo Comunitario gestionado por Futuex. La educadora se pondrá en contacto con ella para organiarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2023-03-23','Ana: Correo de Mónica, Ed. de los PPSS de Plas. (educacion.pisosplasencia@grupo5.net): "informarte de que, desde la trabajadora social del Equipo de Salud Mental, se ha gestionado la derivación de Félix a un piso tutelado de mayores. Se trata de un piso ubicado en Casas del Monte (a media hora de Plasencia) con un coste de 617€ (14 pagas). Félix es conocedor de esta información y se muestra de acuerdo con el cambio de recurso, valorando positivamente la cercanía a Plasencia; consciente de la edad que tiene (64 años) y de no tener grado de dependencia suficiente para ocupar una plaza pública. Desde dirección del C.R.R. se ha contactado directamente con el piso y se plantea la posibilidad de incorporación el 12 de abril para favorecer que Félix cierre el ciclo en el piso supervisado y en Plasencia. El número de contacto es 649163256 y la persona encargada de la gestión se llama Gema. De todas formas, mañana Carol te llamará para darte esta información y cerrar la derivación de Félix."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-03-24','Ana: Llamo al Programa de Familia (927 14 71 14 / 648 69 15 67) hablo con Patricia, Psicóloga: se pondrán en contacto con Gloria, Ed. Futuex, para coordinarse sobre la información que hay que dar a Pilar, y quién se la dará, al respecto de la cancelación de los Seguros de Vida y el de Decesos que tenía contratados con el banco. ························· Por otra parte, me informa de que ayer estaba algo inquieta, ya que ha recibido una carta de un compañero de Jorge de la Prisión, pidiéndole copia del DNI y del contrato de telefonía. Todo un poco raro. *Ella no quiere responder. ············ Le tranquilizan y le explican que está en su derecho de no hacerlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-03-17','Ana: Correo de Ana, nueva TS de F. Autismo Sur (teayudamos@autismosur.es): "Me presento, soy Ana Castillo, trabajadora social de Fundación Autismo Sur. El día 25 de marzo a las 10:00h nos han dado cita para poder renovarle el pasaporte a Alexandru. Nos dieron la posibilidad de poder realizarlo aquí en Málaga sin la necesidad de trasladarnos a Sevilla. Os solicito que nos hagáis llegar una autorización para poder acompañarlo. Aprovecho para comentarte que Alex está muy bien. Muchas gracias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-03-24','Ana: Envío a Ana, TS de F. Autismo Sur (teayudamos@autismosur.es) la Autorización para que acompañen a Costi a RENOVAR el PASAPORTE, firmada digitalmente por el Presidente de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-03-24','Amalia , envio email a Futuex y todos los sectores implicados , ya se ha enviado toda la documentación para ingreso a CRR a la Unidad de Salud Mental. He hablado con la Sección y el ESM y está todo cuadrado. He contactado también con el Equipo de dependencia para revisión PIA . La próxima semana desde el CRR Mérida , contactarán con la TS del SSASB del pueblo para que avise a Fco. dado los problemas de comunicación que existe con él ,porque su tf no siempre está operativo. Por favor , contactad con Magdalena ( TF 669501741) para que nos avise y podamos apoyar con ese traslado . A ser posible que lo acompañe la delegada tutelar a la entrevista previa del CRR . No tiene dinero en cuenta , pero creo que podremos pagar algún transporte . Pongo en copia a la sección económica para que nos indique saldo actual, para ver la opición de taxi . A ver de que´ forma podemos asegurar ese traslado. Gracias . Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-03-24','Amalia , envio email a Futuex y todos los sectores implicados , ya se ha enviado toda la documentación para ingreso a CRR a la Unidad de Salud Mental. He hablado con la Sección y el ESM y está todo cuadrado. He contactado también con el Equipo de dependencia para revisión PIA . La próxima semana desde el CRR Mérida , contactarán con la TS del SSASB del pueblo para que avise a Fco. dado los problemas de comunicación que existe con él ,porque su tf no siempre está operativo. Por favor , contactad con Magdalena ( TF 669501741) para que nos avise y podamos apoyar con ese traslado . A ser posible que lo acompañe la delegada tutelar a la entrevista previa del CRR . No tiene dinero en cuenta , pero creo que podremos pagar algún transporte . Pongo en copia a la sección económica para que nos indique saldo actual, para ver la opición de taxi . A ver de que´ forma podemos asegurar ese traslado. Gracias . Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-03-24','informo a la TS del ESM , soy Amalia , comuniqué a los jurídicos la situación de Alejandro Nuñez Bono y van a comunicarlo ellos al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-03-24','informo a la TS del ESM , soy Amalia , comuniqué a los jurídicos la situación de Alejandro Nuñez Bono y van a comunicarlo ellos al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-03-24','información recibida por Esperanza (Trabajadora Social Equipo Salud Mental de Mérida Norte) y por Magdalena (Trabajadora Social SSB Oliva de Mérida). Para que Fco Casillas pudiera entrar en CRR Mérida. Falta por adjuntar el compromiso firmado por Francisco para someterse a tratamiento, la solicitud de la Ley de dependencia junto con el informe de salud que es necesario adjuntar a dicha solicitud. Pero la ts de la localidad ha contrastado con el, y al parecer si estaria dispuesto. El contexto es el siguiente: En la mañana del 22 de marzo de 2023 se pone en contacto con el programa Esperanza (Trabajadora Social Equipo Salud Mental de Mérida) para indicarnos que hay disponible una plaza, para Francisco, en el CRR de Mérida. Le solicitan desde la Comisión de Valoración de recuersos, dar una respuesta, lo más pronto posible, de si existe disponibilidad para ingresar por parte de Francisco. Otro de los requisitos es que acepte recibir tratamiento en CEDEX por el consumo de sustancias, ya que es algo que se indica en sus informes médicos. Número de teléfono Comisión Valoración: 924 00 92 63 (por si consideras ponerte en contacto) Hablamos desde el programa con Magdalena (Trabajadora Social de Oliva de Mérida), nos indica que ella tiene la solicitud para Ley de dependencia y que ha entregado en el centro de salud la documentación para que le realicen el informe de salud. También ha realizado un escrito firmado ya por Francisco, donde refleja su compromiso para someterse a tratamiento durante su ingreso. Toda la documentación nos la enviará a última hora de la mañana por correo electrónico y te la pasariamos, con el objetivo de que se gestione lo necesario para que Francisco pueda acceder a esta plaza en centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2023-03-24','ALFONSO DAVID REBANALES NIETO A 16 de marzo de 2023 se acude a domicilio de Alfonso David con el objeto de trasladar la información referente a la cita en sede judicial para el próximo 4 de abril de 2023. Dicha información se recoge en un documento para poder entregárselo en mano y por escrito. El documento refleja: Desde Comisión Tutelar de Adultos de Extremadura como representante legal de D. Alfonso David Rebanales Nieto informan que, D. Alfonso David Rebanales Nieto debe compadecer en el JUZGADO DE PRIMERA INSTANCIA E INSTRUCCION NUMERO 1 SALA 3 (Planta Baja) ubicado en Av. Comunidades S/N, Mérida el próximo 04 DE ABRIL DE 2023 A LAS 10:00 HORAS para Entrevista Personal en sede Judicial. Si tiene alguna cuestión o duda puede dirigirse a Comisión Tutelar de Adultos de Extremadura, con sede en Dirección: Avda de las Américas, 4. 06800. Mérida (Badajoz) Teléfonos: (924006057 - 924006030 - 924006085) Tras varios intentos sin éxito de localizarlo en domicilio e inmediaciones, se realizan varias llamadas telefónicas al nº de contacto de su madre. Conseguimos que atienda al presentarnos e indicarle que necesitamos entregarle dicha información, se niega y se pone a la defensiva, alega que su hijo es mayor de edad y no va a acudir al juzgado. Negándose en la misma linea, a ser la receptora de la información por miedo a que su hijo se enfade con ella. Cuelga el teléfono y no vuelve a atender a las llamadas realizadas. Desde el equipo de apoyo social comunitario trataremos de hacerle llegar la información en próximas gestiones realizadas en Mérida. Pero por el momento, ha resultado infructuoso. Saludos -- Antonia María Ramírez Cruceras. Psicóloga. Coordinadora Área Psicosocial email: areasocial3@futuex.es FUTUEX: Fundación para la Promoción y Apoyo a las Personas con Discapacidad Tel.: 924491914 - Fax: 924492051 Plaza Santa María 5 - Apartado 84. 06100 Olivenza (Badajoz) www.futuex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-03-24','Ana: Correo de Miguel, A. Jurídico: "Ana necesito saber el tipo de centro ya que en los informes no se indica. Por otra parte veo que la sentencia sólo nos habilita en el ámbito de la salud con lo que entiendo será un problema de carácter económico para gestionar esta Curatela, que como sabes está pendiente de procedimiento de revisión de medidas de apoyo. Ahora el jzdo nº1 de Mérida se ha inhibido a favor de los de Trujillo porque su domicilio lo tiene en Miajadas" ·················· Mi respuesta: "Por la edad ya no puede volver a CRR, y de todas formas, como sabéis, este centro requiere voluntariedad, otro motivo por el que no podría ser. Yo entiendo, que, dados los signos de descompensación, debería ingresar primero en UHB, para estabilización clínica y de ahí a CENTRO RESIDENCIAL DE MAYORES. O, en el peor de los casos, si creéis que no procede UHB, directamente a centro residencial de mayores y si allí fuera necesario que activen 112. *Pero no sería la primera vez que nos autorizan UHB"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-24','Ana: Conversación con Ana Benavente, TS ESM-Plas (74924): La semana que viene nos remitirán presupuesto para autorización de retirada de efectivo para la compra de ropa y productos de limpieza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-03-27','Ana: Recibimos del Serv. Territorial de CC, Documento de PNC, de elección entre PNC y PFHC. Pongo para la firma la elección de PFHC = 453,30 h x 12. ···························· Envío a Julio, Aux. CTAEx, para que remita por REGISTRO a SS.TT. CC. - Prestaciones, Oficio adjuntando documentación y Documento de ELECCIÓN DE PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-03-27','Ana: Correo de Carolina, Directora/Psicóloga del CRR/PS Plas. (direccion.crrplasencia@grupo5.net), de ayer domingo: "Buenos días! Os escribo para informaros que desde el viernes 24 de marzo Javier Agudo Cumplido, usuario del piso supervisado no ha regresado al recurso. El viernes por la noche se interpuso denuncia de desaparición ante la Policia Nacional, adjunto informe con más información. A lo largo del fin de semana no hemos obtenido más información, una de las posibilidades que manejamos es que esté en Cataluña puesto que su deseo es residir allí, pero no tenemos datos que lo confirmen. Os mantendré informadas de todo, si necesitáis cualquier información no dudeis en contactar conmigo a través del movil ( 673 22 55 27), que a primera hora voy a subir de nuevo a la Policia. La Policia necesita vuestra autorización, si lo considerais, para la difusión de imágenes y datos personales." ·················· Guardo en el expte. el Informe que adjunta y reenvío el correo a Miguel y Ángel, A. Jurídicos. ···················· Ángel, A. Jurídico, se encargará de llamar a la Policía. ··································································································································································································· Nuevo correo de Carolina: "Correo de Carolina, Directora/Psicóloga del CRR/PS Plas. (direccion.crrplasencia@grupo5.net): "Buenos días! Como ya os he informado Javier ha aparecido en Tarragona con la Guardia Urbana . He facilitado a Ana Matamoros el teléfono de la persona con la que he hablado, Lidia, pero os lo dejo nuevamente por aqui para que contactéis con ella 664587528 ya que me ha vuelto a llamar. Yo he hablado con Javi y se niega a regresar a Plasencia, quiere que se le envíe dinero y quedarse allí. Le he explicado que la manera adecuada de proceder es que regrese y podamos continuar con él trabajando para lograr su objetivo de forma planificada pero no acepta. Mañana le toca inyectable (Abilify Maintena 400 mg) y está sin medicación desde el viernes, os adjunto la pauta de medicación. Os facilito su número de teléfono también para que contactéis con él sí lo consideráis; 624109525. La Policia ya está avisada de que ha aparecido y me han indicado que tengo que retirar la denuncia, en un rato subiré a retirar la denuncia." ····························································································································································································· Tras valorarlo Ángel, Maite y yo, Maite y yo llamamos a Javier, a pesar de darnos la razón a cada argumento que planteamos, él insiste en que "no puede volver a Plasencia". Pedimos que se piense el regreso temporal para que pueda marcharse a posteriori con todo bien organizado (alojamiento, expediente médico, cuenta bancaria y autorización de retirada de efectivo en Tarragona...) y acordamos que volveremos a llamarle mañana. ·································· Ángel y Miguel llaman a José Manuel Rubio, Fiscal de Plasencia: Éste indica que hagamos comunicado por escrito al Juzgado y a Fiscalía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2023-03-24','Ana: Correo de Gema, Directora Res. Malpartida - Grupo Nexus Integral (gsanchez@nexusintegral.com), al ctutelar@: "Hola, buenos días Ana. Respecto a la llamada telefónica en relación a D. León Leal referente al aumento de su asignación mensual; reunida con él hoy día 24.3.23 paso a detallarte su presupuesto de gastos. MAQUINA DE REFRESCOS Y SNACK. Todos los días consume 1 refresco (1 euro) y 2 cafés (0,70 por café). Además suele invitar a otros mayores a algún refresco. TOTAL UNOS 90 EUROS TAXI MENSUAL PARA VOLVER DE CACERES CUANDO VA AL BANCO A POR LA ASIGNACIÓN MENSUAL. 20 EUROS FARMACIA: aproximadamente 35 euros al mes GASTOS PERSONALES; como ropa, calzado, bolsas de caramelos, bolsas de patatas fritas y similar. 80 euros Peluquería y Podología: 15 euros al mes Me ha dicho que en total necesitaría unos 240 euros al mes. D. León también me traslada que os pregunte si está recibiendo alguna prestación de la tesorería general de la seguridad social, ya que me dice que él hizo un trámite para solicitar una prestación de invalidez pero que a fecha de hoy no ha tenido respuesta. Le podéis ayudar con este tema, por favor? Ana hoy estoy en la residencia con León, si quieres llámame y te lo paso para que puedas hablar con él Quedo a la espera que me digáis cuando está efectivo este cambio de asignación para que puede ir D. León a primeros de abril y poder ya sacarlo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2023-03-27','Ana: Respondo al correo de Gema, Directora Res. Malpartida - Grupo Nexus Integral (gsanchez@nexusintegral.com) en relación al presupuesto para asignación mensual: "A mí me parece bien el presupuesto y no creo que haya ningún problema. Así se lo transmito al Jefe de la Sección Económica. Mi compañeros de la sección económica te lo confirmará, pero supongo que será efectivo ya para la asignación de abril la semana que viene. En cuanto a los Ingresos de D. Leal, él ya tenía gestionado: - P. Orfandad - Prestación Familiar por Hijo a Cargo La nueva prestación que ha empezado a percibir en el mes de febrero, no es de la Seguridad Social, sino de la Junta: Prestación Económica Vinculada al Servicio de Atención Residencial." ················· Envío correo a Alberto y Óscar, Secc. Ecca., con OK, al presupuesto y pidiendo confirmen a la Res. desde su sección.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-03-27','Amalia , escribo a ctutelar : Buenos días , la semana pasada María recibió la llamada de su sobrina . Hay un desperfecto en la vivienda y quería saber si su tía mantenía el seguro de la casa . Ella dice que no vive allí , pero que acude a menudo por dar una vuelta al piso. Le comentó si habíamos enviado la Fe de vida a Alemania. Creo que es porque ha abierto el correo que le llega a esa vivienda . Yo ya he solicitado cambio de dirección a la seguridad social para que las notificaciones nos lleguen ; pero de momento nada. Hasta el año pasado , su madre , llevaba esa carta a la residencia ,que me enviaba el cdo. como residente y yo me encargo de enviarlo a la Seguridad Social . Pero este año no lo han hecho y por eso le han dejado de pasar la pensión. Ya está todo tramitado , sólo para registrar. Por otro lado , se pidió por 3 veces solicitud a seguridad social de Alemania para que nos indiquen Nº cuenta o entidad donde se les ingresa la otra pensión ( tiene 2 una de unos 900€ y otra de unos 700) . No nos facilitan esa información , nos indican que revisemos sus cuentas porque la pensión la están enviando y no tienen devolución de la misma . Estabamos pendiente por si desde la AET la tenían registrada y se podía averiguar algo más. Le quedarían para 2 años de liquidez para seguir pagando la residencia , la señora es muy mayor , supera los 90 . Sería interesante poder reducir costes de la vivienda y averiguar lo de la segunda pensión para poder alargarlo. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-03-24','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informarte que hemos tenido la visita de profesionales del Proyecto Mi casa. Han conocido a Felisa y después de informarle sobre en qué consiste el proyecto, le han preguntado si le gustaría ir a vivir a Don Benito. La respuesta ha sido rápida, un sí rotundo y preguntando cuándo se iba. Ha preguntado y ha contado lo que le gusta hacer, luego ha estado conmigo enseñando las instalaciones del centro para que pudieran saber de qué les habla Felisa. Les ha dado explicaciones de todo. Hemos quedado que durante la próxima semana abordaremos con ella distintos aspectos del proyecto para asegurarnos que lo conoce y entiende bien. Por otro lado, vamos a ver la posibilidad de organizar una visita al piso. Iría junto con otros residentes a Don Benito como si fuera una actividad de ocio. La fecha de ingreso será la que vayamos organizando entre los dos equipos. Me han dicho que tendría reservada la plaza durante los primeros 6 meses. No sé cómo hay que proceder en cuanto a los trámites de firma de documento para ingreso,.... El martes 28 le acompañaremos al Juzgado para la cita con el médico forense, en relación a las medidas de apoyo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-03-27','Amalia , escribo a ctutelar : Buenos días , la semana pasada María recibió la llamada de su sobrina . Hay un desperfecto en la vivienda y quería saber si su tía mantenía el seguro de la casa . Ella dice que no vive allí , pero que acude a menudo por dar una vuelta al piso. Le comentó si habíamos enviado la Fe de vida a Alemania. Creo que es porque ha abierto el correo que le llega a esa vivienda . Yo ya he solicitado cambio de dirección a la seguridad social para que las notificaciones nos lleguen ; pero de momento nada. Hasta el año pasado , su madre , llevaba esa carta a la residencia ,que me enviaba el cdo. como residente y yo me encargo de enviarlo a la Seguridad Social . Pero este año no lo han hecho y por eso le han dejado de pasar la pensión. Ya está todo tramitado , sólo para registrar. Por otro lado , se pidió por 3 veces solicitud a seguridad social de Alemania para que nos indiquen Nº cuenta o entidad donde se les ingresa la otra pensión ( tiene 2 una de unos 900€ y otra de unos 700) . No nos facilitan esa información , nos indican que revisemos sus cuentas porque la pensión la están enviando y no tienen devolución de la misma . Estabamos pendiente por si desde la AET la tenían registrada y se podía averiguar algo más. Le quedarían para 2 años de liquidez para seguir pagando la residencia , la señora es muy mayor , supera los 90 . Sería interesante poder reducir costes de la vivienda y averiguar lo de la segunda pensión para poder alargarlo. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-03-21','-Amalia : me reuno con May , ya se ha entregado y registrado la solicitud por decreto . Quedo pendiente recibir la resolución para solicitar 112 .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-03-21','-Amalia : me reuno con May , ya se ha entregado y registrado la solicitud por decreto . Quedo pendiente recibir la resolución para solicitar 112 .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2023-03-27','Buenos días, he mandado a IBERCAJA DON BENITO, la asignación que tiene asignada. 120€ semana Lo comunico al centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-03-27','Ana: Llamo a Mamen Sánchez, TS Cáritas (607 68 05 53): me confirma que Miguel Ángel está pernoctando en el CES (Centro de Emergencia Social). Está consumiendo. En Centro Vida no van a volver a aceptarlo, después de la trayectoria y de haber desaprovechado todas las oportunidades que se le han dado. Además tiene muchas causas pendientes. *Intentará enviarme los documentos al respecto que tiene en el expte. ··················· Pedirá a Pedro, Coord. que nos remita Certificado/Informa confirmando la estancia allí de Miguel Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2023-03-27','Ana: Llamada de Mª Ángeles, Aux. SAD (675 264 255): Han enviado presupuestos para sábanas, pijamas y espuma para arreglar el sofá. ········ Los pijamas ya se los han dado en la tienda. *Le digo que no vuelvan a hacerlo así, o corren el riesgo de que no se paguen, primero es necesaria la autorización. ·················· La secc. soc. da el visto bueno a todos los gastos propuestos. Lo hablo con Lourdes, Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-03-27','Manuel Contador lleva desde el mes de septiembre de 2022 marchándose a Badajoz todos los fines de semana. Tras el problema de salud de su hermana en diciembre y puesto que esta dijo que no podían continuar trayendo a su hermano al centro los domingos en coche ( HASTA EL MOMENTO SE MARCHABA LOS VIERNES Y REGRESABA LOS DOMINGOS ) se decidió en consenso de ambas, que Manuel pasase dos noches en el hotel y una en su casa todos los fines de semana y se regresara al centro los lunes por la mañana en bus. Así ha estado siendo hasta este mes de marzo, que puntualmente, por ser un mes que dispone de 5 fines de semana y porque a nivel económico no podíamos hacerlo de otro modo, ha habido dos fines de semana que Manuel se ha quedado 2 noches en su casa y 1 en el hotel ( información de la que era conocedora su hermana ) pero repito, de manera puntual, porque creíamos que romper la rutina de marcharse menos días en el fin de semana iba a suponer un mal mayor para Manuel. Manuel C. lleva ya dos fines de semana yéndose tal y como lo estaba haciendo siempre, dos días al hotel y uno a su casa ( el domingo pasa la noche en su casa porque el Hotel donde se aloja los domingos cierra). Ya se marchó esta mañana. No obstante, me gustaría hablar contigo y poderte comentar todo con más detalle. Un saludo y buen fin de semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-03-27','Manuel Contador lleva desde el mes de septiembre de 2022 marchándose a Badajoz todos los fines de semana. Tras el problema de salud de su hermana en diciembre y puesto que esta dijo que no podían continuar trayendo a su hermano al centro los domingos en coche ( HASTA EL MOMENTO SE MARCHABA LOS VIERNES Y REGRESABA LOS DOMINGOS ) se decidió en consenso de ambas, que Manuel pasase dos noches en el hotel y una en su casa todos los fines de semana y se regresara al centro los lunes por la mañana en bus. Así ha estado siendo hasta este mes de marzo, que puntualmente, por ser un mes que dispone de 5 fines de semana y porque a nivel económico no podíamos hacerlo de otro modo, ha habido dos fines de semana que Manuel se ha quedado 2 noches en su casa y 1 en el hotel ( información de la que era conocedora su hermana ) pero repito, de manera puntual, porque creíamos que romper la rutina de marcharse menos días en el fin de semana iba a suponer un mal mayor para Manuel. Manuel C. lleva ya dos fines de semana yéndose tal y como lo estaba haciendo siempre, dos días al hotel y uno a su casa ( el domingo pasa la noche en su casa porque el Hotel donde se aloja los domingos cierra). Ya se marchó esta mañana. No obstante, me gustaría hablar contigo y poderte comentar todo con más detalle. Un saludo y buen fin de semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-03-27','Manuel Contador lleva desde el mes de septiembre de 2022 marchándose a Badajoz todos los fines de semana. Tras el problema de salud de su hermana en diciembre y puesto que esta dijo que no podían continuar trayendo a su hermano al centro los domingos en coche ( HASTA EL MOMENTO SE MARCHABA LOS VIERNES Y REGRESABA LOS DOMINGOS ) se decidió en consenso de ambas, que Manuel pasase dos noches en el hotel y una en su casa todos los fines de semana y se regresara al centro los lunes por la mañana en bus. Así ha estado siendo hasta este mes de marzo, que puntualmente, por ser un mes que dispone de 5 fines de semana y porque a nivel económico no podíamos hacerlo de otro modo, ha habido dos fines de semana que Manuel se ha quedado 2 noches en su casa y 1 en el hotel ( información de la que era conocedora su hermana ) pero repito, de manera puntual, porque creíamos que romper la rutina de marcharse menos días en el fin de semana iba a suponer un mal mayor para Manuel. Manuel C. lleva ya dos fines de semana yéndose tal y como lo estaba haciendo siempre, dos días al hotel y uno a su casa ( el domingo pasa la noche en su casa porque el Hotel donde se aloja los domingos cierra). Ya se marchó esta mañana. No obstante, me gustaría hablar contigo y poderte comentar todo con más detalle. Un saludo y buen fin de semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-03-27','Ana: Llamo a Mamen Sánchez, TS Cáritas (607 68 05 53): me confirma que "Paco", está de nuevo en su centro. Le van a dejar estar en torno al mes - mes y medio, para recuperarse, pero luego tendrá que marcharse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-03-27','TERESA Buenas tardes, soy Helena Macías, trabajadora social del Ayuntamiento de Zafra. Me gustaría hablar con vovotros por una petición de ayuda a domicilio del tutelado Jose Mª Valle Simón. Mi teléfono es el 924540073 y el correo este mismo desde el que escribo Un saludo HABLO CON HELENA Y LE INFORMO QUE CON FECHA 30 DE ENERO DE 23 SE HA SOLICITIDO REVISION DE PIA Y DE GRADO, CONTINUA EL EXPEDIENTE INACTIVO, VALORAREMOS LA OPICON DE SAD JUNTO CON CRR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2023-03-27','TERESA He hablado con Ángela, me comenta que se quiere ir a una residencia como bien me comentaste a la de Jerez. Voy contactar con ellos y ver si hay plaza y precio Con respecto a la ayuda a domicilio la solicito en el 2019 y se le concedió la ayuda de 88€ en 2020, la ayuda ahora está suspendida por incumpliendo de requisitos ( tenía el contrato con condición suspensiva y nunca inicio el servicio con lo cual ha generado un cobro indebido el cual tenemos que devolver). Ella comenta que no quiere ayuda a domicilio, que prefiere a sus vecinas las cuales le pagan 10€ la hora, voy a pedir a la sección económica que le suba la asignación para que pueda pagar a estas señoras que le están prestando ayuda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-03-27','Ana: Correo de Paula, TO CRR-Plas (tocupacional.crrplasencia@grupo5.net): "Comentarte que hemos planificado con Isabel que se vaya a casa del 3 al 8 de Abril, aumentando un día para que pueda regresar (el viernes no había transporte público y aunque intentamos otras opciones no lo logramos)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-03-27','Ana: Correo de Sonia Bernabé, Asindi: "Hola Ana, hoy la psicóloga ha hablado con Felisa para que entienda bien en qué consiste el proyecto Mi casa. La información que tiene es el documento que nos dejaron en lectura fácil. Ha ido viendo todos los puntos y al final firma como que lo ha entendido. Por lo que veo precisa de la firma del representante legal. Por este motivo, te mando el documento completo. Imagino que después se lo tenemos que remitir a ellos." ························ Subo el documento al portafirmas digital para la firma del Presidente de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-03-28','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Informar sobre el alta en la UHB de Cáceres de la persona usuaria Consuelo Nevado Pacheco en la tarde de ayer. Seguiremos informando de la evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-03-28','Ana: María, Secc. Ecca, me confirma que a Juan Gregorio, el día 24 de marzo, le ingresaron la pensión en la cuenta nueva (Ibercaja). Sólo la mensualidad de marzo. ····························································································································································································· Cumplimento y subo al portafirmas digital la SOLICITUD DE ABONO DE MENSUALIDAD IMPAGADA, para reclamar el abono de la mensualidad de pensión de Febrero de 23. ···················· La remito a la Oficina de Atención al Ciudadano (oac.merida.san@juntaex.es) para que la remitan por REGISTRO a la Dirección Provincial de INSS- CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-03-28','Ana: Envío a Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): el documento "Hoja de información para P.D. del Proyecto Mi casa: una vida en comunidad" firmada digitalmente por el Presidente de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-03-27','Ana: correo de Laura Salguero Sánchez, TS ONCE (LASS@once.es), que se ha vuelto a incorporar: "Justamente ahora mismo se ha presentado Ventura aquí para solicitar las vacaciones sociales (hay otro viaje en mayo). Estoy en reunión y no he podido atenderle. Pero el plazo termina este miércoles 29. No veo viable que presente la solicitud sin haber valorado la experiencia anterior, sin haber aclarado todo lo anterior, y mucho menos, porque tiene que pasar de nuevo por vuestro filtro y por vuestra unidad económica." ······································································································································································································ Mi respuesta: "Con respecto al viaje de Ventura, estoy de acuerdo contigo en que es muy precipitado y en que además, habría que valorar con él, y tener en cuenta, la experiencia anterior. Además, justo la semana pasada ha estado en un balneario con el Programa de Termalismo del IMSERSO, que también se aprobó y solicitó."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-03-28','Ana: Llamo a Julia Durán, TS del Centro de Mayores - "Hogar Peña del Cura" de CC (22032): en relación a la solicitud de TAD. Ya tiene preparada la solicitud. Está pendiente de que Ventura le lleve el Informe Médico. Cuando lo tenga todo nos lo hará llegar para la firma del D. Gerente y remitirlo por registro desde aquí al IMAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-03-28','Ana: Recibimos "INFORME DE CITA PROGRAMADAS" firmado por la Dra. Gómez del Castillo, Coordinadora del ESM CC. - No se presentó a la cita del día 14/03. ·························· Se lo envío a A. Jurídicos, con copia a Maite: "En relación a la solicitud de ingreso involuntario de JOAQUINA MAYORAL PIZARRO, os adjunto otro documento que podéis aportar; “INFORME DE CITAS PROGRAMADAS”, y que está en relación con lo que os puse en el correo anterior de ingreso previo en UHB, pues no se ha presentado a la cita que tenía en la Consulta de Psiquiatría el día 14/03/23 (Podéis verlo en la 2º página del documento adjunto, que es lo que nos envía la Coordinadora del Equipo de Salud Mental) En el pueblo nadie ha activado el 112, porque, entre otras cosas, no ha generado alarma social como tal, pero como visteis en el Informe Social del SSASB que os envié, ella cada día está peor y la situación es cada vez más insostenible."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-03-28','Ángel: Envío correo electrónico a Alberto, Ana y Maite. "Buenos días, Me ha llamado Carlos González Leo (665022593), es una curatela representativa que hemos aceptado recientemente. He ido sacándole información, porque aún no disponemos de mucha en el expediente. • Tiene cuenta en Liberbank. • Vive solo en su piso, sito en C/. Caupolicán, 7, 2º d, de Cáceres. Es un piso heredado de su madre fallecida. El padre los maltrataba, según él y no se lleva bien con él. • Come en casa de un amigo • Cobra una pnc (420 euros) • Su centro de salud es San Jorge, de Cáceres (cerca de donde vive, en C/. Caupolicán), donde tiene su médico de cabecera y su Trabajador Social de Referencia. No va a salud mental, porque no lo necesita, dice. • En general balbucea un poco, pero entiende todo y se expresa más o menos bien. • Tiene acceso a internet, a través de wifi. • Tiene dos mascotas. • Pide que le demos dinero, para atender sus necesidades. • Le he facilitado el correo electrónico de Comisión Tutelar. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-28','Ana: Envío correo a REGISTRO (oac.merida.san@juntaex.es): "Adjunto, la siguiente documentación, relativa a D. ENRIQUE SANTOS GARCIA-PUENTE, cuyo cargo ostenta la Comisión Tutelar de Adultos, para remitirlo a la Dirección Provincial del INSS de Cáceres: - Oficio-solicitud de Certificado Actualizado de Pensión de Incapacidad Permanente Absoluta - Testimonio Aceptación del Cargo Ante cualquier cuestión, no dudéis en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-03-28','Ana: Correo de Ángel, A. Jurídico: "Han citado a Ventura Gómez García, el día 3/4/23, a las 10:00 h, en el Instituto de Medicina legal de Cáceres, para ser reconocido por el Médico forense, en el procedimiento revisión de medidas. Hay que comunicárselo a él, para que ese día vaya a la citación." ··············· Se lo reenvío a Toni-Futuex: "Te reenvío correo de Ángel, Asesor Jurídico, subrayo en amarillo. Para que se lo hagáis llegar a Ventura en persona a la mayor brevedad a través del Programa de Apoyo Comunitario. Espero, así mismo, que acepte vuestro acompañamiento al Juzgado, o al menos que se persone en el día y hora fijadas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-03-28','Ana: Tras recibir llamada de Mª Aª (927 095 795 // 677 80 64 45), envío correo a Alberto y Óscar, Secc. Ecca.: "Acabo de recibir llamada de Mª ANTONIA BERNARDO PIRIS. Dice que tenía una cuenta en CAIXABANK, que no han cerrado aún. Ya en su día os lo puse en un correo (en marzo de 2012), dice que le genera comisiones y que aún no se ha cerrado (es posible que desde la Secc. Económica hayáis solicitado ya la cancelación y que el banco no haya hecho caso, pero no lo sé). A parte de esto, dice que a fecha de 01/01/21, se hizo un traspaso de 1340€, de esa cuenta de Caixabank a no sabe dónde y qué en el banco: 1- No le quieren dar información al respecto 2- Le dicen que tiene que ir acompañada de su tutor legal… Quiere hablar con alguien de la sección económica y que le aclaren todas estas cuestiones. Su teléfono es: 677 80 64 45. Ya me aclaráis cuando podáis. Y, por favor, llamarla a ella para explicarle todo bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-03-28','miguel, ante la falta de asistencia de Adrian al procedimiento por delitos leves 147/2022 del jzdo nº1 de Plasencia, hablo con Eva Alvarez Ts 924-454727 y 647-616146 quien logra conectar a Adrian, pero su señoría decide suspender el juicio, de acuerdo con el Fiscal porque quiere saber la capacidad que dispone el tutelado actualmente. ********envío email a Ines, Angel y parte social Maite: Hola, el juicio por delitos leves147/2022 cuya cita estaba previsto para hoy en el jzdo nº1 de Plasencia ha sido suspendido. Es posible que desde el juzgado se inste el procedimiento de revisión de medidas de apoyo de Adrian porque el fiscal quiere saber la capacidad de la que dispone actualmente Adrian. Tras hablar con Eva del Plena Inclusión me comenta que no sabía nada de la citación. Por favor para posteriores ocasiones nos tenemos que asegurar que los centros estén avisados de las citaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-03-28','Ana: Envío correo a REGISTRO (oac.merida.san@juntaex.es): "Adjunto, la siguiente documentación, relativa a D. ANTONIA BRAVO PATILLA, cuyo cargo ostenta la Comisión Tutelar de Adultos, para remitirla por registro a la Dirección Provincial del INSS de Cáceres: - Oficio-solicitud de Certificado Actualizado de Pensión de Incapacidad Permanente Absoluta - Testimonio de Sentencia y Aceptación del cargo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-03-23','Ana: Correo de Tamara Sánchez, TS del IMAS- Ayto.CC (tamara.sanchez@ayto-caceres.es): "Me pongo en contacto con ustedes en referencia a uno de sus tutelados Carlos González Leo, que me piden un Informe social y alguna documentación, necesitaría que me aportaran un número de teléfono donde pueda contar con el usuario para poder citarlo y realizar las gestiones oportunas. He intentado localizarles por teléfono pero me ha sido imposible, espero su respuesta." ································································································································································································ Respuesta de Julio, Aux. Adtvo. CTAEx: "En contestación a su solicitud de aportación de un número de teléfono al que dirigirse para responder a nuestro oficio en el que les solicitábamos Informe Social y diversa documentación, referente todo ello a D. Carlos Glez. Leo, les informamos que el cargo fue aceptado el 15 de marzo de este mismo año, con lo que se están dando aún los primeros pasos en el caso de D. Carlos. Por tanto, el número telefónico que podemos alcanzarles es el único que figura en la documentación que obra en el procedimiento de adopción de medidas de apoyo de D. Carlos. Y que, a su vez, ha llegado hasta el expte. que D. Carlos mantiene abierto en la Comisión Tutelar. El número es: 653 177 271. Según la documentación ya mencionada, pertenece al antiguo tutor de D. Carlos. Figura que ejercía su propio padre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-03-28','Ana: Correo de Ángel, A. Jurídico CTAEx: "Me ha llamado Carlos González Leo (665 022 593), es una curatela representativa que hemos aceptado recientemente. He ido sacándole información, porque aún no disponemos de mucha en el expediente. • Tiene cuenta en Liberbank. • Vive solo en su piso, sito en C/. Caupolicán, 7, 2º d, de Cáceres. Es un piso heredado de su madre fallecida. El padre los maltrataba, según él y no se lleva bien con él. • Come en casa de un amigo • Cobra una pnc (420 euros) • Su centro de salud es San Jorge, de Cáceres (cerca de donde vive, en C/. Caupolicán), donde tiene su médico de cabecera y su Trabajador Social de Referencia. No va a salud mental, porque no lo necesita, dice. • En general balbucea un poco, pero entiende todo y se expresa más o menos bien. • Tiene acceso a internet, a través de wifi. • Tiene dos mascotas. • Pide que le demos dinero, para atender sus necesidades. • Le he facilitado el correo electrónico de Comisión Tutelar." ···································································································································································································· Facilito a Tamara Sánchez, TS del IMAS- Ayto.CC (tamara.sanchez@ayto-caceres.es), el número de móvil de Carlos, para que pueda contactar con él. ································································································································································································· Correo de Carlos al ctutelar@ (gonzalezleocarlos29@gmail.com): "Hola Soy Carlos González leo Mi dni es : 76052989Q .. Solicito dinero para una Vacuna de una cachorra de 4 meses que vale 25 € en el veterinario También para un saco de pienso Qué vale 10 € Y por última dinero para comer y comprar Cosas de Aseo Para higiene Si puede ser por favor lo antes posible Por qué la vacuna la tengo este viernes 31 de marzo y Llevo 2 semanas sin dinero Por qué el anterior tutor no me mandó dinero y Estoy comiendo en casa de un amigo ¿ Gracias un saludo" ····························· Mi respuesta: "Buenas tardes, Carlos, Encantada. Soy Ana, TS del Gabinete Técnico de la Comisión Tutelar de Adultos. Decirte que tu expediente es tan reciente, que aún no tenemos acceso a tu cuentas. ES más, no sabemos qué ingresos tienes, ni en qué entidad bancaria te los ingresan, pues el Juzgado nos da 60 días para conformar el expediente, y aunque ya se ha pedido desde aquí información a distintos organismos, aún no tenemos nada más que el Auto de las Medidas Judiciales de Apoyo. Así pues, habrás de tener paciencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2023-03-29','Ana: Llamada de Esther, TS del SSASB de Alcuéscar (927 38 40 02): ha ido a hablar con ella un hermano de Antonio, le ha dicho que quiere entrar en la casa de Antonio para ver que está todo bien y no hay desperfecto tras la fuertes lluvias que hubo. ···························· Por otra parte, dice que su hermano trabajó en el extranjero, que este año cumple los 65 años y que tiene toda la documentación para solicitarle la Pensión de Jubilación. ··································· Le pedirá que haga la solicitud para entrar en la vivienda por escrito y que lleve la documentación para que nos la pueda hacer llegar ella escaneada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-03-29','-Amalia : Contacto con el C. R. Los Molinos , Dtra. Lourdes 659788909 , lourdeslibra13@gmail.com Quedo pendiente valoración para activar 112 y proceder al ingreso .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-03-29','-Amalia : Contacto con el C. R. Los Molinos , Dtra. Lourdes 659788909 , lourdeslibra13@gmail.com Quedo pendiente valoración para activar 112 y proceder al ingreso .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-03-29','Amalia : escribo a los compañeros , Buenos días , para que Manuel pueda salir los fines de semana del CRR a Badajoz , y pasar las 3 noches fuera en el hostal necesitaría una subida de 150€ más al mes . Hay una noche que la pasa en su domicilio familiar pero éste no reune condiciones de habitabilidad y la familia está exigiendo que se remedie esta situación. Indicadnos si dais OK desde la parte eco para proceder . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-03-28','Ana: Correo de Miguel, A. Jurídico: "Adjunto escrito del CSS al juzgado en relación con el internamiento involuntario que dictó el Jzdo nº2 de Cáceres, donde se oponen a que se haga en la UME. Esto facilitaría, entiendo, que finalmente cumpla la pena que le impongan en el centro psiquiatrico penitenciario de Sevilla. Quedo pendiente me enviéis el acta de la subcomisión que tuvisteis a efectos de enviárselo a la abogada defensora…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-28','Ana: Correo de Puerto, TS SSASB de Valdeobispo (ssb5@mancomunidadvalledelalagon.es): "Buenos días: te pongo los teléfonos de los hermanos de ENRIQUE SANTOS - Ricardo TFNO 649628797 - Nacho TFNO 670743476 - Carmen TFNO 606704973 - Miguel Ángel, no lo tengo. Me comenta Enrique que tiene que comprarse ropa de primavera y tiene que realizar limpieza del patio (desbroce de la hierba) además del mantenimiento del perrito (corte de pelo) No sé si llegará con lo que tiene semanalmente, pero le he dicho que se tiene que organizar e ir haciendo las cosas poco, según lo que tenga semanalmente... La ayuda a domicilio de momento muy bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-03-29','Ana: Envío correo-respuesta a Puerto, TS SSASB de Valdeobispo (ssb5@mancomunidadvalledelalagon.es):: "Muchas gracias. Esta misma mañana intento ponerme en contacto con Ricardo. En cuanto a la petición económica de Enrique, la semana pasada me llamó Ana Benavente, compañera del Equipo de Salud Mental de Plasencia. Enrique le hizo el planteamiento de necesidad de ropa y de productos de limpieza para el servicio de ayuda a domicilio. Le pedí que enviarán un presupuesto aproximado para que lo valoren en la sección económica. Justo hoy nos lo ha hecho llegar y solicitan: “doscientos euros adicionales para compra de ropa, zapatillas, productos de limpieza y pago de otras deudas”. No dicen nada del desbroce de las hierbas ni del corte de pelo del perrito. Como digo lo valorarán en la correspondiente sección y darán una respuesta en función de viabilidad. En caso que se lo aprueben, deberá administrarlo para todo lo que pide en esta ocasión. Tu respuesta me parece adecuada en términos generales y es la que habitualmente hay que darle, excepto cuestiones y momentos puntuales a lo largo del año y en función de la necesidad. Si él sigue pidiendo extras cada dos por tres, la sección económica comenzará a denegárselos a no ser que sea estrictamente necesario. Así pues, hay que intentar encontrar el equilibrio y hacérselo entender. Iremos viendo poco a poco cómo funciona y sus demandas. Me alegro que el SAD, al menos de momento, esté funcionando bien. Ojalá y que siga así." ················································· Respuesta de Puerto: "Enrique va a estar pidiendo "extras" continuamente, es su obsesión, entonces tiene que priorizar las necesidades y gastos porque no se puede gastar más de los que tiene... Respecto a lo que demanda esta vez te informo: - para la limpieza de la auxiliar del SAD ya ha comprado la legía con detergente (2), utensilio para quitar telarañas y fregona completa. Pagado lo tiene. - respecto a la ropa de primavera pues con el cambio de estación necesitará - para desbroce del patio sí es cierto que son unos 20 m2 de superficie que está en bruto y ahora con la primavera se llena de malas hierbas - la mascota de quique necesita cuidados (tiene el pelo lleno de nudos) y cuando le toquen sus vacunas. Pero como tiene 400euros mensuales para gastos de bolsillo, tabaco y desayuno, podría cubrir ciertos gastos de estos si se gestiona bien de lo que le sobre a la semana. Esto precisamente es lo que le he dicho... Aunque su demanda económica va a ser permanente y habrá que ir corrigiéndolo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-03-29','Ana: Correo de Ángel, A. Jurídico CTAEx, a Alberto, Óscar, Miguel, Maite y a mí: "Manuel ha enviado al correo de ctutelar la multa. En ella viene el lugar donde se puede hacer el abono. No sé si tiene dinero para abonar la multa, son 300 por pronto pago (si tenemos en cuenta que la ctaex ha tenido notificación vía correo electrónica ayer). Ya me decís."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-03-29','Amalia . Se recibe llamada y escrito de su hna. Mª José , no quiere que su hermano paso los fines de semana en la casa familiar en Badajoz . Contrastada toda la información con la terapueta y psicologa del CRR se confirma : que pasa 3 noches en el hostal Cervantes , la del domingo la pasa en su casa , solo va a dormir pq el hostal cierra . No puede volver al CRR pq no hay autobús los domingos . Las propias hermanas así lo solicitaron . Se acuerda subir a 750€ mes para que pase las 3 noches en un hostal .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2023-03-29','Ana: A fecha de 16/03, Óscar, Secc. Ecca., nos comunica que ha enviado el Inventario ya al Jdo. sin Informe Social, pues seguimos sin recibirlo. ·································································································································································································· Santiago tiene 24 años. Tiene reconocido un Grado de Discapacidad del 42%. Diagnóstico según el dictamen Técnico del CADEX: 1º Retraso Mental Ligero. 2º Alteración de la Conducta. 3º Anomalía Morfo-torácica. 5º Enfermedad del Aparato Circulatorio. ··················· No está valorado por Dependencia. ·················· Según consta en la sentencia, en el Informe Médico-Forense se detalla: "presenta autonomía en la gran mayoría del desarrollo de las actividades básicas de la vida diaria , con limitaciones , requiere apoyo total en las habilidades económico jurídicas administrativas contractuales, no requiriendo apoyo en el manejo de dinero de bolsillo , y sí requiere apoyo total en las habilidades de salud, como seguimiento de pautas adecuadas alimenticias , tratamientos médicos, consentimientos, etc." ·························· En la sentencia también se indica que vive con su madre, la cuál padece una enfermedad crónica. ················································· No le constan sueldos, pensiones, ni ninguna propiedad. ······························································································································································································ Envío correo con la derivación al Programa de Apoyo comunitario a Toni-Futex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-03-29','Ana: Mamen, TS de Centro Vida - Cáritas CC, nos remite Informe Social, que le ha solicitado María, CTAEx, para la Rendición Anual al Jdo. Al final del mismo indica: "Francisco ha vuelto a ingresar en nuestro centro de acogida temporal con fecha de 14 de marzo con los objetivos de reparación personal, restablecimiento de tratamientos médicos, como objetivo final, alquilar una habitación que es lo que el participante desea."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-03-30','Ana: Envío correo-e a Mamen, TS de Centro Vida, Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Muchas gracias. Mi compañera María lo remitirá al Juzgado con la rendición anual. Por cierto, aprovecho para comentarte que ayer llamó Francisco por teléfono y habló precisamente con María. Él le dijo que se va a un piso compartido de alquiler el día 1 de abril. Ya sé que me dijiste que era uno de sus objetivos, de hecho así lo indicas en el Informe, pero no esperaba que fuera tan inminente, por eso, agradeceríamos que nos confirmaras que es así y en tal caso si hay contrato legal y el precio del alquiler, pues de esto no le dijo nada." ································································································································································································· Correo-respuesta de Mamen: "En efecto desde el martes se ha puesto a buscar vivienda, me refiere que el Padre Gianni un sacerdote que ayuda a las personas sin hogar aquí en Cáceres), le tenía guardado dinero que Francisco había ahorrado (cosa que confirmo que es cierta con el Padre Gianni), ayer su madre le acompaño a ve una vivienda, y ha decidido quedarse con ella, en principio me refiere que le van a hacer contrato, así que quedo con él que cuando lo tenga me lo traiga lo escaneo y te lo envío. También he estado hablando con él el tema de que sea ayudado y apoyado por la Caritas Parroquial de donde va ha vivir, asi que hablares con los compañeros para que le echen una mano. En principio es lo que te puedo informar. Te adjunto un recibo que ha firmado con la cantidad que ha dado Francisco. Fianza. Se marcha el día 1 de abril al piso Te mantendré informada" ······························································································································································································· Respondo: "Decirte, eso sí, por si se lo queréis trasmitir, que el contrato, además de firmarlo él, debería firmarlo el representante legal (Presidente de la CTAEx). Por otra parte, sería bueno conocer el coste del alquiler (no sé si es la misma cuantía que la fianza) para que puedan reajustar en la sección económica su asignación y poder afrontar el abono del mismo sin problema. Y si hubiera contrato, quizá lo mejor sería abonarlo mediante transferencia desde su cuenta. Agradeceríamos que le comunicaras todo esto, que en persona se le explica mejor que por teléfono."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-03-30','TERESA ENVIO SOLICITUD DE ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-03-29','Ana: Correo de Tamara Sánchez, TS del IMAS- Ayto.CC (tamara.sanchez@ayto-caceres.es): "ayer pude entrevistar al Carlos y también he podido hablar con su padre, mañana tengo programa la visita domiciliaria, he recabado ayer toda la documentación que he podido. Un saludo, estamos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-03-30','Ana: Llamada de Mª Carmen, TS del HSPA (56283 / mariac.rodriguez@externos.salud-juntaex.es): comunica que Saturnino pide hablar con la Abogada, si no puede ir a verla, al menos que llame. Me facilita un nº para que la abogada llame para pedir cita: 927 25 69 65. ·················· Envío correo a Miguel, Asesor Jurídico solicitándole que lo trasmita a la Abogada Defensora. ············ Respuesta de Miguel: "Perfecto Ana, se lo reenvío a la abogada"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2023-03-30','TERESA SE ENVIA SOLICITUD VIA DECRETO PARA ACCEDER A PLAZA RESIDENCIAL EN JEREZ DE LOS CABALLEROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2023-03-30','-Amalia : Queda pendiente que Eva me confirme que acceden a los 480€/ anual para extras . No ha gastado nada en todo el año. Se acepta desde el centro , se lo paso a la seccione eco para que procedan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-03-30','Ana: Llamada de Juan Manuel, hermano de José Blas (687 819 309 / jmcl1966@hotmail.com). Le comunico que el expediente de su hermano se ha aceptado recientemente y aún está en periodo de inventario (el Jdo. nos da 60 días para elaborarlo). ··········· Me informa que José Blas vive con su madre, quién es ya mayor y está delicada de salud. La convivencia está un poco deteriorada, entre otras cosas, por episodios de agresividad/violencia de José hacia su madre. Ahora está más tranquilo. ·················· Asiste a CO a Centro Down - CC. ·················· Tiene pareja desde hace 20 años y muchas amistades. Está muy arraigado en Cáceres y pide que no se le saque de allí, pues sería contraproducente para él. ···· Hace años tuvo una ruptura de pareja (con la chica actual, con la que volvió después) y entró en depresión. ····················· Considera que el recurso ideal para él sería Vivienda Tutelada. Le indico que en la ciudad de Cáceres no hay a día de hoy. ·················· La otra opción que se ha planteado sería que compartiera piso con otra personas del centro en situación similar. ··················· Estudiaré el expediente y la situación. ··········· Por lo pronto haré derivación al Programa de Apoyo Comunitario gestionado por Futuex. ············· El teléfono fijo de casa de su madre es: 927 24 89 86.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2023-03-30','-Amalia : contacto con Adela de PNC . Los meses de agosto 2022 y enero 2023 se han ingresado en la cuenta que Macarena abrió en B. Santander. En febrero 23 , sección eco ha abierto otra nueva en Ibercaja y se empieza a percibir aquí desde febrero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2023-03-30','-Amalia : contacto con Adela de PNC . Los meses de agosto 2022 y enero 2023 se han ingresado en la cuenta que Macarena abrió en B. Santander. En febrero 23 , sección eco ha abierto otra nueva en Ibercaja y se empieza a percibir aquí desde febrero.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-03-30','Amalia : Escribo a CRR se autoriza la subida mensual para que Manuel pueda pasar 3 noches en hostal , pasa a 750€. Si el domingo el Hostal Cervantes no abre se le puede buscar otro para esa noche o cambiar las 3 noches al mismo . Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-03-30','Amalia : Escribo a CRR se autoriza la subida mensual para que Manuel pueda pasar 3 noches en hostal , pasa a 750€. Si el domingo el Hostal Cervantes no abre se le puede buscar otro para esa noche o cambiar las 3 noches al mismo . Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-03-30','Buenas de nuevo, respecto de Fco Casillas, desde CRR Mérida nos confirman la entrevista inicial en el recurso para el jueves 30 de marzo, nos informa el director (Javier Pecero) que la entrevista será para conocer a Francisco y para que él conozca el recurso, la duración total de la misma será de una hora y media aproximadamente. También nos comunica vía telefónica que el ingreso se concretará otro día. Esto nos dejó un poco frías, dadas las caracteristicas del caso, que corra el riesgo de no querer volver.. además del coste del desplazamiento, que ahora hay que hacer en dos dias distintos, pero dicen que son las normas del recurso y nada se puede hacer... Pedimos presupuesto y disponibilidad con un taxista cercano a la localidad (Francisco López). La cuantía del traslado es 60 euros aproximadamente, se incrementa un poco el presupuesto ya que tiene que esperar el tiempo de la entrevista para el retorno a Oliva de Mérida. El pago será por transferencia bancaria, le solicitamos que nos facilite la factura cuando la tenga por correo electrónico. Teléfono Francisco (taxista): 600 50 38 22 Por último nos ponemos en contacto con Juan Manuel (Policía Local de Oliva de Mérida) para que pueda informar a Francisco de la cita para la entrevista y nos espere en el ayuntamiento a las 10:30 horas mañana. Desde el programa de apoyo social comunitario le acompañaremos durante el trayecto y la entrevista. Trasladamos la información a la Trabajadora Social de SSB, ya que la coordinación con este recurso ha sido primordial en todos los seguimientos y gestiones, puesto que con el no se puede contactar. --','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-03-30','Buenas de nuevo, respecto de Fco Casillas, desde CRR Mérida nos confirman la entrevista inicial en el recurso para el jueves 30 de marzo, nos informa el director (Javier Pecero) que la entrevista será para conocer a Francisco y para que él conozca el recurso, la duración total de la misma será de una hora y media aproximadamente. También nos comunica vía telefónica que el ingreso se concretará otro día. Esto nos dejó un poco frías, dadas las caracteristicas del caso, que corra el riesgo de no querer volver.. además del coste del desplazamiento, que ahora hay que hacer en dos dias distintos, pero dicen que son las normas del recurso y nada se puede hacer... Pedimos presupuesto y disponibilidad con un taxista cercano a la localidad (Francisco López). La cuantía del traslado es 60 euros aproximadamente, se incrementa un poco el presupuesto ya que tiene que esperar el tiempo de la entrevista para el retorno a Oliva de Mérida. El pago será por transferencia bancaria, le solicitamos que nos facilite la factura cuando la tenga por correo electrónico. Teléfono Francisco (taxista): 600 50 38 22 Por último nos ponemos en contacto con Juan Manuel (Policía Local de Oliva de Mérida) para que pueda informar a Francisco de la cita para la entrevista y nos espere en el ayuntamiento a las 10:30 horas mañana. Desde el programa de apoyo social comunitario le acompañaremos durante el trayecto y la entrevista. Trasladamos la información a la Trabajadora Social de SSB, ya que la coordinación con este recurso ha sido primordial en todos los seguimientos y gestiones, puesto que con el no se puede contactar. --','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2023-03-30','Respuesta de seccion eco : La cuenta no vamos a poder cerrarla porque la titular principal entiendo que debe ser la madre, según me comentó ella hace unos meses. Vamos a intentar quitarle de titular, pero Ibercaja ya nos lo ha negado en varias ocasiones a tutelados en la misma situación: son titulares de una cuenta de sus padres y éstos dejan de realizar ingresos o percibir pensiones por estas cuentas y empiezan a generar deuda. Además, la oficina a la que corresponde la cuenta ya no existe; enviaré el escrito a la oficina de Mérida a ver si nos hacen un poco más de caso o, al menos, que nos digan a qué oficina dirigirnos. MARIA DE LOS ANGELES GALINDO BARRENA Me comenta mi compañera Carolina que continúa recibiendo llamadas de la empresa externa que tiene contratada el banco para exigirle la deuda que tiene Ricardo Rocha Barco con ellos. Necesitamos, por favor, que anuléis dicha cuenta lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-03-30','Ana: Llamada de Doroteo (609 928 621): Cuestiones eccas.: Tiene una deuda en El Corte Inglés de 17,40 € ············· Por otra parte, dice que Virginia, Ed. Futuex, va a enviar factura de unas gafas de cerca, pero que lo ha pensado bien y le parecen muy caras (100€), dice que buscará otras más económicas. ································· Por último dice que ya lleva 6 meses en Alcuéscar y ya se quiere ir de allí. Quiere irse a vivir a un piso de alquiler solo a Cáceres. ········· Le digo que cuando nos remitan un informe favorable desde el centro lo valoraremos. ············································································································································································································· En relación a la deuda con El Corte Inglés, Óscar, Secc. Ecca., me informa que no llegó a abonarse, porque nunca dijeron cómo hacerlo. *Se le planteó, que cuando él pueda, lo abone con su asingación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2023-03-30','TERESA Me ha comentado la chica que va a limpiar la cada de Cándido que lo encuentra muy delgado y con mal aspecto, Nosotros tenemos una curatela económica pero ya que no tiene a nadie igual hay que al menos indicarle que pida cita para médico y le vean….','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-03-29','Ana: Maite y yo volvemos a llamar a Javier (624 109 525), a pesar de volver a darnos la razón a cada argumento que planteamos, para que vuelva a Plasencia y pueda volver a marcharse otra vez con todo bien organizado (alojamiento, dinero, atención sanitaria...) él insiste en que "no puede volver a Plasencia".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-03-30','Ana: Llamamos a Carolina, Psicóloga y Directora en funciones del CRR-Plas. (673 22 55 27). Ellas también han hablado con Javier, y éste se mantiene en el mismo discurso. ············ En cuanto al dinero, plantea que puedan enviarle ellas mediante Giro postal el dinero del extra anual que tiene en el piso. ····· Lo hablaremos con Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-03-31','Ana: Correo-e de Mamen, TS de Centro Vida, Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Te informo que Francisco Cacho no se va ya al piso que alquilo en otro día, me ha enseñado unos wasap de esta persona y le dice que la chica que esta en estos momentos y que supuestamente se iba a marchar y entrar él, ya no se va, por lo que Paco no puede entrar en el piso el día 1 de abril. Paco el ha solicitado la devolución de su dinero (que aunque en el recibo pone 200, refiere que le día también 220 y eso ya no lo pone el recibo), en fin que le ha reclamado 420€, pero este chico le contesta todo vía wuasap que no puede devolverle el dinero hasta el día 10 de abril que cobra el paro. Desde nuestro centro le hemos orientado a que denuncia, no se que hará, esta muy nervioso. un desastre tras otro." ························· Lo traslado a Ángel, A. Jurídico, por si considera comunicarlo al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-03-31','Ana: correo de Cruz Merino, TS SSASB (cruzmerino@tajosalor.es): Este tema no es estrictamente económico, pero tampoco creo que sea de tu servicio, pero no sé exactamente a quién debo dirigirme. Es relativo a Juan Gregorio Lozano Valle y al perro que éste tenía antes de ir a la residencia. Me ha reenviado la policía local un acuerdo de cesión, que la perrera le ha hecho llegar, para poder dar en adopción al perro que aún sigue en la perrera. No sé si debe autorizarlo el Gerente del SEPAD, como representante de Juan. Te lo envío y ya me dices que se hace en estos casos." ·············· Reenvío el correo a los A. Jurídicos, para que nos indiquen cómo proceder. ······························· Respuesta de Ángel que le reenvío a Cruz, TS: "El modelo que envían es un tanto escueto.., faltan algunos datos: nombre del perro, número de microchip, algún dato que lo identifique, firma de la Asociación, especificación que la cesión es para adoptarlo. Una vez tengamos esos datos, lo pasamos a la firma de JV."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-03-31','Ana: Correo de Toni-Futuex, en relación a la cita con el Médico Forense: "Lo de Ventura, está comunicado y parece que accede a que se le acompañe el lunes, asique bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-03-31','Ana: Correo de ayer a última hora de Toni-Futuex: "Y comentarte brevemente, hoy se ha recibido una llamada en Futuex, de la estación de buses de Badajoz, indicando que estaba alli un señor que pedí hablar con alguien... era Mediavilla. Se ha venido de Caceres a Badajoz, y luego su idea era coger un bus para Olivenza, para no se que de traer un "sujetador" a no se quien a una tal Helena, me ha parecido entender, porque lo he atendido yo. Está sin móvil se lo ha olvidado en Cáceres, y pedia (que para eso ha llamado ) que fuera alguien a buscarlo o que se le pusiera un taxi.. todo muy esperpentico. Ha llamado dos veces. Supongo que finalmente regresara esta tarde a Cáceres, pero es cierto y esto ya me lo habia avanzado la compañera, que se toma el trakimazin y le sienta fatal, cuesta hasta entenderle.. Estuvieron esta semana en el medico de primaria (que les trato un pco mal) que es quien le pauta el trankimazin, a pesar de que su psiquiatra se lo ha quitado. Pero la medica decia que si no se lo manda no se va de alli y que es muy demandante y bueno ya sabemos... Entre su patología y que muchas veces es imposible una intervencion eficaz con el, desde los diferentes recursos de la comunidad pues ya sabes.. Asique nada, mañana, lo llamara su educadora de referencia.. y a ver si podemos elaborar nota, con la visita del otro dia a su medico, que era para recabar el informe para lo de centro que le habia pedido Pilar Martin... a ver si le dan algun recurso otra vez (aunque estara dificil) pq esta otra vez fatal..." ············································ Contesto a Toni y le informo sobre lo que nos transmitió ayer Raquel Gómez, Secc. Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2023-03-31','Ana: Llamada de Felipe (617 688 763): se va el lunes a la Romería de su pueblo. ···· Le confirmo que se le han concedido el extra de 200€ que solicitaron desde el centro (Novaforma). Podrá retirarlo el mismo lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2023-03-31','TERESA ENVIO CAMBIO DE PERFIL Y TRASLADO DE EXPEDIENTE AL CADEX DE VBADAJOZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2023-03-31','Ana: Llamada de Nuria, TS del EVD-Trujillo (54513): Ha ido a valorar a Andrés a la Residencia Sta. Marta de Magasca. Pregunta si en el PIA plantea Prestac. Ecca. Vinculada a SAR y Plaza Pública en al misma residencia. ·················· Revisando la anotaciones, veo que Andrés en su día solicitó plaza pública en Malpartida de CC. ········ Nuria me lee extractos de Informes Sociales previos. NO era conveniente que los dos hermanos (Dionisio y él) convivieran juntos pues Dionisio le anulaba por completo, lo tenía totalmente sometido. ············· Lo hablaré con Estrella, TS SSASB Malpartida. ············· *En principio se solicitará Vinculada y plaza en al residencia donde está. ····················· *En la sección económica tiene que hacer de nuevo la ficha, pues ya tienen acceso a todas las cuentas e incluso a un fondo de pensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2023-03-31','Amalia se le dará un extra anualde 480€ que incluirá todos los extras y se getionará desde el centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-03-31','Ana: De la farmacia envían a ctutelar@ Informe del Hptal. José Manuel se ha resbalado en el baño y se ha caído. Le han indicado reposo, ponerse frío y "Reflex". Se autoriza la comprar. ············ Hablo con José Manuel, le confirmo que puede pasar a la farmacia a recogerlo. ··············· Se le entiende fatal. Dice que ha tomado el Trankimazin, le digo que por qué lo toma si el Psiquiatra dijo que no debía quitarlo y se lo quitó de la receta. Dice que se lo ha pedido a la MAP y ésta se lo ha recetado. ········· Pero dice que Virginia - Ed. Futuex, ha hablado ya con la médica y ya no se lo va a recetar más. ··············· Pide irse una semana de vacaciones a algún sitio. Se valorará más adelante, ahora mismo no se le va a conceder, está muy reciente la retirada que hizo sin permiso. ············ Cuenta también que a una de sus hermanas le ha dado un infarto y está ingresada en la UCI. ················ Con respecto a la Solitud de CRR, le transmito lo que nos dijo ayer Raquel, Enfermera de la Secc. de Salud Mental. ··· Responde que entonces quiere irse de alquiler a una casa de planta baja. ······ Le digo que puede empezar a buscar y cuanto encuentre alguna habrá que valorarlo con la sección económica y, en su caso, con la Secc. Jurídica para firmar el contrato.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-03-31','Ana: Correo de Ángela, sobrina de Arturo (angela.platero@madrid.org): "ayer miércoles 29 de marzo estuve en la Residencia de Santiago de Alcántara porque le hicieron a mi tío (ARTURO JOSE ROCHA MERCHÁN ) la revisión del grado de dependencia, la persona que lo valoró estimó que el estado de salud había empeorado, y que para el traslado a otra residencia tenia que solicitar que le hicieran una adaptación del PIA. Estas son la residencias que hemos mirado y que están próximas al pueblo.- USAGRE.- (también se las facilité a la persona que hizo la valoración). 1. RESIDENCIA DE MAYORES DE CAMPILLO DE LLERENA C/ Valdefierro S/N 06443 Campillo de Llerena (Badajoz) 2. RESIDENCIA DE MAYORES ALCALDE JOSÉ GONZÁLEZ BARRERO C/ Virgen de Guadalupe S/N 06300 Zara (Badajoz) 3. RESIDENCIA DE MAYORES ALCALDE ANTONIO ZAPATA C/ Las Monjas, 1 06230 Los Santos de Maimona (Badajoz) 4. RESIDENCIA DE MAYORES NUESTRA SEÑORA DE GUADALUPE Plaza de la Cruz, 1 06240 Fuente de Cantos Badajoz"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-03-30','Ana: Correo de Óscar: "Se ha pagado al centro 8.025,26€ de atrasos y a partir de abril le cobrarán la cuantía de dependencia incluida en la cuota del centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-03-31','Ana: Correo de Tamara Sánchez, TS del IMAS- Ayto.CC - IMAS ZONA ZONA CENTRO (tamara.sanchez@ayto-caceres.es // TF: 927 212335 - ext 4414): "Acabo de enviar a los compañeros el informe para que os lo hagan llegar. he recopilado toda la documentación que me solicitabais en el informe, te la adjunto en este email para que la tengáis, en ella también va un extracto bancario que me ha proporcionado el padre de Carlos." ··································································································································································································· Según el AUTO de Provisión de Medidas Judiciales de apoyo: "...necesita asistencia en los actos relativos al ámbito médico sanitario en todo lo que afecte al control de la medicación, seguimiento de tratamiento médico y farmacológico, asistencia a las citas médicas o para entrevistarse con los profesionales médicos para tratar temas relativos a su salud; y requiere supervisión completa para adoptar decisiones relativas a ingresos hospitalarios, consentimiento informado en el ámbito de la salud o en otras leyes especiales o tratamientos médicos de importancia; así como para la realización de actividades de orden o con trascendencia económico-jurídico-administrativo, como prestar juramento, efectuar gastos, administrar ordinariamente sus bienes, celebración de contratos administrativos públicos, interponer demanda, actos de disposición o gravamen, seguimiento o control de sus cuentas corrientes, efectuar transferencias, otorgar poderes, celebrar negocios jurídicos complejos gratuitos y onerosos, suscribir contratos, decidir cantidades semanales de dinero que manejar para atender sus necesidades básicas, facultando al curador para solicitar todo tipo de ayudas y prestaciones económicas, sociales y asistenciales que puedan corresponder..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-04-03','Ana: Subo al portafirmas digital la SOLICITUD DE TELEASISTENCIA municipal remitida por Julia Durán, TS del Hogar Peña del Cura. ··············································· Envío correo a Oficina de Atención al Ciudadano - REGISTRO (oac.merida.san@juntaex.es): "Adjunto remito SOLICITUD DE SERVICIO DE TELEASISTENCIA MUNICIPAL relativa a D. VENTURA GÓMEZ GARCÍA, cuyo cargo ostenta la CTAEx. Así mismo, adjunto la siguiente documentación que hay que enviar junto con la solicitud: - Informe Médico - Archivo con documentación varia: o DNI o Tarjeta Sanitaria o Certificado de Discapacidad o Dictamen Técnico - Testimonio Aceptación del Cargo - DNI – Representante Legal - Decreto Nombramiento D-Gerente - Resolución Delegación de Competencias Hay que remitirlo al INSTITUTO MUNICIPAL DE ASUNTOS SOCIALES del Ayto. de Cáceres C. Atahualpa, 10, 10005 Cáceres"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-04-03','Ana: Correo Estrella, Aux. Adtvo. Secc. Ecca. a Sheila, Directora del CRR-CC (crr@grupociudadjardin.com): "Buenos días, se informa que desde la sección económica se autoriza el presupuesto dental de Félix. Contamos que el total del presupuesto sería 640 €. Ruego me envíen por correo electrónico las facturas a mi atención, para su posterior pago."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2023-04-03','Buenos días, desde la sección económica se autoriza el presupuesto por importe de 1.350€ para el tratamiento dental. He llamado a la clínica para el tema del pago.Saludos.(Estrella )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2023-04-03','TERESA Como sospechábamos, abrió una cuenta en Caja Almendralejo de Monesterio en octubre. En esa cuenta cobró la pensión y extra de noviembre y la pensión de febrero. Contrató una tarjeta (envío escrito para cancelación), ha realizado reintegros (en el mismo escrito se limitan) y ha pedido un préstamo rápido de 300€, por ahora. Debe haber generado deuda de la tarjeta porque tiene varios cobros por impagos de la VISA.','2');
