insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-04-03','Ana: Llamada de Antonio, padre de Carlos (653 177 271): Me facilita un nº de cuenta de su hijo, dice qué el también está de titular, pero que el dinero es sólo de su hijo, es por la que cobran los suministros de la vivienda. El padre me dice literalmente “lo van a tener ustedes muy mal con él”. Dice que él ya no puede más. Que estuvo unos días ingresado en el hospital por sus problemas de salud y su hijo aprovechó para sacar 8.000 €. Tiene deudas con ORANGE de productos que ha financiado (4 o 5 ordenadores, tables, móviles, patinete eléctrico…). Ya le dio en su día 5.000 € para que saldara las deudas, pero no sabe si lo abonó o qué hizo. Percibe una PNC, pero él ha estado dándole dinero aparte para comer. ············· Por otra parte, dice que en casa tiene armas: pistola de bolas y cosas así y armas blancas, como machetes. Dice también que es muy grande, mide 2 metros. Y alguna vez ha tenido que llamar a la Guardia Civil ante la agresividad de su hijo. ······························································································································································································ Envío correo con toda la información ecca. a Alberto e Icíar, Secc. Ecca. ····························································································································································································· Recibimos INFORME SOCIAL de Tamara Sánchez, TS del SSASB (tamara.sanchez@ayto-caceres.es): en el mismo dice que vive solo en Cáceres, en una casa que era propiedad de sus padres (C/Caupolicán nº 7 Piso 2 D). Expresa que no tiene hipoteca, se hace cargo de los gastos de suministros. ········· Carlos no tiene expediente abierto en Servicios Sociales. Unidad familiar unipersonal, Carlos de 31 años es soltero y sin cargas familiares. Ha vivido siempre con su madre hasta que ésta ha fallecido en el año 2019. "En la entrevista se denota que relación con su progenitor no es buena, hace referencia que tiene interpuestas denuncias contra él y está pendiente de juicios". "Comenta que fue adoptado cuando tenía 5 años por Antonio y Juana." ····· Sus ingresos proceden de una Pensión no contributiva. Estudió hasta 2º de la ESO. No ha ejercido ninguna actividad laboral. ········· grado de discapacidad del 66% por sufrir retraso mental ligero y alteraciones de conducta. ························································································ Entre los documentos que envía la TS se encuentra un recibo de un abono bancario para licencia de armas. Pólizas de Seguro de Decesos y del Hogar. Y otros documentos personales. ···································································································································································································· Alberto, Jefe Secc. Ecca., me comunica que darán de baja el contrato de Orange. ···················· Icíar esperará a que se lo hayan comunicado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-04-03','Ana: Correo de Sonia BerNabé, TS ASINDI (trabajosocial@asindi.e.telefonica.net): Nos remite INFORME para la Rendición Anual. *Se pidió a la UHDAC, pero desde allí les han pedido a ellos que lo hagan y nos lo envíen, a pesar de que Aarón ya lleva mes y medio en dicha unidad. ·················· En el informe narran la situación que ya conocemos. *No hacen alusión a su ingreso en la UHDAC. ········· Se lo dijo a Óscar, Secc. Ecca., para que lo indique en la Rendición.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-04-03','TERESA adjunto lo referente a las gestiones efectuadas con Pablo Galan Gilgado así como, las facturas de taxi tanto de ida como de vuelta. Fue todo finalmente bastante bien! aunque el dia seiguiente de su llegada se emborrachó. 21/03/2023: Presencial – Zalamea Serena Tal y como se había planificado, esperamos a Pablo en la plaza del ayuntamiento en Zalamea Serena. Llega en taxi (Antonio, taxista Alcuéscar 666916410). Trae el tratamiento preparado en bolsitas distribuido por días acompañado con la hoja de tratamiento en la que figura también el número de teléfono de Julia y de la enfermera de la casa Misericordia. Acudimos a la farmacia de referencia en la localidad para ver la posibilidad que sean ellos quienes suministren dicho tratamiento a Pablo como se hacía anteriormente. Acceden sin problemas, Pablo debe acudir por la mañana para tomar las pastillas del desayuno y se lleva la ½ pastilla de la hora de comer, después, sobre las 19h tiene que volver a la farmacia para tomarse la pastilla de la cena y llevarse la pastilla que le toca antes de dormir. De esta manera nos aseguramos al menos dos tomas diarias, ya que se las toma en la farmacia. Se realiza acompañamiento a retirada de dinero, en esta ocasión son 50 euros. Con dicho dinero se realizan las siguientes gestiones: - Compra de tabaco: 6 euros. En el centro consume 10 cigarrillos al día, por lo tanto, intentamos que mantenga el hábito. Hablamos con el estanco y se le compra 2 paquetes de 20 cigarrillos que se va a gestionar desde el estanco. El miércoles tiene que ir a buscar 10 cigarrillos y el jueves otros 10. El otro paquete se lo damos nosotros el viernes para regreso al centro. - Compra alimentación: 25.05 euros. Se realiza compra de alimento con previsión para 3 días. Pablo indica que en su domicilio aun tiene comida no perecedera. En efecto, en su domicilio tenía: 2 bolsas de café, 2 de azúcar, 2 de arroz y varias latas de conserva. - Recarga de teléfono móvil, tarifa symio: 10 euros. - Desayuno pagado para miércoles y jueves: 3 euros. En el centro se ha acostumbrado a comer en el desayuno y nos pidió si podíamos darle dinero para desayunar en el bar. Como no puede manejar dinero por el riesgo al consumo de alcohol, le dejamos pagado dos desayunos en el bar que suele frecuentar. Café + churro. - Café al llegar a Zalamea: 1.20 euros. Total gastos: 45.25 euros. Dinero sobrante: 4.75 euros. Se entregarán el viernes para que los deje en centro. Por otro lado, se destaca que Pablo está bastante convencido que tiene que regresar al centro el viernes. Sabe que estos días son como unas vacaciones y solicita volver una semana en verano. En cuanto a la vivienda, se encuentra bien, algo sucia pero normal al estar tantos meses cerradas. Tenía luz y bombona, pero el agua estaba precintada por Aqualia. Para tres días es muy complicado volver a dar de alta el agua, incluso es el mismo Pablo quien nos indica que lo dejemos así, pues tiene dos bidones llenos en el corralón y su vecina le ha dado dos garrafas de agua para beber y cocinar. Para finalizar, también se gestiona el servicio de taxi de regreso a Casa Misericordia con Manuel de Zalamea, el viernes a las 10:45h. 24/03/2023: Presencial Zalamea Tal y como se había planificado previamente por teléfono, acudimos al domicilio de Pablo para comprobar que deja todo recogido y bien cerrado en la vivienda. Seguidamente acudimos a la farmacia de referencia para comprobar si Pablo había cumplido con lo establecido. Nos indican que faltó la tarde del miércoles. Dicho miércoles entorno al mediodía, mediante una llamada de teléfono percibimos que Pablo ya había consumido alcohol. Se paso todo el día llamando por teléfono a la casa Misericordia y al equipo de apoyo social comunitario. Se destaca que ni vecinos ni personas de referencia en la localidad nos transmiten quejas ni incidencias causadas por Pablo durante estos días. A las 10:30h lo recoge el taxi en la puerta del Ayuntamiento (Manuel taxista de Zalamea). En una carpeta le guardamos para que entregue en el centro, un paquete de tabaco, un sobre con el dinero sobrante 4.75 euros, el DNI, la hoja de tratamiento y las pastillas que no se tomó. Esta carpeta la guarda Manuel para entregarla en mano en el centro. Para finalizar, el comportamiento de Pablo fue el correcto, estaba convencido que tenía que volver al centro y volverá de vacaciones a su localidad unos días en verano.','2');
