insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-04-03','Ana: Llamada de Julia (644 89 73 39): solicita un extra de 100€ por su cumpleaños (es el 17 de abril). ·········· Traslado la petición a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-04-03','Ana: Correo de Ana Mª, Ed. Social Plena Inclusión Zafra (social@plenainclusionzafra.org): "Te escribo referente a Remedios, Ha acudido a su medico hace una media hora porque tenía fiebre alta. Ante la sospecha de que pueda ser Neumonía o bronquitis, y para descartar una posible ingesta, la derivan al hospital para hacer radiografía. En el caso de que sea neumonía, la quedarían ingresada. Si esto fuera así como debemos proceder?? Hay posibilidad de que Reme costeé un profesional con ella, que la acompañe en hospital?? Estamos barajando las distintas opciones, dada la hora que es y las circunstancias que se nos pueden dar." ·································· Confirmo que sí podría costear un acompañamiento hospitalario si fuera necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-03-31','Ana: En reunión con Alberto, Jefes secc. ecca, Maite y yo acordamos con él: Se autoriza a la Directora del Piso Supervisado para que le remitan por GIRO POSTAL, la mitad del dinero que tiene en el piso, correspondiente a su extra anual (concepto por el cuál Javier no podrá volver a pedir dinero este año). Después, si siguiera viviendo en Tarragona, se le abrirá cuenta en otra entidad bancaria en la que pueda retirar dinero allí y se le hará autorizaciones periódicas de retirada semanal, por el importe total mensual de la suma de sus pensiones, para que pueda vivir dignamente allí, como es su deseo. ······························································································································································································ Maite y yo llamamos a Javier (624 109 525) varias veces, pero el teléfono está apagado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-04-03','Ana: Llamo varias veces a Javier (624 109 525): La llamada dos tonos y después una locución dice que le móvil está apagado o fuera de cobertura. ····································· Llamo a Carolina, Psicóloga-Directora CRR y PS (673 22 55 27), ellas tampoco han conseguido contactar de nuevo con Javier. ·············· No sabe exactamente cuánto dinero tiene Javier en el Piso de su extra anual, eso lo lleva Mónica, Ed., y ésta está de vacaciones esta semana. Acordamos que le enviarán entre 700 - 800 € mediante Giro Postal, nos confirmarán por correo. ··········· La primera que consigamos hablar con él le consultaremos en qué oficina de correos le viene bien y si también es factible la Sucursal de Ibercaja de la C/ La Unió para la apertura de nueva cuenta en esta entidad bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2023-04-03','Ana: Correo de Paula, TO, CRR-Plas: Buenas, os escribo para comentaros que Mª Angeles Santos Urbano se va unos días de vacaciones a su pueblo (del miércoles 5 al sábado 8 de Abril). Como siempre, hemos trabajado con ella habilidades para que mantenga los autocuidados en el domicilio y pueda disfrutar de su estancia con su padre durante estos días."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-04-03','-Amalia , aclaro lo del tto. dental con Mª Jesús y envio email a los compañeros. Buenos días , me pasó Oscar los dos presupuestos dentales que en su día presentó Mª Jesús , había otros más de Mérida. De ellos ella solicitó el de Vivanta , a pesar de ser más caro, incluía un tratamiento mucho mayor que ella necesitaba. Se estudió viabilidad económica , y se autorizó el de Vivanta llegando a un acuerdo con ellos ;transferencia de 1000€ y financiar el resto a 36 meses 80€ . Ya autorizado , decidió dejarlo para que se le pudiera dar más dinero mensual . Hablé con ella y le expliqué el acuerdo para que siguiera haciendo el tratamiento. He conseguido hoy hablar por tf. , ha cambiado el Numero , me lo ha facilitado su tia 610843541- Me confirma que la dentista que va es al de Carmen Delgado , en la C/ San José . Dice que ella habló con alguien para decirlo , que no se acuerda con quién . Que no quiere estar tutelada ni dar explicaciones de lo que hace . Por lo tanto , entiendo que habrá que reclarmar el dinero entregado en Vivanta puesto que allí no está acudiendo . Y pagarle ese dinero a los de la clinica de Carmen Delgado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2023-04-04','-Amalia : LLega resolución PNC concedida , 486€ al mes .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2023-04-04','-Amalia : LLega resolución PNC concedida , 486€ al mes .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-04-04','Ana: Correo de Ana Mª, Ed. Social Plena Inclusión Zafra (social@plenainclusionzafra.org): "A Reme finalmente la quedaron ingresada, está bastante fastidiada, creemos que una semana podría permanecer en el hospital. La placa que le hicieron es bastante dudosa pero se ve una mancha en pulmón y se ve que hay infección. Está con oxígeno, probaron por la tarde a quitárselo pero enseguida se lo tuvieron que poner porque por si sola no podía y la saturación otra vez se bajaba. Ayer encontramos una chica que se quedó con ella desde las 5 hasta ahora por la mañana, dentro de un rato que irá la profesional de referencia de Reme de la mañana para quedarse con ella y a la espera de encontrar a alguien más que pueda quedarse con ella y hacer turnos porque las horas allí con una supervisión tan estrecha como necesita Reme, se hacen difíciles. A la familia la avisaremos de que finalmente la quedaron ingresada durante la mañana. No sabemos si la familia estaría dispuesta a hacer ese acompañamiento y en ese caso si procede que hagan ese acompañamiento?? Lo han hecho en otras ocasiones?? Cualquier novedad al respecto os iremos informando y cualquier cosa que debamos tener en cuenta, por favor,…lo mismo hacerlo saber" ···················································································· Mi respuesta: "...Con la familia no se puede contar para nada de esto. Está bien que se lo comuniquéis para que lo sepan y por si quieren ir a verla, pero nada más. Espero que encontréis a más de una persona dispuesta a hacer el acompañamiento. Y en el peor de los casos, se puede preguntar en alguna empresa privada aunque resultase más caro." ······································································· *Nuevo correo de Ana Mª, Ed. P.I. Zafra: "Acabo de confirmar con una antigua trabajadora nuestra, que entre ella, su hermana y quizás una sobrina cubrirán las 24 horas del día, de aquí al lunes como muy pronto. A partir del lunes, veríamos como seguir gestionando, en caso de que siga ingresada. Reme de ánimo está bien, en principio está tranquila, pero está bastante agarrada, la tos ha empeorado y se fatiga mucho." ···························· Mi respuesta: "Cuando estuvo ingresada en el Hospital de Plasencia, finalmente no se le puso acompañamiento por las noches. Así, que si os parece bien, se puede poner una noche más, para corroborar que sigue tranquila y no es necesario y a partir de ahí, que se haga sólo en las horas necesarias. Dime qué os parece."','2');
