insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2023-04-03','Ana: Correo de Esther, TS del SSASB Alcuéscar (tsocial7@mancomunidadsierrademontanchez.es): "Te envio el documento que me ha facilitado el hermano de ANTONIO HIDALGO ROMO, para pensión de jubilación del extranjero, también comentarte que se ha registrado el escrito del hermano para poder visitar la vivienda y comprobar su estado." ···························· Paso todo a Teresa, TS CTAEx, pues desde que pasó el periodo de adaptación en el Centro le corresponde a ella el seguimiento del expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2023-04-04','Amalia . LLaman de SADEX 618552660 , Rosa salió el domingo por la tarde y se desorientó . La encontró la policia que la llevó al hospital . Se piden ptos que cubran más horas de tarde y noche . La mañana está cubierta por Isabel y algunas horas de la tarde. Tiene en cuenta 114.000 , se puede mantener en su domicilio un par de años más como es su voluntad .Tiene 89 años .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-04-04','Amalia ; Se ha abierto nueva cuenta con 2 titulares Santiago y J.Vicente . El propio banco se encarga de hacer el cambio de Nº cuenta en la pension.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-04-04','Amalia : Llama la madre y su hermano Pedro , han ido al banco y no le han dado el dinero . Pregunto en la sección eco que me confirman que han enviado el reintegro a todas las oficinas , pero aún así lo vuelven a mandar . Respuesta de eco : Ya se envío el 28 de febrero a todas las oficinas de Unicaja de Badajoz, ya que no sabíamos a cuál iba a ir. De hecho, el mes pasado si se lo dieron, en la oficina de la Avda. de Europa. Otra cuestión es que quieran sacar todo el dinero, como habían hecho en BBVA. El límite que se fijó fue de 200€, para que recuperara parte de los más de 8.000€ que sacaron en verano. ----------------------------------------------------- Les llamo para confirmar si han podido retirar el dinero . Le han dado los 200€ pero Pedro se queja de que quiere sacar más . Le indico que esta cantidad se ha visto reducida porque durante muchos meses ha estado sacando más de los 330€ que tenía estipulado . Me dice que ese dinero lo ha gastado en ropa para su hermana y nos acusa de estar quedándonos los de " la Junta " con el dinero de su hermana . Que nos va a denunciar . Que está preparando todo para ser él el tutor .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-04-04','-Amalia : reenvio sentencia de aceptacion de ingreso en UHDAC a la TS del centro N.S.La Luz , Maite y Soraya . De momento no al CSS .','2');
