insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-04-04','Ana: Maribel, TS de la Secc. de Discapacidad, nos comunica que le han concedido plaza en RAE en Plena Inclusión Mérida. *NO sabíamos que lo tenía solicitado. ····· Al parecer la solicitud estaba firmada por la madre. ················ Maite habla con Andrés, Director-Gerente de Down-CC: Éste le dice que no va a querer trasladarse a Mérida. Dice que tiene hecha su vida allí. *La idea de que se trasladara a un piso de alquiler, si encontrase con quien compartir, le parece muy bien, pues dice que es muy autónomo. Con apoyo de otros servicios como SAD y seguimiento, podría resultar.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-04-04','Ana: Maribel, TS de la Secc. de Discapacidad, nos comunica que le han concedido plaza en RAE en Plena Inclusión Mérida. *NO sabíamos que lo tenía solicitado. ····· Al parecer la solicitud estaba firmada por la madre. ················ Maite habla con Andrés, Director-Gerente de CO Down-CC: Éste le dice que no va a querer trasladarse a Mérida. Dice que tiene hecha su vida allí. *La idea de que se trasladara a un piso de alquiler, si encontrase con quien compartir, le parece muy bien, pues dice que es muy autónomo. Con apoyo de otros servicios como SAD y seguimiento, podría resultar. ········· No obstante, hablarán con José Blas a la vuelta de las vacaciones de Semana Santa, por si aceptara la plaza concedida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-04-04','Ana: Llamada de Javier, dice que llama desde CÁRITAS (97 724 23 37 // C/ d,August): Dice que sigue en la calle, que vendió su móvil para poder tener algo de dinero. ··············· Le informo de que desde el piso le harán un giro postal con buena parte de su dinero (del extra anual que tiene en el piso). Nos confirma que la oficina de Correos que mejor le viene es la de la Plaza Corsini. Le informo también que desde la secc. ecca. le abrirán nueva cuenta en la entidad Ibercaja, que tiene una sucursal en la C/ La Unió que nos dijo Alberto, secc. ecca. Donde podrá retirar dinero semanalmente una vez esté operativa. Le parece bien. ············· Me pasa con Germei, de Cáritas, me facilita una dirección de email (cit@caritasdtarragona.cat) para que comuniquemos cualquier información que queramos hacer llegar a Javier. Acordarán con él que acuda una vez en semana (los lunes de 9 - 13 h) a que le faciliten la información que hubiera. *Me comunica que tiene un comedor social al que podría acudir a comer a diario. Para pernoctar no cuentan con recurso, pero le ha informado de que puede acudir a la Fundació Bonanit a tal fin, pero tiene que gestionarlo él mismo. ··································································································································································································· Llamo a Carolina, Psicóloga - CRR (673 22 55 27), y le informo al respecto. ································································································································································································ Correo de Maite, Jefa Secc. a Carolina, Psicóloga CRR: "Respecto al giro del dinero de Javier, hemos consultado en correos, y nos dicen que tiene efecto inmediato. Nos han hecho hincapié en la importancia de que el nombre de la persona que lo va a recoger esté exactamente igual que en su DNI, de no ser así no le darán el dinero. Como hasta el martes de la semana que viene no le pueden dar la información de la realización del giro, no lo hagáis a este ese día."','2');
