insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2023-04-05','Buenos días Amalia. Con respecto a Jonathan Ramírez Juárez, se ha ido trasladado al C.P. de Estremera (Madrid) el día 31/03/23. Le habían pedido traslado desde el módulo 6, y posteriormente fue trasladado al módulo UTE, desde donde se ha ido, así que no he podido verle para actualizar el I.S., por lo que remito el último que tenemos del interno de fecha 28/10/22. Te dejo el tlf de contacto del C.P. Estremera para que contacteis con ellos: CENTRALITA 91 8.75.00.00 ------------------------------------------------------ Solicito a seccion eco , gestion de cuenta peculio y anular la de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2023-04-05','Buenos días Amalia. Tengo el informe de Cristofer Rollán, te lo remito por GEISER. Con respecto a Jonathan Ramírez Juárez, se ha ido trasladado al C.P. de Estremera (Madrid) el día 31/03/23. Le habían pedido traslado desde el módulo 6, y posteriormente fue trasladado al módulo UTE, desde donde se ha ido, así que no he podido verle para actualizar el I.S., por lo que remito el último que tenemos del interno de fecha 28/10/22. Te dejo el tlf de contacto del C.P. Estremera para que contacteis con ellos: CENTRALITA 91 8.75.00.00 Un saludo.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2023-04-10','-Amalia : me llama Jonathan desde Estremeza . está en el modulo preventivo , aclaro con él el tema econoómico. Se llevó de Badajoz 100€ , el jueves vuelve a cogerlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2023-02-11','SALIDA El 11/02/2023. Salida a ver la procesión de las antorchas en Cáceres. Hora salida: 13:30; Hora regreso: 22:00. Organiza Hospitalidad de Lourdes. Tpte.: autobús adaptado. Acompañantes: voluntarios de la hospitalidad. Observaciones: Vienen cenados, por lo que únicamente preparar agua y fruta si quieren (comentarlo con los residentes). Ropa de abrigo y medicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2023-02-11','SALIDA El 11/02/2023. Salida a ver la procesión de las antorchas en Cáceres. Hora salida: 13:30; Hora regreso: 22:00. Organiza Hospitalidad de Lourdes. Tpte.: autobús adaptado. Acompañantes: voluntarios de la hospitalidad. Observaciones: Vienen cenados, por lo que únicamente preparar agua y fruta si quieren (comentarlo con los residentes). Ropa de abrigo y medicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-04-05','Ana: Tras hablar con Mariluz Madrigal, Jefa Secc. Acceso RR. Salud Mental-SEPAD, leo correo de Pilar Martín: "Ana le ofrecen a Doroteo plaza en CRR de Don Benito, he hablado con él y dice que prefiere estar en la Casa de la Misericordia. Tenemos que contestar antes del lunes. Ya me dices. Un saludo." ··································· Mi respuesta: "...justo acababa de hablarlo con Mariluz e iba a llamar yo a Julia y al propio Doroteo, pero como tú ya has hablado con él, perfecto. Se queda donde está. Ya se lo he dicho a Mariluz y lo bueno es que como al final en la solicitud sólo se pidió el CRR de Cáceres, no se le quita de la lista."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2023-04-05','Ana: Correo de Toni-Futuex: "...En la mañana de ayer contacta el fontanero a quien le han encargado dicha tarea (608025320), se acude con este profesional al piso. Se revisa la vivienda entera, cada bajante, cada tubería que pueda dar lugar a las supuestas goteras que tiene el vecino de abajo. Se revisa la terraza, salón y cuarto de baño, principalmente, pues son las dependencias que lindan con la zona donde tiene las goteras el vecino, pero no se encuentra nada, el fontanero realiza fotografías a todo. También se revisa el resto de la vivienda, se ve una humedad en el techo de la cocina, pero, en todo caso, la afectada es Mª Jesús y de ahí no pasa al vecino de abajo, sólo la tiene en el techo, nada más. Se le consulta qué se debe hacer y dice que, por su parte, cree que el problema lo tiene el vecino de abajo, dará parte a la administradora. Creemos que con esto, estaria todo resuelto, pero no obstante pasados unos dias, nos pondremos en conctacto con la administradora, para saber si el asunto ya se queda zanjado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-04-05','Ana: Guardo en el expte. correo de seguimiento remitido por Toni-Futuex. A destacar: "Desde el día 17 de marzo, Pilar se encuentra algo más nerviosa e intranquila. Dicho día, a la salida de la realización del TAC para los trámites de la operación de la hernia, al sentarla en la sala de espera mientras llegaba la ambulancia, a pesar de haberle indicado que no hablase con la persona que allí se encontraba pues no había gustado a la educadora, Pilar no hace caso; en un momento que la educadora va a solicitar la cita para los resultados del TAC, aprovecha y establece conversación, al volver comenta que es un hombre de Moraleja que conoce a su hijo Jorge, porque él también ha estado metido en temas de droga y cárcel, al parecer le ha contado que su hijo va a salir de la cárcel la próxima semana. Pilar se pone bastante nerviosa preguntando si va a ir a su casa, si la va a buscar… Se le dice que no se va a atrever porque sabe que vuelve a la cárcel, cualquier vecino llamará a la policía si merodea por la casa; también se le dice que se le indicó que no hablase con aquel hombre, pues no habían gustado sus formas y, aún así, lo hizo… Se le intenta tranquilizar lo máximo posible, se le dice que todas las profesionales que trabajamos con ella vamos a estar más pendientes y no va a pasar nada, además, su hijo no se va a atrever a ir por allí porque no querrá volver a la cárcel; se queda algo más tranquila." ·············· "El día 28, cuando se acude al acompañamiento para la anulación de los diversos seguros, Amanda, auxilair de S.A.D., establece que el fin de semana Pilar intentó tomarse más pastillas, lo hizo con las de ketiapina que tiene de la antigua pauta médica. La vio su compañera Lidia que era quien estaba el fin de semana, parece ser que, al final, se tomó sólo dos porque estaba nerviosa indicó. Se le dice que cuando hay un cambio de pauta médica, la medicación que ya no va a tomar hay que recogérsela y entregarla en la farmacia para evitar estas situaciones, se le pide que lo haga mientras se va con Pilar al banco. Se aborda la situación con Pilar, establece que empezó a darle vueltas a la cabeza por lo de Jorge, se puso nerviosa y sólo quería algo de medicación de rescate para relajarse, se le dice que no se puede automedicar, pues el psiquiatra no le ha pautado eso, por lo que no lo puede hacer por voluntad propia. Se le vuelve a insistir en que Jorge no va a ir por allí porque no le interesa, sabe que puede volver a la cárcel. Se le dice que se va a intentar pedir cita con el psiquiatra para poder abordar la nueva situación y consultar si puede tener algo de rescate, Pilar acepta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-04-05','Ana: Hago derivación al Programa de Apoyo Comunitario gestionado por Futuex. ················· Comunico a Tamara, TS que se pondrán en contacto con ella a tal fin. Pido que la primera cita puedan atenderle en las dependencias de SSASB y hagan entrevista conjunta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-04-10','Gracias. Lo he canalizado ya para la UHDAC. Saludos Soraya Masa Moreno','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-04-10','Gracias. Lo he canalizado ya para la UHDAC. Saludos Soraya Masa Moreno','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-04-05','Ana: Correo de Ana Mª, Ed. Social Plena Inclusión Zafra (social@plenainclusionzafra.org): "Hemos podido hablar con el médico ahora mismo, de manera excepcional porque le hemos explicado la situación, no trabajamos hasta el lunes y a partir de esta tarde tiene a personas externas de la entidad atendiéndola. Brevemente ha confirmado el diagnostico de neumonía bilateral y la previsión de tratamiento y hospitalización dice que no menos de 7 u 8 días de antibiótico intravenoso pero hay que ir viendo evolución, que en principio está siendo favorable."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-02-08','miguel, recibo email de la abogada Eva Perez Escarmena (649-555601) >eperezescarmena@icac.es>: Buenos días, le escribo el presente correo para comunicarle que estoy a la espera de que la empresa de construcción me envíen presupuesto de la reposición de la cubierta . Me han indicado que para finales de esta semana lo tendrán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-02-15','miguel, recibo email de la abogada Eva Mª. Pérez Escarmena >eperezescarmena@icac.es> Buenos días, os enviamos nuestro presupuesto, el de la empresa constructora aún no nos lo han entregado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-03-06','miguel, recibo email de la abogada Eva Mª. Pérez Escarmena >eperezescarmena@icac.es> Buenos días , la constructora no acaba de enviar presupuesto. La semana pasada solicitamos el proyecto para que otra constructora pudiese presupuestar, pero los hermanos Plasencia no acaban de remitir el proyecto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-04-10','-Amalia: envio email a la dtra. adjuntando toda la documentación necesaria para su expediente. Le pido que nos calculen el copago de la plaza y cómo se le dará el dinero de bolsillo y extra para ropa . Tiene seguro de decesos , le envio la póliza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-03-15','miguel, recibo email de la abogada Eva Mª. Pérez Escarmena >eperezescarmena@icac.es> Buenos días, en relación a la liquidación del impuesto de sucesiones de la herencia de Doña Rosa Gómez Nevado. Lo primero es que tenemos que hacer declaración de herederos, no hay testamento. Luego creemos que lo más conveniente es liquidar el impuesto de sucesiones. Ha venido el sobrino, Manuel Gómez al despacho y asegura que sus tíos quieren renunciar a su favor, todos los hermanos son solteros y él es el único heredero','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-04-10','miguel, envío email a la abogada Eva Perez Escarmena, reenviando el email de Ana y Futuex sobre el estado de la vivienda: Buenos días Eva, te adjunto el informe de la persona que ha ido a ver la vivienda de Juan Ramón. Por favor, habla con el constructor y si no tendréis que buscar uno rápidamente para que se proceda con urgencia al arreglo de la vivienda. En cuanto me envíes el presupuesto de la parte concreta que corresponde al tutelado tanto tuya como de la empresa de reforma te haremos el abono y procederé en cuanto me digas tipo de procedimiento y cuál juzgado de primera instancia es el competente a solicitar el correspondiente poder apud acta, para lo cual tienes que darme los datos correspondientes del procurador. Quedo a la espera de tu información','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-04-10','miguel, envío email a la abogada Eva Mª. Pérez Escarmena >eperezescarmena@icac.es>, reenviando el email de Ana y Futuex sobre el estado de la vivienda: Buenos días Eva, te adjunto el informe de la persona que ha ido a ver la vivienda de Juan Ramón. Por favor, habla con el constructor y si no tendréis que buscar uno rápidamente para que se proceda con urgencia al arreglo de la vivienda. En cuanto me envíes el presupuesto de la parte concreta que corresponde al tutelado tanto tuya como de la empresa de reforma te haremos el abono y procederé en cuanto me digas tipo de procedimiento y cuál juzgado de primera instancia es el competente a solicitar el correspondiente poder apud acta, para lo cual tienes que darme los datos correspondientes del procurador. Quedo a la espera de tu información ********************************************************* contestación de la abogada: ******************************************************** Llamo por teléfono a la abogada y queda en que me mandará los presupuestos para los trámites judiciales de gastos extraordinarios de este caso y para el procedimiento de adjudicación de herencia de Gomez Nevado (por el fallecimiento de su hermana Rosa) Envío email a Ana y Maite: Buenos días, acabo de hablar con la abogada y me confirma que ha pedido presupuesto a otra empresa, hace unos 20 días y que iba a llamar para insistir que se lo envíen ya. Por otra parte vamos a intentar ir ganando tiempo, teniendo en cuenta que la obra podría retrasarse unos meses, para lo cual como hay que pedir autorización judicial para estos trámites, ya la he pedido presupuesto para tramitar el procedimiento de gastos extraordinarios. (Paralelamente esta abogada también nos lleva otro caso: me mandará el presupuesto para tramitar la herencia de Rosa Gomez Nevado, cuyo hermano, heredero y está tutelado por la Ctaex).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-04-10','-Amalia: envio email a la dtra. adjuntando toda la documentación necesaria para su expediente. Le pido que nos calculen el copago de la plaza y cómo se le dará el dinero de bolsillo y extra para ropa . Tiene seguro de decesos , le envio la póliza.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE RAMON'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2023-03-15','miguel, recibo email de la abogada Eva Mª. Pérez Escarmena Buenos días, en relación a la liquidación del impuesto de sucesiones de la herencia de Doña Rosa Gómez Nevado. Lo primero es que tenemos que hacer declaración de herederos, no hay testamento. Luego creemos que lo más conveniente es liquidar el impuesto de sucesiones. Ha venido el sobrino, Manuel Gómez al despacho y asegura que sus tíos quieren renunciar a su favor, todos los hermanos son solteros y él es el único heredero','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-04-10','miguel, Maite me envía el Acta de la Subcomisión de Casos. compruebo en email de 31-3-2023 de Escalona (recibido por Inés) que por Providencia desestiman el Internamiento Involuntario, por lo que envío email a la Abogada, Carmen Lucas con el Acta de la Subcomisión de casos, junto a dicha providencia, para que lo haga llegar al Ministerio Fiscal y al Juzgado nº6 de Cáceres: Buenos días Carmen, adjunto el acta de la subcomisión que se realizó a efectos de decidir el centro más adecuado para Saturnino, para que lo hagas llegar al ministerio fiscal y al Juzgado nº6 (no sé si a la Audiencia Provincial) donde se está conociendo el procedimiento penal por el delito de agresión sexual. Por otra parte adjunto la providencia denegando dicho internamiento por el juzgado nº2 de Cáceres, que desde aquí intentamos al tratarse del juzgado que tiene asignado y al que se le rinden las cuentas anuales. **************************************************** Reenvío dicho email a Ana y Maite, para su información','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-04-10','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informarte que mañana, 11 de Abril, Felisa Bruno empieza a vivir en Don Benito. El piso está en la dirección Avenida de la Constitución portal 18 nº 2ºA. El día 5 de abril estuvo unas horas allí para ver el piso y conocer a los profesionales y compañeros que tendrá. Estos días ha estado preparando equipaje, fiesta que quiere celebrar hoy para despedirse,.... Voy a volcar todos los datos de gastos de marzo para ver cómo queda y después ajustamos cuentas con Estrella para que quede todo a cero aquí y los ingresos para gastos personales que recibimos nosotros que pasen al piso." ··························· Comunico a Julio, Aux. CATEx, para que modifique la dirección en la base de datos y a Alberto y Óscar, secc. ecca. De momento sólo hay que modificar lo relativo a la autorización de la asignación para gastos de bolsillo. Como la plaza en Asindi se le reserva 6 meses, tendrá que seguir abonando ésta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-04-10','Ana: Correo de Alberto detallando acuerdo e inicio de las gestiones oportunas: "RESUMEN: JAVIER AGUDO CUMPLIDO (UNICAJA), RESIDENTE CRR PLASENCIA, SE VA, SIN AUTORIZACIÓN A TARRAGONA. ES NECESARIO HACERLE LLEGAR SU ASIGNACIÓN. SE CONSIGUE HABLAR CON USUARIO Y NOS INDICA QUE HAY UNA SUCURSAR DE IBERCAJA EN C/ DE LA UNIÓ DE TARRAGONA EN LA QUE SE PODRÍAN HACER LOS REINTEGROS. SE DECIDE PASARLE TOTALIDAD PENSIÓN, EXCEPTO EXTRAS, CON DISPOSICIÓN SEMANAL. OSCAR: • APERTURA NUEVA CCC IBERCAJA: EN TEORÍA LOS REINTEGROS SE HARÁN EN TARRAGONA, SUCURSAL UBICADA EN Calle Unio 45, 43001 – Tarragona (Tarragona ) ---- TFONO.: 977 21 52 02 • TRANSFERENCIA, DE MOMENTO PUNTUAL Y MENSUAL (SE REPETIRÁ HASTA QUE ANA NOS INDIQUE OTRA COSA), HASTA QUE SE ESTABILICE O REVIERTA LA SITUACIÓN, X 1.600 € A NUEVA CCC DE IBERCAJA.... • REINTEGRO PERMANENTE SEMANAL X 370 €/SEMANA EN LA SUCURSAL DE IBERCAJA EN TARRAGONA (CALLE UNIO). • OSCAR: JUSTO ANTES DE HACER EL PRIMER REINTEGRO HABLAR CON ANA PARA VER SI HAY QUE RETRASARLO PORQUE CRR LE HAYA MANDADO DINERO DE SU EXTRA ANUAL (ASÍ NO DISPONDRÁ DE TANTO DINERO EN TAN POCO TIEMPO). ACUERDO: USUARIO NO DISPONDRÁ DE UN SÓLO EXTRA EN LO QUE QUEDA DE AÑO, EXCEPTO EL RESTO DEL EXTRA ANUAL QUE YA SE HA ABONADO A CRR DE PLASENCIA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2023-04-10','TERESA SE AMPLIA HORAS DE SAD PRIVADO POR IMPORTE DE 350€ MES. SE SOLICITA LEY DE DEPENDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2023-04-10','TERESA Beatriz Muñoz ha estado esta semana en el pueblo con sus padres y ha ido a visitar a su hija. Me ha llamado la trabajadora social del pueblo ya que Beatriz sigue con la idea de pedir la custodia de la niña y de pedir un trasladado para estar más cerca de ella. En tiempo íbamos a ir visitarla al centro pero lo pospusimos pues el centro consideró que no era buen momento. Sería conveniente retomar el tema de la visita ya que Beatriz demanda vernos y ahora mismo se muestra muy insegura con toda esta situación que tiene con su hija ya que la niña es cada vez mas mayor y se da mas cuenta de todo y Beatriz quiere tener mas contacto con su hija. Actualmente solo la ve una vez al mes porque económicamente no se puede permitir más viajes debido al costo que tiene pues esta muy lejos el centro de la vivienda donde se encuentra la hija','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2023-04-10','TERESA Se ha recibido una llamada de Mari, la casera de Paloma. Comenta que está cansada de que Paloma y su padre le dejen a deber facturas tan a menudo. Los suministros están a nombre de Mari y, cada final de mes, se acerca a casa de Paloma con las facturas y ésta se las paga (por supuesto con el dinero de su padre). Mari comenta que Paloma siempre deja algo sin pagar. Por el momento, le debe 100€ de una factura de agua y, por otro lado, casi 80€ de una de luz. Cuando Mari va a cobrar, apunta en las mismas facturas, el dinero que Paloma le entrega y lo que quede pendiente, entonces Paloma lo firma para dejar constancia. Mari asegura que le dijo a Paloma que tienen que dejar el piso lo antes posible porque lo único que consigue teniéndolo alquilado a su padre y a ella es tener disgustos. Mari explica que la pared, los sillones y el sofá están en muy malas condiciones porque Paloma no mantiene la casa limpia ni cuida el mobiliario. Explica que cuando Paloma y su padre entraron a vivir todo estaba en perfectas condiciones. Asegura que, tanto pintar el piso como poner un sofá y unos sillones nuevos es algo que debe pagar Paloma, ya que cuando dejen el piso tiene que estar en las mismas condiciones en las que se le entregó y tanto las paredes como el sofá y sillones estaban perfectos. Mari comenta que ha hablado con un abogado y éste le ha asegurado que estos gastos corren a cuenta de Paloma. Mari comenta que si la situación va a seguir siendo la misma que hasta ahora, prefiere que se vayan e irse ella a vivir allí con su marido que tiene problemas de movilidad y allí estarían mejor. Se le ha comentado si podría facilitarnos una copia del contrato de alquiler (se le llamó esta mañana a Paloma y aseguraba que la casera no se lo había querido dar ayer tarde). Mari dice que no tiene el contrato impreso (que lo tiene su hijo en el ordenador), se le pregunta cómo entonces se lo ha enseñado al abogado, dice que no se lo ha enseñado pero que el abogado se fía de su palabra. Por otro lado, cuando se le ha preguntado a Mari, asegura que estaría dispuesta a que Paloma y su padre se quedaran si tuviera la seguridad de que van a pagar todo cuanto deben hasta el momento, así como las facturas mensuales que vengan de aqui en adelante en tiempo en forma, y, también, si se comprometen a mantener la casa limpia y cuidada. Es un poco complejo, porque los suministros los paga el padre y claro no los tiene domiciliados, pero es Paloma, quien hace los "chanchullos" con no pagar cuando debe.. no sabemos que solución al respecto podria tomarse, porque ciertamente como tengan que marcharse es un problema. Se facilita el número de teléfono de Mari: 658 64 80 51.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-04-10','Ana: Corre de ayer domingo, de Sara García Martín, TS de Residencial Banium, Baños de Montemayor: "Me pongo en contacto con ustedes para informar que Concepción Barbero Sánchez se encuentra hospitalizada en el Virgen del Puerto de Plasencia. En la noche del día de ayer tuvo que ser derivada tras sufrir una caída. Desde el hospital se han puesto en contacto con nosotros porque necesitan que se firme una autorización o consentimiento para poder proceder a intervenirla de una operación de cadera." ·········································· Tras hablar con Celia Gía, TS HVP Plas. (78206 / celia.garcia@salud-juntaex.es), le envío: CI Anestesia, CI Fractura Fémur Proximal, CI Proyecto Registro Nacional de Fracturas de Cadera por fragilidad en el anciano y CI para transfusión de componentes sanguíneos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-04-10','Ana: Llamo a Pilar Martín, TS ESM-CC (54612): no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-04-10','Ana: Tras intercambiar correos con Tamara, TS SSASB-CC, donde indica que no puede hacer la entrevista conjunta con la Ed. de Futuex por entender que su Intervención ha finalizado con la visita y emisión de Informe Social, envío correo a Toni-Futuex: "En relación a la última derivación: CARLOS GONZÁLEZ LEO, acabo de caer en que, creo, que no te dije el tipo de cargo aceptado: CURATELA REPRESENTATIVA, para los ámbitos: “médico-sanitario”, “económico-jurídico-administrativo” y “para solicitar todo tipo de ayudas y prestaciones económicas, sociales y asistenciales”. Por otra parte, comunicarte que no podemos contar, al menos no ahora, con la colaboración de la Trabajadora Social del SSASB, quien manifiesta que su “intervención ha terminado”. Por lo que tendrán que ir dos de las compañeras del equipo, si así lo estimáis. No obstante, por si os sirve, os copio una frase literal de la compañera del SSASB (tamara.sanchez@ayto-caceres.es): “Al estar en el domicilio, en el salón él hizo referencia a que no me asustará que tenía armas pero eran de fogueo, estaba nervioso por irse hacer tatuajes por lo que no pare a mirar ya que le vi con prisas e impaciente por irse.....”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-04-10','Ana: Correo de Ana Mª, Ed. Social Plena Inclusión Zafra (social@plenainclusionzafra.org): "A Reme le han repetido la placa hoy y la médico ha dicho que está mas o menos, que aún la ve “muy cerrada”. Le han cambiado el antibiótico y dice que a ver los próximos días la evolución pero que prevé que al menos dos, tres días más de hospital tendrá. Dice que es una paciente inmunodeprimida e institucionalizada y por ese motivo su neumonía es de repetición y puede que siga ocurriendo. Como está “dinero” para saber y para hacer previsión de apoyos?? Está nerviosa, ha empezado a enredarse de nuevo en uñas y talones y no la vemos para quedarse sola, la verdad. Hoy por la mañana hemos vuelto a cubrir el turno con su profesional de referencia del servicio de centro diurno pero para los próximos días no sabemos si va poder ser así y podremos evitarle por tanto ese gasto de acompañamiento por esas horas. Las chicas que han estado estos días muy bien, han ido haciendo registros y comunicando todo y Reme se ha adaptado a ellas muy bien. Siguen disponibles para que le vayamos diciendo los turnos a cubrir pero nos preocupa eso…la falta de recursos para seguir prestando esa apoyo." ······················ Mi respuesta: "Gracias por mantenernos informadas. De momento pueden continuar realizando el acompañamiento, puede asumirlo. Una compañera de la sección económica estará pendiente y llegado el momento en que no pueda mantener el gasto nos avisarán y veremos cómo reducir en horas. Ojalá y que evolucione bien y en unos 3 días pueda regresar al centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-04-10','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Informaros de que la persona usuaria Consuelo Nevado Pacheco se encuentra desde el pasado miércoles día 5 de abril ingresada en la UHB por desestabilización de su patología de base. Os iremos informando de su evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-04-10','Ana: Paso a Julio para que envíe a la Gerencia Territorial de CC del SEPAD, la ACEPTACIÓN PIA consistente en SAR. El primer centro solicitado es el de Campillo de Llerena. ···················· Actualizo en la Base de Datos el grado de la nueva valoración de Dependencia: GRADO III.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-04-11','miguel, tras la llamada de Jose Antonio Porro (abogado nombrado por la familia para tramitar la impugnación de las ejecutorias de sentencias de hace 13 años y 5 años), me remite el email explicativo de los trámites realizados justificando la provisión de fondos que solicita y que traslado a la parte económica (Oscar) para su abono: Buenos tardes. Como ya te expliqué detalladamente en la conversación mantenida en la mañana de hoy, la provisión de fondos solicitada corresponde al trabajo que estamos haciendo en este despacho profesional en la Ejecutoria 443/201 del Juzgado de lo Penal Nº 1 de Badajoz. En dicha ejecutoria se han realizado numerosas gestiones desde hace casi un año, destacando fundamentalmente, en primer lugar, el Recursos de Reforma formulado contra el Auto de 10 de mayo de 2022, que revocaba la suspensión de la ejecución de la pena de prisión impuesta por la A.P. por un delito cometido el 29 de mayo de 2009 concedida por la Audiencia Provincial de Badajoz mediante Auto de 11 de febrero de 2016, por haber cometido Alberto un nuevo delito el día 15 de mayo de 2018, y acordaba ingreso en prisión para el cumplimiento de esta pena. Tras varias visitas de Alberto y de sus familiares y dada la situación de aquél, se recomendó el inmediato ingreso en Centro de deshabituación, recabándose abundante documentación y realizándose numerosas gestiones en fiscalía. Posteriormente, se formalizaron escritos aportando pruebas documentales y se realizaron alegaciones complementarias. Por último, ante la desestimación del Recurso de Reforma se ha formalizado Recurso de Apelación para ante la Audiencia Provincial de Badajoz contra el Auto de la Juez de lo Penal que rechazó de plano nuestra solicitud. Tras la formalización del recurso se han vuelto a realizar gestiones en Fiscalía por entender que no es nada razonable ejecutar una sentencia dictada hace más de 13 años. Ante la eventual desestimación del Recurso de Apelación, además, se ha empezado a recabar documentación para la inmediata presentación de una solicitud de indulto por conmutación, para intentar evitar el ingreso en prisión de Alberto. se insiste, si el Recurso de Apelación no prosperase. En las distintas conversaciones con los familiares de Alberto, se me ha insistido en que solicitara una provisión de fondos, puesto que es imposible ahora mismo prever el resultado del Recurso de Apelación planteado y resulta prácticamente imposible confeccionar un presupuesto sin conocer muy bien los trabajos que será necesario realizar. Es por ello que se solicitó una provisión de fondos en lugar de elaborar una minuta por los trabajos realizados, puesto que es previsible que haya que realizar nuevos trabajos de los referidos en este correo. Espero haber aclarado debidamente la situación, y me pongo a vuestra entera disposición para cualquier aclaración adicional que sea precisa. Sin otro particular por el momento, quedo a la espera de vuestras noticias. Recibe un cordial y afectuoso saludo. PD.- En la provisión de fondos está referido el número de cuenta en el que hacer el ingreso. José Antonio Romero Porro Abogado C/ San Sisenando, 2, 3º F. 06002 BADAJOZ. Teléfonos: 924242304. 667529460. --','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-04-11','Ana: Envío correo a Carolina y Mónica, Piso Supervisado Plas., pidiendo, que si tienen escaneado a color el DNI de Javier nos lo envíen y preguntando por el dinero que finalmente tenía allí y cuándo y cuándo se lo van a enviar por giro postal como habíamos hablado. ···································································································································································································· Envío correo a Germei, Cáritas Tarragona (cit@caritasdtarragona.cat): "Tal y como habíamos acordado, le escribo a esta dirección para que pueda trasladarle la información a Javier Agudo Cumplido, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura. Lo primero que quiero comunicarle es que nos solicitan su DNI escaneado a color para la apertura de la cuenta bancaria en la entidad que le indicamos (Ibercaja). ¿Podrían solicitarle que nos la haga llegar a la siguiente dirección: ctutelar@salud-juntaex.es? No sé si es posible a través vuestra o en alguna copistería o algo así. En cuanto me confirmen algo más, con respecto al giro postal, me pondré de nuevo en contacto con usted." ································································································································································································· Desde CÁRITAS nos remiten DNI escaneado a color. Informan también que le están ayudando a buscar alojamiento. ································································································································································································· Correo de Carolina, Directora de CRR (direccion.crrplasencia@grupo5.net): "Respecto al dinero ayer le hicimos el giro para que hoy lo pudiese recibir, en coordinación con cáritas de Tarragona. Me llamaron el mismo día que hablamos nosotras y di por hecho que se habían coordinado con vosotros, siento no haberte informado. Enviamos el código a la dirección de mail de Cáritas, estmos a la espera de que nos confirmen. El giro, como hablamos ha sido de 800 €, aún queda dinero en la resi. Te adjunto informe de gastos para que me digas qué hacemos con el restante." ········································································ Reenvío el correo a Alberto y Maite, Jefes CTAEx: "...Mi propuesta es que el dinero que le queda en el piso, lo ingresen en su cuenta y se contemple para gastos extraordinarios en lo que queda de año, pues como ya ha perdido la plaza en el recurso, no se lo pueden guardar allí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-04-11','Ana: Correo de ayer de Isabel, al ctutelar@: "Buenos días Ana quería decirte que me quiero ir a vivir con mi madre a Placencia a las dos solas." ······························································································································· Respondo poniendo en copia a las profesionales del CRR: "Ya trataremos este asunto con calma. Es una decisión que no puede tomarse a la ligera. Las profesionales del CRR, son quiénes mejor conocen tu evolución y nos podrán informar si estás preparada para ello. Nosotras, desde el Equipo Técnico de la CTAEx, consideramos que aún no es el momento y qué todavía tienes que trabajar algunos aspectos para que un paso así no suponga un retroceso en tu proceso. Además, como bien sabes, tenemos que valorar qué es lo mejor para ti y velar por tu adecuada evolución y tu BIENESTAR. Pongo copia a las compañeras del CRR para que estén informadas y para que puedan abordar esta cuestión contigo de manera presencial, que siempre es mucho mejor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-04-11','Ana: Óscar, secc. ecca., me comunica que a María ya le están ingresando la prestación vinculada al SAR en la nueva cuenta bancaria. ················································· Envío a REGISTRO (oac.merida.san@juntaex.es) Oficio-Solicitud de Certificado Actualizado de Pensión, para remitirlo por registro a la Dirección Provincial del INSS de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-04-11','Ana: Conversación con Pilar Martín, TS ESM-CC: Me enviará el Acuerdo de la Comisión de Valoración de exptes. para acceso a CRR. ·············· Se le remitirá al Jdo. desde la CTAEx. ··········· Plantea solicitar nueva valoración de Grado de Dependencia, pero finalmente acordamos que hasta que no responda el Jdo. no se solicitará nada más. ······························································································································································································ Envío mail a A. Jurídicos CTAEx y a Maite, Jefa Secc.: "...os envío el ACUERDO DE LA COMISIÓN DE VALORACIÓN DE EXPEDIENTES relativa a la Solicitud del CRR de Don Benito, tramitada por el Equipo de Salud Mental de Cáceres, tanto porque él lo solicitaba, como porque el equipo considera que es el recurso más adecuado para él. Pero como veis, el acuerdo argumenta 2 cuestiones para no valorar la solicitud: 1. La CTAEx no ha firmado la solicitud (cosa que no se ha estado haciendo de aquí para atrás por ser un recursos que requiere la voluntariedad de la personas, al igual que las Comunidades Terapéuticas, para las que tampoco se firma la solicitud por el Representante Legal) 2. El Juzgado no se ha pronunciado sobre el informe emitido por el SEPAD a fechad de 3 de enero de 2022, que se le remitió desde aquí Considero que hay que enviar al Juzgado este acuerdo también, pues éste es el único recurso para el que da perfil de acuerdo a sus características, pero según el acuerdo que adjunto, dada su trayectoria tampoco se adecúa su perfil al CRR. Si esto es así, nos quedamos sin recursos a los que a día de hoy pueda acceder. Así mismo, la realidad nos muestra que tampoco reúne requisitos para vivir sólo y los apoyos que se le pueden prestar (Catering, Servicio de Ayuda a Domicilio así como el seguimiento y apoyo del Programa de Apoyo Comunitario gestionado por FUTUEX, que recibe) resultan insuficientes para mantenerse en condiciones óptimas en su domicilio con un mínimo de calidad de vida y bienestar. Cada vez presenta más problemas de salud y dificultades para acceder a su vivienda y cada día resulta más difícil la intervención con él, pues no acepta las indicaciones médicas, sanitarias ni de las distintas profesionales de la intervención social, haciendo caso omiso de todas ellas." ······························································································································································································ Llamada de José Manuel (627 788 797): Dice que ya no puede subir y bajar las escaleras. Que está fatal. Le van a hacer una resonancia de las rodillas. Tiene mucha artrosis. ············· También dice que tiene el azúcar alta, pero al preguntarles afirma que sigue tomando a diario las bebidas energéticas. ···· Tampoco reduce el consumo de tabaco. ················ Manifiesta también que el jueves santo ingresó en la UHB porque "estaba de los nervios", pero que por la tarde le dieron el ALTA VOLUNTARIA. ············ Dice que necesita ROPA y CALZADO, pide al menos 300€. ············· También necesita productos de limpieza (desengrasante y lejía principalmente).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-04-11','Ángel: Asistimos hoy, mediante videoconferencia, a la comparecencia de Beatriz, en el Juzgado de 1ª. Inst. e Inst. nº 2, de Zafra, DPA DILIGENCIAS PREVIAS PROC. ABREVIADO 0000121 /2023, para prestar declaración, por la comisión de un presunto delito de usurpación de estado civil. En la declaración, el Juez le pregunta a Beatriz si es verdad que contrató líneas de teléfono, utilizando el DNI de su hermana Rosa Mª. Dice que no, que fue Rosa quien contrató esas líneas y que estaba de acuerdo en ayudar a Beatriz, porque no tiene tarifa plana de móvil, sino de prepago. Beatriz, lo único que quiere es que la ctaex le pague a la hermana los importes por el consumo de esa línea de teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-04-11','Hola Amalia, soy Marta, la trabajadora social de la residencia de Montehermoso. He estado hablando con Santos sobre los temas de ropa, dinero y salidas. En todo ha dicho que ni necesita nada ni quiere salir al pueblo. De todas maneras le he dicho y repetido que en cualquier momento nos haga saber si necesita algo o le gustaría salir, que no hay ningún problema. Me ha enseñado que guarda en su cartera 60 euros. La ropa en estos días vamos a ponernos con ello y te decimos. Cualquier cosa que necesitéis, aquí estamos. Un saludo, Marta Custodio Batuecas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-04-11','Hola Amalia, soy Marta, la trabajadora social de la residencia de Montehermoso. He estado hablando con Santos sobre los temas de ropa, dinero y salidas. En todo ha dicho que ni necesita nada ni quiere salir al pueblo. De todas maneras le he dicho y repetido que en cualquier momento nos haga saber si necesita algo o le gustaría salir, que no hay ningún problema. Me ha enseñado que guarda en su cartera 60 euros. La ropa en estos días vamos a ponernos con ello y te decimos. Cualquier cosa que necesitéis, aquí estamos. Un saludo, Marta Custodio Batuecas.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-04-11','Amalia : copago de la plaza 685€. No quiere que le enviemos dinero de bolsillo ni comprarse ropa . Le han dado ropa que tenían allí . Ya han acudido al centro de salud y le han asignado médico y pautado medicación. TF DE LA TS MARTA 660858095','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-04-11','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "...estamos terminando de organizar la documentación para que se lleve Felisa (certificado de discapacidad, resolución dependencia, informes médicos,....) y me he acordado el tema de que disponga de dinero para sus gastos imagino que lo veréis vosotros con los responsables del piso. Te mando el teléfono de Sergio Romero para tratar de este tema 633 632061. Estoy cerrando los gastos que ha tenido este último mes para pasarlo a la Comisión porque seguramente hay deuda. Pero si os parece le voy a mandar 30 euros para que tenga estos días hasta que organicéis el tema de gastos con ellos." ·························· Respondo: "Gracias por el contacto de Sergio, pues no sabíamos con quién hablar. Todo lo hemos sabido por ti. Le llamaré hoy. Quedamos a la espera de la información relativa a los gastos y a las posibles deudas. En cuanto lo de los 30€ nos parece bien." ··································································································································································································· Llamo a Sergio Romero, Responsable Vivienda Proyecto Mi Casa- Don Benito (633 632 061): Acordamos que de momento se mantendrá a Felisa la misma asignación para gastos de bolsillo que tenía en ASINDI: 25 €, pero en lugar de hacer transferencia a la entidad, se realizará una autorización de retirada mensual en a la sucursal de Don Benito sujeta a acompañamiento de profesionales del recurso. ··· Enviará un correo con los datos de los distintos profesionales a tal fin. Las retiradas comenzarán el próximo mes de mayo, pues como sabes, hoy va con 30 € para lo que pueda necesitar en lo que queda de mes. ··········· Ya le he explicado como proceder cuando necesite comprar ropa, calzado, etc. ·········Las necesidades básicas las tiene todas cubiertas (ropa de cama, higiene personal, etc.) ·············································· *Envío correo con toda esta información a Lourdes, Aux. Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-04-11','Amalia : copago de la plaza 685€. No quiere que le enviemos dinero de bolsillo ni comprarse ropa . Le han dado ropa que tenían allí . Ya han acudido al centro de salud y le han asignado médico y pautado medicación. TF DE LA TS MARTA 660858095','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-04-11','-Registrado cambio Nº cuenta en la prestación de dependencia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-04-10','miguel, recibo email de una de las dos hermanas de Flora juanamaria_gutierrez@hotmail.com> Buenos días: En primer lugar pedirle disculpas por el retraso de este correo, pero teníamos que reunirnos las dos hermanas de Flora para tomar una decisión sobre el tema. La decisión que hemos tomado es que la herencia pase a favor de nuestra hermana Flora Gutiérrez García. Para agilizar el tema desearíamos que la gestión de documentos nos fuera facilitada. Nosotras le enviamos nuestros DNI. Del resto de documentación nosotras no tenemos nada. Le enviamos nuestra información de contacto: -Modesta Gutérrez García. Telf. 673972619. -Juana María Gutiérrez García. Telf.615309968. Quedamos a vuestra disposición. ************************************************ Reenvío email a la notaria de plasencia mplgonzalez@despacho.notariado.org Buenos días, adjunto email de las hermanas de Flora (tutelada por la Ctaex) Estamos pendientes de firmar la declaración de herederos… Adjunto el email que me remitisteis desde la notaria, necesitaría hablaseis con las hermanas para que las indiquéis cómo tramitar dicha renuncia de herencia, para lo cual puedes ver los datos de contacto debajo. Te llamaré entre hoy y mañana para concretar los siguientes pasos a seguir','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2023-04-11','Soy Luis, el hijo de Antonia Hernández Sanchez. Finalmente, no zanjamos el asunto de mi madre. Igualmente, quisiéramos poder hablar contigo sobre la situación de futuro que puede darse para ver si puedes orientarnos. Puedes llamarme al 633176893.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-04-11','Ana: Llama Ramón, hijo de Julián Ramón (647 694 013), habla con Icíar, quién le pasa con Miguel, A. Jurídico, quiere preguntar acerca de la obra del edificio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-04-11','miguel, me llama su hijo Ramón (647-694013; email 01@unparpadeo.com al que informo de cómo está el procedimiento y quedamos en que él llamará una vez a la semana a la abogada Eva y yo la enviaré un email para ver los avances en el expte','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-04-11','miguel, tras días sin lograr hablar con Rafael de la notaria de Don Benito, me confirma hoy que sí es necesario Autorización judicial para la herencia pese a enviarle como ejemplo el de otra donde se aceptó a beneficio de inventario. El motivo es porque dice que es casi una venta ya que se adjudica y transmite en la misma escritura a su hermana y eso supone que el juzgado tiene que admitir la cantidad que se adjudica. El problema es que conforme email de Oscar sólo dispone la tutelada en su cuenta 3.803,88€, siendo nula su capacidad de ahorro. Por tanto tengo que solicitar abogado de oficio para herencia en el domicilio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-04-11','Buenas, en su sentencia de incapacitación, el Juzgado autorizó su ingreso en el CSS, de la Granadilla, para que le prestaran los apoyos necesarios para la realización de las actividades de la vida diaria e instrumentales, quien debe remitir al Juzgado Informe sobre el estado de aquella cada 6 meses. Si su voluntad es abandonar el centro, no podemos retenerla, tan solo intentar convencerla que en este centro tiene todas su necesidades básicas cubiertas y que fuera del mismo no las tendría. Si insiste en abandonar el centro, tan solo podemos, junto con el centro, ponerlo en conocimiento del Juzgado y de la Fiscalía. Necesitaríamos un Informe del centro. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-04-12','Ana: Correo de Ana Mª, Ed. Social Plena Inclusión Zafra (social@plenainclusionzafra.org): "He estado en el hospital sobre las 15:00 y la hemos visto (dormida) mucho mejor. Hemos hablado con dos de sus cuidadoras y con el médico de planta, y ambos coinciden en una evolución muy favorable y estabilidad que si se mantiene en un par de días le pueden dar el alta. Ojalá sea así. Os voy informando." ······························· Envía también Declaraciones Juradas de acompañamientos hospitalarios a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-04-12','Ana: Envío correo a Alberto, Jefe Secc. Ecca., con copia a Maite y Óscar: "En relación a José Manuel Romero Mediavilla, necesita ropa y calzado, así como productos de limpieza para que la Aux. de Ayuda a Domicilio pueda continuar haciendo su trabajo. Al resto de cosas que solicita se le está diciendo que no, pero esto consideramos que hay que autorizarlo. - Con respecto a los productos de limpieza, ya lo hemos hablado Icíar y yo, y ella acaba de hablar con la Auxiliar de Ayuda a Domicilio, Maira, para que el lunes le acompañe ella al banco a retirar 20 € y comprar los productos que necesita. - Para la ropa y calzado pide 300 €, teniendo en cuenta que necesita “tallas grandes” no me parece excesivo, yo al menos le concedería 250 €. ······· Hemos hablado de que la compre en Kiabi, pues allí hay tallas especiales y a mejor precio, pero como allí es más complicado lo de pedir presupuesto y abonar mediante transferencia, ayer comenté con Maite la posibilidad de, si a ti y a Futuex os parece bien, hacerle una transferencia a Futuex y que la Educadora que le acompañe lleve el dinero para abonar la ropa en metálico y nos remita la factura. Ya nos dices para hablar con Futuex." ··································································································································································································· Llamada de José Manuel (627 788 797): esta mañana ha iodo Virginia, Ed. Futuex a visitarle hoy. ········· También ha hablado con Pilar Martín, TS del ESM y con la Enfermera del mismo. Se encuentra tan mal que está dispuesto a ingresar en UME o URH. La enfermera le ha dicho que hablará con el Psiquiatra para que le den cita y lo hable con él al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-04-12','miguel, envío email a Rafa de la notaria de Don Benito: Buenos días Rafa adjunto la rendición final de cuentas en su días, junto a certificado de defunción y últimas voluntades (cuyos originales tengo y los aportaría cuando vaya a firmarla o ratificarla). Adjunto también certificado negativo de catastro, motivo por el que necesito me envíes nota simple del inmueble que pretende adjudicarse en la escritura de herencia lo antes posible para enviarlo al abogado que ha de pedir autorización judicial para la herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-04-12','miguel, envío email a Sara: sara lozano >sarita_pei@hotmail.com> Buenos días Sara, necesito que me envíes la nota simple de la vivienda que se quiere adjudicar tu madre?, de la herencia de Isabel Diaz Rodriguez Adjunto certificado de fallecimiento, últimas voluntades (en el que podrás ver que no otorgó testamento y por tanto tienes que hablar con Rafa para que prepare la Declaración de Herederos). Por otra parte y tras hablar ayer con Rafa, me confirmó que vamos a necesitar Autorización judicial para la adjudicación de la herencia, para lo cual voy a necesitar una tasación o informe de valoración de mercado de la vivienda, ya que el juzgado debe autorizar el precio mínimo de transmisión de la vivienda. Al no aparecer en catastro dicha vivienda, necesito que me envíes la nota simple de la vivienda que se va a incluir en la herencia ya que teníamos constancia de la existencia de la misma. Por tanto en cuanto puedas envíame: nota simple y tasación o informe de valoración por perito de la vivienda para que el abogado pueda pedir la autorización de adjudicación de la herencia. Por mi parte voy a ir solicitando al Colegio de Abogados de Cáceres que asignen un abogado de oficio en Plasencia que represente a Isabel Valades Diaz para poder aceptar la herencia. Al fallecer Isabel Diaz Rodriguez en Plasencia, necesitamos que la autorización para aceptar la herencia en notaria, sea dictada por dicho juzgado de Plasencia que es el juzgado competente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2023-04-12','TERESA ampliación del servicio de ayuda a domicilio de Rafael Dávila Hidalgo. Pasando a ampliarse a 6 horas y 30 minutos semanales, por la cuantía de 350 euros. Pedro es la persona de contacto de la empresa Atención a la Dependencia Extremeña, S.L. Teléfono: 647 61 37 31','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2023-04-12','TERESA ampliación del servicio de ayuda a domicilio de Rafael Dávila Hidalgo. Pasando a ampliarse a 6 horas y 30 minutos semanales, por la cuantía de 350 euros. Pedro es la persona de contacto de la empresa Atención a la Dependencia Extremeña, S.L. Teléfono: 647 61 37 31','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-04-12','TERESA me pongo en contacto con usted para comunicarle que a la paciente Mª Jesús Cruz se le están realizando tratamientos bucales que aún no han sido abonados, ascendiendo el importe pendiente de pago a 300€. La paciente lleva sin acudir a consulta desde el 09/03/2023 y no somos capaces de ponernos en contacto vía telefónica con ella. Ruego liquiden la deuda pendiente y en caso de no continuar, comuníquemelo, por favor. Para ponerse en contacto conmigo, adjunto teléfonos: 924 66 62 63 679 511 149. HABLO CON M JESUS Y ME CONFIRMA QUE ESTA LLENDO A LA CLINICA , LE EXPLICO EL PROBLEMA QUE HEMOS TENIDO CON LA CONFUSION DE INGRESO A VIVANTA, SE ENFADA ANTE LA SITUACION Y COMENTA QUE NO LE VALE DE NADA ESTAR A CARGO DE LA COMISION ME COMENTA QUE EL NOVIO LE HA ECHADO DE CASA Y QUE AHORA ESTA VIVIENDO CON SU PADRE, HA PAGADO ELLA EL IMPORTE INTEGRO DEL ALQUILER YA QUE EL NOVIO NO TIENE DINERO Y ACTO SEGUIDO LE HA ECHADO LE EXPLICO QUE PARA MAYO PODRA CONTINUAR CON EL TRATAMIENTO Y QUE ESTAMOS RECLAMANDO EL DINERO A LA COMPAÑIA TELEFONO M JESUS 610843541','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-04-12','Ana: Recibimos Cdo. Actualizado de P. Jubilación del INSS - Importe Líquido: 1.272,46 €','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-04-12','-Se recibe email del CRR , ha solicitado la baja voluntaria: Como venimos hablando en el caso de Javier Giraldo, viene teniendo un consumo activo continuado y frecuente de cannabis desde el ingreso en el CRR, lo cual interfiere tanto en su funcionamiento como en su actitud frente a profesionales y demás personas usuarias, al igual que en su sintomatología psicótica. Desde que el equipo es conocedor de esta situación se ha intervenido de diferentes maneras, derivación al CEDEX, controles periódicos, apoyo en gestión económica, trabajo desde el área de psicología, terapia ocupacional y educador de referencia… Todas estas intervenciones sin ningún resultado. En diferentes citas con profesionales Javier ha reconocido el consumo y su intención de seguir haciéndolo, del mismo modo que su interés de volverse al domicilio familiar con su padre. Tras los últimos consumos, la semana pasada nos reunimos con él para confrontar su situación actual, en cuya reunión, él decide abandonar el recurso, con la intención de que pueda replanteárselo se le emplaza a esta semana para volver a tratarlo, donde mantiene su postura de abandonar el recurso, por tanto, se le da apoyo para organizar su salida al domicilio familiar, se le acompaña a comprar el billete de autobús hacia su pueblo (Calzadilla de los Barros), sin embargo no tenemos claro si se quedara con su padre o sus tíos. PARA LA COMISIÓN TUTELAR: En referencia a sus pertenencias se le hace entrega de la medicación, sus enseres, informes, tabaco para el mes completo y dinero correspondiente a gatos de bolsillo y del mes de abril, siendo la cantidad de 40€ más 10€ del billete de atubus, quedando en el centro la cantidad de en torno a los 500€ lo cual lo ingresaremos en el número de cuenta que nos indiquéis. El contacto del padre es: F.º Javier 600 002 476 Para cualquier cosa, estoy a vuestra disposición','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-04-12','-Amalia : hablo por tf , con su padre y con Javier ( tf 603029360). Su padre dice que temporalmente puede quedarse allí , él economicamente no lo puede mantener . La intención de Javier es de quedarse con su padre . Le indico que se le dará un reintegro de 100€ al mes para gastos. Acuerdo hacer transferencia de 200€ a la cuenta del padre para manutención. Paso el caso para seguimiento por Futuex .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-04-12','-Amalia : hablo por tf , con su padre y con Javier ( tf 603029360). Su padre dice que temporalmente puede quedarse allí , él economicamente no lo puede mantener . La intención de Javier es de quedarse con su padre . Le indico que se le dará un reintegro de 100€ al mes para gastos. Acuerdo hacer transferencia de 200€ a la cuenta del padre para manutención. Paso el caso para seguimiento por Futuex .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-04-12','Ana: Correo de Óscar, Secc. Ecca.; "He detectado una orden de transferencia permanente de 200€ al mes a la cuenta del hijo. Ya la he anulado y he avisado al banco. ANA: cuando puedas habla con el CSS de Plasencia para ver si ha sido ella quien lo ha ordenado. En el banco no se explican como ha podido hacerse, ya que tiene la cuenta bloqueada. ALBERTO: por fin he conseguido que el BBVA me diga de qué son los seguros que tiene contratados, por los que paga 57,96€ al mes: - Seguro de hogar de su vivienda: mantenemos??? - Seguro de salud con Sanitas: entiendo que hay que darlo de baja, por su situación ECO. Hay que llamar a Sanitas al 917522852 para darlo de baja antes del 30 de abril; si no, tendrá que pagarlo otro año." ························ Realizo la consulta a Estrella, TS CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-04-12','Ana: Recibo llamada de Bibi, TS - Plena Inclusión Mérida (924 31 20 56): les ha llegado resolución de plaza RAL para José Blas. Pero ha llamado a la familia (madre y hermano) y ninguno de ellos ni el propio José Blas, quiere venirse a vivir a Mérida. No quieren desarraigarlo. Confirmo esta información y que Maite, Jefa de Secc. ya habló con Andrés, Gerente de Down al respecto, pues Blas asiste allí a C.O. ······························· Acordamos que enviarán el documento a Down para que Blas firme allí la renuncia y luego nos lo harán llegar a nosotros para que lo firme también el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-04-12','En archivo adjunto se envía la factura del desplazamiento en taxi para el ingreso de Francisco en el CRR de Mérida, en el dia de ayer, la cual puede ser abonada por transferencia bancaria (incluido número de cuenta en la factura). La acogida en el centro ha sido positiva y su actitud con respecto a la institución también ha sido buena. Francisco valora el cambio que el centro le puede proporcionar, ya que en su localidad no tenía cubiertas las necesidades básicas de aseo, alimentación, descanso... Desde el centro tanto la educadora social (Cristina) como la terapeuta ocupacional (Gisela), le ayudarán a gestionar sus gastos de bolsillo, ya que muestra déficits en este aspecto. Hasta el momento retiraba toda la asignación.------------ Se acuerda con el centro mantener de momento los 400€ al mes y coger sólo una extra de gastos al año .La otra se le puede ahorrar. Se intentará sacar Seguro decesos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-04-12','miguel, envío nuevo email a Rafael de notaria de Don Benito: Gracias Rafael. Entiendo que la herencia sería por tanto de ambos padres, el padre Juan que fallece en 2010 y la madre Isabel que fallece en 2013, y ésta no dejó testamento, con lo que habría que hacer la declaración de herederos…, no así del padre que sí tiene testamento. A la fallecida madre tampoco le aparecía en catastro que tuviera ningún inmueble, motivo por el que os he pedido a Sara y a ti, me remitáis nota simple del inmueble para dárselo al abogado (que de oficio he solicitado) a efectos de que pueda pedir la aprobación de la herencia (adjudicándose el inmueble en la misma escritura notarial con lo que no hay escritura de venta posterior). También me hace falta tasación o informe pericial de valoración para que el abogado pueda acreditar al juzgado que el importe por el que se va a adjudicar el bien es igual o superior al que se indique en dicho informe pericial o tasación. En el caso de la madre, Doña Isabel Diaz Rodriguez, que sepamos, según veo en el expediente, sólo ha dejado una cuenta bancaria Caja de Extremadura de Plasencia nº 2099-001-50-0000676302 que a fecha de fallecimiento de la misma el 4-1-2013 era de unos 20.000€. La cuestión es que conforme el artículo 94 ley jurisdicción voluntaria 15/15, que establece que la el juzgado competente es el del domicilio del causente. Así, si solicitamos la autorización judicial para la aceptación de la herencia, tendríamos que dirigirnos al juzgado del domicilio del causante (y al ser dos causantes el padre fallecido en Don Benito y la madre en Plasencia) y para evitar tener que pedir dos abogados (que además serían de oficio, con lo que la burocracia dilataría el asunto) y dos procedimientos judiciales para la aceptación de la herencia, y teniendo en cuenta lo establecido en el actual artículo 289 del Código Civil (antiguo 271 Código Civil), que establece: “No necesitarán autorización judicial la partición de herencia o la división de cosa común realizada por el curador representativo, pero una vez practicadas requerirán aprobación judicial. Si hubiese sido nombrado un defensor judicial para la partición deberá obtener también la aprobación judicial, salvo que se hubiera dispuesto otra cosa al hacer el nombramiento”. Por tanto, si firmamos y después se pide la aprobación judicial de la herencia, sería plenamente legal y así lo hemos hecho muchas veces en otros expedientes. Echa un vistazo, si quieres con el notario, y confírmame si podemos hacerlo así, de tal forma que podríamos agilizar el trámite y sólo habría que pedir autorización judicial de la aprobación de la herencia ya firmada en notaria Te adjunto las sentencia firme de incapacitación y nombramiento a la Comisión Tutelar de Adultos, el testimonio de aceptación del cargo, dni y certificado de minusvalía de la curatelada e hija, Isabel Valades Diaz) Quedo a la espera de tu respuesta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-04-12','miguel, se trata de un error, la fallecida madre de la curatelada no es la que teníamos en la Ctaex tutelada, aunque se llamaba igual, según me aclara y veo en la testamentaria que me envía Rafa. Voy a solicitar abogado de oficio al Colegio de abogados de badajoz para que inste al juzgado la aceptación y aprobación de herencia al jzdo de Don Benito (lugar de fallecimiento de los padres) Rafa me envía la escritura de propiedad de la vivienda. Le he solicitado me tendrá que indicar qué compone la masa hereditaria para cuando el abogado solicite la correspondiente autorización judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-04-12','miguel, email a Rafa de notaria de Don Benito: Tras recibir su email con la escritura de la vivienda. Perfecto, gracias Rafael. Al tiempo que voy pidiendo el abogado de oficio para jzdo de Don Benito voy a hablar con Sara para que vayan liquidando el impuesto en una gestoría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-04-12','Ana: Correo de Puerto, TS SSASB de Valdeobispo (ssb5@mancomunidadvalledelalagon.es): "Buenos días: ayer estuve en el domicilio de Enrique para seguimiento del SAD, y efectivamente se ha comprado ropa, calzado y utensilios de limpieza, ha limpiado el patio... "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2023-04-13','Ana: Subo al portafirmas digital C.I. para utilización de contención mecánica: BARANDILLA CAMA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-04-13','Amalia: envio email al registro del SES: solicitudes y Modelo Alta 3º para cambio de cuentas en las pensiones de Orfandad y PFHC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-04-13','Amalia: envio email al registro del SES: solicitudes y Modelo Alta 3º para cambio de cuentas en las pensiones de Orfandad y PFHC . Una vez que se produzca el cambio , Oscar hará transferencia permanente a su hermano para cubrir gastos . Lo llamaré para informarle de este cambio , tb con delegada tutelar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-04-13','miguel, envio email a la notaria a pilar Buenos días Pilar mplgonzalez@despacho.notariado.org, no he logrado ayer ni hoy hablar contigo. Por favor, cuando puedas ponte en contacto conmigo para confirmarme si ya has logrado hablar con las dos hermanas que quieren renunciar a la herencia pero no quieren tener problemas con hacienda en el futuro (por donación…) Por otro lado, a efectos de que vayas preparando la declaración de herederos, creo que del centro ofrecían dos testigos. Dime si sabes algo. Por último si falta alguna documentación. Yo no dispongo en principio de más documentación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-04-12','Ana: Correo de Sergio Romero, Coordinador Proyecto Mi Casa Don Benito (sergioromerodiaz@plenainclusiondonbenito.org) al ctutelar@: "Me pongo en contacto como responsable del Proyecto Mi casa; una vida en comunidad en Plena Inclusión Don Benito por el tema económico de Felisa Bruno Saavedra. Os adjunto los datos del personal del apoyo necesarios para que lo transmitáis al banco, quedo a la espera de que me confirméis cuál es, para que acompañen a Felisa la primera semana del mes para sacar los 25€ mensuales. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-04-13','miguel, hablo con Rafa que me indica que el valor fiscal que indica la pagina de la junta ya no vale ya que desde hace más de un año, la valoración sale directamente de la pagina de catastro(enlace que Angel y yo no tenemos habilitado, y por tanto solo lo tendran las notarias). El valor que a él le sale la vivienda son 56.141,01€, mientras que en el valor fiscal de la junta eran 71.319,83€. Aun así dice que ellos pondrían un poco más en la escritura. Le comento a él y a Sara que todo esto dependerá del informe del perito que enviaremos al juzgado para que éste dictamine el precio mínimo. Al tiempo Sara buscará gestoría que tramite la liquidación del impuesto de sucesiones de los tres hermanos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-04-13','Ana: Llamada de Felisi (722 494 033) Su hijo está en su casa con ella desde el sábado. Dice que ya ha dejado la relación con Mirella. "Se porta regular", "no ayuda, come mucho y con ansia, sale para arriba y para abajo", "se alborota mucho", "dice que los electrodomésticos los ha pagado él y que la casa es suya y eso a mí no me gusta". Lo he recogido porque estaba por ahí pasando hambre. También le ha dicho que quiere trabajar y cambiar de vida. Que Mirella le ha "puesto los cuernos". Tiene un móvil nuevo. ··········· El Programa de Familia ya sabe que está ahí y han hablado con él. Hoy irán también a su casa. ················ Jesús se ha ido a casa de su madre, se ha llevado toda la ropa y todas sus cosas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-04-13','procedimiento de internamiento involuntario en el Juzgado nº 1 de Trujillo (nº de registro 306/23)','1');
