insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-04-13','Ana: Correo de Toni-Futuex: "Intentaremos llamarlo para quedar con el, a lo mejor, en la calle a ver que tal.. te voy informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2023-04-13','Ana: Correo de Toni-Futuex: "Se visitó ya, a Santiago Pajares Talavera, en Arroyo de la Luz, a falta de enviarte la nota de seguimiento, aunque normalmente el chaval acude a centro ocupacional a navofarma en Cáceres, por lo que es dificil pillarlo en el domicilio, pero en principio se obtuvo información que te pasare en cuanto tengamos redactada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-04-12','Ana: Correo de Anabel, TS Miajadas (servicios.sociales@miajadas.org): "sabes algo nuevo en relacion con el ingreso involuntario en centro de JOAQUINA? la situacion empeora por momentos, las deudas van en aumento, debe dinero en el estanco (tabaco), farmacia, pasteleria, catering de comida a domicilio, ...." ·············· Hablo con Anabel, TS, cada día la situación es más insostenible. ························· Reenvío el correo a los A. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-04-13','TERESA 11 abril: acompañamiento a Beatriz Mejías a la cita en los juzgados de Zafra y a pedir presupuesto de ropa. Se acude al domicilio de Beatríz y se le acompaña a los juzgados de Zafra. Se charla con el abogado de oficio asignado, Beatríz le explica su versión acerca del contrato de Vodafone a nombre de su hermana Rosi. Explica que, cuando ella vivía en el anterior piso en la barriada Salamanca de Zafra, en una de las visitas que le hizo Rosi, decidieron contratar una linea de teléfono e internet a nombre de ésta. Beatríz comenta que fue algo que gestionaron ambas para que Beatriz pudiera tener internet, por tanto Rosi es consentidora y conocedora de ello. Beatríz cuenta que Rosi necesita pedir un préstamo para comprar un coche pero que no se lo dan porque aparece como morosa debido a las facturas que debe a Vodafone. Beatríz asegura que ella es responsable de estas facturas y que quiere que esto se solucione para que Rosi no tenga a su cargo estas facturas sin pagar. El abogado le recomienda que diga la verdad o que puede no declarar si así lo desea. En el juicio Beatríz explica esto mismo ante el juez. Al salir comenta que se encontraba un poco nerviosa y que no quiere que su hermana se enfade por esto que ha dicho pero que es la verdad. El abogado de oficio comenta que esto va a seguir su curso legal y que él va a ser, en todo momento, el abogado de Beatríz durante el proceso. También explica que Rosi debería haber reclamado con respecto a este tema pero por vía civil con un abogado y un procurador, ya que dadas las circunstancias Beatríz es investigada y, al mismo tiempo, testigo. Se ha acompañado a Beatríz a pedir presupuesto de ropa a mundo moda, un bazar chino, se ha explicado a la encargada de la tienda el tema del presupuesto pero comenta que no trabajan de esta manera. Beatríz prefiere ir aquí a comprar ropa porque le sale mas económico que en las otras tiendas. Se ha acudido con Beatríz a tomar un café y se ha calculado más o menos cuánto puede necesitar para comprar esa ropa y calzado que necesita: 40€ (2 vaqueros) 25€ (camisetas) 20€ (2 mallas) 15€ (ropa interior) 30€ (ropa de vestir, algún vestido o similar) 25€ (sandalias) TOTAL: 155€ aproximadamente. Se le podría dar este extra (entre 140€ y 150€) y nosotros podríamos acompañarla a comprar la ropa y después remitir el tiquet o factura correspondiente. Beatriz comentaba que esta misma información la comunicaría a la Comisión directamente. También se ha hablado con Virginia (casera de Beatriz) que ha facilitado el contrato de arrendamiento debidamente firmado por ella y, además, mandará esta semana una nota para entregar en el padrón del Ayto. De Zafra sobre la modificación de bajo A, en lugar de 1ºA como aparece en el contrato, también debidamente firmada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-04-13','Ana: Respuesta de Ángel, A. Jurídico: "El Juzgado nº 1 de Trujillo (nº de registro 306/23), me dice que aún no han incoado el expediente. Toca esperar." ··········· Lo reenvío a Anabel, TS SSASB-Miajadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-04-13','miguel, me llama la medico del CSS Mérida y Mª Angeles Galindo trabajadora social para consultarme para asesorar al tutelado ya que esta atormentado por una pena que cumplio en los años 80 por un homicidio en la Zarza (a la que dice no poder volver por ese motivo) Despues me llama el tutelado para asesorarse por lo mismo, donde lo que él quiere es que se demuestre su inocencia y paguen los que lo hicieron. Al tiempo se queja que el Alcalde en ese momento nunca le arregló los papeles del paro ya que trabajó unos meses para el ayto de la Zarza. Me pide que localice su procedimiento a la Audiencia provincial de Badajoz nº2, pero no indica ni nº de procedimiento ni ninguna documentación que dice no tiene. Tras escucharle le indico que son procesos finalizados, cosa juzgada y que cualquier acción está prescrita, ya que los hechos son de los años 80. Le informo que en próximos meses seguramente se inicie de oficio por el jzdo de Mérida nº2 la revisión de su sentencia de incapacitación para su adaptación a la ley 8/21 de medidas de apoyo y allí él podrá expresar sus inquietudes, incluida ésta. Una vez lo exponga le pido pase página y deje enterrado el pasado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-04-13','Ana: Envío correo a los A. Jurídicos CTAEx, con copia a Maite, Jefa Secc.: "Con respecto Julia Morón Hernández, si recordáis, tenía pendiente enviaros documentos relativos a su ALTA VOLUNTARIA del CRR, acordamos que cuando tuviéramos todo os lo enviaba. Estaba esperando porque también pedí informe a Futuex, pero en vista de que aún no lo han enviado y que tenemos otros dos, creo que es suficiente para COMUNICARLO AL JUZGADO. Por tanto, os adjunto: - Documento de Alta Voluntaria del Centro Residencial de Rehabilitación de la Red de Salud Mental, firmado por la propia Julia. - Informe del mismo centro (CRR) - Informe de la Trabajadora Social de los Servicios Sociales de Atención Social Básica de Cilleros, localidad donde regresó a vivir de nuevo, al domicilio familiar con sus padres - Resolución SEPAD de Pérdida de Plaza En relación a la citación que nos indicas, intento averiguar algo y os digo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-04-13','Ana: Correo de la Residencia Femar: "Adjunto cita presencial de oftalmología de Valentina Fernandez. El acompañamiento sería desde que sale de la residencia en la ambulancia hasta que regresa , y el precio es 50 euros. La chica que la acompaña cuando llega aquí nos informa de los cambios o advertencias que indique el doctor y nos dará documentación remitida por el oftalmólogo." ················· Guardo Citación: 17/04/23. ················ Se acepta el acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-04-13','-Amalia : recibo llamada de la TS de SSASB de Calzadilla , Nuria 606712992. Alarma social en el pueblo tras el regreso de Javi al domicilio familiar . Confirmo que por la ejecutoria 444/22 cumplió 10 meses de internamiento en CSS , liquidó esa condena el 26 de diciembre. No se le puede impedir juridicamente que vuelva a su casa . Solicitamos a la Sección Salud Mental que mantengan la plaza en CRR unos días más por si conseguimos que regrese.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-04-13','Ana: Correo de Sergio Romero, Coordinador Proyecto Mi Casa Don Benito (sergioromerodiaz@plenainclusiondonbenito.org) respondiendo a mi consulta sobre los primeros días de Felisa en el recurso: "Pues la verdad que genial, por ahora sigue muy contenta. Ayer hicimos fiesta de inauguración en la que no faltó tema de conversación, pero súper contenta e integrada con sus compañeros y con el personal de apoyo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-04-13','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Informar sobre el alta en la UHB de Cáceres de la persona usuaria Consuelo Nevado Pacheco en la tarde de ayer. Seguiremos informando de la evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-04-13','Ana: Correo de Nerea, Coordinadora de Cáritas Tarragona (nlopez.cit@caritasdtarragona.cat // 977 24 23 37 // 640 365 497): "soy Nerea, la coordinadora de Càritas aquí en la ciudad de Tarragona. Hasta ahora has estado hablando con mi compañero Germain, pero él es la persona de recepción y valoramos que no tienen las competencias para abordar el caso de Javier. sé que él le ha ayudado a buscar un hostal donde dormir y tambien en la gestión de poder tener numero de cuenta para que pueda tener ingressos. Que tipo de intervención haceis con este chico? Nosotros des de càritas no conocemos para nada el caso, y es por eso que me gustaria tener información y valorar si es el recurso necesario para él o no." ···························· Mi respuesta: "Encantada. Gracias por ponerte en contacto. Desconocíamos el puesto de Germain, pero de entrada fue el único contacto del que disponíamos y nos vino fenomenal para poder contactar con Javier. Con respecto al número de cuenta, que sepamos, lo único que ha hecho Germain es confirmarnos que hay una sucursal de Ibercaja en la C/ la Unió. De las gestiones oportunas con la entidad bancaria se encargarán mis compañeros de la Sección Económica de la Comisión Tutelar de Adultos de Extremadura (CTAEx). Pues allí no oficinas de la entidad en que él tiene su cuenta y en la que le ingresan su pensión. Javier está a cargo de la Comisión Tutelar de Adultos de Extremadura por Sentencia Judicial (Antigua Tutela), está pendiente de revisión para la provisión de las nuevas Medidas Judiciales de Apoyo para Personas con Discapacidad. Residía en un recurso de la Red de Salud Mental de Extremadura, donde estaba bien atendido, estable y aparentemente conforme con su proceso terapéutico, trabajando para su futura vida independiente, pero de la noche a la mañana decidió marcharse a Tarragona sin previo aviso. Él no quiere regresar, no ha habido manera de que cambie de idea y tampoco se le puede obligar, no hay sentencia alguna de internamiento involuntario en la actualidad. Y como sabes, de acuerdo a la Ley 8/21, hay que atender sus deseos y preferencias. Esta situación ya ha sido comunicada de forma oficial a Fiscalía y al Juzgado competentes hasta la fecha en que se marchó. Desde éstos, entendemos que se pondrán en contacto con los que correspondan de Tarragona. Por nuestra parte, en la medida que él nos lo permita y en la de nuestras posibilidades, seguiremos apoyándole para que su situación sea mejor de lo que ha estado siéndolo durante las primeras semanas que ha pasado en vuestra localidad. Especificar, eso sí, que si finalmente decide establecer su residencia en Tarragona, sería bueno que buscara un piso de alquiler y que pudiera asignársele un centro de salud. Cuestión que ya hemos hablado también con él por teléfono, pero él no quiere ningún tipo de control. *Una de la cuestiones que más nos preocupan es que se marchó sin su medicación y, sin ésta y sin los seguimientos periódicos en el Equipo de Salud Mental puede volver a descompensarse. Ante cualquier cuestión, no dudes en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2023-04-13','Ana: Solicito a Aurora, TS de la Mancomunidad (mancomunidadaurora@hotmail.com) que nos remitan el DNI de Andrés escaneado a color.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-04-14','Ana: Felisa, madre de Aitor, nos comunica que éste volvió el sábado pasado a su casa. Ya no mantiene relación con Mirella. Le dio tanta pena que le dejó entrar. ··········································· Correo del Programa de Familia (programafamilia@tajosalor.es): "Comunicarte que AITOR de nuevo está viviendo en Navas con su madre, con Felisi, pero ha dejado a su novia Mireia. Ahora nos demanda que hagamos con él la compra semanal como hacíamos cuando vivía en Navas" ······································ Correo de Ángel, A. Jurídico, en relación a la vuelta de Aitor al domicilio de la madre: "...ha habido, hasta ahora, 2 inhibiciones, os puedo decir que lo último que tenemos es que llegó ayer a Trujillo y le han dado traslado al Forense, que está de baja, para que señale día de reconocimiento forense (procedimiento ITR 138/23). Ahora, si como dices, está en el domicilio de Felisa, que está en Navas del Madroño, Trujillo volverá a inhibirse a Cáceres, que es el competente." ························ Teresa, TS CTAEx, solicita al PAF que se reanuden las compras tal y como se hacía antes, cuando vivía con Mirella. Así colabora en casa con la compra de comida y otros productos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-04-14','Ana: Pido al PAF que intenten llegar a un acuerdo con el estanco, al igual que con el supermercado, para la compra de tabaco mensual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-04-14','miguel, Inés enviará hoy por lexnet comunicación al juzgado de Plasencia nº5, la comunicación de la documentación recibida por Ana de Alta voluntaria en el CRR Plasencia, a los efectos oportunos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-04-14','Ana: Reenvío correo de Futuex a la Secc. Ecca. - ctutelar@ : "Os reenvío correo de Toni – Futuex, todo es eco: gestión con banco (subrayo en amarillo en el hilo) y asignación (subrayo en verde). Solicitan aumento de la asignación, no indican cuantía, pero yo entiendo que con la pensión de viudedad que tiene ahora y viviendo ya sola (es decir, antes contaba con los ingresos del Marido y las compras que hacía éste) los 200 € resultan muy escasos. Por mi parte, incluso le doblaría la asignación mensual, que todo se ha encarecido mucho."','2');
