insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CASADO'and apellido2='CARRION'),'2023-04-14','-Amalia : Tras estudio del caso , realizo Plan de intervención. Antonia se encuentra en URA del CSS , tiene 2 hermanas que residen en la casa familiar que la visitan mensualmente . Todas ellas presentan discapacidad intelectual . Adaptada a CSS y sin expectativas de externalización actualmente. Percibe PFHC Y P. ORFANDAD. Se abona el 75% de los ingresos de copago en el centro. Gasta poco dinero . Solicito a sección eco que den autorizacion a la Direccion del centro para poder sacar algún extra para ropa y gastos de bolsillo. Hay que abonar la parte que le corresponde a ella de la poliza de decesos de Sta Lucia con nº 32167879.Es conjunta de las 3 hermanas . Se lo paso a sección eco. tf de las hnas . 622202638-656423603','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CASADO'and apellido2='CARRION'),'2023-04-14','Email a seccion eco : Se necesita enviar autorización al Dtor. para que puedan sacar algún dinero extra para ropa . No se le pone reintegro pq no gasta apenas. De cogago de plaza se abona el 75% de sus ingresos . Con respecto al S. decesos , tiene hecho uno conjunto con sus 2 hnas en Sta. Lucia . No tienen la poliza pero sí el Nº 32167879. Habría que abonar la parte proporcional que le corresponde a cada hna. Os facilito tf. de la persona que gestiona este seguro : Virginia 927629824-680422690','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2023-04-14','Buenas , este plan de intervención lo hago yo , se encuentra ingresada en CSS de Plasencia. Se necesita enviar autorización al Dtor. para que puedan sacar algún dinero extra para ropa . No se le pone reintegro pq no gasta apenas. De cogago de plaza se abona el 75% de sus ingresos . Con respecto al S. decesos , tiene hecho uno conjunto con sus 2 hnas en Sta. Lucia . No tienen la poliza pero sí el Nº 32167879. Habría que abonar la parte proporcional que le corresponde a cada hna. Os facilito tf. de la persona que gestiona este seguro : Virginia 927629824-680422690','1');
