insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-04-14','Ana: Llamada de Mª Carmen, TS del HSPA (56283): Han hablado con la Abogada, Carmen Lucas, dice que el Fiscal ha ofrecido: 2 años y 6 meses de prisión o 3 años de internamiento en centro Psiquiátrico. Además de una de estas 2 tendrá que cumplir 10 años de libertad vigilada con seguimiento de tratamiento psiquiátrico. ··············· Lo comunico a los A. Jurídicos y planteo si puede decidir y firmar el documento el propio Saturnino. ······························································································································································································· Respuesta de Miguel, A. Jurídico: "estamos un poco perplejos porque esa decisión corresponde al fiscal no al tutelado ni a la Ctaex. No entendemos que el juzgado no haya comunicado esto por escrito y esto se trate de una llamada de una intermediaria que no tiene que ver con el juzgado… En base a las pruebas aportadas para el enjuiciamiento del procedimiento en el jzdo nº6 CC que ha conocido del delito de agresión sexual, deben ahí decidir cual es la medida más adecuada para él. A nuestro entender no es la Ctaex ni el tutelado quienes deben tomar esa decisión. Nos remitimos de nuevo al acta de la subcomisión donde recomendaban que el centro más adecuado es el centro penitenciario psiquiatrico. Recordemos que esa es también la línea del defensor del pueblo, que vaya a un centro adecuado y no a la cárcel. Por último recordemos que el jzdo nº2 CC(su juzgado, nos denegó el internamiento involuntario porque desde el Sepad se dejó claro que el ESM no es un centro adecuado y que por eso se convocó una subcomisión) En conclusión, que quien menos debería tomar esa decisión es el tutelado, y que la misma debe ser tomada conforme a las pruebas del procedimiento, y por parte de la Ctaex deberíamos remitirnos al acta de la subcomisión." ············································································································································································································ En cuanto al deseo de Saturnino de hablar con su madre, llamo a Mar, hermana de Saturnino (690 671 204): dice que su madre está fatal y no puede hablar con Saturnino. Tampoco quiere hablar ella ni su hermano. ········· Se lo comunico a Mª Carmen, TS HSPA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2023-04-14','Ana: Recibimos RESOLUCIÓN de dependencia aprobatoria de PRESTACIÓN VINCUALDA AL SAR. Le corresponde un importe mensual de 175€, le corresponden 215, 83€ de atrasos, por lo que el primer abono a percibir: 390,83€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2023-04-14','Ana: Raquel, Secc. Salud Mental, nos trae con nota interior: RESOLUCIÓN de PERDIDA DE PLAZA en CRR, por derivación a Recurso de Mayores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-04-14','Amalia : escribo a todos los recurso implicados: Buenos días , como sabéis Javi firmó el martes pasado su alta voluntaria del CRR de Mérida por querer volver a su casa con su padre y porque no está dispuesto a dejar el consumo de cannabis. Tras su llegada al pueblo se ha generado alarma social . Previo a su ingreso en CRR estuvo ingresado en CSS cumpliendo medida judicial por 10 meses por amenazas a un chico del pueblo . El padre verbaliza que en su casa no puede residir . Hay que puntualizar que tanto el padre como sus hermanos por parte de madre , que residen con ésta en Fuente de Cantos ,presentan consumo de drogas . La TS del SSASB insiste en que en el pueblo no puede quedarse . Ante esta situación , pedimos a la Sección de Salud Mental , que se le reservara la plaza durante unos días antes de darle de baja por si cambiaba de opinión. Así ha sido y Javi está dispuesto a regresar al CRR . He contactado con Javier , director del CRR que no se opone a darle otra oportunidad en el recurso , a pesar de que no está cumpliendo con los objetivos de la rehabilitación. Regresa con el compromiso de dejar el consumo , se está trabajando este objetivo en coordinación con el Equipo de Conducta Adictiva. Si no fuese así , iniciarían expediente de expulsión del recurso . He coordinado tanto con el CRR , como con el SSASB que Javier regresará el lunes a primera al centro . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2023-04-14','TERESA EVIO SOLICTUD DE DEPENDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-04-14','Amalia : escribo a todos los recurso implicados: Buenos días , como sabéis Javi firmó el martes pasado su alta voluntaria del CRR de Mérida por querer volver a su casa con su padre y porque no está dispuesto a dejar el consumo de cannabis. Tras su llegada al pueblo se ha generado alarma social . Previo a su ingreso en CRR estuvo ingresado en CSS cumpliendo medida judicial por 10 meses por amenazas a un chico del pueblo . El padre verbaliza que en su casa no puede residir . Hay que puntualizar que tanto el padre como sus hermanos por parte de madre , que residen con ésta en Fuente de Cantos ,presentan consumo de drogas . La TS del SSASB insiste en que en el pueblo no puede quedarse . Ante esta situación , pedimos a la Sección de Salud Mental , que se le reservara la plaza durante unos días antes de darle de baja por si cambiaba de opinión. Así ha sido y Javi está dispuesto a regresar al CRR . He contactado con Javier , director del CRR que no se opone a darle otra oportunidad en el recurso , a pesar de que no está cumpliendo con los objetivos de la rehabilitación. Regresa con el compromiso de dejar el consumo , se está trabajando este objetivo en coordinación con el Equipo de Conducta Adictiva. Si no fuese así , iniciarían expediente de expulsión del recurso . He coordinado tanto con el CRR , como con el SSASB que Javier regresará el lunes a primera al centro . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-04-14','Buenos días, adjunto para su cumplimiento la medida impuesta por el juzgado de plasencia nº4 consistente en: Parte social :continuación del tratamiento médico psiquiatra de dos meses Parte económica: el abono de la indemnización de los 114€ que podeis ver en el documento Exhorto. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-04-14','Ana: Según la sentencia, "la curatela será de naturaleza representativa en el ámbito personal y patrimonial" ······························································································································································································· Envío derivación al Programa de Apoyo comunitario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-04-14','Ana: Correo de Ana Mª, Ed. Social Plena Inclusión Zafra (social@plenainclusionzafra.org): "A Reme le dan el alta en un momento…está mucho mejor, la placa de ayer estaba casi limpia y hoy han probado con quitar oxígeno y ver saturación y nueva analítica y valoran el alta. Aun así preocupa la repetición de esta neumonía y la derivaran al neumólogo para seguimiento. El lunes te adjuntaré todos los informes que traiga del hospital y pasare a Eco el resto de horas de las cuidadoras. Hoy por suerte esta su profesional de referencia allí y facilitará todo el tema del alta y el regreso al centro. Ella desde que escuchó ayer alta, está triste y mal porque no quiere venir (incluso decía que estaba peor y no podía estar sin oxígeno) entendemos perfectamente el por qué…ha estado en el hospital 24 horas sola pero con supervisión constante. Las cuidadoras con ella han estado genial, muy pendientes y cariñosas (le llevaban fresas con nata, churros con chocolate…) y aquí , aunque tiene supervisión constante y exclusiva, vuelve a ser una más. En fin…el lunes vuelvo a escribirte."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-04-14','Ana: Correo de Pilar Martín, TS ESM-CC (pilar.martinp@salud-juntaex.es): ", ESTA MAÑANA HE TENIDO A MIGUEL ÁNGEL RAMOS ANDRES, POR EL TEMA DE LA TARJETA SANITARIA LE HE DERIVADO A SU CENTRO DE SALUD PARA QUE LE HAGAN LA DE DESPLAZADO, AHORA EL SE ENCUENTRA EN EL ALBERGUE DE RIOS VERDES Y ASISTIENDO AL COMEDOR SOCIAL. LE HE DERIVADO DE NUEVO AL ECA. SEGÚN ME DICE NO TIENE MÓVIL."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-04-17','Ana: Envío correo a Mamen, TS Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Te escribo en relación a Miguel Ángel Ramos Andrés, pues no hemos recibido de tu compañero el documento informativo (certificado o breve informe) sobre su estancia en el Centro de Emergencia Social. ¿Te importaría recordárselo?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2023-04-17','TERESA REGISTRO SOLICITUD TARJETA DE TRANSPORTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-04-17','Ana: Llamada de Felisi (626 16 44 02): Aitor sigue allí, dice que ya casi no les queda comida. Le explico que se establecerá un acuerdo con el supermercado como se hizo en su día. ······· De todas formas mañana tiene previsto ir a retirar su asignación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-04-17','Ana: Envío correo a Leire Sanz, TS - Centro de Mayores Ciudad Jardín Cánovas (t.socialcanovas@grupociudadjardin.com): "En relación a JOSEFA SÁNCHEZ DÍAZ, te reenvío correo de mi compañero Miguel, A. Jurídico. Desde el Juzgado solicitan INFORME MÉDICO necesario para la revisión de su sentencia de incapacitación y provisión de las nuevas medidas judiciales de apoyo. ¿Podríais solicitárselo a su Médico de Atención Primaria? En cuanto a la vista (“práctica del acto”), se hará mediante videollamada, a través de CISCO. En los documentos adjuntos tenéis la información. Ante cualquier cuestión, no dudes en contratar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-04-17','Ana: Correo de Estrella Durán, TS CCS-Plas: "En relación a JOSEFA SÁNCHEZ DÍAZ, te reenvío correo de mi compañero Miguel, A. Jurídico. Desde el Juzgado solicitan INFORME MÉDICO necesario para la revisión de su sentencia de incapacitación y provisión de las nuevas medidas judiciales de apoyo. ¿Podríais solicitárselo a su Médico de Atención Primaria? En cuanto a la vista (“práctica del acto”), se hará mediante videollamada, a través de CISCO. En los documentos adjuntos tenéis la información. Ante cualquier cuestión, no dudes en contratar." ·························· Mi respuesta: "Me parece bien que esté ocupada en estas gestiones y con el apoyo de la T.O. mejor aún. Ya nos iréis informando,. En cuanto a solicitarle Teleasistencia, me parece muy buen idea, no lo había planteado porque ella siempre ha sido reacia a estas cuestiones, pero en cuanto pueda me pongo con la solicitud. Por cierto, ¿creéis que aceptaría Ayuda a Dominio? Sería otra forma de que tuviera un apoyo y “seguimiento” más continuado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-04-17','Ana: Correo de Ana Mª, Ed. Social Plena Inclusión Zafra (social@plenainclusionzafra.org): "El fin de semana ha estado bastante nerviosa. Ha intentado en varias ocasiones autolesionarse: con las uñas, con la piel de los talones y quitando un cristal de la gafa, que se metió en la boca pero por suerte no le dio tiempo a ingerir y se lo devolvió a los monitores. Hoy lunes, desde primera hora con su monitora de referencia, llorando y demandando atención… sabemos que no quería venirse de hospital por toda la atención recibida allí y el fin de semana en residencia, con cambios de turnos del personal y menos actividad que en el centro de día…se le habrá hecho más cuesta arriba. A ver que tal la semana y si su rutina la ayuda y frena un poco el intento de ingesta y demás porque nos preocupa, la verdad, está bastante ansiosa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2023-04-17','Ana: Llamada de Minerva, TS del CR Cervantes (22237): Mª Luisa tiene una úlcera vascular grave en la pierna, la tiene infectada. El médico le ha recomendado unos sobres de Iodo en polvo, que no entran por la Seg. Soc. (80-90 €). ····· Nos envía el informe médico con dicha recomendación y solicitando se apruebe el tratamiento. ············ Guardo el informe en el expte. y lo remito a la secc. ecca. con mi ok a la compra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-04-17','Ana: Ángel y Miguel, A. Jurídicos, hablan con María, Psiquiatra del HSPA, y con la Abogada, Carmen Lucas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-04-17','Ana: Envío correo a Julia, Coord. Casa de la Misericordia (casadelamisericordia.alcuescar@gmail.com): "En relación a Doroteo Días Cerro, creo que ya lo sabíais, pero me piden desde la sección jurídica que os recuerde la cita de mañana 18/04/23. Adjunto documento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-04-17','Ana: Corre de ayer domingo, de Sara García Martín, TS de Residencial Banium, Baños de Montemayor (TrabajadoraSocialBanium@hotmail.com): "Informarles que Doña Concepción Barbero se encuentra ya de nuevo en el Centro residencial Banium desde la tarde del día 14 de abril de 2023. La intervención de cadera ha salido bien, y se ha comenzado hoy con el proceso de recuperación por parte de la fisioterapeuta del centro. Vamos a trabajar para intentar recuperar la deambulación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-04-18','Ana: Correo de ayer de Isabel, al ctutelar@ (imariacano.ic@gmail.com): "he hablado con Ceferino Mariscal Crespo mi pareja actual y con mi madre y queremos irnos los tres a un piso de alquiler y lo pagamos los tres a medias qué te parece por favor quedemos irnos del CRR" ····························································· Mi respuesta: "Como en planteamientos anteriores, tengo que decirte que son decisiones muy importantes, que hay que madurar bien. Considero que sería muy beneficioso que lo hablases con las profesionales del CRR. Me parece que aún es pronto para que salgas del recurso, pero son ellas quienes mejor conocen tu evolución y pueden apoyarte en tu proceso. Pongo en copia a Paula y Bea, para que estén al corriente y cuando puedan, si lo consideran, aborden esta cuestión contigo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-04-18','Ana: Correo de Óscar a Ana Sánchez, Residencia (anatdelat@hotmail.com): "Se aprueba la subida de asignación a 100€ a partir del 1 de mayo. Se realizará la recarga correspondiente en la tarjeta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2023-04-18','Ana: Llamo a Gema, Gerente P.T. Casas del Monte (649 163 256): De momento Félix se está adaptando bien. El tabaco se lo está administrando él solo. Su asignación económica (de momento el dinero que llevaba del piso) se lo está administrando ella. ·················· *Nos enviará el contrato de ingreso en el PT así como la Orden SEPA para cargarle en cuenta el coste de la plaza. Pasan el recibo a primeros de cada mes. Puesto que abril, al haber ingresado a mediados de mes, no se lo han cobrado, se lo pasarán junto al de mayo. ····· La asignación en principio se mantendrá. Habrá que ver si puede retirarla en el pueblo. ································· Comunico a Alberto y a Julio, CTAEX el cambio de recurso para modificación en la base de datos y lo relativo al abono de la plaza y asignación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2023-04-18','Ana: Remito a la Oficina de Atención al Ciudadano(oac.merida.san@juntaex.es) :"Adjunto remito Oficio-Solicitud de Certificado Actualizado de Pensión, relativo a ANDRÉS LANCHO SANGUINO, cuyo cargo de Curatela Representativa ostenta la CTAEx, para darle registro y remitir a la Dirección Provincial del INSS de Cáceres, junto a la siguiente documentación: - Testimonio de Firmeza de Sentencia de Medidas Judiciales de Apoyo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2023-04-18','Ana: Llamo a Juan (633 391 891 / 613 11 20 91), pues ha llamada a Amalia, dice que está en el banco y no le dan el dinero. ········· Le llamo varias veces, pero no coge el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-04-18','-Amalia : nos envian oficio del INSS , han cambiado el domicilio a efectos de notificaciones como he pedido . Han reenviado la Fe de vida a Alemania . No tienen información de la otra pensión de Alemania que no somo capaces de encontrar.','2');
