insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2023-04-18','Amalia , se registra la declaración. Cuando el centro me envie el cdo. solicitado lo enviaré a esa misma dirección. Se adjunta declaración de persistencia de requisitos de nuestro tutelado Jesus Bermejo , para la percepción de la prestación por hijo a cargo de MUFACE y documentación anexa. Para registrar a : SERVICIO PROVINCIAL DE MUFACE DE CACERES SECRETARIA DE ESTADO DE FUNCION PUBLICA MINISTERIO DE HACIENDA Y F. PUBLICA EA 0040071 Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-04-18','Ana: Remito a la Oficina de Atención al Ciudadano(oac.merida.san@juntaex.es): "Adjunto remito Oficio-Solicitud de Certificado Actualizado de Pensión, relativo a DOROTEO DÍAS CERRO, cuyo cargo ostenta la CTAEx, para darle registro y remitir a la Dirección Provincial del INSS de Cáceres, junto a la siguiente documentación: - Testimonio de Firmeza de Auto de Remoción y nombramiento"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-04-18','Amalia , a Eva de P.Inclusión : adjunto solicitud firmada por el Gerente . Tiene que firmarla el usuario y el punto 4 tenéis que indicarlo desde la Entidad . Todo ello , junto con los informes en su caso que estiméis oportunos lo registráis al CADEX directamente . Saludos .','2');
