insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-04-18','miguel, me llama el abogado por encargo de la hermana de la tutelada, Josefa, Javier Agenjo Ruiz javieragenjo@hotmail.com, movil 687-277737,tlfno 924-800050 c/ Portugal Don Benito, y quedo en enviarle la testamentaria que me envió Rafa de la notaria de Don Benito, catastro, valor fiscal de la junta, dni, certificado de minusvalía, sentencia de incapacitación y nombramiento a la Ctaex. Le explico que hay que liquidar Impuesto de Sucesiones, hace falta tasación, y autorización judicial de aceptación y aprobación de la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-04-18','Ana: Llamada de Carlos (665 022 593): Ayer le visitó Futuex. No recuerda el nombre de la educadora. ················ Dice que su padre maltrataba a su madre. ········· En cuanto ésta falleció movió todo para solicitar la remoción del padre, al que ha puesto varias denuncias. ··············· Verbaliza que en la escrituras de su vivienda, el padre consta como su tutor, no como propietario. ············ También dice que su padre ha acudido varias veces a su casa a amenazarle. La última vez con "un cuchillo jamonero". ····································· En cuanto a su asignación semanal, pide poder retirarla poco a poco, todas las semanas y a ser posible lunes y jueves. Esto no sé si es posible, ya le confirmaremos, pero una vez a la semana seguro que sí. ······················ En cuanto a la comida, dice que le gustaría tener cáterin, pero cobrando una PNC, no podrá permitírselo. ················ En la Asoc. Cultural, Clesis le dan alimentos la primera semana de cada mes. ············· La oficina bancaria en la que quiere retirar dinero es la de la C/ de la Cruz de los Caídos. ·············· Considera que no necesita SAD. Pero al plantearle la posibilidad de serv. para hacer la comida, le gusta la idea, sobre todo si la persona le enseñase a cocinar. *Plantearé la posibilidad al IMAS. ···················· No fuma. ············ Va a la peluquería todos los meses (8€/mes). ·················· Tiene 2 perritas. Una de ellas es pequeña y necesita vacunas. La lleva a la Clínica SANACAN (927 21 69 99 / Avda. Isabel de Mostezuma), la perrita se llama Chispi. -- Preguntaremos si se puede abonar por transferencia las cuestiones pendientes. ··············· En cuanto a su seguimiento en ESM, está pendiente de nueva cita. Ahora no toma medicación, dice que la dejó de forma pautada por la Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-04-19','Ana: correo de ayer de Isabelal ctutelar@ (imariacano.ic@gmail.com): "Hola Ana estoy muy preocupada a mi madre le an cortado la luz y mañana la cortan el agua aver si la puedo ayudar en algo porfa estoy triste no tengo ganas de nada mi madre no puede pagarlo hasta mayo..." ······················· Mi respuesta: "Con respecto a esta cuestión, supongo que tu madre habrá acudido a los servicios sociales de Trujillo, para solicitar las ayudas que le puedan corresponder. Si no es así, sería bueno que le dijeras que acuda para solicitar ayuda. Con respecto a que tú puedas ayudarle económicamente, tendríais que hacernos llegar documentos que justifiquen el corte de suministros y la deuda que tiene. Desde la sección económica valorarían si puedes ayudarle y con qué cantidad. Pongo en copia a las compañeras del CRR para que estén al corriente y por si pueden ayudaros a recabar y remitirnos la documentación que te indico. Un saludo y mucho ánimo." ··············································· En otro correo de ayer solicita dinero para ir en verano de vacaciones a Islantilla. Le recuerdo que estas peticiones tiene que ser a través de Paula, T.O. ······················ Tras nuevos correos de Isabel con imágenes de las facturas impagadas, así como un requerimiento, y diciendo que en los SSASB no le ayudan, llamamos a Mercedes, TS SSASB, tras hablar con ella envío nuevo correo a Isabel, con copia a Paula y Bea, CRR: "Hemos hablado con Mercedes, Trabajadora Social de los Servicios Sociales de Trujillo, nos dice que tu madre no ha pasado por allí. Si tu madre hubiera solicitado con anterioridad el Bono Social, por ley no le hubieran cortado los suministros. Además puede que le corresponda los Mínimos Vitales, así que Mercedes nos ha dicho que vaya para allá. Como para el reenganche de luz, sería más complicado a través de estas ayudas, quizá sí podrías ayudarle tú para abonar esa parte, si Alberto, Jefe de Sección Ecca. lo aprueba. No obstante, hasta que no nos confirmen desde Servicios Sociales que ha hecho las gestiones oportunas y que reúne los requisitos, no se va a abonar nada, pues de continuar con esta dinámica de impagos, volverán a cortarle los suministros y vuelta a empezar. Espero haberme explicado bien. Pongo de nuevo en copia a las compañeras del CRR." ··············································································· Respuesta de Paula: "hemos leído los correos que habéis intercambiado con Isa, muchas gracias por informarnos y ponernos en copia. Respecto a la situación de su madre: Isa lleva un tiempo hablando de las dificultases y nuestra recomendación en todo momento estaba en la misma línea que la vuestra, que su madre acudiera a servicios sociales para informarse de los apoyos que podía recibir. Si bien Isa no nos ha verbalizado en ningún momento que fuera a comunicarse con vosotros al respecto. Respecto a unas posibles vacaciones: ya acordamos con Isa en su momento que debía elegir, de forma razonada, en qué se invertiría el dinero anual. Con apoyo ha identificado lo que ha considerado más relevante, no siendo las vacaciones. De hecho en la última sesión que tuvimos lo explicitamos y era consciente de no poder destinar dinero a esto porque tenía otras prioridades."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-04-19','Ana: Llamada de Felisi (626 164 402): dice que no le gusta Virginia, Ed. Futuex, que dice algunas cosas que no le gustan. Le dijo que las rejas tenían que estar cerradas y ella dice que de día le gusta tenerla abierta. ············ Aitor, pasó ayer todo el día fuera con un amigo. Espera que puedan entenderse mejor los dos. Y que él colabore en la limpieza de la casa. ············· Jesús, le llamó y le dijo que ya no estaba viviendo ahí con ella por su familia, pero que la quiere mucho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-04-19','Imagino que estaréis enteradas por Soraya, pero mando correo para que quede constancia de ello. En la tarde del lunes, se acompañó a Emi a urgencias donde finalmente se decidió ingresarla en UHB. No hubo alteraciones conductuales en este caso, se le acompañó por desesperanza, lenguaje desorganizado y demanda constante de ayuda. Creíamos conveniente y necesario un ingreso (aunque sea breve), por la desestabilización que presentaba estas últimas semanas y meses. Ayer me comentaron desde psiquiatría que Emilia se encontraba tranquila. Seguiremos pendiente del proceso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-04-19','Imagino que estaréis enteradas por Soraya, pero mando correo para que quede constancia de ello. En la tarde del lunes, se acompañó a Emi a urgencias donde finalmente se decidió ingresarla en UHB. No hubo alteraciones conductuales en este caso, se le acompañó por desesperanza, lenguaje desorganizado y demanda constante de ayuda. Creíamos conveniente y necesario un ingreso (aunque sea breve), por la desestabilización que presentaba estas últimas semanas y meses. Ayer me comentaron desde psiquiatría que Emilia se encontraba tranquila. Seguiremos pendiente del proceso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-04-19','Buenos días Patricia , te reenvío la respuesta del jurídico que me planteabas. Quedamos pendiente del tema de asignación de plaza , gestionar el empadronamiento , establecer pto. mensual y deudas pendientes . A ver si no se demora mucho el tema de la plaza que podamos avanzar. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2023-04-19','miguel, hablé días anteriores con el hijo de la tutelada que andaba preocupado porque la familia le presionaba para que se vendieran los bienes o renunciaran a la herencia. Yo le expliqué que no se va a renunciar a la herencia y que ella no dispone de capacidad económica pero eso no significa que vaya a renunciar a la herencia.*************************** Me llama la sobrina de la tutelada Rebeca y despues de explicarle que no va a renunciar a la herencia y que no pueden vender sin autorización judicial (a través de la Ctaex), quedamos en que iran a una notaria (la de Moraleja seguramente) y me enviaran la información para ver si tiene dinero suficiente para pedir autorización judicial','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-04-19','Buenas tardes. Informaros que en el día de hoy ha llegado una cédula de citación judicial para Juan José Murillo Romano con respecto a un robo con fuerza. Dicho procedimiento tendrá lugar el día 11 de mayo de 2023 a las 11:00h en el juzgado de lo penal 002 de Badajoz. Adjunto la citación que nos ha llegado hoy y un acta de declaración que le realizaron a fecha de 24 de agosto de 2021. Su abogado de oficio se llama Francisco José Fernández Fernández. Mañana me pondré en contacto con él para poder obtener más información al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2023-04-19','Ana: Correo de Alberto, Jefe Secc. Ecca.: "ANA: OK, PERO X FAVOR QUE TE INDIQUEN EL PRECIO REAL DE LA PLAZA PARA CONTABILIZARLO EN LA FICHA. ANA: REINTEGRO OK-----MANTENEMOS LOS 400€/MES"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-04-19','Ana: Llamada de Ventura (927 245 250): No ha podido retirar su asignación porque están haciendo obras en la sucursal bancaria. Ha ido a otras dos pero sin la autorización no le dan el dinero. ·········· Óscar envía la autorización a la oficina de la C/ San Pedro, pues es la que pide Ventura. ·············· En cuanto al correo de Toni, informando de este asunto y sobre la solicitud de un extra, le contesto: "He hablado con Ventura y un amigo suyo. Ya está solucionado, mañana podrá retirarlo en la C/ San Pedro, pues dice que es la que mejor le viene. Aquí también desconocíamos lo de las obras. Gracias, como siempre, por la intervención. En cuanto al extra, no nos había llegado solicitud alguna, no sabíamos nada del bautizo. No creo que haya problema, pero tendrán que valorarlo en la sección económica. Pongo de nuevo en copia para que se dé el visto bueno." ····················································· Correo de Óscar a Toni-Futuex: "...En cuanto al extra, se autoriza para que lo extraiga la semana que viene."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-04-19','Ana: Alberto autoriza hacer transferencia de 250 € a Futuex, para compra de ropa. ····························· Reenvío correo a Toni-Futuex: "En relación a JOSÉ MANUEL ROMERO MEDIAVILLA, y su petición de ropa, te reenvío correo que le envié primero a Alberto la semana pasada para hacer la consulta. Viendo que ha dado el visto bueno, os pregunto a vosotras si sería posible hacerlo tal y como le planteé a Alberto, por favor, lee lo subrayado en amarillo en el hilo y cuando os sea posible, confirmarme si Teresa podría encargarse de este acompañamiento y gestión. Así como, en tal caso, la fecha para que el compañero de la sección económica hagan la transferencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-04-19','Ana: Correo de la Residencia Femar (residenciafemar2019@gmail.com): "se adjunta la declaración de la compañera para el cobro del acompañamiento de Valentina Fernandez Trejo. Ayer, día 17/04/23, Valentina acudió a la consulta de revisión de oftalmología en Trujillo. En general todo bien, salvo que en uno de los ojos ha desarrollado cataratas, la citan dentro de unos meses para ver como evoluciona."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2023-04-20','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net) al ctutelar@: "Buenas, os escribimos en relación a Mª Ángeles, por la posibilidad de solicitar una revisión en CEDEX por su situación de discapacidad, puesto que pensamos que podría lograr un aumento del grado y con ello tener unos mayores ingresos. Si lo consideráis oportuno se comunica a Ana Benavente (Trabajadora social de salud mental) para que pueda iniciar los trámites." ············································ Mi respuesta: "Para solicitar una revisión del Grado de Discapacidad del CADEX, es necesario presentar Informes Facultativos que acrediten dicho aumento de su discapacidad. Si disponéis de ello o se pueden obtener, nos parece bien que lo comuniquéis a Ana Benavente para que inicie el trámite. Ella sabe que será necesario la firma del Representante Legal." ···························· Llamo a Ana Benavente, TS ESM-Plas (74955): tiene pendiente hablar con la Psiquiatra, pues en el Dictamen Técnico el único diagnóstico que consta es Trastorno Mental por Esquizofrenia Residual. ············ Como impresiona de Discapacidad Intelectual. Si proporcionan informe que pueda presentarse para la revisión del Grado de Discapacidad, prepararé la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-04-20','TERESA AITOR HA VUELTO AL DOMICILIO MATERNO PERO SIN MIRELLA,YA NO ESTAN JUNTOS En la sección social, hemos pensado que lo mejor, es volver a establecer un acuerdo con el supermercado del pueblo para la compra de alimentos así como productos de limpieza e higiene. Estableciendo un máximo de gasto de 100€/semana. Ésta sería la forma de que Aitor contribuyera a su mantenimiento en el domicilio familiar. De estas gestiones se encargarán desde del Programa de Familias. A las sección económica volverían a enviar las facturas para su abono mediante transferencia. En cuanto a sus gastos de bolsillo, consideramos que no se le debe dar mucho, por riesgo de consumo. Y como fuma, hemos planteado llegar un acuerdo también con el estanco del pueblo. Como fuma unos 6 cigarros al día y tabaco de liar, con 50 €/mes podría llegar. Al igual que con el supermercado, de esta propuesta se van a encargar las compañeras del programa de familias. Y desde aquí de nuevo se abonarían las facturas mediante transferencia bancaria. AITOR SIGUE CON SU IDEA DE VIVIR SOLO EN UNA VIVIENDA DE ALQUILER Y TRABAJAR PARA PAGARLA ········································································································································································································ Correo del Programa de Familia (programafamilia@tajosalor.es): "he enviado el ticket de la compra que hicimos ayer con Aitor en otro correo. Se lo he enviado también a la sección económica. Ayer, mientras hacíamos la compra Aitor nos pidió ir al psiquiatra, ya que cuando estaba en la calle, nos dice, tomó mucha medicación sin pautar y tiene mucha presión en el pecho, está nervioso…(debe ser un mono brutal). Le hablamos del CEDEX pero nos dijo que no porque le iban a meter en un centro y de eso no quiere ni oír hablar. También observamos que escupe sangre, nos dijo que es porque se le mueven los dientes. No sabemos si será de eso pero no nos gustó. Le dijimos que tenía que ir al médico pero no tiene tarjeta sanitaria ni documentación ni nada… Nos preocupa por él, porque puede ser cualquier enfermedad de pulmón, tuberculosis…después de estar en situación de calle cualquier cosa, y también por nosotras la verdad. Nos cuenta y nos dice que no os contemos (jejeje) que durante el tiempo que ha estado por ahí ha pasado 5 días en prisión porque le pillaron con droga. No sabemos si será verdad o invención porque no extraña que no os haya llegado nada a vosotros y además sin documentación ni nada…no sé… Otra cosa, hablamos con la señora del estanco pero no quiere, dice que se va a jubilar pronto, que en mayo no puede vender tabaco por una multa que le han puesto…vamos, que no, nos decía que ella le iba apuntando y le pagásemos en metálico cada semana o diez días, le explicamos que eso no podía ser. No hay más estancos en Navas, así que no sé cómo podemos hacerlo." ····················· Reenvío a Maite y Teresa con propuestas y planteo reunirnos mañana para tomar decisiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-04-20','TERESA ENVIO SUBSANACION DOCUMENTACION DEPENDENCIA VALLE SIMON','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANO'and apellido2='ARROYO'),'2023-04-20','TERESA ME COMUNICA BARBARA QUE HACEMOS EL INGRESO EN RESIDENCIA EL PROXIMO LUNES 24 barbarasr.asoma@gmail.com 650643759 SALDRA DE CABEZA DEL BUEY A LAS 9 EN TAXI CON ACOMPAÑAMIENTO LA CUENTA SIGUE BLOQUEDA, SE PAGARA POR TRANSFERENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-04-20','Ana: Llamada de José Manuel (624 91 50 03), dice que va al médico, que le duelen mucho las rodillas. Está de camino al C.S. para que le vean y le manden algo para el dolor. ··········· Ha estado ingresado en la UHB desde el jueves hasta el lunes por la parte, que le dieron el alta. Le han cambiado/ajustado la medicación. ········ Le han mandado otra analítica de control, pues tenía bajos los niveles de un ácido. ············ Mantiene la idea de alquilar una vivienda en planta baja. Ha preguntado en una inmobiliaria y le van a buscar algo entorno a 300-350€. ···································· Vuelve a llamar José Manuel, ya ha salido el médico. Le han inyectado ENANTIUM y le han dicho que acuda mañana a ponerse otra inyección. ·············· Le indican de nuevo Reflex y también le ha recetado insulina, para el azúcar y para que adelgace.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2023-04-20','Ana: Tras autorización de Alberto del gasto del viaja Lourdes, subo al portafirmas la Inscripción y la autorización para que faciliten al personal del CAMF documentación clínica.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2023-04-20','Ana: En relación al Viaje a Lourdes solicitado por Mª Carmen, envío correo a Alberto, Jefe Secc. Ecca.: "Hemos hablado con la TS del CAMF-Alcuéscar. En relación a Mª CARMEN GÓMEZ MUÑOZ, nos ha confirmado que no hay previstos grandes gastos y en caso de ser necesaria alguna cosa, intentarán recortar los más posible. *Para gastos de bolsillo se llevará 50 €." ················ Por tanto, puesto que se ajustan el resto de gastos, se autoriza el viaje a Lourdes del 30 de junio al 5 de julio 2023. ··································· Envío a Felisa Custodio, TS CAMF-Alcuescar (trabajador_social_alcuescar@imserso.es): la ficha de inscripción para el viaje a Lourdes, firmada digitalmente por el representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-04-20','-Amalia : Para terminar el expediente de ingreso en centro falta -declaración de bienes , derivo a S. eco. -Firmeza del auto de internamiento involuntario , me lo pasarán los jurídicos. -I. médico , se va a ingresar sin él ,pq no acepta acudir al Ctro. de salud. Hablo con May , Victor y Toni Sabido , bastará con la sentencia y el informe del me´dico forense.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-04-20','-Amalia : Para terminar el expediente de ingreso en centro falta -declaración de bienes , derivo a S. eco. -Firmeza del auto de internamiento involuntario , me lo pasarán los jurídicos. -I. médico , se va a ingresar sin él ,pq no acepta acudir al Ctro. de salud. Hablo con May , Victor y Toni Sabido , bastará con la sentencia y el informe del me´dico forense.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-04-20','Email del CRR : Buenos días, Informaros que a partir de este fin de semana, Manuel Contador pasará las tres noches en el hostal tal y como acordamos. El hostal en el que se va a hospedar es “ Hostal Niza”. La semana pasada no pudo marcharse por dar positivo en COVID y el anterior, al ser semana santa, no había disponibilidad el domingo para poder pasar la noche por lo que ese fin de semana, a modo excepción, lo hicimos como lo estábamos haciendo hasta el momento ( dos noches en el hotel cervantes y una en su domicilio ).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2023-04-20','Ana: Conversación con Ana Benavente, TS ESM-Plas (74955): Guadalupe ha estado en su despacho y le ha manifestado que no está a gusto en la Residencia de Malpartida de Plasencia y quiere pedir el traslado. ······· Puesto que su hija reside en la residencia de la Asociación Vera de Jaraíz de la Vera, le gustaría solicitar traslado por acercamiento familiar a la C.M. de dicha localidad. ····················· Llamo a Cristina, Asoc. Vera, su hija no está a cargo de la CTAEx, es una persona muy autónoma. La relación con la madre nunca ha sido demasiado buena, pero no habría inconveniente en que residieran en la misma localidad, al ser recursos diferentes. ··························· Llamo a Carmen Gía. - TS EVD - Plas. (24108): El centro que pide ella es para personas autónomas, además ahora mismo está en obras. Como su plaza es T4, en principio tendrán que ofrecerle plazas de la misma tipología. ················ Llamo a la Residencia Ntra. Sra. de la Luz (927 45 91 67) para hablar con Guadalupe, pero en este momento no se puede poner. Me piden que vuelva a llamar mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2023-04-20','Ana: Tras autorización de Alberto del gasto del viaja Lourdes, envío a Felisa Custodio, TS CAMF-Alcuéscar (trabajadora_social_alcuescar@imserso.es): la ficha de inscripción para el viaje a Lourdes del 30 de junio al 5 de julio, firmada digitalmente por el representante legal, así como el documento del SES de autorización de entrega de documentación clínica a profesionales del CAMF.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CRESPO'and apellido2='MARTIN'),'2023-04-09','EXITUS El centro informa de su fallecimiento, ocurrido el 09/04/2023. Remite, así mismo, documentación de D. José. Incluido el Certificado de Defunción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2023-04-20','-Amalia : la compañera plantea que del extra anual que se le tiene que enviar a JOAQUIN GONZALEZ MILLON según lo acordado , se le resten estos 290. Me parece bien , sólo hay que enviarle 190€ para que lo pueda retirar . Y eso es lo que tiene para todo el año.','2');
