insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-04-20','miguel, envío justificante a Rocio Gracian de transferencia de las cantidades que faltaban de representación de ella y la procuradora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-04-18','miguel, email recibido por Damian Yo no quiero verme tirado en la calle y no quiero revision de la curatela es que yo no tengo la culpa de estar enfermo debla cabeza y yo tengo mucha ansiedad y he estado a punto de querer quitarme la vida con una absoluta yo tengo que estar que una persona esté pendiente de mi sino con lo que tengo ahorrado denuncio al sepad porque quereis que un enfermo mental se busque la vida y yo no puedo estar solo si tengo que enseñarle al juez mi papel de la invalidez absoluta se lo voy a enseñar pero a mi no me quita la plaza nadie porque ha sido mucho esfuerzo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-04-18','miguel, email recibido por Damian Yo no quiero verme tirado en la calle y no quiero revision de la curatela es que yo no tengo la culpa de estar enfermo debla cabeza y yo tengo mucha ansiedad y he estado a punto de querer quitarme la vida con una absoluta yo tengo que estar que una persona esté pendiente de mi sino con lo que tengo ahorrado denuncio al sepad porque quereis que un enfermo mental se busque la vida y yo no puedo estar solo si tengo que enseñarle al juez mi papel de la invalidez absoluta se lo voy a enseñar pero a mi no me quita la plaza nadie porque ha sido mucho esfuerzo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-04-20','email de la TS sobre el ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-04-20','email de la TS sobre el ingreso. Sobre Crístofer Figueroa te explico cómo ha sido su ingreso: Estrella (TS de la UHDAC) se puso en contacto con el Centro el pasado lunes 17 para comunicarnos que hoy miércoles 19 de abril se produciría el ingreso de Crístofer en la UHDAC. Como sabíamos que en el momento en el que Crístofer fuese consciente de que iba a ser ingresado en la UHDAC no se lo iba a tomar bien, acordamos no anticiparle su ingreso para evitar que se alterara y presentara problemas de conductas agresivas como en otras ocasiones cuando se ha tratado el tema con él. A su vez, la psicóloga que lo trata en nuestro Centro, se puso en contacto con el equipo de Salud Mental que atiende a Crístofer para poner en su conocimiento la situación. El psiquiatra le explicó cómo debíamos proceder indicándole la pauta de medicación a administrarle. Esta mañana, se le ha administrado la medicación pautada previamente por su psiquiatra y se le ha explicado que debían acudir a Cáceres para un ajuste en su medicación. Felipe (Coordinador del Servicio de Viviendas) y Lourdes Delgado (Directora de Centro Ocupacional) han sido los profesionales que han acompañado a Crístofer hasta Plasencia para llevar a cabo su ingreso. Durante el viaje según refiere Felipe, Crístofer ha permanecido tranquilo, pero al llegar al Centro antes de entrar, el personal de seguridad que se encontraba en la garita les preguntó si se trataba de un nuevo ingreso y esto hizo que Cristofer ya se diese cuenta de la situación y comenzase a mostrarse alterado. Una vez dentro en las instalaciones, les atendieron Estrella y Mari Paz (psicóloga) Felipe y Lourdes les comunicaron que Crístofer desconocía que fuese a ingresar. Ambas preguntaron por qué no se le había anticipado y se les explicó los motivos. Mari Paz le indicó a Crístofer que aquello se trataba de un hospital y que se debía quedar ingresado durante un tiempo. Esto provocó que Crístofer continuase alterándose. Posteriormente, Felipe y Lourdes se reunieron con Mari Paz y Estrella a solas. Según me dicen, Mari Paz les indicó que la persona con discapacidad no puede entrar en el Centro sin saberlo y según refirió se trataba de la primera vez que les ocurría una situación como esta. Mari Paz les afirmó que los usuarios que ingresan en la UHDAC saben a dónde van y el motivo por el que ingresan. Tanto Lourdes como Felipe continuaron explicándole los motivos de por qué se había decidido actuar así e hicieron referencia a la necesidad de la autorización judicial de internamiento debido a que se trataba de un ingreso involuntario. Por otra parte, Mari Paz les afirmó que consideraba que la UHDAC no se trata del recurso adecuado para Crístofer. Según les indicó, los usuarios que allí ingresan son usuarios con grandes necesidades de apoyo con perfil de RAE y que además su ingreso se había decidido en una Reunión de la Comisión Territorial sin tener en cuenta la lista de espera que existe para su acceso. Mari Paz le manifestó su disconformidad sobre ello. Por otra parte, Estrella les preguntó por qué Crístofer no había sido derivado a la Unidad rehabilitadora de media estancia (UME) de Mérida y por qué no se había solicitado antes su ingreso en la UHDAC. Se le explicó que el recurso ha sido determinado por el equipo de Salud Mental que lo atiende el cuál ha considerado que el recurso más adecuado para Crístofer es la UHDAC por tratarse de un centro de atención a personas con discapacidad intelectual con problemas graves de conducta. Una vez terminaron la reunión, volvieron con Crístofer. Felipe se dirigió a él para explicarle que debía quedarse ingresado hasta que se le ajustara la medicación lo máximo posible y ante esta afirmación Crístofer cogió impulso y se abalanzó a Felipe dándole una patada. Esto provocó que tuviese que ser contenido por el personal de seguridad del Centro. Según me dice Felipe, en ese momento Estrella le pidió a Mari Paz que ordenara su contención para que se produjera su ingreso de forma inmediata y así se hizo. Tanto Lourdes como Felipe me han transmitido su descontento con el ingreso ya que consideran que la atención recibida por parte de Mari Paz no ha sido la más adec','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-04-14','Le puede preguntar a amalia si ella tiene los papeles de mi pension? Un saludo y buen fin de semana queria comentarle cuando se haga el procedimiento de desahucio si la comision la parte economica puede ayudarme a vender en malaga y comprar aqui.es el 30 de junio cuando tienen que irse los inquilinos?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-04-14','Le puede preguntar a amalia si ella tiene los papeles de mi pension? Un saludo y buen fin de semana queria comentarle cuando se haga el procedimiento de desahucio si la comision la parte economica puede ayudarme a vender en malaga y comprar aqui.es el 30 de junio cuando tienen que irse los inquilinos?*********************************************** Señor miguel queria que me llamara porque confio plenamente en usted era porque los papeles del piso yo en un futuro quiero vender mi piso de malaga y comprarme uno en merida.como se tramita eso una vez que se hayan ido los inquilinos si la comision se ocupa de los tramites de la venta del piso pero sin malvenderlo y comprarme mi vivienda aqui en merida para estar cerca de la comision','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-04-19','miguel, email de Amalia: Buenas , se lo he reenviado a la psicologa del centro , me preocupa el tema del intento autolitico','2');
