insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2023-04-20','Ana: Subo al portafirmas digital para la firma del Representante Legal la Autorización para acudir a una reunión de antiguos alumnos del colegio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-04-20','Ana: Tras hablar con Cristina, Ed. Asoc. Vera, y ver el correo que envía, escribo a la secc. ecca: "Por mi parte, ok a retomar la retirada de asignación de 15 €/semana de Mª ANTONIA BRAVO PATILLA. El objetivo es ayudarle a ahorrar allí semanalmente algo de dinero (que sea “palpable” para ella) y poder llevar efectivo las veces que va de visita con su hermano al pueblo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2023-04-20','Jonathan Vázquez Muñoz de momento, está en lista de espera para la Residencia de Apoyo Limitado de "Ntra. Sra. de la Luz". No es usuario de Centro Ocupacional. Un Saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2023-04-21','Ana: Envío correo a Cristina, Ed. A. Vera (educadorasocial@asociacionvera.com): "Adjunto la AUTORIZACIÓN de AUSENCIA VOLUNTARIA para que D. Joaquín Herrero García, para que pueda asistir a la Convivencia que realiza su antiguo Colegio de Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2023-04-20','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Juan Gabriel se ha caido y posiblemente es fractura de muñeca. La han derivado a urgencias para asegurarse con pruebas. En cuanto sepa algo concreto os informo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2023-04-21','Ana: Llamada de Marta, RR.MM. Montehermoso (660 858 095): no obtengo respuesta. ················· Le escribo explicando que puede remitir al hijo al Juzgado que las incapacitó si quiere más información. ································································································································· Hablo con Marta, TS RR.MM. Montehermoso (660 858 095): cuando el hijo dijo que quería ir a ver a Florencia, le ofreció varias fechas para programar la visita, pero decía que ninguna le venía bien y finalmente dijo que no iba a ir de momento. Tampoco le hizo gracias que la visita tuviera que ser supervisada. ································ Me informa también que esta semana ha ido Virginia-Ed. Futuex a visitarla, y Florencia se puso muy contenta. ············ Se encuentra bien y muy a gusto con su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2023-04-20','Ana: Correo de Marta Custodio, RR.MM. Montehermoso (mcustodiob24@hotmail.com): "el hijo de Florencia Simón Martín nos reclama saber quienes son los tutores legales de su madre y su abuela. De su madre, le dije que era la comisión tutelar de adultos de Extremadura pero de su abuela no le he dicho porque es su tía materna y desconozco si puedo dar esa información. Dice que su abogado le ha dicho que tiene derecho a saberlo. Ya me dices o me llamas al 660858095"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-04-20','Ana: Correo de Puerto, TS SSASB Valdeobispo (ssb5@mancomunidadvalledelalagon.es): "según estamos observando Enrique últimamente está más alterado, está acudiendo a muchos vecinos demandando que le lleven a Plasencia, Montehermoso, etc llamando a las puertas de los vecinos de forma insistente. El martes pasado le cerró la puerta y le apagó la luz a la auxiliar del SAD, hoy he realizado visita a domicilio y le he informado de que si se vuelve a repetir tendremos que suspender el SAD... Estaba intentando arreglar el móvil y de forma impulsiva se cruza con cualquiera y le solicita que llamen a su tío... Hoy me ha llamado una vecina informado que iba con el coche y que se le cruzó parándola para que lo llevara a Plasencia... le comento que se lo comunique a equipo de atención primaria SES. Creo que sería oportuno seguimiento de cerca por salud mental por posible pico de alteración... Además hay que descartar que esté consumiendo tóxicos por sus antecedentes (cuenta con dinero semanal) Lo que se comunica a los efectos oportunos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2023-04-21','Hola Soy Marga TS de Jontan Ramírez Juárez, como ya sabrás se está adaptando bien al módulo de discapacidad de CP Madrid VII. Parece que se ha quedado tranquilo con el ingreso de peculio. He estado mirando la documentación que me remiten desde el ultimo centro y el certificado de discapacidad es ilegible, por favor si pudieras enviarme uno que se vea, os lo agradecería. Respecto a Dependencia no sé qué Grado tiene, si pudieras también enviarme copia lo adjuntamos a su protocolo Cualquier cosa que necesites no dudes en llamarme Un saludo Atentamente cid:image001.png@01D164B9.4EAB6DC0cid:image002.png@01D164B9.4EAB6DC0 Marga Utrillas Trabajadora Social Nª profesional.: 16918 Secretaría General de Instituciones Penitenciarias Centro Penitenciario Madrid VII - Estremera Ctra. M 241 Km 5,750 28595 Estremera MADRID Telf.: 91 875 00 00 ext. 415580 Fax: 91 875 00','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-04-21','Ana: En relación al correo de ayer, respondo a Puerto, TS SSASB: "Como bien has planteado, sería bueno que le vieran en el Equipo de Atención Primaria – SES. ¿Sabes si la vecina ha llegado a comunicarlo? ¿Has hablado tú con alguien del centro de salud al respecto? Yo me voy a poner en contacto con el Equipo de Salud Mental, para informarles de la situación actual y ver si pueden agilizar la próxima cita. Voy a pedir también al Equipo de Apoyo Comunitario gestionado por Futuex que intenten visitarlo lo antes posible. Y en cuanto al consumo de tóxicos, si finalmente se confirmara, tendrían que derivarle al Equipo de Conductas Adictivas. Si él no aceptara, ya iremos viendo. Por otra parte, si Enrique realiza más acciones que puedan resultar peligrosas para él o terceras personas, no dudéis en activar el 112." ························································· Escribo a Ana Benavente, TS ESM (anamaria.benavente@salud-juntaex.es): "En relación a ENRIQUE SANTOS GARCÍA-PUENTE, te reenvío el correo de la compañera del SSASB, para haceros conocedores de los indicios de descompensación de su patología de base y/o consumo de tóxicos. No sé si habrán llegado a verlo desde el Equipo de Atención Primaria, y en tal caso, si os han comunicado algo. ¿Con quién puedo hablar del Centro de Salud? Desconozco quién es su MAP y quién es la compañera Trabajadora Social que atiende allí. Si pudieras facilitarme estos contactos, te lo agradecería. Preguntarte así mismo, si sería posible agilizar la próxima cita de Psiquiatría y en tal caso, si volveríais a desplazaros a su pueblo para atenderlo. Quizá, sería bueno que lo vieran antes de que se descompense del todo, por si hubiera que ajustar medicación y poder evitar un posible ingreso hospitalario. Ya me dices cuando puedas." ····································································································································································································· Respuesta de Ana Benavente: "Nos lo envió también Puerto a nosotros. Hemos hablado con él esta mañana . Enrique no está descompensado, sí es cierto lo que dicen que está más insistente con la gente. Lo de la auxiliar de ayuda a domicilio es que le cerró la puerta para enseñarle unas luces en el techo, a nosotras también nos lo enseñó cuando fuimos a la visita. Ya le hemos dicho que eso no tiene que hacerlo, que la auxiliar tiene que hacer su trabajo y él limitarse a una relación no personal. Hemos quedado en ir a visitarle al domicilio la semana que viene con el ETAC ( Equipo de Tratamiento Asertivo Comunitario ). Nosotros estamos muy pendientes de este paciente. Es verdad que en el pueblo ya saltan las alarmas por cualquier cosa. Él de todas formas ha agradecido la llamada y se ha comprometido a ser un " caballero " textualmente." ··············································································· Nuevo correo-respuesta de Puerto, TS SSASB Valdeobispo (ssb5@mancomunidadvalledelalagon.es): "Buenos días: ayer hablé con César el enfermero, la médica Susana no estaba, pero hoy a las 11 horas estará en Valdeobispo y contactaré con ella para informarla, dos vecinos también van a ir a comentárselo porque están preocupados... la verdad que Enrique está diferente, como más alterado. Te voy contando novedades. Esperemos que se estabilice y no esté consumiendo tóxicos. (Ayer tenía el fregadero atascado de la cocina porque le hecha los posos del café, el fontanero iba hoy a desatascarlo) La casa está más limpia y recogida." ································································································································································································· Toni-Futuex, confirma que irán a visitarle la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2023-04-21','TERESA Teresa, en relación al traslado de Juan Carlos hemos hablado el equipo de educadoras y psicologo y pensamos que es mejor que se quede aquí que no en residencia de ancianos. El a veces dice que aquí, otras que en piso, es decir la residencia de ancianos no entra en sus planes. Es algo que nos plantea desde hace tiempo el ir a piso tutelado, pero le transmitimos que no es perfil adecuado lo entiende, aunque más adelante lo vuelve a plantear de nuevo.....','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2023-04-21','Amalia : Contacto con Marga , TS de Estremera : Ok al inicio de dependencia A día de hoy sale con la total el 14 de septiembre , pero tiene 1 citación en mayo y creo que tiene algo más pendiente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-04-21','Ana: Correo de Pedro Pablo Garvi, TS del CES de Cáritas (pgarvi.cdcoriacaceres@caritas.es): "Hola Ana, soy Pedro, coordinador del programa de Personas sin Hogar de Cáritas diocesana de Coria- Cáceres. Disculpa la tardanza en contestarte. Con respecto a Miguel Ángel Ramos, lo atendemos en el Centro de Emergencia Social por primera vez el día 10 de Marzo, donde nos refiere que ha abandonado la C.T. La Garrovilla. Nuestro Centro de Emergencia abre de 22:00 a 10:00, por lo que la atención sólo se limita a la pernocta y el desayuno. Desde el dia 10 de Marzo al 18 de Abril, ha estado pernoctando de forma habitual en el Centro de Emergencia, faltando alguna noche que otra. El 18 de Abril, habiendo disponibilidad de plazas, lo acogemos en Centro Vida para recuperación personal." ·································· Lo paso a PDF, guardo en el expte. y se lo envío a Ángel y Miguel para que comuniquen al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2023-04-21','TERESA SOLICITA SALIR FUERA DEL CENTRO Y PECONOTAR Tras comentar la situación con los asesores jurídicos la comisión no autoriza las salidas ya que no podemos asegurar la toma de la medicación Vamos a comunicar la decisión al juzgado y le remitimos informe social y el informe del psiquiatra para que valoren esta decisión. En caso de que se vaya pues no podemos retenerlo en contra de su voluntad se lo comunicaríamos inmediatamente al juzgado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2023-04-21','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, Juan Gabriel tiene fractura distal del radio derecho. En 10 ó 12 días le hacen revisión. De momento lo lleva con paciencia y no manifiesta dolor. La Fisioterapeuta va a hacer el seguimiento. Me ha comentado que anteriormente tuvo la misma fractura pero en la mano izquierda y se recuperó muy bien. Ya te iré informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANO'and apellido2='ARROYO'),'2023-04-24','TERESA BUENOS DIAS TERESA ME PONGO EN CONTACTO CONTIGO DEL CASO DE ANTONIA CANO ARROYO TUTELADA POR LA COMISION DE ADULTOS ESTA SEÑORA SERA TRASLADADA DESDE EL CENTRO RESIDENCIA DE CABEZA DEL BUEY ,JESUS DE NAZARENO A UN CENTRO RESIDENCIAL CON PLAZA PUBLICA EN UN PUEBLO DE CACERES ME GUSTARIA PODER HABLAR CONTIGO DE ESTE CASO PARA PODER SOLICITAR EL TRASLADO A UN CENTRO MAS CERCANO DE LA LOCALIDAD DE CASA DE DON PEDRO UN SALUDO ANA LUQUE TRABAJADORA SOCIAL DEL SSASB SIBERIA MI TELEFONO PEROSONAL ES 616179255','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-04-24','Se mantiene como defensa judicial. No obstante, nos han nombrado curadores provisionales en virtud de medidas cautelares dictadas mediante Auto de 4 de agosto de 2022. Se acepta, por tanto, el cargo de Curador Provisional. La carpeta digital estará guarda en CR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-04-24','Ana: Envío correo a Toni-Futuex, con copia a Marta, TS del SSASB: "En relación a JULIA MORÓN HERNÁNDEZ, comunican desde el Juzgado de Plasencia que es importantísima la asistencia de la tutelada al juicio para el cuál la citan. El mismo tendrá lugar el próximo día 5 de mayo a las 10 h. ¿Sería posible que la acompañara la Educadora del Programa de Apoyo Comunitario al mismo? Comunicárselo por favor a ella, aunque yo también se lo diré. Supongo que le tranquilizará el que podáis acompañarla. Pongo en copia a Marta, Trabajadora Social del SSASB, para que esté al corriente. Seguimos en contacto." ······························ El juicio es en relación a la denuncia que interpuso por Abusos Sexuales. ··································································································································································································· Envío correo a la secc. ecca. al ctutelar@: "He recibido hoy llamada de Julia Morón Hernández. Pide un extra de 100€ para ir a la peluquería (quiere darse mechas) y para comprar un regalo a su madre por el día de la Madre. A Maite y a mí nos parece mucha cantidad. Pensamos que como mucho 70-80 €, si es que se puede, pues no sabemos exactamente cómo está su situación económica a día de hoy."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-04-24','TFNO. DE CONTACTO Tfno. de Beatriz: 639 07 30 69.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2023-04-24','Ana: Tras recibir llamada de Felipe (617 688 763), envío correo la secc. ecca. al ctutelar@: "En relación a FELIPE BLANCO GUISADO, tiene una asignación semanal de 20€. Aunque la retirada de efectivo la realiza una vez al mes y se lo administran desde el centro, dándolo los 20€ semanales. Dice, con coherencia, que ha subido todo mucho y que ya no le llega con esta cantidad, y pide que se le suba la asignación a razón de 25 o 30 €/semana. Por mi parte, si es viable, ok. Podéis confirmar de este incremento, en caso de aprobarse, a la Trabajadora Social de Novaforma, Teresa (trabajadorasocial.novaforma@gmail.com), a quién pongo en copia para que esté al corriente de esta solicitud." ······························································ Respuesta de Óscar con copia a Teresa, Novaforma: "Felipe tiene asignados 180€ al mes, de lo que resulta una media algo superior a los 41€ a la semana. Según comenta Felipe, lo extrae a finales de mes y lo entrega en el centro para su administración. Por favor, necesitamos confirmación por parte de Novaforma de esta situación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-04-24','Ana: Correo de Puerto, TS SSASB Valdeobispo (ssb5@mancomunidadvalledelalagon.es): "me confirma el fontanero que ya está solucionado el atasco y que Enrique le ha pagado esta mañana" ······························································································································································································· Llamo a Ricardo, hermano de Enrique (649 628 797), Técnico de Rayos en el HVP-Plas., en relación a la factura de electrodomésticos del verano del año pasado que según su hermano. Me dice que no lo abonó él, sino otro hermano José Ignacio, "Nacho" (670 743 476) ··········· Aprovecha para informarme que su hermano NO tienen alta de luz y agua a su nombre, tiene suministros porque lo tiene enganchado la vivienda de su madre, ubicada en la misma finca. Comunica que están realizando los trámites de la herencia y que pronto harán la partición. Pide que se le den de alta los suministro. Seguramente se le pedirá que devuelva el gasto que ha supuesto en la cuenta de su madre fallecida de aquí para atrás. ································ Lo comunico a Alberto y Óscar, Secc. Ecca. ················································································· Llamo a José Ignacio, "Nacho" (670 743 476): NO obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-04-24','Ana: Llamada de Felisi (626 164 402): discurso similar al de las últimas llamadas. Dice además que quiere mucho a su hijo, pero que, a veces, hace cosas que no le gustan y le habla mal. Opina que estaría mejor en un centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-04-24','Ana: Llamada de José Manuel (624 91 50 03): dice que mañana enviarán desde la ferretería un presupuesto para poner un ventilador en el techo de la habitación, pues en verano pasa mucho calor. ············· Con respecto a la búsqueda de vivienda, dice que está muy complicada. Que la semana pasada fue un día a Olivenza y preguntó en una inmobiliaria y le dijeron que no había nada para alquilar de planta baja. Así que está pensando quedarse en su piso en CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-04-24','-Amalia : nos comunica Javi que el viernes consumió y lo han expulsado . El padre no se ha opueto a que vuelva con él. Se ha llevado del centro 375€ que ha entregado al padre para que se lo administre, le da 2,40€ al dia para café. Se ha llevado su cartilla y la medicación. Indicaré a futuex que lo visiten en el domicilio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2023-04-24','Ana: Llamada de Nuria, TS del EVD-Trujillo (54513), en relación a las negociaciones PIA, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-04-25','Ana: recibimos el certificado actualizado de Pensión de Incapacidad Permanente Absoluta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GUISADO'and apellido2='GUAY'),'2023-04-25','EXITUS Mediante Decreto n.º 142/23, de 14 de abril, dicatdo por el Jzdo. de 1.ª Inst. e Inst. n.º 2 de Mérida, se da por cerrado el procedimiento por la pérdida sobrevenida del objeto del proceso. Esto, el fallecimiento de D. José.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-04-25','Ana: Correo de Óscar, Secc. Ecca.: "Cobra 453 de una PF (12 pagas) y se le pasan a la madre 300€ al mes (250€ de manutención y 50€ para ella). Se le acaba de comprar un móvil (105€) y un reintegro la semana pasada de 100€ por su cumpleaños. Como mucho, se le podrían dar 70€ y no puede pedir más extras en unos meses, salvo urgencia médica o fuerza mayor. Lo preparo para que los reintegre entre miércoles y viernes." ························ Hablo con Julia, le explico si situación económica. Acordamos que no podrá volver a pedir ningún extra hasta pasados al menos 4 meses. El jueves podrá retirar el reintegro de 70€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-04-25','Ana: Correo de Paula, TO: "Hola Ana, os escribimos para comentaros que durante el fin de semana Isabel tuvo una ingesta de pilas. A lo largo del fin de semana estuvo en el hospital en Cáceres y, según informes, no le quedaban más pilas al alta. Ayer regresó al CRR. Hace crítica de lo sucedido, y comenta que se ha sentido muy estresada en relación a la situación de su madre (corte de luz). Sabe de todos los apoyos que ésta puede recibir y que está en proceso de solucionar la situación. Verbaliza estar un poco más tranquila. Desde aquí se continúan haciendo apoyos para intentar ayudar a Isabel a que pueda participar de su vida de forma saludable."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-04-24','Ana: La sección ecca. aprueba retomar el reintegro permanente de 15 €/semana a partir del 01/05/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2023-04-25','-Email que envía Angel : Aquilino, que sepamos, cuenta con tres hermanos. Juan Vicente y Pilar, ambos viven en Murcia y desconocemos sus domicilios, tenemos sus teléfonos y una tercera hermana, Pepi, que vive en Italia, desconocemos domicilio y teléfono. Pude hablar, después de muchos intentos con el marido de Pilar, me manifestó que la vivienda en cuestión se la quitó el Banco, al no poder hacer frente al pago de la hipoteca (de hecho la vivienda está en ejecución hipotecaria con el Juzgado y la ejecutante, Caixabank, ha pedido la subasta, aunque ahora mismo no se la han concedido, estoy a la espera me digan el motivo). Intenté hablar con Juan Vicente, que es quien firmó la hipoteca junto con su madre, Mencía, me comentó que renunció a la herencia, aunque no lo sé formalmente y al Juzgado no le consta. Con la que no he podido saber nada es de la tercera hermana, Pepi. La casa en cuestión, está en la calle Bravo Murillo, 32, de Badajoz. Según el propio vecino, está en estado ruinoso. Os adjunto foto. Con estos antecedentes y salvo que la parte ejecutante nos informe que han subastado la vivienda, vamos a solicitar autorización judicial para renunciar a la herencia. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-04-25','Ana: Conversación con Estrella, TS CSS-Plas (24146): Montaña está hoy de excursión en Alcalá de Henares, han ido con Terapia. ·········· Hace unos días también asistió al Teatro. ········ Está contenta y se ha adaptado bien al Centro. ··················· Posiblemente pase a URA, pero llegado el momento nos lo comunicarán. ··········································· Con respecto a la situación familiar, según el expediente: Montaña tiene un hijo de 24 años. Estudia y trabaja y vive con sus tíos paternos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-04-25','Maria Puertas >mariapuertasgil48@gmail.com> tf 633936731 hermana , he hablado con ella , quiere ser tutora de Santiago. No pudo ser tutora pq el cargo lo cogió su hno. de padre Adelino . No es hno. de madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-04-25','Ana: En relación a la Solicitud de SAD, no podemos pedirla a través de la Ley de Dependencia, pues además de tener 59 años (se concede a partir de 65 años. Con menos edad sólo en casos muy muy excepcionales), al tener reconocido Grado II, el TAD sólo puede concederse como Servicio complementario, no como serv. único. ···························· Dado que el Ayto. de Plasencia tiene este servicio, se solicitará allí. ······· Pido a Estrella, TS CSS, que le faciliten el modelo de Informe Médico para que pida cita con el MAP y se lo lleve.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-04-25','Ana: En relación a la Solicitud de SAD, no podemos pedirla a través de la Ley de Dependencia, pues además de tener 59 años (se concede a partir de 65 años. Con menos edad sólo en casos muy muy excepcionales), al tener reconocido Grado II, el TAD sólo puede concederse como Servicio complementario, no como serv. único. ···························· Dado que el Ayto. de Plasencia tiene este servicio, se solicitará allí. ······· Pido a Estrella, TS CSS, que le faciliten el modelo de Informe Médico para que pida cita con el MAP y se lo lleve.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-04-25','Ana: Marta Custodio, TS de la RR.MM. LOS MOLINOS de Montehermoso (mcustodiob24@hotmail.com): remite un presupuesto para ropa (161,88 €). Por mi parte, ok.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-04-25','Ana: Correo de Mónica, Ed. PS Plas (educacion.pisosplasencia@grupo5.net): "Estas últimas semanas ha sido Carol la que ha contactado contigo dada la situación vivida con Javi, pero vuelvo a retomar yo las coordinaciones con respecto al piso, aunque en la actualidad solo está Carmen Solana. Te mando este corre para comentarte. Tras la baja de Javi, una persona ha pasado a ocupar su plaza y nos ha surgido la duda sobre qué hacer con sus pertenencias. Entendemos que actualmente puede resultar complejo hacérselo llegar, pero en el piso no disponemos de mucho espacio para poder guardárselo, ¿qué hacemos con las pertenencias? Cuando se marchó se llevó prácticamente todo y entendemos que dejó lo menos importante o aquello que no le resultaba necesario (algo de ropa, unas toallas, un par de mochilas, un par de zapatillas y su caja de caudales vacía). Ya me dices para poder organizarnos (enviarlo, donarlo). Aprovecho también para preguntarte por él, esperamos que esté bien." ··························· Aún no tenemos teléfono de contacto de Javier. Intentaré contactar con Nerea, Cáritas Tarragona, por si supiera algo de Javier y/o nos pudiera facilitar nº de contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-04-26','Ana: Llamo a Nerea, Coordinadora de Cáritas Tarragona (nlopez.cit@caritasdtarragona.cat // 977 24 23 37 // 640 365 497): está reunida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANO'and apellido2='ARROYO'),'2023-04-25','EXITUS El centro informa de su óbito, ocurrido el 25/04/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-04-26','Ana: Tras recibir llamada de Eva Álvarez, TS Plena Inclusión Montijo, exponiendo que están con Christofer visitando a su hermano Alejandro en Cruz Blanca, envío correo a Paz Boticario, TS Cruz Blanca (et-caceres@cruzblanca.org): "En relación a ALEJANDRO MONTERO VÁZQUEZ, residente en vuestro centro residencial y cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, desde el Equipo Técnico de dicha Comisión, se autoriza la salida en el día de hoy, 26 de marzo de 2023, por Cáceres para dar un paseo y tomar algún refresco, con motivo de la visita de su hermano CRISTOFER MONTERO VÁZQUEZ, acompañados ambos por los dos profesionales (Trabajadora Social y Monitor) de Plena Inclusión Montijo que han acudido a la visita. Así mismo, tal y como he hablado con Eva Álvarez, Trabajadora Social de Plena Inclusión Montijo, acordamos que para futuras visitas, se comunicará la intención de salir a pasear con más tiempo, desde vuestros recursos, para que se pueda realizar con carácter previo un documento más formal que pueda firmar el presidente de la CTAEx."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-04-26','Ana: Redacto oficio y lo remito a Julio, CTAEx, junto con el Informe actualizado del Serv. de Psiquiatría que me facilita Sheila, Directora del CRR-CC, para que lo registre a la Gerencia Territorial-CC y allí lo adjunten al expediente de revisión del grado de dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-04-26','Ana: Llamada de Francisco (641 569 490): le han devuelto el dinero que dio como fianza para otro piso de alquiler. Ya ha encontrado otro, va a el día 1 de mayo a compartir con otros 2 chicos. Le cuesta 200€ más los consumos (30-40 €/mes). ····· El dueño del piso no va a declarar el alquiler y él no quiere generarle ningún problema al respecto. Pero nos lo enviará para que lo vean los jurídicos y comprueben que no hay cláusulas abusivas. ··········· Dado el aumento de gasto, pide una subida de asignación a 400€/mes. ·················· *Su madre le sigue pasando la manutención a su hija. ························· Pedirá a Mamen, TS Centro Vida, que nos remita un correo con toda esta información y motivando la solicitud de subida de la asignación. ·································································································································································································· Correo-e de Mamen, TS de Centro Vida, Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Sobre Francisco Cacho Garrido, el día 1 de mayo se marcha en el centro a un piso de alquiler, voy intentar hacerle seguimiento desde el centro, citándole una vez al mes, además también voy a derivarlo a la parroquia que le pertenece para ayuda de alimentos. Tambien le he dicho que cuando tenga el contrato me lo traiga y te lo envió."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-04-26','Ana: Llamo a Laura Bazaga Cordobés, TS Asoc. APTO Plena Inclusión, Navalmoral de la Mata (927 53 14 30 // trabajosocial@asociacionapto.org): Desde su entidad han comunicado en varias ocasiones la situación a Fiscalía. ········· Vive en domicilio familiar con sus hermanas, Monserrat y Mª Ángeles (la vivienda creen que es propiedad de todas por herencia de la madre). Tanto una hermana como otra no han administrado bien sus cuentas, de hecho ambas en distintas ocasiones han hecho uso indebido de su dinero para interés personal. Incluso han pedido préstamo a su nombre y le han generado deudas con el banco. Recientemente ha recibido un MONITORIO por impago. ············· Desde APTO en los Informes que enviaron proponían que nombraran Curador al hermano, Jose Emilio, pero en el procedimiento anterior nombraron a Mª Ángeles. **El próximo 13 de junio tendrá lugar las vista para la revisión de las Medidas Judiciales de Apoyo. ······················ Beatriz es causante de una PFHC y trabaja a media jornada en el Centro Especial de Empleo de APTO. ············ Abona la cuota de socia (domiciliada) y come allí a diario. ··········· Saben que tiene cuanta en el Banco Santander, pero en su día una de las hermanas abrió otra en Abanca, no sabe si ésta sigue abierta. ····························· Tiene móvil, cree que de contrato, esto habrá que verlo, lo mismo hay que dar de baja el contrato y tiene que comprar tarjeta de prepago. ····················· En la casa no tienen al día el abono de los suministros. ····································· Acordamos que solicitarán el Informe de Salud y solicitaremos Valoración de la situación de Dependencia. ························ **En APTO están haciendo trámites para acreditar un servicio de Vivienda Tutelada, pero no saben cuando podrán ponerlo en marcha. A ELLA LE GUSTARÍA IRSE A VIVIR A ESTE RECURSO CUANDO ESTÉ EN FUNCIONAMIENTO. ······· *Cuando tengamos número de cuenta o se abra cuenta nueva, solicitaré la PFHC como entidad jurídica. ····························· También haré derivación al Programa de Apoyo Comunitario gestionado por Futuex. ····································································································································································································· Desde los SSASB, no han intervenido nunca. La TS que le correspondería sería Antonia Glez. Montero (927 53 30 80).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-04-26','Adjunto nota de seguimiento de Francisco Casillas efectuado ayer 24 de abril en CRR Mérida. Justo se habia programado visita en crr Mérida y nos sorprendió todo. Como resumen de la misma: ha dado positivo en consumo de alcohol en el control de CEDEX o ECA o como sea ahora, y se niega a cumplir las pautas del tratamiento que le estipulan, quiere renunciar a la plaza en CRR y volver a su localidad. Javier, director de CRR Mérida, le propone la posibilidad de irse durante 15 días a su pueblo y después decida si quiere volver al centro o quedarse definitivamente en su localidad. Despues de lo último que aconteció con la gente de plazas de salud mental, pues no sabemos si estoy seria posible o era simplemente una opinion de Javier. De todos modos, parece bastante raro, que quiera cambiar de opinión pasados unos dias. Nota seguimiento efectuado martes 24/05/2023 Se realiza seguimiento presencial en CRR en coordinación con Gisela, terapeuta ocupacional de CRR. Al llegar nos indica Gisela que Francisco ha llegado el CEDEX acompañado de Cristina, educadora del centro. Ha dado positivo en alcohol, está bebiendo desde que llegó al centro. En CEDEX le indican que tiene que cumplir tratamiento para la adicción, revisiones semanales y no puede manejar dinero en efectivo tan solo el euro para destinarlo en café. Como no quiere cumplir con ello, Francisco quiere irse del centro y volver a su localidad. Esta muy convencido de ello amenazando de irse sin avisar. Javier, director de CRR Mérida, le explica a Francisco el procedimiento para irse del centro. Le indica que tiene que esperar un par de días hasta que esté todo gestionado. Le propone la posibilidad de volver a su localidad y pasado 15 días, tome la decisión de volver al centro o quedarse definitivamente en su localidad. Francisco mantiene la idea de querer vivir en su pueblo hasta que le arreglen su vivienda, algo que según expresa se lo ha dicho la trabajadora social del ayuntamiento. (En fin, sabemos que eso no es viable) A pesar de explicarle su situación en Oliva de Mérida e intentar convencerle entre el equipo de apoyo social comunitario, Gisela, Cristina y Javier del CRR de quedarse en el centro puesto que es beneficioso para su salud y bienestar físico y emocional, Francisco continúa diciendo que se va y quiere firmar la renuncia de plaza. Cristina, educadora del centro y personal de referencia de Francisco nos indica que este se ha dedicado a pedir dinero por la calle y a sus compañeros para destinarlo al consumo de alcohol. Es más, estando en el centro varios compañeros se acercaron para demandar que Francisco les devolviese el dinero que le habían prestado. En cuanto podamos planificaremos una visita a la localidad de Fco. Seguimos!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-04-26','Ana: Correo de Carmen Sánchez, Directora F. Autismo Sur (direccionhogares@autismosur.es): "Os paso la factura que se va a pasar, con los gastos ocasionados de los tramites realizados para la renovación del pasaporte de Costi Alexandru." ························· Pido que, cuando sea posible, nos remitan escaneado el pasaporte renovado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-04-26','Ana: Correo de Sergio Romero, Responsable, Proy. Mi Casa (sergioromerodiaz@plenainclusiondonbenito.org) al ctutelar@: "Como ya comenté por teléfono con Ana, el proyecto Mi casa, cubre las necesidades básicas, pero lo necesario para la higiene personal es una de las cosas que no entran en los presupuestos. Felisa llegó a nuestras viviendas de Asindi con tales necesidades cubiertas, pero tras casi un mes se le está terminando. Por ese motivo, tras hablar con su referente en la vivienda me plantea si existe la posibilidad de tener una partida presupuestada de unos 20€ para ese tipo de gastos. Otras de las cosas que también nos estamos dando cuenta que con solo 25€, en Don Benito no tiene suficiente ya que el nivel de vida aquí es más alto, aunque se lo estamos racionando bastante bien, no sé si existe la posibilidad de aumentar esa cuantía mensual. Van hacer inventario de ropa con Felisa, ya que nos hemos dado cuenta que la ropa que tiene o está muy vieja, o le queda muy pequeña (estamos yendo al gym con ella para adelgazar un poco), pero si que me pregunta Raquel la referente de ella si existe la posibilidad de comprar algo de ropa nueva de verano que ya empieza el calor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-04-27','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net), de ayer: "...Héctor, hermano de Aaron, ha contactado con nosotros porque le han dicho que está aquí y quiere hablar con él. Aún no le he explicado que está actualmente ingresado en la UDHAC. Nos ha dejado su teléfono. Por lo que he visto con este hermano tuvo varios altercados domésticos y llevan tiempo sin tener relación. Llámame en cuanto puedas para ver cómo procedemos. Creo que tantearé a algunas de las tías de Aaron por si tiene noticias de Héctor antes de hablar con él." ······································································· Mi respuesta: "...Yo ni siquiera recordaba que Aarón tuviera un hermano. Según informe del piso en que residía antes de ingresar en vuestro recurso: “Aarón tiene un hermano, Héctor, el cual regresó al domicilio familiar en marzo de este año. Han tenido diversos altercados domésticos y actualmente no mantienen relación. Aarón lo tiene bloqueado en su teléfono y no quiere hablar de él, se pone irritado cuando habla de este tema.” Creo que esa información es muy significativa, además de que no hemos tenido noticias de este hermano, al menos nosotras no, en todo el tiempo que lleva a cargo de la CTAEx. Antes de preguntarle a él incluso, considero que sería más conveniente ponerlo en conocimiento de la UHDAC, para saber en qué punto se encuentra a nivel psicopatológico y si ellos ven conveniente este tipo de contacto en estos momentos, dada la trayectoria previa de los hermanos y la falta de interés mutua en los últimos años. Es por ello que pongo en copia a Estrella, compañera del C. Sociosanitario, para que puedan valorarlo en equipo y darnos una respuesta antes de comentar nada a Aarón. Por cierto, Sonia, si obtienes más información a través de las tías de Aarón, sobre la situación actual del hermano y el posible interés que pueda tener para contactar con Aarón, por favor, comunícanoslo a todas. Pongo en copia también a Maite para que esté al corriente." ······················ Nuevo correo de hoy de Sonia Bernabé: "Hola Ana, he hablado con Héctor, hermano de Aaron. Le he comunicado que está actualmente no está en este centro y me ha preguntado por el nombre de la nueva residencia, ante lo que le indicado que no podemos facilitar ningún tipo de datos de los residentes, y menos de los que actualmente no están viviendo aquí. Insiste en saber con quien puede hablar y le he dicho, como habíamos quedado, que Aaron tiene la figura de curador, por lo que son los únicos que pueden ver este tema y nosotros no podemos facilitarle la respuesta de quienes son. Si quiere saber quienes son tiene que dirigirse al Juzgado. Nos pregunta en qué sección del Juzgado tiene que preguntar, por lo que intuyo que parece que tiene intención de hacerlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-04-27','teléfono de su hermano Adelino Lozano , es hermano de madre . Ahora no puede devolver llamadas porque no tiene saldo ni dinero para ponerlo. 603641483.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-04-26','Ana: Correo de Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Te escribo para comunicarte que quiere venir una tía de Aarón Rosado Alarcón a verlo y a sacarlo por Plasencia a tomar algo...., se llama Inmaculada. Queríamos saber vuestra opinión al respecto..." ···································· Mi respuesta: "Inma, tía de Aarón, es hermana de su madre fallecida. Trabaja (o al menos trabajaba) en el hospital de Cáceres y en varias de las ocasiones que ingresó en UHB, iba a visitarlo y estaba pendiente de él. También le llamaba de vez en cuando al recurso y cuando vivía en el piso de menores, acudió a algún que otro evento a verlo (actuaciones, fiestas fin de curso y similar). En principio, las veces que yo he hablado con ella, muestra buena disposición y aunque sea en ocasiones puntuales, creo que puede ser un buen apoyo para él. Eso sí, si tenéis que establecer algún límite claro desde la Unidad, decírselo desde un inicio, pues, siempre con buena intención, a veces le consentía demasiado y después Aarón era más difícil de abordar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2023-04-26','Ana: Correo a Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Comunico que Yolanda Caldera Martín irá de pase a su centro Includes de Villanueva de la Serena la semana del 8 al 12 de mayo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-04-27','Ana: Llamada de Felisi (626 164 402): está disgustada con Jesús, hay cosas que no le gustan y no tira para ella. Además le ha dicho que su madre "no quiere verla ni en pintura". ············ Dice que Aitor se está portando muy bien. Pero sale mucho con un amigo a dar vueltas en coche por ahí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-04-27','Buenas , he hablado del caso de SANTIAGO PUERTAS GIL con Icíar . Se le va a abonar a la entidad ASPACEBA al Nº de cuenta que indican, el copago de la plaza del 75% de la pensión. Estamos pte. que nos pasen el total por los días que lleva y os lo digo . Este mes será algo más , luego se hace una transferencia pte. por el importe del 75% que nos van a indicar. Además se les enviará de la misma forma , una asignación de 60€ al mes , para gastos de bolsillo. Va a entregar recibos de suministros el hermano que tenemos que abonar para que no le corten agua y luz. El tema del empadronamiento no lo puedo hacer hasta tener la asignación de plaza, necesito ese documento para justificar el nuevo domicilio. Queda pendiente este trámite . Os paso el Nº cuenta. La pensión ya hizo el cambio el banco directamente, tengo que saber qué cantidad es . Si es PFHC y Orfandad no tengo que hacer nada más','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-04-27','Ana: Correo de Ángel, A. Jurídico: "Beatriz en catastro no tiene nada, porque las certificaciones a las que tenemos acceso son solo en Extremadura. He pedido Nota Simple al Registro de la Propiedad y aquí si tiene algo, en el municipio de Huércal-Overa (Almería). Cuando me envíen la Nota Simple te digo." ··················································································· Lo comunico a Laura, TS APTO (trabajosocial@asociacionapto.org).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-04-27','Maite: he hablado con Nerea ( coordiandora de Cáritas en Tarragona). Javier no ha vuelto a pasar por allí. Cuando se hizo el giro postal con el dinero, pasó a decirles que ya lo tenía y que se quedaba en un hostal. No tienen su número de teléfono. Nerea me dice que no ha vuelto a ir al comedor de Cáritas y tampoco ha ido al centro de dia. Nos avisarán si vuelve a contactar con ellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-04-27','Buenas , he hablado del caso de SANTIAGO PUERTAS GIL con Icíar . Se le va a abonar a la entidad ASPACEBA al Nº de cuenta que indican, el copago de la plaza del 75% de la pensión. Estamos pte. que nos pasen el total por los días que lleva y os lo digo . Este mes será algo más , luego se hace una transferencia pte. por el importe del 75% que nos van a indicar. Además se les enviará de la misma forma , una asignación de 60€ al mes , para gastos de bolsillo. Va a entregar recibos de suministros el hermano que tenemos que abonar para que no le corten agua y luz. El tema del empadronamiento no lo puedo hacer hasta tener la asignación de plaza, necesito ese documento para justificar el nuevo domicilio. Queda pendiente este trámite . Os paso el Nº cuenta. La pensión ya hizo el cambio el banco directamente, tengo que saber qué cantidad es . Si es PFHC y Orfandad no tengo que hacer nada más','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-04-27','-Amalia : contacto con la TS para aclarar estos conceptos que han detectado desde sección eco . Escribo email a sección eco y Ana : he podido contactar con la TS para averiguar el concepto de los 100€ mensuales que habéis detectado en su cuenta. Se le envían a su sobrina. Proceder a la baja , cubrían gastos de suministros y algunas comidas que le llevaba. Igualmente hay que dar de baja al Ctro de día . Este mes se lo han cargado por error , lo van a devolver . He visto que han pedido desde el centro dinero para ropa , Ana lo ha autorizado. En un principio desde la resi me indicaron que no enviásemos nada de dinero por el momento , allí tenían mucha ropa . El señor no quería ni que le dieran dinero de bolsillo , no sé si habrá solicitado ya algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-04-26','Ana: Correo a Mamen, TS Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Te informo que Miguel Ángel Ramos Andrés, ha estado alojado en el centro de acogida temporal Centro Vida desde el día 18 al 25 de abril, ayer decidió abandonar el centro por ganas de consumo." ·························· Reenvío a los A. Jurídicos para que comuniquen al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2023-04-27','Respuesta de Angel sobre el tema de la vivienda: No se necesitaría su autorización, toda vez que su sentencia lo incapacita por completo, para el gobierno de su persona y bienes y la actual legislación, se remite a lo que diga la sentencia. Solo sería necesaria la autorización judicial. En cuanto a la creencia de Aquilino por el estado en el que se encuentra la vivienda no es actual. Disponemos de la demanda que presentó el vecino del bajo, en el año 2016, con fotos, en la que ya entonces la vivienda del vecino presentaba humedades, con abombamiento y agrietamiento del techo, por filtraciones de agua de la vivienda de la madre de Aquilino. Se pueden apreciar las humedades en la parte alta del edificio (buhardilla), que afectan también a la fallada. En cualquier caso, la vivienda está en ejecución hipotecaria, porque los que firmaron la hipoteca, su madre y hermano, dejaron de pagar la hipoteca. Y el banco ha solicitado subastarla. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-04-27','Maite:Aitor no puede sacar dinero en Navas ya que no hay sucursal, sí cajero. Decidimos hacer una tarjeta monedero para que pudiera retirar el dinero. Hoy nos comunica Oscar que el banco pone problemas para ello. Por tanto se va a hacer una transferencia mensual a la cuenta de su madre ( Felisi) de 80 €, y ésta le dará 40 € quincenales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-04-27','Ana: Envío correo-e a Toni-Futuex, con derivación al Programa de Apoyo Comunitario. ·············· Comunico a Francisco (641 569 490) dicha derivación. ························ Y a Julio, Aux. Adtvo. la nueva dirección: C/ Médico Sorapán. Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-04-27','Ana: Llamada de Estrella Durán, TS CSS-Plas. (24146): le ha facilitado mi número a Desideria, por si tiene que llamarme en algún momento. Por otra parte, le ha dicho la conveniencia de renovar el DNI, pues además ahora por cambio de domicilio, no tendrían que abonar las tasas, pero le ha dicho que "ahora hace mucha calor para eso"... ······· *En cuanto al TAD, puesto que el serv. municipal hay que abonarlo, se niega a ello. Por tanto, de momento no lo solicitaremos.··············· Volverá a recordarle la conveniencia de ambas cosas más adelante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2023-04-27','miguel, email de Inés: Hola compis, referente al caso de Ana Cruz Santos, en relación al Auto que se recurrió (Escalona), ayer le pregunté a Escalona el estado en que se encuentra dicho procedimiento. Me contestó que, lo ultimo notificado es una diligencia de ordenación de 29 de marzo de 2023 de la Secc Segunda de la Audiencia Provincial de Badajoz, incoando el recurso de apelación bajo el numero 296/2023, y nombrando magistrado ponente del mismo. Esta es la Dior que os reenvío. Ya esta subido a su expdte. en Defensa Judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2023-04-27','Respuesta de Angel sobre el tema de la vivienda: No se necesitaría su autorización, toda vez que su sentencia lo incapacita por completo, para el gobierno de su persona y bienes y la actual legislación, se remite a lo que diga la sentencia. Solo sería necesaria la autorización judicial. En cuanto a la creencia de Aquilino por el estado en el que se encuentra la vivienda no es actual. Disponemos de la demanda que presentó el vecino del bajo, en el año 2016, con fotos, en la que ya entonces la vivienda del vecino presentaba humedades, con abombamiento y agrietamiento del techo, por filtraciones de agua de la vivienda de la madre de Aquilino. Se pueden apreciar las humedades en la parte alta del edificio (buhardilla), que afectan también a la fallada. En cualquier caso, la vivienda está en ejecución hipotecaria, porque los que firmaron la hipoteca, su madre y hermano, dejaron de pagar la hipoteca. Y el banco ha solicitado subastarla. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2023-04-27','Respuesta de Angel sobre el tema de la vivienda: No se necesitaría su autorización, toda vez que su sentencia lo incapacita por completo, para el gobierno de su persona y bienes y la actual legislación, se remite a lo que diga la sentencia. Solo sería necesaria la autorización judicial. En cuanto a la creencia de Aquilino por el estado en el que se encuentra la vivienda no es actual. Disponemos de la demanda que presentó el vecino del bajo, en el año 2016, con fotos, en la que ya entonces la vivienda del vecino presentaba humedades, con abombamiento y agrietamiento del techo, por filtraciones de agua de la vivienda de la madre de Aquilino. Se pueden apreciar las humedades en la parte alta del edificio (buhardilla), que afectan también a la fallada. En cualquier caso, la vivienda está en ejecución hipotecaria, porque los que firmaron la hipoteca, su madre y hermano, dejaron de pagar la hipoteca. Y el banco ha solicitado subastarla. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2023-04-27','Maite: Maribel Rivera, directora de la residencia de INCLUSIVES, ha enviado un informe relativo al permiso terapeútico de Yolanda durante los días 17,18,19 de Abril. (subido a su expediente).Ponen de manifiesto las dificultades que supone prestarle la atenciónn que requiere. Desde la UHDAC piden otro permiso terapeútico para del 8 al 12 de mayo. INCUSIVES solicita la búsqeuda de un recurso mas adecuado a las necesidades y atención que requiere YOlanda. Este mismo informe, lo han enviado también a la Unidad de Programas Asistenciales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2023-04-27','Ana: llamada de Abraham, hijo de Mª Pilar (927 234 706): dice que les gustaría irse a una vivienda social, porque actualmente viven de alquiler y económicamente no llegan a cubrir todos los gastos. Se lo ha comentado a Gloria, Ed. Futuex. ················ Ha acudido también a hablar con Carmen, TS de Vivienda. Ésta le ha dicho que vuelva a finales de mayo. ························································· Envío correo a Toni- Futuex: "En relación a PILAR GARCÍA MORENO, acabo de hablar con su hijo Abraham. Dice que económicamente van tan ajustados que se están planteando irse a una vivienda social. De hecho ya ha hablado con la TS de vivienda y ésta le ha dicho que vuelva a finales de mayo. Quería pediros, que en la medida de lo posible, agilicéis la próxima visita a domicilio para que nos comuniquéis cómo sigue la situación desde la perspectiva profesional y aparte, que redacten el desglose de la media de gastos mensuales y que indiquen también qué cuantía aporta Abraham (según él casi todo… ) y qué cuantía su madre. Así se podrá valorar con la sección económica si es necesario, y viable, aumentar la asignación mensual de Pilar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2023-04-27','Amalia : ingresada en el H.U.B , en la UCI 5 dias por EPOC. Saldrá muy dependiente , he quedado con la familia que se valorará ingreso en plaza sociosanitaria. Al alta hay que solicitar revision dependencia y PIA. Puede necesitar ingreso en C. Residencial , los hijos quieren llevarsela a uno en el P. Vasco. Quedo pte. que me enviarán los informes medicos de alta para tramitarlo . Se le va a enviar los 100€ a la cuenta de la madre para gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2023-04-27','Ana: Correo de Felisa Custodio (trabajadora_social_alcuescar@imserso.es) al ctutelar@: "Buenos días, la residente quiere irse dos meses al CAMF de Leganés, ha iniciado una relación sentimental con un antiguo novio, residente en el CAMF de Leganés y quiere ir a verlo. El chico ha estado en Alcuéscar las navidades pasándolas con Maribel. Me han anticipado que es difícil que se lo puedan conceder porque hay más demandas pero la residente lo quiere intentar, ya se lo denegaron para ir el pasado mes de marzo. Adjunto solicitud para firma si lo estiman oportuno. Saludos." ·························· Pido a Felisa, que confirme si el gasto de taxi sería el mismo que planteaban en el mes de enero, cuando finalmente le denegaron la estancia temporal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-04-27','miguel, email de Soraya: Os dejo debajo mail de la psiquiatra de Saturnino Miguel, tenemos que insistir con el juzgado a ver si se pronuncian le van a dar el alta....','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-04-28','miguel, envío email a la abogada Carmen Lucas: Buenos días Carmen, necesitamos saber cuándo van a resolver el juzgado el procedimiento de Saturnino. Quieren darle el alta de forma inminente en el hospital con el problema que ello puede suponer… El día 10 me comentaste que estabas pendiente de hablar con él para trasladarle lo que el Fiscal ha ofrecido: 2 años y 6 meses de prisión o 3 años de internamiento en centro Psiquiátrico. Desde la Comisión y el SEPAD hay gran preocupación por este expediente y por saber cuanto antes cuál es la resolución del procedimiento judicial. Desde la oficina del Defensor del Pueblo han vuelto a escribir para preguntar. Por favor, intenta agilizarlo e indícame si ha habido avance sobre el mismo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-04-28','Ana: Correo de Pedro Pablo Garvi, TS del CES de Cáritas (pgarvi.cdcoriacaceres@caritas.es): "Hola Ana, para tenerte informada. Miguel Ángel abandonó el centro el martes por la tarde y esa misma noche y el miércoles se quedó a dormir en el Centro de Emergencias. Hoy no hemos sabido nada de él." ································································································································································································· Envío mail a A. Jurídicos y a Julio, Aux. Adtvo. CTAEx: "Os adjunto nuevo correo (pasado a PDF, como en la ocasión anterior) remitido por el Coordinador del Centro de Emergencias Sociales de Cáritas, comunicando que MIGUEL ÁNGEL RAMOS ANDRÉS abandonó el otro centro (como nos había dicho la TS de Centro Vida) y ahora está pernoctando en el CENTRO DE EMERGENCIAS SOCIALES. Espero que os sirva para comunicarlo al Juzgado. Podéis pasar también a PDF el de Mamen (TS) si lo veis conveniente. Pongo en copia a Julio, por si quiere hacer nuevo cambio de domicilio en la base de datos… aunque tampoco sé lo que durará ahí." ······························· Respuesta de Miguel, A. Jurídico: "Perfecto, si el lunes no aparece iremos a la comisaria a poner la denuncia por desaparición…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-04-28','Maite escribe a Patricia , TS : Santiago Puertas tiene reconocida una pensión de orfandad absoluta por la que percibe 832,80 € al mes. Cuando hagáis el cálculo nos lo pasa','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-04-28','Maite escribe a Patricia , TS : Santiago Puertas tiene reconocida una pensión de orfandad absoluta por la que percibe 832,80 € al mes. Cuando hagáis el cálculo nos lo pasa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2023-04-28','Amalia : Ana ha acudido a su banco para pedir tarjeta de crédito , desde la sección eco indican a la entidad que no se le da a ningún tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2023-04-28','Ana: Correo de Ángela, Directora Placeat (directora@placeat.org): "Maria demanda salir de residencia con un grupo de amigas (usuarias del centro ocupacional) los fines de semana, concretamente el domingo por la tarde. Nosotros consideramos que ella tiene habilidades suficientes para ello, además era algo habitual que ella hacia antes de ingresar con nosotros. No sé si para ello es necesario tener autorización vuestra, o es suficiente ponerlo en conocimiento." ························ Mi respuesta: "Puesto que el equipo técnico del centro sois quienes mejor la conocéis y, siendo su deseo, cuenta con capacidad y habilidades para ello, no hay ningún problema en que salga los domingos con su grupo de amigas del CO. Tomo nota"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-04-28','miguel, contestación de la abogada Carmen Lucas, que reenvío junto a mi email a la parte social y a Soraya: Hola Miguel buenos días, no te puedo decir cuando se va a resolver, no depende de mi. Estuve ayer fuera y estoy aún abriendo el correo, si hubiera algo nuevo te lo dirá, Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-04-28','Ana: Correo de Toni-Futuex: "en 2018, se intentó un seguimiento con Francisco Cacho Garrido, cuando se encontraba en UHB del Virgen de la Montaña, que se nos solicitó para conocer el estado del caso, por prescripción medica no pudimos verle, fue informarnos a través de los profesionales. Lo que nos indicaron es que se derivaba a UME de Plasencia. Según me dices, ha pivotado por muchos recursos residenciales y ya de vuelta.. como sabes, que las personas con trastorno mental grave, establecen redes entre sí, hemos sabido indirectamente de él.. porque fue la pareja de una tutelada nuestra, una relación complicadisima y él, almenos anteriormente consumidor activo, creo que estuvo en rehabilitación en proyecto hombre. Pero nada, en cuanto podamos, lo incorporamos al programa e intentamos verlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-04-28','Ana: Correo de Ángel, A. Jurídico: "Te envío Nota Simple del Registro de la Propiedad, es negativa." ······················· Se lo comunico a Laura, TS APTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO'and edp.apellido1='CUEVAS'and apellido2='MOYANO'),'2023-04-28','TERESA En relación a la salida del usuario de este centro D. Francisco Cuevas López, ruego a la Comisión Tutelar de Adultos de Extremadura, que determine si existe o no alguna limitación legal para que este usuario salga del centro. El usuario ha solicitado permiso para ir a Badajoz el día 3 de mayo, para visitar a un amigo, y volver ese mismo día. Realizaría el viaje en autobús de línea. Hasta ahora (remito informe de la psicóloga del centro), está cumpliendo puntualmente con su toma de medicación, así como como con las terapias psicológicas que le pauta la psicóloga, a las que acude según la planificación horaria pactada con él, desarrollándose de forma satisfactoria. Entiendo que si existiese alguna limitación de privación de libertad de este señor, no hubiese sido derivado a un recurso residencial como éste, sino que hubiese debido continuar en algún centro cerrado, donde se le pudiese impedir la salida. Es más, según los antecedentes que conocemos, antes de ser derivado a este centro, el usuario tuvo la oportunidad de irse a vivir a su domicilio, y decidió ingresar voluntariamente en una residencia, por lo que a nivel legal, deduzco, que una vez cumplidas las medidas recogidas en el auto judicial, no debería haber limitaciones a sus movimientos o medidas de apoyo desde esa Comisión Tutelar. Ante estos antecedentes, y habiendo sido informados de que su comportamiento en el Centro Sociosanitario de Mérida fue de colaboración, al igual que aquí, hasta hora, tener que esperar a que el Juzgado se pronuncie sobre la idoneidad o no de su salida del centro, lo único que puede hacer es empeorar la salud mental de esta persona, haciendo que presente más ansiedad y nerviosismo, pues no sabemos el tiempo que el Juzgado tardaría en pronunciarse, y, por otra parte, incluso si podríamos ser demandados por él mismo por privarle del derecho a la libertad de movimientos. Por todo ello, ruego nos trasladéis la respuesta a esta solicitud, basada en la legislación que deba aplicarse, y que podamos darle a este usuario una respuesta antes del miércoles día 3 de mayo. Os quedo muy agradecido por vuestras gestiones. AUTORIZAMOS SALIDA Y COMUNICAMOS AL JUZGADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2023-04-28','Ana: Tras hablar con Ángel, A. Jurídico y con el Habilitado, Gómez-Bascuñana, modifico a mano la Declaración de Aptitud Legal incluyendo la Retención Judicial que se le practica. ··································· Envío correo a Julio, Aux. Adtvo.: "Te envío los siguiente documentos relativos a D. MATEO RUANO MORENO, para remitir al habilitado: - Oficio - Declaración de Aptitud Legal 2023 - Certificado de Clases Pasivas con detalle de Retención - Extracto Bancario con los importes detallados de la cuantía líquida que percibe"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2023-04-28','Ana: Envío correo a Felisa Custodio, TS CAMF: "Remito adjunta la SOLICITUD DE ESTANCIA TEMPORAL EN EL CAMF DE LEGANÉS, relativa a Dª. ISABEL DEBON CHENIQUE, firmada digitalmente por su Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-04-28','Ana: Envío correo-e a Mamen, TS de Centro Vida, Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Buenos días Mamen, ¿Sería posible que le trasmitieras a Francisco que desde la Sección económica se autoriza el aumento de asignación mensual que solicitaba? Le conceden los 400€ /mes que pidió, pero con la CONDICIÓN DE NO SOLICITAR EXTRAS. Te lo pido a ti para que así estés tú también al corriente y porque supongo que hoy le verás, ya se va el lunes. Si no te es posible, dímelo y le llamo." ····················· Su respuesta: "yo le informo, sin problema"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-04-28','miguel, la abogada Carmen Lucas me envía la citación para el 31-5-23 para la vista del juicio oral. *************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-02','miguel, mi contestación a la abogada Carmen Lucas: Buenos días, gracias. Ignoramos si tendremos que asistir (la Comisión tutelar como tutor) en cuyo caso deberán hacerlo por Cisco (videoconferencia). Por otra parte no sé si el tribunal es consciente de que le van a dar el alta y volverá a escaparse, ya que no creo que puedan mantenerle allí otro mes. Supongo que se lo habrás hecho saber. Quedamos a tu disposición para lo que necesites. ******************************************************* Reenvío a Soraya, Maite y Ana el email con el auto de la Audiencia Provincial de Cáceres señalando vista de juicio oral el 31-5-23: Buenos días, adjunto fecha de la vista para el juicio oral, que quedó pendiente desde febrero por no estar localizado Saturnino. Como podéis leer desde febrero sabe el tribunal que se encuentra en la UHB y no ha dictado señalamiento para la vista del juicio oral hasta el 31-5-23, esperando el alta médica. Para que no se escape de nuevo deberíamos comunicar a la Audiencia la fecha en la que le darían el alta (varios días antes) y el riesgo que supondrá de que de nuevo se escape o bien le trasladaran a otro centro. O bien si es posible que lo comunique directamente la UHB a la Audiencia, a efectos de que dicten las medidas oportunas o al menos lo sepan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-05-02','Ana: Reenvío correo de Laura, TS APTO, a Alberto y Óscar, Secc. Ecca., y explico: "Te reenvío correo de la Trabajadora Social de la Asociación a la que acude Beatriz Parra Domínguez. No sé si tendréis ya información sobre su cuenta y acceso a la misma, yo creo que es pronto. Pero nos pasan los últimos movimientos bancarios, así que ahí constan el número de cuenta, que no sé si ya disponíamos de él. Tenemos que decidir si se le va a abrir nueva cuenta o se mantiene esa, porque tengo que cambiar la pensión (PRESTACIÓN FAMILIAR POR HIJO A CARGO), solicitándola a nombre del representante legal. Es decir, mantendrá la misma, pero tengo que hacer el trámite sí o sí. **En cuanto se pueda, hay que dar de baja tarjetas y aplicaciones móviles. Como podéis ver en los movimientos, e indica la TS en el correo, la hermana continúa haciendo mal uso del dinero de Beatriz en beneficio propio. Creo recordar que ya le dije cuando hablé con ella, que con el móvil no aceptamos contrato y tendrán que cambiarlo a tarjeta de prepago, pero igual no se enteró bien. Habrá que volver a decírselo. En relación a las vacaciones, en cuanto tengamos acceso a las cuentas, si es viable, por mi parte, ok. Indican que han acordado que el dinero lo retire su hermano José, le explicaré que se pondrá a José como acompañante, pero que tiene que ir ella con él. Me parece bien que éste le ayude a administrarlo. Como veis, envían también un presupuesto de gastos. Dividen los gastos comunes entre las tres hermanas que conviven en el mismo domicilio. Ya me decís que os parece."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CABEZAS'and apellido2='MAZON'),'2023-05-02','EXITUS El centro informa de su óbito, acaecido el 01/05/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-05-02','miguel, nos llama José Lavado 661423311 a Angel y a mi, para ofrecernos que su despacho nos hará el escrito de subsanación para vender las 3 fincas que quedan, y sería firmado por su despacho de abogados (su hija) en vista de que Angel Garcia Calle no responde ni a emails ni llamadas desde hace meses. En cuanto lo tenga lo revisaremos y tras su firma por el gerente se lo enviaremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-05-02','miguel, envio a Escalona informe social y médico solicitado para procedimiento de revisión de medidas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-05-02','miguel, pregunto a PEDRO PABLO GARVI GARCIA >pgarvi.cdcoriacaceres@caritas.es>: Hola, buenos días. Miguel Ángel abandonó el Centro Vida el martes 25 de Abril por la tarde, y desde esa fecha está pernoctando de 22:00 a 10:00 en nuestro Centro de Emergencia Social pasando el resto del día en la calle, hasta el día de hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-05-02','Ana: Recibo llamada de Montaña, TS del SSASB-La Cumbre (621 247 249): Montaña ha recibido una carta de PNC, al hacer la revisión anual se han dado cuenta de que no tiene vigente el Cdo. de Discapacidad. Era provisional. ······ Al parecer recibió una carta del CADEX con nueva citación. Ella pensó que era para que la ingresaran, así que ni se la llevó a nadie ni se presentó a la cita en el CADEX. ································································································································································································· Llamo a Domingo Salas, Director del CADEX -CC (927 00 55 09): Me informa de que el expediente ya está archivado. Le enviaron la carta el 8/11/22, firmó el acuse de recibo, la citaban el 16/11/22 y no se presentó. 3 meses después archivaron el expediente. ··········· Habría que hacer nueva solicitud y están tardando 2 años en valorar. ·········· La única alternativa que queda es que el Director-Gerente del SEPAD, envíe escrito ordenando la reapertura del expediente por situación de emergencia social. ······························································································································································································ Por otra parte, hay que activar el 112 para el ingreso en los PP.TT. de Santa Marta. *Montaña acordó con el Alcalde que le cobraran en función de sus ingresos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-05-02','Ana: correo de Mónica, Ed. PS el sábado: "hemos conseguido información sobre su situación y ubicación: actualmente se encuentra en Mataró. Javi esta semana ha llamado al C.R.R. solicitando que le ayudemos a contactar con vosotros/as pues ha intentado llamar en varias ocasiones, pero no ha conseguido hablar contigo, y es cuando nos cuenta que está en Mataró y que no le queda dinero. Hoy, sábado 29, la situación ha cambiado pues ha ido a urgencias del hospital de Mataró pidiendo ayuda, desde allí han podido contactar con su hermano Jorge. He hablado con él y se muestra preocupado por la situación de Javi, pues no sabe con quién hablar sobre la situación de su hermano y como proceder para poder retirar dinero del cajero. Me cuenta que Javi continúa manteniendo su deseo de quedarse en Mataró, por lo que también plantea si podría darse un cambio de tutela, si podría regresar de alguna forma a Extremadura. Se muestra nervioso y con muchas dudas sobre qué va a pasar con Javi. Su teléfono es el 635610832 y su correo sultanesdelswilg75@gmail.com (creo que no hay error de transcripción con el correo). De todas formas, si no pudieras contactar con él, me dices por si te puedo ayudar hablando con ellos o puedo facilitarles tu correo para que directamente te escriban ellos a ti. Pide que contactes con él lo antes posible, pues intentarán mantenerle ingresado hasta el lunes 1 o martes 2 como medida de protección, pero expresan duda de poder alargar el ingreso más tiempo." ···································· Tras hablar con Jorge, hermano de Javier (635 61 08 32) y Cristina, TS SSASB Mataró (93 758 23 01); Javier está hospedado en un hostal. Regresará en trasporte público el jueves, nos concretarán. ················· Envío correo a Mónica, Ed. PS: "Muchas gracias por informar. Nada más leer tu correo esta mañana, entró una llamada de Jorge, el hermano de Javier. Ayer, como bien decías en tu correo, le dieron el alta en el hospital. Hemos hablado también con la TS del los servicios sociales de base de Mataró, a la que han acudido también. En principio, si no hay cambio en de última hora Javier regresará a Plasencia el viernes, pues viajará el jueves por la noche. Buscaremos algún alojamiento para él. Su deseo de vivir en Mataró persiste, por lo que habrá que organizar su traslado con tiempo, tal y como estabais trabajando con él desde el recurso. En cuanto a sus pertenencias, le diremos que pase a recogerlas por el piso una vez que esté instalado en Plasencia." ································································· Informo a Alberto y Óscar, de la nueva situación: "...Habrá que hacer nuevos cálculos. No obstante, su proyecto personal sigue siendo irse a vivir a Cataluña de aquí a unos meses, pero esta vez, si tiene paciencia, se le ayudará a programarlo y organizarlo bien, pues habrá que ayudarle a buscar allí alojamiento, empadronarlo y hacer todo el traslado de expedientes varios… así que la apertura de nueva cuenta no habrá sido en vano. Cuando esté ya en Plasencia le pediremos que acuda a una oficina de Ibercaja a escanear el DNI." ··································································································································································································· Correo de Jorge, hermano de Javier (sultanesdelswing75@gmail.com): "Tal y como habíamos acordado por teléfono previamente te informo de la llegada de Javier será sobre la 01:30 de la madrugada a Plasencia, siendo este el único billete directo posible que he encontrado. Adjunto el billete con sus paradas correspondientes para que tengas información exacta del recorrido del autobús por si sucediera cualquier cosa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-05-02','Ana: correo-e a Mamen, TS de Centro Vida, Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Te informó que Paco se marcho del centro el día 30 de abril, ese día por la mañana recibe una llamada del chico que le había alquilado el piso, y le dice que no puede entrar el día 1 de mayo, ya que la persona que tiene que marcharse esta en Madrid y no se marcha hasta el 4 o 5 de mayo y entonces es cuando podría entrar Paco, este se enfada mucho y le pide que le devuelva el dinero que le ha entregado de señal, al final del día decide abandonar Centro Vida, y esta durmiendo en el Centro de Emergencia Social. joooo un desastre, si hablo con el te informo." ····························································································································································································· Mi respuesta: "...me dejas de piedra… qué rabia… Pongo en copia a mis compañeros Asesores Jurídicos, por si quieren comunicar este nuevo cambio al Juzgado, y a Maite, Jefa de Secc. para que esté al corriente de la nueva situación…. A ver qué hacemos con él… ya lo había derivado a Programa de Apoyo Comunitario para seguimiento en su nueva dirección, les comunicaré el cambio y siendo así, será difícil que puedan trabajar con él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-05-02','Ana: Correo de Óscar al banco: "Buenos días Jorge. Veo que Montaña ya ha sacado los 200€ que solicitas. ¿Ha sido ella en persona? Te lo digo porque, según nos consta, está ingresada en el Sociosanitario de Plasencia." ············································· Respuesta del banco: "Ha sido ella, me ha dicho que tenía hoy libre y que mañana ingresaría de nuevo. Como es la primera disposición del mes de mayo, he utilizado vuestra autorización histórica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-05-03','Ana: correo de Isabel Cano, al ctutelar@: "Buenos días Ana te quería comentar de que me quiero quitar la cicatrices de las quemaduras y quisiera saber si puedes tú indagar a ver dónde me las puedo quitar ya que cada vez que me voy a duchar y me desnudo me veo al espejo y me veo horriblemente fea y veo las cicatrices y me pongo a llorar pero a llorar mucho gracias un saludo." ·································································································································································································· Mi respuesta: "Entiendo que te sientas así, es comprensible. Sinceramente, no creo que este tipo de intervenciones las cubra la seguridad social, no obstante, voy a consultarlo, por si acaso y en cuanto me confirmen algo te lo transmitiré. En cualquier caso, considero que es algo que también podrían tratar contigo las compañeras del CRR, por ello las pongo en copia, para que podáis ir abordándolo independientemente de la respuesta que me den en el SES."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-05-03','Ana: Llamada de Anabel, TS SSASB Miajadas (927 34 70 00 / Directo: 927 90 12 38): Joaquina le ha llamado diciendo que le ha llegado una cita del Juzgado el día 17/05, pero no sabe explicarle nada más. ······························· Ángel, A. Jurídico llama al Juzgado de Trujillo, confirman que se trata del Reconocimiento del Forense por el Procedimiento de Internamiento Involuntario. ······························································································································································································ Anabel, TS, llamará al C.S. para intentará conseguir un informe de salud en que indiquen su dificultad en la deambulación y las úlceras que presenta en la pierna para solicitar que la revisión del Forense tenga lugar en el domicilio. ······················· Tampoco dispone de medios económicos, pues su escasos ingresos se los gasta nada más cobrarlos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-05-03','miguel, contestación de la abogada Eva Mª. Pérez Escarmena >eperezescarmena@icac.es> Buenos días, la verdad es que el presupuesto de reposición de la cubierta es muy superior al anterior de 2021, pero son los precios que hay en este momento. Aunque te remito dos presupuestos , se trata de una sóla obra la reparación o reposición de la cubierta, las cuotas de participación son 33.47%, conforme catastro, son para los propietarios de la primera y segunda planta. El local de la farmacia tiene un 19.47€ y el local de nuestro despacho un 13.59%, ya que es el que menos superficie tiene. El problema es, que como sabes el primer piso pertenece a una "empresa", que esa empresa no existe y no quieren abonar su parte, de tal forma que Civantos con arreglo a tener una cuota superior y por que ha sido un acuerdo que propusimos habría de pagar el 50% de lo que le corresponde al propietario que no quiere pagar, y el otro cincuenta sería abonado entre los propietarios de la farmacia y nosotros, quedando así abonado por completo el precio de las obras. Posteriormente repetiríamos contra este propietario con intención de cobrar lo que vamos a adelantar, pero te adelanto que no va a ser fácil cobrar, ya que tienen el piso a nombre de una empresa para evitar que se lo embarguen y esa empresa estará inactiva fiscalmente, etc. No obstante, tenemos solicitado otro presupuesto para comparar, que creo no enviarán esta semana. Aunque el importe va a variar poco. Si quieres que comentemos todo más directamente por teléfono, estoy disponible para aquello que puedas necesitar ******************************************************** Email de Alberto a la parte social Ana y a mi: TOD@S: TRAS EXPLICACIÓN DE LA ABOGADA/VECINA, Y TRAS HABER HABLADO CON MIGUEL, PARECE BASTANTE MÁS RAZONABLE EL PRESUPUESTO QUE NOS REMITE DICHA ABOGADA. CONDICIONES QUE DEBERÍAMOS INCLUIR: • CONTAR CON EL ACUERDO QUE LA ABOGADA DICE QUE HAN PROPUESTO Y CON LA ACEPTACIÓN DEL TUTELADO DEL MISMO....MIGUEL: QUIZAS ESE ACUERDO, U OTRO QUE SE REALICE, DEBERÍA INCLUIR EL REPARTO DEL DINERO UNA VEZ QUE EL VECINO QUE SE NIEGUE A PAGAR LO HAGA. • COMUNICAR AL JUZGADO EL GASTO QUE SE VA A REALIZAR INCLUYENDO INFORMACIÓN SOBRE EL VECINO QUE NO PAGA Y QUIZÁS EL ACUERDO ENTRE VECINOS. EN MI OPINIÓN, Y PENDIENTE DE LO QUE DIGAIS LOS DEMÁS, CREO QUE SE PUEDE AFRONTAR ESTE GASTO ******************************************************* Contesto a la parte social Ana y parte economica Alberto: Buenos días, yo remitiré comunicación consistente en el presupuesto y un acuerdo firmado por el tutelado. Para ello preparé una petición de arreglo de la vivienda y de estar de acuerdo con el importe presupuestado, que enviaré a Ana para su firma por Julián Ramón','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-05-02','miguel, envío a la abogada las dudas de la parte económica: Hola Eva, desde la parte económica de la Comisión les surgen las siguientes dudas. En relación al importe que nos remitistes de obra necesitamos saber lo siguiente: • ESTAMOS HABLANDO DE ABONAR 25.399,11 € (IVA INCLUIDO). ES MUCHO DINERO PARA UNA OBRA. • DUDAS: o ESTAMOS SEGUROS DE QUE A EL LE CORRESPONDE EL 33 % DE LA OBRA COMÚN???  ESTO QUIERE DECIR QUE ÚNICAMENTE HAY 3 VIVIENDAS EN EL INMUEBLE??? o ENTENDEMOS QUE, ADEMÁS DE LA OBRA COMÚN, HAY OTRA OBRA QUE NO CORRESPONDE A LA COMUNIDAD Y QUE ÚNICAMENTE AFECTA A 2 DE LOS 3 PROPIETARIOS (EL DE LA PRIMERA Y EL DE LA INTERMEDIA)  ESTAMOS SEGUROS DE QUE ESTA OBRA NO LE CORRESPONDE TAMBIÉN A LA COMUNIDAD???  ESTAMOS SEGUROS DE QUE A EL LE CORRESPONDE EL 50 % DE LA OBRA (AQUELLA QUE NO CORRESPONDE A LA COMUNIDAD) Y QUE COMPARTE CON OTRO VECINO??? ******************************************************** Email de Alberto: TOD@S: • ESTAMOS HABLANDO DE ABONAR 25.399,11 € (IVA INCLUIDO). ES MUCHO DINERO PARA UNA OBRA. • DUDAS: o ESTAMOS SEGUROS DE QUE A EL LE CORRESPONDE EL 33 % DE LA OBRA COMÚN???  ESTO QUIERE DECIR QUE ÚNICAMENTE HAY 3 VIVIENDAS EN EL INMUEBLE??? o ENTENDEMOS QUE, ADEMÁS DE LA OBRA COMÚN, HAY OTRA OBRA QUE NO CORRESPONDE A LA COMUNIDAD Y QUE ÚNICAMENTE AFECTA A 2 DE LOS 3 PROPIETARIOS (EL DE LA PRIMERA Y EL DE LA INTERMEDIA)  ESTAMOS SEGUROS DE QUE ESTA OBRA NO LE CORRESPONDE TAMBIÉN A LA COMUNIDAD???  ESTAMOS SEGUROS DE QUE A EL LE CORRESPONDE EL 50 % DE LA OBRA (AQUELLA QUE NO CORRESPONDE A LA COMUNIDAD) Y QUE COMPARTE CON OTRO VECINO??? SI NO TENEMOS NINGUNA DUDA BASADA EN LO ANTERIOR O EN OTRAS QUE PUDIERAIS TENER, ABONAMOS. MIGUEL: EN MI OPINIÓN HABRÍA QUE COMUNICAR AL JUZGADO EL GASTO QUE VAMOS A REALIZAR...NO HABLO DE PEDIR AUTORIZACIÓN (ESO YA SABES TU SI HAY QUE HACERLO O NO), SI NO DE COMUNICAR QUE HEMOS AFRONTADO UN GASTO TAN ELEVADO Y SIGNIFICATIVO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-04-28','miguel, envío email a la parte económica: Parte económica, le decimos entonces a la abogada que comience los trámites?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-04-27','miguel, recibo presupuesto de la abogada:Buenos días Por fin, ayer por la tarde nos enviaron uno de los presupuestos solicitados, los adjuntamos al presente correo *************************************************** mi contestación: Buenas tardes, por fin. Necesitaríamos tener un presupuesto concreto de la parte del tutelado Ramon Civantos… ********************************************************* contestación de la abogada: sí, va en el correo anterior, te lo vuelvo a adjuntar ********************************************************* reenvío presupuesto a parte económica y social: Este es el presupuesto definitivo de arreglo de la vivienda. Necesito que ambas partes social y económica deis el visto bueno al presupuesto de arreglo de la vivienda antes de que la abogada solicite la correspondiente autorización judicial por gastos extraordinarios… *********************************************************** contestación de Alberto: Hola. Con independencia del presupuesto que se acepte, lo "importante" es saber cuanto va a tener que pagar el tutelado. Su situación ECO es buena, pero: • Aún no sabemos cuanto tiempo va a tener que estar fuera de su vivienda, abonando pensión/hotel/otros, NI el importe de esto. Entendemos todos que suele ser muy caro y que además no van a dejar de pasarle consumos, impuestos, etc. • Miguel: en relación con el punto anterior y desconociendo la realidad de la situación. Si esta obra es responsabilidad de la CVecinos, no es esta la que tendría que hacer frente a los gastos de estancia del tutelado fuera de su domicilio habitual??? **********************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-04-28','miguel, email a la parte económica y social: Buenos días, la comunidad no está constituida por lo que los arreglos corresponden por cuotas proporcionales. La cuestión es que son pocos y hay uno que se acabará declarando insolvente y al parecer aunque intentaramos posteriormente cobrar esa deuda con un embargo sobre la vivienda de nada serviría porque tiene hipoteca previa. En cualquier caso ya se ha contratado y adelantado cantidad a la abogada para que vaya gestionando la autorización correspondiente y hasta septiembre me comentó no comenzarían las obras. Lo hablamos si queréis ya que al menos la parte de él son los +o- 20.000€+abogada+demás gastos que sepáis desde la parte económica…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-04-28','miguel, email a la parte económica y social: Buenos días, la comunidad no está constituida por lo que los arreglos corresponden por cuotas proporcionales. La cuestión es que son pocos y hay uno que se acabará declarando insolvente y al parecer aunque intentaramos posteriormente cobrar esa deuda con un embargo sobre la vivienda de nada serviría porque tiene hipoteca previa. En cualquier caso ya se ha contratado y adelantado cantidad a la abogada para que vaya gestionando la autorización correspondiente y hasta septiembre me comentó no comenzarían las obras. Lo hablamos si queréis ya que al menos la parte de él son los +o- 20.000€+abogada+demás gastos que sepáis desde la parte económica… *************************************************** contestacion de Ana: En este caso, considero que hay que preguntarle a él, si está dispuesto a asumir este gasto para arreglar su vivienda. Él en principio sí que quería y estaba desolado por el estado en que e encuentra su casa, pero está cada vez más mayor y más delicado de salud y no sé si es consciente de lo que le puede costar. ¿Os parece que haga gestiones para que la Educadora de Futuex le informe del gasto real para que en base a ello manifieste su conformidad y así tengamos en cuenta su voluntad, deseos y preferencias? ****************************************************** mi contestación a la parte económica y social: Buenos días, el arreglo de la vivienda es una obligación legal ya que puede ocasionar daños a terceros. Al ser el propietario y tener disponibilidad económica y salvo que tenga seguro que se ocupe del arreglo del mismo hay que actuar lo antes posible ya que la empresa comenzaría los trabajos en septiembre y en estos meses la abogada irá agilizando la autorización judicial de gastos extraordinarios. Hablad si queréis con él, pero cuanto antes decidme si le decimos o no a la abogada que vaya solicitando dicha autorización al juzgado. ********************************************************* contestación de Ana: Si como dices es una obligación, no hay nada más que hablar. Proseguid tal cual está previsto. ********************************************************** envío email a parte económica y la social: Parte económica, le decimos entonces a la abogada que comience los trámites?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-05-03','Ana: Correo de Lourdes, Secc. ecca., a Marta Custodio, TS Montehermoso y a mí: "se adjunta justificante de pago para la ropa de Santos García Esteban."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-05-03','Ana: Reenvío a los A. Jurídicos, la consulta realizada por Paula, TO (tocupacional.crrplasencia@grupo5.net): "Buenos días, me pongo en contacto contigo para realizarte una consulta. Como Ceferino compró una nueva controladora, hablamos de la posibilidad de vender la otra. Para ello quería preguntarte si podría subirla a páginas de segunda mano u otro tipo de plataforma o podría hacerlo directamente a través de una tienda o directamente con una persona. Acordamos que el dinero que recibiera lo guardaríamos y planificaría en qué lo quería gastar (acciones u objetos con objetivos significativos)." ·································································································································································································· Respuesta de Ángel: "Si, no hay problema para que pueda vender la controladora. Ojo, debe asegurarse que funciona correctamente y no está dañada, porque el comprador tendría una garantía de 6 meses. En el caso de querer utilizar plataformas online, tiendas, etc, que nos diga con quién quiere venderla, para ver condiciones. ¿Cuál sería el importe por el que quiere venderla?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2023-05-03','Ana: Subo al portafirmas la Aceptación PIA - Mantenimiento de SAR - RM Villa del Rey. ·························································· Envío a Julio, Aux. Adtvo. CTAEx: "Te reenvío, para su registro en SIREX, ACEPTACIÓN PIA DE MANTENIMIENTO DE SERVICIO RESIDENCIAL, relativo a Mª SALVADORA CHAVES MENDOZA. Adjunto también la carta donde indica dónde hay que remitirlo, junto al código de registro (buzón) de SIREX."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-04-25','miguel, recibo email de jorge calvo (abogado)reuniomabogados@gmail.com> POJ PIEZA OPOSICION A EJECUCION - 333/2022 - CARMEN LEAL BENITO - 25/04/2023-Notificación Recibida Buenas tardes, Me temo que tengo que ponerte en conocimiento que la ejecución que se ha presentado del asunto de Carmen Leal ha sufrido un revés y el proceso que se ha abierto nos lo han cerrado (con expresa imposición en costas, cantidad que quedará pendiente de calcularse). el motivo de discrepancia es que el Arbitro había notificado a la parte del laudo arbitral mediante una carta certificada. El momento en el que nos encontramos ahora es el siguiente: 1º. Estudiar si recurrimos o intentamos iniciar nueva ejecución, subsanando lo que dice el Juez. 2º. Si no recurrimos estaremos a la espera de que se calculen las costas como un daño y pérdida que tendría Carmen. Este punto no me gusta, soy pesimista en la cantidad que pudiera resultar de este revés sufrido. Te ruego me puedas confirmar la recepción del presente email. ******************************************************* mi contestación: Buenos días Jorge, estamos decepcionados con esta resolución judicial ya que llevamos años con este problema. El auto indica los errores cometidos y que alegó la parte demandada: 1º) Nulidad el despacho al amparo del art. 559.3º LEC por no poder someterse a arbitraje el contenido del laudo, esto es, la resolución contractual y el desahucio, teniendo la parte demandada el derecho a enervar la acción de desahucio; 2º) Falta de firmeza del laudo arbitral por no haber sido debidamente notificado Esto es así? No entendemos que no tuviesen constancia de este procedimiento…y por tanto si es nulo no tiene sentido recurrirlo, sino iniciarlo de nuevo? Cual será el importe de las costas? El tribunal ha entendido que ha habido mala fe por nuestra parte demandante? Qué ocurre con la mensualidad que sigue sin recibir desde que está en trámite todo este asunto? Si quieres lo comentamos. ********************************************************* Email a la parte económica y social: Buenos días, malas noticias. Carmen Leal pierde el juicio con imposición de costas que más adelante nos dirán. El motivo es lo que indico en mi contestación al abogado, donde además le pregunto las dudas que nos queda después de esto. La solución pasaría por iniciar de nuevo todo el procedimiento para desahuciar a los inquilinos… Recordad que los inquilinos insistían que la han ido abonando las mensualidades en mano. Si decidís que encarguemos al abogado que lo reinicie, ya me lo decis. ********************************************************* Recibo aclaración del abogado Jorge Calvo: El auto indica los errores cometidos y que alegó la parte demandada: 1º) Nulidad el despacho al amparo del art. 559.3º LEC por no poder someterse a arbitraje el contenido del laudo, esto es, la resolución contractual y el desahucio, teniendo la parte demandada el derecho a enervar la acción de desahucio; - El árbitro realizó la notificación del laudo por correo certificado. Por lo que la parte demandada a fin de ejercitar su "derecho de queja" vino a decir que lo que se le había notificado no era el contenido del laudo. - Nosotros iniciamos el proceso de ejecución con la documentación que ha sido facilitada por el Árbitro del proceso. 2º) Falta de firmeza del laudo arbitral por no haber sido debidamente notificado - Por lo anterior, el Juzgado ha dado presunción a lo que se queja de la requerida debe prosperar por garantía procesal. Esto es así? No entendemos que no tuviesen constancia de este procedimiento…y por tanto si es nulo no tiene sentido recurrirlo, sino iniciarlo de nuevo? -tenía pleno conocimiento del proceso. Lo que dice es que no "se ha acreditado" que se le haya notificado el laudo (documento de terminación del proceso). Un requisito formal que parece que el juzgado lo hace valer sobre el término de justicia. Cual será el importe de las costas? El tribunal ha entendido que ha habido mala fe por nuestra parte demandante? - El importe no lo tengo calculado. - No he notado que el Juzgado indique mala fe. De hecho, hubo una notificación del Juzgado en donde el Secretario advertía de que el laudo no había sido notificado por burofax, y pasó a la mesa de su señoría para admitirse la ejecución o no. En ese momento nos podríamos haber encontrado con la inadmisión del proceso, y de ahí a reclamar al Arbitro que lo arregle, pero lo cierto es que el Juzgado vino a admitir el proceso y a continuar con el trámite. Traas eso, y tras demorar todo lo posible, la requerida vuelve a manifestar lo mismo que tuvo que valorar el Juez para la admisión, con la sorpresa de que ahora le dan la razón y archiva el proceso. Qué ocurre con la mensualidad que sigue sin recibir desde que está en trámite todo este asunto? -Deberán ser objeto de proceso. Pero ante la presumible insolvencia, ya se verá cómo actuar. El laudo ha condenado a un importe que se liquidó en su momento. Iniciar ahora actuaciones con importes mayores, hubiera encarecido el asunto para no saber el resultado que se podría tener. Pero, con la documentación que estoy viendo en el proceso, ya adelanto que dudo que podamos recuperar dinero, por su situación de insolvencia. SOBRE EL RECURSO, PUES HAY QUE VALORAR LA SITUACIÓN. Se necesita tiempo para trabajarlo y verlo. ******************************************************* Reenvío la aclaración a la parte económica y la social: Buenos días, ha respondido el abogado a las dudas planteadas de si nos merece o no la pena recurrir el procedimiento. Echad un vistazo porque tenemos que decidir qué hacer: recurrir, o no hacer nada, o iniciar de nuevo el procedimiento con el coste que conllevará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-05-02','miguel, envio email al abogado josé manuel rubio Buenos días José Manuel, te envío documentación relacionada con un expediente cuyo objeto era un procedimiento de desahucio por falta de pago por la vía del arbitraje, pues así figura en su contrato de alquiler. La cuestión es que se ha denegado con imposición de costas a la tutelada. Los inquilinos presentaron recibos supuestamente firmados mensualmente por la inquilina, si bien en el contrato figuraba que tenían que haberlo ingresado en su cuenta. Dicho contrato fue firmado por ella, estando tutelada y la Ctaex tuvo conocimiento tiempo después…y nunca se impugnó. La cuestión es que ni antes ni después de dicha demanda se ha abonado que sepamos cantidad alguna por los inquilinos, y ahora nos encontramos en la encrucijada si impugnar vía recurso la resolución (ya que dice el abogado que obedece a que los demandados dicen no haber sido notificados en forma de la demanda porque el arbitro les notificó por carta certificada, no constando por tanto el contenido de la misma. Te dejo debajo lo que me escribió el abogado y las preguntas que le hice a raíz de la resolución judicial. Me gustaría saber tu opinión y consejo al respecto. Te llamaré mañana a las 10h para comentarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-05-03','Ana: Correo a Toni-Futuex: "Ayer hablamos con el hermano y con la Trabajadora Social de Mataró en distintas veces a lo largo de la mañana. Javier regresará a Plasencia. Hoy nos han confirmado que mañana jueves día 4 cogerá un bus hasta Zamora y de allí a Plasencia, con llegada a la misma a la 01:30 h (del viernes ya). Como sabéis, la plaza en el Piso Supervisado la ha perdido, por tanto hay que buscarle un alojamiento en Plasencia. De momento, visto el poco tiempo y la urgencia, habrá que buscarle un hostal o algo así. Una vez que esté instalado y más tranquilo, habrá que ayudarle un piso de alquiler. *Os solicitamos que, por favor, os encarguéis de esta gestión. No sabíamos que estaba propuesto para CRPS, lo cuál nos parece muy adecuado. Supongo que esta derivación la mantendrán y se podrán retomar las citas de seguimiento en el Equipo de Salud Mental sin problema. Agradeceríamos también que gestionaseis la nueva citación por la que no se presentó. Al hostal/pensión, se abonará, como imaginaréis, mediante transferencia bancaria, por lo que tendrán que facilitar número de cuenta bancaria. Deciros también, qué de momento, hasta que tenga un alojamiento más estable (piso de alquiler) y pueda establecerse nuevo presupuesto de gastos, se le mantendrá la misma asignación mensual que tenía cuando estaba en CRR y Piso: 500€/mes. De hecho podrá retirarlo de la oficina habitual el mismo viernes. La idea, es, retomar la intervención con él, desde los distintos recursos/programas, para organizar su regreso a Cataluña pero de forma organizada y programada. Con un alojamiento ya buscado y en el que se pueda empadronar para proceder después al traslado de expedientes de Sistema de Salud, Dependencia, Discapacidad, etc… Aún no tenemos nº de contacto de Javier, le he pedido al hermano que, si ya lo ha comprado, nos lo facilite." ································································································································································································· Comunico a A. Jurídicos, el regreso de Javier a Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-05-03','miguel, hablo con el fiscal Jose Manuel Rubio quien me indica que no le ve fácil solución y que teniendo en cuenta que se declararan en insolvencia si se gana el procedimiento, lo suyo sería pedir que desocupen la vivienda por cumplimiento de contrato (hacer los preavisos oportunos) y si acaso en procedimiento aparte judicial reclamar las cantidades adeudadas. ******************************************************** Tras reunión con la parte económica Alberto y la social Maite y Amalia se decide no hacer nada por ahora. La parte económica mirará los movimientos de cuenta para comprobar quién está pagando los suministros y gastos de mantenimiento de la vivienda. Por mi parte mando a Alberto la identificación de la finca y a la social enviaré los datos que puedan acreditar si está o no en exclusión social los inquilinos en cuyo caso no se les podría expulsar. ******************************************************** Email q envio a la parte económica Alberto y a la social Maite y Amalia: Buenas tardes, adjunto los datos de la vivienda (nota simple y contrato de alquiler) junto a la contestación a la demanda y destaco el documento DTO 2 Demanda-Unidad familiar.PDF (compuesto por la información económica + certificado de empadronamiento, libro de familia, etc) No veo informe ni apartado solicitando la exclusión social, y como veis viven el padre, la madre y la hija nacida en 1990…Amalia aclaranos si podrían acogerse a dicha exclusión social. Si no hubiera dicha exclusión social vuelvo a proponer dos soluciones a elegir: 1.-Demandar vía judicial la extinción del contrato y así lograr que desalojen. 2.-Llegar a un acuerdo de nuevo contrato de alquiler, previo firma del mismo por la tutelada Carmen Leal. Si finalmente decidis que no merece la pena actuar decídmelo para comunicárselo al abogado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-05-03','miguel, envio a Inés con copia a Ana y Angel: Buenos días Inés, envía por Lexnet al juzgado de 1º instancia e instrucción nº5 de Cáceres, (los datos de su sentencia de incapacitación), un Oficio que contenga “ A los efectos oportunos, se adjunta comunicación de Cáritas en relación al tutelado Francisco Cacho Garrido que se marchó el 30-4-2023 y desde entonces pernocta en el Centro de Emergencias” Adjunta el email de debajo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-04-24','TERESA Se contacta con Belén la taxista de la localidad para reservar plaza en el Taxi para llevar a Aitor al juzgado de Cáceres para la cita del día 10, Belén confirma que el precio seria 50€ y como en otras ocasiones acepta el pago por transferencia, confirma que pasara a recogerlo a las 9:30 del día 10 de mayo. Cuando nos de la factura la remitiremos. El día anterior en la vista al domicilio y en la gestión para la realización de la compra semanal se le explica al tutelado que tiene esta cita y la idoneidad de acudir a la misma, se le explica también que tiene otra cita para el día 8 en Trujillo pero que de momento no debe acudir tal y como se informa desde la coordinación del equipo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-05-02','TERESA Se acude a Navas para acompañar a la madre de Aitor, Felisa, a la retirada de la asignación quincenal, Aitor en el momento de la llegada esta acostado y no acompaña a su madre, pero a la vuelta de la gestión se vuelve a la vivienda y se le recuerda la cita de los juzgados y la hora a la que lo recoge el taxi, la pregunta su puede ir con su madre a lo que se le responde que no hay ningún problema. Aitor confirma los datos aportados por su madre y explica que sale a diario con un amigo suyo de la infancia llamada José Manuel, este fin de semana ha estado en una localidad cercana a Coria para asistir a un encierro de vaquillas, también viaja a menudo a Cáceres y Plasencia….explica que este amigo le invita a todo y no tiene que pagar nada, no acepta consejos pero se le recuerda que la gente no suele dar nada gratis y que los favores personales suelen tener una contraprestación, pero él insiste en que esta persona es buena compañía. Se muestra hermético al preguntarle sobre lo que hace fuera de casa, y no es del todo claro en sus mensajes durante la conversación por lo que no es posible indagar más, solo explica que realizan actividades de ocio como asistir a discotecas, vaquillas etc. y que también están buscando trabajo juntos. Pero la realidad es que pasa poco tiempo con su madre y casi todas las tardes las pasa fuera del domicilio incluso de la localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-03','miguel, recibo email de la abogada Carmen Lucas: Puedes volverme a dar el teléfono de contacto??? Para hablar con él al respecto, no sé si está en Psquiatría o en la Cárcel ***************************************************** Mi contestación: Buenos días, el último teléfono de contacto que tenemos de él es el 689937787 Sigue ingresado y me comentan que seguirá ingresado en la Unidad de psiquiatría del Hospital San Pedro de Alcántara de Cáceres. El email de la trabajadora social de contacto es Maria del Carmen: mariac.rodriguez@externos.salud-juntaex.es En vista de que el juzgado no ha dictado las medidas cautelares para asegurar la asistencia del tutelado (no hay un protocolo sanitario y de seguridad por parte de la Junta, como da a entender la Audiencia en el Auto…). Es por eso que ya he indicado a la parte social de la Comisión que hable con el Hospital para asegurarnos de la asistencia a la vista para el juicio oral el día 31-5-23. ********************************************************* Envío email a la parte social Ana y Maite: Buenos días, os envío para vuestro conocimiento contestación a la abogada de Saturnino que me pedía el tfno de él… Como veis la veo perdida pues no sabía ni donde está… Maite coordinad como hemos hablado que Saturnino asista a la vista el día 31-5-23. *******************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-03','miguel, recibo email de la abogada Carmen Lucas: Puedes volverme a dar el teléfono de contacto??? Para hablar con él al respecto, no sé si está en Psquiatría o en la Cárcel ***************************************************** Mi contestación: Buenos días, el último teléfono de contacto que tenemos de él es el 689937787 Sigue ingresado y me comentan que seguirá ingresado en la Unidad de psiquiatría del Hospital San Pedro de Alcántara de Cáceres. El email de la trabajadora social de contacto es Maria del Carmen: mariac.rodriguez@externos.salud-juntaex.es En vista de que el juzgado no ha dictado las medidas cautelares para asegurar la asistencia del tutelado (no hay un protocolo sanitario y de seguridad por parte de la Junta, como da a entender la Audiencia en el Auto…). Es por eso que ya he indicado a la parte social de la Comisión que hable con el Hospital para asegurarnos de la asistencia a la vista para el juicio oral el día 31-5-23. ********************************************************* Envío email a la parte social Ana y Maite: Buenos días, os envío para vuestro conocimiento contestación a la abogada de Saturnino que me pedía el tfno de él… Como veis la veo perdida pues no sabía ni donde está… Maite coordinad como hemos hablado que Saturnino asista a la vista el día 31-5-23. *******************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-05-03','Ana: Envío correo a Laura, TS APTO (trabajosocial@asociacionapto.org): "comunicarte que desde la sección económica han estado mirando la situación económica de Beatriz. Aún no tienen acceso a las cuentas, en cuanto tengan darán de baja tarjetas bancarias, servicios de Bizum y todo lo demás. Como alguna de las heramas esté de titular en la cuenta la cosa se complicas. Es posible que se le abra una cuenta sólo para ella. Quería preguntarte, también, pues así me trasladan la consulta, qué tipo de contrato tiene Beatriz (duración) y si tiene las pagas extras prorrateadas o las cobra a parte. El viaje se autoriza, así que cuando podáis, haced el cargo en cuenta, pues como digo, aún no tienen acceso en la secc. económica. Confiemos en que no sigan cargándoles otros gastos las hermanas… Ah, otra cuestión que os tengo que aclarar, es el hecho de que Beatriz no podrá mantener el contrato de telefonía que tiene, así que por favor, hablarlo con ella y con las hermanas, pues tendrá que comprar una tarjeta prepago y dar de baja ese contrato. Por favor, ayudarla con esta gestión si es posible. Ya digo que desde aquí aún no hay acceso, por lo que nos e puede pagar nada todavía desde aquí. Suponemos que aún puede sacar el dinero como siempre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-05-03','-Amalia : hablo con Estrella para que den su opinion y solicitar por PIA plaza en CRR . La opcion del P. Mi casa , no hay plazas .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-05-03','Ana: Envío correo a Sergio, Coord. Proy. Mi Casa, Don Benito (sergioromerodiaz@plenainclusiondonbenito.org): "En relación a FELISA BRUNO SAAVEDRA, necesitamos que nos remitáis, en cuanto os sea posible, un CERTIFICADO DE INGRESO en vuestro centro, indicando que reside en vuestro recurso y la fecha en que ingresó, pues hemos de comunicarlo al Juzgado. Espero que Felisa siga bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-05-03','Amalia : percibe 2 pensiones , se le indica a Patricia para calcular copago. Orfandad: 832,80 € Prestación por hijo a cargo: 679,90','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-05-03','Ana: Correo de Arantxa, Directora de la RM Parque del Príncipe (parquedelprincipe@grupociudadjardin.com): "Buenos días, como hable ayer contigo por teléfono, os mando por escrito los últimos acontecimientos que ha pasado sobre la residente María Jiménez y su hermana Isabel Jiménez. El jueves pasado se persono en la residencia para hablar conmigo, el abogado Antonio Alfredo Barca Duran, con un poder notarial en el que se había firmado que era el represéntate de doña Isabel Jiménez, la hermana de María, anteriormente teníamos otro poder en el que la representare era la sobrina de las dos, Carmen Jiménez Sixto. El abogado además de traerme el poder, me dijo que todo lo que afectara a su representada, se le tenía que comunicar a él. (Con este tema, ya hemos tenido problemas, ya que llaman lo sobrinos y también quieren que los informemos y ya les hemos dicho que si hay un represéntate, ya es a él al que le damos la información.) Me trajo un escrito en el que me pedía una serie de cosas, como facturas, reglamento, contrato, régimen de visitas, etc... Me estuvo comentando que era un abogado muy quisquilloso y que había visto muchas irregularidades por parte de la tutela de la junta, yo le conteste que no iba a permitir que dijera eso, porque era totalmente falso, que la junta y la residencia siempre ha velado por el bienestar de las dos hermanas, todos los años que aquí llevan. Me hablo de irregularidades en las cuentas y yo le conteste que nosotros nunca hemos tenido acceso y ha sido aparecer la sobrina y sacar a Isabel y traer extractos de las cuentas. Le dije que no entiendo como dicen que los demás han hecho irregularidades, si ellos han sido los primeros en sacar a Isabel y en menos de dos meses firmar dos poderes notariales cuando Isabel no está capacitada para saber lo que firma, ya que Isabel tiene un internamiento no voluntario dictado por el Juzgado de 1ª Instancia de Cáceres en 2020, por su deterioro. Ayer el señor abogado, iba a venir para hablar con mi superior, conmigo y la trabajadora social pero no se ha presentado. Sobre todo para hablar de temas de visitas, salidas y de dar información a terceros. Paralelamente ayer, me llego una notificación del juzgado, en el que se me cita para testificar como testigo en el juicio por “el robo/ocupación en la casa de las dos hermanas”, no entiendo que se me cite a mí, ya que yo no soy testigo de nada, todo lo que se, es porque me lo ha dicho Carmen Jiménez, la sobrina o la policía nacional cuando vino a pedir información. La verdad que esta historia no acaba nunca, pero bueno hay que tener paciencia y llevarlo lo mejor posible." ························· Reenvío a Ángel y Maite, CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-05-03','Amalia : percibe 2 pensiones , se le indica a Patricia para calcular copago. Orfandad: 832,80 € Prestación por hijo a cargo: 679,90','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2023-05-03','TS DE LA LUZ: Buenos días. Adjunto envío factura de la silla de ruedas que le ha sido comprada a Cristóbal García Casquero. Por otra parte, informarte que la neuróloga que lo está tratando en CasaVerde le indicó ayer a Segunda que se prevé que Cristóbal tenga el alta hospitalaria el día 18 de mayo. Ese día volverá a nuestro Centro y deberá continuar con la rehabilitación en la clínica ambulatoria Casaverde que está situada aquí en Badajoz. Como no tiene reconocido Grado de Dependencia creemos que sería conveniente que se lo solicitáramos. Una vez vuelva y comprobemos las necesidades que presenta quizás valoremos un cambio de perfil si considerásemos que fuera necesario. Si te parece bien, preparo la documentación y os la envío para su firma. Ya me dices. --------------- Se inician gestiones de dependencia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2023-05-03','TS DE LA LUZ: Buenos días. Adjunto envío factura de la silla de ruedas que le ha sido comprada a Cristóbal García Casquero. Por otra parte, informarte que la neuróloga que lo está tratando en CasaVerde le indicó ayer a Segunda que se prevé que Cristóbal tenga el alta hospitalaria el día 18 de mayo. Ese día volverá a nuestro Centro y deberá continuar con la rehabilitación en la clínica ambulatoria Casaverde que está situada aquí en Badajoz. Como no tiene reconocido Grado de Dependencia creemos que sería conveniente que se lo solicitáramos. Una vez vuelva y comprobemos las necesidades que presenta quizás valoremos un cambio de perfil si considerásemos que fuera necesario. Si te parece bien, preparo la documentación y os la envío para su firma. Ya me dices. --------------- Se inician gestiones de dependencia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-05-03','futuex: Amalia te actualizo lo que vamos sabiendo de Fco Javier Giraldo, y también el seguimiento realizado a Santos Garcia Esteban, que se realizó en la residencia de Montehermo: Fco Javier Giraldo El viernes pasado, se ha habló por teléfono con Nuria (TS de Calzadilla) que ha facilitado el numero de teléfono de Luis (médico de primaria). Se ha estado hablando con Paqui (enfermera) que aseguraba que Javi estuvo ayer en el consultorio medico para ponerse el inyectable , el cual le toca cada 28 días , comenta que normalmente Javi acude solo cuando le toca, de cualquier manera se le podría acompañar en algún momento para conocer presencialmente a la enfermera y al médico. Después, se ha hablado con Luis que comentaba que ayer vio a Javi muy estable y tranquilo. Ha comentado que para poder pedir una nueva cita para el CEDEX y para revisión de salud mental en Zafra, es necesario primero gestionar el cambio a este área de salud, ya que Javi sigue en el área de Mérida. Se gestionará llamando al centro de salud de Fuente de Cantos como ha indicado Luis. Esta semana estaba previsto hacerle un seguimiento en la localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-05-03','Ana: correo de Ana, Ed. Plena Inclusión Zafra: "Hemos acompañado a Reme al Juzgado. Hemos pasado primero al forense y después junto al forense con el juez. El objetivo era valorar su situación y ratificar que debe seguir en la residencia. Ha ido bien… supongo que os llegará la comunicación…en el caso de que nos llegue aquí, os lo envío Seguimos en contacto" ············ Reenvío a Jurídicos y a Maite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-04','Ana: Reenvío a A. Jurídicos CTAEx, correo de Mª Carmen, TS HSPA, reenviando a su vez correo de Carmen Lucas, Abogada : "Buenos días, soy Carmen Lucas, la Letrada de Saturnino, me gustaría saber como hacemos para entrevistarnos porque el 31 de mayo empiezan las sesiones del juicio y quiero saber si vamos a defender o quiere acuerdo. También necesito saber si se me podría hacer un informe indicando que tal es su estado que está total y absolutamente impedido o incapacitado para controlar sus actos, en cuyo caso, podría defenderse una eximente completa." ··········· Adjunta AUTO: "SE ACUERDA SEÑALAR PARA EL INICIO DE LAS SESIONES DEL JUICIO ORAL LA FECHA DEL 31 DE MAYO DE 2023, a partir de las 10:00 horas de su mañana"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-03','Ana: Correo de Miguel, A. Jurídico CTAEx: "Buenas tardes, adjunto denegación a la retirada del carnet de conducir que solicitamos en marzo del 2021 al jzdo de Saturnino, el jzdo nº2 de Cáceres. Tuvimos que reiterar la petición en octubre de 2022 ante la falta de contestación y nos contestan en mayo de 2023 para denegárnoslo en base a que conforme el informe del Ministerio Fiscal, Carmen Barquilla, es una medida a valorar en el procedimiento de revisión de medidas de apoyo que se deberá instar. No está mal, que hayan pasado más de dos años para esta resolución denegatoria… Inés: Ya lo he guardado en su expediente"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-05-04','Ana: Jordi, hermano de Javier, nos facilita nuevo nº de móvil de su hermano Javier: 657 340 972. Lo facilito a Toni-Futuex. ··································································································································································································· Correo de Toni-Futuex: "El hotel que parece que encajaba mejor es el Hotel Azar, son 80 eu la noche pero tiene recepción 24 h y tiene disponibilidad, había otras opciones más económicas pero no tenían para todos los días del finde y tendría que cambiarse. Pasado estos días, se puede mirar otra cosa, más económica. Esta avisado ya Javier En nota adjunta esta presupuesto y nota con número de cuenta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-05-04','Ana: A petición de Óscar, secc. ecca., envío correo a Laura, TS APTO (trabajosocial@asociacionapto.org): "En relación a BEATRIZ PARRA DOMÍNGUEZ, por favor, necesitamos que nos envíes escaneado a color, a la mayor brevedad, su DNI. Finalmente se procederá a la apertura de nueva cuenta bancaria." ························································································································ Recibo llamada de Laura, TS APTO: Beatriz tiene Contrato Indefinido. Las Pagas extras no están prorrateadas. Laura le acompañará hoy a cita médica para solicitar Informe de Salud para Ley de Dependencia. ············ Le acompañará también al banco para retirar dinero y *pedirán en el banco que cancelen las claves de la banca online. ········· Tengp pendiente Autorización para el Viaje. ············· Nos ha remitido el DNI escaneado. Lo paso a Óscar. ··························· Envío correo a Alberto y Óscar, secc. ecca., facilitando la información ecca. ································································································································································································· Subo al portafirmas digital la AUTORIZACIÓN PARA EL VIAJE A ALMUÑECAR del 16 - 20 junio. ················· Una vez firmada por el representante legal , la remito a Laura, TS APTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-04','miguel, email de Ana: Buenos días compis, Os reenvío correo remitido por Mª Carmen, TS del Hospital San Pedro de Alcántara. A su vez, es el correo que le ha remitido Carmen Lucas, Abogada. Por favor leer el hilo del correo y contestad a Mª Carmen. ************************************************* La trabajadora social ha reenviado el email que le manda la abogada Carmen Lucas: Buenos días, soy Carmen Lucas, la Letrada de Saturnino, me gustaría saber como hacemos para entrevistarnos porque el 31 de mayo empiezan las sesiones del juicio y quiero saber si vamos a defender o quiere acuerdo. También necesito saber si se me podría hacer un informe indicando que tal es su estado que está total y absolutamente impedido o incapacitado para controlar sus actos, en cuyo caso, podría defenderse una eximente completa. ********************************************************* Mi contestación a Ana, Maite y Angel: Buenos días Ana, la trabajadora social no te adjunta duda alguna…Lo que nos envía ( y que la ha enviado la abogada) es lo que ya os comuniqué, la citación para la vista del día 31-5-23. Lógicamente lo que la abogada quiere es hablar previamente con Saturnino para que le diga si quiere llegar al acuerdo que ya le expuso la abogada a la trabajadora social (la propuesta del fiscal de Cárcel o internamiento en Centro Psiquiátrico) o bien la defensa en el sentido de declararse inocente en cuyo caso no sabemos qué dictará el juez. Es lógico que quiera hablar con él y exponerle, dentro del nivel de comprensión que tenga el tutelado, las dos opciones propuestas por el ministerio fiscal para que el día de la vista 31-5-23 lleguen a un acuerdo (si Saturnino se declara culpable) o le defienda proponiendo la inocencia porque Saturnino no quiera declararse culpable (en cuyo caso le vendrá bien el informe solicitado al Hospital y se acogerá a la eximente del artículo 20 del Código Penal que explico más abajo) Recordad que tanto la abogada como el juzgado ya saben la posición de la Comisión Tutelar de Adultos que es la establecida en el acta de la subcomisión sociosanitaria regional de gestión de casos, que establecía…sugería que el centro adecuado podría ser centro del tipo psiquiátrico penitenciario u otros que reúnan características similares en relación con dichas necesidades. Paralelamente le está pidiendo a la trabajadora social que le remitan desde el Hospital un informe indicando “…su estado que está total y absolutamente impedido o incapacitado para controlar sus actos” es decir, que no controla sus actos de forma absoluta y por tanto no sabe lo que hace…con la finalidad de que la abogada pueda pedir la exención establecida en el código penal artículo 20 que establece: “Están exentos de responsabilidad criminal: 1.º El que al tiempo de cometer la infracción penal, a causa de cualquier anomalía o alteración psíquica, no pueda comprender la ilicitud del hecho o actuar conforme a esa comprensión. El trastorno mental transitorio no eximirá de pena cuando hubiese sido provocado por el sujeto con el propósito de cometer el delito o hubiera previsto o debido prever su comisión. 2.º El que al tiempo de cometer la infracción penal se halle en estado de intoxicación plena por el consumo de bebidas alcohólicas, drogas tóxicas, estupefacientes, sustancias psicotrópicas u otras que produzcan efectos análogos, siempre que no haya sido buscado con el propósito de cometerla o no se hubiese previsto o debido prever su comisión, o se halle bajo la influencia de un síndrome de abstinencia, a causa de su dependencia de tales sustancias, que le impida comprender la ilicitud del hecho o actuar conforme a esa comprensión. 3.º El que, por sufrir alteraciones en la percepción desde el nacimiento o desde la infancia, tenga alterada gravemente la conciencia de la realidad. 4.º El que obre en defensa de la persona o derechos propios o ajenos, siempre que concurran los requisitos siguientes: Primero. Agresión ilegítima. En caso de defensa de los bienes se reputará agresión ilegítima el ataque a los mismos que constituya delito y los ponga en grave peligro de deterioro o pérdida inminentes. En caso de defensa de la morada o sus dependencias, se reputará agresión ilegítima la entrada indebida en aquélla o éstas. Segundo. Necesidad racional del medio empleado para impedirla o repelerla. Tercero. Falta de provocación suficiente por parte del defensor. 5.º El que, en estado de necesidad, para evitar un mal propio o ajeno lesione un bien jurídico de otra persona o infrinja un deber, siempre que concurran los siguientes requisitos: Primero. Que el mal causado no sea mayor que el que se trate de evitar. Segundo. Que la situación de necesidad no haya sido provocada intencionadamente por el sujeto. Tercero. Que el necesitado no tenga, por su oficio o cargo, obligación de sacrificarse. 6.º El que obre impulsado por miedo insuperable. 7.º El que obre en cumplimiento de un deber o en el ejercicio legítimo de un derecho, oficio o cargo. En los supuestos de los tres primeros números se aplicarán, en su caso, las medidas de seguridad previstas en este Código”. Por eso debería llamar Saturnino a la abogada y como mínimo hablar por teléfono para saber qué quiere el tutelado. Si a la trabajadora social le queda alguna duda puede llamarme o bien indícame su teléfono y hablo con ella. Pero ya digo que de esta forma también se da una seguridad jurídica en el sentido de que cumplimos con la actual Ley 8/2021, de 2 de junio, por la que se reforma la legislación civil y procesal para el apoyo a las personas con discapacidad en el ejercicio de su capacidad jurídica…ya que hemos puesto todas las medidas posibles de apoyo a este tutelado incluido el que la abogada le escuche y sepa su decisión de declararse culpable (y poder llegar a un acuerdo) o inocente, ya mencionadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-04','Ana: Llamada de Enrique (662 56 78 32), solicita un extra de 20 - 25 €, dice haber tenido que abonar deudas de gastos sobrevenidos (peluquero canino, fontanero y otros gastos), dice que no tiene dinero ni para café para el desayuno. ············· La sucursal de su pueblo abre L-X-V. ························· Correo de Ana Benavente, TS ESM Plas. (anamaria.benavente@salud-juntaex.es): "Enrique Santos García Puente me dice que ya no tiene dinero para la semana, dado que ha pagado todas las deudas que tenía pendiente. Ha preferido pagar lo que debía, pero ahora se encuentra sin dinero." ··························································································································································································· Tras respuesta de Óscar, con indicación de su situación económica, contesto: "Por favor, confirmarle mañana, si os es posible par mañana mismo la autorización, que puede retirar 20 €, pero aclararle que no podrá solicitar más extras en el tiempo que estiméis. Pongo en copia a Ana Benavente, TS Equipo de Salud Mental para que esté al corriente. El teléfono de Enrique es: 662 56 78 32"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2023-05-04','Amalia : Se envia a registro SES Cdo. discapacidad para registrar al INSS. Sigue sin plaza publica en La Luz, está en una de menores, nos indica Soraya que se pretende que Cristofer pase de RAL a RAE y esa plaza se la adjudicarían a él .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2023-05-04','Ana: Llamada de Sonia Bernabé (927 390 193): Juan Gabriel, está mejor, evoluciona positivamente. Tiene pendiente una radiografía para confirmar que está soldando bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-05-04','Ana: Llamada de Sonia Bernabé, TS y Directora Asindi (927 390 193) informando de incidentes protagonizados por los dos hermanos: Roberto, se enfada y da un golpe leve a un compañero. Tras esto, su hermano Justo se altera también y acaba dando un golpe a una monitora. ····································· En cuanto a la próxima salida al domicilio familiar, si no hay cambio, se irán del 12 al 14 de mayo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-05-04','miguel, envío email a la parte social y Angel, tras recibir la llamada del jzdo de Trujillo para comunicarnos que van a declararse incompetentes. Buenos días Ana, acaban de llamarme del Juzgado de Trujillo para comunicarnos que no vaya Aitor a las citaciones programadas ya que van a declararse incompetentes porque Aitor está residiendo en Navas del Madroño. Al estar en huelga ha preferido llamarnos desde el juzgado ya que no sabe si dará tiempo a que nos llegue la notificación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-05-04','Ana: Llamada de Sonia Bernabé, TS y Directora Asindi (927 390 193) informando de incidentes protagonizados por los dos hermanos: Roberto, se enfada y da un golpe leve a un compañero. Tras esto, su hermano Justo se altera también y acaba dando un golpe a una monitora. ····································· En cuanto a la próxima salida al domicilio familiar, si no hay cambio, se irán del 12 al 14 de mayo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-05-02','Ana: Correo de Toni con SEGUIMIENTO de Marzo-Abril: Acompañamiento a citas en ESM y MAP, reunión con coordinadora del SAD. Ideación autolítica. + Ingreso en UHB durante el fin de semana del 13/04, muy descompensado, con alta el día 17 (Indican que pida cita y acuda al "CEDEX", y nuevas citas: Enfermería ESM el 19/04 y Psiquiatría ESM con la Dra. Blanca Suárez el 28/04). Aporta Informes Médicos. ······· Nuevo ingreso en UHB a fecha de 28/04/23.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-05-04','Ana: Llamada de Montaña, TS SSASB (621 247 249): Guadalupe tiene 49 años. Aunque hicieran el favor de que ingrese en el Piso de Santa Marta, no cumple el perfil ni por la edad ni por la patología mental que presenta. No es un recurso adecuado para ella. ········ Planteamos que se realice una Subcomisión de Casos. ·························· Llamo a Mª del Sol Tafur, TS ESM y E.C.A.- Trujillo y La Cumbre en distintas ocasiones a lo largo de la mañana (53418 / 54513): no obtengo respuesta. ··································································································································································································· Hablo con José Vicente Granado Granado, comunico la situación de Pérdida de PNC, por no haber acudido a la valoración del CADEX en noviembre y la situación de Emergencia Social en que se encuentra. Éste solicita a la Gerente Territorial de Cáceres que hablen con Domingo, Director del CADEX, para ORDENAR LA REAPERTURA DEL EXPEDIENTE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2023-05-04','-Amalia : LLega resolución IMIVI , le conceden 162,45€ al mes . De PNC percibe la completa 480€ Y de REGA 282.16 Hablo con Adela , me indica que PNC tiene en cuenta ingresos anuales y IMIVI igresos de la renta del año anterior y que es muy probable que genere ingresos indebidos. Por IMIVI si tuviese reconocido el 65 Gº.D. tendría derecho a un cpto.del 22% pero ella no acude al CADEX. No sé si por estar tutelada lo asimilan. Volveré a llamar al tecnico de REGA para que me indique cómo quedaria esa pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-05-04','Ana: Según Ángela, sobrina de Arturo, a éste le han concedido el traslado a la Res. Municipal de Los Santos de Maimona. Nosotros no tenemos constancia de nada. ··············· Hablo con Mai, Jefa Secc. Mayores, ha sido un error. Me facilitan la resolución. ·································································································································································································· Llamo a la Residencia (924 57 15 35) y hablo con Isabel, Directora. ······················ Envío correo a Ángela, sobrina, y a Mª Jose, TS de Sierra de San Pedro (mjacosta@mancomunidadsierrasanpedro.com): "He hablado con Isabel, Directora de la Residencia Municipal de Los Santos de Maimona. Como os he comentado en correo anterior, por error no nos habían envido la RESOLUCIÓN. En la Residencia la han recibido el día 2, por lo que estamos en plazo. Yo mañana no trabajo y ella no trabaja el lunes, por tanto hemos acordado hablar el martes para organizar el traslado. Normalmente se realizan en taxi, si las condiciones de la persona lo permite y si fuera necesario se abonaría un acompañamiento. No obstante, me ha dicho Isabel, que tú, Ángela o alguno de tus hermanos estaríais dispuestos a realizar este traslado, si es así, hacédnoslo saber. El martes concretaremos día y modo de proceder."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AVILA'and apellido2='RAMOS'),'2023-05-05','TERESA SE SOOLICITA CAMBIO DE LA DOMICILIACION DE LA PENSION A NUEVA CUENTA DE UNICAJA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-05-05','TERESA Se recibe llamada de Julia de la Casa Misericordia de Alcuéscar indicando que Pablo Galan Gilgado se encuentra en Zalamea de la Serena. Desde este programa se le visitó el miercoles y está muy bien. Pero indican que tras consumir alcohol, Pablo se puso muy agresivo, según nos comunican, es la primera vez que lo ven tan agresivo, indicando que se quería ir a su casa e intentando agredir físicamente a sus compañeros. Julia indica que el centro no está capacitado para controlar dichos comportamientos y al final tuvieron que llevarlo a su domicilio. Le dieron el DNI, tarjeta sanitaria, medicación para una semana y vieron que Pablo disponía de dinero, desconocen la procedencia del mismo. En su casa tenía comida no perecedera de la otra vez. Y supuestamente tabaco de liar también. Tampoco entendemos que la premisa del centro fuera llevarlo a su pueblo a la buena de dios, sin planificar esa visita, y por su cuenta... creemos que esto va a ser muy perjudicial porque ya sabemos que cada vez que quiera ir pues la liará. Y si se pusó mal y agresivo, pues nosotras entendemos que deberian haber avisado a 112 o algun servicio medico, para que le pusieran alguna medicación o determinar que hacer, pero no actuar de este modo. Desde que esta alli, a pesar de que nos dijeron, que si que se iba a tramitar no ha tenido seguimiento en salud mental.. ni nada. Decian que tenia una cita para cedex pero no existe la voluntariedad de dejar de beber, si tiene medios (dinero) beberá. En fin.. te iban a llamar hoy del centro, al parecer. No sabemos exactamente por cuantos dias, le han mandado a casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-05-05','TERESA RECIBO LLAMADA DE LA MADRE DE MARTA 643430944 PARA INDICARME QUE MARTA NECESITA UNA MALETA PARA IR A LOS JEDES ME DIRA PRECIO EL LUNES PARA AUTORIZAR LA COMPRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-05-05','emial de Amalia a Alberto y a mi: Buenos días , no tenemos datos de la familia para valorar si existe o no situación o riesgo de Exclusión Social. Por la información que se aporta , residen en la vivienda el matrimonio y su hija mayor de edad ( 23 años ) . No hay menores en la familia , que sería un indicador prioritario. Para valorar la exclusión social , se tienen en cuenta datos económicos , laborales, sanitarios , sociales...que se desconocen y a los que no vamos a tener acceso porque no es la familia la que solicita algún tipo de ayuda. Las dos opciones que planteas me parecen válidas , creo que el criterio jurídico es el que tendrá que determinar la actuación . ******************************************** mi contestación: Buenos días, si de mi dependiera elegiría la primera opción: Demandar vía judicial la extinción del contrato y así lograr que desalojen. Quedamos pendiente de la respuesta de Alberto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2023-05-05','TERESA ENVIO SOLICITUD CAMBIO DE PIA PARA PEDIR PRESTACION VINCULADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-05-05','Ana: Correo de Sheila, Directora CRR-CC: "Informaros de que la persona usuaria Consuelo Nevado Pacheco se encuentra desde ayer por la tarde ingresada en la UHB por desestabilización de su patología de base. Os iremos informando de su evolución."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-05-05','Ana: Correo de Sheila, Directora CRR-CC: "Informaros de que la persona usuaria Consuelo Nevado Pacheco se encuentra desde ayer por la tarde ingresada en la UHB por desestabilización de su patología de base. Os iremos informando de su evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-05-05','Ana: Correo de Paula, TO CRR-Plas (tocupacional.crrplasencia@grupo5.net): "Hemos estado hablando de la próxima salida a Trujillo. Como quería también la posibilidad de poder contar con una fecha para pasar la noche con su pareja en un hostal en Plasencia, propone lo siguiente: Poder ir a Trujillo del 15 al 17 de Mayo (dos noches) y después poder pasar la noche fuera del día 20. Por nuestra parte no habría problema, para este ajuste, puesto que ha tenido en cuenta el presupuesto máximo que puede utilizar." ································· Mi respuesta: "Si se ha ajustado al presupuesto y vosotros lo veis bien, por nuestra parte no hay problema."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2023-05-08','Ana: Tras leer correo de Ángela, Directora Placeat, remito correo a A. Jurídicos y Estrella Durán: "Os reenvío correo de Ángela, Directora de Placeat. Han nombrado y citado a Carlos Alberto Vicente Calderero, como suplente de 1º vocal en la próximas elecciones del día 28. ¿Podéis redactar las alegaciones? Ya nos decís si le dais registro o cómo se va a remitir. Como podéis leer en el hilo Ángela se ofrece a llevarlo al Juzgado. Pongo en copia a Estrella, para que estén al corriente y, pasada la fecha, procedan a empadronarlo en el C. Sociosanitario. Estrella, nos podéis enviar la hoja de inscripción para la firma del Representante Legal. También pongo en copia a Ángela." ····························································································································································································· Subo al portafirmas digital la Solicitud de Empadronamiento remitido por Estrella, TS del CSS-Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-05-08','Ana: Envío correo a Toni-Futuex: "Gracias. Ya me decís si encontráis algo más económico para después. Hoy podrá ir a retirar su asignación mensual, para que tenga para sus gastos. Una vez que se le encuentre otro alojamiento más económico (o piso de alquiler) a ver qué prefiere él, habrá que recalcular y ajustar su asignación." ································································································································································································· Correo de Carolina, Psicóloga y Directora en funciones del CRR-Plas. (direccion.crrplasencia@grupo5.net): "Javio Agudo está por Plasencia desde el sábado, ahora mismo se encuentra en los alrededores de la residencia, se encuentra tranquilo aunque su estado (principalmente físico, tiene dolores de pies y cuello) no es el mejor. Ha estado el fin de semana en urgencias, aunque no han considerado necesario ingresarle. He hablado un rato con él, quiere que le demos el dinero suyo que tenemos aqui (475 €) porque le hace falta." ····································· Maite y yo llamamos a Carolina; Javier puede retirar su asignación mensual habitual (500€) en la sucursal de siempre de Plasencia. La otra cantidad es mejor reservarla para el extra anual que pueda necesitar. De momento la custodiarán ellos. ···· Carolina confirma que Javier suele hacer uso responsable del dinero. ········ Se lo trasmitirán a Javier.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-05-08','Ana: Correo de Anabel, TS Miajadas (servicios.sociales@miajadas.org): "Adjunto informe de salud que justifica las dificultades de movilidad correspondiente a JOAQUINA MAYORAL PIZARRO." ················ Se lo envío a Ángel, A. Jurídico - CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-05-08','miguel, envío email a Angel Garcia Calle y su procurador Pedro Redondo Miranda: Buenos días Angel, hemos intentando contactar en reiteradas ocasiones contigo. De hecho como puedes comprobar en email de debajo, tu procurador Pedro Redondo fue quién nos remitió la firmeza del auto que adjunto el 31-1-23 tras asegurarnos con el juzgado que había sido emitido semanas atrás. Como puedes ver, y pongo en copia a tu procurador, en diciembre te remití la subsanación que debías presentar en el juzgado (email del notario D. Carlos Duro de 15-12-2022) y estamos en mayo y sigues sin ponerte en contacto con esta Comisión, pese a que ya has cobrado los honorarios, motivo por el cual debías haber presentado dicha subsanación. Desconocemos si lo has hecho o no. Pero debido a tu falta de comunicación con esta Comisión, quedamos a la espera en 48h de una contestación, caso de que no respondas daremos por concluido cualquier relación profesional contigo y procederemos a subsanar a través de otro abogado dicha resolución judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-05-08','-Amalia : me llama Carmen de la sección de mayores , está el primero para pasar a la R. M. R. Ibarra. Tienen informe de psiquiatria de marzo del 23 que es favorable a ingreso. Lo comunico a las compañeras de CSS .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2023-05-08','Buenos dias, Amalia. REGINA REINA LARA, acogida en el recurso sito en C/ Rota 41 de Badajoz y gestionado por Asociación HOFA, realizará excursión a Moraleja (Cáceres) , desde el 9 al 12 de mayo de 2023, para participar en la CONVIVENCIA DE JUEGOS DEPORTIVOS EXTREMEÑOS (JEDEX) acompañada por profesionales de su centro educativo,los cuales se harán responsable de la misma durante este periodo., por considerarse beneficioso para su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2023-05-08','Ana: Recibimos Resolución de Valoración de Dependencia. Le reconocen Grado III.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-05-08','Ana: Subo al Portafirmas Digital la Solicitud de Catering Municipal - IMAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-05-08','Ana: Correo de Arantxa, Directora de la RM Parque del Príncipe (parquedelprincipe@grupociudadjardin.com): "Buenos días, comentarte que me llamo la directora de la residencia Geryvida, que Isabel estuvo allí antes de venir aquí, me llamo para comentarme que le había llamado Carmen, la sobrina de las hermanas, hablando fatal de la comisión tutelar y de nuestro centro, que nos iban a denunciar a todo... La verdad que de vergüenza, para que me llamara la directora imagínate como se quedo, Llamo allí para ver si lo que estábamos haciendo estaba bien. Les dijo que no las dejamos ver, así que lo que he hecho es guardar los vídeos de cuando vienen, aunque esta todo apuntado, pero por si acaso, nos guardamos las espaldas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-05-05','Ana: correo-e a Mamen, TS de Centro Vida, Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Te informo que Francisco Cacho Garrido definitivamente no va al piso de alquiler, hemos hablado con el chico que se lo iba a alquilar y le va a realizar una transferencia a la cuenta de su madre devolviéndole los 400€, (parece ser que el chico que tenía que abandonar el piso no lo ha hecho). Hoy ha estado en nuestro centro y le hemos convencido para que se quede aquí hasta que encuentre otro piso compartido y lo haga a través de una inmobiliaria. Paco me refiere que si le queréis baja otra vez la asignación que por él no hay problema (`punto a su favor) Me refiere que ayer le llamo una chica del apoyo comunitario Futuex, para quedar con él, y Paco le conto, me imagino que tendrás que informar que esta otra vez con nosotros, para que no pierda el apoyo si se llega a ir a una vivienda." ···································· Respondo con copia a Toni-Futuex, para que esté al corriente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2023-05-08','-Amalia Le faltaría el cpto. ATP de agosto a diciembre de 2022 , pq según Oscar que ha revisado cuentas , lo está cobrando desde febrero y le dieron atrasos desde diciembre . Mª Angeles lo registró a PNC , está todo en su expediente, van a volver a revisarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-05-08','miguel, Buenos días, por acuerdo de las tres partes de la Comisión tutelar de adultos, la parte jurídica entiende que la mejor solución pasa por demandar a los inquilinos por finalización de contrato. Esto supone que además de las costas procesales que hay que abonar por perder el juicio de arbitraje, y que a fecha de hoy no sabemos cuánto cobraran, lo suyo será que una vez sepamos la cantidad y la abonemos procedamos como digo a Demandar (contratando de nuevo los servicios del abogado) pero esta vez por finalización de contrato. Esto supondrá si se gana, que desalojen la vivienda, y posteriormente nos plantearíamos demandarles por el dinero que deban y por los daños que puedan haber dejado en la vivienda. Por tanto, voy a comunicarle al abogado que nos pase el importe de la ejecución por costas a pagar. Una vez lo cual, recabaremos la firma de la tutelada consintiendo que los demandemos por fin del contrato. Y con ello ya podrá interponer el abogado la demanda correspondiente. Llamo al abogado Jorge Calvo para comunicárselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2023-05-08','-Amalia Le faltaría el cpto. ATP de agosto a diciembre de 2022 , pq según Oscar que ha revisado cuentas , lo está cobrando desde febrero y le dieron atrasos desde diciembre . Mª Angeles lo registró a PNC , está todo en su expediente, van a volver a revisarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-05-08','Buenas , he llamado a esta señora y os cuento el lío. Hace 2 años que compraron un coche de 7 plazas , según ella para que su hna y su exmarido también pudieran viajar junto a su familia. El préstamo bancario no se lo daban a ellos . LLegan a un acuerdo con la hermana y su expareja , y sacan un préstamo a nombre de Remedios y el coche también lo ponen a su nombre. ( supongo que para desgravarse los impuestos , ojo que ésto está muy supervisado ) Todos los meses la hna. ingresa en la cuenta de Remedios el pago mensual por el coche. Tienen un documento firmado con la autorización de Remedios. Como la vamos a quitar de la cuenta , para incluir a J. Vicente y además ella ya no quiere saber nada de la hermana , quiere regularizar el tema del coche. No ha hecho el ingreso de este mes pq quiere asegurarse de que no va a tener problemas . Por si no consigue pasar el coche a su nombre. Y porque las transferencias también le van a costar dinero. Quiere que hagamos como una venta del coche a su nombre . Supongo que para ésto , si se decidiera hacer , se necesita autorización judicial . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-03','Ana: Correo de Toni-Futuex con seguimiento del día 27 de abril. Guardo en el expdte. Notan a Enrique muy obsesionado con la cuestión económica. Solicita extras en varios conceptos. ··········· También observan algunas conductas excéntricas, y se muestra muy verborreico, pero no pueden asegurar que esté descompensado. Suele adular a las mujeres, incluida a la propia Educadora con expresiones tipo “tú eres muy guapa” "serás para mi” y mensajes similares.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-08','Ana: Llamada de Enrique (662 56 78 32) con nuevas peticiones de extras: Pida subida de asignación, más 50 € para desbrozar, dentista, productos de limpieza, comida para el perro... Se le recuerda que el viernes se le dio un extra de 20€ y que hoy ha retirado los 100€ de esta semana. No puede estar pidiendo dinero constantemente. ············· Para el dentista se le indica que acuda a una clínica y nos haga llegar el presupuesto, después se abonará mediante transferencia. ······························································································································································································ Llamo a Ana Benavente (74955): Acordamos que cuando le vuelva a llamar, le recordará que tiene que ajustarse a los gastos. Que para el dentista debe remitir presupuesto y para desbrozar también. Después se valorará en la secc. ecca. *Para el resto de gastos debe administrarse con su asignación semanal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2023-05-08','MIGUEL : por acuerdo de las tres partes de la Comisión tutelar de adultos, la parte jurídica entiende que la mejor solución pasa por demandar a los inquilinos por finalización de contrato. Esto supone que además de las costas procesales que hay que abonar por perder el juicio de arbitraje, y que a fecha de hoy no sabemos cuánto cobraran, lo suyo será que una vez sepamos la cantidad y la abonemos procedamos como digo a Demandar (contratando de nuevo los servicios del abogado) pero esta vez por finalización de contrato. Esto supondrá si se gana, que desalojen la vivienda, y posteriormente nos plantearíamos demandarles por el dinero que deban y por los daños que puedan haber dejado en la vivienda. Por tanto, voy a comunicarle al abogado que nos pase el importe de la ejecución por costas a pagar. Una vez lo cual, recabaremos la firma de la tutelada consintiendo que los demandemos por fin del contrato. Y con ello ya podrá interponer el abogado la demanda correspondiente. Llamo al abogado Jorge Calvo para comunicárselo. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-05-08','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Informar sobre el alta en la UHB de Cáceres de la persona usuaria Consuelo Nevado Pacheco en la mañana de hoy. Adjuntamos documento informativo de últimos ingresos y duración de la persona usuaria. Seguiremos informando de la evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2023-05-08','MIGUEL : por acuerdo de las tres partes de la Comisión tutelar de adultos, la parte jurídica entiende que la mejor solución pasa por demandar a los inquilinos por finalización de contrato. Esto supone que además de las costas procesales que hay que abonar por perder el juicio de arbitraje, y que a fecha de hoy no sabemos cuánto cobraran, lo suyo será que una vez sepamos la cantidad y la abonemos procedamos como digo a Demandar (contratando de nuevo los servicios del abogado) pero esta vez por finalización de contrato. Esto supondrá si se gana, que desalojen la vivienda, y posteriormente nos plantearíamos demandarles por el dinero que deban y por los daños que puedan haber dejado en la vivienda. Por tanto, voy a comunicarle al abogado que nos pase el importe de la ejecución por costas a pagar. Una vez lo cual, recabaremos la firma de la tutelada consintiendo que los demandemos por fin del contrato. Y con ello ya podrá interponer el abogado la demanda correspondiente. Llamo al abogado Jorge Calvo para comunicárselo. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-05-08','Ana: correo de ayer de Isabel Cano, al ctutelar@: "Hola una cosa estoy escribiendo con Ceferino Mariscal Crespo la tercera parte de Bill little y quería salir en el libro ya que lo estoy escribiendo con él y queremos sacar 100 ejemplares cuando lo acabemos por favor ángel díselo a punto rojo libro y hazme un presupuesto para 100 ejemplares para Ambos yo pago la mitad y Ceferino la otra mitad la obra ya está en marcha y antes de que acabe el año la tenemos un saludo buenas noches espero tu respuesta"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-05-09','TERESA Se recibe llamada de Rufi, policía local de Zalamea. Nos indica que Pablo Galan Gilgado está en su domicilio sin agua, sin dinero, sin comida, sin medicación y sin tabaco.. Como otras veces, se está generando una alarma social, porque desde los recursos de la localidad, están dispuestos a colaborar, pero están muy a la defensiva, "que está desamparado" "que asi no puede estar" etc... Se les explica como ha sido todo, y el proceder del centro y parece que lo entienden. Comida, tenia latas. Y medicación le dieron para varios dias, aqui hay un poco de lio, porque comenta que Pablo estos días ha recogido comida de la residencia de mayores gestionada a través del ayuntamiento (no sabemos quien pagará esto, les dijimos que en tiempos dejó de hacerse este sistema porque tiraba la comida, por esto se hizo el sistema de ir a comprar con el comida) La chica de la farmacia también le ha comprado comida porque Pablo (porque lo habra considerado asi...) Cuando y cuanta cantidad, se le va a poner para retirar? , para organizar el seguimiento y poder ir con el. El viernes, desde la farmacia nos indican que Pablo llega con medicación para los días del 6 al 11 de abril y le falta la toma de 1/2 rivotril al mediodía. Al ser día 5 cuando acude a la farmacia le indicamos que le adelanten todas las tomas por lo que solo habría medicación hasta el día 10. Hoy volvemos a hablar con la farmacia y expresan que están muy enfadados con la situación pues siempre han colaborado para gestionar el tratamiento de Pablo porque se ha trabajado en colaboración con el equipo de apoyo social comunitario y las medidas de apoyo han sido fijadas. En esta ocasión ha sido totalmente diferente, Pablo acude a la farmacia con tratamiento solo para unos días y sin rivotril. Además, el fin de semana no abren porque no les toca estar de guardia y no tienen instrucciones de cómo suministrar el tratamiento a Pablo. Con toda esta información llamamos a Julia de la Casa Misericordia (608077298) para saber sobre la medicación de Pablo. Efectivamente solo le dieron medicación preparada para una semana y el rivotril se olvidó de añadirlo. Por lo cual, tienen medicación y pertenencias de Pablo (sobre todo ropa) en el centro a espera de enviarlas donde se les indique. Sobretodo la medicación y las pertenencias, las tendran que enviar al domicilio no? parece que estan esperando a que desde la comisión se les diga algo. . En resumen,Pablo tiene el agua cortada en la vivienda, no tiene apenas latas comida ni tabaco, tampoco tiene dinero ni autorización para retirada del mismo y en cuanto a medicación tiene solo hasta el día 10 (excepto el rivotril). Asi que, esta semana pretendemos ir para alla, pero sobretodo para saber si se considera hacer una retirada a partir de que dia seria... Por otro lado, el médico lo tiene en Alcuéscar por lo que tendríamos que cambiarlo para Zalamea. No se le puede sacar medicación alli, por lo del rivotril, hasta que no tenga medico de nuevo, esto lo intentariamos gestionar tambien desde el equipo el dia que se vaya. De cara a la intervención con Pablo, ¿Sería posible autorizar retirada de dinero para gestionar comida y tabaco? Y es urgente arreglar el tema de la medicación, el centro debe enviar la medicación lo antes posible pues en la farmacia no pueden darle pastillas que consta en la tarjeta como retiradas y que están en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-05-09','Ana: Subo al portafirmas digital la SOLICITUD DE TAD MUNICIPAL y el CONSENTIMIENTO EXPRESO PARA LA CONSULTA DE DATOS. ···························································································································································································· Envío correo a Estrella Durán, TS del CSS-Plas: "Ya he cumplimentado y puesto para la firma la solicitud de TAD, pero necesito que asista al médico para que le cumplimente el Informe Médico que hay que adjuntar (está en el mismo documento que me adjuntaste). ¿podríais por favor, cuando acuda al centro, explicárselo y facilitarle el documento que tiene que llevar? Una vez os lo devuelva cumplimentado, me lo enviáis, por favor, para que podamos proceder a registrar la solicitud." ············································ Respuesta de Estrella: "Sí, el jueves viene para acá, la veo y se lo digo..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='CAPILLA'and apellido2='CAPITA'),'2023-05-09','TERESA Juan Carlos Capilla Capita se encuentra hospitalizado en el HDBV, la familia le acompaña durante el día, y esta ha solicitado acompañamiento por la noche, e igualmente, Ana Gallardo la responsable de área residencial y asistencial me ha informado que así lo hiciera, por tanto, durante esta semana se ha contratado a una persona que facturará a finales de semana mediante declaración jurada. El horario es de 22:00 a 07:00 horas. Por favor comunicame si existe algún inconveniente económico. Se desconoce la previsión de la hospitalización. Ayer no me dió tiempo a informarte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2023-05-09','Ana: Remito a Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es) la Solicitud de Empadronamiento para que la lleven al Ayuntamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-05-04','Ana: correo de Estrella Durán: "la última vez que hablé con Desi le volví a decir que solicitara la Teleasistencia del Ayuntamiento, le expliqué que tiene que pagar 27 euros/mes y que se lo puede permitir, ahora que tiene una pensión más alta. Me dijo que sí, así que puedes retomarlo cuando quieras."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2023-05-09','TERESA ayer a medio dia , al parecer hubo un incidente en casa de Maria, salia mucho humo de su vivienda y acudieron los bomberos y la policia, la novia de maria esta en llerena ingresada por intoxicacion por humo, Maria me ha dicho que esta bien... no se mas cosas. otra cosa, ya he mandado el informe al juzgado, en dicho informe pone que Maria esta tutelada por la comision tutelar, que tiene un trastono mental grave, sus ingresos y sus relaciones con la familia y el entorno. un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2023-05-09','TERESA ENVIO PENSIO DE JUBILZACION CON LOS DATOS DE SUIZA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-05-09','Ana: correo-e del día 4/05 de Mª Jesús Gutiérrez, Psiquiatra ESM - Plas. (mariajesus.gutierrez@salud-juntaex.es): "quería informarte que el paciente no ha venido a consulta en las ultimas ocasiones; sí comprobamos que se pone el inyectable; he hablado con Gloria de Futuex para comunicárselo. Le he comentado a Gloria la apertura del ETAC (equipo asertivo comunitario ) con la posibilidad de derivar a alfonso a este equipo) que consiste en desplazamiento del psiquiatra y otros profesionales al domicilio y trabajar con el desde alli, dada la mala vinculacion aquí. Ella me ha dicho que lo comentaria en la comision tuteltar, quería comentartelo también y tener vuestra aceptacion, aunque evidentemente dependera tambien de la colaboracion o no del paciente." ································································· Mi respuesta: "Gracias por comunicarnos la no asistencia de Alfonso a las citas. ¿Sería posible que nos enviaseis un “informe” (SOAP o lo que consideres) indicando las fechas exactas y la no asistencia a la consulta par poder remitírselo al Juzgado? Por otra parte, me parece perfecto la derivación de Alfonso al EQUIPO DE TRATAMIENTO ASERTIVO COMUNITARIO, ojalá y que él lo acepte, colabore y se consiga la vinculación con el mismo. Gloria probablemente se lo haya comunicado a su coordinadora, pues por protocolo de la empresa no le permiten dirigirse a nosotras directamente y su coordinadora aún no nos ha remitido nada al respecto, así que agradezco me ha hayas escrito a mí directamente. Ante cualquier otra cuestión, no dudes en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-05-04','Ana: Correo de Ángel, A. Jurídico CTAEx: "Ya tenemos la citación para Joaquina Mayoral Pizarro"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2023-05-04','Ana: Correo de Margarita Montero, TS Mancomunidad Integral Sierra de Montánchez (tsocial4@mancomunidadsierrademontanchez.es): "Deciros que con esa cuantía, que percibe MATEO RUANO MORENO es: 974,85 €/mes. el abono mensual de la residencia de MONTANCHEZ, sería 739,26€" ················· Paso la información a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-05-09','Ana: Se abona la factura de ropa. Previamente enviaron presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-02','Ana: Correo de Puerto, TS SSASB - Valdeobispo (ssb5@mancomunidadvalledelalagon.es): "a partir de hoy al domicilio de Enrique Santos, por petición de la auxiliar del SAD y valorado por el Ayuntamiento se procede a poner a dos auxiliares en el domicilio de Enrique puesto que "por circunstancias especiales" la auxiliar ya no se atreve a ir sola como nos indica en el parte de incidencias. Se mantendrá con dos horas semanales, martes y jueves, que prestarán dos auxiliares de forma simultánea, una para realización de tareas domésticas y otra a modo de apoyo educativo en habilidades para la promoción de autonomía personal. El precio seguirá siendo el mismo. Seguimos considerando oportuno un seguimiento muy de cerca por parte la CTAEX y del equipo de salud mental. Hoy está solicitando más dinero semanal... aludiendo a que tiene deudas..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-04-27','Ana: Correo de Toni-Futuex con Informe de la primera visita a domicilio por parte de Virginia, Ed. Programa de Apoyo Comunitario. En dicho informe se hace contar, entre otras cuestiones: "A simple vista se aprecia que es una persona bastante autónoma, no se observan problemas de movilidad ni sensoriales y tiene capacidad para moverse por la ciudad sin problemas. Su madre y su hermano confirman que es bastante autónomo, pero le cuesta cumplir las normas dentro del domicilio, lo que genera problemas de convivencia entre él y su madre." "Acude a Centro Ocupacional de Down Cáceres, allí conoció a Fátima su pareja con la mantiene una relación desde hace más de 20 años. En el centro pasa las mañanas en horario de 9-15h. y según relata partida en la actividad de jardinería y huerto. También está en un equipo de balonmano con el que participa en los JEDES. Por las tardes sale a pasera con su pareja por la ciudad y llega a casa a la hora de cenar, la relación con la familia de su pareja es adecuada según transmiten. En la infancia, hasta los 18 años estuvo en PROA y después en Novaforma." "El principal problema de convivencia es la falta de implicación en las tareas domésticas y la escasa motivación para el aseo, por lo que se hace necesario intervenir y llegar a un acuerdo con José Blas de aumentar la frecuencia de las duchas y colaborar más en las tareas domésticas." ············································· Para gastos de bolsillo se acuerdan 30€/semana y para aportar para manutención: 25€/semana. ····································································································································································································· Llamo a Juan Manuel, hermano de José Blas (687 819 309): confirma que finalmente José Blas ha rechazado la plaza residencial en Plena Inclusión 7, Mérida. ··········· Por otra parte le pregunto por las transferencias que han realizado en el mes de marzo de la cuenta de José Blas (inicialmente estaban su padre y él) a otra cuenta cuyo titular actual es su madre, por una cuantía total de 8.000 €. *Explica que ese era dinero familiar que su padre ingresaba en dicha cuenta, por eso la han transferido. ·············· José Blas no tenía ingresos propios hasta Septiembre de 2021, tras el fallecimiento de su padre que le solicitaron la P. Orfandad. ················· *Me cuenta también que han abonado la fianza para un viaje con Novaforma a Torremolinos. ·············· Para las retiradas de efectivo, le acompañará él al banco una vez al mes. Nos enviará sus datos mediante mail. El dinero para manutención se lo darán en efectivo a su madre. ······················· *Cuando envíe los datos lo comunicaré a Alberto, Jefe Secc. Ecca., para hacer la autorización bancaria. ···· Óscar, Secc. Ecca., hará mañana la ficha ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='DIAZ'and apellido2='ABADES'),'2023-05-09','miguel, llego citación para la intervención de la ctaex en procedimiento de revision de oficio a la que no asistimos ya que debían haber notificado desde el juzgado a abogacia general para que interviniesen procesalmente. Así se lo explico por teléfono al juzgado. No obstante, Inés se lo comunica a abogacía general y Antonio Alonso le indica que no pueden intervenir porque no tienen ni la demanda. Según nos informa Mª Angeles Galindo, se ha suspendido el procedimiento y tendrán que citar de nuevo a la Ctaex, y remitir la documentación del procedimiento a abogacía general para que pueda representar a la ctaex','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-05-09','miguel, llega recurso de apelación de Justa Diaz Borreguero ante el jzdo nº1 de Montijo: envío email a la parte social y a Angel: Buenos días, adjunto la interposición del recurso de apelación realizado por Justa Diaz Borreguero contra el internamiento involuntario. Nos dan 10 días para oponernos. Se basan en la falta de justificación médica psiquiátrica. Intentad haceros con informe psiquiátrico. Hay que hablarlo lo antes posible entre la parte social y la jurídica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-05-09','miguel, se firma la venta en notaria de Santos de Maimona de la finca 8978. Envío al día siguiente a notaria de Mérida (Jose Luis) la escritura, auto firme, y certificado de nacimiento para que me de dia y hora para ratificar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-05-10','Ana: Llamada de Minerva, TS del C.R. Cervantes (927 005 575 // 22237): Gloria, Ed. de Futuex, ha remitido el 26 de abril una propuesta de aumento de asignación. Aquí no la hemos recibido. ······························ Eugenia ya no quiere ingresar en la Res. San Francisco de Plasencia, sólo quiere ir a Hervás, donde está Pedro, su pareja. Minerva llamará a la Gerencia Territorial CC para hablar con Pedro, TS Secc. de Mayores., solicitará que eliminen la opción de Plas. ····························································································································································································· Envío correo a Toni-Futuex solicitando nos remita la propuesta de Gloria, Ed., de subida de asignación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAQUEL MARIA'and edp.apellido1='DELGADO'and apellido2='ESTEVEZ'),'2023-05-10','TERESA Buenos días, soy Mª José Herrera, facilitadora del Proyecto MI CASA Escribo para comunicar que Raquel Delgado ha cambiado de recurso, actualmente se encuentra en Villafranca de los Barros, en el proyecto MI CASA una vida en comunidad, está compartiendo vivienda con otros compañeros. Mandé un correo a Teresa Blanco y llamé varias veces para informar, pero no obtuve respuesta, por eso me pongo en contacto a este otro correo, ambos me los facilitó Rosa, directora de Centro Ocupacional de Fuente de Cantos. Me explicó Rosa cómo lo hacían para pedir dinero cuando Raquel realiza algunas compras, me podrían explicar bien para saber que pasos debemos seguir?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-05-10','Amalia : LLega resolución de traslado por dependencia a R. M. R. Ibarra de Villafranca. Hablo con la TS del centro y de CSS para coordinar el traslado. Se irá acompañado en el tte. del CSS , me indicarán el dia. Envío toda la documentación para el ingreso. Quedo pte. actualizar cuentía de la P. I. Pte y calcular dinero de bolsillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-05-10','Ana: Llamada de José Manuel, dice que ayer le atendió el Psiquiatra Enrique Goenaga y, a petición suya, acepta hacer la derivación a UME. ··································· En cuanto a la compra de ropa, Alberto, Jefe Secc. Ecca, aprobó 250 €. ··········· Toni-Futuex, acepta la propuesta de que se les haga transferencia y que Teresa le acompañe al Kiabi de BA. Pero sólo de forma excepcional, será la última vez que se haga así. ··· Para la siguiente tendrá que buscar una tienda de tallas grandes en CC. ······················· Paso a Óscar, secc. ecca. la información para hacer la transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-05-10','Ana: Envío a REGISTRO (oac.merida.san@juntaex.es): "En representación de D. Ventura Gómez García, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, os remito Oficio y Solicitud de Servicio de Comida a Domicilio Municipal, junto con toda la documentación relacionada a continuación e indicada tanto en la propia solicitud como en el oficio, para dar REGISTRO: - DNI de la persona interesada - DNI del Presidente de la Comisión Tutelar de Adultos - Testimonio de Aceptación del cargo - Decreto de Nombramiento del Director-Gerente del SEPAD - Resolución de delegación de competencias como Presidente de la CTAEX - Informe de Salud - Certificado de discapacidad del CADEX"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2023-05-10','Ana: Llamada de Nuria Carrasco, TS del EVD-Trujillo (54513): no obtengo respuesta. ·················· Le envío un correo (nuria.carrascos@salud-juntaex.es) solicitándole se ponga en contacto conmigo. ··································································································································· Hablo con Nuria Carrasco, TS EVD-Trujillo: Finalmente no enviaremos la Aceptación PIA para la prestación vinculada, pues visto los ahorros que tiene, no lo necesita. ··········· *Sólo enviaremos la ACEPTACIÓN PIA de SAR(Dio Grado III), está de los primeros en la lista de espera para el Centro de Santa Marta de Magasca, residencia en la que reside y de donde no conviene moverlo dado el grado de deterioro cognitivo que presenta. ······························································································································································································ Envío a Julio, Aux. Adtvo. CTAEx, la ACEPTACIÓN PIA de SAR, para que la registre en SIREX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-05-10','Ana: En relación a la petición que realizan desde NACE, de extra para la feria de CC, envío correo a Alberto y Estrella, Secc. Ecca.: "Pesto que el año pasado se les concedió 60, y todo ha encarecido mucho, se consensua desde la sección social que este año se apruebe un extra de 100€ para la feria."','2');
