insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-05-10','Amalia : desde el CSS informan que Si todo va bien, ingresará el día 24/05/23.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2023-05-10','TERESA David Vita nos solicita pagar esta multa de su padre por importe de 1400€. He hablado con David y con su hermano ya que David manifiesta querer pagar la multa con su dinero. Tras hablar con la trabajadora social del centro donde reside David y con la trabajadora social de la localidad donde reside el padre, ambas nos manifiestan que lo mejor que le puede pasar a esta familia es que el padre entre prisión. Hay antecedentes de malos tratos aunque no se han denunciado nunca, el padre David anda embriagado por el pueblo hasta tal punto de que se queda dormido en los bares o se cae y se queda en el suelo hasta que alguien lo recoge. Ya en otras ocasiones nos han solicitado dinero para hacer frente a las numerosas deudas que el padre de David va contrayendo, además se le dan 70€ mensuales para aportar a los gastos de la casa ya que David pasa algunos días en el domicilio familiar y otros en el centro. En base a todo esto y a que David tiene poco dinero ahorrado y solo percibe una PNC la sección social decide no pagar esta multa y que el padre asuma las consecuencias de su comportamiento. Sección Jurídica: indica que podemos tomar la decisión en base la situación economía de David Sección económica: entiendo que estarás de acuerdo en esta decisión atendiendo a los ingresos y gastos que tiene David actualmente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2023-05-10','TERESA ACORDAMOS REUNION CON MERCERDES DE PLENA INCLUSION Y DAVID PARA COMUNICAR LA DECICION DE NO DARLE EL DINERO QUE SOLICITIA PARA PAGAR LA MULTA YA QUE NO PUEDE ASUMIR ESE GASTO TELFNO DAVID:685411765','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-05-10','Ana: Conversación con Sergio Romero, Coordinador Proy. Mi Casa Don Benito (633 632 061): informa de que Felisa se "está adaptando fenomenal". Está muy activa, va a diario a Zumba y ha perdido 6 kg en poco más de un mes. *Desde que está en el recurso sólo ha protagonizado dos incidentes, un intento de agresión a la cuidadora, quién consiguió salir corriendo y zafarse de ella y otra agresión a la misma monitora tirándole del pelo. ·········· Intentan atajarlo mediante "consecuencias" como privarle de chuches, que le encantan y advirtiendo que cuando realice una conducta inadecuada le prohibirán utilizar los cascos al día siguiente. Artículo que le encanta y supone un gran aliciente para ella y que además le relaja mucho. ··································································································································································································· Envío correo a Teresa, TS CTAEx y Sergio, Proy. Mi Casa: "En relación a FELISA BRUNO SAAVEDRA, dada su buena evolución y adaptación al nuevo recurso, y a que lleva ya residiendo en el mismo más de un mes, procedo a hacer la derivación para seguimiento a Teresa, Trabajadora Social de referencia de Don Benito."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-05-10','Ana: Envío correo-e a Mª del Sol Tafur, ESM y E.C.A.- Trujillo (mariasoledad.tafur@salud-juntaex.es) y a Montaña, TS del SSASB de la Cumbre (ssasbmancomunidadtrujillo@gmail.com): "Os escribo para comunicaros que finalmente nos han dado nueva cita para valoración en el CADEX de MARIA GUADALUPE GIL CABELLO, citada el día 22/05/23 a las 11:30. Con PNC aún no he podido hablar, a ver si lo consigo antes de marcharme. De momento, como sabéis ha seguido percibiendo la PNC. Montaña, ¿sería posible que el ayuntamiento se hiciera cargo del traslado y acompañamiento a la cita del CADEX? Yo voy a proceder a hacer la derivación al Programa de Apoyo Comunitario, gestionado por Futuex, mediante convenio firmado con la Junta. En inicio no quise hacer derivación para no levantar sus suspicacias, no sé con quién de vosotras lo hablé al principio, que se mostraba muy desconfiada, pero mientras se resuelve el ingreso en algún recurso, creo que pueden hacer un buen trabajo con ella y será más el beneficio que el perjuicio (o eso espero) Por otra parte, voy a pedir también a la sección económica que bloqueen su cuenta bancaria, para que no saque todo nada más cobrarlo. Montaña, ¿sabrías decirme en qué sucursal suele retirar ella el efectivo y qué cuantía crees que es adecuado autorizarle que saque cada semana y si esto es viable? Por último, quedo pendiente de confirmación de la Subcomisión pues tendremos que hacer las gestiones oportunas/solicitudes para el viaje." ································································································································································································ Respuestas de Montaña, TS: "Ana no te preocupes que se hace cargo el ayuntamiento, me hubiera gustado ir con ella pero al ser Lunes no puedo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-05-09','Ana: Llamada de Domingo Salas, Director del CADEX -CC (927 00 55 09): nos enviarán el documento de citación para el día 22/05 a las 11:30 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-05-11','Ana: Llamo a Isabel, Directora de la Residencia Municipal (924 57 15 35 // ) ····················· Ana: Remito a Mª José Acosta, TS de la Mancomunidad Sierra de San Pedro (mjacosta@mancomunidadsierrasanpedro.com / 626134446 / 691596071):','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-05-11','He hablado con Soraya sobre Alejandro. Me dice que aunque no aparezca en el diagnóstico trastorno mental grave, el hecho de que las conductas que presenta sean persistentes en el tiempo y que las tenga desde hace mucho se considera trastorno mental. Ella la semana pasada habló con Estrella de la UHDAC y quedaron en que lo iban a proponer para CRR. He hablado esta mañana con Estrella y van a hacer ellos la derivación. Nos irán informando por si necesitan algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-05-12','Ana: Correo de Paula, TO: "Isa lleva una semana un poco complicada, tuvo que ir al juzgado el viernes, una situación de especial complejidad para ella a la hora de afrontarlo, además quería ir a Trujillo unos días, que había planificado conmigo y que yo había comentado con Ana matamoros, siendo aceptada la propuesta, pero su madre, con intención de cuidado, le propuso otra opción y se descuadró cuando insistimos en la necesidad de que pudiera atenerse al compromiso. También verbalizó que se iba a encontrar con una antigua compañera de CRR con la que tuvo problemas muy importantes y sentía temor porque lo que pudiera ocurrir en ese encuentro. El resultado es que, a pesar de pedir ayuda y que se la damos y acompañamos y retiramos los objetos que va diciendo que pueden ser "potencialmente ingeridos" por ella, finalmente hace una ingesta de colonia y otro producto. Se avisa a 112 y se la atiende en hospital, regresando a las pocas horas al CRR tras comprobar que está en buen estado y que no es necesaria la hospitalización. Vuelve realizando crítica de su acción, puesto que, como ocurre en muchas ocasiones, utiliza acciones de este tipo como medio de manejar el estrés. En ningún momento a nosotras nos habla de que tenga ninguna relación con Ceferino o con la escritura del libro. Es posible, que la suma acumulada de todas las situaciones que te hemos comentado haya conducido a que realice esta acción. Por otro lado, comentaros que Isa acude a urgencias o al médico con una frecuencia muy elevada, semanal y hay temporadas que varias veces en semana. Esto, como se comentó en la subcomisión de casos es una situación que, sin querer normalizarla, hemos tenido que aprender a "aceptarla" para que Isa pueda continuar en nuestro recurso. Puesto que desde sociosanitario nos comentaban que la dinámica era similar y en ocasiones aún mayor, pero con el problema de que allí no podía tener oportunidades para una vida más "normalizada". Estamos en proceso de escanear los últimos informes para poder enviároslos. Por otro lado, hemos considerado positivo sostener las fechas previstas de la próxima semana para su salida a Trujillo, que ya había consultado con Ana (del 15 al 17)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-05-12','Ayer en reunión de UHDAC, se trató la cuestión de que recurso residencial sería más conveniente para Alejandro, concluyéndose que no tiene diagnóstico de Trastorno Mental Grave con lo que no sería aceptado para C.R.R. y probablemente, se adaptaría mejor a un Piso Tutelado o Centro de Discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-05-15','Ana: correo de Paula, TO - CRR, de la semana pasada: "os escribo en relación a Ceferino Mariscal. Como os conté en anteriores ocasiones estamos planificando que pueda irse 4 días a Isla Antilla de vacaciones. Las fechas propuestas serían del 29 de Mayo al 2 de Junio. Se abonaría con el dinero de los extras anuales, y se está llevando a cabo una planificación acerca de cuestiones relacionadas tanto con el viaje en sí como con su autocuidado durante el mismo. Necesitaríamos que confirmarais vuestro acuerdo respecto al viaje cuanto antes (para que no le suban el precio de la oferta que le han realizado)." ················································································· Mi respuesta: "Tal y como se acordó en la reunión, ese tipo de gasto se incluye en sus extras anuales. Si en el equipo técnico del CRR consideráis que esta actividad es positiva para él, tanto a nivel personal como por momento de proceso terapéutico en que se encuentra, y como dices, estáis abordando con él la programación del viaje así como su autocuidado durante el mismo, no tenemos ningún inconveniente en que así se realice."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-05-12','Ana: Correo de Toni-Futuex: "Ayer se puso en contacto Ana Benavente para informar que Javier Agudo iba a ser ingresado. Se estuvo gestionando el que acudiera a otro hotel mas rentable, durante unos dias, pero no ha hecho falta. Imagino que desde salud mental te habran comunicado el ingreso, no sabemos nada mas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-05-15','miguel, envío email a José Lavado y a Angel, para modifique el escrito de solicitud de subsanación del auto en su día dictado (teniendo en cuenta que hace una semana que envié email al abogado que hasta ahora representaba a la tutelada (donde le di un plazo de 48h para contestar): Buenos días José, entendemos que tenéis que rectificar vuestro escrito y remitírnoslo de nuevo donde conste: 1.- La representación de la Comisión Tutelar de Adultos: El inicio del escrito se hace mención de que Pedro Miranda actúa en representación del SEPAD, lo cual no es cierto si no que lo hace en nombre de la tutelada Doña Isabel Moreno Follarat. Habría que rectificar por tanto en los siguientes términos: “Pedro Miranda actúa en representación de la tutelada Doña Isabel Moreno Follarat, y a su vez ésta está representada por la Comisión Tutelar de Adultos de la Junta de Extremadura, conforme poder apud acta (10-10-2019, otorgado por la letrada de justicia Mª de los Angeles Muñoz Hurtado del Servicio Común General de los Juzgados de Mérida)concedido por el representante de dicha Comisión Tutelar de Adultos D. José Vicente Granado Granado, Director Gerente del SEPAD y Vicepresidente de la Comisión Tutelar de Adultos de Extremadura, al amparo de lo establecido en el artículo 9.2 del Decreto 52/1996, de 9 de abril, por el que se crea la mencionada Comisión, y en virtud del nombramiento mediante Decreto 102/2019 de 2 de Agosto-DOE nº 151, de 6 de Agosto de 2019, donde la Comisión que representa ostenta el cargo de Tutor legal de Dña. MARIA ISABEL MORENO FOLLARAT, por Auto de 4 de septiembre de 2001 dictado por ese Juzgado en el Procedimiento de Incapacitación 56/2001, se nombra Tutor de Dña. MARIA ISABEL MORENO FOLLARAT a la COMISION TUTELAR DE ADULTOS DE EXTREMADURA, la cual pertenece al SEPAD, cuyo cargo que fue aceptado con fecha 12 de julio de 2001” Se encuentra defectuoso dicha autorización de venta, entre otros por que no se tendría que haber autorizado la venta al SEPAD, en vez de a la Comisión Tutelar de Adultos, que es la que fue nombrada como tutor de Doña Isabel Moreno Follarat. Por otra parte necesitamos nos confirmes por email que las actuaciones a realizar por tu despacho no conllevará gasto o coste alguno para la tutelada. Si necesitas algo indícanoslo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2023-05-15','-Amalia , le conceden plaza en ADISER , en Castuera. He hablado con su madre , me dice que ahora no es el momento Que cuando lo solicitó se encontraba mal pero que actualmente tiene una pandilla de personas con discapacidad con las que sale todas las tardes y hacen muchas actividades. Que en casa también está tranquila y que como ya le solucionamos el tema de la pensión , está muy contenta. Le he dicho que me mande por email algún documento firmado por Macarena en el cual indique las causas por las que la rechaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='CRESPO'and apellido2='CRUZ'),'2023-05-15','miguel, envío email a parte social (Ana y Maite) y economica (Alberto y Oscar): Ha llamado la trabajadora social del Centro Socio Sanitario de Plasencia (Victoria Clemente Matias 24142) porque ha fallecido la tutelada Victoria Crespo Cruz el día 13-5-2023. Me comenta que normalmente lo llevaba otra trabajadora social (Emilia Almodovar que estos días no está) Parece ser que el gasto de sepelio se le cargará en su cuenta, llevándosela la funeraria. La pregunta de ella era qué hacer con el ajuar (incluida joyas) ya que han ido unos sobrinos que querían quedarse con los bienes que tenía en el centro. La he indicado que los sobrinos tienen que esperar a que tengamos la rendición final de cuentas para ver quién es el heredero o sino que decida el juez con la rendición final de cuentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='CRESPO'and apellido2='CRUZ'),'2023-05-15','EXITUS El centro informa de su fallecimiento, acaecido el 13/05/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2023-05-15','-Oscar escribe a Marga ,TS del Ctro. Penitenciario. Le vamos a hacer una transferencia puntual a su cuenta peculio por el importe de la factura (15,95€). En cuanto a las transferencias de marzo y abril, te mando los justificantes de las misma. Por lo que respecta al escrito que mandó solicitando información de su procedimiento de curatela y de la orden de alejamiento de su padre, se le ha contestado por escrito y llegará en los próximos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-05-15','-Amalia : Resultados de la visita de Futuex , estudio económico . Desde el programa de apoyo social comunitario se ha llevado a cabo en el seguimiento presencial del día 8 de mayo y para informar de los nuevos cambios en relación a la situación laboral de Antonia. El pasado 5 de mayo (viernes) la empresa le comunica que es el último día de trabajo, ya que existen desavenencias entre la empresa que contrata a Antonia (Smart Topservices) y el grupo Abeto empresa del sector de limpieza encargada del servicio de limpieza de los centros educativos. Provocando esta situación el despido de las 11 personas contratadas a través de Smart Topservices. Según se comprueba en la vida laboral la fecha de baja es el próximo 12 de mayo ya que actualmente le deben retribuir los días de vacaciones. Área económica: Ingresos: 411,92 euros. Tramitada la documentación por la trabajadora social del Centro Social de Suerte Saavedra para cobrarla integra (484,61 euros). Cobraba menos, pq estaba empadronada en casa de la madre que cobrara alguien mas PNC Gastos: - Alquiler domicilio: 475 euros mensuales. Durante el seguimiento vamos a varias inmobiliarias para buscar una vivienda más económica, la oferta es nula de viviendas en alquiler y nos indican que las que le llegan suelen ser precios más elevados. Desde servicios sociales le han solicitado la ayuda al alquiler con un único pago anual de 525 euros. Se ha solicitado en abril y tardan en contestar un par de meses. También ha echado la solicitud para el alquiler de viviendas sociales, pero desde servicios sociales indican que todavía no hay disponibilidad de estos inmuebles. - Seguro decesos: 50 euros anuales (Mapfre) - Comida: la hermana le da 15 euros semanales. Hablamos con el comedor social de Martín Cansado, nos indican que si existe necesidad puede ir a comer allí diariamente y que la entrega de alimentos en crudo es dos días al mes. Preparamos la documentación (contrato alquiler, fotocopia DNI, empadronamiento y justificante pensión) para que Antonia pueda recibir estos alimentos y disminuya algunos gastos mensuales. Ya ese martes le entregaron una bolsa de alimentos en crudo. - Gastos de bolsillo: 15 euros semanales. - Deuda: 220 euros (deuda seguridad social cobro indebido pensión). - Luz, agua y gas; pasan los recibos por la cuenta bancaria. Nos dice la trabajadora social que aún no puede solicitar los mínimos vitales ya que piden ingresos de los tres meses anteriores y con las nóminas se pasa del mínimo establecido para poder solicitarlos. - Móvil: 15 euros mensuales (contrato domiciliado cuenta bancaria) Ana Isabel (hermana) tiene domiciliado el pago de su vehículo en la cuenta de Antonia, nos indica que se está informando para poder cambiar el nombre de titularidad, que nos facilitará la documentación cuando la tenga preparada. Aunque refiere que el préstamo no puede ser cambiado. Área laboral: Durante el seguimiento vamos a las empresas de YMCA y SIFU para la incorporación a sus bolsas de empleo. Ya que son empresas que ayudan a la incorporación laboral de personas con discapacidad. ---------------------------- Me pongo en contacto con Vvda.para buscar ayudas al alquiler, no consigo que me atiendan telefónicamente. Busqueda en internet de pisos más económicos, he encontrado un apartamento por la zona en la que vive Antonia .Se lo paso a Futuex para que la informen. Averiguo con S. eco si ya puede hacer retiradas en el banco sola.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-05-15','miguel, envío email a parte económica, Oscar y parte social Maite y Amalia: Buenos días, Oscar necesito saber lo que cobra la tutelada y los gastos mensuales ordinarios y extraordinarios tiene, para unas alegaciones que tengo que presentar en un par de días. Maite y Amalia, necesito me aportéis el último informe del ESM y un informe vuestro de los contra (al internamiento involuntario) en caso de que denieguen el internamiento involuntario o bien que incluyais vuestra posición en la contestación o alegaciones en Word que os adjunto, y necesito que como muy tarde el miércoles 17-5-23 me lo mandéis o modifiquéis e incluyais la posición social (porque nos han dado 10 días para alegaciones), y hay que ponerlo a la firma del gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-15','Ana: Correo de Maite, Jefa Secc. CTAEx, a Mª Carmen Rguez., TS UHB: "Hola de nuevo Mª del Carmen, Acabo de hablar con la Audiencia Provincial de Cáceres. Han comunicado a la Policia Nacional el juicio de Saturnino para que vayan a buscarlo ese día y lo lleven custodiado ( por lo visto es así el protocolo). Os han enviado un escrito a vosotros via Lexnet, va dirigido a complejo hospitalario. Vamos hablando por si hay alguna novedad al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-05-15','Amalia , escribo a Miguel y envío la documentación solicitada. Miguel adjunto informe social de la TS del SSASB de Montijo sobre Justa , con una fecha muy reciente de 12/4/23 donde se refleja la emergencia social de Justa . También te envío el informe médico que he podido conseguir después de más de 3 citas que se le han dado a Justa y a las que no acudía, de su médico de cabecera con toda su patología médica . Estos informes los he pedido para poder solicitar la plaza pública en R. Mayores. En tu escrito de alegaciones no hay nada más que podamos aportar, está perfectamente argumentado. Nos reiteramos en la necesidad de una plaza residencial o de cualquier tipo de recurso habitacional para Justa por motivos: -médicos , por su extensa patología sobre todo mental necesita supervisión y ayuda para poder vivir sola . -económicos : está desahuciada de su vivienda de la que la van a echar y no tiene capacidad económica para pagar gastos de alquiler y suministros. Se ha pagado ayer una factura de luz que debía desde hace meses. La solicitud de vivienda social no garantiza la disponibilidad de ese recurso , existe lista de espera , tiempo del que ella no dispone porque el desahucio es inminente . Se pidió a uno de los hijos que plantearan otras alternativas o algún tipo de ayuda económica para poder valorar otro recurso y no se obtuvo respuesta. -sociales , sin red social ni familiar de apoyo. Ahora que sea el juez el que decida dónde va a poder estar Justa una vez que la echen de su vivienda. Nosotros hemos comunicado la necesidad de esta señora , y hemos propuesto el recurso con el que podemos contar para que no se vea en la calle . Si bien es cierto , que Justa no quiere ingresar en centro , tampoco plantea otras opciones. Ni ella , ni su familia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-05-15','Ana: Correo del Comedor Social de Cáceres - Obra Social La Milagrosa (oslamilagrosacaceres@gmail.com): "Buenos día, por favor, necesito que te pongas en contacto conmigo para hablar de Miguel Ángel Ramos Andrés. Viene al Comedor Social de Cáceres y nos hace consultas que no podemos resolver." ·········· Solicito que me faciliten nombre y teléfono de contacto para poder llamarles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2023-05-16','TERESA ENVIO SOLICITUD DE CAMBIO DE CUENTA PENSION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2023-05-16','Ana: Correo de Pilar Cerrillo (calidad@grupociudadjardin.com) con Diligencia del Juzgado nº3 de CC: "Estando señalado para el día 22 de mayo de 2023, a las 11:30 horas, la celebración de comparecencia en el procedimiento" ······················ Se lo reenvío a los A. Jurídicos CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-05-08','miguel, Jorge me indica que el reconocimiento o parte declarativa del procedimiento estimando el desahucio ya está. Por tanto lo que han estimado en el juzgado a la parte demandada es la ejecución del procedimiento. Por tanto quedan dos posibles recursos antes del 25: 1.-Recurrir la ejecución en sí pues él entiende que aunque el arbitro envió carta certificada del auto declarativo al demandado y éste alega indefensión por no poderse demostrar el contenido de esa carta certificada. Él entiende que el tribunal aceptó y dió continuidad al proced de ejecución por lo que se entiende correcta la notificación 2.-Reclamar las costas procesales Tras hablar con la parte económica Alberto, quedamos que antes de decidir los siguientes pasos a seguir, que nos acredite el coste de cada opción, alguno de esos dos recurso o iniciar de nuevo el procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-05-16','miguel, recibimos en ctutelar email del abogado jorge calvo: Buenos días. El Plazo se termina el día 25. Por lo que dicho día debe estar presentado lo que vayamos a presentar. Dicho esto. El jueves sería posible vernos? O tendría que ser otro día por vídeo llamada. Para vernos personalmente debería estar a primera hora en Merida porque a media mañana tengo que irme a don Benito. Quedo pendiente de que me digas gracias *********************************************************** mi contestación que también envío a parte social y económica: Buenos días, quedamos pendiente que me indicarías aproximadamente el coste de cada una de las opciones que tenemos: 1.-Recurrir el procedimiento de ejecución de la resolución declarativa estimando el desahucio 2.-Las costas y gastos del procedimiento 3.-Iniciar un procedimiento nuevo. Mi compañero de la parte económica no volverá al menos hasta el martes 23 y la decisión ha de tomarla la parte económica, social y jurídica por lo que si te parece bien envíame importe aproximado de cada opción y pros y contras de cada una. El mismo 23 te daremos una contestación, previo nos envíes esta información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2023-05-16','Amalia : escribo a CRR de Mérida efectivamente tiene un cobro indebido con PNC , solicitó por su cuenta P. de Orfandad y al comunicarlo a PNC al ser incompatibles , le reclaman las cantidades indebidamente adeudas. Por el momento creo que con esa pensión cubre sus gastos personales . No hay copago en la plaza que ocupa y veo contraproducente solicitarle otra pensión más. En el momento que necesite más ingresos me lo indicáis y lo valoramos. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2023-05-16','Amalia : escribo a CRR de Mérida efectivamente tiene un cobro indebido con PNC , solicitó por su cuenta P. de Orfandad y al comunicarlo a PNC al ser incompatibles , le reclaman las cantidades indebidamente adeudas. Por el momento creo que con esa pensión cubre sus gastos personales . No hay copago en la plaza que ocupa y veo contraproducente solicitarle otra pensión más. En el momento que necesite más ingresos me lo indicáis y lo valoramos. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-05-16','Os comunicamos que Antonia Perez Perez tutelada por la Comisión Tutelar de Adultos de Extremadura y usuaria del servicio de centro ocupacional, falta muy a menudo al centro, como se puede comprobar en los listados de asistencia que os enviamos. Está comunicado a Comisión Tutelar, como sus tutores legales, y dada la situación de personal y familiar de Antonia, y su entorno directo, consideramos, Comisión Tutelar y Aprosuba 3 P. I. Badajoz que es aconsejable mantener la plaza para que así, se pueda acompañar a Antonia, en los días que asiste al centro. Agradecemos que confirmen la recepción de este correo. Saludos. Catarina Mª Ferreira Barbedo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-05-16','Ana: Tras hablar con Carlos (665 022 593), envío correo a Alberto e Icíar: "He estado hablado con Carlos, en principio él considera que necesitaría entre 45 – 50 € a la semana, es más de lo que tú planteas Alberto. Yo voy a solicitar el Catering Municipal, que ha vuelto a salir la convocatoria y es gratuito, con lo que nos daría un gran margen de protección y tranquilidad. Pide retirar la asignación 2 veces a la semana (Lunes y Viernes), no sé si es posible, pues así se administraría mejor. Alberto, porfa, confírmame en cuanto puedas la cuantía máxima semanal y los días de retirada. Está pendiente y necesita dinero. Si fuera posible la primera retirada sería le próximo viernes 19." ····························································································································································································· Desde la Secc. Ecca. confirman que finalmente se le hará una transferencia semanal de 50€/semana. ···· Icíar se lo ha confirmado ya.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-05-16','Ana: Tras hablar con Carlos (665 022 593), envío correo a Óscar e Icíar, secc. ecca., con copia a Alberto, Jefe Secc.: "He estado hablado con Carlos, en principio él considera que necesitaría 50 € a la semana, es menos de lo que planteaba Alberto. Yo voy a solicitar el Catering Municipal del IMAS – Cáceres, que ha vuelto a salir la convocatoria y es gratuito, con lo que nos daría un gran margen de protección y tranquilidad, por lo menos en este aspecto. Pide retirar la asignación 2 veces a la semana (Lunes y Viernes), no sé si es posible, pues así se administraría mejor. Serían 25€ lunes y 25€ los viernes. Óscar, como Alberto no está, porfa, confírmame en cuanto si es posible esta cuantía semanal y los días de retirada. Está pendiente y necesita dinero. Si fuera posible la primera retirada sería el próximo viernes 19. Pongo en copia a Alberto, para que pueda leerlo a su vuelta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2023-05-16','Ana: Envío correo a Paz Boticario, TS Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org): "Adjunto remito la autorizaciones de anuales de actividades organizadas desde el hogar Virgen de la Montaña firmadas por el Presidente de la Comisión Tutelar de Adultos, para este 2023"','2');
