insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2023-05-16','-Amalia : LLamada desde Ctro. penitenciario de Alicante 965102222. Ha sido trasladado desde el Ctro. Penitenciario de Sevilla. Me va a enviar email con el nuevo nº de cuenta peculio. Dar de baja al de Sevilla. Se le ingresan 240€ . Solicita sentencia de incapacitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-05-16','-Estrella: Buenos Días, éste trámite ya lo preparé con Ocaso en el pasado mes de marzo. He comprobado su cuenta y ya a primeros de abril le cargaron 42,51 € de ocaso y hoy le han vuelto a cargar el ocaso, no entiendo la preocupación de la familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2023-05-16','José Castelló Asensi Trabajador Social Hospital Psiquiátrico Penitenciario de Alicante Cra. Alicante-Madrid S/N 03113-ALICANTE Tlf. 965.10.07.38 y 965-10.22.22 extensión: 420093. Fax. 965.10.17.61 jjesus.castello@dgip.mir.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-05-16','Ana: Conversación con Aitor: aún no ha recogido la tarjeta monedero de Unicaja en la oficina de Trujillo. Le recuerdo que se le ingresarán 20€ para sus gastos de bolsillo. Intentará ir con un amigo. ·········· Dice también que lleva 2-3 semanas sin beber alcohol y está dejando el cannabis. ·········· *Le recuerdo que el límite de gasto en el supermercado es de 100€, y en la última compra lo han pasado. A partir de ahora, si se pasan deberá abonarlo Felisi, su madre, con su asignación. Desde su cuenta se abonará un máximo de 100€, que es lo que está autorizado por el Jefe de Secc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-05-16','Ana: Envío correo a Julio y compis secc. ecca: "En relación a ARTURO ROCHA MERCHÁN, comunicaros que mañana se producirá su traslado e ingreso en la nueva residencia Municipal de los Santos de Maimona. Julio, porfa, modifícalo en la Base de Datos: Residencia de Mayores Alcalde Antonio Zapata, Teléfono: 924 57 15 35 // rmayores@lossantosdemaimona.org Compis Eco: - cuando ingrese habrá que ver qué sucursal hay en el pueblo, si es de la misma entidad para que pueda retirar asignación o ver cómo podemos hacerlo - el traslado se hará en taxi, el taxista se llama Jose Antonio (606 26 69 40). Enviará la factura con número de cuenta al ctutelar@, cobrará 260 € (Son algo más de 400 km)" ····························································································································································································································································· Envío correo a la Residncia El Pendere, la directora de la Res. Alcalde Aº Zapata, la TS de la mancomunidad y la sobrina: "En relación a Arturo Rocha Merchán, y su traslado el día de mañana para ingreso en la Residencia Municipal de Los Santos de Maimona, comunicaros que ya está gestionado el traslado con un taxista de confianza cuyo contacto me han facilitado desde la Residencia Alcalde Aº Zapata. El taxista se llama José Antonio (606 266 940). Se le abonará el traslado mediante transferencia. Le recogerá en torno a las 10:00 en la Res. de Santiago de Alcántara para llegar entorno a las 12:00 h a las residencia de los Santos de Maimona. El señor está sensibilizado con las personas mayores y confiamos en que todo irá bien y será un buen acompañante además de taxista. Esta mañana a primera hora hablé con Mª José y me dijo que en la residencia actual tienen ya todo preparado para su traslado e ingreso. Ante cualquier cuestión, ya sabéis cómo contactar." ································································································································································································· Envío nuevo correo a Isabel, directora Res. Alcalde Aº Zapata y a Mª José, TS SSASB Mancomunidad: "En cuanto a los documentos que constan el vuestro escrito, Isabel, deciros que, entiendo, que Arturo mañana llevará en mano: - DNI - Tarjeta Sanitaria - Tratamiento actual - Últimos informes médicos que tengan en la Residencia Actual En cuanto al certificado de pensión, acabo de entrar en su expediente y veo que no disponemos del actualizado de este año, no sé por qué no nos lo habrán enviado la actual, el del año pasado sí lo tenemos. Voy a solicitarlo al INSS y en cuanto lo tenga te lo hago llegar. El tipo de pensión y cuantía sí te lo puedo decir: ORFANDA ABSOLUTA: 832,80 € El IBAN de su cuenta bancaria es: ES33 2085 4592 1503 3033 5326 En cuanto a las vacunas del COVID, tenemos las autorizaciones que se remitieron para que se le administrara las vacunas, pero no la cartilla de vacunación como tal. María José, no sé si disponen de ella en la residencia y en tal caso se la podéis facilitar. Por último, adjunto la póliza del seguro de decesos. Por lo demás, Mª José me ha dicho que lo tienen todo preparado para el traslado de mañana. No obstante, ante cualquier otra cuestión, estamos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-05-16','Maite: Joaquina tiene mañána cita con el médico forense. Pedimos que la visitara a domiclio pero el juzgado dice que se haga por videoconferencia. El lunes 22 de mayo tiene vista en el juzgado de Trujillo a las 10:30. La trabajadora social de Miajadas nos ha dicho que la llevarán en taxi. Le hemos enviado mail a FUtuex para que la acompañen. Buenos días Toni, En relación a Joaquina Mayoral Pizarro, necesitamos que el próximo lunes día 22 la acompañéis a la vista que tiene en el juzgado de Trujillo a las 10:30. Desde el Ayuntamiento de Miajadas le han gestionado un taxi para llevarla. Podéis esperarla en la puerta del juzgado porque como sabéis tiene dificultades de movilidad. Por otra parte, sabemos que es muy precipitado, pero nos acaban de confirmar que mañana a las 10:30 tiene el reconocimiento del médico forense en relación al procedimiento de internamiento involuntario, en su domicilio mediante videollamada. ¿ Sería posible que estuvierais con ella?. Os facilitamos el teléfono de nuestro compañero Miguel ( jurídico) quien también estará presente desde aquí: 924 00 38 09. Por favor confirmadnos la asistencia. Gracias ·································································································································································································· Respuesta de Toni-Futuex: "Vamos para allá mañana, y como sabemos que tiene buena relación con una profesional de ssb y una auxiliar de SAD nos pondremos en contacto por si no la localizamos en casa o se mostrara esquiva como otras veces y nos da tambien para planificar el seguimiento del lunes en Trujillo. Si hay problemas contactamos con Miguel. Y os vamos informando de todo. Aprovecho y os comento, lo que más o menos sabemos de ella (que no es demasiado porque visitas realmente efectivas solo ha permitido una) -JOAQUINA MAYORAL PIZARRO: •Dirección: C/ Donoso Cortés, 12-1º Drcha., Miajadas •Teléfono: 669736411 Con Joaquina se empezó a trabajar en noviembre de 2022, pero no se consigue intervención en persona hasta enero de 2023, ha sido la única intervención que se ha llevado a cabo. Presenta delirio en forma activa. Habla constante habla de una tía que la quiere encerrar, que la quieren coger de los pelos… Pero se puede mantener una conversación y seguir un hilo, más o menos, coherente. En todo momento esquiva hablar de la toma de medicación y sobre consultas médicas sólo comenta la rehabilitación y las curas por la caída, debido a la cual tiene una úlcera bastante grande en el tobillo izquierdo.No sabemos por lo tanto, si está en tratamiento o seguimiento por salud mental, con independencia de estas gestiones, era uno de los objetivos a conseguir en este seguimiento. Joaquina comenta que la auxiliar de S.A.D. va a diario y le apoya en las citas médicas y demás. No tenemos el contacto, pero a traves de ssb lo intentaremos conseguir. La casa se encuentra en buen estado y exceptuando que hay polvo, está recogida, cuidada y limpia. La comida se la lleva un catering, se la reparten sobre las 4-4:30 de la tarde, según comenta, por lo que lo que come es lo del día anterior siempre. Tiene de referencia a Anabel , trabajadora del servicio social de base, (intentaremos contactar con ella para estas gestiones o posibles futuros seguimientos, ya que por lo que comenta sigue bastante las pautas que le marca esta profesiona). De su vida de casada no cuenta mucho, menciona más a su actual pareja, al parecer un hombre que conoció en CRR de Mérida, Ángel Pinilla Badajoz, según cuenta, con el que tiene encuentros de vez en cuando. Mantiene contacto con su hija María, pero sólo cuando ésta la llama, la tutelada no puede llamarla, le tiene restringidas las llamadas entrantes suyas. No se consigue hablar sobre su enfermedad y el seguimiento en salud mental, esquiva la conversación, no tiene conciencia de enfermedad y mucho menos adherencia al tratamiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-05-16','-Amalia . el próximo miércoles día 24/05/23 Sebastián será trasladado al centro residencial. Aquí no marcamos la ropa de los pacientes. Se encarga la familia. En el caso de Sebastián, sus hermanas hace meses que no le visitan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-05-16','Ana: Correo de Mª del Sol Tafur, ESM y E.C.A.- La Cumbre (54509 // mariasoledad.tafur@salud-juntaex.es): "...el viernes 19 a las 11.00h. os esperamos para celebrar la reunión sobre el caso de Dª Guadalupe G.C. Miguel Medina, psiquiatra, ya ha cambiado las citaciones de ese día para estar disponible en ese horario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-05-16','Ana: Correo de Leire Sanz, TS de la Res. Ciudad Jardín (t.socialcanovas@grupociudadjardin.com): "Me pongo en contacto nuevamente contigo para comunicarte que en esta mañana van a venir del JUZGADO DE 1º INSTANCIA Nº 7 a valorar el Médico Forense a Isabel y a María, solicitado por los familiares."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-05-16','Ana: Felisi, ayer fue al gimnasio, de 17 a 20 h. Está muy contenta, le gustó mucho la experiencia. ·········· Por otra parte ayer fue a sacar dinero con Virginia, y dice que no pudo sacar, que la tarjeta estaba bloqueada. Confirma después que fueron ella y su hijo previamente a sacar y metieron 3 veces mal la clave y por eso se ha bloqueado. ···· Óscar, secc. ecca., lo ha mirado en la banca online y no aparece que esté bloqueada. ······· Le recuerdo que el límite de gasto en el supermercado (alimentación/productos de higiene/ limpieza) es de 100€, y en la última compra lo han pasado. A partir de ahora, si se pasan deberá abonarlo Felisi, con su asignación. Desde la cuenta de Aitor se abonará un máximo de 100€, que es lo que está autorizado por el Jefe de Secc. ··················· Por otra parte, Aitor aún no ha recogido la tarjeta monedero de Unicaja en la oficina de Trujillo. Le recuerdo que se le ingresarán 20€ para sus gastos de bolsillo. Intentará ir con un amigo. ··············· Como mañana van a verla del Programa de Familias, les escribo (programafamilia@tajosalor.es): "He hablado con Felisa y con Aitor esta misma mañana. Voy por partes. - Aitor intentará ir a la oficina bancaria de Unicaja de Trujillo a retirar una tarjeta monedero, como la de su madre, con la que podrá retirar 20€/semana para gastos de bolsillo. - Nos recuerdan desde la Secc. Económica que el límite de gastos en el supermercado es de 100€, no pudiendo pasar de ahí. De modo que lo que supere esa cuantía tendrá que abonarlo Felisi en efectivo de su asignación (o Aitor si fuer el caso de algún capricho para él). Esto ya se lo he explicado a los dos. Y si no me equivoco también os lo ha trasladado mi compañera Lourdes. - Por otra parte, Felisi me dice que ayer acudió Virginia a visitarles y la acompañó a retirar el dinero del cajero, pero no pudieron hacerlo porque la tarjeta estaba bloqueada. Después me confiesan que habían ido los dos con anterioridad y habían metido 3 veces mal la clave. Mi compañero Óscar, sección económica, ha entrado en la banca online y no le aparece bloqueada. Como me han dicho que mañana vais vosotras, ¿podríais por favor acompañarla a ella? Su clave es 4285. Con ella en teoría podríais cambiar la contraseña a una nueva. No obstante, si estando en el cajero os encontráis con algún problema, por favor, poneros en contacto con Óscar: 924 00 85 11."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-05-16','Ana: Correo de Ana Mª, Ed. Social Plena Inclusión Zafra (social@plenainclusionzafra.org): "Adjunto el Consentimiento Informado para el TRATAMIENTO DENTAL por el PADDI firmado por el Presidente de la CTAEx."','2');
