insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-05-17','miguel, envío el escrito que me remitió José Lavado, firmado por el Gerente para su presentación en el juzgado para modificar el auto de venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-05-16','miguel, recibo email de José Lavado (abogado) Te remito el escrito en parte como hablamos ayer, sin muchas modificaciones no sea que nos anulen todo lo actuado, si ahora pasa así, ya está mejor identificada la representación de la Comisión Tutelar de Menores. Y a ver que nos dicen del Juzgado en cuanto tenga vuestra firma lo hace la letrada, que renuncia a sus honorarios, y lo remito al Procurador para que lo presente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-16','miguel, recibo informe psiquitría del tutelado enviado por Ana: Aquí tenéis el Informe de Psiquiatría elaborado por María Gía Navarro, Psiquiatra de la UHB del hptal. De Cáceres. Lo habías pedido Miguel','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-17','miguel, mi contestación Buenos días, en el informe que envías indica que remitirán acta de la comisión regional. Tenéis ya ese segundo acta? El otro ya lo remitimos al juzgado. En cuanto me enviéis ese segundo acta enviaré ambas cosas al juzgado y a la abogada. A ver si la abogada nos comenta algo relacionado con la conversación que tuvo ayer con el tutelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-05-16','Ana: Correo de Paula, TO del CRR, en relación a la petición de Ceferino de compra de otra consola: "Hola Ana, gracias por reenviarlo. Este tema como te dice ya lo hemos hablado. Él en 2022 compró dos consolas para jugar y ambas las vendió. Esto estaba motivado porque el objetivo de las mismas realmente no conectaba con su interés. Conseguir el aparato era más importante que el uso que quería darle. Así ambos aparatos terminaron en manos de otras personas, siendo vendidos. He acordado con él que, a lo largo de este año, pueda buscar realmente un objetivo (si lo tiene) para usar la play (según observamos juega de forma puntual en el ordenador y cuando tuvo las plays no le duraron más de una o dos semanas, pero eso podría cambiar). Por ello, si le sigue interesando el año que viene, podrá comprarla y disfrutar de ella. Comentaros así mismo que finalmente vendió la controladora antigua. Ésta estaba dañada (ya había intentado arreglarla antes y le costaba bastante). El precio han sido 180 Euros, con los que se ha comprado unos cascos para poder hacer sus grabaciones, un proyector, se ha ido de cena un día y le han quedado unos eurillos para otras cosas. Aunque el centro no ha mediado, el proceso que ha realizado y el destino del dinero (proyector, cascos y actividades ocio) ha sido el que había ido comentando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-05-17','Ana: Correo del PAF (programafamilia@tajosalor.es): "Sin problema, luego le acompañamos e intentamos desbloquearla."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2023-05-17','Ana: Envío correo a Toni-Futuex: En relación a: - Emiliana Sánchez Bermejo - Gregoria Moreno Bermúdez Nos preguntan desde la residencia quién va a ir a acompañarlas a retirar su dinero del banco. Ambas se muestran inquietas desde que han sabido que Gloria ya no irá más. Íbamos a informar a la residencia de que estáis en pleno proceso de selección de personal para cubrir le puesto vacantes y que a una malas irá alguna otra educadora del programa, pero hemos preferido consultarte primero antes de contestar. Quedamos a la espera de respuesta"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2023-05-17','Ana: Envío correo a Toni-Futuex acerca de la consulta de la Res. de Calzadilla: En relación a: - Emiliana Sánchez Bermejo - Gregoria Moreno Bermúdez Nos preguntan desde la residencia quién va a ir a acompañarlas a retirar su dinero del banco. Ambas se muestran inquietas desde que han sabido que Gloria ya no irá más. Íbamos a informar a la residencia de que estáis en pleno proceso de selección de personal para cubrir le puesto vacantes y que a una malas irá alguna otra educadora del programa, pero hemos preferido consultarte primero antes de contestar. Quedamos a la espera de respuesta"','2');
