insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-05-17','Ana: Correo de Mª del Sol Tafur, ESM y E.C.A.- La Cumbre (54509 // mariasoledad.tafur@salud-juntaex.es): "La dirección es Plaza del Molinillo, 2. Es de fácil acceso según venís por la carretera de la Cumbre. Está muy cerca de la Guardia Civil. A la reunión, de nosotros vamos el Psiquiatra, el enfermero y yo. No es una subcomisión como tal, puesto que no hemos convocado otros dispositivos de Salud Mental. Lo estuve hablando con Juanjo Molina, el coordinador de SM, y de momento, solo nos reunimos nosotros con el SASB de la Cumbre y vosotros la Ctutelar."','2');
