insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2023-05-17','Adela PNC : En el expediente de Rubén Montero Sánchez, que está en situación de Extinción desde 01/02/2023 hay un cobro indebido de 2.665,35 €, cobro indebido que ha sido reintegrado con fecha 23/03/2023. Con lo cual habéis tenido que recibir la notificación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-05-17','miguel, email Inés: referente al juicio que estaba señalado para hoy dia 17/05/2023, LEV JUICIO SOBRE DELITOS LEVES 153/2022 , jzdo nº4 Badajoz, por delitos leves, se ha archivado el caso, pues han retirado la denuncia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2023-05-17','TERESA Me pongo en contacto para comentarte en primer lugar que al padre de Beatriz lo intervienen de cataratas el día 23 y Bea quiere estar con él el día de la operación y quedarse algunos días más porque tiene que echarse varios colirios varias veces al día y lo vemos oportuno ya que el padre no cuenta con ningún apoyo familiar que pueda hacerlo. Así también aprovecharía para hacer la visita mensual a su hija puesto que no la ve desde Semana Santa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2023-05-16','TERESA David se quedó en el centro tal y como habíamos acordado contigo el fin de semana y se fue ayer a casa y se encuentra más tranquilo que el miércoles. Su padre sigue en casa pues imagino que pasará un tiempo hasta que se ejecute lo que dicta la sentencia sobre la consecuencia del impago. Y me dice David que los 70€ que le ingresáis mensualmente a su padre que es mejor que se le autoricéis la retirada a David en su banco de Fuente de Cantos puesto que si se le llega a la cuenta bancaria del padre pues no pueden retirarlo ya que se lo embargan inmediatamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2023-05-16','TERESA hable con paco y con la guardia civil, al parecer tiene versiones parecidas, una pareja de novios que paso por calera vio a paco y se pararon, le preguntaron si estaba bien, como el no les contesto llamaron a la guardia civil, y la guardia civil le hizo preguntas a paco sobre en que dia estabamos, como se llamaba etc.... y ahí quedo la cosa…. haber, la su vida es levantarse a las 13:00h , comer a las 18:00h y cenar a las 12:00h y luego se pone a ver la tele hasta las 4 , cuando no hay nada interesante en la tele pues, se aburre y sale a pasear y eso lo ha hecho siempre, la gente del pueblo que lo conoce no llama a la policía, pero como las personas que le vieron eran de fuera de la localidad,.... por otro lado esta el tema de las elecciones, hace 4 años dos miembros del partido popular , lo sacaron de casa y le dieron una papeleta para que fuese a votar, lo pillaron con la ropa mas sucia que tenia y con esa pinta se fue a votar, este año yo le he propuesto que vote por correo, porque a el no le gusta el contacto con la gente, que vote a quien quiera o en blanco pero por correo para ahorarse el trago, el me ha dicho que no quiere ir a votar, y que se va ha encerrar en casa, pero yo se que van a ir otra vez a por el , desde la comision tutelar podeis hacer algo ? un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2023-05-17','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net) a mí y al ctutelar@: "Hola, os escribo para comentaros que en estos días va a ser el cumpleaños de Ignacio Rodriguez Alcántara y nos ha pedido una tablet. Ahora mismo tiene dinero en su fondo para gastos personales. El gasto sería de unos 100 € para una tablet básica y necesitaría una funda para evitar daños. Desde ASINDI veríamos con Ignacio las condiciones para hacer buen uso de la tablet. Cuando podási nos comunicais si nos autorizais para poder comprarla y que sea su regalo de cumpleaños." ······················· Respondo a ambos, por mi parte ok.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-05-17','Ana: Envío correo a la Res. de Santiago de Alcántara (residencia@santiagodealcantara.com) y a la de Los Santos de Maimona (rmayores@lossantosdemaimona.org): "En relación a ARTURO ROCHA MERCHÁN, cuyo cargo ostenta la COMISIÓN TUTELAR DE ADULTOS de Extremadura, por indicación de Mª José, Trabajadora Social de la Mancomunidad Sierra de San Pedro, solicito nos remitan por esta misma vía, tanto a Isabel, Directora de la Residencia Alcalde Antonio Zapata, a quien pongo en copia, como a mí: - Informes Médicos - Pauta de medicación - Cartilla vacunación COVID - Documentos SEPAD (Valoración Dependencia / Resolución PIA) - y cualquier otro documento pertinente que obre en su expediente y sea necesario para el ingreso en su nuevo centro residencial y a tener en cuenta para su adecuada atención integral Aprovecho para preguntaros a ambas, qué tal ha ido el traslado, pues he tenido la mañana tan atareada que no me ha sido posible llamar para preguntar. Confío en que todo se haya desarrollado sin incidencias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-05-17','Ana: Envío correo a Mª José Acosta, TS del SSASB - Mancomunidad Sierra de San Pedro (mjacosta@mancomunidadsierrasanpedro.com): "En relación a JULIÁN RAMÓN CIVANTOS FERNÁNDEZ, quería preguntarte varias cuestiones: - ¿Qué tal está? Pues cuando ingresó presentaba bastante deterioro - ¿Qué tal continúa su adaptación al centro? - ¿Mantiene la intención de quedarse allí con plaza pública / prestación vinculada o presenta ideas de regresar en un futuro próximo a su domicilio? De esto último me piden aclaración desde Dependencia, por el SAD que recibía en su casa y las negociaciones PIA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-05-17','Ana: Miguel y yo hablamos con la Forense que va a valorarla mediante videollamada. Explicamos las limitaciones, deterioro, falta de cuidado, la inadecuada alimentación, la no adherencia al tratamiento, la mala gestión económica y la necesidad de ingreso en recurso y de ajuste previo de medicación en UHB. ························· Virginia-Ed. Futuex la acompaña en el domicilio durante el reconocimiento. ······························································································································································································ Maite y yo, hablamos con Anabel, TS del SSASB. Acordamos que por avanzar, y confiando en que autoricen el ingreso en centro, solicitaremos plaza en Residencia de Mayores a través de Dependencia por Emergencia Social. Yo cumplimentaré la solicitud y Anabel hará el Informe Social (Anexo IV). Además ella pedirá al MAP, informe de no presentar alteraciones de conducta para adjuntarlo también a la solicitud. ··········· Por otra parte, nos confirman que mañana acudirá a la cita en ESM, para lo que le han solicitado una ambulancia. Y hay una amiga de la infancia que le va a acompañar. ··························································································································································································································································· Correo de Toni-Futuex: "La compañera apenas a podido hablar delante del ella pero ha buscado la forma de hacerle saber a la forense, que no tiene seguimiento en salud mental ni conciencia de enfermedad y también que no tiene adherencia al tratamiento. Pero la ha preguntado la pauta y se la sabía... ya es mala suerte, que no se tome la medicación y se la haya sabido! Ha podido ver, que camina completamente inclinada hacia un lado y con mucha dificultad También le ha preguntado por si hija que vive en Ibiza al parecer, por lo que no hay apoyo por esa parte. Ha hablado de algún conflicto vecinal Y sobre la ayuda a domicilio 2 horas de lunes a viernes la forense lo considera insuficiente ella cree que necesita más... Ha mencionado (la forense) que quizá debería estar en un centro para ancianos sobre todo por los problemas de movilidad pero hoy no la ha visto desajustada como para ingresar primero en UME que al parecer es lo que solicitaba desde la comisión. Asique si se confirma esto en el dictamen de la forense mal.. porque parece que no ha hecho mucho caso a los informes. Ni ha atendido a que habitualmente se mantien en delirio activo, que no tiene adherencia ni conciencia de enfermedad ni nada. Nosotros pensamos que alomejor, Joaquina ha simulado estar un pco mejor de lo que realmente está.. Han hecho un recorrido por la casa, que estaba limpia y ordenada. También le ha entregado una copia de una citación para mañana en salud mental, que te adjunto, dice que si que va a ir, con una amiga.. y que ya ha solicitado hasta ambulancia... veremos si finalmente es asi. Respecto de lo del lunes, le ha pedido a la compañera que si puede ir con ella en taxi, desde Miajadas, se le ha explicado que la idea era encontrarla en Trujillo, pero bueno que valoraremos si es necesario para asegurarnos que vaya a la cita, y lo haremos de este modo, tambien parace como que tiene cierta dependencia emocional, y llamadas de atención, asique bueno si aseguramos que va a a la cita, pues lo haremos desde miajadas con ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-05-17','Ana: Correo de Arantxa, Directora Residencia (parquedelprincipe@grupociudadjardin.com): Informa de que ayer acudió el Médico-Forense a valorar a las dos hermanas. Y las incidencias con el Abogado de Carmen al repecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-05-18','Ana: Envío a Registro (oac.merida.san@juntaex.es): "En representación de D. Arturo Rocha Merchán, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, os remito Oficio Solicitud de Certificado Actualizado de Prestación de Supervivencia: ORFANDAD, junto con la siguiente documentación para registrar: - Testimonio de Sentencia de Incapacitación y Nombramiento - Acuerdo de Aceptación del cargo La solicitud va dirigida a: DIRECCIÓN PROVINCIAL DEL INSS DE CÁCERES AVDA. DE ESPAÑA, 14 10001 – Cáceres"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-05-18','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Informaros que la persona usuaria Consuelo Nevado Pacheco necesitó en fecha 16.05.2023 ajuste de tratamiento en urgencia del equipo de salud mental por parte de su psiquiatra de referencia. Ayer 18.05.2023, sin que existiera mejoría ambulatoria con el ajuste realizado, precisó de valoración psiquiátrica en urgencias del Hospital San Pedro de Alcántara, quedando ingresada en la UHB por desestabilización de su patología de base."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-05-16','Ana: Llamada de Carmen Jiménez Xisto, sobrina de María (639 50 35 36): Explica que está moviendo todo para ejercer ella el cargo de su tía. Según dice, durante el procedimiento judicial de provisión de medidas judiciales de apoyo, ella estaba pasando por un proceso oncológico, debido al cuál no pudo asumir ella el cargo. ··· Expresa haberse preocupado siempre por ellas. ············· Solicita poder sacar a su tía María de la Res. y llevarla por su cumpleaños a una casa de campo que tiene en el Pantano de Valdesalor. ········ Su cumpleaños es el día 18 de mayo. ················ Le indiqué que dados los incidentes, procesos judiciales abiertos y llamadas con distintos argumentos de las distintas sobrinas, de momento no se autorizan las salidas del centro de su tía María por protección, desde el Gabinete Técnico de la CTAEx debemos velar por su bienestar y todos sus intereses. No obstante, cuando sea posible, valoraremos en equipo esta solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-05-10','Ana: Conversación con Mª Luz, Eva y Raquel, Secc. de acceso a recursos de Salud Mental: Dada la trayectoria de Consuelo y la cantidad de descompensaciones e ingresos recientes en UHB, Plantean un TRASLADO DE OFICIO al CRR de Plas. Consideran le puede venir bien y cambio de aires. ··················· Hablaré con Sheila, Directora del CRR-CC. Si Consuelo está de acuerdo se promoverá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-05-18','-Amalia : se incluye en el seguimiento de FUTUEX para acompañamientos puntuales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-18','Ana: Tras conversación con Mª Carmen, TS del HSPA (56283), envío correo a Toni-Futuex: "En relación a SATURNINO MIGUEL SALGADO JIMÉNEZ, comunicaros que se va a producir su traslado el día 31 de mayo al juicio y después, se irá temporalmente a UME de Plasencia o, directamente a Sevilla, al hospital psiquiátrico-penitenciario. Desde el hospital de Cáceres nos solicitan proveerle de los siguientes productos (por demanda propia y/o necesidad detectada): • 2 pantalones, 1 vaquero azul y otro negro. Talla S ó 40-42 (creen que la 40 podrías servirle, pues está muy delgado de la parte inferior) • Camisetas de verano - Talla M. • Pijama de verano • Botas nº 39-40 + Zapatillas de verano • Ropa interior (calcetines y calzoncillos). Con respecto a esto, ya le comprasteis cuando ingresó en la UHB, pero será bueno que lleve algunos más. • Crema hidratante para la cara (al parecer la tiene muy deshidratada. Como no sabemos cómo de sensible tiene la piel, comprar una en la farmacia para estar más seguros de no le vaya mal) • Su guitarra de su domicilio o comprar armónica. Con respecto a esto, van a averiguar si tiene las llaves en el hospital y, en tal caso, agradeceríamos que Virginia pase a recogerlas para ir a buscar su guitarra. Entendemos que es buena para él. Podría pedir a la trabajadora social del Alcuéscar y/o a la Policía Local que le acompañen. A este respecto, pongo en copia a mis compañeros asesores jurídicos, para que nos indiquen si es necesario que el Representante legal firme alguna autorización y en tal caso, la redacten para que os la podamos enviar con tiempo. Me dicen desde la sección económica que se puede hacer como la otra vez, que nos remitan, a ser posible directamente desde la/s tienda/s/farmacia, por agilizar, las facturas correspondientes a nombre de Saturnino con el número de cuenta para abonarlo mediante transferencia bancaria a la mayor brevedad. Sería conveniente tener todo antes de la fecha indicada." ····························································· Toni confirma que Virginia, Ed-Futuex, se encargará de la compra de los productos. ······ Cuando sepamos lo de las llaves de la vivienda se lo diremos también para ir a buscar la guitarra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-05-18','Ana: Llamo a Montaña, TS SSASB La Cumbre (621 247 249): Mañana visitaremos a Guadalupe antes de acudir a la reunión con el ESM en Trujillo. Montaña hará la visita con Maite y conmigo ···· Acordamos ver primero a Guadalupe en el despacho de la TS (Hogar del pensionista. C/ Antonio Illera) antes de ir a su vivienda, con el "pretexto" de ver el tejado de la vivienda para ver si podemos ayudarla. Una vez allí pediremos ver la casa entera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-05-18','Ana: Conversación con Celia, TS UHB - HVP-Plas. (78206): Informo de la trayectoria de Javier, desde que se asumió el cargo por la CTAEx. Y las últimas incidencias relativas a su viaje no programado a Tarragona. ········ Puesto que ha salido del circuito de S.M., con respecto al alta de la UHB, no tenemos otra opción que buscarle un alojamiento. ····· Tendrá que retomar el Seguimiento en el ESM y confiemos que se mantengan la derivación al CRPS. ·············· Comunicará todo al Dr. Blanco, Psiquiatra. No sabe cuándo le darán el alta. "No hay prisas, pero posiblemente a mediados de la semana que viene". ································· Envío correo a Toni-Futuex: "hablé esta mañana con Celia, TS de la UHB. Precisamente iba a escribiros para deciros, si es posible, que vayáis tanteando opciones, pero con cautela pues no saben aún fecha de alta. Dice que quizá a mediados de la semana que viene según evolución. La idea es justo la que tú planteas: que vuelva al hotel Azar, o a algún otro, y se continúe en la búsqueda de alguna opción más económica. Lo de compartir piso, como tú dices, es más complicado. No obstante, dado que tiene posibilidades económicas, igual se podía hacer como con José Moreno Moyano, buscar alguna pensión o similar. Desde el Equipo de Salud Mental propusieron, justo antes de irse, la derivación al CRPS, y sería estupendo que al menos contase con el apoyo de este recurso. Se lo he dicho también a la TS del hospital para que lo tengan en cuenta. En cuanto nos digan fecha de alta, os la comunicamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-05-18','Ana: En relación al correo de Ceferino a Ángel, A. Jurídico: "Hola Ángel necesito asesorarme para ver qué puedo hacer para poder salir a vivir fuera de él CRR ya que llevo mucho tiempo en este tipo de recursos María de la gestión económica me ha dicho que estoy tutelado no curatelado ahora no tengo vivienda pero tengo 87.211 con 25€y quisiera comprarme un piso para poder irme a vivir o bien al piso de alquiler por favor contéstame al correo o cógeme el móvil cuando puedas" ································································· Escribo a las profesionales del CRR: "Os reenvío correo de Ceferino Mariscal Crespo, para qué cuando podáis, nos informéis sobre si os ha planteado esta cuestión, si, en tal caso, habéis tenido ocasión de abordarlo con él y vuestra opinión al respecto. Ángel, Asesor Jurídico, me ha dicho que no ha querido responderle hasta tener más información al respecto y, una vez más, sigamos desde las distintas partes un mismo criterio a la hora de intervenir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2023-05-18','Ana: Respuesta de la secc. ecca. a Sonia Bernabé- Asindi: "Buenas tardes, se autoriza el extra para la tablet, tal y como indicáis, disponeis de fondo para asumir este gasto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2023-05-18','Ana: Corre de Belén Pavón (Belen.asoma@outlook.es): "...María Salvadora Chaves Mendoza, Pisos Tutelados de Villa del Rey, Cáceres, tiene una cita médica el día 22 de mayo lunes, que fue comunicada a Gloria anteriormente, no he recibido respuesta de Gloria, de si puede acompañarla, y no contesta ni a mensaje ni a llamadas, no sé si estará de vacaciones... El caso, ayer escribí directamente a Toni un email que puedes ver más abajo, pero no he conseguido tampoco respuesta. No sé si me puedes ayudar a contactar con ella para confirmar si Gloria podrá acompañar a María Salvadora o de lo contrario tengo que buscar un acompañante (pago de 50€) por acompañamiento hospitalario. A la espera de tus noticias, gracias de antemano" ································································ Consulto a Toni-Futuex: "¿Podéis confirmar si alguna de las compañeras podrá acompañar a Mª Salvadora a la cita con el especialista en el Hptal. Universitario de Cáceres? Para buscar sino otro acompañamiento. Dime en cuanto puedas, porfa" ··························· Envío correo a Beatriz Pavón: "Me confirman desde Futuex, que no será posible este acompañamiento, al parecer a Gloria se le debió pasar comunicarlo antes de marchar y no sé si es que la coordinadora no vio tu correo. Disculpa las molestias. ¿Podríais, por favor, gestionar el acompañamiento por otra persona, al menos por esta vez?. Una ver realizado, remitir a la siguiente dirección ctutelar@salud-juntaex.es la DECLARACIÓN JURADA DE LA PERSONA con el número de cuenta para que se le puedan abonar los 50€ que planteas mediante transferencia. Pongo en copia a las compañeras de la sección económica para que estén al corriente y procedan al abono una vez remitáis la declaración jurada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2023-05-18','miguel, llega email de Mª Galindo TS del CSS Mérida: La médico somático de Miguel Gamero, es decir, M.ª Luz Romero Furones, ha contactado vía telefónica con la dentista Dra. Diana G.ª, ya que el paciente ha sido valorado nuevamente por ella y le ha indicado que los implantes que le pusieron en la Clínica Dental Estetic no tienen un buen agarre y podrían desprenderse. Le ha explicado que una opción para demostrar los problemas que ha tenido Miguel con dicha clínica es a través de un perito. Por lo tanto, la CTAEX debe contactar con el Colegio de Oficial de Dentistas de Extremadura y solicitar un perito. ********************************************************* mi contestación a ella, Amalia, y MariLuz Romero Furones: Buenos días, vuelvo a remitirme al email de 18-11-2023: hay que demostrar la relación causa, efecto, es decir hay que aportar la documentación y pruebas que demuestren, cuando se ha producido el daño, cómo, quién lo produjo, qué dinero se abonó…y tras el daño qué informes o justificantes existen de cuándo, dónde y ante qué profesional ha ido, y qué diagnostico se le dio. En definitiva: Puede demostrarse y justificarse momento y lugar en que se han producido los hechos ilícitos? Hay documentos firmados indicando el seguimiento del tratamiento, garantía, informes que acrediten el antes y después de cómo están la dentadura? . Se ha hecho algún escrito de queja a ambos centros dentistas y se ha recibido o no respuesta? Incidimos de nuevo que si tiene un derecho de garantía y va a otra clínica, aunque vuelva el derecho lo pierde porque no ha permitido su seguimiento por la clínica donde tenía la garantía. No vale por tanto con nombrar a un perito, que lo único que va a indicar es si unos implantes están bien o mal puesto y los riesgos de que se caigan. Si nos remitis documentación la estudiaremos y os diremos si vemos opciones de reclamar daños si es que no ha prescrito el derecho de reclamar. ************************************************** Y reenvío mi contestación a Angel, parte económica y social: Os adjunto email de contestación a la indicación del CSS Mérida de que solicitemos un perito dentista para acreditar el daño en los implantes del tutelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-05-18','miguel, Inés envía por lexnet las Alegaciones contra el recurso interpuesto por la abogada de la tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-18','Ana: Correo de Ana Benavente, TS del ESM (anamaria.benavente@salud-juntaex.es): "Queremos informar desde el ETAC que en los últimos meses Enrique nos está llamando de forma insistente al Equipo de Salud Mental demandando que nos pongamos en contacto con vosotros ante la imposibilidad de contactar por él mismo. Por este motivo hemos realizado una visita a domicilio ( ayer ) para concretar demandas y hemos podido comprobar que por un lado no hay descompensación psicopatológica , sin embargo existen una serie de necesidades que el paciente necesita cubrir y que no puede gestionar . Le surgen gastos extraordinarios a los que no puede hacer frente ( desbrozar su jardín , dentista, cortar un árbol caído) . Algunos vecinos del pueblo le hacen los trabajos , peros se agobia porque no puede pagarlos , con lo que nos llama insistentemente por teléfono para que hablemos con la CTA. Se trata de un paciente que solo hace unos meses dependía de su madre para casi todo , y ahora se ve solo con una problemática , que no es grave , pero que no puede resolver . Persisten todavía las deudas con su hermano y con su tío, lo que está empeorando la ya deteriorada situación familiar. Todo esto está generando que el paciente se encuentre en una situación de estrés casi continua, ya que aparte de su sintomatología afectiva presenta unos rasgos de obsesivos de personalidad que le obligan a tener un control sobre su entorno. Quizás sea necesario revisar la asignación que percibe mensualmente y ver la forma de establecer una comunicación más fluida entre paciente y Comisión Tutelar. Por todo ello creemos necesario abordar esta problemática que está generando situaciones personales y sociales en el paciente que afectan a la frágil estabilización de Enrique." ··························································································································································································································································· Mi respuesta: "En relación a tu correo, me alegra saber que ayer el ETAC realizasteis una nueva visita presencial a ENRIQUE SANTOS GARCÍA PUENTE y que además sigue estable a nivel psicopatológico. Como sabéis, el cargo que ha asumido la CTAEx, es una CURATELA REPRESENTATIVA de carácter administrativo, no es lo mismo que si la hubiera aceptado una persona física. Como sabéis también tenemos muchas limitaciones en cuanto a personal y para las visitas a personas a cargo que residen en su domicilio, contamos sólo con el Programa de Apoyo Comunitario que gestiona Futuex (mediante convenio) y son sólo 2 educadoras por provincia (ahora se ha quedado sólo una en la provincia de Cáceres porque la otra ha encontrado otro trabajo. Ya están realizando proceso de selección). Desde este programa le realizan vistas periódicas, pero en función de las posibilidades reales que tienen. Ya nos gustaría que fuera con mayor frecuencia. En cuanto a las llamadas, habitualmente no llegamos a atender todas llamadas que entran cada día (entre otras cosas porque no siempre estamos en la mesa y tenemos que entender otras cuestiones: gestiones, trámites administrativos, reuniones, comisiones/subcomisiones de casos, juicios/contacto con forenses para reconocimiento, entre otras), pero además, se ha juntado con tres días consecutivos de curso de formación presencial (toda la mañana). Lo siento pero no estamos todo el tiempo disponible al teléfono. Otras cuestiones, que también conocéis, desarrolladas en coordinación con el resto de recursos son: mantenimiento del servicio de comida que se lleva a domicilio, y Servicio Municipal de Ayuda a Domicilio, que se solicitó desde aquí. El pasado mes de marzo, también se le formalizó Seguro de Decesos que no tenía. Por otra parte, en cuanto a las “necesidades” y “gastos” extraordinarios que tiene que cubrir, entendemos vuestra demanda, pero como ya le explicamos a él y a ti, la forma de funcionar es con presupuestos previos y facturas posteriores, no es por complicar las cosas, sino porque, como también sabéis, desde aquí hay que rendir cuentas al Juzgado y, excepto gastos de bolsillo, tenemos que justificar TODO. Especificar también que según su sentencia, hay que proporcionarle para gastos de bolsillo 100€/semana. Y es lo que se hace, 100€ x 52 semanas/año. Para mayor claridad y comprensión de la situación económica, os paso a detallar los gastos que asume mensualmente y los extraordinarios que se han gestionado desde que aceptó el cargo por la CTAEx. Esta información me la facilita un compañero de la sección económica: “INGRESOS: 783,10 € * 14 pagas. GASTOS: Media mensual aproximada: - Cáterin: 200€ - SAD: 16,20 € - Wifi: 21€ - Teléfono móvil: 43€. - Reintegros semanales: 433€. - Deceso: 8€ - TOTAL MENSUAL: 721,20 € Gastos extras abonados en los últimos 3 meses: 1.182€ (TV, ropa y otros). Gastos previstos (no cuantificables en la actualidad): - Consumos de agua y luz a abonar a partir de ahora. - Pago de atrasos a los hermanos de consumos de su vivienda. - Pago de deudas a varios familiares. Con estos datos, su situación económica no permite una subida de asignación ni realizar autorizar más extras, ya que su evolución es negativa.” Como veis, su situación económica es la que es y no puedes seguir gastando por encima de sus posibilidades. Pongo en copia a: - Óscar, Jefe de Negociado de la Sección Económica (En ausencia del Jefe de Sección Económica) - Maite, Jefa de Sección Social de la CTAEx. - Puerto, compañera del SSASB Valdeobispo Para que estén al corriente. Puedes reenviar el correo, si lo consideras, al resto del ETAC."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AVILA'and apellido2='RAMOS'),'2023-05-17','TERESA Buenos días, el usuario de la residencia de Santa Ana, D. Francisco Ávila Ramos, tiene desde el 13 de enero del 2023 un curador representativo, D. José Vicente Granado Granado, por lo que he podido leer en la sentencia no hay ningún problema para que D. Francisco Ávila Ramos ejerza su derecho al voto, pero como tenemos próximamente las elecciones municipales y autonómicas, el señor quiere saber si realmente no hay ningún impedimento para ejercer su derecho al voto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AVILA'and apellido2='RAMOS'),'2023-05-19','TERESA Ya somos curadores de Francisco como me ha comentado en el anterior correo. Hemos domiciliado su pensión en Unicaja porque en la cuenta que tenía anteriormente nos ponían muchos problemas para poner a Jose Vicente Granado. Estamos viendo el tema de los seguros para gestionar la baja. Necesito me elabore un pequeño presupuesto sobre los gastos que tiene Francisco en su día a día (farmacia, peluquería, podología, etc.) así como el dinero para sus gastos personales ( dinero de bolsillo) y si puede el a sacarlo del banco una vez autoricemos el reintegro así como la temporalidad, mensual, quincenal…. Con respecto al pago de la plaza residencial como se está haciendo el pago de la mima? También necesito saber si está al corriente de pago o tiene alguna deuda. Cualquier duda se puede poner en contacto conmigo bien por teléfono o a esta dirección de correo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-05-19','Amalia : medidas de apoyo para ámbitos salud , jurídico , advo. y contratos para actos más complejos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-05-19','Amalia : medidas de apoyo para ámbitos salud , jurídico , advo. y contratos para actos más complejos . Le escrio a Sandra : Juanjo puede sacar su tarjeta de transporte , esos 7 € que los coja de su asignación mensual. Te enviaré la solicitud firmada por el Rpte. legal , tendréis que terminarla de cumplimentar con la foto y algún dato más. Con respecto a los 90€ de cuota de socio que habéis solicitado en varias ocasiones , le pedí a los compañeros de cuenta que estudiaran la viabilidad económica para ello. Nos sorprendió que la cuota ya se la estáis cargando desde hace unos meses . Se ha aceptado el que sea socio por el momento , mientras sus ingresos se lo permitan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-05-19','Amalia : medidas de apoyo para ámbitos salud , jurídico , advo. y contratos para actos más complejos . Le escrio a Sandra : Juanjo puede sacar su tarjeta de transporte , esos 7 € que los coja de su asignación mensual. Te enviaré la solicitud firmada por el Rpte. legal , tendréis que terminarla de cumplimentar con la foto y algún dato más. Con respecto a los 90€ de cuota de socio que habéis solicitado en varias ocasiones , le pedí a los compañeros de cuenta que estudiaran la viabilidad económica para ello. Nos sorprendió que la cuota ya se la estáis cargando desde hace unos meses . Se ha aceptado el que sea socio por el momento , mientras sus ingresos se lo permitan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-05-19','Angel , envia este email : En relación con este asunto, en el que estoy trabajando desde principios de año, con correos al hijo Flavio Escribano, fescribano@gmail.com y al despacho de Abogados, Juan Carlos Sanchez Mañero, juancarlos@menayaabogados.es, para que nos remitan documentación/información relacionada con esta herencia y que nos están remitiendo, todo ello a los efectos de aceptarla o no, os contesto, Desde el área jurídica, queremos manifestar, como venimos haciendo desde principios de este año, que NO hemos firmado la hoja de encargo enviada por el despacho de Abogados, porque nos despertaba bastantes dudas esta herencia, al haber deudas (que sepamos un préstamos de 5.000 euros), los hijos han renunciado, desconozco cuáles y los motivos, les he pedido que nos envíen las renuncias formales, hay un vehículo del que no se dispone de documentación y hay que solicitar duplicado del permiso de circulación, pasar la itv y gestiones a parte con una gestoría, que habría que abonar a parte. En el testamento de Blas, lega a Mª. Rosa 1/3 de libre disposición y el usufructo universal y vitalicio y nombra herederos a la hija adoptada por él (Mª. Rosa Ródenas Serrano) y las 2 hijas de Mª. Rosa (Dulce Nombre Mª y José Manuel Escribano Serrano), tampoco concreta gastos de procurador y lo deja abierto. Sin embargo, desde el área económica se han abonado 500 euros al Abogado, reenviándonos Hoja de Encargo. El primer plazo de la hoja de encargo, era de 423,50 euros. Por todos estos motivos, os envié un correo el 15/2/23, en el que os decía que antes de firmar la Hoja de encargo, deberíamos aclarar todos estos aspectos con el despacho de Abogados, que es lo que estoy/estaba haciendo hasta ahora. Por lo expuesto y toda vez que desde el área social/económica se ha dado el visto bueno a esta Hoja de encargo, al margen de lo manifestado por el área jurídica, desde ésta no nos hacemos responsables de todos los gastos que esta herencia va a ocasionar: Deudas (préstamo 5.000 euros). Pago del resto de la hoja de encargo (605 euros). Gastos por gestiones a parte con una gestoría y que no se detallan, para solicitar duplicado del permiso de circulación, pasar la itv del vehículo, del que no disponemos de documentación. Gastos por cualquier otra intervención compleja distinta a las anteriores y que no se detallan en el Hoja de Encargo. Gastos por honorarios del Procurador y de otros profesionales o técnicos que deban intervenir en el procedimiento y que no se detallan en la Hoja de Encargo. Gastos por desplazamientos o gastos de cualquier naturaleza, así como suplidos, que puedan ocasionarse al ABOGADO suscribiente en la ejecución de los trabajos encomendados y que no se detallan en la Hoja de Encargo. Como también se os remitió por correo electrónico el 24/1/23, Rosa, al estar curatelada, no necesita autorización judicial para aceptar la herencia, por tanto, no se precisan los servicios de Abogado y Procurador. Con nuestra intervención, sería suficiente. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='TESORO'and apellido2='GARCIA'),'2023-05-19','EXITUS El centro informa de su fallecimiento, acaecido el 19/05/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='TESORO'and apellido2='GARCIA'),'2023-05-19','TERESA SE ENVIA AUTORIZACION PARA INCINERACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-19','Ana: Respuesta de Puerto, TS SSASB (ssb5@mancomunidadvalledelalagon.es): "Buenos días Ana, qué buena gestión! coincido totalmente con vosotros, no se puede gastas más de lo que uno tiene, además de que hay que priorizar las necesidades básicas! Enrique necesitaría más tratamiento no farmacológico, terapéutico, manejo de habilidades, las auxiliares del SAD están trabajando lo que se puede con él... Estamos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-22','Ana: Envío correo a Toni-Futuex: "En relación a ENRIQUE SANTOS GARCÍA PUENTES, estamos totalmente de acuerdo con el planteamiento que hace Puerto, TS del SSASB: “Enrique necesitaría más tratamiento no farmacológico, terapéutico, manejo de habilidades”, por lo que queríamos solicitaros que la Terapeuta Ocupacional y/o la Trabajadora Social, del Equipo de Apoyo Comunitario, acuda a visitarle de forma intercalada en el tiempo con la Educadora, para seguir abordando estas cuestiones con él. Pues aunque la Auxiliar de SAD, intenta trabajar algo con él, no cuenta con la cualificación necesaria."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2023-05-22','Buenas tardes. Por la presente comunicamos la fuga del paciente Miguel Gamero Gómez sobre las 18: 20 horas. Se ha comunicado su fuga a Policia Nacional y Local. Para que así conste y surja los efectos oportunos. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-05-23','TERESA Siento escribir tan tarde. Pablo ha llegado hace un ratito de la consulta del CEDEX. Lo ha entrevistado la enfermera y hay que esperar la cita para el médico. Por el momento es lo único que tenemos… Buen fin de semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-23','Ana: Correo de Ana Benavente, TS del ESM (anamaria.benavente@salud-juntaex.es): "Muchas gracias Ana por toda la información aclaratoria sobre Enrique. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-05-23','Ana: Envío correo a Julián Álvarez: "En relación a la reunión que mantuviste con Alberto, Jefe de Sección Económica, retomando la solicitud de poner a Tomás un acompañante para que pueda realizar salidas semanales con carácter periódico, lo cual, como ya hablamos en su día, desde la sección social nos parece adecuado y positivo para él, te paso la información detallada que me ha facilitado Alberto sobre la situación económica de Tomás y las posibilidades de “contratar” este servicio: .... Por tanto, como ves, lo factible sería las 3 horas semanales de acompañamiento para ocio. Es lo que se puede autorizar. Si ya tenéis la personas para realizar el acompañamiento, sólo falta “formalizarlo” conforme acordaras con Alberto en la reunión mantenida. De todas formas, si lo estimas conveniente, mañana hablamos. Buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-05-23','Ana: Envío correo a Celia, TS HVP (celia.garcia@salud-juntaex.es), con copia a Ana Benavente (anamaria.benavente@salud-juntaex.es): "Por lo visto, finalmente le dieron el alta ayer. Menos mal que desde el Programa de Apoyo Comunitario de la Junta, gestionado por Futuex, pudieron encontrar unas noches en el hotel Azar, pero la situación va a estar complicada, a penas hay disponibilidad en alojamientos de Plasencia y a partir del 25 corre el riesgo de quedarse en la calle, pues ya nos han dicho en el hotel que no puede quedarse más días por tenerlo previamente reservado y completo. Como sabéis, la CTAEx no dispone de recursos propios, ni de reserva de plazas, ni prioridad en el acceso a ningún recurso. Las personas a cargo acceden a los recursos por las mismas vías que el resto de la ciudadanía extremeña. No sé si sería factible valorar el caso como emergencia social en Salud Mental, para que pudiera solicitársele por esta vía algún recursos, pues sino tendrá que pasar de nuevo por el circuito por la vía ordinaria y sabemos que esto se demora. Pongo en copia a Ana Benavente, compañera del Equipo de Salud Mental de Plasencia, por si se les ocurre alguna opción desde el equipo, pues a expensas de que puedan encontrar pensión, hotel o piso de alquiler (están en ello desde el Programa de Apoyo Comunitario) no tenemos más alternativa." ······························································································································································································· Correo de Toni-Futuex: "En el hotel nos confirman que llegó a las 3 de las mañana... aparentemente bien, sin estado aparente de embriaguez, pero vaya, que en fin... no son en principios unas horas muy razonables. No conseguimos contactar con el, el teléfono sigue apagado. Se sabe algo para cuando tenga que dejar el hotel el jueves?" ····································································································································································································· Envío correo a Toni-Futuex: "Gracias por informar. Por lo que informáis, la situación está más que complicada. He escrito a Celia, TS del hospital, pues tenía correo de ella de ayer a las 10:19, diciendo que le daban el alta a partir de ese día cuando se le confirmara el acceso a recurso…. en fin... Como te decía, le he constestado a ella y he escrito también a la Trabajadora Social del Equipo de Salud Mental, para ver si pueden valorar el caso como emergencia social y que pudiera acceder a piso o CRR, pero me temo que no vamos a tener respuesta en esta línea. De momento, por favor, continuar con la búsqueda de pensión/hostal, lo que os quede por consultar y de piso de alquiler. Pues si a demás a Cáritas no quiere… lo tenemos complicado." ······································ Último correo de Toni-Futuex de la mañana: "Vale, gracias, el jueves trasladamos todo esto... confiemos en dar con el. Y que quiera ir a Caritas, el finde, claramente, como bien dices no se puede llegar a mas, tambien a tener en cuenta dada la trayectoria que con dinero se las apañara para ir o estar en algun lado, eso seguro Para el finde todo lleno, pero vamos a ver el jueves también con el , si se libera algo en los hoteles/hostales para comienzo de semana, y el tema de ir a alguna inmobiliaria. Pero sobretodo trabajaremos el que acuda al centro de Cáritas. Hacemos con todo lo recopilado y lo que se pueda intervenir o no, y enviamos informe una vez lo visitemos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-05-23','Ana: Correo de Toni-Futuex: "Hemos enviado al area economica, la factura proforma porque solicitan que se abone en uno o dos dias, en el hotel AZAR donde estvuo con anterioridad. No hay disponibilidad en ningun hotel de plasencia y en este solo hasta el jueves 25. Se está itentando localizarlo en el numero de telefono del que disponemos para comunicarselo pero está apagado, también a la ts del hospital virgen del puerto nos han dicho que hoy ya estaba de alta. Tras muchisimos intentos hemos conseguido comunicar con la ts del hospital, que le iba a comunicar al tutelado que tiene hasta el jueves hotel. Y que podria ir ya hoy. Aunque en el hotel nos dicen que está supeditado a que reciban el pago, porque se demoró mucho en la otra ocasión y no es la politica de la empresa. Ademas estuvo pidiendo a todos los huespedes. Desde el hospital, erroneamente, consideran que es la comisión quien debe proveerle un recurso y que hoy estaria de alta. Desconocemos la pauta de medicación con la que sale o si estan en contacto con salud mental. Tiene hotel hasta el jueves pero a partir del viernes NO TIENE DONDE IR. NO HAY DISPONIBILIDAD EN NINGUN HOTEL CONSULTADO Y AL CENTRO DE TRANSEUNTES DE CARITAS NO QUIERE IR. Suponemos que no tiene dinero, porque ya retiraria su asignación en mayo, pero no lo sabemos. Se puede intentar busqueda de piso y se le ha pedido a el, que de modo activo también lo haga.. pero no creemos que se consiga nada realmente con tan pocos dias. Que se puede hacer? para cuando deba dejar el hotel azar? la verdad que no sabemos como mas proceder.. no sabemos si en alguna residencia o centro pueda solicitarse una estancia temporal o si se le puede gestionar algo por emergencia o exactamente que. El jueves se le visitará. Quedamos a la espera para ver como podemos intervenir, con las opciones escasas, de las que se dispone en este caso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-05-23','Ana: Correo de Ana, Ed. de Plena Inclusión Zafra: "Quería pedirte el certificado de discapacidad de Reme. No lo encuentro, la verdad es que no sé si te lo llegué a pedir y lo necesitamos para llevarla a PADDI (dentista). A grandes rasgos, te diré que está bien…vamos trabajando algunas cosillas con ella y parece que hay pequeños resultados… seguiremos avanzando…seguro!!!" ········································· Mi respuesta: "Qué bien! Qué buenas noticias, me alegro que esté evolucionando bien. Te envío adjunto el Certificado del Cadex y el Dictamen Técnico Facultativo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-05-22','Ana: Correo de Toni-Futuex: "Nos comunican al llegar al juzgado que se anula este jucio previsto para hoy, que debe ser el número dos o algo así. Despues de movilizar todos los recursos para acompañarla. Afortunadamente aun no habían salido de Miajadas, cuando se lo hemos comunicado, aunque no sabemos si el taxi cobrará algo. La compañera si ha ido para allá. Dicen en el juzgado que lo comunicaron a la comisión el pasado viernes la suspensión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2023-05-24','Ana: Envío correo a Paz Boticario, TS - Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org): "Adjunto las Autorizaciones para los viajes a Lourdes firmadas digitalmente"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-05-24','Ana: Envío correo a Paz Boticario, TS - Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org): "Adjunto las Autorizaciones para los viajes a Lourdes firmadas digitalmente"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2023-05-24','Ana: Envío correo a Pilar Cortijo, Residencia Santiago Apóstol - Navezuelas (pilarcortcer@gmail.com): "Espero que estéis bien. Adjunto los consentimientos informados para administración de anestesia, relativos a JUAN JOSÉ HORNERO RODRÍGUEZ, debidamente firmados y sellados por el representante legal. Por favor, cuando se trate de cuestione que no sean estrictamente económicas o jurídicas, remitidlo a la dirección desde la que escribo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-05-23','miguel, tras la conversación ayer con Jorge Calvo (abogado) por parte económica y jurídica, la social no cree necesario su participación. Se decide que no se recurra debido al coste y el tiempo que puede conllevar la resolución del mismo, unido a la falta de seguridad en ganar dichos recursos contra la condena en costas y gastos y contra la desestimación en la ejecución del procedimiento de desahucio por falta de pago. Por tanto se acuerda únicamente la revisión de oficio cuyo escrito y documentos adjuntos me lo remite el abogado para ser firmado por José Vicente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-05-24','miguel, remito firmado por José Vicente el recurso de revisión de oficio vía email a Jorge Calvo (Abogado)>reuniomabogados@gmail.com>644340448 y 924-223012','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2023-05-24','miguel, recibo comunicación (reenviada por Tere) de la TS de la Providencia Mª Cadenas trabajadorasocial@providencia.es>, El 12 de Mayo falleció la madre de acogida de Carmen Asensio García. Me ha llamado una de las sobrinas de la madre de acogida y me informa que Carmen está incluida en el testamento familiar. Van a empezar los trámites de la declaración de herederos. Ya le informé que una vez que tengan el abogado tendrá que contactar con vosotros','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-05-18','Ana: Correo de Isabel, directora de la Res. Municipal de Los Santos de Maimona (rmayores@lossantosdemaimona.org): "El ingreso se produjo un poquito mas tarde de lo que se había cerrado pero nos avisaron y se hizo sin problema. José como le gusta que le llamen (Arturo) se ha adaptado perfectamente. Yo diría que demasiado rápido. Ha pasado la noche bien y tranquilo. No ha puesto oposición ni a asearlo, ni al lavado de dientes ni a nada...Asi que de momento, genial."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-05-18','Ana: Correo de Isabel, directora de la Res. Municipal de Los Santos de Maimona (rmayores@lossantosdemaimona.org): "El ingreso se produjo un poquito mas tarde de lo que se había cerrado pero nos avisaron y se hizo sin problema. José como le gusta que le llamen (Arturo) se ha adaptado perfectamente. Yo diría que demasiado rápido. Ha pasado la noche bien y tranquilo. No ha puesto oposición ni a asearlo, ni al lavado de dientes ni a nada...Asi que de momento, genial."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-05-24','Ana: Envío correo a Isabel, directora de la Res. Municipal de los Santos de Maimona (rmayores@lossantosdemaimona.org) con copia a Mª José, TS Mancomunidad de la Sierra de San Pedro (mjacosta@mancomunidadsierrasanpedro.com): "¿qué tal continúa el proceso de adaptación de “José”? Me resulta curioso que le guste que le llamen así, pues según el DNI, no tienen nombre compuesto. En relación a los documentos que nos hace llegar Mª José, TS de la Mancomunidad Sierra de San Pedro, a quién pongo en copia, adjunto el RECIBÍ del REGLAMENTO DE RÉGIMEN INTERIOR, firmado digitalmente por su representante legal. Con respecto a los informes médicos, pauta de medicación y documentos similares, ya solicité a la Residencia de Santiago de Alcántara por escrito, que se nos los hiciera llegar tanto a la Residencia de Los Santos de Maimona como a mí. El documento de Autorización para la publicar fotos en Redes Sociales, a raíz de la Ley 8/2021 de 2 de junio, si la persona tiene capacidad para ello, puede dar ella misma el consentimiento. ¿Podríais preguntarle a él si le importaría salir en Facebook y demás redes en que hagáis publicaciones? Si es así, puede firmarlo y para mayor tranquilidad por vuestra parte, si lo consideráis, enviármelo firmada por él para que también acompañe la firma del Presidente de la CTAEx. Por último, anoto aquí el número de cuenta para el cargo en cuenta de la residencia" ·············································································································································································································································································································································································································································· Respuesta de Isabel, Directora Res.: "LA ADAPTACIÓN ESTÁ SIENDO MUY MUY BUENA. YO DIRÍA QUE YA ESTÁ ADAPTADO. ES UN SEÑOR DE CARACTER AFABLE Y SIMPÁTICO Y LA VERDAD QUE CUALQUIER INDICACIÓN QUE LE DIGAS, LA ACEPTA SIN NINGÚN PROBLEMA. DE ACUERDO AL TEMA DE LAS REDES SOCIALES Y RESTO DE DOCUMENTACIÓN SALUDOS" "CON RESPECTO AL TEMA ECONÓMICO, EL AYTO CARGA EN SU CUENTA EL IMPORTE DE LA MENSUALIDAD A MES VENCIDO Y A COMIENZOS DEL SIGUIENTE MES. ······················································································································································································································································································································· En relación al correo de Ángela, sobrina (aplaterorocha@gmail.com), respondo a ella y a la directora de la Res. de Los Santos: "En relación a las cuestiones que planteas, Ángela, desde la residencia pueden solicitar a la sección económica de la CTAEx una asignación mensual a tal fin, ya sea a través de retirada de efectivo por parte de tu tío en la sucursal (podría ser acompañado) o mediante transferencia a la propia residencia. La otra opción es que le carguen en cuenta este tipo de gastos. En relación a la necesidad de comprar ropa, es necesario remitir, también a la sección económica, presupuesto de ropa de la tienda en cuestión a nombre de ARTURO y, una vez aprobado por el Jefe de dicha sección, con factura posterior, se podrá proceder a abonarlo mediante transferencia bancaria directamente a la tienda."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='GARCIA'and apellido2='AMBROSIO'),'2023-05-24','TERESA ENVIO REVISION GRADO DE DEPENDENCIA Y REVISION DEL PIA PUES EL CENTRO CASA MISERICORDIA PADRE LEOCADIO ESTA ACREDITADO Y PUEDE COBRAR VINCULADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-05-24','Ana: Llamada de Anabel, TS SSASB Miajadas (927 34 70 00 / Directo: 927 90 12 38): está preocupada por la demora del juicio para el procedimiento de jurisdicción voluntaria para ingreso involuntario. ·························· Hablo con Ángel, Asesor Jurídico, argumenta que desde aquí ya se ha comunicado al Juzgado la gravedad de la situación y ya no van a llamar ni a escribir más. ······································· *Acuerdo con Maite, Jefa de Secc. y Anabel, TS Miajadas, que no registraremos la solicitud de plaza por emergencia social hasta que no sepamos la fecha de la vista para el internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-05-24','TERESA De Beatriz Mejias, se ha contactado con Virgina (casera) que comenta que puede que la mesa camilla se haya descolado y que la lavadora la compró nueva hace un año aproximadamente. Virginia ha explicado que, ya hace un año aprox., al igual que esta vez, la lavadora perdía agua, el técnico fue a verla y el motivo era que un tubo tenía un mordisco probablemente del perro de Beatriz. Virgina explica que como la lavadora era bastante vieja hizo la vista gorda y compró una nueva, con lo cual le extraña mucho que esté dando problemas ahora. Virgina comenta que, antes de llamar a ningún técnico quiere ver el estado de la lavadora y de la mesa, que llamará a Beatriz para quedar con ella ya que el hijo de Virginia está en Zafra y quizás pueda acercarse a echar un vistazo. Se ha llamado a Beatriz, se le ha dicho que le va a llamar en estos próximos días Virginia y que esté pendiente del teléfono, también se le ha comentado que la lavadora es nueva, según nos ha dicho la casera. Beatriz ha comentado que no es cierto, que esta lavadora ya le dio el mismo problema de pérdida de agua pero que la arregló el marido de Virginia. De cualquier manera seguiremos en contacto con ambas partes acerca del tema, se remitirá cualquier novedad al respecto. Beatriz, al despedirse ha dicho que iba a mandarnos la foto del ticket del calzado pero no se ha recibido nada. Al respecto de esto nos ha hecho el lio enorme, no ha justificado esto porque no ha querido basicamente, a tenerlo en cuenta para cuando solicite proximos extras, no le parecio bien comprarlo ese dia, y lo ha ido retrasando con excusas tontas, que si va con la hermana que si tal y si cual.. y nada, que no se ha comprado los zapatos y se ha queddo con el dinero. Lo ultimo ha sido , mandar una foto de una zapateria de madrid que dice que una amiga se los ha comprado.. en fin.. ni comentario merece. Por otro lado, con respecto al empadronamiento, desde el padrón informan de que la tutelada ya está empadronada en el piso en el que reside actualmente, la próxima semana se quedará con ella para apoyarla en la gestión de la ayuda a domicilio con la TS del Ayto de Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-05-24','TERESA CITA PARA VALORACION DEPENDENCIA 26 MAYO: para cuando vayan a valorarlo anotado , va a estar la compi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2023-05-24','TERESA RECIBO LLAMADA DE LA TRABAJADORA SOCIAL DE MONTERUBIO 924610025 PORQUE EL ALCALDE LE HA DICHO QUE PEDRO TOMAS ANDA PIDIENDO POR LA CALLE, DERIVO A FUTUEX mañana se va para allá precisamente, se ha hablado con la ts para mañana ir junto con Pedro, ella no lo conoce por lo que comenta, se lo ha dicho el alcalde que le ve que si pidiendo o lo que sea. A ver que opciones de intervencion comunitaria tambien plantean ellos, pero este hombe, por ej, al centro de mayores de su pueblo (ni a otro centro) quiere ir. Se hace compra de alimentación y para tabaco y no se le deja ni un duro, para qeu no pueda consumir. Aunque ya sabemos que luego se las apañan.. a el le deben dar dinero o algunas gratificaciones porque hace colaboraciones radiofonicas en el pueblo, para el ayto, etc.. está en cuñas en la radio, a menudo, asique alomejor obtiene algo que no sabemos. Tambien ahora comentaba que un amigo le invitaba a cannabis de vez en cuando.... Estuvo en salud mental en don benito hace poco, no le cambio nada, salvo que decia que dormia peor y le puso alguna medicacion mas para dormir. Pero no contempló nada mas el psiquiatra, ni Pedro dijo nada mas allá de lo que manifiesta en determinadas epocas, de estar mas de bajón y etc. El tema del consumo ya sabemos que rechazo cuando estaba todo preparado ingresar en la unidad de desintoxicación, en el CSS de plasencia y en el ECA que ha acudido durante un tiempo, no pueden hacer nada mas, porque ya habia tenido algunos positivos y sin apoyo comunitario no consideraban ponerle mas tratamiento, aparte del coste eco que le suponia...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2023-05-22','Ana: Correo a Paz Boticario, TS Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org): "Les informamos, que hemos tenido un pequeño brote de Covid-19. Alberto Molano Iglesias y D. Alejandro Montero Vázquez han sido positivos, pero permanecen sin sintomatología alguna."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-05-22','Ana: Correo a Paz Boticario, TS Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org): "Les informamos, que hemos tenido un pequeño brote de Covid-19. Alberto Molano Iglesias y D. Alejandro Montero Vázquez han sido positivos, pero permanecen sin sintomatología alguna."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-05-24','Ana: Correo-respuesta de Paula, TO CRR-Plas.: "comentarte que seguimos trabajando en relación al compromiso con la participación en su proyecto de vida. Esto implica un trabajo de identificación de objetivos personales y una meta vital que oriente esos objetivos (el ideal al que tender y respecto al cual los objetivos se van construyendo). Así Ceferino ha ido aumentando su responsabilidad frente al cuidado de su espacio personal, compromiso con sus intereses (realización de sus "sesiones" musicales), acudir a la mayor parte de sus citas y cumplir, con apoyo profesional con las tareas comunitarias (comedor). Todo esto se puede ir trabajando bajo la meta vital de lograr una vida más autónoma, y de forma más concreta, poder aspirar a pasar a piso supervisado. Aunque aún no hay fechas para esto, después del verano comenzaremos a hablar de ello de forma más concreta, pudiendo concretar nuevos objetivos y retos para orientar los pasos hasta el piso supervisado. Así pues, a futuro, si va logrando objetivos y pasa a piso supervisado con éxito, podréis ir valorando comprar o no un inmueble. Respecto a su proceso de recuperación aún le quedan pasos que dar para tener una alta terapéutica. Espero haber respondido a vuestras dudas, si necesitáis algo más." ······················ Lo reenvío a Maite, Jefa de Secc. y Ángel, Asesor Jurídico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2023-05-24','-Amalia : Resuelven a favor en la solicitud de VT en Ap3. Pasa a lista de espera con 20 puntos . Escaneo la resolución en su expediente digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-24','Ana: Envío correo a Toni-Futuex: "En relación a SATURNINO MIGUEL SALGADO, por favor, comprarle también un macuto/bolso de viaje, para que pueda trasladar sus cosas. Es una cuestión en la que no reparamos ni Mª Carmen, compañera del Hospital, ni yo. Nos hemos acordado esta mañana. Por otra parte, no tiene llaves de su domicilio en el hospital, así que no hay que ir a buscar la guitarra. Eso sí, comprarle entonces una armónica, por favor. Perdonad que no lo haya dicho hasta ahora, pero había pedido a las sección económica que me miraran posibilidades económicas, pues son muchas cosas a la vez y me acaban de pasar la nota. A día de hoy es viable."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2023-05-24','Ana: Reenvío correo-respuesta a Felisa Custodio, TS (trabajadora_social_alcuescar@imserso.es), y a Mabel, Directora (927 384 533 / mariaisabeljimenez@imserso.es), del CAMF Alcuéscar: "En relación a la llamada de esta mañana, Isabel, y el correo remitido, Felisa, comunicaros que, tras haber revisado la sentencia y haberlo valorado en equipo, desde la Sección Social del Gabinete Técnico de la Comisión Tutelar de Adultos, no vemos inconveniente en hacer cumplir el deseo de Esther de pasar una noche en un alojamiento de la misma localidad, Alcuéscar, con su actual pareja, dado que también ha asistido varias veces a visitarla al centro y ha facilitado todos los datos personales y relativos a la propia salida/pernocta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2023-05-24','Ana: Estrella comunica que José ha sido trasladado al C. Penitenciario de Cáceres el pasado día 22 de mayo de 2023. ·············· Finaliza la medida de internamiento el 22/03/2024. ······················· Amalia me lo pasará una vez finalice el "periodo de adaptación".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2023-05-24','Ana: Envío a Paz Boticario, TS Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org): la Autorización de Actividades Organizadas por el centro, debidamente firmada y sellada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-05-24','-Amalia , escribo a Luis Sanza-Calcedo , agente rehabilitador TF 667622229: nos ha enviado un familiar de M. Luisa Espinar del Arco esta documentación . M. Luisa está tutelada por esta Comisión. No se lee muy bien el documento ,pero creo que desde la Comunidad de vecinos se va a solicitar una subvención a la Junta; del "programa de conservación, seguridad y accesibilidad de la vivienda". Solicito nos informe y reenvíe la documentación pertinente . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-05-24','Ana: Correo de Arantxa, Directora de la Res. (parquedelprincipe@grupociudadjardin.com): "vuelve a decirme la sobrina si puede sacar a Maria, ya le he dicho que lo estáis decidiendo, dice que no es capaz de ponerse en contacto contigo." ···························· Mi respuesta: "llevo dos semanas con cursos, reuniones y viajes de trabajo, normal que no haya podido contactar conmigo. Precisamente hoy he estado hablando tanto con el Jefe de la Sección Económica como con el Asesor Jurídico, sobre las facturas que nos han enviado (relativas a trabajos contratados y realizados sin previa comunicación a la CTAEx, y por tanto sin autorización de la misma) y otras cuestiones. También nos hemos reunido, la sección social, y hemos determinado que hasta que no finalice el PROCEDIMIENTO DE REMOCIÓN DEL CARGO que la sobrina ha promovido en el Juzgado, no se va a autorizar las salidas de María, pues a día de hoy no se ha podido constatar que las sobrinas actúan de buena fe. La llamaré ahora para comunicárselo, pero si te insiste a ti, puedes trasmitirle este mismo mensaje." ······························· Llamo a Carmen Jimenez Xisto, sobrina, y le transmito ambas decisiones. ···························································································································································································································································· Correo de Alberto, Jefe Secc. Ecca., con respecto a las facturas remitidas por Carmen, sobrina: "tal y como hemos quedado, no abonaremos las facturas, en principio debido a que es un gasto que no se ha autorizado con carácter previo por la CTAEX. Estas personas no se han comunicado en ningún momento con nadie de la CTAEX para comentarles este asunto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-05-24','Ana: Correo-respuesta de Julián Álvarez Delgado - Gerente de COCEMFE (gerencia@cocemfecaceres.org): "Reviso lo que me has enviado y la semana que viene hablamos, esta semana son ferias en Cáceres y el viernes no trabajamos por lo que se concentra todo más. Gracias por tu correo, Tomás se pondrá muy contento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-05-19','Ana: Correo del PAF (pafmoraleja@mensajerospazex.es): "Nos ponemos en contacto contigo porque nos informó la semana pasada, la auxiliar que asiste a Pilar Díez, que Gloria terminaba su función. Comunicarte que, Pilar tiene consulta con su psiquiatra el día 12 de junio a las 13:50. También nos dice la auxiliar que envió factura de un viaje en taxi que se realizó el día 12 de abril, al centro de salud de Coria, que no se le ha abonado. Solicitamos información sobre si se ha asignado a alguien para ejercer las funciones que realizaba Gloria, si fuera posible, para comunicárselo a Doña Pilar. ·························· Comunico que aún están con el proceso de selección. Pediré la factura pendiente y comunicaré a la coordinadora de Futuex la necesidad de acompañamiento/gestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-05-24','miguel, me pide la abogada Eva, En relación a la solicitud de autorización judicial para gasto extraordinario de Julian Ramon Civantos, necesitamos: • sentencia judicial de incapacitación • aceptación del cargo • notas simples del registro de la propiedad de todos los propietarios del edificio (que recuerdo las habíais solicitado) rendición de cuentas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-05-25','miguel, envío a la abogada la documentación solicitada (notas simples, testimonio de incapacitación, nombramiento, aceptación del cargo) menos la rendición anual de cuentas (que no se está hecha)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-05-24','TERESA . Esta mañana desde las 6:00 am hemos estado recibiendo mensajes incoherentes y videos fuera de lugar de Beatriz. Hemos hablado con el Equipo de Salud Mental y no podían trasladarse a su domicilio, por lo que hemos ido nosotros. Nos la hemos encontrado muy incoherentes, muy angustiada, con muchas ideas delirantes, lleva sin dormir tres dias y no se toma la medicación desde el sábado. Por lo que hemos tenido que llamar al 112. Va ahora para la UHB de Llerena, donde supongo que ingresará. LLeva algo de ropa que hemos podido encontrar entre el barullo y la mierda que hemos encontrado, pero poca cosa y no tenía tabaco, por lo que supongo que su hermana necesitará. No sé cuanto tiempo estará ingresada, pero si el lunes le toca retirar el dinero, os pido que autoriceis a su hermana porque Beatriz ya no tiene dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-05-25','Ana: Envío correo a Toni-Futuex, con copia a Beatriz, Directora Res.: "En relación a JUAN GREGORIO LOZANO VALLE, me comunican desde la Sección Económica, que necesitan llevar a IBERCAJA, pues así se lo exigen ahora, el DNI para escanearlo. En Garrobillas de Alconétar no hay sucursal, por tanto habría que llevarlo a la más cercana, que es la sucursal bancaria de la Avda. de Alemania de Cáceres. ¿Podríais, por favor, encargaros de recoger el DNI en la residencia, y llevarlo a escanear a la oficina indicada? En la mayoría de ocasiones aceptan que le enviemos desde aquí el DNI ya escaneado. Pero en este caso nos obligan a llevar el original. Pongo en copia a Beatriz, Directora de la Residencia para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-05-25','TERESA Me ha llamado M Jesus que ha dejado el trabajo porque los clientes llegan borrachos y se meten con ella. Se vuelve a casa de su tía con lo cual volvemos a la situación inicial. Ella dice que saca el dinero cuando cobra ….. como este caso me vino derivado de Amalia estoy perdida en ese sentido, necesito información de como vamos a funcionar a nivel eco con ella… Yo la veo muy estable y super autónoma…. Quiere que le pidamos la revisión de la medida y me parece oportuno porque la sentencia es del 2015 y la situación de entonces nada tiene que ver con la de ahora…. Esta incapacitada totalmente y eso a ella le produce mas prejuicio que beneficio pues le angustia tener que depender de nosotros para gestiones que ella es perfectamente autónoma Me ha dicho que tiene cita en junio con el psiquiatra, le he dicho que le pida informe para pedir la revisión de medida por mejoría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-05-25','Ana: Llamo a ANA SOLEDAD PORRAS RAMOS, T.S. RESPONSABLE SERVICIO AYUDA A DOMICILIO Y TELEASISTENCIA - IMAS CC (927 21 23 35 EXT. 4420 // ana.porras@ayto-caceres.es) en relación a la solicitud de CATERIN. No obtengo respuesta. ·········· Le envío un mail. ······························································································································································································· Subo al portafirmas digital las solicitudes de SAD y de CATERIN municipales. ·································································································································· Correo de Ana Porras, TS responsable SAD y TAD: "Para SAD no hay modelo de informe de salud específico. Sólo para caterin. Ahora no puede solicitar caterin porque no está de alta en el servicio de ayuda a domicilio, siendo requisito indispensable. No procede solicitar caterin porque se le denegaría por no cumplir requisito, ok?" ············ De momento registraré sólo solicitud de SAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-05-22','TERESA Se ha puesto en contacto con el programa, e indica por teléfono que a final de mes se va a vivir a un piso de alquiler que son 350 euros mensuales, que firma contrato de alquiler mes a mes. Con el novio que vivia, lo dejó, volvio, y no sabemos que mas.. pero que no puede vivir con el. La tia tampco quiere. En la actualidad está trabajando en una sala de juegos por lo que tiene más soltura económica, (según dice ella, que el contrato tampoco lo hemos, cobra 1200 eu) pero en el momento que cese su actividad laboral, solo con la PNC es inviable asumir ese gasto. Ademas para este piso, tendria que pagar fianza, y según dice ella.. quiere retirar minimo 1000. Luego esta el tema de que si de verdad cobra eso, se tendra que informar a PNC.. y se la quitaran, pero le hemos pedido el contrato y no nos lo ha pasado. No ha cobrado aun, porque este es el primero que está trabajando . Cuando le hemos pedido el contrato para pasaroslo, nos dice "no os lo voy a pasar , prefiero tener una multa de pensiones". Expresa que ella no puede compartir vivienda, prefiere estar sola y asumir ese gasto aunque tenga que dejar de comer que volver a casa de su tía, de su padre o compartir piso. Ella tiene la intención de poder retirar más dinero ahora que tiene un sueldo. Se niega a escuchar y expresa "haré lo que me dé la gana". En 5 meses ha pasado de vivir con su tía, para irse con su novio, volver con su tía, retomar la convivencia con su novio, dejarse y volver con su padre, con su abuela y por último, compartir piso pues alquiló una habitación. A día de hoy, se encuentra de nuevo durmiendo en casa de su tía Manola. Ella dice que ha intentando hablar con la comisión, le hemos explicado que tal vez ella no pueda firmar el contrato, y determinadas cosas, pero esta cerrada a entender o colaborar en nada.. no se si consideras buena','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2023-05-25','-Amalia : me escribe Iris y me indica: Comunicarte que al curatelado Cristóbal García Casquero le dieron el alta hospitalaria en el Hospital Casaverde el pasado jueves día 18 y ha vuelto a nuestro Centro. Debe continuar con la rehabilitación en la clínica ambulatoria Casaverde que está situada aquí en Badajoz. Por ahora, descartamos solicitar un cambio de perfil porque consideramos que en principio, no va a ser necesario. Se ha recuperado bastante bien, aunque aún le queda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2023-05-25','-Amalia : me escribe Iris y me indica: Comunicarte que al curatelado Cristóbal García Casquero le dieron el alta hospitalaria en el Hospital Casaverde el pasado jueves día 18 y ha vuelto a nuestro Centro. Debe continuar con la rehabilitación en la clínica ambulatoria Casaverde que está situada aquí en Badajoz. Por ahora, descartamos solicitar un cambio de perfil porque consideramos que en principio, no va a ser necesario. Se ha recuperado bastante bien, aunque aún le queda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-05-25','Ana: Hablo con Pilar, Comedor Social de Obra Social La Milagrosa (671 01 66 15): Me comunican que Miguel Ángel acude a diario al comedor, pero ya no acude a dormir al CES. Está pernoctando en la estación de autobuses. ················· Le ha explicado que estando en la Comunidad Terapéutica La Garrovilla, solicitó la Ayuda de 200€ de la Agencia Tributaria. Se lo concedieron, pero le han cobrado comisiones y sólo le quedan 176,15 €. Ha ido a la sucursal y no le dejan sacarlo. ···················· Comunico a Alberto, Jefe Secc. Ecca. para que, si autoriza, envíen autorización bancaria a la sucursal de la C/ San Pedro. ······································································ Respuesta de Alberto: "AUTORIZAMOS REINTEGRO PUNTUAL X 140 €..." ························································································································································································································································· Realizo derivación al Programa de Apoyo Comunitario gestionado por Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2023-05-25','Ana: Tras llamada de Juan (613 112 091), escribo a Alberto, jefe de Secc. Ecca.: "He recibido llamada de Juan Chamorro, solicitando un extra de 200 €, para calzado, algo de ropa y pagar “deudas” que tiene en el pueblo. Me dice María que tiene en cuenta 9.236 €. Como desde Navidades no se le ha vuelto a dar ningún extra, por mi parte Ok a esta petición. Pedía poder sacarlo hoy mismo, le he dicho que no es posible y que se intentará para MAÑANA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-05-25','miguel, recibo contestación de la abogada Carmen Lucas: Ay que ver, si lo que pido es un informe de imputabilidad y esto son cuestiones de otro tipo ¿Es que nadie me puede dar un informe en que pueda basar una eximente completa? Lo he pedido por activa y por pasiva. Poco te puedo informar, el justiciable en principio aceptó un acuerdo, pero la acusación popular (la hermana de la víctima) no está de acuerdo, quiere más pena, más dinero y también quejarse contra supuestas irregularidades cometidas, así que me estoy preparando la vista, porque no sé ni qué va a suceder ************************************************** mi contestación: Gracias Carmen, sabrías decirme si sólo habrá una vista y tras ella se procederá a resolver? Se puede saber aproximadamente si aceptaran en el juzgado un acuerdo?. Lo del informe no está en nuestra mano, ya que aunque trasladamos tu petición no nos hicieron informe de inimputabilidad, aunque entiendo que conforme al artículo 20 Código Penal puede acogerse a la eximente, aunque la exención de responsabilidad deberá dictarla entiendo el informe del médico forense. En relación a la reducción, incluso exención de responsabilidad he encontrado este enlace en vlex por si te fuera de interés: https://app.vlex.com/#vid/584536558 Quedamos a la espera de dicha vista el 31-5-2023. ********************************************************* Reenvío ambos emails a la parte social (Ana y Maite) y a Soraya: Buenos días os envío la contestación de la abogada donde reconoce la intención de llegar a un acuerdo por Saturnino, frente a la oposición de la acusación popular. También os envío mi contestación a lo que ella indica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2023-05-25','Me indican que no tiene un coste la clínica de Badajoz. Que es asumido por la Seguridad Social sin necesidad de copago. Del tiempo que ha pasado en Mérida, no hay nada pendiente de pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-05-25','miguel, remito al abogado Jorge la renuncia a recurrir que solicitó','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2023-05-25','Ana: Recibimos Certificado Actualizado de Pensión de Jubilación SIN IMPORTE del INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-05-25','Ana: Recibimos el CERTIFICIADO actualizado DE PENSIÓN DE ORFANDAD: 832,80 € ································· Se lo envío a Isabel, directora de la Res. Municipal de los Santos de Maimona (rmayores@lossantosdemaimona.org).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2023-05-26','Ana: Correo de Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Te comunico que Yolanda Caldera irá de nuevo a su centro el lunes día 29 y hasta el día 7 de junio"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-05-25','Ana: Correo de Toni-Futuex: "Lo de Javier Agudo, ha ido mucho mejor de lo esperado. Finalmente ayer conseguimos contactar con el, también le habían contactado desde salud mental, hoy ha tenido un seguimiento allí, con la ts, enfermera y psiquiatra, le van a hacer una analítica a la semana (según han dicho porque tras el abandono del tratamiento hay que hacerlo así, al menos delante de el han dicho eso). Y que se va solicitar crps y crr por emergencia, el ha accedido, a ir donde hubiera plazas. También estaba medio convencido para acudir al centro de personas sin hogar, pero no había plazas para este fin de semana. Esta yendo a comedor, porque el desayuno si lo ha tenido incluido en el hotel, pero la comida no, al parecer ha estado comiendo de bocadillos. Tiene 200 euros todavía, más los 100 que iba a poder sacar. Asiqeu va tener dinero para poder comer y todo lo que necesite estos dias. Hemos encontrado, in extremis, un sitio para que se pueda quedar hasta el lunes incluida la noche del lunes, se llama hostal Dora, que ha tenido una cancelación y le permiten y está muy bien de precio, 38 eu la noche, como el tiene dinero hemos quedado que lo pague el con su dinero. Asique ya de cara a la semana que viene, a ver que se puede encontrar para que se quede, y esperemos que la plza para CRR se le tramite lo antes posible."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-05-26','Ana: Envío correo a Pilar, TS del Comedor Social CC - Obra Social La Milagrosa (oslamilagrosacaceres@gmail.com): "te escribo con 2 buenas noticias: 1. Se le autoriza a Miguel Ángel a retirar 140 € a partir del próximo lunes 25 (antes no pueden tener la autorización preparada y firmada para el banco). Alberto, Jefe de Sección económica, no quiere darle todo precisamente porque la cuenta le genera comisiones. La idea inicial era darle todo y cerrar la cuenta mientras no se le pudiera tramitar nada y abrirle otra cuenta llegado el momento. Y aquí viene la segunda buena noticia y motivo por el que no se le cancela. 2. Ya han modificado la Disposición adicional vigésima quinta del Real Decreto Legislativo 8/2015, de 30 de octubre, por el que se aprueba el Texto Refundido de la Ley General de la Seguridad Social. Por la que se aprueba la Asimilación a un grado de discapacidad igual o superior al 65 por ciento a aquellas personas para las que, como medida de apoyo, por resolución judicial, se les nombra un curador representativo. Así pues, si me es posible, hoy mismo, cumplimentaré de nuevo la solicitud de PNC y le daré registro. ¿Podrías por favor confirmarle que el lunes puede retirar el dinero? Por cierto, para que puedan hacer la autorización necesitamos saber a qué sucursal irá." ········································· Respuesta de Pilar: "Ana, no te puedo confirmar la sucursal porque ayer, Miguel Angel, no fue al comedor y hoy es festivo en Cáceres. El lunes, si va a comer, hablaré con él y te digo. Me alegro del cambio de la legislación y que pueda ser posible la tramitación de la PNC." ···································································································································································································· Cumplimento SOLICITUD DE PNC y redacto OFICIO indicando la modificación legislativa. ························· Remito a Julio-CTAEx, para que lo remita por registro al Serv. Territorial de CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESSA'and edp.apellido1='CARRERAS'and apellido2='PEREZ'),'2023-05-10','Ana: En relación a la petición que realizan desde NACE, de extra para la feria de CC, envío correo a Alberto y Estrella, Secc. Ecca.: "Pesto que el año pasado se les concedió 60, y todo ha encarecido mucho, se consensua desde la sección social que este año se apruebe un extra de 100€ para la feria."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2023-05-26','Ana: Llamo a Juan, varias veces, para confirmarle que se le ha aprobado el extra de 200€, que hoy mismo puede ir a retirarlo al banco, pero salta el buzón de voz. ············ Le dejo mensaje. ··················· Lo comunico a Toni-Futuex a título informativo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-05-26','-Amalia : va a Lourdes , ya se ha abonado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-05-26','Ana: Envío a Julio, CTAEx: "Adjunto COMUNICACIÓN DE CAMBIO DE DATOS (cambio de dirección del centro), relativo a MARTÍN MIGUEL MIRANDA HERNÁNDEZ, para que, cuando puedas, lo remitas por registro a la Sección de Dependencia de Cáceres ( Gerencia Territorial de Cáceres). Sección de Dependencia I Pza. Hernán Cortés, 1 C.P. 10001 CÁCERES BUZÓN de Registro Electrónico A11030403"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-05-26','Ana: Correo del Programa de Familia (programafamilia@tajosalor.es): "Buenos días compañeros, adjunto remitos los tickets de las compras de la semana pasada y la de hoy hechas por Aitor Moreno Felipe. Me dicen en la tienda que no se ha pagado la compra de la semana pasada, que deberían pagarse en la semana… Os lo reenvío por si no llegó. Otra cosa, Aitor me pregunta si no podría ir de campamento este verano como otros veranos anteriores." ································································································································································································· Mi respuesta: "Pues no habíamos recibido los tickets. Gracias, las compañeras de la sección económica se encargarán de abonarlos a la mayor brevedad. En cuanto a los campamentos, me temo que ya no tiene edad para ellos. Si estuviera en algún centro (como cuando estaba en Adiser) podía ir a los viajes que organizan desde los mismos. Ahora la única opción que se nos ocurre, y no sabemos si será de su agrado, son los CAMPOS DE TRABAJO que organiza la Junta, y tampoco sabemos si aún está abierto el plazo. Hoy no me da tiempo a mirarlo y el lunes tengo formación toda la mañana. Si queréis/podéis mirarlo vosotras y, en tal caso, ofrecérselo, os lo agradeceríamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-05-26','Ana: Correo de Estrella, CSS Plas, a mí y al ctutelar@: "Como sabéis Conchi Fernández Muñoz está ingresada en UME de este centro socio-sanitario y necesita dinero, he llamado al CRR y no tiene en metálico, así que solicito enviéis la autorización para que pueda ir un Ordenanza a retirar lo que tengáis estipulado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-05-26','Ana: envío a registro (oac.merida.san@juntaex.es): "En representación de D. CARLOS GONZÁLEZ LEO, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, os remito Solicitud de Servicio de Ayuda a Domicilio Municipal, junto con toda la documentación relacionada a continuación e indicada en la propia solicitud, para remitir por REGISTRO: - DNI de la persona interesada - Tarjeta Sanitaria - Certificado de Empadronamiento - Certificado de discapacidad del CADEX - DNI del Presidente de la Comisión Tutelar de Adultos - Testimonio de Auto de Nombramiento - Acuerdo de Aceptación del cargo - Decreto de Nombramiento del Director-Gerente del SEPAD - Resolución de delegación de competencias como Presidente de la CTAEX La solicitud va dirigida a: INSTITUTO MUNICIPAL DE ASUNTOS SOCIALES C/ Atahualpa, s/n 10005 – Cáceres CÁCERES"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-05-26','-Amalia : se lo paso a Alberto para verlo : uenas , hablamos el martes también de este caso . Jose Mª tenía cuentas compartidas con su hermano Juan . Se advirtieron pagos por internet que nos hicieron dudar de la buena administración de las cuenta por parte del hno. Lo que se planteó desde S. eco , fue abrir cuenta nueva , solo con nuestro tutelado y Jose Vicente y pasar a esa nueva cuenta las pensiones y la prestación dependencia . Me teneís que confirmar si ya está esto gestionado y tenemos que acordar la transferencia que tenemos que pasar al hno. para gastos. Abona a la empresa de SAD unos 700€ ( me dice el hno que lo hace él por transferencia ) , esta gestión tenemos que hacerla desde la CTAEX . Lo vemos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2023-05-29','-Amalia : finalmente no va a Chipiona , se le van a entregar los 480€ anuales concedidos que son de los que va a disponer para todo el año .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2023-05-29','-Amalia : finalmente no va a Chipiona , se le van a entregar los 480€ anuales concedidos que son de los que va a disponer para todo el año .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-05-29','-Tf de Isabel la auxiliar SAD contratada por la empresa : 634843266 Le he pedido pto. estimativo de gastos en común y de J.Mª solo. Hay que dar el Nº cuenta nuevo para que le carguen la comida a domicilio de 90€. Hay que pedir el Nº cuenta de la empresa de SAD para hacer transferencia del servicio . Al Sepad dar nuevo Nº cuenta para la PVS SAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-05-29','Ana: Correo de Toni-Futuex: "Eugenia Pacheco solicita una subida de asignación, comenta que se le dijo que no era viable por el tratamiento para dejar de fumar, pero ya acabó hace tiempo y continúa en la misma situación. Se le dice que se va a comunicar a la comisión y que harán un estudio de su situación de ingresos y gastos mensuales y se valorará si es viable solicitar una subida de asignación, la tutelada acepta. El 26 de abril, se acude al banco con ella a poner la cartilla al día y ver los movimientos de cuenta, en lugar de pedir extracto de cuenta porque ya le cobran 3´60€ por ello y Eugenia tiene libreta. Se revisan los gastos de los dos últimos meses, se comprueba que en el mes de marzo los gastos son los siguientes: -Asignación………………15€x5…………………………………………………………………………75€ -Residencia………………………………………………………………………………………………….279´68€ TOTAL………………………………………………………………………………………………………..349´68€ Teniendo de ingresos el subsidio por desempleo…………………………..480€ Por lo que en marzo ahorró………………………………………………………..125´32€ En el mes de abril los gastos fijos son los siguientes, contando con la retirada que va a realizar el viernes día 28, para hacerlo completo: -Asignación…………………………15€x4………………………………………………………………60€ -Residencia…………………………………………………………………………………………………279´68€ TOTAL…………………………………………………………………………………………………………339,68€ Igualmente, su único ingreso es el subsidio de 480€ Por lo que en el mes de abril ahorró……………………………………………..140´32€ Eugenia señala que todos los meses pasa por el podólogo que va a la residencia, el gasto son unos 4€, pero estos dos últimos meses lo ha pagado con algo de ahorros para demostrar que puede hacer frente a esos pequeños gastos si se le sube la asignación. Se plantea para la consideración de la comision tutelar, la posibilidad de que se le pueda subir a 20€/semana la asignación, de este modo, el gasto asciende a 359,68€, pudiendo ahorrar 120´32€/mes, exceptuando el mes que va a la peluquera, en el cual se gastaría 371´18€ y tendría un ahorro, por tanto, de 108´82€. En todo momento el ahorro es superior a 100€/mes. El hecho de la subida de asignación a Eugenia sería un refuerzo positivo bastante bueno, pues vería que su buen hacer tiene un recompensa y se podrían trabajar más aspectos para los que se mostraría, seguramente, más accesible, como es el área ocupacional." ····································································································································································································· Tras consulta a Alberto, Jefe responde: "OK A SUBIDA ASIGNACIÓN A 20 €/SEMANA (87 €/MES) A PARTIR 01/06/2023", "A CENTRO LE TIENE QUE QUEDAR CLARO QUE CON UNOS INGRESOS TAN BAJOS, CUALQUIER CUESTIÓN SOBREVENIDA QUE AFECTE A SU ECONOMÍA SE VERÁ REFLEJADA EN LA BAJADA DE LOS REINTEGROS"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-05-30','Ana: Envío correo-respuesta a Minerva, TS del CR Cervantes (minerva.salvador@salud-juntaex.es): "En relación a la solicitud de subida de asignación de Mª Eugenia Pacheco Vicente, desde la secc. económica aprueban la subida de asignación a 20€/semana. Copio su respuesta: "OK A SUBIDA ASIGNACIÓN A 20 €/SEMANA (87 €/MES) A PARTIR 01/06/2023", "A CENTRO LE TIENE QUE QUEDAR CLARO QUE CON UNOS INGRESOS TAN BAJOS, CUALQUIER CUESTIÓN SOBREVENIDA QUE AFECTE A SU ECONOMÍA SE VERÁ REFLEJADA EN LA BAJADA DE LOS REINTEGROS"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-05-29','Ana: Correo de Laura Bazaga, TS APTO (trabajosocial@asociacionapto.org): "Beatriz sigue pendiente de que le remitáis la asignación mensual. Me dice si la podéis aumentar un poco este mes porque tiene que ir al podólogo y a comprarse las cosas que necesita para el viaje a Almuñécar (maleta, bañadores y dinero para gastos personales durante la estancia)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-05-30','Ana: Remito a Registro (oac.merida.san@juntaex.es): "Adjunto la siguiente documentación relativa a BEATRIZ PARRA DOMÍNGUEZ, cuyo cargo de Curatela Representativa ostenta la CTAEx: - Solicitud de Prestación Familiar por Hijo a Cargo - DNI de la persona solicitante - DNI del Representante Legal - Testimonio de Auto de Nombramiento de Curador Representativo - Acuerdo de Aceptación del Cargo - Decreto de nombramiento dl Director-Gerente - Resolución Delegación de Competencias - Documento justificativo del Código IBAN Para remitir a la DIRECCIÓN PROVINCIAL DEL INSS de Cáceres Avda. de España, 14 10001 – Cáceres" ································································································································································································· En relación al correo de Laura, TS APTO: le indico que aún no tenemos acceso a sus cuentas, con lo cuál puede continuar retirando ella el dinero acompañada de su hermano, como habíamos hablado. ············· En cuanto a los gatos indicados, se contemplarán como gastos extraordinarios. Enviarán presupuestos. ································································································································································································· Correo pendiente de Laura, TS APTO: "Te adjunto los documentos necesarios para que podáis solicitar el reconocimiento inicial del grado de dependencia de Beatriz, tal y como acordamos. Te adjunto la solicitud cumplimentada (falta añadir los datos del representante legal), el informe de salud y el informe social que ha redactado la trabajadora social del SSASB de Ayto. de Navalmoral. En cuanto a las autorizaciones de los miembros de la unidad familiar indicados en la solicitud, no he podido adjuntártelas porque las hermanas se han negado a firmarlas (actualmente no se están mostrando colaborativas en los aspectos que conciernen a Beatriz, ni en las demandas que se puedan solicitar por parte de nuestra entidad). Beatriz lleva todo el mes en casa de su hermano, se tuvo que ir de su casa por el trato que estaba recibiendo." ···························································· Cumplimento lo que falta y subo al portafirmas digital la SOLICITUD de VALORACIÓN DE LA SITUACIÓN DE DEPENDENCIA, para su firma por el representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2023-05-30','Ana: Llamada de Jairo, pregunta por Gloria, Ed. Futuex. le explico que ya no trabaja en el programa y están realizando nuevo proceso de selección de personal. ·········· Quiere retomar la búsqueda activa de empleo para poder irse a vivir en un futuro de forma independiente. ······················ Lo comunico a Toni-Futuex, para cuando puedan comenzar a visitarle de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-05-30','Ana: envío a Miguel, Asesor Jurídico, los informes médicos facilitados por Leyre Sanz, TS de la Res. Mayores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-05-30','Ana: Llamo a Victoria, Dependencia (68467): me enviará resolución pendiente. Ya ha recibido la BAJA del SAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-30','Ana: Correo de de Puerto, TS SSASB (ssb5@mancomunidadvalledelalagon.es): "Buenos días: estamos observando a Enrique más alterado, lleva toda la cara tatuada con pegatinas completamente, hoy no ha abierto a las auxiliares del SAD, lo he llamado muchas veces y me dice que estaba dormido... Ayer soltó a su perro para que mordiera a una vecina según me informan en el Ayto, en su vecindario refieren que hay conflictos con él... por lo visto la mascota intenta morder a la gente y él lo fomenta... Enrique no cuenta con autonomía para vivir solo, necesita más apoyos que revisen su toma de medicación, horarios de descanso, comida y consumo o no de drogas" Quizás los vecinos del municipio terminen realizando escrito para que se actúe desde Fiscalía, si la situación va a mayores. Desde el SSASB y el SAD se le está intentando dar indicaciones y manejo de habilidades para su autonomía pero es muy complicado, tiene muchas fluctuaciones en el estado de ánimo. Lo que se comunica a los efectos oportunos," ··································································································································································································· Respondo a Puerto, con copia a Ana Benavente, ESM, y Toni-Futuex: "Decirte que, con respecto a los problemas con los vecinos, es normal que los vecinos se planteen comunicarlo a Fiscalía, y en estos casos de intento de perjuicio o perjuicio directo si el perro hubiera llegado a morder, solemos animar a las personas perjudicadas a que denuncien, pues es la única forma de que quede constancia y que se tomen medidas al respecto. Igual también es conveniente que lo sepan en el centro de salud, no sé si alguna podéis facilitarme el contacto de la compañera (que no sé quién es) y/o del MAP que le corresponda. Por otra parte, Puerto, si Enrique en algún momento actúa atentando contra la integridad de otras personas o la suya propia, no dudéis en llamar al 112. Eso también puedes decirlo a los vecinos y el propio ayuntamiento. Pues a nosotros, que no estamos in situ, sólo nos permiten activarlo cuando tenemos ya Orden/Autorización de Internamiento Involuntario. En cuanto a esto último, y lo que indicas en tu correo de que “no cuenta con autonomía para vivir solo, necesita más apoyos que revisen su toma de medicación, horarios de descanso, comida y consumo o no de drogas", lo único que podemos hacer es iniciar procedimiento de jurisdicción voluntaria para solicitar internamiento involuntario en centro adecuado. Y para ello necesitaríamos que no enviaras Informe Social actualizado en el que se haga constar dicha afirmación para adjuntarlo. Estos procedimientos suelen tardar, pues según nos han dicho, en más de una ocasión, no se consideran urgentes. Añaden siempre que los internamientos urgentes en recursos de salud mental, pueden promoverlo los Psiquiatras. Pero podemos intentarlo. Pongo en copia a Ana Benavente, compañera del Equipo de Salud Mental y a Toni, Coordinadora del Programa de Apoyo Comunitario, para que estén al corriente. Toni, por favor, en la medida de lo posible, intentad agilizar la próxima visita." ·································································································································· Respueseta de Toni-Futuex: "De acuerdo Ana, si podemos para esta o para la proxima sin falta, intentamos cuadrar un seguimiento, con alguna compañera mas del equipo ademas de la educadora de referencia, para poder "intervenir" si se puede o minimo hacer un informe de situación por si sirve de cara al juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-05-31','Ana: Asignación mensual acordada: 310 €, de los cuáles son 100€ para gastos de bolsillo, 10 € para la recarga del teléfono y el resto para la contribución a los gastos comunes de la casa (comida, agua, basura, electricidad, comunidad, butano, IBI...). ·································································································································································································· En cuanto a la situación con los hermanos, Laura, TS APTO (trabajosocial@asociacionapto.org) confirma "sigue con el hermano. Sigue todo igual, creo que están todos a la espera de ver qué ocurre el día 13 en el juicio. Toca esperar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELESTINO'and edp.apellido1='NAVARRETE'and apellido2='MURGA'),'2023-05-31','TERESA Celestino ha hecho un ingreso en cuenta de 1600€, me comenta Vansea la directora del Hernanod de Soto (21781) que el dinero lo tenia en su casa.... Ya le han explicado que no puede disponer de él pero solicitia una subida de asignacion','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-31','Ana: Como en otras ocasiones, llamo varias veces a José Ignacio, "Nacho" (670 743 476), hermano de Enrique: No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2023-05-31','TERESA Soy Dora Salamanca , la madre de Javier Fraile . Me dirijo a vosotros para manifestaros mi preocupación por mi hijo Javier. Lo veo emocionalmente inestable , con ansiedad , nervioso y por este motivo haciendo mal uso de la medicación a su manera. Sospecho que pueda estar tomando cervezas , bebidas energéticas y cafeína (a veces confirmado por él y siempre con la promesa de no volver a tomarlo). Su casa , está desordenada , no ayuda con las tareas a la chica que va a ayudarlo, solo fuma y duerme. Realmente no está preparado para vivir en autonomía e independencia . Ha perdido todas las habilidades adquiridas en el piso tutelado y no se hace cargo de tener su casa en orden y limpia. Querría saber si hay posibilidad de que vayan a supervisarlo y puedan hablar con él respecto a todo lo que ha conseguido y todo lo que puede perder . A lo mejor si tiene un toque de la comisión y una supervisión puede que reaccione, y si no reaccionase querría saber si hay posibilidades de que pueda volver a piso tutelado de nuevo . No sé , estoy muy preocupada y me da miedo que de nuevo , si no ponemos solución , pueda irse de las manos todo esto. María teresa , me gustaría poder ir a hablar contigo y poder contarte todo con detalle a ver de qué manera podemos solucionar esta situación antes de que vaya a más. Si tuvieras tiempo me gustaría poder ir a hablar con voostros, es muy importante para mí , porque la preocupación es muy grande !!!! . Muchísimas gracias por atenderme . Estoy a la espera de tu contestación . Qué tengas un buen día María teresa !! LA CITO PARA EL MIERCOLES 7 DE JUNIO A LAS 12 PASO INFORMACION A FUTUEX PARA QUE LO VISITE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-05-31','Ana: A petición de Marina Carmen Jiménez Cinta, Jefa de Secc. de Prestaciones II - PNC (924 005 922): entreo a la secc. ecca. CTAEx, ALTA DE TERCEROS, ya cumplimentado y sellado para que lo lleven al banco. ······································································································································································································ Llamada de Carlos (665 022 593), hablamos Maite y yo con él: Como el viernes pasado fue fiesta en CC, no pudo sacar su asignación, le explicamos que puede cualquier día de L-V, para que no le ocurra la próxima vez. ···· Mañana acudirá a sacar lo de la semana pasada y lo de esta (María, Secc. Económica, envía correo al banco para comunicarlo). ········ Aprovechando que retira los 100€, le pondrá la vacuna a una de las perritas que tiene. ··············· *Le explicamos que el Caterin municipal no se le puede solicitar hasta que tenga concedido el SAD. *Intentaremos que le asignen el servicio 2h/semana (1 h. cada día) a primera hora 9:00h. Pues sobre las 10 se va todos los días a un Estudio de Tatuaje en el que ayuda y a cambio le pagan con tatuajes y piercings. Allí pasa gran parte del día. ················· Ha comenzado a acudir a comer al comedor social de Cáritas. ······················· Por otra parte dice que necesita Tratamiento Bucodental, enviará presupuesto de clínica dental. ··············· Y enviará también presupusto de la Clínica Veterinaria, pues tiene que poner el chip + vacunas a uno de los perros. Tiene 2.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-05-31','Amalia, escribo a Seccion eco : Buenas , esta señora percibía 2 pensiones de Alemania ; de 2 organismos diferentes . Una de ellas he conseguido reactivarla , empezará a percibirla en Julio de 2023 , cuantía de 1011€ y le darán atrasos desde mayo unos 1900€ . Los atrasos que se deben desde 2022 - Diciembre , vendrá en otra notificación aparte que quedo pendiente de que me lo remitan. He vuelto a escribir a otro organismo diferente , a ver si podemos averiguar qué ocurre con la otra pensión que percibía de 764€ y que nos dicen que siguen enviando pero no sabemos la entidad . Anotaros comprobar en julio que nos hacen ese ingreso que os indico. Seguimos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-05-31','Amalia : remito a Eva contrato de Mi casa firmado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-05-31','Ana: Tras conversación con Julia (644 876 893), envío correo a Ángel y Miguel: "En relación a JULIA MORÓN HERNÁNDEZ, he hablado con ella y su madre. Informan que el pasado día 23 de mayo a las 9:30 acudieron a la Audiencia Provincial nº 2 de Cáceres, por un procedimiento abierto antes de estar a cargo de la CTAEx. No saben donde han puesto el papel de la cita, por lo que no pueden facilitarnos el Nº de procedimiento. La RESOLUCIÓN aún no se la han enviado. Dice que ha “ganado el juicio”, pues no tuvo que declarar al confesar los hechos y declararse culpable la persona denunciada por delitos de abuso sexual (ella fue la víctima). Los hechos ocurrieron hace unos 5-6 años en el barrio de San Lázaro de Plasencia. Es toda la información que he podido recabar. ¿Sería posible que llamaseis a la Audiencia para que nos hicieran llegar la resolución judicial una vez la tengan? Aunque los hechos acaecieron con anterioridad a la asunción del cargo por la CTAEx, considero que sería conveniente que obrara en nuestro expediente. A ver si con esos datos os la pueden facilitar." ··········································································· Pido a Lourdes, secc. económica, que abone el servicio de taxi. ····················································· A parte, Julia dice que necesita ropa. Le indico que envíe presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-05-31','Ana: Envío a Julio, CTAEx, para registro en SIREX: "En relación a BEATRIZ PARRA DOMINGUEZ, cuyo cargo de CURATELA REPRESENTATIVA, ostenta la CTAEx, adjunto la siguiente documentación para remitir a la UNIDAD DE VALORACIÓN DE DEPENDENCIA del SEPAD: - Solicitud de Valoración de Dependencia - DNI de la persona interesada - Informe de Salud – Anexo II - Informe Social – Anexo IV - Testimonio de Auto de Nombramiento - Acuerdo de Aceptación del Cargo - DNI del Representante Legal - Decreto de nombramiento del Director Gerente del SEPAD - Resolución de Delegación de competencias del Consejero"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2023-05-31','Ana: En relación al escrito recibido por SIREX, de IFAR FORMACIÓN S.L. (ifar2010@live.com, envío CORREO-E a Alberto, Jefe Secc. Ecca.: "Por lo que puedo deducir del escrito adjunto, desde enero hay una empresa nueva que está gestionando la residencia municipal de Guijo de Granadilla, en la que reside NEMESIA GARCÍA PANIAGUA. Al parecer no está al corriente de pago la plaza desde entonces. ¿Podrías comprobar todo esto en su cuenta y contactar con la empresa/ayuntamiento para aclararlo y actualizar los pagos? En el escrito viene nº de teléfono y dirección de e-mail, de lo que entiendo es la empresa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2023-06-02','TERESA Envio a inss dcitamen tecnico facultativo solitido por el organismo en relacion a pfhc','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-06-02','Ana: Llamada de Felisa, madre de Aitor (626 164 402): Dice que Aitor le está tratando mal, le grita mucho, le habla mal y de forma "muy borde". Y le pide dinero para porros y cuando no se lo da le monta un escándalo, "se pone muy agresivo". ·············· Todavía no ha ido a a la sucursal de Trujillo a retirar la tarjeta monedero. ·············· Está yendo con un amigo a las fiestas de los toros de los pueblos (Moraleja, Coria, entre otros). ············· Todos las semanas gastan bastante más de 100€ en el supermercado, porque Aitor come mucho. Después de cenar se fríe 4-5 huevos todas la noches. Y se bebe 2 litros de leche al día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-06-02','Ana: Llamada de Felisa (626 164 402): Dice que Aitor le está tratando mal, le grita mucho, le habla mal y de forma "muy borde". Y le pide dinero para porros y cuando no se lo da le monta un escándalo, "se pone muy agresivo". ·················· Todos las semanas gastan bastante más de 100€ en el supermercado, porque Aitor come mucho. Después de cenar se fríe 4-5 huevos todas la noches. Y se bebe 2 litros de leche al día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-06-02','Ana: Correo de ayer de Mª Carmen, TS del HSPA (mariac.rodriguez@externos.salud-juntaex.es): "Buenos días, informar que Saturnino M. Salgado Jiménez es trasladado hoy, a la UME de Plasencia, siguiendo las consideraciones de la Comisión Regional de Casos celebrado el pasado mes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-06-02','Ana: En relació a la solicitud de Empadronamiento en Cedillo y el documento de ingreso en centro, contesto a Mª José Acosta, TS Mancomunidad Sierra de San Pedro (mjacosta@mancomunidadsierrasanpedro.com): "Adjunto la Hoja de Inscripción en el Padrón Municipal, firmada por el Presidente de la Comisión Tutelar De Adultos, como representante legal. No lo envío directamente al ayuntamiento ni le doy registro, porque, de acuerdo a la Ley 8/21, el propio Julián Ramón tendría que firmarla también. Dejo el hueco a la izquierda para que pueda hacerlo. Si lo imprimís a color supongo que no tendréis problema. En cuanto al otro documento que envías, los dato no están bien. Es nombre compuesto: NOMBRE: JULIÁN RAMÓN APELLIDOS: CIVANTOS FERNÁNDEZ De todas formas, podríais, además de modificarlo, enviar el documento firmado, sellado y con la fecha de la firma? Lo necesitamos para el expediente y para hacer comunicación al Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-06-02','Ana: Correo de Laura, TS - IMAS (laura.dominguez@ayto-caceres.es): "Buenos días Ana! Te adjunto la resolución de concesión de la ayuda para suministros mínimos vitales de Montaña. La luz la pagamos directamente a iberdrola nosotros, pero el gas lo debe abonar ella, ya que se lo ingresamos en cuenta, porque no tenemos convenio con gas extremadura. Te adjunto si te parece también la factura que presentaron sus padres. Vinieron ayer por aqui preocupados por este tema. Presentarán otra factura que les ha llegado recientemente, cuando tengamos resolución de esta factura te la hago llegar también." ············· Le indico que ha olvidado adjuntar los documentos.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-06-02','Ana: Respuesta al correeo de Sara, TS R.M. Banium Residencial (TrabajadoraSocialBanium@hotmail.com): "Te he llamado, y ya me ha dicho tu horario. Puesto que tengo curso presencial toda la mañana L-M-X, no podríamos hablar hasta el jueves. No obstante, decirte que no hemos recibido el la CLAUSULA DE NOVACIÓN DEL CONTRATO que mencionas. Por otra parte, la modificación de la tarifa de precios, entiendo que tenéis que enviarla desde el Centro al SEPAD. Supongo que de ese modo procedéis cuando la persona no tiene ninguna curatela o cuando la ejerce una persona física (familiar). *El documento de “Cláusula de novación” que envías, la iba a poner a la firma del Presidente de la CTAEx, pero no está bien cumplimentada. Debe poner, en lugar de “COMISIÓN TUTELAR DE ADULTOS”: D. JOSÉ VICENTE GRANADO GRANADO, PRESIDENTE DE LA COMISIÓN TUTELAR DE ADULTOS. // DNI: 76015154Q. Con domicilio en: AVDA. DE LAS AMÉRICAS, Nº 4 de MÉRIDA. Mediante testimonio de SENTENCIA. Cuando nos lo envíes modificado lo pongo a la firma y te lo hago llegar." ······································· *Icíar, Secc. Ecca., confirma que ya han hecho las transferencias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-06-02','TERESA ENVIO SOLICITUD DE INFORME SOCIAL AL AYTO DE MONTINJO TRAS CONVERSACION CON EL PSICOLO DEL CAMP LAS CRUCES ME COMENTA QUE TANTO LA MADRE COMO LA HIJA MUESTRAN INTERES EN VERSE E INCLUSO HACER SALIDAS AL DOMICILIO MATERNOÇ ACTUALMENTE LAS ESTA HACIENDO AL DOMICILIO PATERNO PARA PODER ASEGURAR LAS SALIDAS EN UN AMBIENTE IDONEA DADO LOS ANTECEDENTES DE LA MADRE NOS GUSTARIA TENER MAS INFORMCION SOBRE LA SITUACION ACTUAL DE LA MADRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-06-05','Ana: Reenví a Alberto, Jefe Secc. Ecca. el correo remitido por Laura, TS IMAS-CC: "Te adjunto la resolución de concesión de la ayuda para suministros mínimos vitales de Montaña. La luz la pagamos directamente a iberdrola nosotros, pero el gas lo debe abonar ella, ya que se lo ingresamos en cuenta, porque no tenemos convenio con gas extremadura. Te adjunto si te parece también la factura que presentaron sus padres. Vinieron ayer por aqui preocupados por este tema. Presentarán otra factura que les ha llegado recientemente, cuando tengamos resolución de esta factura te la hago llegar también."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2023-06-05','TERESA Te escribo para comentarte algunas cosas. La semana pasada me ausenté un par de días de casa, mi madre fue al banco a cobrar y se gastó parte del dinero en comprarse unas prendas de ropa que le hacen falta, aquí te mando la factura para ver si me lo podéis reembolsar a mí para comprarle algo de comer hasta que vuelva a cobrar esta semana, son solo 11,98 euros, pero es que después también se suele comprar de vez en cuando otras cosas como por ejemplo una pasta dentífrica especial para dentadura postiza que cuesta alrededor de diez euros y ni me da ticket ni nada y ya cuando me manda a comprar pues es poco lo que le queda y ya le tengo que ayudar yo con lo que pueda. Le tengo dicho que ese dinero es para comprar comida, que todo lo demás pues yo misma se lo compro y ya después me hacéis vosotros una transferencia, pero ella como siempre pues hace lo que le parece. Entonces no sé en ese aspecto pues qué hacer, creo que sería más conveniente que me hagáis a mí la transferencia de lo que cobra semanalmente y ya se lo gestiono yo, al menos mientras yo siga aquí, porque ella termina haciendo con el dinero lo que le da la gana. También me gustaría saber qué pasaría con ella cuando yo no esté aquí porque tarde o temprano lo más seguro que me tenga que volver a ir de casa a trabajar fuera y mi madre sola pues, lo mismo no va a ponerse la inyección, a día de hoy dice que se toma la medicación y no es así, también para hacer la compra y demás ella sola no se apaña… Había pensado en la posibilidad de solicitar en el ayuntamiento ayuda a domicilio aunque sea un par de horas al día para echarle una mano a mi madre y ver que está bien y demás. Por otro lado, he de decir que no se cuida lo suficiente, no lleva una dieta equilibrada y abusa mucho de refrescos, azúcares y cosas poco saludables, le tengo dicho que tiene que comer mejor, pero nada. Y en cuanto a higiene personal, pues más de lo mismo. Yo intento ayudarla en todo lo que puedo pero ella se siente bien consigo misma así. Hay otro asunto que hace un tiempo os comenté y con el cual ya no sé qué hacer porque siempre me he visto sola en todo esto… Mi madre es heredera de un patrimonio bastante considerable por parte de mi abuela que falleció hace unos tres años. Se trata de varios terrenos y propiedades en Zalamea de la Serena y alrededores, solicité el servicio de un abogado aquí en Azuaga hace unos años y ya pasado todo este tiempo no tengo noticias. El caso es que habría que hacer el reparto de la herencia mitad a mi madre y mitad a mi tía que también está incapacitada judicialmente, os lo comento por ver si me podríais ayudar en este aspecto porque de tomar yo una decisión creo que optaría por rechazarlo todo puesto que se me acumulan todos los recibos del IBI de todos los años y yo pues no tengo tanto dinero como para afrontar todo esto y llega un momento en que me siento frustrada y agobiada. Espero tu respuesta y muchas gracias de antemano','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2023-06-05','Amalia : LLega resolución del INSS , por error informático se le había suspendido la PFHC desde hacía bastante tiempo. Lo he gestionado y se vuelve a reponer la prestación , le ingresarán unos 13.000€ de atrasos . A la sección económica , por favor , confirmad que se ingresa ese dinero en la cuenta. Nuria , puedes seguir teniendo en cuenta esta prestación para el servicio que le prestáis desde el Ayuntamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='CACHO'and apellido2='LINDO'),'2023-06-05','Se comunica desde el CSS de Mérida el traslado de D. José María Cacho Lindo en el Hospital de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-06-05','-Amalia : hablo con Julio , Dtor. Granadilla , quedo pte. que nos indique qué dia quiere hacer el traslado a la R.M. Olivenza . Desde CTAEX se le pondrá ambulancia+ acompañante de Cruz Roja . Estamos pte. de recibir el pto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2023-06-05','.Amalia : en su expediente archivo opción de PNC , Y se deja la PFHC de menor de 18 años que venía percibiendo. La firma la DTRA. del Centro que es quien estaba de titular de la misma .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-06-05','-Amalia : el padre de Alberto ha enviado un email a ctutelar y a Oscar , para que le ingresen en su cuenta 1000€ de varias cosas que ha pagado a su hijo y que no estaban previamente autorizadas por la CTAEX ni por la parte social . Alberto no lo va abonar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2023-06-06','Ana: Envío correo a Pilar (pilarcortcer@gmail.com): "Adjunto CONSENTIMIENTO INFORMADO para RESECCIÓN TRANSURETRAL DE VEJIGA, relativo a JUAN JOSÉ HORNERO RODRÍGUEZ, debidamente firmado y sellado por el presidente de la CTAEx."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='CACHO'and apellido2='LINDO'),'2023-06-06','-Amalia : ingresado en Hospital de Merida desde el CSS . Van a contratar acompañamiento hospitalario unas horas .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-06-06','Desde el programa de apoyo social comunitario se realiza nota de las gestiones llevadas a cabo en el seguimiento presencial del día 22 de mayo para informar de los nuevos cambios en relación a la situación laboral de Antonia. En primer lugar, se concreta el seguimiento para darse de alta como demandante de empleo. Al regresar de la oficina de empleo recibe una llamada del grupo SIFU para la incorporación a un puesto de trabajo. Le solicitan como documentación para formalizar el contrato; DNI, número de la Seguridad Social, Certificado de discapacidad (al ser empleo protegido) y certificado de la demanda de empleo. Aprovechando que estamos realizando el seguimiento preparamos todo y lo llevamos a la oficina de SIFU. El puesto de trabajo es para la limpieza y mantenimiento de la piscina del Casino de Badajoz. El horario es de lunes a jueves de 15h a 18h. Las instalaciones abren el próximo 5 de junio, pero la incorporación al trabajo puede ser esta misma semana para la preparación de las instalaciones. La duración del contrato es para los 3 meses de verano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-06-06','Lo de M Rosa de Valdelacalzada, que me comestate en el email. En resumen desde el equipo se considera que esta mujer tiene un poco de morro.... Ella querría ir a la compra a cualquier supermercado y por su cuenta, porque tiene un problema con esa gestión. Ya sabe que es en día, y con supervisión y acompañamiento. Ella querria pues pedir por internet y que se lo llevaran a casa o que fuera alguien por ella.. vamos que es bastante poco lo que hace, se le proporciona bastante ayuda. Normalmente se va con ella y se le ayuda con las bolsas y se le lleva en coche.. (se le apoya, casi que demás, porque es un poco "comodona" la señora). La semana pasada en cuestión, tuvo un par de dias y es habitual, que se encontraba mal que mejor ese dia que se habia previsto no fuera la compañera.. y estas cosas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS CARLOS'and edp.apellido1='FRADE'and apellido2='PARRA'),'2023-06-06','LOURDES: SUBIMOS REINTEGRO A 200 €/QUINCENA. LOURDES/AMALIA: LA MEDIA REAL ANTES DE ESTA SUBIDA YA ES DE 400 €/MES----INDICAR A CENTRO QUE ESTA SUBIDA SE REALIZA PARA NO TIRAR DE EXTRAS. LOURDES/AMALIA: AMALIA, EN 02/2023 HABIAMOS DICHO QUE SE IBA A CONTRATAR TELEFONO X 15 €/MES----A DÍA DE HOY NO HAY NINGÚN CARGO X ESTE CONCEPTO (NOS OLVIDAMOS DE ESTE ASUNTO).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2023-06-06','-Amalia : comunican traslado al Ctro. Penitenciario de Caceres . Ha sido trasladado el 20 de mayo. Las gestiones en cuenta peculio se han hecho y se le va a seguir ingresando la misma cuantía económica . cid:image001.jpg@01D95C12.D0AC4DA0cid:image002.jpg@01D95C12.D0AC4DA0cid:image003.gif@01D95C12.D0AC4DA0 Carla Trabajadora Social Secretaría General de Instituciones Penitenciarias Centro penitenciario de Madrid VII Crta. M-241 km 5.7 CP. 28595 Estremera (Madrid) Telf: 91-8755585 FAX: 91-8750033','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-06-06','-Amalia : Emi tiene entrevista de valoración para UME el jueves a las 12 , la llevarán en ambulancia desde la UHB de Badajoz.','2');
