insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-06-06','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Buenos días, comunicar que ayer en la tarde, se produjo el alta de la UHB del HSPA de Cáceres de la persona usuaria Consuelo Nevado Pacheco." ··························· Mi respuesta: ", ¿habéis hablado con Consuelo la posibilidad de traslado al CRR de Plasencia? Consideramos que puede ser una alternativa para ella y no sé si ella estaría dispuesta a ese cambio. De lo contrario, si continúa con sucesivos ingresos hospitalarios corre el riesgo de que se quede sin opción a estar en vuestro centro por no reunir criterios y, como sabéis, regresar al domicilio familiar no es una opción adecuada para ella. Ya me dices cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-06-06','Ana: Correo de Miguel, Asesor Jurídico: "Buenos días, adjunto la sentencia. Le imponen el internamiento en Centro Psiquiatrico Penitenciario finalmente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-06-07','TERESA RECIBO LLAMADA DE GLORIA TRABAJADORA SOCIAL DE MONTIJO EN RELACION A LA PETICION DE INFORME SOCIAL SOLICITADO SOBRE M CARMEN MILLON PAVON DNI 08854769E ME COMENTA QUE LA HA DESHAUCIADO, ELLA MISMA HA ENTREGADO LAS LLAVES DE LA VIVIENDA EN EL JUZGADO LA SEMANA PASADA LO MA PROBABLE QUE YA ESTE VIVIENDO EN BADAJOZ PUES NO HA IDO A LOS SERVICIOS SOCIALES A SOLICITAR NINGUNA AYUDA CONSULTADO LOS DATOS DEL PADRON AUN APARECE EMPADRONADA EN MONTIJO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2023-06-07','TERESA Nos piden desde el juzgado para la revisión de medidas de Paco que asista al juzgado de Castuera, en 10 días a partir de hoy. Organizar acompañamiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2023-06-07','TERESA Quería hablaros sobre el tutelado José López Ruíz, con DNI núm.: 11778025R. Este paciente está actualmente institucionalizado en Residencia de mayores COMSER de Almendralejo, ocupando una plaza socio-sanitaria Tipo T1 de cuidados intensos y continuados. Su plaza es revisable cada tres meses hasta un máximo de seis meses. Él ingresó con nosotros en COMSER el 29-09-2022. El caso es que ha perdido la condición como residente T1 y da puntuación para ser residente T2, pero tendría que trasladarse a otro Centro donde hay este tipo de plazas, en concreto CK Villafranca Senior en VILLAFRANCA DE LOS BARROS. Para poder gestionarle la plaza preciso contactar con el Centro de Salud de Referencia para que se la gestionen, pero precisaría de vuestra autorización como responsables de él, para ir moviéndole todo. Ayer nos visitaron los responsables de T1 (Nuria Blanco, Rocío Guisado y Nuria Paniagua), y estuvimos viendo caso por caso. DECIMOS TRALADO A NAVALMORAL QUE ESTA MAS CERCA DE SU LOCALIDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='IGLESIAS'and apellido2='MENDOZA'),'2023-06-08','Ana: Envío a Rosa Bravo el Consentiento Informado para la Cirugía de Cataratas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-05-09','Ana: Correo de Toni-Futuex: "El día 5 se contacta con Javier para ver qué tal había pasado la noche y demás, comenta que todo bien, pero está sin dinero, se le dice que si no retiró nada antes de volver o a la llegada, comenta que no, que no tiene nada… Se le dice que para comer, de momento, podria comer en el hotel. Ya me comentaste ayer, que podia retirar de momento la asignación, no sabemos muy bien en que la estará gastando.. mañana va la compañera para allá. Hoy lo ha localizado por teléfono, despues de bastantes llamadas (dice que no estaba pendiente del teléfono porque se sigue encontrando mal) que tiene cita en el médico para el viernes 12. No ha mirado pisos ni nada... Pero quiere que sea compartido, se le ha comentado que en busquedas por internet no se ha encontrado nada, insiste en que no quiere vivir solo, entonces se le ha propuesto que busque alguna pensión, porque el hotel es muy caro para mantenerse ahí. Se le ha dicho que se va ir para apoyarle en esta busqueda pero que también tiene que moverse y buscar mientras tanto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-05-30','Ana: Correo de Anabel, TS SSASB - Miajadas (servicios.sociales@miajadas.org): "Adjunto Informe (anexo IV) en relaciópn con la solicitud de centro residencial con carácter prioritario correspondiente a JOAQUINA MAYORAL PIZARRO; en relación con la vista, logramos hablar con el Juzgado, y al parecer se está a la espera del informe del medico-forense, para fijar la vista, no se... me parece raro cuando este tuvo la videollamada ya el pasado dia 17 de mayo. Os ruego de verdad, intentar darle en la medida de lo posible prioridad a este expediente, de lo contrario lamentaremos que a esta persona le pase algo en su domicilio, nuestra ayuda es absolutamente insuficiente y la carencia de red de apoyo, unida a su nula conciencia de enfermedad hace que la situación de riesgo para su vida sea evidente, debido fundamentalmente al no seguimiento de las pautas medicas prescritas así como a la mala gestión de la alimentación, sin contar la pesima gestión de su presupuesto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2023-06-08','TERESA Ayer nos reunimos con la madre y la hermana de Javier, Dora y Mercedes. Solicitaron reunirse por la situación actual de Javier. Comenta que le pide dinero continuamente, a nosotros también no está solicitando extra. Parece ser que esta consumiendo mucho café, coca cola, etc. e incluso se sospecha que consuma porros. No está siguiendo de forma correcta la pauta de medicación con lo cual sospechamos que se está descompensado. La madre nos plantea la posibilidad de tener una mayor control de la medicación y para ello propone que se le prepare todos los lunes un pastillero semanal. Sería posible que la educadora le prepara ese pastillero todos los lunes? Le he insistido que a la mínima que ella vea que esta descompensado activen el 112. Me temo que tarde o temprano terminara ingresado dado a la trayectoria que lleva estos últimos meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2023-06-08','TERESA TERESA Ayer nos reunimos con la madre y la hermana de Javier, Dora y Mercedes. Solicitaron reunirse por la situación actual de Javier. Comenta que le pide dinero continuamente, a nosotros también no está solicitando extra. Parece ser que esta consumiendo mucho café, coca cola, etc. e incluso se sospecha que consuma porros. No está siguiendo de forma correcta la pauta de medicación con lo cual sospechamos que se está descompensado. La madre nos plantea la posibilidad de tener una mayor control de la medicación y para ello propone que se le prepare todos los lunes un pastillero semanal. Sería posible que la educadora le prepara ese pastillero todos los lunes? Le he insistido que a la mínima que ella vea que esta descompensado activen el 112. Me temo que tarde o temprano terminara ingresado dado a la trayectoria que lleva estos últimos meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-06-08','Ana: En relación a la petición del Juzgado, solicito a Toni-Futuex que nos facilite los datos y contacto de la hija de Joaquina si los tienen o, en su defecto, que intenten conseguirlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-06-08','Amalia: envio email a ctutelar y Alberto para actualizar todo lo de este expediente. Hay que actualizar todas las cuentas de este usuario . Se le ha abierto una cuenta nueva en B. Pueyo a Jose Mª , separando así las cuentas de las de su hermano. Ingresos de Jose Maria : PFHC ... 679.99 € * 12 PAGAS P. ORFANDAD ABSOLUTA ... 536.15€ * 14 PAGAS P.V.SEPAD .......................... 465,70€*12 PAGAS TOTAL INGRESOS ............. 1681,7 En la nueva cuenta ya se le cargan las pensiones ( pedí el cambio de Nº cuenta) y falta cambiar el Servicio de Prestación Vinculada del SEPAD . Estoy con esa gestión. Hay que hacer una transferencia permanente al Nº de cuenta que indica la dueña de la empresa Leonor Hurtado en su email por la prestación del servicio de ayuda a domicilio. Son 812€ al mes . Se debe el de mayo que también hay que abonar. He facilitado el Nº cuenta nuevo al Ayto . y ya le han cargado 90€ /mes del servicio de comida a domicilio. Os paso otro correo con el Nº de cuenta de su hermano Juan ,para que se le haga transferencia permanente de 600€ al mes , empezamos ya con el mes de junio . El hermano tiene domiciliado en su cuenta todos los gastos de vivienda , sumistros , decesos , seguros , .. TOTAL GASTOS : 1502€ AHORROS APROXIMADOS AL MES : 179€ Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-06-08','Ana: Envío a los A. Jurídicos, con copia a Maite, los informes remitidos por Anabel, TS SSASB Miajadas: Informe Social actualizado a fecha de ayer 07/06/23 e Informe de la Guardia Civil de hoy. ···································································· Llamo Anabel, TS SSASB Miajadas (927 34 70 00 / Directo: 927 90 12 38): en relación al empeoramiento y gravedad de la situación. ···················· Hablo con Ángel, A. Jurídcio, remitirán los documentos al Juzgado para que los tengan en cuenta en ambos procedimientos (Internamiento y Revisión de Medidas Judiciales de apoyo).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-06-09','Ana: Como en otras ocasiones, llamo varias veces a José Ignacio, "Nacho" (670 743 476), hermano de Enrique, pero no obtengo respuesta. ···························································································································································································································································· Llamo también a su tío José Luis (637 826 463 - nº facilitado por Ana Benavente): dice que no quiere cobrarle a su sobrino las facturas pendientes, que lo hizo por ayudar y no se lo quiere cobrar. *Se muestra colaborador y se ofrece a ayudar en lo que esté en su mano. ··· Habla con él casi a diario y cuando pasa días sin hablar con él se preocuapa y llama a otros vecinos del pueblo. ················ Agradece la gestión económica que se hace desde aquí, pues entiende que es fundamental para Enrique. ············· Pregunta por la herencia de la madre de Enrique, pues teme que los hermanos puedan hacerla de modo que le perjudique. *Le digo que en teoría no podrán finalizar los trámites sin la firma del Representante de Enrique.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-06-08','-Amalia : he estado en contacto con los compañeros del CSS , hablé con Juanjo y Manoli para asegurar que tenían toda la información necesaria . Emi ha tenido la entrevista hoy , pasa a lista de espera para ingresar en UME en breve . El ingreso será voluntario , les ha pedido ingresar lo antes posible , les ha comentado que ella allí se encuentra mejor . La plaza del CRR Olivenza la pierde , pasará por UME y URH y cuando se encuentre bien volverán a pedir la plaza en CRR .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-06-09','Ana: Soraya Masa, Jefa U.P.A., nos envía SENTENCIA. Establece MEDIDA DE SEGURIDAD de INTERNAMIENTO EN CENTRO PSIQUIÁTRICO PENINTENCIARIO por tiempo máximo de 3 AÑOS. + MEDIDA DE SEGURIDAD DE LIBERTAD VIGILADA a posterioridad con OBLIGACIÓN DE SOMETIMIENTO A TRATAMIENTO MÉDICO PSIQUIATRICO, por tiempo de 10 AÑOS. Y obligación de participar en PROGRAMAS FORMATIVOS DE EDUCACIÓN SEXUAL.','2');
