insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-06-09','TERESA TRAS CONVERSACION CON PSICOLOCO CAMP 20111, ACORDAMOS PEDIR INFORME SOCIAL A SASB BADAJOZ PARA TENER MAS INFORMACION SOBRE LA MADRE DE NATALIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-06-08','TERESA RECIBO LLAMAD DE M CARMEN 666898994, MADRE DE NATALIA ME COMENTA QUE YA ESTA VIVIENDO EN BADAJOZ EN CALLE LOS CANDILES N 30, ES UNA VIVIENDA DE ALQUILER. EL PADRE LE AYUDA A PAGAR EL ALQUILER SE OFRECE PARA COMPARTIR LAS SALIDAS DE FINES DE SEMANA Y VACACIONES DE NATALIA CON EL PADRE MANIFIESTA TENER UNT TRATO CORDIAL CON EL PADRE DE NATALIA','2');
