insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2023-06-09','Ana: Envío correo a Felisa Custodio, TS CAMF (trabajadora_social_alcuescar@imserso.es): "Adjunto las Solicitudes de Certificados de Beneficiarias de PNC, relativas a: - Isabel Debon Chenique - Mª Carmen Gómez Muñoz Supongo que le das registro tú, ¿no? ¿o quieres que las envíe a registro yo ya os envíe los certificados cuando nos los hagan llegar? Ya me dices."','2');
