insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2023-06-09','Amalia : Luisa va ir al INSS a solicitar pension de +65años de Suiza. Le indico que la solicitud tb la tiene que firmar el rpte.legal. Se le pasa el Nº cuenta donde hay que abonarla. Pido que me envien todo para firma y rgto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-06-09','Ana: Correo de Julián Álvarez Delgado - Gerente de COCEMFE (gerencia@cocemfecaceres.org / 927 23 90 28): con respecto al acompañamiento de Tomás para salidas, se justificarán mediante declaraciones juradas mensuales. Serán 3 h/semana. ························ Informa también que ha cogido mucho peso y no creen que obedezca a la alimentación del centro. *Están pendiente de cita de endocrino por la Seg. Soc. ··········· Preguntan si podría ir a un nutricionista privado, en caso de que la cita por la seguridad tarde mucho. ········ En tal caso enviarán presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-06-12','Ana: correo de Rosa Bravo, CSS Plas: "En la mañana de hoy, (9:45 h.), está previsto el traslado del paciente Saturnino M. S.J. al Centro Psiquiátrico Penitenciario de Sevilla. Dicho traslado se realizará en ambulancia y escolta de la Guardia Civil."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-06-12','Ana: Reenvío a Alberto, Jefe Secc. Ecca., correo de Laura, TS - IMAS (laura.dominguez@ayto-caceres.es): "Buenas Ana! Perdona que te escribo otra vez, los padres de Montaña han vuelto a venir por aqui por el tema de los suministros. Traen ahora una carta de deuda con la diputación por el tema del agua. Dicen que ellos pagaron toda la deuda que tenian de agua, pero imagino algunas facturas ya habrían pasado a ejecutiva. Os la adjunto para que podáis pagarla. De todas maneras me dicen que ahora les pasan a ellos las facturas del agua, podriais poneros en contacto con ellos para domiciliarlas a la cuenta de Montaña?? Te adjunto la carta del oargt."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-06-12','RESPUESTA DE ALBERTO: LA RESPUESTA, QUE SERÁ PUBLICADA EN DOE, ES NO SE VA A ABONAR (ESTRELLA) UNA MULTA DE 800 € APROX. X POSESIÓN. EL RESTO DE FACTURAS ABONADAS X PADRE, NO SE ABONARÁN X NO TENER AUTORIZACIÓN PREVIA CTAEX Y HABER SIDO ADVERTIDO EL Y RESTO FAMILIA DE CUAL ES EL PROCEDIMIENTO A SEGUIR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-06-12','Ana: Envío a Registro (oac.merida.san@juntaex.es): "En representación de D. Javier Agudo Cumplido, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, os remito Oficio-Solicitud de Certificado Actualizado Prestación de Supervivencia: ORFANDAD, junto con documentación indicada en el oficio para enviar por registro a: DIRECCIÓN PROVINCIAL DEL INSS DE CÁCERES AVDA. DE ESPAÑA, 14 10001 – Cáceres"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-06-12','TERESA El pasado viernes Felisa Bruno Saavedra se creó una cuenta en Facebook, siempre supervisada por el personal de apoyo de la vivienda donde se encuentra. Felisa en todo momento ha verbalizado que se acuerda del nombre de su madre, de su hermano, de su prima Saray, por ese motivo hace una búsqueda en la red social mencionada y encuentra a Saray, se pone en contacto con ella y le pasa el teléfono y Facebook de su madre. Tras realizar la búsqueda realiza una videollamada, con la suerte, que su madre coge esa llamada a la primera. En esa llamada se van agregando personas, su hermano, su cuñada, su hermana pequeña, sus abuelos…en todo momento la llamada es supervisada por el personal, para controlar que no se dan datos de Felisa antes de pedir permiso. Mi pregunta es, ¿puede Felisa mantener contacto con la familia? ¿puede viajar a Mérida a ver a su hermano?, su madre está embarazada de nuevo y Felisa quiere verla. Su familia en todo momento verbaliza que se harán cargo de todos los gastos que necesite Felisa, ropa, productos de higiene, incluso un teléfono móvil para mantener contacto con ella. Os voy a adjuntar un documento que realizaron las dos personas que estaban de apoyo en la videollamada, donde al final del documento aparecen los teléfonos que proporcionó la familia a Felisa, por si en algún momento os queréis poner en contacto con ellos. Yo estoy a la espera de que me digáis como proceder en este caso, ya que no se si existe alguna medida cautelar para que Felisa no mantenga contacto con sus familiares, o por lo contrario es algo que para ella sería muy positivo, ya que está en su meta personal encontrar a su familia. Voy a estar esta mañana en Cáceres en una reunión que tengo a las 10:00h, pero si me gustaría, que cuando puedas María Teresa, me llames y hablemos sobre el tema, ya que actualmente ella está muy contenta por lo acontecido estos días, pero me preocupa el tener que comunicarle que no puede tener contacto con ellos…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-06-12','TERESA Felisa actualmente se encuentra en el proyecto mi casa de Don Benito Como podéis ver en e correo que me manda el responsable del proyecto Felisa ha encontrado a su familia y quiere conocerla e incluso visitarla He leído al sentencia y con respecto a sus padres habla que tras la separación de los mismos el padre no quiso hacerse cargo de ella y la madre manifestó ser incapaz de hacerse cargo de ella En el año 2018 el padre está en prisión cumpliendo condena y la madre solicita poder visitar a su hija. Felisa tiene problemas de conducta, ya en el centro de Don Benito ha presentado alguna a pesar de su buena adaptación al mismo. Parece ser que el reencuentro con su familia es algo muy importante para ella ya que fue abandonada cuando tenia 12 años y siempre ha estado buscando a su familia. ¿Cómo gestionamos este reencuentro? Es necesario hacer una comunicación al juzgado? Felisa manifiesta querer contacto con su familia y visitarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2023-06-12','TERESA Me han llamado de la empresa Servicios del Freno que la auxiliar ha dejado el trabajo por las circunstancias en las que se encuentra Adolfo El hermano ya se ha marchado a trabajar fuera. Han enviado a otra auxiliar pero al tercer día también ha cesado Comenta que se pone muy agresivo y las auxiliares tiene miedo, además de que nadie de Villafranca quiere ir a este domicilio. Van a intentar esta semana encontrar a alguien y si no lo encuentran darán de baja el servicio. Si finalmente nadie asiste al domicilio solicitaremos de nuevo ingreso involuntario pues se quedaría solo en el domicilio con lo que eso supone Solicito visita de la educadora para valorar situación actual de Adolfo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-06-12','Ana: Conversación con Cristina, Ed. Vera (681 14 39 11 / 927 460 598): Ya ha pasado el periodo de adaptación de Proyecto Mi Casa y los 6 meses que se le guardaba la plaza. Por tanto hay que firmar el documento de baja en Asociación Vera - Plena Inclusión. Nos enviará el documento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-06-12','aaaa','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2023-06-12','-Amalia , escribo a los jurídicos: Buenos días, ha contactado conmigo la hna. de Agustín, que está ingresado en R. Mayores. Tienen una casa familiar , que pertenece según la hna. a 4 hermanos. *********************************************************** miguel, contesto a parte social y economica: Buenos días, antes de alquilar hay que saber cuál es la voluntad del tutelado y si la parte económica está de acuerdo con alquilar. En cuanto nos confirméis ambas cuestiones desde el punto de vista social y económico hablaremos con la inmobiliaria. Alguna persona de contacto? ********************************************************** email de Amalia: Buenas , el tutelado tiene Alzheimer , no creo que llegue a entender el alcance de este alquiler . Desde la parte social no hay inconveniente en este alquiler , el resto de hermanos está de acuerdo y lo hacen más que por el beneficio económico que será bajo por tener la vivienda mantenida , lleva mucho tiempo cerrada y se les está cayendo. Os he pasado el tf de la persona que gestiona esa inmobiliaria. ***************************************************** contesto a parte social y economica: Buenos días, en su día este hombre tuvo capacidad para autorizar a su hija dar 10.000€. Por lo que si desde la parte económica y la social no hay inconveniente dicho contrato de alquiler debe ser firmado por él y por José Vicente en nombre de la Ctaex. Voy a hablar con la inmobiliaria para que nos pase el contrato ******************************************************** Hablo con la inmobiliaria 689799322 de Aliseda y queda que me enviará el contrato. Lo llamaré de nuevo porque el email que me da no es correcto. La van a alquilar , está ubicada en C/ Tomás Pizarra de Aliseda ( Caceres ) Os paso tf. de la inmobiliaria : 689799322 para que podáis contactar , es para que firmemos por Agustín para poder alquilarla . Supongo que tendréis que echar un vistazo al contrato de alquiler también. Es urgente , el chico que la quiere alquilar la necesita cuanto antes. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-06-12','-Se recibe email del Centro La Luz . La tutelada Juana Remedios Palomo González se encuentra ingresada en la unidad de psiquiatría en el Hospital Universitario de Badajoz desde ayer al mediodía. Ayer domingo por la mañana durante un paseo con las cuidadoras salió a correr, distanciándose del grupo con el que paseaba. Una de las cuidadoras cogió un coche y pudo seguirla. A su vez, avisaron a la Policía Nacional y les indicaron donde creían que estaba. La Policía se dirigió al sitio indicado y allí la encontraron. Debido al estado de agitación que presentaba, decidieron junto con Felipe, trasladarla al Hospital Universitario de Badajoz. Una vez en el servicio de Urgencias de dicho hospital, siguió mostrándose muy agitada e intentó de nuevo volver a escaparse, sin conseguirlo, ya que estaba custodiada por la Policía. Cuando veía a Felipe y a la cuidadora se mostraba más alterada. Los psiquiatras que la atendieron, al ver el estado en el que se encontraba y ver sus antecedentes de fuga, decidieron ingresarla en la unidad de psiquiatría. La psiquiatra que habló con Felipe le manifiesto que consideraba que no debía volver a nuestro Centro, ya que, según ella, no se trata del recurso adecuado para ella. Según le refirió, su intención es derivarla al centro sociosanitario de Mérida o Plasencia. Quedaron con Felipe en ponerse en contacto con nosotros, pero aún no lo han hecho. Cuando tengamos más noticias las pondremos en vuestro conocimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-06-12','-Amalia : envio email a Sandra , DTRA .de Aexpainba: Buenas Sandra , vamos aclarar el tema de las cuotas de socio de los 2 usuarios de los que la CTAEX es representante legal y están actualmente en AEXPAINBA . Desde hace meses venís solicitando que ambos sean socios de la entidad para poder beneficiarse de unos servicios que a nivel privado presta la misma . De ninguno de ellos se había dado autorización previa , porque antes hay que comprobar que sea viable económicamente , y esa gestión se hace desde la Sección económica de esta entidad. -Juan José Murillo Romano , efectivamente , como decías no es socio y no se le está cargando ninguna cuota . Se confundió el nombre con el de Jose Mª . De momento , no se le va hacer socio de la entidad . -Jose Mª Rodriguez Moya , el martes te envié un email en el que comunicábamos que se aceptaba la cuota como socio , concretamente de 90€ al mes . Pero esta cuota se le está cargando desde febrero de 2023 ( justificado con la consulta de movimientos de su cuenta bancaria que te facilité ) . Te adjunto tu email del 30/03/2023 en el que volvéis a solicitar a la CTAEX autorización para que continúe como socio, cuando el 07/02/23 ya se la había cargado la cuantía de 90€ en su cuenta . En ninguno de esos emails nos comentáis nada del protocolo de baja como socio que tiene la entidad . Concretando , Jose Mª , va a seguir siendo socio como te indiqué el martes y se aceptarán las cuotas que se han cargado desde febrero y que no se habían autorizado . La solicitud firmada por Jose Mª para ser socio tenéis que reenviárnosla para tenerla en su expediente . Así mismo , solicitamos que nos indiquéis los servicios a los que tendrá derecho al ser socio . Para futuras acciones , no se puede cargar en cuenta nada que previamente no esté autorizado desde CTAEX , dado que tenemos que presentar Declaración Anual de cuentas al juzgado y todos los ingresos y gastos tienen que quedar justificados. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-06-12','tf de Isabel la auxiliar SAD que tiene en el domicilio 634843266 Esta chica no me da confianza , va 70h contratada por la empresa SAD de dependencia pero luego acude otras que paga Juan y que desconocemos. Nos pregunta sobre el dinero de los hermanos y no quiere que se controlen las cuentas a Juan . ( hno )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2023-06-12','tf de la hna , Isabel 622686274','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2023-06-12','tf de su marido , Angel : 618436443 Nos comunica que Castillo salió de madrugada de la casa en pijama y que la ha localizado , está ingresada en la UHB del H. de Mérida . La ha estado viendo Alfredo de la Rubia , al parecer esta semana la va a ver otro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-06-12','TF DE JUAN : 685281056 /924366711 TF DE LA TS DE VILLAGONZALO , GUADALUPE : 675259326','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-06-12','Amalia : se le ha abierto expediente disciplinario , será trasladada a R. M. en Olivenza ,en Virgen de Guadalupe. Julio quería que fuese con 112 pero no es posible ,ni hay autorización judicial . Se le pasa pto. aceptado con traslado de Cruz Roja . Quedamos pte. que nos indique el día del traslado . A su pareja lo van a trasladar a Don Benito. Se hicieron gestiones con vivienda , para valorar esta posibilidad y no es posible . Ella va en silla de ruedas , no tiene capacidad de administración económica , ni para las AVD .. No podría vivir sola ni con su pareja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-06-05','-Amalia : se envía firmado contrato Mi casa .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-06-12','-Amalia : hago gestiones con las pensiones de Alemania. Envio fe de vida y se levanta la suspensión para una de las pensiones. Escribo a otra dirección para averiguar donde se ingresa la otra pensión que no aparece en su cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-06-12','Respuesta de Adela , PNC En primer lugar, el cobro indebido que tiene esta señora es de 12.299,60 € correspondiente al período del 01/06/2019 al 31/10/2021, pertenece a un expediente que se extinguió. Esa deuda se envió a la Tesorería General de la Seguridad Social el 16/02/2022, es a ella a la que le tienes que preguntar que importe queda por abonar y que importe es el abonado, ya que ellos son el órgano recaudatorio. En segundo lugar, con respecto a la suspensión del pago del 01/05/2023, ella comunica en 04/2023 que vive sola, ya que tenía una cuantía (411,92 €) establecida en función del nº de beneficiarios de pnc en la misma unidad familiar, y comunica actividad laboral. En la notificación de suspensión se le requirió documentación, la cual fue aportada el 17/05/2023 ( comunica fin de la actividad laboral) , en base a ella se va a resolver ya para el mes de julio ( ten en cuenta que nosotros trabajamos con un mes de antelación). Si ha habido otra variación, como es la que comentas, nos la envías registrada para poder revisar nuevamente el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-06-13','Ana: Correo de Inés, Adtvo. Secc. Jurídica CTAEX: "Hola compis, os traslado Providencia referente al procedimiento de Internamiento Involuntario en relación a Doña Joaquina Mayoral Pizarro. Señalamiento el prox día 05/07/2023 a las 11:00 horas. Se adjunta Cedulas de Citación e Informe del Médico forense. Ya lo he subido a su expediente." ·························· Lo envío a Anabel, TS y Toni-Futuex, para que se organice el traslado y acompañamiento. ································································································································································································· Correo de Anabel, TS del SSASB Miajadas: "Gracias por remitir la información, respecto al traslado, si podriamos hacernos cargo, aunque no es imprescindible con lo que me genera dudas, considerando que lo que ella pueda aportar no va a ayudar en nada, y probablemente falte a la verdad, si quieres lo comentamos cuando tu puedas, tambien considero que debemos esperar a que a ella se le haga llegar la citación y ver si demanda o no ayuda para dicho traslado, te recuerdo ademas que este en mayo pidio dos veces taxi para ir a Merida y tengo sospechas de que hoy tambien lo vaya a hacer, con lo que me parece una incongruencia mas pagarle nosotros uno para ir al Juzgado, cuando ella a pesar de su situación, utiliza este servicio de forma absolutamente innecesaria."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-06-13','TERESA Perfecto, mañana tengo pensado en ponerme en contacto tanto con el hermano como con su madre, para ver cuáles son las intenciones que tiene, ya que he hablado con Sonia (Asindi), y me comenta que este acercamiento con la madre ya se ha realizado en anteriores ocasiones y que acaba desapareciendo de nuevo. Mañana le pediré todos sus datos, les diré que tengo que hacer una hora de registro para saber, si en algún momento Felisa va a visitarles, dónde estará. Me parece lo más correcto comenzar ese acercamiento poco a poco mediante llamadas supervisadas, incluso videollamadas y ya con el tiempo alguna visita de la familia a la vivienda. sergioromerodiaz@plenainclusiondonbenito.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-06-13','MEDIDAS JUDICIALES DE APOYO En cumplimiento del Auto n.º 44/23, de 20 de abril, por el que se dictan medidas judiciales de apoyo para D. Doroteo, se procede al cambio de expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-06-13','TERESA ME LLAMA AITOR PARA DECIRME QUE HA PEREDIDO LA TARJETA QUE LA BLOQUEEMOS EN EL BANCO NOS DICEN QEU TIENE QUE SER EL QUIEN LA BLOQUE LLAMANDO AL NUMERO 952076264 LE LLAMO Y LE INDICO QUE LLAME Y LA DE DE BAJA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-05-09','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Tras el alta de la usuaria Consuelo Nevado Pacheco en el día de ayer, adjuntamos incidencias recogidas por el equipo rehabilitador en el día de ayer y la mañana de hoy: Llaman para decirnos que le dan el alta. Va la monitora a las 13:30 horas a recogerla. Le modifican el tratamiento. En el camino hacia el centro, llora en varias ocasiones y refiere "la medicación actual no me sienta bien". A su llegada al centro, se muestra delirante y realizando interpretaciones constantes sobre las compañeras a Juan Mario. Llora en varios momentos al referir que Juan Mario le a dejado y no le da el cariño que ella quiere, aun pasando gran parte de la tarde juntos. Se le ofrece medicación de rescate, rechazándola. Insulta a varias usuarias del centro, alterándose éstas por la situación reiterada de insultos hacia ellas, expresando no poder sostener la situación. Tras la cena Consuelo llora en la segunda planta al haberse metido Juan Mario en su habitación. Refiere a gritos que Juan José es el demonio y M Ángeles, “una puta de las de la biblia, que la tenían que matar para estar todos libres”. Se le ofrece medicación de rescate, no accede a su toma. Regresa a su habitación refiriendo que no ira a urgencias al indicarle que de no tranquilizarse se activaría protocolo, cierra la puerta de la habitación diciendo “no me vais a ingresar”. Al inicio del turno de noche, escuchamos gritos y voces. Al ir a supervisar estado, nos hace referencia a lo mismo que el turno anterior (que Juan Mario no le quiere, insultos hacia compañeros, etc.). Se le ofrece medicación de rescate, pero no la quiere, aunque sí pide la de la noche. Se le da a las 22:10 horas. Baja en 4 ocasiones más, en el mismo estado, por lo que se le vuelve a ofrecer la medicación de rescate y la acepta (22:50 horas). Durante este periodo varias personas usuarias expresan su malestar con la situación, los gritos y los insultos. A las 23:10 horas, vuelve a acudir a la sala de monitores, expresando querer que se llame al 112 para valoración. Al continuar con un estado de agitación, nerviosismo y ser incapaz de controlar el llanto y los gritos, se decide llamar al 112, para valoración. Tras hablar con el técnico del PAC, nos pasan para hablar con el Dr. Medina (psiquiatra de guardia), al que informamos del estado de Consuelo. Nos indica que le demos un comprimido de Olanzapina 10 mg, ya que ellos no pueden desplazarse para hacer valoración al centro. También nos dice que, de continuar con el mismo estado, se hable con su psiquiatra de referencia. Se marcha a su habitación, saliendo al pasillo en tres ocasiones más, regresando enseguida a su habitación. Al hacer la ronda, se encontraba dormida. A primera hora del día de hoy se muestra con labilidad emocional, pasando del llanto al enfado de manera rápida. En el desayuno no quiere tomar la medicación, tras mucha intervención, la toma. Se observa buscar de manera descontrolada a Juan Mario por todas las plantas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-06-13','Ana: Coversación con Pedro, TO, y Cristina, Psicóloga, CRR - CC: En el equipo consideran que es mejor que hablemos nosotras con Consuelo para plantear el traslado al CRR-Plas. Pues considerean que esta propuesta puede afectar negativamente a la Relación Terapéutica. Ellos se lo han insinuado alguna vez y Consuelo se muestra reticente. ········································· Maite, Jefa CTAEx y yo, llamamos a Consuelo. Al preguntarle como está dice que no está bien. Su discurso denota delirio activo "...Yo soy la Virgen de...". ······· Expresa mucho miedo a que le "quiten" a su novio. Dice que en el centro hay mujeres que se lo quieren quitar. ················· También expresa que quiere dejar de fumar, pues el tabaco hace daño a sus bronquios. ············· Ante la propuesta de traslado al CRR de Plasencia se niega en rotundo, por no querer separarse de su novio Juan Mario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-06-13','Ana: Tras hablar con Pedro, TS de Centros de la Gerencia Territorial de Cáceres (927 00 42 39), envío correo a Minerva, Ts de C.R. Cervantes (minerva.salvador@salud-juntaex.es): "Acabo de hablar con Pedro, me dice que no es necesario hacer nada con respecto a la solicitud de traslado a Plasencia. Eugenia está la primera de la lista de traslado para la Res. de Hervás y también para San Francisco de Plasencia. Como los ingresos en Plasencia están paralizados por las obras de la residencia, no cree que le llamen antes de ahí. Y en el remoto caso, se podría hacer una renuncia en el momento y solicitar que permanezca sólo en la lista para Hervás. Esperemos que el traslado a Hervás no tarde mucho. No sabe exactamente, pues como sabes, de cada 5 ingresos uno es traslado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE DOLORES'and edp.apellido1='VARGAS'and apellido2='CHAVERO'),'2023-06-13','-Amalia : hablo con el TS del SSASB , Jose Julian 685398572 , le informo que voluntariamente aceptamos la limpieza del solar del que tb es propietario Jose. Sigue en CSS Mérida. Nos indicarán como proceder al pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2023-06-13','-Amalia : archivo en su expediente el rgto. para la revision de PNC enviado por Ap3 para que le den la cuantia total , ya está empadronada allí','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-06-13','Se le ha abierto cuenta nueva en B. Pueyo , ya tiene cambiadas las pensiones PFHC , P. ORFANDAD ABS, P.V.SAD. Se hace transferencia pte. a la empresa SAD de 812€ por 70h. y a su hno. Juan de 600€ al mes para cubrir todos los gastos en comun +90€ silla de ruedas .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-06-12','TERESA RECIBO LALMADA DE ROSA HERMANA DE BEATRIZ 696337732 BEATRIZ ESTA INGRESADA EN LLERENA, ESTA AISLADA NO PUEDE VER A NINGUNA FAMILIAR HASTA QUE MEJORE VAN A VALORAR DERIVACION A UME ROSA SOLICITA TRANSFERENCIA A SU CUENTA DE LA ASIGANACION QUINCENAL PARA PODER COMPRAR LO QUE SU HERMANA NECESITA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-05-10','Ana: correo-e de Mª Jesús Gutiérrez, Psiquiatra ESM - Plas. (mariajesus.gutierrez@salud-juntaex.es): "Remito el informe que me pides. Te señalo que ayer ya la dra gomez y el etac realizo visita a domicilio del paciente, por lo que la psiquiatra de refrencia de alfonso a partir de ahora será ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-05-10','Ana: correo de Óscar, secc. ecca., a Juan Manuel Cañas Lozano, hermano de José Blas: "Enviaremos autorización para 240€ mensuales para gastos de manutención y asignación personal de José Blas. Necesito que me confirmes que la oficina es la de San Pedro 15, para enviar allí la autorización. En cuanto a la compra de ropa, nos enviáis contestando a este correo electrónico, la factura o ticket de compra y se realizará una autorización de reintegro extra posteriormente, para que pueda sacarlo José Blas, acompañado por ti."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-05-19','Ana: Maite y yo realizamos visita a Guadalupe en su domicilio junto con Montaña, TS de SSASB. ·············· Después mantenemos reunión las tres con el ESM de Trujillo, en el C. Salud. ······················ *Elaboramos ACTA con acuerdo e itieneraio que se considera más adecuado. (*Guardado en el expte. digital con los Informes).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-06-13','Ana: Tras reunión mantenida en días previos con Soraya Masa, Jefa UPA, Maite envía a Soraya Informe Social elaborado por la CTAEx (Maite y yo), para que remita a Fiscalía junto con el acta de la reunión, para que pueda solicitar con con carácter urgente ingreso en UME, emergencia social - grave riesgo para la salud e integridad. (Informe guardad en el expte. digital).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-05-11','Ana: Correo de Puerto Paniagua, TS SSASB: "Buenos días Ana: sí, Enrique continua pidiendo extras, ahora para higiene bucodental, la verdad es que siempre va a estar solicitando más dinero, pues es su afán... según tengo entendido el equipo de salud mental no se desplazó a verlo, fue telefónico. A Virginia de FUTUEX sí la vi el jueves y estuve hablando con ella, coincide conmigo al respecto. Por lo demás, con las dos auxiliares de SAD parece ser está bien... hoy voy a Valdeobispo y seguro que lo veré porque acude todas las semanas... Te remito el presupuesto adjunto del dentista de Enrique."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-05-15','Ana: Correo de Laura, TS - IMAS (laura.dominguez@ayto-caceres.es): "Te escrito para informarte que los padres de Montaña han presentado en registro la solicitud de la ayuda para suministros mínimos vitales en nombre de Montaña, asi les dije que lo hicieran para que fuese más rápido. Solo informaron, que la deuda que tiene de luz la pagaremos directamente de iberdrola, y el gas le ingresaremos en su cuenta las facturas que vayan presentando sus padres y la debeis pagar. También informaros que le solicité el bono social."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-06-13','Ana: Recibimos RESOLUCIÓN DEL INSS aprobatoria de la PFHC a nombre del Representante Legal. Fecha de efectos: 01/07/23. Importe mensual: 453,30 € x 12 pagas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-06-13','Ana: Recibimos del INSS los Certificados Actualizados de Pensiones de Orfadad Absoluta (1.050,19 € x 14) y Orfandad Simple (248,39 € x 14) solicitados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-06-14','Ana: Envío correo a Toni-Futuex: "En relación a ENRIQUE SANTOS GARCÍA PUENTES, dos cuestiones: - ¿Podrías preguntar a Virginia, Educadora, si sabe si ha acudido a una cita en la clínica dental a finales de mayo? La comisión tutelar aún no había dado autorización a tal fin. Agradeceríamos que le recordaseis que hasta que no se aprueban los presupuestos por el Jefe de Sección Económica no puede contratar servicios del tipo que sean. Primero es necesaria la autorización. - Por otra parte, me comenta la TS del SSASB que ya se han quejado varios vecinos de que les está pidiendo dinero, incluso entra en las casas a tal fin. Ella misma no entiende que no le llegue el dinero para sus gastos con una asignación de 100€/semana. Y que ha vuelto a haber algún pequeño incidente con el perro. ¿Podríais abordar estas cuestiones desde el Programa de Apoyo Comunitario? La trabajadora social ya ha comunicado a los vecinos con lo que hubo problemas porque incitaba al perro a morderles, la importancia de que acudan a denunciar. Veremos cómo sigue todo." ··································································································································································································· Respuesta de Toni-Futuex: "La semana pasada se hizo un seguimiento, y en cuanto revisemos la nota del mismo te la paso. Pero te anticipo algunas cosas que hablamos ese dia la compañera y yo. Parece como si, la ts.. no estuviera ahora muy colaboradora, y que les "urge" de alguna manera que este señor salga a un centro.. porque era un poco el leitmotiv de lo que le comento a la compañera el dia de la visita, que "aqui no puede estar" "que solo no puede estar.." y luego la verdad que en los seguimientos no percibimos tal cosa, o no, de la forma tan extrema como se plantea. Lo del tema del dentista, que sepamos, no ha ido, lo que pidió fue un presupuesto. Se le explicó que tenia que esperar a que se le concediera. Se le insistio mucho en que no fuera hasta que no se apruebe pero este hombre es muy impaciente e impulsivo el ppto de hecho lo ha pedido el por su cuenta. La visita fue el jueves si no recuerdo mal. Lo del dinero, pues es un poco desastre, es cierto, nos parece una persona muy caprichosa y fuman muchismo, a ver si podemos volver adjuntar fotos, porque por ejemplo, lleva 4 relojes y la cantidad de calzado que tiene es impresionante. Va bien vestido, pero con una estetica y gustos digamos extravagantes. Esta última vez se intento supervisar el armario pero no lo permitió solo mostró una parte y tiene muchos zapatos más y mucha ropa pero no pude hacer foto. Tambien informar que se hecha colonia constantemente incluso en la cara. Asique gran parte del dinero, suponemos que lo debe invertir en estas "costumbres y gustos. Lo del perro, es un perro pequeño de esos tipo pequines, pero como con muy mala leche, tal y como me trasmiten de modo coloquial.. no hemos constatado en ningun seguuimiento que el incite a perro (tampoco lo podemos negar) simplemente no lo hemos visto, pero si que el perrito es bastante de intentar morder y demas, al ser tan pequeño es raro que genere heridas o daños, pero claro no es normal, ni es plan, que el perro muerda a nadie. Espero haber podido aclarar algunas dudas, mientras pasamos el seguimiento mas detallado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PECO'and apellido2='CARRANZA'),'2023-06-14','miguel, me llama Anabel Ts del Ayto de Madrigalejo 927-354002 para decirme que en la cuenta de unicaja (antes liberbank) aparece la madre fallecida hace 20 años. Que la única heredera es la curatelada. Que además hay una vivienda que está que se cae. Me mandará con copia a Maite y Ana certificado de defunción, y lo que encuentre de la vivienda para iniciar la tramitación de la herencia de la fallecida madre. ******************************************************** miguel, recibo email de Anabel,SSB025 Vegas Altas Madrigalejo >ssb025vegasaltas@madrigalejo.es> con copia a Ana y Maite: Según conversación mantenida por teléfono, adjunto copia de la cartilla bancaria de la tutelada donde consta que continúa como titular su madre, la cual falleció en 2001. Se adjunta certificado de defunción. Por otra parte, también se adjunta toda la documentación que existe en el Ayuntamiento referente a su vivienda, a nombre del padre Antonio Pecos Reyes, la cual como pueden ver está en muy malas condiciones y es urgente hacer algo con ella, a ser posible alguna actuación que reporte beneficios económicos a la tutelada. Quedo a la espera de vuestras noticias. Reenvío dicho email a la parte económica y social:Buenos días, de esta curatela tenemos que reunirnos la parte económica, social y jurídica para acordar qué hacer en este expediente pues dice la trabajadora social del ayuntamiento que la vivienda de los padres fallecidos está en malas condiciones. La última rendición es de hace muchos años con lo cual desconozco qué bienes tienes y cuál es el saldo bancario y las condiciones económicas de esta curatelada Parece ser, por lo que dice Anabel, la trabajadora social que la única heredera es ella. Por tanto habría que hacer la herencia y la venta o arreglar la vivienda? La curatelada podría firmarnos estar de acuerdo con una actuación sobre dicha vivienda? En principio, salvo que la notaria nos lo requiera, entiendo que no es necesario que solicitemos dichas autorizaciones judiciales para aceptar, aprobar la herencia, incluso para vender, ya que la sentencia de incapacitación y nombramiento “que la declara parcialmente incapaz, necesitando la asistencia de un curador para el ejercicio de aquellos actos enumerados en los artículos 271 y 272 CC, y en general para la administración y disposición de sus bienes, estando también facultado el curador para representar a la incapaz ante los organismos oficiales para llevar a cabo los trámites burocráticos que precise y, en el plano asistencial, para someter a dicha incapaz al tratamiento médico que en cada caso precise…”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-06-14','Ana: Envío correo a Toni-Futuex: "En relación a JESÚS MANUEL RAMO BARGÓN, su madre nos comunica que su hijo no está bien en la vivienda en al que vive (ya sabemos que esto no es nuevo y que es muy difícil la intervención con él), no obstante, ¿podríais prestarle apoyo desde el programa para la búsqueda de otra vivienda de coste similar? En cualquier caso, quiero decir, si colabora o no, si hay viviendas de alquiler a este precio o no y las dificultades que encontréis en estas gestiones, por favor, enviarnos si no informe, al menos nota informativa." ······························································································································································································ Respuesta de Toni: "ultimanente esta mejor y no rechaza tanto los seguimientos, mña se ha quedado con el, se intentara ir a una inmobiliaria para contrastar la informacion que ya me adelanta la compañera por la busqueda con otros tutelados, que es inviable por ese precio, tal y como esta el mercado. Pero intentamos pedir precios en agencia inmobiliaria y pasar por escrito nota"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-06-14','Ana: Comunico a Julia que a partir ahora, podrá volver a retirar 350€ de asignación. Se pone muy contenta. ·············· Hoy está con sus padres en Arévalo, pues ha ido con sus padres a visitar a su hermano José María.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-06-14','Ana: En relación al correo remitido por Pedro Pablo Garvi, Coordinador del CES - Caritas (pgarvi.cdcoriacaceres@caritas.es): "Solo quería informarte que Miguel Ángel lleva un par de semanas sin pasar por el centro de emergencias. Tampoco lo he visto por donde se suele mover." ························· Le respondo: "Muchas gracias por informar de nuevo. Precisamente ayer me llamó desde el teléfono de un amigo. Le pregunté y me dijo que llevaba alguna noche, de forma puntual, durmiendo en la estación de autobuses, y que había estado en otro recurso de la Asociacion REMAR, pero que le habían expulsado por fumar tabaco. Dice que volverá a acudir al CES… veremos. Lo cierto es que dada su trayectoria y su falta de adherencia a los recursos y el no cumplimiento de las normas de los mismos, hacen muy difícil la intervención con él. Agradecería me mantuvierais informada en caso de volver a pernoctar allí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-06-13','Ana: Llamada de Miguel Ángel, desde el teléfono de un amigo (633 609 131): Dice que ha estado un par de semanas en el recurso residencial de la Asociación REMAR (Atención a P. con Adicciones), pero le expulsaron por fumar tabaco. ··············· Dice que de forma puntual lleva algunas noches durmiendo en la Estación de Autobuses. ········ Pilar, TS del Comedor Soc. le ha facilitado mi teléfono. ··········· Dice que seguirá acudindo al comedor y que irá a pernoctar al CES. ··········································· Por otra parte, en relación a la retirada de 140 € que se le autorizó pero no se le pudo comunicar, acudirá el jueves a retirarlos. Dice que los invertirá en un móvil y le llevará el tiquet a Pilar, TS Comedor. Y nos facilitará nuevo número de teléfono para poder contactar con él. ····················· *Le informo de la derivación al Programa de Apoyo Comunitario y se muestra conforme. ·································································································································································································· Correo de Pilar, TS Obra Social La Milogrosa (oslamilagrosacaceres@gmail.com): "Buenos días, Ana, no me he puesto en contacto contigo antes porque, Miguel Angel, no ha venido estos días al comedor. Ayer ha vuelto y nos ha dicho que ha estado en un centro de Remar en Talavera de la Reina. Otra vez está en la calle. Le hemos preguntado y nos ha dicho que la sucursal a la que quiere ir es la que hay al final de la calle Pintores, así que, entiendo que es la oficina principal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-06-14','Ana: Tras comunicarme Julio, Aux. Adtvo. que Ángel Félix me ha llamado, (643 622 174) le devuelvo la llamada, pero no obtengo respuesta. ······························· Vuelvo a intentarlo a lo largo de la mañana en distintos horarios y no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2023-06-12','Ana: Correo de Alberto: "ANA: PODEMOS SUBIR ASIGNACIÓN A 80 €/SEMANA (347 €/MES) PERO PRESUPONIENDO QUE NO VA A TENER MÁS EXTRAS COMO LOS DE LA VIVIENDA O SIMILARES. ANA: EL PAGO DE LA AYUDA A DOMICILIO HA SUBIDO DESDE ABRIL A 875 €/MES---HASTA ABRIL ERAN 833 Y ANTES 805---SÓLO PORQUE TENGAS CONOCIMIENTO ---- X SUPUESTO EL INGRESO SEPAD SE MANTIENE EN 715 € LOURDES: SI ANA DA OK LE SUBIMOS ASIGNACIÓN A PARTIR DE 01/07/2023 + REVISAMOS EN 6 MESES" ········································· Doy el Ok a Lourdes, quien contestará a Mª Ángeles, Auxiliar de SAD, que es quien hizo la solicitud en nombre de Felipe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-06-14','-Amalia : escribo a Teresa TS : Buenas , Fco. Javier Giraldo salió del CRR de Mérida en marzo , baja voluntaria , y se fue a vivir con el padre en Calzadilla de los Barros. Se lo envié a Julio para que hiciera el cambio de domicilio en la base , y ahora ya lo paso a tu zona , creo que no lo he hecho aún. Está en seguimiento con Futuex . Vive con su padre y tiene una asignación económica establecida . De momento , todo está estable y no ha habido ninguna incidencia. Tiene una citación judicial , voy a ver si Futuex puede acompañarlo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE DOLORES'and edp.apellido1='VARGAS'and apellido2='CHAVERO'),'2023-06-14','-Amalia : Continua ingresado en CSS de Mérida. Tienen un solar familiar en Calzadilla , hace años que viene pagando el desbroce del mismo . Se ha llamado a Carlos Ferreira tf , 675898775, que nos ha cobrado 70€ por la limpieza . Nos envía por email su Nº cta para abonar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2023-06-13','Ana: Correo de Juan Carlos Díaz, Seguridad Social (juan-carlos.diaz1@seg-social.es) adjuntanto el INFORME DE VIDA LABORAL NEGATIVO solicitado. ························································································ Se lo remito a Teresa, TS Novaforma (trabajadorasocial.novaforma@gmail.com), junto con el Cdo. de Titularidad Bancaria, facilitado por Lourdes, secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-06-14','TERESA ENVIO SOLICITUD DE ELECCION DE CENTRO, SOLICITAMOS TODOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-06-14','Ana: Envío correo a Alberto, con copia a Maite e Icíar: "...tras haber abordado el asunto en la sección social, se plantea como necesaria la compra de los siguientes productos: - Teléfono móvil: Entre otras cosas, porque el que tiene actualmente, para empezar no es suyo, se lo han prestado, y además no dispone de conexión a Internet (sólo le permite hacer llamadas) y él necesita poder usar el WhatsApp, pues es la vía por la que le envía los menús del Catering para poder elegir entre las distintas opciones diarias. - Ventilador: Pues vive en un cuarto (última planta) y el tejado del edificio es de uralita, sin aire acondicionado, sería más que conveniente que al menos tenga uno para cuando llegue el calor. Contemplamos que percibirá la paga extra en este mes y, si no me equivoco, puede permitírselo." ·········································································································································· Respuesta de Alberto: "ICIAR: EL MÓVIL MÁS BARATO. ICIAR: TE TOCA ESTAR PENDIENTE...CADA 1,5 MESES HASTA LOS 6 MESES, COMPRUEBA QUE NO HAY UN SÓLO CARGO DE TELEFONÍA....SI APARECE CUALQUIER TIPO DE CARGO: SE DEVUELVE SIN CONSULTAR."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-06-14','Ana: Envío correo a Ana Mª, Ed. Social Plena Inclusión Zafra (social@plenainclusionzafra.org): "Adjunto la autorización para hipoterapia relativa a REMEDIOS CHAVES MASERO, firmada digitalmente por el Representante legal. Aprovecho ya para comunicar que del seguimiento de Reme ya se encargará mi compañera Teresa, la pongo en copia. Por lo que a partir de ahora, será a ella a quien tenéis que dirigiros para las cuestiones relativa a Reme." ································································································································· Correo de Ana, Ed. P.I.: "Por aquí seguimos bien, cada vez conociendo más a Reme y ampliando la oferta de actividades adecuadas para ella y de su interés. Esperando que todo vaya dando sus frutos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2023-06-14','Ana: Envío correo a la secc. ecca. al ctutelar@: "Os remito correo de Paz, TS de Los Hermanos de la Cruz Blanca. Hay que abonar el coste del viaje a Lourdes de: - Antonio Tejada Fernández - Alejandro Montero Vázquez En el concepto, como podéis leer más abajo se pone nombre y apellidos + CRUZ BLANCA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='BLAZQUEZ'and apellido2='SANDOVAL'),'2023-06-14','Ana: Envío a Teresa, TS Novaforma (trabajadorasocial.novaforma@gmail.com) C.I. de participación en el Programa de Doctorado sobre Accesibilidad Cognitiva - CC, firmado digitalmente por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2023-06-14','Ana: Correo del CRR-CC (crr@grupociudadjardin.com): "Adjuntamos informe de solicitud e información de comienzo de tratamiento para dejar de fumar por parte de la persona usuaria Antonia Canelada del Río. Tanto su psiquiatra de referencia como su neumólogo recomiendan el comienzo del tratamiento. Una vez se reciba la aceptación por vuestra parte se comenzará con la dispensación de la medicación." ····························· Se da el visto bueno desde la Sección Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-06-14','Ana: Envío correo a Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Ayer finalmente no me dio tiempo de volver a llamar a Pedro y a Cristina, agradezco que le transmitas también esta información. Como, imagino, que ya sabréis, en conversación telefónica mantenida entra Maite y yo con Consuelo Nevado Pacheco, a pesar de que con sólo preguntarle cómo estaba ésta expresó que estaba mal en el centro, se niega en rotundo a trasladarse a otro CRR, siendo el principal motivo el no querer separarse de su novio Juan Mario. Dijo textualmente que “me lo van a robar” Por otra parte, expresaba ideas propias de su constante delirio, como que era la “Virgen de Covadonga” y la mujer que quiere robarle a su novio la “Virgen puta de…” (no recuerdo dónde) y cuestiones similares. Por otra parte, transmitiros que nos dijo que quiere dejar de fumar. Le dijimos que os lo comunicaríamos para que se le pueda pedir cita al médico a tal fin. No sabemos si será necesario o no que acuda al Equipo de Conductas Adictivas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-06-14','Ana: Toni-Futuex, confirma acompañamiento al Juicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2023-06-14','Ana: envío correo a Toni-Futuex: "En relación a Pilar García Moreno, he recibido nueva llamada de su hijo Abraham. Dicen que hace mucho tiempo que no les visita la educadora y que no está conforme con la asignación mensual actual, pues no llegan a cubrir las necesidades y le supone tener que aportar él mayor cuantía que su madre. Cuando sea posible, por favor, haced nueva visita de seguimiento y abordar esta cuestión con ellos. Le he dicho que tengan preparadas facturas de suministros, tickets de compras del mes (para calcular medias de gasto) e información de otros gastos habituales que suelan tener para que, de ser necesario, podáis plantear una nueva propuesta de asignación mensual y se valore por la sección económica. Conforme os escribo, me entra la duda, ¿esta familia no tiene los suministros domiciliados en la cuenta de Pilar? En fin, a ver si con la información que facilitéis y la que disponen en la sección económica se puede clarificar todo y tomar decisiones. Por cierto, esta información envíala directamente al ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-06-15','Ana: En relación a la plaza que van a conceder a José Manuel en la Residencia de Hervás, consulto a Paula, TO CRR-Plas., si José Manuel sigue convencido con este cambio de recurso. ·············· Repuesta de Paula (tocupacional.crrplasencia@grupo5.net): he hablado con José Manuel, y aunque le da penilla irse, tras ver las ventajas y las oportunidades de apoyos que le ofrece la residencia valora de forma positiva la misma. Con esto te confirmo que acepta el traslado, para que puedas realizar los trámites oportunos. Por si se ponen en contacto con vosotras de la residencia, podéis facilitarle nuestros datos de cara a llevar a cabo las acciones necesarias para el traslado (desde documentación a enseres/ropa…)." ····································································································································································································· Escribo a Mai, Jefa de Secc. Acceso a RR. de Mayores (margarita.masegosa@salud-juntaex.es): "En relación al expediente del que hablamos ayer, JOSÉ MANUEL MORENO CARLOS, me confirman desde el CRR, que aunque le cuesta un poco la decisión, es consciente de las necesidades que presenta y los apoyos que tendrá en la residencia para las mismas. Acepta acepta totalmente el cambio de recurso. Por tanto, cuando tengáis los documentos, me los podéis pasar sin problema." ·································································································································································································· Noelia Cuesta, Aux. Adtvo. Secc. Acc. RR. Mayores (noelia.cuesta@salud-juntaex.es): Me remite resolución aprobatoria del SAR en la la RESIDENCIA DE MAYORES DE RIOLOBOS. Por la plaza le correponderá abonar 312,00 €/mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-06-15','Ana: Correo de Anabel, TS SSASB - Miajadas (servicios.sociales@miajadas.org): "Se han puesto en contacto conmigo desde el Juzgado, con objeto de comunicarme que el próximo dia 21 de junio de 2023, la jueza tiene previsto efectuar una visita al domicilio de Joaquina, lo que quieren es que me asegure de que esté en el domicilio y que acompañe en la visita, así lo haré, esto tiene que ver con la revisión de las medidas de protección según me ha parecido entender." ·················· Respondo y pondo en copia a Maite y A. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-06-15','TERESA Comentar tambien que al respecto de Maria Jesus Cruz. Informar que ayer 13/06/2023 tenía consulta de psiquiatría del Equipo Salud Mental de Almendralejo. Se intenta realizar acompañamiento desde el equipo de apoyo social comunitario pero esta se niega. En todo momento le hacemos saber que todo esto se registra para que lo lea la comisión tutelar de adultos. Le preguntamos qué tal la consulta y nos indica que el informe de psiquiatría lo remitirá directamente a Teresa de la comisión que para eso le facilitó el email. Desde que ha retomado la relación con su pareja siempre pone excusas para el desarrollo de los seguimientos presenciales. DE MOMENTO NO HE RECIBIDO EL INFORME','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2023-06-15','TERESA Buenas, es bastante complicado realizar este seguimiento, porque ella rechazando cualquier visita, hace mucho,. Pero hace pocas semnas, en coordinación con los SSB planificamos una reunión informal en el ayuntamiento para poder ver a Trinidad. Nuestra sorpresa ha sido cuando vemos llegar a Trini acompañada de su hermana. Comentan que iniciaron el procedimiento para remoción de tutor hace tres años mediante una abogada de oficio. Tras no ver cambios al respecto, el año pasado contrataron a un abogado privado, Antonio Carretero para que retomase los tramites. En un primer momento, pensaron proponer al padre de Trinidad como tutor, pero dadas las circunstancias y tras recuperar la relación con su hijo, en la actualidad, quieren que sea su hijo Jesús quien asuma la curatela representativa de Trinidad. Jesús tiene 27 años. Nos cuentan que Tomas, la pareja de Trini fallece de forma repentina el 15 de enero de 2023. Le ha dejado todo de herencia a Trinidad. La hermana comenta que les urge arreglar el tema del tutor para después arreglar el tema de la herencia. No quieren mover la herencia estando la junta de Extremadura por medio, dice A Trini la observamos bien, pero es cierto que su hermana la deja hablar poco. Trinidad expresa que ella quiere seguir residiendo en Barcarrota y quiere que su hijo asume la tutela. En el pueblo acude a actividades del hogar del mayor y al taller de pintura en el instituto viejo. Desde que retomaron los trámites para remoción del tutor cortó la relación con el equipo de apoyo social comunitario, se negó a atendernos y renuncio a cualquier apoyo desde nuestra intervención. En esta ocasión conseguimos verla gracias a la mediación de Fernanda, la trabajadora social de los SSB. En cuanto al teléfono, nos percatamos que, tenía nuevo número de teléfono, por lo tanto, ha debido coger algún terminal nuevo y de ahí las cuantías de las facturas. Desde el equipo intentaremos planificar otro seguimiento presencial para explicarle la situación respecto al terminal móvil. Se intentará también a través de la trabajadora social de SSB del ayuntamiento de Barcarrota, ya que a ella no la asocia directamente con la negativa de estar tutelada por la Comisión Tutelar de Extremadura y no la ve como impedimento a su objetivo principal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2023-06-15','TERESA El pasado día 5 de junio, se contactó con Elena (auxiliar que ha estado acudiendo a casa de Adolfo a diario, estas gestiones las realizó Lorenzo y lo comentó con la Comisión de forma directa) y comentaba que a partir de ese jueves (8 junio) dejaría de acudir a casa de Adolfo debido a un problema que ha tenido con Lorenzo. No explicaba el motivo pero comentaba que no le genera nada de confianza el hermano de Adolfo y que, a pesar de que no le había dicho a Lorenzo el motivo real de por qué lo dejaba, si que le había comentado a la empresa que ya no acudiría a ver a Adolfo. Elena comentaba que Lorenzo no atiende ni tanto ni tan bien a su hermano como él quiere hacer ver y que se queda con todo el dinero que retira Adolfo. Hasta donde sabemos Adolfo va a retirar su asignación al banco, puede que Lorenzo le pida el dinero cuando llega a casa, se investigará acerca de esto. El, 9 de junio, se ha recibido un whatsapp de Lorenzo comentando que Elena ha solicitado la baja y que acudirá, a partir del próximo miércoles, otra auxiliar a visitar a Adolfo (entendemos que de la misma empresa), se procurará coincidir con ella en próximas visitas para intercambiar los teléfonos. No sabiamos que se habia ido ya, pero es que el hermano está casi peor que Adolfo.. que a su vez también tiene lo suyo, pero es que ultimamente almenos en lo que respecta a lo que observamos en los seguimientos, esta mas aseado y aparentemente tranquilo, almenos en las visitas que le realizamos nosotros. No obstante, hacemos seguimiento la semana que viene, y pasamos nota','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2023-06-15','TERESA La semana pasada, el viernes, se acudio al domicilio de Concepción y se ha hablado con ella y su hija acerca del tema de la asignación de la tutelada. Se les ha planteado la posibilidad de que se ingresara una parte de la asignación a Concepción y la otra parte a Inmaculada para que ella lo administre para los gastos de comida y productos del hogar. Ambas coincidían en que era mejor que siguiera Concepcion retirando los 70€ íntegros y que luego diera a su hija el dinero para la compra. Inmaculada comentaba que la idea era que le ingresaran todo a ella pero que ve más incómodo que ingresen una parte a cada una y que, en este caso, seguiría resultando más conveniente que Concepción siga retirando su asignación como es habitual. De lo que se quejaba Inmaculada es que el otro día su madre compró ropa interior y, por tanto, les quedó menos dinero para el resto de gastos. Se le ha comentado a Concepción que todo aquello que necesite de ropa, calzado o cualquier otra cosa relacionada con el autocuidado personal nos lo comente a nosotros para acompañarla a pedir presupuesto y que desde la Comisión, si lo consideran necesario, le aprueben un pequeño extra para aquello que necesita. Inmaculada comentaba que suelen administrarse bien. También ha explicado que sigue llevando las facturas de la luz a Pepi (TS) ya que les aprobaron la ayuda para el pago de suministros por familia vulnerable. Se ha estado charlando con Concepción acerca de la importancia de llevar una buena alimentación ya que compra muchos refrescos, se le ha explicado que podría comprar y consumir un poco menos para dedicar ese dinero a alimentos. Se ha estado hablando con ella acerca de la administración del dinero. Se ha vuelto a proponer a Concepción la posibilidad de recibir por parte de algún catering/restaurante/residencia la comida y cena diaria, de esta manera no tendría que preocuparse de qué cocinar, llevaría una alimentación más variada y también tendría que comprar mucho menos. Se le ha explicado que se le podría proponer a la Comisión para ver diferentes opciones que sean económicas y ella pueda permitirse, Concepción se ha negado. Por otro lado, se ha hablado del tema de auxiliar de ayuda a domicilio que Inmaculada intentó solicitar hace un par de años pero desde los servicios sociales le dijeron que la tutelada era muy joven. La idea es que esta auxiliar ayudara a la tutelada en tareas como la compra, la limpieza de la casa, los recados en la farmacia e incluso acompañamiento al centro de salud. Concepción pasa mucho tiempo sola y esto preocupa a Inmaculada si en un futuro cercano ella tiene que irse. Se ha acudido al Ayto a ver a Pepi (TS) pero han comentado que había salido de viaje y no se encontraba allí. Se contactará con ella para hablar acerca de este tema y se remitirá dicha información. Esta misma mañana, se ha hablado con Pepi (TS de Azuaga) acerca del tema de ayuda a domicilio de Concepción, comenta que por parte del ayuntamiento no sería posible debido al lugar donde se encuentra la finca de Concepción, explica que las auxiliares no tienen coche, se desplazan a pie y tienen que atender a más de un domicilio, con lo cual no podrían desplazarse hasta el domicilio de la tutelada. Pepi recomienda solicitar la revisión del grado de dependencia y de esta manera, si se le reconoce algún grado, se pueda gestionar alguna auxiliar de ayuda a domicilio SOLICITO PIDAN CITA CON EL MEDICO PARA INFORME MEDICO Y SOLCITAR REVISION DE GRADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-06-15','Amalia: Emi ha pasado del CRR de Olivenza al CSS de Mérida . Julio cuando puedas lo actualizas en la base .Sigue quedando en mi zona. A nivel eco , necesitan que enviéis la autorización a la directora para que puedan disponer del dinero como el resto de usuarios. Van a hacer una compra inicial extra para comprar todo lo que necesita para el ingreso : ropa , calzado , productos de higiene.. y la asignación mensual ,que allí es muy reducida. Ya saben la cuantía de su PNC y controlarán los gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-06-15','Ana: En relación al correo de Carolina, Directora en funciones del CRR-Plas (direccion.crrplasencia@grupo5.net): "Como ya sabeis seguimos teniendo en el recurso dinero y pertenencias de Javi Agudo. Respecto a las pertenencias en dos ocasiones hemos quedado con él y no se ha presentado a por ellas por lo que ya no podemos seguir guárdandoselas más tiempo y nos gustaría que nos dijeses que hacemos con ellas (porque sí no las vamos a tirar) Cuando hemos hablado con él respecto a esto no le da mucha importancia a las cosas, expresando que las dejó poruqe no las necesitaba. Por otro lado el dinero por favor indicanos un número de cuenta para que le ingresemos tal y como nos dijisteis." ························································ Respondo: "Pues, sinceramente, sí él mismo, que es el principal interesado y no tiene problemas de movilidad, no va a recoger sus pertenencias, poco se puede hacer. Consideramos que quizá podíais volver a llamarle dándole un “ultimátum”, diciéndole que si en un par de días no pasa a recoger sus cosas las vais a tirar. Y cumplirlo en caso de que no acuda. En relación al dinero, podéis ingresárselo en el siguiente número de cuenta..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-06-14','Ana: Correo de Carlos Javier Hdez., TS del SAD - IMAS CC (carlosj.hernandez@ayto-caceres.es): "Informaros que habiendo realizado visita al domicilio de Carlos González para valorar expediente de Servicio de Ayuda a Domicilio, nos informa que tiene intención de renunciar a la prestación del Sad ya que, según manifiesta, tiene pareja y pretende irse a vivir con ella, además manifiesta que el realiza las tareas domésticas no necesitando ayuda para ello. Necesitamos que nos confirméis esta situación y en su caso que sea la Comisión Tutelar quien solicite la renuncia a la prestación del Servicio de Ayuda a Domicilio. Quedamos a la espera de vuestras noticias para continuar con el cierre del expediente." ·········· Solicito su nº para llamarle.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-06-15','Ana: Llamo a Carlos Javier Hdez., TS del SAD - IMAS CC (927 21 23 35 EXT. 4419): Cuando hizo la visita Carlos le dijo que iba a rechazar el SAD, porque ice que tiene pareja (49 años) y quiere irse a vivir con ésta su hijo de 9 años. / Al parecer se ha tatuado la imagen del niño. ········· También le dijo que ya ha dejado de ir a comer al Comedor Social porque va a comer a casa de ella. ············ *Y que quiere hablar con los A. Jurídicos de la CTAEx porque quiere poner su piso en alquiler. ·········································································································· Nosotros desconocíamos toda esta información, nunca nos había hablado de ella y de estas nuevas intenciones. ······································································ **Acuerdo con Carlos, TS IMAS, que dejarán el expediente en standby hasta que podamos abordar esta cuestiones con él. Llegado el momento nos enviarán la renuncia al SAD, que le indiamos que lo ideal es que la firmara primero Carlos y, una vez firmado por éste, recabaré la firma del Representante Legal. ······························································································································································································· Envío correo a Toni-Futuex: "En relación a CARLOS GONZÁLEZ LEO, he hablado con el Trabajador Social del SAD – IMAS Cáceres. Al parecer, cuando ha ido a visitarle para poder valorar el inicio del Servicio de Ayuda a Domicilio, Carlos le ha dicho que va a rechazar el servicio, porque quiere irse a vivir con su novia(de 48-49 años) y el hijo de ésta (de 9 años). Dice que lleva 3 años con ella, pero a nosotras no nos ha manifestado nada al respecto ninguna de las veces que hemos hablado con él. En la nota vuestra de la primera visita tampoco consta nada. Y en el Informe Social del SSASB para el inventario, tampoco se hace mención, en cambio sí nombra amistades… El sentido de solicitarle SAD, era principalmente para que tuviera un mínimo apoyo para ciertas cuestiones (entre ellas la compra y que le enseñara a cocinar cosas sencillas. De hecho él lo demandaba ) y porque así podría tener acceso al servicio gratuito de Catering del IMAS, pues es requisito imprescindible ser usuario del SAD. *De momento van a dejar la solicitud en standby, pero como máximo pueden dejar el expediente sin resolver un mes. **También quiere alquilar su piso cuando se vaya con su pareja. En este sentido, por favor, explicarle que en principio NO se va a alquilar su vivienda, pues si la convivencia con su pareja no va bien, no tendría dónde volver. Desde aquí le transmitiremos la misma idea cuando hablemos con él. ¿Podríais por favor, hacerle nueva visita y abordar todas estas cuestiones? Ya nos vais informando al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-06-15','TERESA ARCHIVO DOCUMENTO CON CONTACTOS FAMILIARES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2023-06-15','TERESA TRAS PREGUNTAR A ANGEL COMPAÑERO ASESOR JURIDICO He hablado con el Abogado y van a solicitar la remoción del cargo que ostentamos, para que lo asuma su hijo. Hasta entonces no hacemos nada relacionado con la herencia. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2023-06-15','Ana: Llamo a Ana Isabel Moreno Gilgado, TS Gerencia Territorial de BA (924 01 01 49 / 20533): me informa que el Mª Luisa sigue en lista de espera para traslado. *Al ser vía Decreto, suele tardar más, las solicitudes por Dependencia se le ponen por delante. ·································································································································································································· En relación al correo de Minerva, TS CR Cervantes (minerva.salvador@salud-juntaex.es): "te quería comentar un asunto referente a la tutelada Mª Luisa Montaña, ayer se presentó en el centro su hija y estuvieron juntas, me comentó Mª Luisa que el viernes volvería a visitarla. Quisiera comentarte al respecto, cuando puedas me llamas por favor.", le escribo un correo: "Como sabrás, hablé con Ana, Directora, quién me transmitió lo que indicas en tu correo y me pedía que te diera respuesta por escrito. Pues bien, tras haberlo valorado en equipo, desde el Gabinete Técnico de la CTAEx, autorizamos las visitas de su hija siempre y cuando a María Luisa no le suponga ningún tipo de perjuicio. Pero en el momento que observéis que la hija tienen intenciones no legítimas o que a ella le altere o perjudique de algún modo, os solicitamos por favor que nos lo comuniquéis y se “revocará” esta autorización automáticamente. En cuanto al traslado de centro, he hablado con Ana Isabel Moreno, compañera de la Gerencia Territorial de Badajoz. Me indica que sigue en Lista de Espera de Traslado. Como ya nos dijo en su día, al ser por Decreto, suele tardar bastante más, pues tiene prioridad los de vía Dependencia. Aprovecho para preguntarte qué tal sigue María Luisa y si ha vuelto a visitarla la hija, tal como dijo que haría, y en tal caso, cómo ha ido la visita. Ya me dices cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-06-15','Ana: Correo de Carlos Hernández Barca (carlosj.hernandez@ayto-caceres.es): "Informaros que habiendo realizado visita al domicilio de Carlos González para valorar expediente de Servicio de Ayuda a Domicilio, nos informa que tiene intención de renunciar a la prestación del Sad ya que, según manifiesta, tiene pareja y pretende irse a vivir con ella, además manifiesta que el realiza las tareas domésticas no necesitando ayuda para ello. Necesitamos que nos confirméis esta situación y en su caso que sea la Comisión Tutelar quien solicite la renuncia a la prestación del Servicio de Ayuda a Domicilio. Quedamos a la espera de vuestras noticias para continuar con el cierre del expediente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-06-16','Ana: En relación a la incidencia con la tarjeta monedero de Felisi, envío correo al Programa de Familia (programafamilia@tajosalor.es): "- Felisi no pudo sacar la asignación completa porque fue a retirarla antes de tiempo. La primera retirada mensual es del 1-15 y la segunda del 16-30, es decir, hasta hoy no debería haber ido a sacar el dinero de la segunda quincena, pues hasta hoy no se recarga. Los 70€ que pudo sacar los tenía ahí de remanente de gestiones iniciales con la tarjeta. - Hoy han ido a recargar la tarjeta y las compañeras se han encontrado con que está “cancelada”. ¿Sabéis si han vuelto a intentarlo ellos solos o han hecho alguna otra acción para que esté cancelada? - Creo que mis compis de la secc. económica van a hacer gestiones para solicitar otra tarjeta nueva. En cuanto esté solucionado os lo comunicarán. - ¿Podríais explicarle todas estas circunstancias? Yo también se lo explicaré cuando hable con ella, pero no sé si me será posible hoy. Pongo en copia también a la coordinadora de Futuex, para que estén al corriente." ··································································································································· Envío nuevo correo al programa de familia: "me dice Lourdes, compañera de la sección económica, que ha llamado a Felisi para comunicarle que ya puede retirar el dinero y el teléfono no está operativo (“No se encuentra disponible"). Ha llamado después al número anterior y le ha contestado Jesús. Le ha dicho que Aitor ha hecho algo con el teléfono de Felisi y ahora ella está sin móvil, incomunicada. NO sé si esto es cierto. Ya nos vais diciendo si podéis hablar con ella hoy y averiguar qué ha pasado además de acompañarla al cajero." ·········································································· Correo-respuesta del PAF (programafamilia@tajosalor.es): "Acabamos de hablar con ellos. Lo que ha pasado con el teléfono de Felisi es que han hecho una portabilidad a otra compañía y hasta esta tarde no tendrá la tarjeta nueva. Ayer ya me lo contaron. A mí también me ha llamado Jesús hablándome mal de Aitor y contándome un montón de cosas, un poco lo de siempre, porque ahora Jesús quiere irse a vivir a Navas con su hermano y mientras esté allí Aitor no pueden. El antiguo número de Felisi lo tiene Jesús porque se enfadó con ella, le dijo que él era el que pagaba la línea y se lo quitó. Estas cosas que suyas…. He quedado con Felisi el lunes para sacar el dinero porque hoy me es imposible, de todas formas aun tiene dinero de los 70€ que sacamos el otro día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-06-16','miguel, envío email a Mª Pilar Lopez Gonzalez, con email mplgonzalez@despacho.notariado.org de la notaria de Plasencia de Jimenez Mancha: Buenos días Pilar, adjunto lo que tenemos que es: *Modesta Garcia Piñero (fallecida) certificado de defunción y últimas voluntades (no tiene testamento) *1º Marido: Pedro Gutierrez Brujera, adjunto certificado de defunción, fallecido el 20-1-1968, donde en el apartado otros títulos o datos indica: “ El finado se hallaba casado con Doña Modesta Garcia Piñero, deja tres hijas llamadas Modesta, Juana y Flora (que está tutelada por la Comisión Tutelar de Adultos) *2º Marido: del que se divorció: Juan Rincon Romano, adjunto certificado de matrimonio, en nota al margen “se declara disuelto por divorcio el matrimonio por sentencia firme de 3-12-1987” No es posible conseguir nada más ya que no disponemos de información ni de dni, ni de lugares de casamiento del 1º matrimonio con Pedro Gutierrez Brujera, y en cuanto al 2º marido Juan Rincon Romano, tampoco tenemos del lugar de fallecimiento, fecha, ni dni. Por todo ello solicito lo comentes con el notario porque creo no es necesario más documentación de sus dos matrimonios. Si todo está correcto, pon en marcha porfavor tanto las renuncias de las hermanas de Flora, como la declaración de herencia de Modesta Garcia Piñero (madre fallecida, extutelada por la Comisión Tutelar). ------------------------------------------------------- Contestacion de Pilar de la notaria mplgonzalez@despacho.notariado.org: Buenos días Miguel, lo veo con el Notario. Las renuncias tienen que ir ellas a una Notaria a hacerlas, o van a venir aquí a firmarlas??? ------------------------------------------------------ mi contestacion: Buenos días, las renuncias las deberán hacer en Cataluña que es donde viven, por lo que habrán de coordinar con vosotros la firma y remisión de la documentación ---------------------------------------------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-06-16','Ana: Correo de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "El martes próximo nos desplazaremos el ETAC (equipo asertivo-comunitario) al domicilio de Alfonso Marín para hacer seguimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-06-16','Ana: Llamada de Enrique (662 56 78 32): Quiere un extra de 20 - 25 €, porque se le ha partido la rama a un melocotonero por tener la "enfermedad de la Barrenilla por dentro". Lo quier "hoy mismo" que desde aquí llamemos al banco y lo digamos. Le explico de nuevo el modo de proceder, que debería enviarnos un presupuesto y, si lo aprueba el Jefe de la Secc. Ecca., después se abonará mediante transferencia. Que, de todos modos, para hoy mismo no podría estar esa autorización, pues hay que prepararla por escrito, recabar la firma del representante legal y después remitirlo al banco. Y el lunes ya cobrará de nuevo su asignación de los 100€/semana. ··························· Lo comunico a Puerto, TS SSASB y a Ana Benavente, TS ESM. ··························································································································································································································································· Ana: llamo de nuevo a José Ignacio, "Nacho" (670 743 476), hermano de Enrique. Me pide que se lo ponga por escrito, pues no quiere dar datos por teléfono. Su correo es: naxopeke@hotmail.com Le escribo: "Tal y como hemos acordado mediante conversación telefónica, te escribo desde el correo corporativo de la COMISIÓN TUTELAR DE ADULTOS DE EXTREMADURA para solicitarte la copia de las facturas pendientes por la comprar de electrodomésticos para tu hermano el verano del pasado 2022 así como un número de cuenta al que podamos abonar, desde la cuenta de tu hermano, el dinero que te adeuda. Ante cualquier cuestión, no dudes en contactar." ··················································· Lo comunico a Puerto, TS SSASB y a Ana Benavente, TS ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2023-06-16','TERESA RECIBO FIRMNEZA DE LA REMOCION SE LO COMUNICO AL CENTRO PLENA INCLUSION ZAFRA Y A JUANA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ANGEL'and edp.apellido1='IGLESIAS'and apellido2='RODRIGUEZ'),'2023-06-16','TERESA ENVIO CAMBIO DE DOMICILIACION PENSION ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-06-19','Ana: Reenvío correo de Nacho, hermano de Enrique, a la secc. ecca.: "Esta factura hay que abonarla al hermano de ENRIQUE SANTOS GARCÍA PUETE. La información la corroboré con las trabajadoras sociales de Salud Mental y la de Servicios Sociales de Atención Social Básica. Los electrodomésticos los compraron en verano del año pasado en previsión del fallecimiento de su madre, pues Enrique no tenía en su casa, utilizaba hasta entonces los de la casa de su madre." ··············· Indico que hay que abonarlo, ya está contrastado con las TS del ESM y SSASB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-06-19','Ana: Reenvío a Alberto, Jefe secc. ecca., correo de Manoli, TS del C. Psiquiátrico Penintenciario de Sevilla (Manuela.Rascon@dgip.mir.es): "Me pongo en contacto para comunicar el ingreso Saturdino Salguero en nuestro Centro procedente Hospital Psiquiátrico de Plasencia , afecto de coordinación y poderle hacer las transferencia mensuales a su peculio. BANCO SANTANDER CENTRA HISPANO ES17-0049-4781-63-2213010136."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-04-26','Ana: Correo de Óscar, con copia a Alberto y Maite, jefes de secc. CTAEx: "Ya he contestado por escrito a María Antonia, ya que registros su solicitud: Primero.- Con respecto a la cuenta de Caixabank, cuyo titular es usted misma, y acabada en 0857, se solicitó la cancelación de la misma, por primera vez, el 6 de mayo de 2019. Segundo.- Visto que por parte de la entidad bancaria hicieron caso omiso al requerimiento, el 16 de diciembre de 2020 se ordenó un traspaso por importe de 1.340€ de esta cuenta a la cuenta de la que también usted es titular de Unicaja Banco (entonces Liberbank). Se aportan movimientos bancarios donde se acredita que dicho traspaso se realizó el 30 de diciembre de 2020. Tercero.- En la actualidad, el saldo de la cuenta de Caixabank es de 14,68 €. Se aporta certificación emitida por la entidad bancaria. Cuarto.- Vamos a solicitar de nuevo la cancelación de dicha cuenta con traspaso del sobrante, en caso de haberlo, a la cuenta de Unicaja Banco."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-06-19','Ana: Envío correo a Toni-Futuex: "Os realizo nueva petición con respecto a CARLOS GONZÁLEZ LEO. Sé que Icíar ya lo habló con él, pero me da que ha hecho caso omiso. Tiene contrato en Orange, por el que les están panado un cargo en torno a 200€/mes. Como sabéis percibe una PNC, por lo que no puede seguir soportando este gasto. Por favor, tratar con él, y acompañarlo si fuera necesario, a comprar una tarjeta prepago de teléfono de otra compañía distinta a Orange. Pues van a devolver los recibos y por tanto, esta línea se dará de baja y no queremos que se quede incomunicado. Por otra parte, ha enviado un presupuesto de teléfono móvil, a través de una profesional de la Gerencia Territorial, pues según dice, se le ha roto el suyo. Alberto en principio decía que no, pero finalmente se aceptará este gasto para que no se quede incomunicado. Que lo cuide bien pues no se le volverá a dar para este concepto en mínimo año/año y medio. También va a enviar, al parecer, presupuesto para zapatillas de verano. Puesto que va a cobrar el extra, si no es desmesurado, se aceptará, al igual que el teléfono, pero Alberto dice que no se pueden aceptas más extras de momento. No puede continuar con este nivel de gastos muy por encima de sus posibilidades. **Con respecto a su idea de alquilar su vivienda, si se fuera a vivir con su pareja, por favor, explicarle también, que desde la CTAEx no se va a formalizar ningún contrato de alquiler en este sentido, por lo menos no por ahora, pues si luego la convivencia con su novia no fuera bien se quedaría sin lugar en que vivir y esto tiene que entenderlo. *Me comunica también Alberto, que acaba de venir a hablar conmigo mientras te escribía, que el gasto de comunidad son 90€/mes y los gasto de suministros de estos mese rondan los 70€ cada uno, que aunque no sea exagerado, no pueden soportar todos estos gastos mucho más tiempo. Y los ahorros con lo que cuenta tampoco son muchos. Así mismo, ¿podríais preguntarle, a ver qué dice, de los reintegros del mes de enero? al parecer retiró en torno a 9.000€ en distintos movimientos, y aunque la CTAEx aún no había aceptado el cargo, resulta muy significativa esa elevada cantidad en tan sólo un mes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2023-06-19','REMOCIÓN Y BAJA DE EXPTE. El 14/06/23 se recibe Testimonio de la firmeza del Auto n.º 79/23, de 25 de abril, por el que se adoptan medidas judiciales de apoyo respecto de Dña. Juana. Nombrando, el mismo Auto, guardadores de hecho a sus padres. Se procede a la baja del expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2023-06-19','TERESA tras hablar con el departamento de administración sobre los gastos extras de DAVID ESTÉVEZ FELIPE, nos parece mejor opción que se le facture los gastos de cafetería (nunca más de 50 € que es lo que tiene para dinero de bolsillo) por cuenta. Haríamos la factura al final del mes con el consumo que haya tenido en cafetería y adjuntamos el tiket. Si en algún momento cambia la dinámica hacermelo saber por favor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-06-19','-Amalia . Escribo a Maite : Juana ha vuelto a intentar escaparse del centro La luz .Desde el centro solicitan que se valore el proyecto Mi casa para Juana . Actualmente está ingresada en la UHB del HUB . He hablado con el psiquiatra , está ya para alta . Considera que no reúne criterios para traslado a UHDAC , ni a UME . Pero ve necesario un cambio de centro , las alteraciones de conductas vienen motivadas por el entorno y estímulos externos. He solicitado un informe para justificar traslado ( podría ser permuta ) con otro centro . Se podría valorar el nuevo proyecto Mi Casa. Se lo tendríamos que plantear a Soraya . Mañana lo hablamos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-06-19','Ana: Correo de Isabel: "Buenos días Ana seguro que ya sabes lo que pasó anoche que pegué a Marimar y quería preguntarte que qué va a pasar conmigo no quiero volver al socio por favor no quiero irme de CRR de Plasencia" ················ Mi respuesta: "Pues no lo sabía. Quizá me haya escrito también las profesionales del CRR, no obstante esta mañana no he podido estar muy pendiente del correo. No puedo contestarte a la pregunta de qué va a pasar. Pongo en copia a Paula y Bea. Seguiremos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2023-06-19','Ana: Correo de Sandra, TS Res. Real Patronato Coria (alexandra.alfonso@coria.org // 927 50 80 00): ", os envío el consentimiento informado para una prótesis parcial de vuestro tutelado ROGELIO FERNANDEZ VEGA" ··················· Subo al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2023-06-20','miguel, envío a Cruz de la inmobiliaria, hpsugd@gmail.com, el borrador del contrato de alquiler sin opción a compra modificado para que lo complete y lo revise.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2023-06-15','miguel, llega de la inmobiliaria, Cruz,hpsugd@gmail.com> borrador de contrato de alquiler con opción a compra de la vivienda que está a nombre de los 4 hermanos (incluido nuestro tutelado):','2');
