insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-06-20','TERESA SE AUTORIZA REINTEGRO MENUSAL DE 125€ LOS RETIRA EL DIRECTOR DEL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-06-20','Ana: Envío a Leire Sanz, TS C.R. Ciudad Jardin (t.socialcanovas@grupociudadjardin.com): los documentos de la residencia, que nos remiten que al parecer no se firmaron al ingreso de Josefa en su cento, debidamente firmados y sellados por el Presidente de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-06-20','Ana: Envío correo a Mónica, Ed. PP.SS. (educacion.pisosplasencia@grupo5.net): "En relación a Carmen Solana Chanclón, quería, por favor, que cuando puedas, nos corroboraras que, de nuevo, quiere ayudar económicamente a su hijo y su madre. La demanda nos la plantea Benita, su madre y también nos ha llegado a través de Ana Benavente, Trabajadora Social del Equipo de Salud Mental. Ya me dices cuando puedas." ····································································································································································································· Respuesta de Mónica: ", he estado hablando con ella y confirma su interés en ayudar económicamente a su madre el tiempo que sea necesario. Consciente de que no sabe el dinero del que dispone, pero sí le gustaría saber cuál será la cantidad que se le facilitará a Benita. Esta tarde hablé con Benita, por otros motivos, y aproveché también para hablar sobre esto y plantearle una propuesta que Carmen hace: vincular la ayuda económica a asegurar una salida mensual a domicilio. Se muestra de acuerdo." ············· Al preguntarle si se refiere que Carmen vaya al domicilio de su madre una vez al mes, responde: "Efectivamente. Previamente venía ocurriendo así, pero por diversos motivos estas salidas desaparecieron y Carmen las identifica como importante para ella para poder mantener relación con su familia (madre, hijos, etc.). Por eso, proponía vincular aprovechando la aportación económica y a Benita le ha parecido bien, acordando dos noches al mes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2023-06-20','miguel, recibo email de Alberto a Maria y a mi: MARIA: TAL Y COMO QUEDAMOS ABONAMOS DEUDA DE LAS 2 CPROPIETARIOS Y ESTABLECEMOS LAS PERMANENTES A PARTIR 01/07/2023. MARIA: EMBARGOS DIP. CC: XFA, INTENTA AVERIGUAR A QUE SE DEBEN ESAS DEUDAS Y SI HAY CUESTIONES PENDIENTES---SI NO LO CONSIGUES TIRA DE MIGUEL...TE ADJUNTO 2 EMBARGOS QUE HAN CARGADO EN ULTIMO AÑO MIGUEL: HAY FORMA DE AVERIGUAR SI TUTELADA ESTÁ PAGANDO LO QUE LE CORRESPONDE X SUS PORCENTAJES DE PARTICIPACIÓN EN LAS DISTINTAS PROPIEDADES???---TE ADJUNTO CARGOS OAR ÚLTIMOS 2 AÑOS ************************************************************ Mi contestación a la parte económica (Alberto y María): Buenos días, de este expediente hemos hablado en otras ocasiones. Esta señora es la que no dispone de liquidez para aceptar la herencia de su hermano, creo ascendía el pago del impuesto, según nos dijo la gestoría, en unos 24.000€, motivo por el cual no vamos tampoco a renunciar, pero es posible que acaben subastando algún bien. Alberto, los pagos que comentas son correctos, porque el OAR se basa para el pago de los mismos en Catastro y conforme los certificados catastrales que están en su expediente y donde verás que tiene muchas participaciones de propiedad en bienes rústicos y urbanos de su marido y su hermano. Vuelvo a insistir, esta señora es muy mayor. Ya hablé con su hijo que tampoco dispone de dinero para pagar el impuesto de sucesiones, por lo que yo no movería nada y el día que ella falte, que herede el hijo y decida si vender, hipotecar o renunciar a los bienes de la herencia. Ha llamado varias veces la que dice ser cuñada de la tutelada Rebeca Gallego intentando que renunciemos a la herencia en nombre de la tutelada, lo cual acrecentaría la parte del resto, y no interesa porque insisto que el activo es bastante superior al pasivo. Otra cuestión es que no haya liquidez y no podéis hacer frente a ellas, por lo que debéis decidir qué ir pagando, aunque no será raro que embarguen su cuenta y lo poco que vaya teniendo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-06-20','Ana: Redacto oficio solicitando INFORME DE SALUD e Historia Clínica Resumida de Soledad a su MAP, Ana Belén Soria Iglesias - CS San Antonio de CC. Y de lo envío a Julio, CTAEx, para que lo remita por REGISTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-06-20','-Amalia : solicito al CADEX revisión de discapacidad , tenía un Gº del 51% provisional hasta 2008 . Se registra solicitud y sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2023-06-20','Ana: Envío a Sandra, TS Res. Real Patronato Coria (alexandra.alfonso@coria.org // 927 50 80 00) el consentimiento informado para prótesis parcial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-06-20','Ana: Correo de Ángel, A. Jurídico: "La vivienda donde vive, C/. CAUPOLICAN 7, Planta: 2, Puerta: D, es propiedad de Carlos y de su padre, al 50% cada uno, la adquirieron por herencia de la mujer y madre, respectivamente. Adjunto Nota Simple del Registro de la Propiedad. Con respecto a los 9.100 euros, en conversación con el padre, según comenta, ese dinero lo sacó Carlos, porque le dejó la cartilla para que pudiera hacer algunas compras necesarias, de comida, medicinas, etc, al encontrarse enfermo por esas fechas, en la actualidad parece que aún sigue, en cama, sin poder moverse mucho, pero se le fue de la mano y compró lo que se le ocurrió y le vino en gana, consola, ordenador, juegos, etc. Por otra parte, le he facilitado al padre el número de cuenta de Carlos, porque según dice, quiere devolverle 2.000 euros que son suyos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-06-20','Ana: Correo de Teresa, TS CTAEx: "Me llama Felisi que su hijo ha hecho un contrato de teléfono con un amigo, me da a entender que esta puesto a nombre del amigo. Habrá que estar pendiente por si hay algún cargo en alguna de las cuentas de Felisi o de Aitor por este concepto"','2');
