insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2023-06-20','Ana: Envío correo a Alberto, Jefe Secc. Ecca., en relación a la carta de cobros indebidos cuya devolución solicitan a Florencia y que nos han hecho llegar desde la residencia de mayores: "Te reenvío correo de Marta, TS de la Res. en que reside FLORENCIA SIMÓ MARTÍN. Me quedé muy sorprendida al recibirlo, pues al ser un cambio de una prestación económica de dependencia por otra prestación de servicio también de dependencia, esto lo suelen dar de baja automáticamente ellos y nosotras no tenemos que comunicar nada. Bajé ayer a hablar con Jorge Morán, Jefe de Unidad de Prestaciones Económicas de Dependencia. Ya hoy me han resuelto las dudas. Al parecer no anotaron en el SISTEMA que la Florencia está a cargo de la CTAEx, por eso no acertaban con el envío del documento (como veis firmado en enero de 2022) y, además, hubo problemas informáticos, por lo que no se cruzaron bien los datos (al parecer hacen cruces mensuales) y mantuvo las dos prestaciones (de servicio y ecca.) a la vez, aun siendo incompatibles… Por ello hay que hacer DEVOLUCIÓN DE COBROS INDEBIDIOS. Esta mañana he pedido a María que mirara la situación económica de Florencia y, dentro de lo malo, como ese dinero no lo ha usado lo puede devolver sin problemas. Te llevo todo lo que me han dado en papel, incluidos los movimientos que ha sacado María."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='SANTANTON'and apellido2='GOMEZ'),'2023-06-21','TERESA ENVIO ALTA A TERECEROS SOLICITADA PARA QUE LE VUELVAN A INGRESAR LA PESION QUE FUE DEVUELTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2023-06-21','Buenos días, Amalia. Juan Mora Rodríguez ha tenido que ingresar hoy en el hospital de Mérida, y es más que probable que se quede ingresado. He visto que tiene recursos, de manera que, si vemos que es necesario, se gestionará un acompañante, como hacemos habitualmente... No oye y es fácil que de desoriente bastante, con lo que creo que será imprescindible. -------------------------------------------- Doy OK a la peticion.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-06-21','-Amalia , envio email a TS del centro: ya me ha indicado el psiquiatra que el jueves le da el alta de la UHB y que ha contactado con vosotros para ir a por ella. Me está llamando su " novio " para ciertas peticiones: -que la dejen utilizar el movil durante el día. -que lo dejen visitarla , y salir con ella fuera del centro regresando en un par de horas . -que se le pida cambio de centro a otro en Badajoz o alrededores . Mi respuesta ha sido que todo lo relacionado con móvil , salidas y demás son decisiones que tomarán desde el centro . Lo que consideréis más oportuno . Igual facilitando las salidas se evitan las fugas. Con respecto al centro , estoy pendiente de la respuesta del SEPAD para ver si la pueden incluir para el Proyecto Mi Casa . Además voy a pedir traslado a 4 centros cercanos a Badajoz. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2023-06-21','VAMOS A DEVOLVER TODOS LOS RECIBOS POSIBLES RELACIONADOS CON TELEFONÍA, EXCEPTO VODAFONE. ESTRELLA: CADA 2 MESES HECHAS UN VISTAZO A LO QUE ENTRA X TELEFONÍA Y: • SE DEVUELVE TODO LO QUE NO SEA DE VODAFONE. • SI EL IMPORTE DE VODAFONE SE ELEVA X ENCIMA DE LO HABITUAL LO HABLAMOS. TERE: HAY QUE INTENTAR QUE PASE A TELEFONO X TARJETA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2023-06-21','-Amalia : se suspende juicio programado para hoy al 5 de julio, ya lo sabe Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-06-21','Ana: Envío correo a Toni-Futuex, con copia a Ana Benavente y Puerto Paniagua: "En relación a ENRIQUE SANTOS GARCÍA PUENTE, te reenvío correo de mi compañera Lourdes con un movimiento bancario que le ha llamado la atención. Como puedes ver en el documento adjunto, el gasto de telefonía ha aumentado sobremanera (del orden de 100 €). Dada su situación económica no puede permitirse este gasto de forma habitual. Por tanto, solicitamos que, además de explicárselo, le apoyéis en la gestión de la compra de una tarjeta de teléfono, de otra compañía diferente a poder ser, pues se va a proceder a dar de baja el contrato actual con Vodafone. *En cuanto al número, no sé si será posible mantenerle el mismo, para que no suponga muchos trastornos ni a él ni a los recursos, pero bueno, eso sería secundario y se podría comunicar a las distintas partes si fuera preciso. He acordado con Alberto, Jefe de Secc. Económica, que se le aumentará la asignación en 20 €/mes, para que pueda seguir asumiendo su gasto en telefonía (era lo que estaba presupuestado. El acuerdo era mantener el contrato con Vodafone siempre y cuando no aumentara este gasto) Por favor, avisarme cuando tenga la tarjeta nueva para dar de baja el contrato y no dejarle mientras incomunicado. Si yo hablo con él le explicaré también todo esto. Pongo en copia a Ana Benavente, TS del Equipo de Salud Mental, y a Puerto Paniagua, TS del SSASB, para que estén al corriente de la nueva situación y de la gestión que os solicitamos. Por cierto, como podéis leer en el correo de Lourdes, la factura de los electrodomésticos ya está abonada a su hermano. El tío declinó la devolución del dinero que le había prestado en otros conceptos." ········································· Respuesta de Puerto, TS SSASB: "De acuerdo, la verdad que mejor una tarjeta que la recargue..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2023-06-21','Ana: Correo de Sonia Generelo, Directora de la Res. Virgen de la Montaña - Grupo Ciudad Jardín (virgendelamontana@grupociudadjardin.com): "Ponemos en su conocimiento que en el día de ayer, fue derivado en ingresado en el hospital San Pedro de Alcantará D.Carlos Mª Grande Vicario, tutelado por ustedes." ······················ Nuevo correo de Sonia en respuesta a mi consulta: "La causa de la derivación fue un brote psiquiátrico cuya agitación no podÍamos controlar en el Centro. Nos comunica el psiquiatra del hospital que nos tendrán informados, según su evolución te iré informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-06-21','Ana: Envío correo a Alberto, jefe secc. ecca.: "En relación a CARMEN SOLANA CHANCLÓN, solicita de nuevo poder ayudar económicamente a su madre y su hijo (que vive con ella). Llevan meses pasándolo mal y aunque el hijo ha realizado recientemente varias entrevistas de trabajo no acaba de acceder a ningún empleo. No sé ahora mismo las posibilidades económicas que tiene, ni cuánto podría darle, pero esta petición viene desde ella misma, la TS del Equipo de Salud Mental y la Educadora del Piso Supervisado en que reside, pues es su demanda y cree que está en disposición de hacerlo. ¿Podrías mirar la posibilidad real y plantear una propuesta? Creo que la idea es darle alguna cuantía cada mes durante un tiempo (esto no lo especifican, podemos determinar un tope desde aquí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-06-22','Ana: Envío correo a A. Jurídicos CTAEx: "Ayer, día 21/06, Julia Morón Hernández, fue a Plasencia a una vista al Juzgado de lo penal nº 2 de Plasencia. El teléfono de su abogada de oficio, cuyo nombre no sabía decirme, es 691 56 70 50, por si la queréis llamar para averiguar algo más, pues no sabía decirme el número de procedimiento. Debe ser un procedimiento más antiguo, porque aquí, que yo sepa, no ha llegado nada. Si averiguáis algo ya me decís."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-06-22','miguel, recibo de la abogada Carmen Lucas la propuesta de liquidación de condena y la reenvío a Soraya, Maite y Ana para su conocimiento. Ya está internado en el Centro psiquiatrico penitenciario de Sevilla, siendo el cumplimiento de la condena hasta el 17-12-2024','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-06-22','-Amalia : registro a la SS documento para la TGSS pidiendo información sobre el cobro indebido .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-06-22','-Amalia : envio a Julio para registrar solicitud de centro de discapacidad por traslado o permuta y el informe del psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-06-22','Ana: Llamo a la Residencia de Mayores de Riolobos (927 45 30 15): hablo con Montaña, Responsable. La TS no está. La documentación la envirán más adelante. El cargo de la plaza lo realizan ellos, enviarán la ORDEN SEPA. ···· Los servicios de Peluquería, tiene un coste de 5€ y el de Podología, 10 €. *Estos también lo cargarán en la cuenta. Tanto la orden SEPA como esta información la remitirán al ctutelar@ ······························································································································································································ Envío correo a Toni-Futuex: "En relación a JOSÉ MANUEL MORENO CARLOS, le han concedido plaza en la Residencia de Mayores de Riolobos. Se ha fijado el traslado a la misma para el día 4 de Julio. Desde el CRR no pueden realizar el acompañamiento, el cuál creemos muy necesario para una adecuada llegada e incorporación al nuevo recurso. ¿Sería posible que VIRGINA, a la cual tiene de referencia y con la que tiene establecido ya un vínculo, realizara este acompañamiento?" ··································································· Respuesta de Toni-Futuex: "De acuerdo, perfecto. Anotado Con la compañera de referencia o con la que corresponda en el caso que ella tenga cosas agendadas ya ese dia, nos ocupamos de acompañamiento. Entiendo que el va en taxi? lo encontramos alli en la a su llegada resi no? como hacemos habitualmente .." ················ Envío correo a Paula, TO CRR-Plas.: "Nos confirman desde Futuex el acompañamiento ese día. Lo que no me pueden asegurar aún que se a Virginia. Le esperarán en la residencia. ¿Podrías, por favor, gestionarle un taxi para ese día? La factura debe ir a su nombre, se abonarán en cuanto nos la haga llegar, ya sea el propio taxista o la educadora al ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-06-22','Ana: Llamo a la Residencia de Mayores de Riolobos (927 45 30 15): no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2023-06-22','Ana: Correo de Pilar, Directora del Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "les informamos que Mª del Carmen Matilla Jiménez realizará la actividad "Viaje a las Ferias de Badajoz 2023" durante los días 23 al 26 de Junio. Como siempre les indicamos, esta actividad se realizará bajo la supervisión de profesionales del Hogar San Vicente De Paúl"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-06-22','Ana: Tras hablar con Maite Solana, Asesora Jurídica del IMAS (teresa.solana@ayto-caceres.es) y Carlos, recibo corro de Maite: "Atendiendo a lo acordado en conversación telefónica te adjunto la documentación relativa a la denuncia interpuesta por Carlos González Leo. He quedado con él para que se pase por aquí mañana para que yo pueda darle las indicaciones que me trasladéis ya que él sigue sin teléfono. Informarte que la próxima semana yo no estaré trabajando y que la Trabajadora Social que por zona corresponde a este chico es Tamara (Zona Centro) y su teléfono 927212335 Ext. 4414" ····························································· Reenvío correo a los A. Jurídicos de CTAEx, con copia a Toni-Futuex: "Os reenvío correo con DENUNCIA interpuesta por CARLOS GONZÁLEZ LEO y CÉDULA DE CITACIÓN PARA JUICIOS RÁPIDOS POR DELITOS LEVES para el próximo día 27/06 a las 9:40 h en el JDO. DE INSTRUCCIÓN Nº2 DE CÁCERES. Miguel o Ángel, ¿podéis llamara al Juzgado al respecto y ver si tenéis/podéis estar de alguna manera? O a las malas que al menos nos mantengan informados al respecto. Pongo en copia a Toni, para que esté al corriente y, Toni, solicitarte que si es posible, por favor, le acompañe alguna de las educadoras. Él decía que fuera Gloria, pero ya le he explicado que ya no trabaja en el programa y tendrá que ser otra. Podría esperarle allí, en el mismo juzgado un rato antes, pues de momento sigue sin móvil, ya que tiene que enviar un nuevo presupuesto más económico que el que él envió a la sección económica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-06-22','-Amalia : registro PIA de Alejandro , se solicita Centro REsidencial de discapacidad . No se ha dado autorizacion a la UHDAC para la salida que pedían para que fuese a ver a la madre ,al ser internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-06-21','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net):"Hola, como hemos hablado de forma telefónica te envío los datos relacionados con la expulsión de Isabel Cano, que tendrá lugar: Del 21 al 23 de Junio. Se alojará en el Hostal La Despensa de Plasencia. Las dos noches son 80 Euros. Desayuno, comida y cena de dos días 40 Euros. Transporte (autobús urbano) 5 Euros. Os facilito además informes por consultas de estos meses para que los tengáis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-06-23','Ana: Envío correo a Maite, Asesora Jurídica IMAS (teresa.solana@ayto-caceres.es): "Te reenvío correo que envié a mis compañeros jurídicos y a la coordinadora del Programa de Apoyo Comunitario gestionado por Futuex, con la respuesta que da esta última. Te lo envío a ti porque entiendo que hoy irá a verte, tal y como me dijo ayer. Después ya contactaremos con la TS de referencia para futuras cuestiones. ¿Por favor, cuando vaya Carlos a verte, podrías decirle que la educadora correspondiente estará esperándole en el Juzgado? Irá un rato antes de la citación. En cuanto al móvil, mis compañeras de sección económica me lo dijeron a última hora, que al parecer el Jefe de sección ha dicho que tiene que ser un presupuesto más económico y debe ir a elegirlo. Se lo han comunicado a él a través de una vecina. La cuál se extraña que ahora no tenga ninguno, pues no hace mucho dice que tenía 2, un IPhone y otro más. Gracias de nuevo por tu apoyo a Carlos y por tu colaboración con nosotras. A menudo los primeros meses de ejercer el cargo la CTAEx, resulta complicado “poner todo en orden”, luego, en función de los casos, suele marchar todo un poco mejor. Confío en que en este caso así sea." ··········································································································································· Correo de Maite, A. Jurídica: "Estuvo ayer aquí conmigo Patricia y he quedado con ella en que hoy cuando venga Carlos la aviso. Mantuvimos reunión con ella y con el Trabajador Social responsable de la valoración del Servicio de Ayuda a Domicilio para informarla de nuestras gestiones. También le presenté a la TS de zona y le facilitamos nuestros teléfonos y correos de contacto." ············· Patricia es el la nueva Ed. de Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-06-23','Ana: correo de Estrella Durán, TS CSS-Plas: "Concepción Fernández Muñoz va a hacer a partir del lunes una Hospitalización Parcial yendo al CRR a dormir, viniendo a hacer actividad ocupacional, comida y siesta en este centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2023-06-23','Ana: Ante el nuevo Correo de Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es) y conversación telefónica con la misma, envío correo a Alberto, jefe de secc. ecca: "Se ha puesto en contacto conmigo la TS del CSS de Plasencia, comunicando que Yolanda Caldera Martín se va de pase a su centro en Villanueva de la Serena del lunes 26 al viernes 30. Habitualmente , asume el C. Sociosanitario la ida y la vuelta la hace con el vehículo del centro de Plena Inclusión de Villanueva. Pero me dicen textualmente: “Nos estamos planteando, si se lo puede permitir económicamente, que pague ella el taxi para ir ya que tenemos muchas dificultades de transporte (faltan conductores y solo hay un coche)”, por lo visto el mismo lunes tienen que hacer otro traslado. Dinos en cuanto puedas si es viable el que asuma ella este gasto." ······································································································································ Desde la Secc. Ecca. llaman a Estrella, CSS, y confirman que puede asumir el gasto de taxi para ir el lunes al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-06-23','ESTRELLA.HABLO CON MANOLI RASCÓN(TS DEL CENTRO PENITENCIARIO DE SEVILLA.955 61 66 66)ME COMENTA QUE MEJOR SERÍA 250€, EL ECONOMATO ES CARO Y CON 200 € SERÍA POCO DINERO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-06-23','Ana: SUBCOMISIÓN SOCIOSANITARIA DE URGENCIA. Pte. de acta. ······························································································································································································································································· Correo de Paula, TO: "te escribo en relación a Isabel Cano. Tenemos dos cuestiones: - Una: ha recibido la cita para acudir a Cáceres para cita en cirugía plástica el día 3 de Julio a las 10.30. Nosotras desde el CRR no podemos acompañarla, era por si desde futuex se pudiera hacer el acompañamiento, puesto que creemos que es esencial que vaya acompañada. - Otra: el lunes venía la madre a verla. Acaba de llegar de la expulsión y no hemos podido hablar. No sé si a vosotras os da tiempo a abordar el tema o si, dada la premura contactáis la semana siguiente y se comienza ya todo el proceso desde ahí. Disculpad la urgencia, hablamos si queréis el lunes más extensamente, aunque si nos decís algo ahora sería genial." ···················· Mi respuesta: "dada la premura, que la vea este lunes y comenzamos después, pues con la madre también tenemos que hablar. Hoy ha sido imposible. Pido el acompañamiento a Futuex para la intervención. Por cierto, ¿requerirá días de ingreso? Para ver si hay que gestionar también acompañamiento en el hospital o no, y a me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-06-23','Ana: Mi correo-respuesta al que han enviado desde el Programa de Familia: "En relación a la compra de ropa y calzado, que remita un presupuesto de la tienda donde lo quiera comprar. Y en cuanto al que quiere ir al ECA (Antiguo CEDEX), nos parece perfecto. Tendrá que pedir cita al Medico de Atención primaria primero, para que éste le derive. No sé si podríais acompañarle vosotras a la consulta o desde el Programa de Apoyo Comunitario gestionado por Futuex. Pongo en copia a Toni, Coordinadora del mismo para que os pongáis de acuerdo. Ya me decís." ·································································································································· Respuesta de Toni: "Parece que ayer, consumió de nuevo, y hoy en contacto telefónico, ya no está dispuesto a acudir a ECA, no obstante, se continuara trabajando con el desde el equipo de apoyo social comunitario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-06-23','Ana: Envío correo a Julia, Coord. Casa de la Misericordia (casadelamisericordia.alcuescar@gmail.com): "En relación a DOROTEO DÍAZ CERRO, y como imaginarás, tras mucha insistencia por su parte, quería saber cómo sigue él y, si en vuestro criterio técnico/profesional, estaría preparado para ir a vivir sólo, pues en las últimas conversaciones telefónicas que he mantenido con él, ésta es su demanda. Sinceramente yo no creo que esté preparado para dar este paso, no estoy segura de que reúna capacidades para vivir de forma independiente, mantener unos hábitos de vida saludables y tomar la medicación de forma adecuada. Pero al fin y al cabo, quienes mejor le conocéis e intervenís con él a diario sois vosotras/os, por lo que os agradeceríamos, que cuando os sea posible, elaboréis un informe al respecto y nos lo hagáis llegar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-06-23','Ana: En relación a los cargos en cuenta por los que me pregunta Alberto, Jefe Secc., consulto a Estrella, CSS. Me corrobora que se le ha cobrado estancia en la UHDAC. Pero me facilita el número de Montse, de Gestión Ecca. del CSS (24150), para qué pueda aclarar mejor la cuantía cobrada (no se correspnde con el 75% de su pensión). ························· Maite y yo llamamos a Montse, Gestión Ecca. del CSS (24150), nos aclara que se le han estado cobrando cada dos meses, por eso la cuantía es más elevada. *Le cobran desde que se renunció a la plaza en Aprosuba3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ANGEL'and edp.apellido1='IGLESIAS'and apellido2='RODRIGUEZ'),'2023-06-23','TERESA HABLO CON LA RESIDENCIA 927452400 ME INDICA QUE NO GENERA GASTOS EXTRAS TAN SOLO PELUQUERIA Y PODOLOGIA Y LO CARGAN EN LA CUENTA JUNTO CON LA PLAZA REDIDENCIA YA NO ACUDE A PLACEAT','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERMINA'and edp.apellido1='LARIOS'and apellido2='CARRASCO'),'2023-06-23','-tf . DE R.M. VALVEDE DE LEGANES teléfonos de contacto: Lourdes.TS : 685964324 Centro : 685955448. Isabel : 6455010644.PERSONAL La persona que se va a encargar de todo lo relacionado con traslado y estancia es Isabel . La puedo llamar al tf del centro o a el personal . El ingreso se hará el 3 de julio , se abona a mes vencido , en agosto el primer mes que será un copago de 367.50€ que cargarán en su cuenta. A mes vencido cargaran otros gastos de farmacia ,pdologia y peluquería son cuantías pequeñas y enviarán factura. NO enviar gastos de bolsillo pq no salen acompñados por el pueblo . Para compras , acompañamientos .. extraordinario le pido contacte conmigo. Está en contacto con CRR que le enviará toda la documentación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-06-26','Ana: Envío correo a Toni-Futuex: "En relación a Isabel Cano Blázquez, tiene cita en cirugía plástica, en Cáceres, el día 3 de Julio a las 10.30. Desde el CRR no pueden acompañarla, ¿podría alguna compañera del programa de apoyo comunitario realizar este acompañamiento, consideramos muy importante que acuda acompañada. La cita es en relación a las cicatrices que tiene en el cuerpo a raíz de haberse prendido fuego en un intento autolítico y le producen mucho sufrimiento cada vez que se ve en el espejo. Ya con confirmas cuando puedas." ······················ Respuesta de Toni-Futuex: "Hemos hablado con CRR de Plasencia, para cuadrarlo. Se va a pasar la compañera por alli (le cae en ruta en otros seguimientos) para que Isabel le ponga cara, y se conozcan minimamente de cara al acompañamiento que se realizara el Lunes en Cáceress. Todo cuadrado ya"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-06-21','Ana: Conversación con Anabel, TS SSASB. La Jueza acudió a verla al domicilio. Es la misma que del procedimiento de incapacitación inicial, ya la conocía. ······································ *Le han concedido ya la PRESTACIÓN ECONÓMICA VINCULADA al SAD, a través de la Ley de Dependencia. Por lo que la Aux. del SAD Municipal dejará ya de acudir a su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-06-26','Ana: Subo al portafirmas digital la SOLICITUD DE REVISIÓN PIA - Solicitud de Prestac.Serv. de Atención Residencial. ············································································· Envío a Julio, Aux. Adtvo. CTAEx: "Adjunto la siguiente documentación relativa a JOAQUINA MAYORAL PIZARRO: - Solicitud de revisión PIA – Solicitud de Servicio de Atención Residencial - Informe Social – Anexo IV - Testimonio de Sentencia de Incapacitación - Testimonio de Aceptación del cargo - DNI José Vicente Granado Granado - Decreto Nombramiento Director Gerente - Resolución Delegación de Competencias Para que cuando puedas lo remitas por registro a la Unidad de Acceso y Valoración de Dependencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-06-26','Ana: Llamada de José Manuel (627 788 797): Dice que le ha hablado con Lourdes del IMAS, que le han concedido el Catering Municipal. ···················· Recibo correo de Lourdes Pérez Ortega - TS IMAS-CC(lourdes.perez@ayto-caceres.es // 927 21 23 35 Ext: 4425): "Hola Ana te informo que Jose Manuel Romero Mediavilla , tiene concedido el servicio de Catering del Ayuntamiento de Cáceres, seguramente se pondrán en contacto con el la empresa , para iniciar el reparto el jueves . Yo he hablado con él y se lo he dicho." ········································································································································ Llamo al Catering Mesa y Mantel (927 62 95 31): Confirmo baja en el servicio de José Manuel por habersele concedido el Serv. de Comida a Domicilio Municipal. ············ Lo comunico a Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-06-26','TERESA RECIGO LLAMADA DE M JESUS Y ME COMUNICA QUE ESTA EMBARAZADA, ESTA PREOCUPADA DE QUE PUEDE PASAR CON ESTE TEMA 610843541','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-06-26','Ana: Correo de Rocío Jociles del Solar, TS EVD - CC (mariarocio.jociles@salud-juntaex.es / 927 004 389): "...ha dado G III. Es cierto que no está para continuar en el CRR ya que, necesita de supervisión constante en todas las actividades básicas de la vida diaria e incluso de apoyo físico para la realización de muchas de ellas. Hable con la psicóloga y el terapeuta del centro y me comentaron que su madre se encuentra ingresada en C.R. El Cuartillo y que a veces lo llevan a que la visite, pero que apenas interaccionan ninguno de los dos. no se que preferencias queréis que ponga de petición de plazas residencial. cuando tu puedas me das un toque y lo hablamos" ················ Llamo a Rocío, acordamos que se solicitará plaza en: 1- C.R. El Cuartillo, 2- C.R. Cervantes, 3- CR El Prado, 4- CR La Granadilla".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2023-06-26','TERESA No se autoriza la compra del terminal puesto que en Febrero de 2022 se autorizaron 300€ para la compra de un móvil ( te adjunto el documento) puesto que se te había roto el que tenías. Por otra parte aprovecho para comentarte que de los 745 € DE EXTRA ANUAL, TE QUEDAN 145 € PARA EL RESTO DEL AÑO (Y ESTAMOS EN JUNIO) -----','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-06-26','-Amalia : de la extra de julio se le autorizan 200€ , para compensar los gastos extras del mes que estuvo en CRR . Se lo comunico tb a la TS . Han solicitado a diputacion el derribo de lo que queda de la casa de los padres para hacerle una nave donde pueda instalarse. Aún sin respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-06-26','Ana: Correo de Julia, Coord. Casa de la Misericordia (casadelamisericordia.alcuescar@gmail.com): "Por aquí vamos más o menos bien. Doroteo, lleva como dos meses insistiendo en la idea de irse a vivir solo. Es cierto que ha coincidido en el moemnto que le han rebajado la medicación y estaba más intranquilo. Desde hace como dos semanas, han vuelto a reajustar el tto y no me insiste tanto, es más, hay días que no me dice nada del tema. Desde el equipo técnico estamos de acuerdo en que no reune las habilidades necesarias para vivir de forma autónoma, pués lo primero que va a dejar es la medicación. Haremos el informe para enviarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-06-26','Ana: Correo de Julia, Coord. Casa de la Misericordia (casadelamisericordia.alcuescar@gmail.com): "En cuanto a Pablo Galán, estamos iniciando tratamiento en Cedex y vamos día a día ....."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-06-26','Ana: Envío correo al Progr. de Familias y Progr. de Apoyo Comunitario, con copia a Teresa TS CTAEx: "en relación con la información que nos facilita Toni, Teresa y yo os planteamos los siguiente. Ya nos decís si es factible y si podríais encargaros desde alguno de los dos programas: ¿Podríais gestionar igualmente la cita con el ECA a través del Médico de Atención Primaria? En caso de que no se presentara pediríamos informe de no asistencia para remitírselo al Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2023-06-26','Ana: Correo de Amalia: "me ha llamado el hno. de esta Sra. que está ingresada en R.Mayores en provincia de Cáceres . Tf. del hno. 695846836 Solicita cancelar la cuenta que tiene su hna. en el BBVA , porque está a 0 y ella ya no está en la localidad . Tendrás que comentarlo con la S. eco. Con lo que se decida , se lo comentáis , queda pte. de la respuesta." ························ Lo reenvío a Alberto, Jefe de secc. ecca., para que hagan las gestiones oportunas. ······ Pido que una vez hechas lo comuniquen a Fermín, hermano de Luisa (695 84 68 36), con quién también hablo por el mismo motivo. ················ Ambos hermanos están en la cuenta y la quiere cancelar.','2');
