insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-06-26','Ana: Envío correo a Soraya Masa: "Miguel, A. Jurídico, el viernes envió al Juzgado por LEXNET el escrito relativo a la solicitud de ingreso de GUADALUPE GIL CABELLO. Te lo digo más que nada para qué estés tú pendiente de esto, por favor" ························ Respuesta de Soraya: "me dijeron que al menos una semana tardarían ya que este juzgado se ocupa de los ingresos no urgentes. Estaré pendiente. Saludos"','2');
