insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-06-27','Ana: Correo de Manuel, desde la cuenta de correo de su hija (mariamartinflores635@gmail.com): "Ana que me lo e pensado mejor cuando me vaya a Mérida a un centro de Drogas, no porque tenga un problema con las Drogas, si para irme a un piso supervisado de Cáritas, cuando vaya ya le diré a la trabajadora social que te llamé, para acerme el ingreso mensual a mi, perdona por decirte que iva a decirle al director del banco que llamase a mi tutor.Pues eso Ana , cuando este en la garrovilla, centro de Drogas,le digo a la trabajadora social que te llamé,o como tú veas, como es en Mérida, pido cita y me acerco y ablamos, el piso supervisado es en Mérida también un saludo cordial mente y que paséis un buen día"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-06-27','Ana: Correo de Sara, TS de la Res. Banium Residencial (TrabajadoraSocialBanium@hotmail.com): "Hola buenas tardes. Se que solo trabajais de mañana. Concepcion Barbero ha sufrido una caida fortuita. Precisa operación quirurgica urgente. Por favor ponganse mañana martes lo antes posible en contacto con el Hospital Virgen del Puerto de Plasencia para autorizar la intervencion al servicio de traumatologia. Muchas gracias"','1');
