insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='VELASCO'and apellido2='CAPERUZA'),'2023-06-27','-Amalia : Hablo con la Dtra. de la residencia mixta, titularidad municipal , gestionada por Mensajeros de la Paz de Monesterio. Mª Angeles 924711970 En seguimiento pasará a la zona de Tere , yo hago el Plan de intervención. Sñor. de 68 años , viudo , verbaliza que sus hijos han fallecido pero este dato no está contrastado . Si viven no tiene ninguna relación con ellos. Ha sido transeúnte , consumidor de alcohol . Con deterioro cognitivo ,con problemas conductuales , han mejorado tras la nueva medicación psiquiatrica . No tiene seguro de decesos , pero tiene un seguro de accidentes en B. Santander. Tiene una deuda de un prestamo personal , hay que averiguar cuantía y entidad . Se lo comento a Icíar. Desde el Ayto. ingresan en su cuenta por copago de la plaza el 65% de la pensión. No quieren que se le envíe dinero de bolsillo , trabajan con él mejor cuando no tiene nada . Para necesidades extras de ropa , acompañamientos ... les explico procedimiento . Los gastos de farmacia los cargan en su cuenta . Peluqueria y podologia es gratuito. Percibe P. viudedad de 839€ al mes .','2');
