insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-06-28','Ana: Ante la consulta, de Sara, TS CR Banium (TrabajadoraSocialBanium@hotmail.com / residencialbanium@villatermal.com), sobre el acompañamiento realizado en ambulancia a Concepción, respondo: "Cuando nos ocurre estos casos (no en todas la localidades hay este tipo de empresas), las personas que realizan el acompañamiento redactan y firman una sencilla DECLARACIÓN JURADA, indicando: - Datos personales - El servicio de acompañamiento realizado - Fecha del mismo - Nº de cuenta bancaria para que se le abone mediante transferencia bancaria Pongo en copia a mis compañeras de la sección económica para que estén al corriente. Pues, como bien dices, ese acompañamiento hay que abonarlo. Cuando el acompañamiento tiene carácter de urgencia, y en fines de semana o por la tarde, como el de esta ocasión, podéis proceder de la misma manera. Cuando podáis preverlo, como una cita programada, debéis comunicarlo con antelación indicando el “presupuesto” (coste) para que se dé autorización desde la sección económica. Ante cualquier otra duda, no dudes en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-06-28','TERESA Solamente para poner en vuestro conocimiento que Aitor se ha ido con un amigo a Ceclavín, en principio nos ha dicho que serán unos días pero no tenemos más información. Cualquier cosa vamos hablando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-06-28','Ana: En relación al correo remitido por Elena - farmacia (farmaciamromano@hotmail.com), respondo: "De acuerdo, dado el informe SOAP de su Médica de Atención Primaria, desde la sección social de la Comisión Tutelar de Adultos, se acepta el cambio del bote de reflex que tenía dos veces al mes por la crema de CBD." ················ Guardo el Informe Soap en el exdpte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-06-28','TERESA Comentarte, que parece ser a tenor de los estados de Whatsapp, nos enteramos que M Jesús está embarazada, adjuntamos foto (que describo por si no se pudiera abrir bien) En la foto se ve una prueba positiva y un texto que dice "te amo en las buenas y en las malas y por nuestro bebe" "conta viento y marea te amo y por nuestro bebe" y banderitas de Perú, España y emoticono de mujer embarazada del whatsapp. Continúa poniendo excusas para establecer el seguimiento presencial. Y mantiene contactos telefonico, solo eventualmente. SE LO COMENTO A LOS JURIDICOS PARA VER SI TENEMOS QUE COMUNICAR AL JUZGADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-06-28','Ana: Envío correo a la Doctora Raquel Ortés, geriatra del Hospital Virgen del Puerto de Plasencia (raquel.ortes@salud-juntaex.es): "adjunto los documentos remitido por usted sobre el REGISTRO NACIONAL DE FRACTURA DE CACERA, firmados digitalmente por el Presidente de la CTAEx. Ante cualquier otra cuestión, no dudéis en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2023-06-28','-Amalia : Hablo con Ana Marta , TS , Joaquina y Fca han fallecido . Son las 3 hnas que estaban en las camitas . Quiere solictar para Angela una silla de ruedas electrica. No entra por SES por su discapacidad. Va a enviar ptos. y justificación de la necesidad de comprarla . Quizás necesitemos A. judicial pq superará los 3000€ o dos pagos ??','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-06-28','-Amalia : escribo mi respuesta a Ap3, solicito informe para solicitar autorizacion judicial para internamiento involuntario en RAL Buenos días, gracias por comunicar la situación de Antonia . Hemos intentado , tanto desde la CTAEX como desde Ap3 su adherencia al recurso de forma voluntaria , flexibilizando e intentando adaptarnos a su situación todo lo posible. Comparto vuestra opinión que en los últimos meses la situación se ha agravado , con continuas faltas de asistencia al recurso , cuando asiste es en malas condiciones .. La falta de colaboración de la familia , madre y hermanos , que incluso llegan a obstaculizar nuestra intervención se ha visto incrementada en los últimos meses. Su hermano mayor , ha llamado con amenazas hacia mí y otros compañeros de la Comisión , por el control económico que se tiene estipulado con Antonia y al que se niega totalmente .Es él el que se encarga de la administración económica de la casa . Ingresan entre todos los miembros de la Unidad de Convivencia varias pensiones y es evidente la falta de capacidad para administrarlos , les faltan servicios mínimos como ropa , alimentación.. pero les sobra móviles de última generación , TV ... Verbaliza que está haciendo gestiones para ser tutor de su hermana , no nos consta comunicación en este sentido del juzgado. Me parece conveniente solicitar autorización judicial de ingreso involuntario para plaza residencia en Centro Residencial de la red de discapacidad. Para ello , necesitamos un informe del centro en el que se haga constar su situación para justificar la necesidad de Antonia de salir de ese entorno y pasar a un centro donde todas sus necesidades básicas puedan ser cubiertas. Saludos. coordinacion.fa@aprosuba3.org Comisión Tutelar de Adultos;Amalia Diaz Gonzalez Susana >direcciontecnica@aprosuba3.org> Buenos días: Os comunicamos que: La calidad de vida de Antonia Perez, tutelada por la comisión tutelar, es bastante inestable en lo que se trata de casi todas sus áreas: Faltas de asistencia continuas para gestiones bancarias y asistencia a cuidados médicos Reporta, telefónicamente y con informe de asistencia a cuidados médicos de urgencias, situaciones de dolor físico, causadas, según la propria, por problemas orgánicos o accidentes domésticos Desconocemos se sigue la terapéutica recomendada para que se pueda curar de sus dolores y problemas físicos y orgánicos Cada vez que asiste al centro, trae ropa que nunca le habíamos visto, es decir, nunca repite ropa, pero pocas veces es la adecuada a su condición o está en buen estado Desprende un olor corporal, que llega a ser fétido, agravado por el calor En los días que asiste, en el autobús a primera hora, empiezan los conflictos con sus compañeros, y en parte por su olor, ya que no es buena compañía y genera conflictos con quien esté a su lado Por su situación personal, hay que trabajar las relaciones sociales en los talleres de habilidades sociales y por el hecho de que no asiste a los talleres, este trabajo se ve afectado, y por lo tanto disminuye sus habilidades para hacer frente a los conflictos que puedan surgir Desconocemos los hábitos de consumo familiares, pero tenemos conocimiento de que se emplean recursos económicos en gastos que no son de primera necesidad (por ejemplo, tiene más jigas de datos de internet y comparte con sus compañeros) y pueden afectar el acceso o otros bienes mas necesarios para su desarrollo, como pueden ser tener agua caliente para el aseo Desde el centro ocupacional, servicio de apoyo diurno a lo cual asiste intermitentemente, le hacemos un seguimiento, con pautas para que pueda mejorar su calidad de vida, pero consideramos que necesita de una acción más coercitiva de quien por derecho lo puede hacer, por ello os pedimos vuestra actuación y nos ponemos a disposición para colaborar en lo que esté a nuestro alcance. Un saludo. Catarina Mª Ferreira Barbedo Servicio de Apoyo a Familias Aprosuba 3 Plena Inclusión Badajoz Tfno.: 610292594 www.aprosuba3.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-06-29','Ana: Envío correo a Ana Benavente, TS ESM (anamaria.benavente@salud-juntaex.es) y a Mónica, Ed. PPSS (educacion.pisosplasencia@grupo5.net): "Os informo: - Carmen ya pasa habitualmente 150€/mes a su madre, Benita, en concepto de colaboración por manutención del hijo, desde hace bastante tiempo. No obstante, puesto que a día de hoy puede permitírselo, se aumentará la transferencia mensual que realiza Carmen a Benita a 300€/mes a partir del día 1 de julio. - Mónica, ¿puedes informar a Carmen para que sepa la cuantía y la fecha en la que se hará efectiva? Ya me iréis informando de las visitas al domicilio familiar que acordó con su madre a cambio. - Indicaros, para que lo sepáis, y también podáis comentarlo con Carmen, que Alberto, Jefe de Sección Económica, condiciona este aumento en la ayuda a su madre a “CONDICIONADO A MANTENER UN REINTEGRO MENSUAL Y EXTRAORDINARIO”, es decir, no debe haber más gastos al año para poder mantener esa transferencia más tiempo. - Sabed también que, seguramente, habrá que comunicar al Juzgado estas transferencias y puede que Carmen tenga que firmar esa petición de ayudar económicamente a su familia. De esto estamos pendientes de confirmación por el Asesor Jurídico." ································································································································································································· Correo-respuesta de Mónica, Ed. PPSS: "He transmitido la información a Carmen y se muestra conforme y más tranquila, aunque comenta que desconocía que ya le ayudaba económicamente. Justo llegó ayer de unos días en el domicilio y, aunque hace buena valoración, se muestra preocupada porque su madre le ha repetido en varias ocasiones las dificultades económicas que tiene. Comenta Carmen que Benita le ha llegado a coger dinero de bolsillo que llevaba sin pedírselo previamente. "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-06-29','miguel, recibo email de Rocio Gracian: Buenos días Miguel, No tengo noticias de los arrendatarios de Damián. Deberían entregar la vivienda mañana y mucho me temo que no van a cumplir el acuerdo pues no dicen nada. Para mayor problema, el gobierno aprobó ayer una nueva prórroga de la suspensión de los lanzamientos para familias en situación de vulnerabilidad económica hasta el 31 de diciembre. Es increible que lo hayan vuelto a prorrogar, ¡¡¡¡están amparando desahucios pendientes desde marzo del 2020!!!!. Una locura. Yo estoy preparando ya la solicitud de lanzamiento para presentarla el mismo lunes, si no hay noticias este fin de semana. Te sigo informando','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2023-06-29','-Ya se han enviado informes sociales para revision de sentencia y se lo he pasado a los juridicos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-06-30','TERESA En cuanto a Pablo Galán, estamos iniciando tratamiento en Cedex y vamos día a día .....','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2023-06-30','TERESA SE ENCUENTRA EN PISOS TUTELADOS HA NEGOCIADO RESIDENCIA Se encuentra en la posición N.º 20 para Los Pinos, N.º 50 para El Cuartillo y N.º 141 para Cervantes','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2023-06-29','TERESA Buenos días Teresa. Nerea ayer por la mañana sobre las 14.00 h. fue necesario recurrir a la policía local para que que la trajera al centro y se tuvo que avisar al 112 para que le inyectaran un tranquilizantes. Se negó a comer y a tomar la medicación. Con la cuidadora conseguimos que se duchara y se quedó dormida en el sofá. Cerramos todas las puertas y en un descuido de salida de uno de sus compañeros, nuevamente se escapó del centro. Me llamaron y fui a Castuera y estuvimos buscándola toda la tarde y sobre las 20.00 la localizamos sentada en un parque. Conseguimos convencerla y traerla nuevamente al centro y hoy parece que está tranquila.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2023-06-30','CIERRE DE EXPTE. POR REINTEGRACIÓN DE LA CAPACIDAD Con f/ 29/06/2023 la CTAEx conoce de la firmeza de la St. 9/23, de 14 de marzo, por la que se reintegra la capacidad de Dña. Aida María.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-06-29','Ana: Correo de Minerva, TS CR CERVANTES (minerva.salvador@salud-juntaex.es): "Esta mañana acude al centro solicitando el Club de Comida, José Manuel Romero, tutelado por la Comisión, me comenta que su educadora es Virginia, refiere que es usuario recientemente del servicio de catering del Ayuntamiento, pero que él prefiere venir a comer al centro a que le lleven la comida a su domicilio. Hablo con Virginia, efectivamente me confirma que esta semana ha empezado con el servicio de Catering. Le he dado la documentación necesaria para la solicitud del Servicio del Club de Comidas. No obstante, me dices si lo consideráis adecuado que pueda ingresar en el Club de Comida del centro, para gestionarlo o no. En el caso que se haga la solicitud, me comunicas el importe de la pensión de José Manuel y os digo lo que pagaría o si está exento de pago." ························· "José Manuel es súper demandante, él insistió en el Catering Municipal gratuito y justo ayer era el primer día que se lo llevaban y ya estaba pidiendo otra cosa… Yo, como sabes, me marcho ahora al curso. Si vuelve por ahí, le indicas, si no te importa, que la solicitud la tienen que firmar el Presidente de la CTAEx, y que esto no se va a valorar hasta que yo vuelva de vacaciones (el día 18 me incorporo). Él sabe que esta semana estoy de curso y las dos próximas tampoco voy a estar. Ya lo hablamos si quieres a mi vuelta."','2');
