insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-07-03','-Amalia , me pregunta Miguel jurídico dónde dejar las llaves de la casa de Málaga . Esta es mi respuesta. : en mi opinión es mejor que se las quede su prima en Málaga , para cualquier incidencia en la que se necesite que abran esa puerta . Damián no tiene claro qué hacer con esa vivienda , unas veces dice de alquilar , otras de vender y otras de que se vuelve él allí a vivir . Si quieres puedo consultar con el centro que pregunten su opinión actual , pero ya sabes que cambia mucho de opinión y no es permanente en sus decisiones. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2023-07-03','TERESA Me pongo en contacto para comunicarte que ya le toca hacer la visita de Bea a su hija. Si no tenéis inconveniente puede irse en tren este próximo lunes día 3 de julio porque iría acompañada de un compañero de residencia que va hasta Plasencia y su padre que la recoja en Cáceres como siempre. Comentaros que su madre al parecer ha renunciado definitivamente a la plaza que tenía en el centro de mayores de Navalmoral y ha regresado a la casa y convive con el padre. Vinieron juntos a pasar el día con Bea el pasado lunes Ya me dices si te parece bien','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2023-07-03','TERESA Te remito certificado de José Luís de estar institucionalizado en COMSER. Él no está empadronado en Almendralejo, ya que solo empadronamos a petición de la familia por venta de vivienda, o en casos de que tengan plaza definitiva aquí y cosas así. Él es de Plasencia y cuando ingresó le trajeron desde el Hospital Virgen del Puerto de Plasencia. Con anterioridad estuvo en el CAMP de Plasencia, así que imagino que seguirá empadronado en Plasencia. Te facilito teléfonos de contacto de personas próximas a él: - Sobrino Antonio: 639 358 430 - T. Social de Centro donde estuvo él anteriormente en Plasencia, Ana Marta 924 01 72 81 - Rafaela Moreno, madrina y amiga de la familia: 625 878 125','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2023-07-03','TERESA ARCHIVO ACEPTACION UHDAC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2023-07-27','TERESA ESTA MAÑANA SE HA LEVANTADO Y SE HA ESCAPADO DEL CENTRO. SABEMOS DONDE ESTA, HEMOS INTENTADO EN 3 OCASIONES TRAERLA PERO SE NIEGA EN ROTUNDO. ESTA AVISADA LA POLICIA LOCAL Y LA GUARDIA CIVIL Y LA HORA DE LA COMIDA INTENTAREMOS NUEVAMENTE ENTRE TODOS QUE ACCEDA AL CENTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-07-03','TERESA Recibo correo de su hermano Juan, solicitando que necesita hablar con nosotros. Le llamo ( 687819309) y manifiesta que la situación está cambiando para mal, que está descontrolado, la convivencia con la madre no es buena. Ha estado tres días en casa sin ir al centro poniendo la excusa de que le dolía la barriga. Le ha visitado Virginia y no ha querido hablar con ella. Juan manifiesta la necesidad de ir a un centro porque la madre no puede ya con la situación con su hijo ya que no hace caso a nada y las peleas son continuas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='SOSA'and apellido2='MARTINEZ'),'2023-07-03','TERESA SE ENVIA AUTORIZACION PARA QEU EL DIRECTOR RETIRE EL DINERO DE BOLSILLO Y PUEDA PAGAR POLOGIA Y PELUQUERIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-03','-Amalia . Sigue ingresado en la UHB de Cáceres , contacto con la TS (56283 Mª Carmen ) pronóstico de alta entre hoy y mañana. He gestionado varias opciones de recursos al alta hospitalaria : -Centro de Cáritas en Cáceres donde previamente había estado : Contacto con Caritas para ver posibiidad de plaza en ese centro . Me indica Pedro Pablo que en la actualidad no hay plaza disponible. -CES de Cáceres , tienen que ir personalmente sobre las 20.00h a solicitar plaza , y entran sobre las 22.00h. Miguel Angel conoce el proceso , se le va a informar de esta opición. -Comunidad Terapéutica , sería el recurso idóneo ,ingresó hace unos meses en la C.T. La Garrovilla y solicitó el alta voluntaria . Planteo a la TS de la UHB si existe voluntariedad para el ingreso , cree que no , está " deseando salir de alta " , no quiere ingreso en recurso. -CRR , en comisión de valoración quedó pendiente de su tto. en C. Terapeútica que no cumplió. -Domicilio famiLiar en Aliseda , Orden de alejamiento de la madre , hermanos y de la localidad. La única opción posible e inmediata es el CES de Cáceres. ................................................. Con respecto a PNC , nuevamente solicitada por Ana , contacto con pensiones . Se la van a denegar por no tener Gº discapacidad . Le paso información de la modificacion del RDLGSS al respecto para que lo vuelvan a valorar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-07-03','-Amalia: llama Cristina , nueva TS del CSS Plasencia para comunicar que se va a su domicilio familiar con los padres . Enviará email a Ana explicándolo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERMINA'and edp.apellido1='LARIOS'and apellido2='CARRASCO'),'2023-07-04','Soy Isabel Morales, de la residencia de Valverde de Leganés. Ayer recibimos a FERMINA LARIOS CARRASCO, procedente de CRR de Mérida, a la cual le han concedido una plaza pública del SEPAD en nuestra residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERMINA'and edp.apellido1='LARIOS'and apellido2='CARRASCO'),'2023-07-04','Fermina Larios Carrasco : Ingresó ayer en R. Mayores Valverde de Leganés procedente del CRR de Mérida . El copago de la plaza lo van a cargar en la cuenta que tiene en la Caixa que es donde tiene más dinero ,367.50€ / mes . Gastos de farmacia y podología , serán poca cuantía, también lo cargan. Le vamos hacer un reintegro permanente de 100€ para gastos de bolsillo , para tabaco la mayor parte . En el pueblo tienen IBERCAJA , y Fermina también tiene una cuenta ahí , el reintegro es para que lo saque en esta entidad . Saludos.','2');
