insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2023-07-03','miguel, llega a ctutelar email de juan jose rebate gallego >juanjorebate@gmail.com> Con fecha de 2 de mayo del corriente año, le envié un correo solicitando la renuncia del usufructo de Emilia Gutiérrez Serradilla, y a fecha de hoy 1 de julio no tengo respuesta a tal solicitud, ruego me remitan respuesta, por la urgencia de la venta apalabrada al futuro comprador de los solares. Reciba un cordial saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2023-07-04','mi contestación a juan jose rebate gallego >juanjorebate@gmail.com> : Buenos días, tras conversación con la familiar Rebeca Gallego, ya se le informó que no se va a proceder a renunciar a la herencia. También contactamos con el abogado José Lomo Carasa en febrero 2023 para que se remitiese a esta Comisión Tutelar de Adultos de toda la documentación que compone la masa hereditaria para su estudio. Conforme el artículo 287 Código Civil para la aceptación, aprobación de herencia y si se precisase futuras ventas, será requisito la correspondiente autorización judicial para lo cual es necesario aporten toda la documentación correspondiente a la testamentaria y la masa hereditaria que compone la herencia junto con la tasación de las fincas para poder comenzar la correspondiente solicitud de abogado que interponga la correspondiente demanda para la mencionada aceptación de herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2023-07-05','TERESA ENVIO POR CORREO POSTAL DOCUMENTANCION SOLICITADA DESDE SUIZA PARA EL COBRO DE PRESTSACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2023-07-04','TERESA Está últimamente con algunos temas médicos que nos preocupan…ayer en revisión de psiquiatría le cambiaron haloperidol por medicación más actual de forma progresiva y hoy su medico lo deriva a digestivo y a ecografía abdominal y rectal. Las analíticas han dado bien aunque hay sangre en una de las muestras de heces y de ahí, y de nuestra insistencia, que sigan haciendo pruebas. Ha perdido mucho peso y tiene un deterioro importante. En Chipiona es donde vive su única hermana y por eso tenemos interés en que vaya, si no hay ningún otro contratiempo o empeora porque ir a Chipiona a ver a la familia es de sus únicos alicientes en la vida y lo espera durante todo el año.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2023-07-05','miguel, atiendo presencialmente a Montserrat 642-544615 y Amparo Ortiz Gordillo quines me piden firmemos la escritura de herencia de la fallecida Josefa Zambrano Rodriguez. Hablo con la notaria de Fuente del Maestre (Pepa: 673195265 quien me confirma que envió el borrador para su verificación a Angel hasta hoy sin respuesta) Me enviará el borrador, y lo firmarán en cuanto lo revise. Lo ratificaremos posteriormente en Mérida y junto con la aprobación de herencia pretenden pidamos la Autorización de Venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2023-07-04','TERESA RECIBO CORREO DEL SASB Hola Teresa, me dicen desde Futuex que el hijo de Ana Cruz Santos sigue haciendo uso de la tarjeta. Me informa el banco que para cancelarla debe tener la orden de la Comisión Tutelar de Adultos por escrito, porque en el mandamiento recibido no consigue ver donde puede acogerse para hacer dicho tramite. Gracias. Saludos. A FEHCA DE HOY SEGUIMOS SIENDO DEFENSORES JUDICIALES Y LA PENSION NO HA ENTRADO EN LA NUEVA CUENTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AVILA'and apellido2='RAMOS'),'2023-07-05','TERESA YA ESTA LA PENSION EN LA NUEVA CUENTA SE MANDA AUTORIZACION PARA QUE PALOMA (menapaloma@gmail.com) LA DIRECTORA RETIRE 100€ MENUSALES PARA CUBRIR LOS GASTOS DE BOLSILLO SE FACILITA NUMERO DE CUENTA PARA QEU EL AYUNTAMIENTO CARGUE LA CUOTA DE LA PLAZA RESIDENCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2023-07-05','Buenos días, nos ponemos en contacto con esta fiscalía, tras la conversación telefónica de ayer para comunicarles que conforme las indicaciones que nos hicieron, hemos procedido esta misma mañana a instar “solicitud de internamiento involuntario urgente” del juzgado de guardia de Cáceres que corresponda, debido a que este tutelado que se encuentra actualmente cumpliendo condena en el Centro Penitenciario de Cáceres, se niega a recibir el tratamiento necesario. Pongo en copia al neumólogo del Hospital San Pedro de Cáceres Don José Antonio Durán Cueto y a la trabajadora social de la Comisión Tutelar de Adultos Doña Amalia Diaz Gonzalez. Se adjunta la documentación presentada. Es de carácter urgente porque pretende su alta voluntaria, y se niega a seguir las pautas médicas de tratamiento médico, con el peligro inminente que eso supone. Se adjunta además del informe médico, la sentencia por la que se nombró curador en el ámbito de la salud (alta médicas, tratamientos médicos, etc) a la Comisión Tutelar de Adultos. Quedando a su disposición para cualquier aclaración o posteriores actuaciones que nos indiquen a realizar. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2023-07-04','-Amalia . Usuario ingresado en Hospital Virgen de la MOntaña derivado del Ctro. penitenciario de Caceres por problemas de asma bronquial grave. Es la cuarta vez que ingresa pero luego solicita alta voluntaria y deja el tto. En esta ocasion el neumologo contacta con la CTAEX , vemos que la curatela es para el tema de la salud y el alta corresponde a nosotros otorgarla . Pero el paciente amenaza que o se le da el alta voluntaria o se quita la via , medicacion.. Hablamos con fiscalía , es necesario soliictar autorización internamiento involuntario . Se pide informe médico y hacemos Expte. jusisdicción voluntaria con Miguel que se encarga de enviarlo a Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2023-07-05','-Amalia . el neumólogo ante la no colaboración del paciente ha cambiado su criterio y le va a dar el alta voluntaria . Le pido que me lo reenvie para firmarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2023-07-05','TERESA Desde el centro donde estaba anteriormente José López Ruiz, nos facilitaron un número de cuenta, a ver si coincide con los que tenéis en la comisión tutelar para formalizar la documentación del residente. Te adjunto el número: ES21 2085 4511 9503 3252 6126 Caja Almendralejo Muchas gracias por tu atención. Daniel Salas (Trabajador Social, Centro de Mayores San Miguel).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-06','-Amalia : contacto con Caritas , para preguntar si ha ido a ese centro o al centro de emergencia social tras el alta de la UHB . Me indican que no ha pasado por allí . Pido que me envíen la respuesta por email para comunicarlo al juzgado . Solicito también a la UHB informe de alta con la misma finalidad . LLamo al tf personal de Miguel Angel , da llamada pero no lo atiende .','2');
