insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-13','-Amalia : hablo con PNC de Cáceres nuevamente junto con Miguel , hay un error de interpretación de la LGSS y se la van a denegar. Se ha acordado , que cuando llegue la denegación , hay que recurrirla por los asesores jurídicos para que se pronuncien al respecto y se aclare ese artículo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2023-06-30','SALIDA Peregrinación Diocesana a Lourdes. Lourdes. Hora salida: 19:30. Hora Regreso: 00:00. Monitor: Pertenecientes a la hospitalidad. Tpte.: Perteneciente a la hospitalidad. Organiza: Diócesis Coria-Cáceres. Hospitalidad Nuestra Señora de Lourdes. Teléfono de contacto en Lourdes para dar a los familiares en caso de urgencia: 609 34 82 73. Acompañantes: Pertenecientes a la Hospitalidad. Observaciones: Día de salida: llevar bocadillos, sandwichs, zumos, agua, etc, para la cena; Solicitan llevar medicación suficiente y levarla a mano; Enseres, útiles de aseo, toallas de baño, toalla de lavabo, chubasuero, ropa de abrigo, calzado cómodo, pañales, cuadrantes, mascarillas, etc; Entrega de equipajes en la sede de la Hospitalidad.','2');
