insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2023-07-06','-Amalia : han trasladado a Jonatan desde Estremera al ctro. penitenciario de Badajoz , estará solo 2 semanas para asistir a un juicio. A la S. eco , solicita algo de dinero para estas 2 semanas , en Estremera lo tiene limitado a 20€ semanales y está sin dinero . Se le puede poner 40€ para estas dos semanas. Es la misma cuenta peculio que tenía antes de irse , y su Nº de identificacion es 2017000499. Miguel , tiene juicio por robo con violencia el 19 de julio en Jgo. Nº 1 de Badajoz , por informaros. No sé si tenéis información al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-07-06','TERESA ENVIO DOCUMENTO DE BAJA DEL SERVICIO A PLACEAT','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-07-07','TERESA RECIBO LLAMADA DE BEATRIZ ESTA DE PASE EN CASA DE SU MADRE, ME SOLICITA DINERO PARA COMPRARSE ROPA HABLO CON SU HERMANA ROSA Y ME COMENTA QUE CONSTANZA LE HA DICHO QUE LA VAN A DERIVAR A UME LA SEMANA QUE VIENE AUTORIZO TRANSFERENCIA ADELANTANDO LA QUINCENA PARA QUE SE PUEDA COMPRAR ROPA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2023-07-07','TERESA RECIBO LLAMADA DE M ELENA, ME COMUNICA QUE LA SITUACION EN SU CASA ES MUY TENSA CON SU PADRE Y HERMANO QUIEREN LLEVAR AL PADRE A UNA RESIDENCIA M ELANA ESTA MUY NERVIOSA Y ANCOHE LA LLEVARON AL HOSPITAL, HA PASADO ALLI LA NOCHE Y EL VAN A DAR EL ALTA HE SOLCITADO RESIDENCIA EN TODA LA COMUNIDAD PARA QUE LE DEN PLAZA LO MAS RAPIDO POSIBLE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2023-07-07','TERESA He hablado con el Abogado y van a solicitar la remoción del cargo que ostentamos, para que lo asuma su hijo. Hasta entonces no hacemos nada relacionado con la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2023-07-07','miguel, email de Amalia a la parte económica, social y juridica: Buenos días, por comentaros sobre el tema de la posibilidad de que tengan carnet de conducir . Los médicos y psiquiatras no hacen informe negativo para ello , aunque estén tomando medicación que pudiera afectar a la conducción. Nos remiten a que los centros de reconocimiento lo autoricen o no . Otra cosa distinta , es que económicamente se lo puedan permitir o no . Un saludo. --------------------------------------------------------- mi contestacion: Buenos días os adjunto anotación en la intranet del 11-11-20: “miguel, llega este email de Curro: En relación a la petición sobre el PERMISO DE CONDUCIR. Se trataría de una modificación de la capacidad, en dicho aspecto por l o que ruego que a la mayor brevedad remitáis escrito en tal sentido, del Director de la CTAEX, además lo remitís también soporte WORD. Pero sobre todo pido que se remita algún elemento de prueba de la necesidad de modificación de la capacidad en tal aspecto. Con la documentación que habéis remitido no se incluye. ********************************************************* le reenvío el email de Curro a la parte económica (Alberto y Juana), social (Amalia y Pedro): Buenos días, en relación a Fco Javier Rodriguez Robles, tal como me solicitasteis desde la parte económica he solicitado por fax al Jzdo nº4 Badajoz retirada del carne, a lo cual hicieron caso omiso, tras hablar con el Jzdo 2 meses después no tenían ni idea donde estaba el fax y me pidieron lo enviara por escrito y oficio, así lo hice a final de Septiembre, 20 días después nos denegaban dicha petición por no estar solicitada vía Lexnet. Dicha incidencia junto con la documentación se la remití por 2 veces a secretaría general (Mª Guerrero) para que remitieran dicha documentación. Hoy nos llega este email de Curro, donde nos viene a indicar que fundamentemos nuestra petición. Dicha petición no pude acreditarla pues me basaba en lo que me comentabais desde el departamento económico de que era un peligro y que a Juana la insistía constantemente en que le adelantemos dinero para recuperar el carne de conducir (y de ahí nuestro dilema…sino estamos de acuerdo con que recupere el carne de conducir, estamos o no obligados a adelantarle ese dinero?), es por ello que hice las comunicaciones o solicitudes anteriores al juzgado. Pedro no sé si podrás hablar con Curro y que te aclare un poco qué es lo que quiere. No sé si por la parte social (Amalia) y económica (Juana) podéis aportar algo en que fundamentemos nuestro escrito al juzgado(emails, quejas…lo que sea). Como veis cada juzgado actúa de una forma, pues con Santos Cordero hicimos lo mismo por fax y ya está pendiente que resuelva el juzgado (ya le ha visto el forense). Por mi parte salvo que me aportéis documentación o algo no puedo hacer más.” Presentamos ese año solicitud de autorización para la retirada del carnet y esa documentación se ve que se perdió en el juzgado, creo que en el nº4 de Badajoz, pues se presentó en el juzgado decano. Alguna aclaración que no sé si se le llegó a contestar a Curro que está anotada y adjunto debajo, imagino que no se le contestaría y él no nos comunicó nada del procedimiento. Por tanto para solicitar retirada del carnet yo me esperaría a que hagan la revisión de medidas de apoyo conforme la nueva ley 8/21 donde indicarán las limitaciones que tenga. Y es ahí donde desde la Ctaex deberíamos decirle en qué basamos nuestra recomendación de retirada del carnet de conducir. Lógicamente si como dice Amalia en su email no hay informes médicos que aconsejen que no puede conducir será casi imposible solicitar la retirada del carnet.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2023-07-07','miguel, llega a ctutelar email del gestor miguel mariscal: Buenos días: Soy el gestor que se está ocupando de los trámites de testamentaría encomendados por Dª Concepción Valcarcel Vidal, a raiz del fallecimiento de su hermana Silvia. Quedarían 3 hermanas, Mª Isabel, Concepción y Sonia como únicas herederas de los bienes de sus padres, siendo estos un piso en Madrid principalmente. Corresponde hacer ahora las herencias de los padres fallecidos (Antonio Valcarcel y Malo de Molina y Mª Asunción Vidal Goy) y a continuación la de la hermana Silvia. En tanto que Sonia es una persona incapacitada y sería la Junta de Extremadura quien la represente en, le doy traslado de la situación actual. De momento le adelanto la documentación que tengo en mi poder, pues el certificado de saldos bancarios aún no se nos ha facilitado. Quedo a su disposición para lo que pudiera necesitar o comentar. -------------------------------------------------------- Tras conversación con él me confirma que la notaria de Norberto Santa Maria de Caceres será donde se firme la Herencia. Le comento que en principio si la notaria no tiene inconveniente se podría firmar la escritura de herencia para después ser ratificada por la Junta en Mérida. --------------------------------------------------------- Le envío email explicativo en ese sentido conforme me solicita Miguel Mariscal >miguel@otelso.com> 675891313: Buenos días, recibida la documentación por email consistente en fotocopia del certificado de defunción de su hermana Sonia y fotocopia de las escrituras de compraventa del inmueble. Tras conversación telefónica le indico los pasos a seguir de tramitación de adjudicación de herencia en partes iguales a las hermanas Concepción y la tutelada Sonia: -Necesitaremos su presupuesto de la parte a abonar por Sonia teniendo en cuenta que hay que tramitar la herencia de los padres y hermana de Sonia, Silvia, (testamentaria+certificados bancarios+liquidación del impuesto de sucesiones+preparar la documentación necesaria en notaria+ tras aportar la autorización judicial de aprobación de herencia a tramitar por la Comisión Tutelar de Adultos de la Junta (mediante la intervención de abogado) una vez firmada dicha herencia, la cual sería ratificada por dicha Comisión Tutelar de Adultos en la notaria de Mérida. -Una vez que el oficial de la notaria solicite acreditación del cargo de representante de la tutelada Sonia por parte de la Comisión Tutelar de Adultos, ésta remitirá la oportuna documentación acreditativa a la notaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2023-07-07','TERESA solicito autorización para vacaciones como periodo de integración familiar de Hermenegildo Ruiz desde el 19 de julio hasta el 24 de julio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2023-07-07','-Amalia : Fco. vuelve a pedir dinero para renovar el carnte de conducir . Con respecto a esto Miguel aclara que se pidió en 2020 al juzgado y explica : Presentamos ese año solicitud de autorización para la retirada del carnet y esa documentación se ve que se perdió en el juzgado, creo que en el nº4 de Badajoz, pues se presentó en el juzgado decano. Alguna aclaración que no sé si se le llegó a contestar a Curro que está anotada y adjunto debajo, imagino que no se le contestaría y él no nos comunicó nada del procedimiento. Por tanto para solicitar retirada del carnet yo me esperaría a que hagan la revisión de medidas de apoyo conforme la nueva ley 8/21 donde indicarán las limitaciones que tenga. Y es ahí donde desde la Ctaex deberíamos decirle en qué basamos nuestra recomendación de retirada del carnet de conducir. Lógicamente si como dice Amalia en su email no hay informes médicos que aconsejen que no puede conducir será casi imposible solicitar la retirada del carnet. ........................ yo he respondido con las ultimas conclusiones de otros casos en comun : Buenos días, por comentaros sobre el tema de la posibilidad de que tengan carnet de conducir . Los médicos y psiquiatras no hacen informe negativo para ello , aunque estén tomando medicación que pudiera afectar a la conducción. Nos remiten a que los centros de reconocimiento lo autoricen o no . Otra cosa distinta , es que económicamente se lo puedan permitir o no . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-07-07','TERESA Buenos dias, se envia presupuesto, de ropa reservada, para el tutelado Juan Jose Gonzalez, Hace unas semanas se acompañó a el tutelado a ver ropa de entre tiempo y verano para solicitar un presupuesto, selecciona unas cuantas prendas y se pide en la tienda que manden la factura, con el número de cuenta, para la transferencia. Desde Tara, envían la factura y, a parte, el número de cuenta, es el siguiente: ES83 2100 2283 9302 0024 4740 El presupuesto para la compra de la ropa es de 159,96€, se adjunta factura a continuación: desde Tara comunican que no pueden tener la ropa reservada durante mucho tiempo, y es cierto que el tutelado la necesita, si se aprueba se solicita nos lo podais indicar para acompañarlo a retirarla. SE AUTORIZA LA COMPRA, PASO CORREO A CTUTELAR PARA QUE ABONEN POR TRANSFERENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-07-07','TERESA Se ha recibido una llamada de Constanza (psiquiatra de la UHB de Llerena) telefono 924877037, comentando que la próxima semana trasladarán a Beatriz Mejías al sociosanitario de Mérida, no saben fecha concreta. Explica que la tutelada necesita ropa que tendría que comprarle Rosi, de modo que la Comisión tendría que autorizar a Rosi algo de dinero para que pueda comprar dicha ropa o lo que ellos consideren o hayan hecho en anteriores ocasiones. Esto es lo que dice Rosi y la psiquiatra, pero si considerais oportuno hablar con ellas para acordar otro modo de hacerlo, o traves del socio una vez este, como se considere. Por otra parte, Constanza asegura que Beatriz está un poco mejor y autorizarán este próximo fin de semana que se vaya a casa con su hermana y su madre. También solicita que se comente a la Comisión la preocupación de la tutelada por perder el piso en el que reside actualmente, Constanza explica que Beatriz estará en el socio como máximo dos meses con lo cual sería recomendable que se continúe con el alquiler de dicho piso para que pueda volver cuando le den el alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2023-07-07','miguel, tras recibir email de Tere a la parte social y jurídica con informe de Futuex comienzo a preparar nuevo internamiento involuntario del tutelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-07-07','miguel, presento presencialmente en el colegio de abogados junto con el abogado jorge calvo la solicitud de asistencia gratuita con solicitud de que sea él el abogado de oficio a nombrar. Me enviará solicitud para la firma por representante de la Ctaex de la solicitud de asistencia gratuita en aplicación del art 28, es decir nombrando el abogado que se quiere sea el de oficio Por mi parte iré preparando el poder apud acta para la ejecución de laudo arbitral','2');
