insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2023-07-10','CURATELA REPRESENTATIVA Mediante Auto n.º 66/23, de 23 de mayo; X58 Provisión de Medidas Judiciales de Apoyo 554/22; se nombra a la CTAEx Curador Representativo de D. Carlos María. Se procede al cambio de expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-10','-Amalia : recibo email de la TS del hospital , finalmente ha estado allí ingresado unos días más ; le vuelvo a pedir informe de alta : Por orden de la psiquiatra Dra. María García informa que hoy se le va a dar el alta al paciente. Desde el día 4 de julio estaba prevista dicha alta, pero se han estado buscando recursos alternativos a ésta y no ha sido posible encontrar ninguno. Así que, se hará efectiva el alta esta tarde y se aconseja al paciente acudir al centro de emergencias de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-07-10','TERESA Me pongo en contacto con ustedes para informar de la situación de Concepción Barbero, Tras la última intervención la pierna izquierda en esta ocasión no esta evolucionando favorablemente, la pierna tiene flebitis, esta endurecida, rotada, se le están saltando las grapas y posiblemente la usuaria presente febricula. Es por ello que hemos tenido que llamar a la médico del SES para que la valore en la mañana de hoy. La doctora ha valorado que se procede a derivar en la mañana de hoy de nuevo al hospital Virgen del Puerto de Plasencia de urgencia. Es por ello que se le va a solicitar acompañamiento como en la ocasión anterior para que vaya con ella en la ambulancia y permanezca con ella hasta que se realice en urgencias su diagnostico y se suba a planta. Donde ya hay personal sanitario que puede encargarse de ella y de informarnos de su estado y evolución. Escribo este mail para que se informe al servicio económico para que tenga en cuenta que esta pendiente el pago del traslado anterior de 71€ (pendiente que el acompañamiento nos entregue el modelo de justificante), y de que habrá otro recibo pendiente del acompañamiento realizado en el día de hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-07-10','miguel, llega Auto no firme (5 días para recurso de apelación)denegando el internamiento involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2023-07-07','miguel, dejo presentado en el colegio de abogados de Badajoz el escrito del abogado de oficio que ha renunciado por incompetencia, Francisco Garcia Vela, para que tramiten la nueva designación(conforme el email que nos remitió el abogado el 4-7-23)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-06','miguel, recibo email de Amalia: Buenas Miguel , este chico ha estado ingresado en la UHB , desconozco el tiempo, y tenía previsión de alta ayer . He solicitado a la TS de la UHB de Cáceres informe de alta para enviarlo al juzgado. He contactado con el centro de Cáritas de Cáceres y con el Centro De Emergencia Social , era el sitio dónde se estaba quedando antes de su ingreso hospitalario y al que podría volver . Me dicen que no ha pasado por allí , les he pedido igualmente que me lo indiquen por escrito para comunicarlo al juzgado . Cuando lo reciba todo te lo paso para comunicar al juzgado lugar de residencia , si es que conseguimos localizarlo. Las actuaciones de protección llevadas a cabo yo las desconozco , es un caso de la zona de Cáceres que ha estado gestionando Ana , tendrás que esperar a que ella vuelva para que te informe sobre ese aspecto. Te recuerdo que este es el caso al que le van a denegar la PNC , lo que estuvimos viendo esta semana . Cuando llegue la resolución denegatoria lo recurrimos como nos indicaron ***************************************************** mi contestacion: Gracias Amalia. Pongo en copia a Ana para su conocimiento cuando vuelva. Quedo pendiente que lleguen los escritos tanto para contestar al juzgado y para recurrir la desestimación de PNC a curatelas representativas, que deberemos verlo entiendo con Secretaria General para que sean intermediarios en dar una solución','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='CASTAÑO'and apellido2='CARDENAS'),'2023-07-11','CURATELA REPRESENTATIVA Mediante Auto n.º 124/23, de 11 de abril, se nombra Curador Representativo, respecto de Dña. María del Carmen, a la CTAEx. Se modifica la relación en s/ expte. y en las bases de datos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-11','miguel, envío email a Ana del requerimiento que nos hizo el juzgado para que indiquemos donde se encuentra residiendo y las actuaciones realizadas con el tutelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-07-11','miguel, escribo a Amalia: Buenos días, de este expediente qué se quiere hacer? Una solicitud de internamiento involuntario? Si fuese así se necesita informe médico y social','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-06-22','miguel, llega documentación por Soraya del jzdo nº2 de Trujillo incluyendo nombramiento a la Ctaex: Os dejo mail enviado a Trujillo y a Fiscalía ahora os digo. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-06-20','miguel, email que Soraya envió a fiscalía de cáceres y al jzdo de Trujillo: Buenas, mi nombre es Soraya Masa Moreno y soy la Jefa de la Unidad de Programas Asistenciales del SEPAD. Con motivo de la Adopción de medias Judiciales de apoyo para la persona Discapacidad con nº 0000259/2022, se emite Auto con número 109/2022, del Juzgado de 1ª instancia e instrucción n2 de Trujillo en el que se indica que se autoriza el internamiento de María Guadalupe Gil Cabello, y la Unidad de Programas Asistenciales del SEPAD (persona que escribe este mail) designará el centro o piso tutelado para el ingreso de la persona Maria Guadalupe Gil Cabello. Así las cosas, les enviamos en los informes adjuntos información de la Comisión Tutelar de Adultos de Extremadura (informe CTAEX- curadores) en el que se indica la falta de voluntariedad de la personas para el ingreso en un centro adecuado, así como un acta de reunión entre los profesionales de la comisión tutelar con los profesionales de salud de la zona (informe reunión ESM) donde se determinan los recursos que serían necesarios para este caso, si bien no se ha podido llevar nada a cabo ante la falta de voluntariedad de la persona para el ingreso. Así las cosas, y con el fin de poder un abordaje adecuado a esta persona, viendo las pésimas condiciones en las que vive (fotos adjuntas), solicitamos a ese juzgado o en su caso a la fiscalía para que se promueva el ingreso involuntario de esta persona en la Unidad de psiquiatría más cercana a su domicilio (en la zona de Cáceres hay en Cáceres Capital y en Plasencia) como forma de iniciar con ella un itinerario de atención, que no se ha podido empezar debido a la falta de voluntad de la persona para el ingreso. Para cualquier cuestión estoy a su disposición en el teléfono 679399244 o en este mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-06-23','miguel, solicito internamiento involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2023-06-28','miguel, solicito internamiento involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-07-11','TERESA Buenos días Teresa, dos cosita respecto a Aitor. En primer lugar, decirte que la semana pasada se fue a Puebla de Obando con un amigo. Ha vuelto hoy a Navas y en principio se vuelve a ir mañana o pasado aunque no es seguro. Ha venido, más que nada, para hacer compra y dejársela a su madre y la pareja de ésta, que en cuanto se ha ido Aitor se ha ido a vivir con Felisa. Puesto que Felisa recibe su asignación quincenal, no nos parece que Aitor haga una compra de 100€ para que se la coman su madre y su pareja, más que nada porque este señor no aporta nada. No sé si os parece que si Aitor se va mañana hagamos una compra pequeña y si se queda toda la semana pues entonces sí, hacerla más grande. Y respecto a la ropa que necesita Aitor, me dijisteis que pidiese presupuesto en una tienda y lo enviásemos, pero va a ser complicado hacerlo así porque en Navas no hay tiendas de ropa, por lo que tendría que comprar en el mercadillo, que no le van a hacer un presupuesto, o ir a Cáceres, en las que tiendas como Zara, Pull and Bear y demás dudo que le hagan un presupuesto, no lo sé. No sé qué solución podría haber… Estamos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2023-06-09','miguel, liquido el impuesto de sucesiones correspondiente al fallecimiento del hermano de la tutelada, siendo herederas su hermana Ramona y la tutelada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2023-07-13','miguel, firmo en la notaria de Badajoz, del notario D. Juan Manuel Angel Avila, Protocolo 1258,la escritura de adjudicación de herencia del fallecido hermano. Me envían desde la notaria copia simple. *********************************************** La abogada Inmaculada Nuñez Amigo, me informa del exceso de valoración de la tasadora que se tramitó desde la Ctaex en unos 10000€ más que la otra tasadora presentado por la otra hermana(heredera a la que ella representa). A ello se une que han abonado por adelantado y nunca han reclamado gastos de herencias anteriores y gastos de la vivienda objeto de esta herencia. Me envía al email muchas de esas facturas y un excell de lo que ha logrado justificar. Tiene ya preparada la demanda para solicitar la aprobación de la herencia y autorización de venta pendiente de que la autoricemos a que lo tramite ella. Le comento que quedo pendiente de verlo con Angel para que lo tramiten ellos (ella se ofrece a no intervenir como compradora si entendemos que exista algún tipo de conflicto de intereses).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2023-07-11','TERESA Tras conversación telefónica, gestionaremos el caso de forma ordinaria. Para ello necesitamos el informe social según el modelo que se requiere en el Decreto 88/96, asi como la autorización para que la AP pueda recabar los datos de IRPF. esta última debe ser firmada por José Vicente. Como es una persona valida, según criterios del Decreto 88/96, los','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2023-07-11','TERESA Te reenvío correo para que me hagas el informe social tal y como nos pide el compañero. Del listado que nos manda de posibles residencias cual crees tu que son las que mejor le vendrían a Maria Elena? Lleva un mes desquiciada llamando continuamente, ahora parece ser que el padre va a ingresar en residencia y que su hermano le dice que no se vaya. Me llamo el hermano para decirme que va a trabajar y que dejemos que se quede la hermana en la casa Yo voy a continuar con la gestión a ver si se va a residencia porque en esa casa no hay nada bueno para ella…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-07-11','TERESA Vuestra tutelada Beatriz Mejías de la Morena ha ingresado hoy en nuestro centro, concretamente en la UME. Necesitaríamos cuanto antes la autorización correspondiente para sus gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-03-31','miguel, firmo la ratificación de la herencia firmada el 24-1-2019, protocolo 98 firmada también en la notaria de Coria Don Andres Diego Pacheco','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES MARIA'and edp.apellido1='ALVAREZ'and apellido2='CARRASCO'),'2023-07-11','-Amalia: contacta conmigo la TS del CSS de Mérida. Hola, Amalia. Adjunto te remito la sentencia de la curatela de Inés Mª Álvarez Carrasco. Por un lado, quería saber si la CTAEX ya ha aceptado el cargo y, por otro lado, quería avisarte de que su hermana Montserrat (anterior tutora legal) ha administrado el dinero de la paciente a su antojo. No se si sería posible que cambiaseis el número de cuenta bancaria o si sería suficiente con que su hermana dejara de ser cotitular de la misma, ya que no nos fíamos de ella. Hasta ahora. M.ª Ángeles Galindo Barrena. Trabajadora Social. ​Centro Sociosanitario de Mérida Ctra. de Valverde Km. 2. 06800 Mérida. 924388182. Ext. 24006.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2023-07-11','Email sección eco : AMALIA/ESTRELLA: OK A PPTO DE 986,15 € X REPARACIÓN VIVIENDA + AMALIA: CUANDO DES OK Y TENGAMOS FACTURA O HAYA QUE ABONAR ALGO X ADELANTADO LE FACILITAMOS LOS DATOS A ESTRELLA PARA QUE CONTROLE Y ABONE LO QUE CORRESPONDA. ESTRELLA: ABONAMOS DESDE CCC DE PILAR ES34 0078 0005 9940 1004 3580 , CONCEPTO "REPARACIÓN VIVIENDA" ESTRELLA: LUEGO HACEMOS 1 TRANSFERENCIA DESDE LA OTRA CCCES62 0078 0005 9740 1002 5520 (HERMANOS) A CCC ES34 0078 0005 9940 1004 3580 (SOLO PILAR) X 657 € CON EL CONCEPTO "PAGO PARTE PROPORCIONAL REPARACION VIVIENDA" -------ESTE PASO LO HACEMOS AL FINAL DEL PROCESO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-11','-Amalia : hablo con la psquiatra , al final ha decidio mantenerlo allí unos días más por si se encontrase algún recurso . No ha sido posible y esta tarde le dará el alta con la idea de que acuda al CES a pernoctar. Tiene cita para mañana en ECA para valorar nuevo ingreso en Comunidad terapeútica . Solicito a CES que me informen mañana si ha pasado allí la noche.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2023-07-12','CURATELA ASISTENCIAL Mediante Auto 126/23, de 26 de abril, se nombra Curador Asistencial a la CTAEx. Se procede a modificar el expte. y las bases de datos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-07-12','TERESA Buenos días Teresa, nos acaban de llamar Felisi y Aitor porque están en una discusión, creemos que se les puede ir de las manos y agredirse porque Aitor está con mono y Felisi enfadada porque se ha ido su novio y culpa a Aitor, y todo esto sumado a las discapacidades de ambos es una bomba. Aitor nos ha pedido salir de ahí, dice que le da igual al centro que le enviemos. Entendemos que esto no puede hacerse de un día para otro y que lo más seguro es que se arrepienta antes de que se le pueda encontrar un centro pero creemos que pueden agredirse, Aitor volver a la calle… No sé si puedes darnos alguna solución… Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2023-07-12','TERESA Claudia Lorena Campus Ante la visitó su hermano Marcelo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-07-12','TERESA Teresa, el equipo multiprofesional del Centro hemos decidido que Natalia comience a partir de este viernes visitar a su madre los fines de semana alternando las visitas con las de su padre, ya que han sido ambos progenitores visitados por los servicios sociales municipales de Badajoz y no nos han indicado lo contrario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-12','-Amalia , envio email a Ana y Miguel : Buenas , os comunico las ultimas incidencias del caso . Ha estado ingresado en la UHB del Hospital de Cáceres ( he solicitado informe de alta , os lo paso en cuanto me llegue ) y ayer por la tarde le dieron el alta . La alternativa era solicitar plaza en el Centro de Emergencia Social , pasaría allí la noche y esta mañana tenía cita en el Equipo de Conducta Adictiva . No acudió anoche al Centro . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-07-12','-Amalia : escribo a los juridicos. Hola , os paso informes para solicitar plaza residencial en Centro para personas con discapacidad . Actualmente sólo acude a Centro Ocupacional . Saludos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES MARIA'and edp.apellido1='ALVAREZ'and apellido2='CARRASCO'),'2023-07-13','-Amalia : La sra. está en CSS Mérida , necesitan con urgencia sacar dinero pero aún no es firme la sentencia . Hola Amalia, ya somos curadores, pero estamos pendientes de la firmeza de la sentencia. Inés por favor reclama con urgencia de nuevo el testimonio de firmeza y acepta lo antes posible el cargo. El expediente está en defensa judicial. Amalia, en cuanto tengamos la firmeza y se acepte el cargo habrá que hacer el inventario y ver qué cuentas e inmuebles hay. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2023-07-13','Buenos días, incluyo a Angel, al que informaré en persona mañana. En mi opinión nuestra función debe ceñirse a nuestro curatelado Fco Javier Rodriguez Robles, cuya sentencia de incapacitación (fuimos nombrados por remoción) indica funciones asistenciales en aspectos económicos. Por tanto si a él no le hace falta no debemos hacer de gestoría gratis a sus familiares. Estoy de acuerdo con Alberto… en su día perdimos mucho tiempo en este asunto ya que se viene trabajando desde antes incluso a que Pedro Gracia fuese jefe de sección… La conclusión a la que llegué cuando lo vimos con Juana es que la hermana, quiere y por tanto redujo el valor de la parcela de Dehesilla del Calamón (está en frente de las Vaguadas, que es una zona de lujo de Badajoz). Dicha parcela tiene bastantes construcciones y a nuestro curatelado le dejaba un local en Valdepasillas y poco más…No había ni de lejos un reparto equitativo. Como dice Alberto, son rencillas familiares y nosotros tenemos que estar al resultado. Si quieren algo que planteen una propuesta formal con las correspondientes tasaciones periciales que acrediten el valor y la propuesta de reparto que hacen. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-07-13','miguel, hablo con Eva Perez (abogada) que me pide emitamos el poder apud acta. Le explico que estamos en pleno cambio de ceses y nombramientos de Consejeros, y altos cargos y hasta que no se constituyan los nuevos no podemos hacer ningún poder apud acta. Me comenta que mientras va a solicitar la constitución legal de la comunidad de vecinos, e interpondrá la demanda de gastos extraordinarios antes de acabar el mes, para posteriormente aportar como una subsanación el poder apud acta (seguramente en septiembre cuando ya tengamos nuevo gerente). Me indica que las obras sí o si se inician en septiembre y que la constitución de la comunidad tiene por finalidad la reclamación preferente al vecino de abajo para obligarle a pagar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-13','LUCIA BORRELLA CABALLERO >lborrella.cdcoriacaceres@caritas.es> Amalia Diaz Gonzalez Buenos días Amalia, anoche sí durmió Miguel Ángel en el CES. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-07-13','-Amalia : El padre de Alberto me escribe solicitando que se le abonen los 1000€ , que así acordó según él con Oscar. Respuesta de Oscar : Buenos días. Vamos por partes: El día que conocí a este señor lo único que me comentó es que Amalia tendría que buscarle un centro, porque en la calle no podía estar. Por este motivo, le dije que se pusiera en contacto con Amalia para esta cuestión. Por tanto, ni me comentó ningún centro al que Alberto quería ir, ni, por supuesto, a mí me pareció "estupendo". Evidentemente, el resto de la conversación no sé con quién la tuvo, pero en ningún momento me comentó las necesidades que iba a tener Alberto al trasladarse a ese centro "estupendo". Por esto, todo lo demás expresado por Juan no lo habló conmigo, al menos estando yo presente. Las únicas cuestiones económicas que salieron a la luz ese día fue las facturas que se le debían por el ingreso en el centro de Montijo y las asignaciones semanales que él le había adelantado a su hijo. Como lo justificó todo debidamente, se le abonó, después de hablarlo con Alberto y con Amalia. Por tanto, yo no puedo negar términos de una conversación que no ha existido, al menos, conmigo presente. Con todo esto no digo que él MIENTA (salvo en la cuestión de que yo dije LITERALMENTE varias cosas), sino que habrá tenido esa conversación con otra persona o pensaría comentarme todas esas cuestiones y se le pasó, porque estaba centrado en que le pagáramos la deuda anterior, que si se le había autorizado. No voy a entrar en más cuestiones, porque NO TIENE SENTIDO Y ES UNA PÉRDIDA DE TIEMPO. En cualquier caso, como ya hemos comentado en varias ocasiones, lo único que habría que hablar con Juan o con la hermana de Alberto, es que asuman la curatela de su hijo/hermano, para así no tener problemas de asumir gastos que después no se le van a abonar, a menos que se les autorice previamente. Un saludo. ----------------------------------------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2023-07-12','miguel, recibo email de la asesoría de Cáceres, Miguel de Otelso Miguel Mariscal >miguel@otelso.com> 927-220458/79 y 675-891313 Buenos días: Cuando me solicita un presupuesto, entiendo que sería nuestro presupuesto de honorarios profesionales por la tramitación de las herencias en las que Sonia tiene interés, que son las del padre y madre, así como la de la hermana Silvia. Aparte estarían los honorarios de notarías (Madrid y Cáceres), registro de la propiedad, etc... y de esto no tenemos constancia de cuánto supondría. En principio a nuestro despacho se ha dirigido Concepción y la sensación que nos ha causado es que ella correría con todos los gastos de todos estos trámites, pero lo confirmaré. No entiendo claramente lo que me detalla en su segundo punto, por lo que si le parece bien podemos hablar por teléfono cuando tenga un ratito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2023-07-13','miguel, contesto a la asesoría: Buenos días, perfecto. He llamado pero comunicaba. Entonces quedo pendiente de la información que vaya necesitando la notaria para completar la escritura. Teniendo en cuenta que Concepción se encargue de los gastos de tramitación y si luego la tutelada Sonia ha de abonar algo, la factura que se emita venga a nombre de Sonia, le sería abonada. Una vez esté el borrador de la escritura de herencia tendré que verlo antes de que se firme y si necesita alguna documentación la notaria, tendrán que ponerse en contacto conmigo para remitirles sentencia de incapacitación y nombramiento. Una vez que esté firmada la escritura, la Comisión Tutelar la ratificaremos en la notaria de D. Gonzalo Fernández Puignaire, Borja Igartua y Francisco Javier Hernández Téllez. Y cuando ya esté firmada necesitaremos un abogado para que solicite la aprobación de la escritura de adjudicación de herencia en los juzgados de Olivenza (lugar competente por ser la residencia de la tutelada)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-07-14','TERESA nuevo señalammiento para el proximo 18/07/23 para revisión de medidas a las 10:30 se gestiona acompañamiento con Futuex','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-07-14','miguel, tras reunirme con Amalia, con la Directora General Territorial de Badajoz Mª José, y con Julio director de la Residencia la Granadilla, acordamos comunicar solicitu de inervención urgente de fiscalía en Badajoz y comunicación al juzgado nº4 de Badajoz. Les remito resguardo de dichos envíos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2023-07-13','miguel, firmo la herencia de su hermano en Badajoz ante el notario Juna Manuel Angel Avila con protocolo 1258. La representante de la hermana, Ramona de la tutelada, Inmaculada Nuñez Amigo, me explica que durante años los únicos que se han hecho cargo de todo han sido Ramona y su Marido. Acreditará lo que pueda, está dispuesta a no comprar la vivienda y que la vendamos a un tercero pero me avisa que está en malísimas condiciones y que a diferencia de su tasadora que valoró el inmueble por 23000€, nuestra tasadora lo ha valorado en 36000€ y claro es excesivo pues comenta que viviendas similares por allí nuevas valen 24000€. Me manda facturas y otros de gastos de notaria que pagaron Ramona y el marido correspondientes al hermano de la tutelada, Arturo, fallecido. Hablaré con Angel de posibles soluciones para adjudicación de la vivienda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-07-17','TERESA otra vez se le ha pasado la citación para médico forense a Aitor, segun el llegó esta semana y la citación era para 7 de julio , pero en el sobre hay un primer intento de comunicación el dia 6, y pone que estaba ausente. Yo no se las veces que le han citado ya, y por unas cosas u otras nada.. Ayer se recibe llamada del programa de familias informando que ayer día 12 de julio en visita al domicilio, Aitor les comunicó que el día anterior recibió una notificación judicial para acudir al instituto de medicina legal de Cáceres para examen médico-forense el pasado día 7 de julio a las 9:00h, pero como es evidente no ha sido posible su asistencia a esta cita por haber recibido la notificación días después de la fecha de la citación, se adjunta dicho documento a Comisión para su valoración y para que se tomen las medicad que se consideren oportunas. Se adjunta también copia del sobre en el que venía la citación done especifica que hubo un primer intento de entrega el día 6 de julio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-07-17','CURATELA REPRESENTATIVA Mediante Auto n.º 82/23, de 4 de julio, se nombra Curador Representativo y Asistencial a la CTAEx. Se procede a modificar las bases de datos y los exptes. Todo en base a Curatela Representativa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-07-17','TERESA RECIBO LLAMADA DE VERONICA TS DE LOS SERVICIOS SOCIAL MORALEJA 927525075PARA INFORMAME QUE LA AUXILIAR SE HA ENCONTRADO EN LA VIVIENDA A PILAR TIRADA EN EL SUELO PARECE SER QUE SE HA CAIDO EL SABADO HAN AVISADO A LOS SERVICIOS DE URGENCIAS SE LA HAN LLEVADO AL HOSPITAL Y SE HA IDO CON ELLA CAROLINA LA AXUILCIAR PARA INFORMAR AL MEDICO DE SU SITUACION, TAMBIEN LE HAN LLEVADO LA MEDICACION QUE TOMA. HE ACORDADO CON VERONIA QUE SI LA INGRESAN CONTRANTEN ACOMPAÑAMIENTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-06-29','Ana: Correo de Laura Bazaga, TS APTO: " Con fecha de 16 de junio de 2023, la juez del Jdo. 1ª Inst. e Instrucción nº 1 de Navalmoral de la Mata, ha revisado las medidas judiciales relativas a la capacidad de Beatriz y ha constituido curatela a desempeñar por su hermano, José Emilio. Con fecha de 28 de junio de 2023, su hermano, José Emilio, firma el acta de aceptación del cargo. Entiendo por ello que ya pasaría su hermano a administrar todo lo que incluye la jueza en el auto, suprimiendo el carácter cautelar que venía desempeñando la Comisión, ¿verdad?" ······················ mi respuesta: "Gracias por informar. Aquí el Juzgado no ha remitido nada. Pongo a mi compañero Miguel, asesor jurídico, para que pueda preguntar al respecto, pues en principio, hasta que ese nuevo AUTO sea FIRME y el Juzgano no nos lo comunique de forma oficial, supongo que la CTAEx, sigue ejerciendo el cargo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-06-30','Ana: Correo de Miguel, A. Jurídico: "procedemos a solicitar testimonio de firmeza de resolución judicial. Hasta que no nos comuniquen dicha resolución seguimos ejerciendo el cargo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-07-18','Ana: Correo del día 14 de Sheila Rguez., Directora Técnica CRR-CC (crr@grupociudadjardin.com): "Informaros de que en el día de hoy ha sido dado de alta Felix Valle. Adjuntamos informe de alta de la UHB, así como resumen de incidencias." ············· Guardo informes en el expediente digital. ·············· Ingresado en la UHB del 10-14 de julio por alteración de la conducta como consecuencia del consumo de alcohol. ······· Cita con la Dra. Rubio, Psiquiatra del ESM el día 21/07/23 a las 13:00h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2023-07-17','EXITUS El centro informa de su fallecimiento. Acaeció el 17/07/2023. Se procede a dar la baja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-07-18','Ana: Durante mi ausencia (vacaciones), Teresa y Lourdes, CTAEx, gestionan compra de gafas para Ventura. ··············· En cuanto al Catering Municipal, se le ha denegado por sobrepasar los ingresos. ·········· Desde el progr. de Apoyo Comunitario-Futuex, se le ha propuesto contratar uno privado y lo ha aceptado. Correo de Toni: "...Las comidas que realiza suelen ser de mala calidad, lo que es perjudicial para él por su diabetes. Es por ello que es muy beneficioso para él que quiera el catering. De los que se han consultado, el mejor tanto económicamente como de calidad es el Catering Sol, el menú básico. El coste es el siguiente (se adjunta imagen): • Menú semanal para 7 días más coste de entrega un día a la semana: 46,30€/semana. • Coste mensual: 185,20€ En el caso de ser aceptado, se contactaría de nuevo con la empresa para proceder a la contratación mensual y la forma de pago (que suponemos podra ser pago por transferencia como es habitual). Este le cae cerca de casa y es que mas le gustaba al tutelado. Se queda a la espera de lo que se considere" ································ Contesto correo a Lourdes: "Por mi parte OK al Catering, estoy de acuerdo con Toni en que sería beneficioso para él. Espero que Alberto también lo acepte. Parece que por fin comienza a tener adherencia con la educadora del programa de apoyo comunitario (FUTUEX) y con ello también acepta mejor la intervención por parte dela CTAEX (ha sido siempre un caso complicado, sobre todo antes de estar yo aquí trabajando). Pongo en copia también a Maite. En caso de ser aceptado por Alberto, ¿podríais confirmarlo a Toni de Futuex para que finalicen las gestiones?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2023-07-18','TERESA Ayer estuvo el técnico de plagas en la casa de Cándido y me comento que han observado que hay muchas cucarachas y que el problema viene porque tiene mal la tubería del fregadero. Yo le insistí que nosotros habíamos llamado por tema de ratones no de cucarachas pero dice que no ha visto restos de excrementos de ratones, aun así pondrá trampas. Le he dicho a Cándido que avise al fontanero para que le arregle el problema y después fumigaran para el tema de las cucarachas. No sé si hará caso y lo avisara o Esperanza está gestionando ya el tema…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-07-18','Ana: Tras recibir llamada de Julia, envío correo a los A. Jurídicos: "He recibido llamada de Julia Morón, al parecer le han puesto una pena de 16 días de trabajo a la comunidad y dice que tiene que acudir al Centro Penitenciario de Cáceres el día 28 de julio a las 10:30 h. Esta vez, parece que sí tiene claro los datos de contacto de la abogada: Mª AMPARO ECHAVARRI RODRÍGUEZ: 619 845 940 / 927 50 07 69 Por favor, ¿podríais llamarla y qué os informe y/o envíe documentos al respecto?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-07-18','Ana: Llamo a Toni-Futuex: Joaquina se ha negado a acudir al Juzgado esta mañana. Ni siquiera le ha abierto la puerta a Patricia, nueva Ed. Futuex. ················· Por otra parte, el viernes pasado, tenía cita en de Psiquiatría, en el ESM (la habían pospuesto por coincidirle con el Sintrón), pero tampoco se presentó a la misma. ···················· Informo a los A. Jurídicos y Maite, Jefa CTAEx. ···································· Remito a Julio, CTAEx, Oficio-solicitud de informe de Psiquiatría para que lo remita al ESM por registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-07-18','Ana: Teresa, TS CTAEx, me informa que finalmente ingresaron a Pilar en el hospital. Le pasarán la herramienta, para ver si da puntuación para plaza T3. En la residencia de su pueblo ahora no ha plazas disponibles. ···················· En la Sentencia de Medidas de Apoyo se autoriza el internamiento en caso de ser necesario. ··········· Valoraremos según evolución y puntuación en herramienta. ···· Presenta insuficiencia respiratoria y necesidad de curas. ·········· A su casa probablemente no pueda volver.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-07-18','TERESA RECIBO LLAMADA TRABAJADORA SOCIAL DEL HCC 77227 PARA INFORMARME QUE PILAR HA SIDO INGRESADA, PRESENTA INSUUFICIENCIA RESPIRATORIA ES CONOCEDORA DE LA SITUACION Y VALORAMOS DERIVACION A UNA T2 O T3 DE CARA AL ALTA TENEMOS AUTORIZACION PARA INGRESARLA SIN SU CONSENTIMIENTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2023-07-19','Ana: en relación al correo de Marina Carmen Jiménez Cintas, Jefa de Sección de Asuntos Generales y Prestaciones II (marinac.jimenez@salud-juntaex.es / 924005922): "a fin de agilizar los trámites, les informo que a nombre del beneficiario de pensión no contributiva D. Alfonso Cámara Moreno, con DNI Nº 07004831C, ha resultado devuelta la mensualidad de junio y paga extraordinaria por importe total de 969,22€. Ruego nos trasladen Modelo para Altas de Terceros.", cumplimento el MODELO PARA ALTAS DE TERCERO y se lo remito a las compañeras de la Secc. Ecca. para que lo lleven cuando vayan al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-07-18','Ana: Correo del Programa de Familias (programafamilia@tajosalor.es): "...Aitor está hoy en Trujillo a recoger su tarjeta de crédito para poder sacar dinero, en cuanto a la convivencia entre ambos cada vez está siendo más difícil porque Aitor cada vez está consumiendo más."','2');
