insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-07-03','Ana: Correo de Miguel, A. Jurídico: "adjunto el auto remitido por la trabajadora social, Laura. Como véis no es firme hasta mediados de Julio. Inés apuntalo para que inmediatamente a su firmeza te manden el testimonio. Mientras no sea firme seguimos ejerciendo el cargo." ······························································································································································································ El hermano tomará posesión del cargo el 17 de julio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-18','Ana: Correo de Pilar: "te informo que desde hoy Miguel Ángel Ramos Andrés se encuentra en el Centro Vida. Solicitado CRR en octubre del 22 pero en principio no aceptado por consumo. Creo que pasado un tiempo de estar en el Centro y acudiendo al ECA y al ESM podemos comunicar la posibilidad de su incorporación al CRR. La otra posibilidad es UME. Ya hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2023-07-19','Ana: Cuenta que fueron a verle desde el programa de apoyo comunitario, pero se levantó tarde y, según dice, Emilia, TS del CSS, no le dejó ir. ················ Pospondrán la cita seguimiento. ·············· Las actividades/talleres a las que asiste con TO, son: pintura, redacción, informática. También sale todos los días por la mañana y de 18-20 h, suele salir solo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-19','Ana: Llamo a Pilar Martín, ESM CC (54612): Plantea que hablemos con la compañeras de la sección de acceso a RR de Salud Mental para que acepten, para el ingreso en CRR, Informes de C. Vida y ECA, de su abstinencia durante un mes o mes y medio. ··········· Lo hablaré con Maite. ············· En cuanto a las causas pendientes, solicito a A. Jurídicos, que pidan información a los Juzgados al respecto. ································································································································································································· Llamo a Mamen, TS de HSPA - CC (56283): me enviará ahora el Informe de Alta de la UHB. ····················· Llamo a C. Vida - Cáritas (927 23 50 82), hablo con Lucía, Educadora. Mamen, TS sigue de baja y Pedro está de vacaciones. *Lucía me enviará Certificado de Ingreso en Centro Vida. ···································································································································· Llamo a Susana, Asociación REMAR, Talavera de la Reina (650 41 93 56 / toledo@remar.org): tal y como acordamos, le solicito por mail Certificado de Ingreso en Centro con la fechas de su estancia y motivo de salida del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2023-07-19','TERESA Buenos días Antonia Fernández se va el mes de agosto, concretamente del 31 al 9 de septiembre a la residencia familiar que le dejan sus allegados en Zafra , residencia que en cada permiso de salida ella suele vivir (semana santa , navidades, feria de Zafra..) . Ella durante este tiempo vive sola, suele buscar una cuidadora que la acompaña y sus allegados(primas) le organizan el menú semanal , así como los gastos diarios, salidas de ocio entre otros. Tras llamada telefónica con su prima, me comenta que aún están en búsqueda de una cuidadora, ya que la que suelen contratar esta a la espera de intervención medica. Me comenta que tiene varios contactos pero piden una suma de dinero elevada para esos días. Estamos a la espera de que nos confirmen el precio que supone acompañar a Antonia durante todo este periodo. En cuanto tengamos noticias os escribimos para solicitar el dinero y daros la cuenta bancaria de la persona cuidadora a la cual debéis hacer la transferencia. Además os solicitaremos dinero para la compra de alimentos y aumentar el dinero de bolsillo durante este mes. Muchas gracias Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-05-13','TERESA: ENVIO SOLICITUD DE RESIDENCIA POR EMERGENCIA SOCIAL LO ENVIO TAMBIEN POR FAX A ANA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-02-13','MIGUEL, HEMOS RECIBIDO INFORME FORENSE A EFECTOS DEL INTERNAMIENTO INVOLUNTARIO, DONDE SE DA TRASLADO AL MINISTERIO FISCAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2018-07-13','- AMALIA , EN VISTA DE LO SUCEDIDO CON LUISA REY CAMPÓN QUE HEMOS PERDIDO LA PLAZA RESIDENCIAL DE MAYORES POR NO TENER LA RESOLUCION JUDICIAL DE INTERNAMIETNO Y TRAS CONVERSACION CON MARIA LEÓN , NOS INDICA QUE NO PODEMOS SOLICITAR PLAZA SIN TENER LA ORDEN JUDICIAL . QUEDAMOS A LA ESPERA DE LA MISMA PARA SOLICITAR PLAZA RESIDENCIAL DE MAYORES POR EMERGENCIA SOCIAL .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2023-07-20','Ana: correo de Ángela Bueno, Directora Asuntos Sociales - PLACEAT (directora@placeat.org): "Buenos dias, el tema es comunicar y solicitar autorización con respecto al tema vacaciones de Maria. Al igual que el año pasado es deseo de la familia de su pareja que compartan periodo vacacional, y evidentemente Maria está ilusionada . Viajaría en tren a Madrid donde los esperaría la hermana de la pareja, sería el lunes 31 de julio hasta el lunes 14 de agosto que regresan y pasarian unos dias en las fiestas de la localidad de Hervás, donde reside la familia de la pareja. María se incorpora a la residencia el 19 de agosto. Por nuestra parte consideramos muy conveniente para el bienestar emocional de María la posibilidad que le ofrece la familia de la pareja de pasar unas vacaciones fuera del servicio residencial." ························ Mi respuesta: "Por parte de la sección social estamos totalmente de acuerdo en la conveniencia de esta salida para el bienestar de María Rosa. Se autoriza la realización de este viaje propuesto con su pareja y la familia de ésta. Esperamos que todo vaya bien y disfruten de las vacaciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-07-20','Ana: Llamada de Mariángeles, TS del HCC-hospital de Coria (77227 / mangeles.ramosg@salud-juntaex.es): a Pilar seguramente le van a dar el alta entre hoy y mañana. El médico está pendiente de un TAC y una analítica. ···· No da puntuación para T3. ·············· Ha hablado con la directora de la Residencia de Torrecillas de los Ángeles pues sí hay plazas en la misma. ··········· Le envío DNI y Tarjeta Sanitaria. ··········· Desde la residencia me harán llegar el contrato cuando lo tengan preparado. ································································································································································································ Llamada de Verónica, TS de SSASB Moraleja (927 515 075): Ya han preparado la maleta de Pilar. Mª Ángeles, TS HCC, le ha confirmado que hoy le darán el alta. ··· En cuanto a las llaves de casa de Pilar, se las darán también a la directora de la residencia para que las custodien allí. ································································································································ Nueva llamada de Mariángeles, TS del HCC-hospital de Coria (77227): finalmente le darán el alta mañana pues el médico ha decido repetir la analítica. Ya se lo ha comunicado a Verónica, TS, que a su vez lo comunicará a la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-07-20','Ana: Envío correo-respuseta a Alberto y Lourdes, secc. ecca., en relación al presupuesto de ropa y propuesta de subida de asignación: "En relación a JULIA MORÓN HERNÁNDEZ, hago algunas aclaraciones: - Julia hace meses que ya no reside en el CRR, vive en el domicilio familiar - Los 300€ se le pasan a la madre en concepto de manutención y gastos de bolsillo. Iban a ser 350€, pero se le redujo a 300 por gastos que realizó sin autorización hasta que lo compensara, lo cual ya ha hecho. - No obstante, es cierto que en los últimos meses ha tenido un aumento inusual de gastos, sobre todo con taxis para acudir a citas judiciales. De hecho me ha comunicado que tienen que volver a Cáceres a una nueva citación la semana que viene. Mi propuesta: - Dado que necesita ropa, creo que podemos abonarla - No se le vuelve a subir la asignación a los 350€, hasta que cesen los gastos de taxi. Podemos volver a valorarlo a final del verano. Pongo a Maite en copia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2023-07-20','Ana: Estrella, Secc. Ecca, me comunica que se aceptan el presupuesto de 4.500€ de tratamiento bucodental - Brackets (Clínica Dental Dr. Javier Vaquero - Plasencia).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-07-20','Ana: Envío correo a Mónica, Ed. PP.SS. (educacion.pisosplasencia@grupo5.net): "En relación a Carmen Solana Chanclón, tras nuevas conversaciones con Benita, madre, y comprobaciones realizadas por la sección económica, me informan mis compañeras que la situación no era exactamente como me habían dicho, sino como sigue: Carmen realiza: • TRANSFERENCIA PERMANENTE DE 75 € A BENITA, MADRE, para su hijo. • TRANSFERENCIA PERMANENTE DE 75 € A HIJA TUTELADA (ISABEL). No obstante, ESTA HIJA ACTUALMENTE TRABAJA EN MERCADONA Y VIVE INDEPENDIENTE CON SU PAREJA (DE ESTO NO TENÍAMOS CONOCIMIENTO). • Este mes de julio ha REALIZADO UNA TRANSFERENCIA PUNTUAL DE 300€ A BENITA, para ayudar a madre e hijo. PROPUESTA QUE REALIZA ALBERTO, JEFE DE SECCIÓN ECONÓMICA A PARTIR DE AHORA: • ANULAR LA TRANSFERENCIA PERMANENTE A SU HIJA (ACTUALMENTE DE 75 €/MES). Pues ya no presenta esta necesidad. • INCREMENTAR, A PARTIR DE 01/08/2023, LA TRANSFERENCIA PERMANENTE A MADRE E HIJO A 150 €/MES Agradeceríamos que se lo explicaras a Carmen, de forma que pueda entenderlo bien y ver si ella está de acuerdo con este cambio. En tal caso, no tenemos el nº de su hija para comunicárselo, nunca hemos tenido contacto con ella, ¿podría Carmen explicárselo con vuestro apoyo? Para que no vea que de repente se le deja de ingresar ese dinero sin ninguna explicación. En caso de que Carmen acepte la propuesta de Alberto, por favor, comunicárnoslo para que las compañeras de la sección económica puedan hacer las gestiones oportunas. Pongo en copia a Ana Benavente, compañera de Salud Mental, para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-07-20','Ana: Envío a Cristina, Ed. Vera (educadorasocial@asociacionvera.com), el documento de autorización de Ausencia voluntaria para que Anotia se vaya con su hermana a Miajadas del 6 al 20 de agosto, firmado digitalmente por el Presidente de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2023-07-21','TERESA recibo llamada de la cuñada Puri 640530868, solicitando traslado por acercamiento familiar Lo comento con mi compañera Ana y decidimos perdir traslado a la cervantes para que M Lusia se quede tranquila ya que este tralado se alargara en el tiempo y ella esta bien adaptada al centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2023-07-21','TERESA Que acabo de ver el correo que has enviado esta mañana con lo del teléfono de orange y lo que debe de IBI (que no puede pagar si tiene 10 € en su cuenta), bueno, sigo necesitando informe social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2023-07-21','TERESA ENVIO SOLICITUD DE TRASLADO POR ACERCAMIENTO FAMILIAR A LA RESIDENCIA CERVANTES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-21','Ana: Envío a los A. Jurídicos - CTAEx, INFORME DE ACTUACIONES para dar respuesta al Requerimiento del Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-07-21','Ana: Subo al portafirmas digital todos los documentos para el ingreso en CR Las Eras de Hernán Pérez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-07-24','Ana: Envío correo a Estela, Directora del CR Las Eras de Hernán Pérez (rmhernanperez@mensajerospazex.es): "Adjunto los siguientes documentos, que me remitisteis, ya firmados por el Presidente de la Comisión Tutelar de Adultos: - Orden SEPA para la domiciliación del abono del centro - Solicitud de plaza - Compromiso de Aceptación - Contrato del Centro Residencial - Consentimiento de tratamiento de datos e imágenes Os envío además el Testimonio de la Sentencia Judicial de Medidas de Apoyo en la que, en la página 13, se autoriza al internamiento centro en caso de ser necesario. Aprovecho para preguntar qué tal fue el ingreso de Pilar y cómo ha pasado el fin de semana. Espero que poco a poco se vaya adaptando bien"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-07-24','Ana: Envío correo a Anabel, TS SSASB - Miajadas (servicios.sociales@miajadas.org): "Adjunto el AUTO por el que nombran a la CTAEx, para el ejercicio de la CURATELA REPRESENTATIVA. En el mismo, en la página 12, se AUTORIZA EL INTERNAMIENTO en centro adecuado. Después de haber llegado el otro auto denegándolo, es un alivio. Ahora henos de esperar a que sea firme (17/08) y, si no lo envían antes, solicitar en esa fecha dicha firmeza para poder proceder al internamiento"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2023-07-24','Ana: Envío a Teresa, TS NOVAFORMA (trabajadorasocial.novaforma@gmail.com), la Aurorización para asistir al viaje a Chipiona, del 28 de agosto al 1 de septiembre, firmada digitalmente por el Presidente de la CTAEx. ······························································································································································································ Envío a Teresa Nogueira: "...te adjunto, por fin, que llegó en mi ausencia, el CERTIFICADO NEGATIVO DE VIDA LABORAL que solicité. No obstante, te digo, si te fijas, el segundo apellido no coincide, se han confundido…. Pero el DNI, nombre y primer apellido, sí están bien. TE lo envío adjunto, a ver si te lo aceptan, y si no, dímelo que comunico el error y lo solicito de nuevo, otra cosa no puedo hacer."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2023-07-24','Ana: Envío a Teresa, TS NOVAFORMA (trabajadorasocial.novaforma@gmail.com), la Aurorización para asistir al viaje a Chipiona, del 28 de agosto al 1 de septiembre, firmada digitalmente por el Presidente de la CTAEx.','2');
