insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='BLAZQUEZ'and apellido2='SANDOVAL'),'2023-07-24','Ana: Envío a Teresa, TS NOVAFORMA (trabajadorasocial.novaforma@gmail.com), la Aurorización para asistir al viaje a Chipiona, del 28 de agosto al 1 de septiembre, firmada digitalmente por el Presidente de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2023-07-24','Ana: Reenvío correo de Teresa Nogueira, TS Novaforma (trabajadorasocial.novaforma@gmail.com), a A. Jurídicos CTAEx: "Os reenvío este correo que tenía aún pendiente del inicio de mis vacaciones relativo a FELIPE BLANCO GUISADO, como nos dice Teresa, TS, quiere hacer testamento. ¿Podéis indicarle cómo proceder?" ·················· Respuesta de Miguel, A. Jurídico CTAEx: "Buenos días, no veo inconveniente para haga testamento, ya que se trata de una curatela, aunque es cierto que tiene una discapacidad del 66% por retraso mental ligero fundamentalmente. Por tanto, que vaya a la notaria acompañado, y que dicha notaria se ponga en contacto con nosotros para lo que necesite, ya que será ésta quién valorará finalmente si puede o no otorgar testamento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-07-20','Ana: en relación al correo de Guadalupe Cortés, TS SAD-IMAS CC (guadalupe.cortes@ayto-caceres.es // 927212335 Ext. 4422): "prestación del Servicio de Ayuda a Domicilio. En la valoración inicial nos proponen prestar SAD 1 día/2horas en semana para el apoyo en tareas domésticas. Ya disponemos de horario para la prestación y estamos tramitando el alta. Como sabéis el SAD conlleva el abono de una tasa que en este caso concreto sería de 0,744€/hora, pago que debería ser domiciliado. Necesitaríamos vuestra autorización para la tramitación del alta y la puesta en marcha del Servicio. Quedamos pendientes de dicha autorización. Por otra parte, en el informe de valoración se plantea también lo conveniente que sería que Carlos recibiera el servicio de catering del IMAS para garantizar una alimentación adecuada. Este servicio se podría solicitar una vez que fuera usuario en alta del SAD." ·············· Hablo con Guadalupe, como Carlos nos dijo unas semanas atrás que ya no quería el servicio, acordamos que hablaré con él si confirma que quiere recibir el servicio se lo confirmaré. ·············· Me informa también que "En el caso de que ahora no estuviera interesado podemos mantener un tiempo en espera", hasta 3 meses a contar desde el día 17/07.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-07-24','Ana: Llamada de Doroteo (609 928 621): ha hablado con Pilar Martín, le ha dicho que han quedado plazas en el CRR de Plasencia, y aunque en principio era reacio, pues sólo aceptaba el de CC, dice que quiere cambiar de aires y acepta el traslado a Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-07-24','Ana: Hablo con Carlos (644 949 205), confirmar que sí quiere el SAD. Pregunta por el coste, le digo que es poquito, menos de 0,75 €/h.············ Por otra parte pregunta, si ahora que se ha dado de baja los otros gastos de telefonía se le puede subir la asignación entre 20-30€/semana. Le explico que el jefe de secc. está de vacaciones, tendrá que esperar a que vuelva éste para que se pueda valorar. ······························································································································································································· Llamo al IMAS, hablo con Lourdes Pérez, TS del SAD, confirmo que pueden tramitar el alta. Me confirmará si la Aux. comenzará este miércoles o el de la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-07-24','Ana: Correo de Mónica Muriel, Ed. PP.SS. Plas (educacion.pisosplasencia@grupo5.net): "He estado hoy explicándole a Carmen todo lo que comentabas en el correo, lo ha entendido y se muestra de acuerdo con los cambios. Añadir que ella tampoco tenía constancia de las transferencias permanentes que realizaba y ha agradecido toda la información facilitada. La conversación con su hija la postponemos a la próxima semana, pues tiene planificada una salida este fin de semana, por el cumpleaños de su hija, y quiere evitar posibles conflictos tras comunicar el fin de la ayuda." ··················································· Confirmo a Alberto y Estrella, Secc. Ecca. que Carmen acepta la propuesta de Alberto. ······························ *Correo-respuesta de Estrella: "ahora mismo mando al banco las autorizaciones.saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-06-26','Ana: Correo de Alberto, Jefe Secc. Ecca.: "MARIA: COMPRAMOS EL TELÉFONO MÁS BARATO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='SORIANO'and apellido2='LEAL'),'2023-07-25','CURATELA REPRESENTATIVA Mediante Auto n.º 207/23, de 30 de mayo, el Jzdo. de 1.ª Inst. n.º 4 de Badajoz, dicta medidas judiciales de apoyo para D. Francisco Javier. Se procede a realizar los cambios oportunos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-07-03','miguel, recibo email de Rocio (abogada): Buenos días Miguel Hemos tenido suerte y los inquilinos han entregado las llaves. Esta mañana me hará entrega su abogada. Dime que hago con ellas, No sé si Damián puede decidir sobre el destino de la vivienda o está dentro de las decisiones que vosotros tenéis que supervisar. Quedo a la espera. ************************************************* mi contestación:Buenos días, qué hacemos con las llaves del piso de Damián, les digo que nos la envíen o se las quede su prima Alicia en Málaga? Antes de que él sepa algo hay que decidir qué destino dar a la vivienda porque él querrá alquilarla de nuevo. **************************************************** envio consulta a Amalia: Buenos días, qué hacemos con las llaves del piso de Damián, les digo que nos la envíen o se las quede su prima Alicia en Málaga? Antes de que él sepa algo hay que decidir qué destino dar a la vivienda porque él querrá alquilarla de nuevo ***************************************************** contestación de Amalia:Buenas , en mi opinión es mejor que se las quede su prima en Málaga , para cualquier incidencia en la que se necesite que abran esa puerta . Damián no tiene claro qué hacer con esa vivienda , unas veces dice de alquilar , otras de vender y otras de que se vuelve él allí a vivir . Si quieres puedo consultar con el centro que pregunten su opinión actual , pero ya sabes que cambia mucho de opinión y no es permanente en sus decisiones ********************************************************** mi contestación:Hola Ama, aunque lo lógico es enviarlo a su prima, entiendo que debemos preguntarle teniendo en cumplimiento de la actual ley 8/21… Pregunta al centro y que le digan si quiere se la demos a su prima. Una vez esté todo correcto en la vivienda habrá que sentarse con la parte económica para decidir en común con Damian el destino de la misma. Con lo que me digas se lo traslado a la abogada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-07-24','miguel, envio email a parte economica y social: Buenos días, la vivienda de Damian fue desocupada y por un lado está la prima Alicia queriendo arreglarla y ponerla de nuevo en alquiler y por otro he recibido de Damian emails que veréis debajo. Tenemos que hablar, lo antes posible, las 3 partes social, económica y jurídica para decidir qué se va a hacer con la vivienda y cómo. Decidme cuándo. En el email siguiente os envío la contestación que le he dado a su prima Alicia. Como veréis son todos emails de la semana pasada, en la que yo estaba de vacaciones *******************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-07-19','miguel, emails de Damian:Mi prima no me gusta el trato que me está dando yo en malaga verdaderamente no tengo a nadie y yo quiero mi última voluntad que la comisión me venda el piso por un dinero alto y me compro algo aquí en Mérida que os mandé la llave pero yo no quiero saber nada de mi prima y menos en gastar dinero en arreglar un piso que ella no me da el trato correcto así que Amalia se ponga en contacto con el centro para venderlo pero no mal venderlo sino por lo que vale un piso en malaga***************************************************** Yo no quiero que mi prima me ayude a alquilar el piso porque mi relación con ella no es cordial y yo no quiero hablar con ella porque me llevo un malrato.le he dado el número a tecnocasa de Málaga para que se ponga en contacto con la comisión y mi prima Alicia no quiero su ayuda.yo no le voy a llamar para molestarla pero tengo clarísimo que no quiero contar con ella.quiero vender el piso y estar aquí con la comisión y la curatela y comprarme un piso en el centro de Mérida pero en tecnocasa de Málaga me han dicho que para yo vender tarda de 6 a 9 meses porque creo que tiene que autorizarle el juez.pido por favor que cuando hable con Alicia que no quiero saber nada de ella y que hay que abonarle el tema del cambio de cerradura yo no me encuentro agusto con mi familia y quiero claramente olvidarme de todo vender y comprar aquí porque a lo mejor se alquila y me destrozan el piso diga lo que me diga mi prima yo me quedo aquí en Mérida y no quiero ningún vínculo de amistad ni con mi prima ni con nadie de Málaga.ella denunciarme no puede porque no le he echo nada malo si que estoy agradecido que haya recogido la llave.yo no quiero contacto con ella','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-07-16','miguel, email de Damian: Hace tiempo que no le mando mensajes para no molestarlo.era para comentarle que mi piso.no sé si le ha informado Rocío se ha quedado vacío y mi prima Alicia está intentando contactar con la comisión para abonar a una empresa que busque mi prima de reformas para hacerle una reforma al piso y alquilarlo a una familia.muchas gracias y feliz verano.este es el teléfono de mi prima para que se lo pase a la parte económica 635525519 muchísimas gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-07-23','miguel, recibo email de Alicia (prima Damian)Alicia Cueto >aliciaasimas@gmail.com> en ctutelar: Estimado Sr. Miguel A. Fernández, mi nombre es Alicia Cueto, y me dirijo a usted, como en otras ocasiones, en relación a uno de sus usuarios, que es primo hermano mío, Damian Salvador Granados Heredia. Me consta que, a través de su abogada, Dña Rocio Gracián, sabe que el piso de su propiedad, ha quedado libre, tras muchos esfuerzos. Las condiciones en las que está el inmueble, requieren una serie de arreglos básicos para poder volver a alquilarlo. Damián me ha pedido que me encargue de realizar estas gestiones: Las obras pertinentes y el posterior alquiler, que en esta ocasión, sería con todo tipo de garantías y blindaje. Evidentemente, todo esto supondrá una serie de inversiones que debe asumir Damian y que son imprescindibles, antes de comenzar cualquier gestión. Le ruego que me indique, que protocolo debo utilizar de manera que la Comisión, que tiene la curatela de Damian, avale y autorice los gastos, incluso con anterioridad a la ejecución de las mejoras. Es decir, que debo hacer para que se me abone los gastos relativos a la obra del piso de Damian. Hasta el momento y por no tener la autorización más que verbal de Damian, solo he cambiado la cerradura como precaución ante los anteriores inquilinos. He tratado de contactar con usted a través de teléfono sin haberlo conseguido, por lo que le solicito que responda a la cuestión que le planteo a través de esta dirección de email. Sin más, esperando su pronta respuesto, reciba un cordial saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-07-24','miguel, mi contestación a la prima Alicia: Buenos días Alicia. Por ahora no haga nada en la vivienda porque tenemos que estudiar la nueva situación la Comisión. Como sabe Damian cambia de opinión a cada momento y está pensando en vender… Cuando tengamos una respuesta nos pondremos en contacto con ambos ********************************************* Reenvío contestación a parte económica y social****************************** Contestación de Amalia: Buenas , hasta que él no lo tenga claro es mejor no hacer nada , en los últimos 4 emails que ha enviado se desdice él mismo , en unos que vende, en otros que no .. imposible que se aclare, ahora se quiere ir a Galicia con un chico que ha conocido .. en fin .. ________________________________________','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2023-07-25','-Amalia , ha llegado escrito de PNC solicitando nominas del Ayto de Montijo que he pedido al centro . Y declaración del IRPF , Iciar lo anota en el listado para la asesoria y pedirá que se le haga.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-07-25','TERESA RECIBO INFORME SOCIAL SOLICITADO PARA VLAORAR LA SITUACION DE LA MADRE DE NATALIA ES INFORME ES FAVORABLE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2023-07-25','miguel, Paco (abogado de Villafranca):es el mismo abogado que en su día renunció al caso de Carmen Ruiz Larena por incompetencia territorial. Me llama porque está tramitando la herencia de 5 personas entre ellas la tutelada. Necesita los testimonios de incapacidad y nombramiento junto con certificado de discapacidad, empadronamiento y dni para la liquidación de impuesto de sucesiones e ir tramitando los bienes de la herencia (una vivienda y una cuenta). Le remito todo a su email 1804@icaba.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-07-25','Ana: Tras recibir llamada de Lourdes Pérez, TS del SAD - IMAS CC (927 949 205), confirmando el inicio del SAD mañana con la Auxiliar MARISA, llamo a Carlos y se lo comunico. ·························· Envío correo a Toni-Futuex: "comunicarte que me acaban de confirmar que mañana comienza a recibir el servicio de Ayuda a Domicilio. Le han concedido 2h/semana, los Miércoles de 8:00 a 10:00h. Carlos ya lo sabe, acabo de llamarlo al respecto. Supongo que es muy precipitado para que mañana esté presente Patricia al principio, si puede ir perfecto, sino no pasa nada, no creo que haya problema alguno. Por otra parte, me dice que tenéis un presupuesto para lavadora para enviarnos, cuando puedas remítelo al ctutelar@ porfa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-07-25','Ana: envío a registro (oac.merida.san@juntaex.es): "En representación de D. CARLOS GONZÁLEZ LEO, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, os remito Solicitud de Inclusión en el Servicio de Comida a Domicilio (Catering) Municipal para remitir por REGISTRO a: INSTITUTO MUNICIPAL DE ASUNTOS SOCIALES C/ Atahualpa, s/n 10005 – Cáceres CÁCERES"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-07-21','Ana: correo de Mª Victoria Gómez Tomé, Psiquiatra ESM-Plas. (mariavictoria.gomezt@salud-juntaex.es): "Buenos días: Mi nombre M victoria Gómez Tomé, soy psiquiatra del ESM de Plasencia, y realizo seguimiento d Enrique santos García-Puente, paciente incapacitado legalmente y tutelado por la CTA , según me dice el paciente asignado a usted. Nuestra trabajadora Social está de vacaciones por lo que no podemos contar con ella para las gestiones sociales. La situación es que esta mañana se ha puesto en contacto con nosotros Enrique para decirnos que le cierran la residencia donde se le proporciona la comida y que no sabe qué hacer ahora. He intentado contactar telefónicamente con la residencia, pero no lo he conseguido. Me dirijo a usted por si tenía noticia de que esto fuera una realidad inminente, como asegura Enrique, y en ese caso, poder plantear otras opciones para resolver la situación. Según me informa la trabajadora social de Valdeobispo también está de vacaciones `por lo que tampoco puede ayudarle."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-07-25','Ana: Conversación con Puerto, TS del SSASB, al Ayto. Valdeobispo (927 45 61 83) y Enrique, ponen manos libre. *Corroboran que cierran la Residencia del pueblo y se queda sin servicio de cáterin. ······················ Envío correo informativo a la Psiquiatra Mª Victoria Tomé: "Hoy he hablado con Puerto, Trabajadora Social del SSASB de Valdeobispo. Por desgracia, para Enrique y sobre todo para los residentes, sí que es cierto que cierran la Residencia y casi sin previo aviso… El problema es que no hay otro servicio similar ni en el pueblo ni en los alrededores. Enrique demanda que se le dé más dinero semanal, junto con su asignación, para la compra de comida que él mismo, dice, puede prepararse, que sabe cocinar cosas sencillas… tenemos ciertas dudas al respecto, pero, dado que es su deseo y, por lo pronto, no hay otra alternativa, hemos acordado Puerto y yo con él (conversación conjunta), probar durante un mes y valorar. *El jueves, que se incorpora el jefe de la sección económica de la CTAEx, veré con él este asunto para subir la asignación. No obstante, mientras tanto, Puerto va a preguntar en el bar del pueblo por si quisieran darle este servicio de comidas y nosotros preguntaremos en catering/servicios de comida a domicilio de Plasencia, pues no sé si alguno hará reparto a otras localidades. E independientemente de esto, estamos a la espera de la activación/revisión del PIA que se solicitó, pues, aunque sólo tiene grado I de Dependencia, podría optar al Servicio de Teleasistencia y Ayuda a Domicilio. El que tiene municipal, dadas las características de Enrique, no está funcionando del todo bien y además, son sólo 2 días en semana. Lo ideal es que pudieran ir casi todos los días de diario y así también podrían, quizá, ayudarle con la preparación de comidas. Pongo en copia a Ana Benavente, para que a su regreso, pueda leerlo y estar informada." ························································································································································································································································· Envío correo a Toni-Futuex informando de la nueva situación y solicitando que pregunten en caterings de Plas. por si alguno hiciera reparto en otras localidades y soliciten presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-07-25','Ana: Llamada de Mª Antonia (927 095 795), ha acudido a una clínica dental, pues necesita tratamiento. ········· Allí le han pedido que nos pongamos en contacto. ······················ Envío correo a Estrella, Secc. Ecca: "He recibido llamada de Mª Angonia Bernardo Piris, ha acudido a una clínica dental, pues necesita tratamiento. Le han dicho que nos pongamos en contacto para que nos faciliten presupuesto y explicar modo de pago y demás. Les habrá resultado un poco raro. ¿Te importaría llamar y encargarte, por favor? Estos son los datos de contacto: CENTRO ODONTOLOGICO AVANZADO MONREAL & ROMAN: 927 42 74 10 Cuando envíen presupuesto habrá que ver si es viable y valorarlo con Alberto." ································································································································································································· Envío correo a Toni-Futuex, pues ya se ha incorporado de vacaciones: solicitando retomen e intensifiquen seguimiento de Aª, dadas las sospechas de su hermana de que no está tomando adecuadamente la medicación y que está consumiendo de nuevo alcohol.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2023-07-25','Ana: Tras recibir llamada de Fermín, hermano de Luisa (695 846 836) envío correo al ctutela@: "En relación LUISA RESY CAMPÓN, le envié este correo a Alberto hace un mes, pero no sé si os ha llegado a pasar algo a alguna. Me ha vuelto a llamar Fermín, hermano de Luisa (695 846 836) preguntando al respecto y solicitando se cancele la cuenta del BBVA en la que está con su hermana y que está “0”. Podéis leer el hilo, está subrayado abajo en amarillo también. Agradecería que me explicaseis, a mí, e incluso a este Sr., cómo está la situación y qué se puede hacer, o incluso qué tendría que hacer él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-07-19','Ana: Llamada de Nandi (648 103 189), hermana de Mª Antonia, residente en Valencia de Alcántara. Dice que su hermana ya ha ido un par de veces al pueblo, sin previo aviso, a pasar unos días en casa de sus padres. No entiende que pueda moverse sin autorizaciones. *Le explico que a su hermana le dieron al alta terapéutica en el recurso en el que estaba y no tiene ninguna orden/autorización de internamiento involuntario y es libre, como cualquier ciudadano para circular y viajar. Además, vive de forma independiente en un piso compartido. ·············· Expresa que cree que no está bien, que hace "cosas que no son normales" como salir a caminar a las 16 horas con todo el calor en verano. Que además fuma mucho y está bebiendo de nuevo alcohol, cervezas, y duda de que esté tomando bien la medicación. ···················· Ante esto, le explico que pediré que agilicen la próxima visita del Programa de Apoyo Comunitario para valorar y pediré informe de asistencia al ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='DIAZ'and apellido2='ROMERO'),'2023-07-25','- emailde Eva : Buenos días Amalia. Adjunto remito contrato de HF, de Alberto Díaz Romero, para que lo firméis y nos lo hagáis llegar cuanto antes, para que lo mandemos al CADEX. ------------------------------- Se lo envío firmado para que lo envíen al CADEX .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-07-25','Vamos a esperar unos días por si finalmente regresa , nos vais informando. OK Ha dicho si finalmente se van a vivir al pueblo ?? Hoy han llamado y dicen que todavía no han ido al pueblo, pero que van a ir. Según nos ha contado un familiar de un usuario, vecino el problema es que como no han pagado la casa donde viven, se la van a quitar. cual era exactamente el sitio donde querían marcharse ? C Hernán Cortes nº 20 La Morera. Ya he pasado a los asesores jurídicos la documentación para solicitar internamiento involuntario en centro de discapacidad . OK.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-07-25','Ana: Correo de Sara García Ramos, Psicóloga - Fundación Autismo Sur (sara@autismosur.es): "Le enviamos algunas fotos de Costi disfrutando de su día a día. Actualmente está mucho más estable, los problemas de conducta han bajado en intensidad y frecuencia, la rodilla la tiene mejor. Tuvimos cita la semana pasada con el especialista en traumatología, nos dijeron que no hay que hacer ninguna intervención ni punción, si vuelve el dolor o malestar, seguir con antiinflamatorio tanto oral como en pomada, no hay ni luxación ni mucho líquido acumulado. Seguimos a la espera de su cita con neurología, que vamos a reclamar ya que ya han pasado los dos meses que hay que esperar para poder reclamar. Por último deciros que Ale sigue disfrutando y bien adaptado al recurso, disfrutando de las actividades veraniegas que estamos poniendo en marcha."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2023-07-26','TERESA ARCHIVO COMUNICACION DE VALORACION DE INGRESO EN RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='POBLADOR'and apellido2='FERNANDEZ'),'2023-07-26','TERESA A Tomás le gustaría pasar del 12 al 15 de agosto, unos días en casa de una compañera del Centro Ocupacional. La familia de la compañera se ha puesto en contacto con el centro, y me comenta que ellos lo recogerían y lo traerían al centro. Sólo debería llevarse algo de dinero (unos 50 - 60 €), para gastar esos días que pase en el pueblo de Campillo de Llerena (Badajoz), porque es fiesta. La familia firmaría un documento al salir del centro, pero no se si sería necesario otro documento para vosotros. SE AUTORIZA SALIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2023-07-26','Ana: con respecto al correo pendiente de Miguel, con AUTO DE INTERNAMIENTO: "Tere, en la base de datos indica que esta administración de bienes es tuya. Pongo en copia a Ana porque la resolución es de Cáceres. Se trata del testimonio de firmeza para el internamiento involuntario de Clementa Ramos Vivas. Desconozco si ya está internada, para que la internéis." Contesto: "Esta Sra. en inicio era mía, pero una vez que ingresó en la Res. El Cuartillo y pasó el periodo de adaptación, pasó a ser de Teresa, porque es uno de los centros de Cáceres que lleva ella. En septiembre de 2021 ingresó, por emergencia social y de forma involuntaria en dicho centro. Desde el Juzgado remitieron al propio centro Auto de Internamiento. La CTAEX sólo ostentaba la Administración de Bienes, al igual que en la actualidad, pues que yo sepa no ha llegado otra resolución judicial. Ya he visto que Tere envió al Centro este nuevo Auto. Entiendo que no hay que hacer nada más"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-07-26','Ana: en relación a las solicitudes de Ventura de viajes varios, llamo a Laura Salguero, TS ONCE (927 627 480): me informa además de las últimas actuaciones realizadas en coordinación con Julia, Centro de Mayores y Patricia, Progr. Apoyo Comunitario - Futuex. ··············· En cuanto a los viajes, la Convivencia en Benalmádena de Noviembre, ya se aprobó y se realizó un primer abono de la mitad (100 €) en mayo, quedan otros 100€ que se abonarán mediante transferencia en septiembre. ········ A parte, quiere ir también a un viaje de termalismo que hace ONCE junto con IMSERSO, en Cuntis, Pontevedra. El precio es de 416€ por 10 días. ··························· *Hablamos también de la necesitad de contratar un catering privado, pero le informo sobre la situación económica actual. Si contratamos el catering estaría gastando más de lo que ingresa, pues en el último año ha gastado más de 4.100 € en telefonía. ······················· Puesto que mientras hablamos avisan a Patricia de que acudido Ventura a verla, aprovechamos para que me llame desde su despacho y hablo con él. ························· Envío correo a Alberto - CTAEx, con copia a Maite-CTAEx y a Toni-Futuex: "Comentaros que acabo de hablar con Ventura, me llama desde el despacho de una de la compañera de la ONCE. Dice que la semana pasada dio de baja el gasto grande de telefonía. No sé si es verdad, pero le he propuesto, y acepta, que lo vais a comprobar y que si le siguen cobrando, se da de baja desde la CTAEx (o se devuelven los recibos). Lo de cambiar su contrato a tarjeta prepago, se muestra más reacio, pero finalmente dice que va a mirar precios y lo va a pensar, espero poder hacerlo con su consentimiento, en lugar de “a la bravas”, ahora que fin se está estableciendo cierto vínculo con él y contamos con la colaboración de las TS de la ONCE y del Centro de Mayores, además de con la nueva Ed. Futuex, con la que parece haber encajado bien. Con el apoyo de ella espero que finalmente acepte el cambio a prepago. **cuando se deje de abonar los -265,48 € de telefonía, si os parece, contratamos el CATERIN privado, pues sería mucho más beneficioso para su salud. Lo demás, poco a poco, lo vamos viendo, si os parece. De todas formas, Alberto, si quieres, lo hablamos mañana. Pongo en copio a Toni-Futuex, para que esté al corriente de la cara a la intervención de Patricia desde el Programa de Apoyo Comunitario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-05-25','Ana: correo de Laura Salguero Sánchez, TS ONCE (LASS@once.es). "Comentarte que Ventura lleva una temporadita muy buena, al menos por aquí en la Once. Socializando bastante, y con una actitud muy positiva. Desde UP (unión política dentro de la ONCE) se organizan convivencias anuales, y como este año él está mucho más integrado, los afiliados le han animado a que también vaya. Son en noviembre (te adjunto toda la información en este correo), y tiene que pagar ahora la semana que viene 100€ a modo reserva de habitación. Él está encantado. En principio, como el gasto es menor, entiendo que no tendríamos que pasar ningún trámite como el de la otra vez, pero debo informaros igual. El precio total son 200€. La mitad la paga la semana que viene, la otra mitad en septiembre. Si necesitáis algo más, me decís. Mañana aquí es festivo, pero el lunes estaré a vuestra disposición."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-05-31','Ana: correo de Laura Salguero Sánchez, TS ONCE (LASS@once.es). "Ventura vino a traer los 100€ del primer pago. Podemos devolvérselos en caso de que no lo autoricéis." ············· Se autoriza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-07-26','Ana: Correo de Toni-Futuex: "se pasa el presupuesto solicitado de lavadora, ayer no me dio tiempo a pasarlo a ctutelar, pero consideramos que se deberia esperar, ya hoy al estar la compañara alli, ha visto que la lavadora que tiene, puede tener necesitar algun arreglo, poruqe tiene obstruido de cal la manguera del agua al parecer, pero enciende, y a priori tras el arreglo necesario, funcionaria. Asique se considera mas adecuado pedir un presupuesto a técnico, y valorar, si te parece bien. Ha estado la auxiliar, y nada, al parecer hay que comprar absolutamente de todo, no tiene nada, de productos de limpieza ni de utilensios.. de hecho, parece por como esta la casa (de polvo y poco uso) que casi no pasa tiempo alli, el dice que se va a comer y a dormir a casa de una novia que tiene. Enviaremos una nota lo antes posible, con lo que le ha pedido la auxiliar y necesita, para ver si se puede autorizar una retirada para este lunes, y que lo acompañe la compañaera para asegurarnos que se invierte en lo que necesita." ··································· Mi respuesta: "De acuerdo a las cosas: - Cuando tengáis presupuesto del técnico para el arreglo lo enviáis a la sección económica. - Y para los productos de limpieza para que la Auxiliar pueda comenzar a realizar su trabajo, en cuanto nos digáis presupuesto aproximado de gastos, lo pasáis también para que realicen esa autorización de retirada al banco para que pueda acudir con la Educadora el Programa de Apoyo, tal y como planteas. Pongo en copia a las compañeras de la sección económica para que estén al corriente y puedan proceder cuando enviéis ambas cosas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-07-19','Maite: ha llamado Verónica, trabajadora social de Cruz Roja de Badajoz para darnos información sobre el paradero de Joaquina . Ayer 18 de julio, Joaquina y su pareja fueron a hablar con Verónica para solicitarle una vivienda social. Les contaron su situación y Verónica habló con el SSAB y con el director de la Granadilla para contrastar la información. Me dijo que están por el parque castelar. No quieren ir a los centros que le han asigando a cada uno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-07-21','Maite: llama de nuevo Verónica para comunicar que Joaquina sigue en la calle , por la misma zona de Badajoz ( parque castelar)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2023-07-26','TERESA Me dice el hijo de Ana que su madre tiene deudas con el OAR y en Hacienda. El teléfono fijo es el 924580199 a ver si es posible mantener ese contrato para que puede beneficiarse del servicio teleasistencia. Estamos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-07-26','Ana: Correo de Puerto, TS SSASB-Valdeobisto: "ayer como sabes estuvimos hablando con Enrique respecto a lo de la comida y la cena, el pleno celebrado con fecha 19 de julio del Ayto de Valdeobispo ha decidido cerrar la residencia de Valdeobispo con fecha 31 julio, por tanto, Enrique se queda sin servicio de comidas... en el municipio y en la zona no hay servicios de catering ni centros residenciales que ofrezcan ese servicio, hablé con la dueña del bar de la Pista y me dijo que ellos no hacen menús y tampoco pueden comprometerse a elaborar diariamente esa comida y cena para Enrique. Tal vez podría probarse el manejo que tiene él al hacerse la comida una semana, pero ahora mismo no tiene SAD¿?¿?¿!! Respecto al SAD comentarte que actualmente Enrique no recibe el servicio al haber finalizado el contrato una de las auxiliares, a su domicilio siempre van dos porque una sola no quieren ir al haber sucedido algunas incidencias ... Sería conveniente que se reactive el PIA de dependencia para PEVS-SAD y TAD puesto que con grado I tendría 20 horas mensuales. Con el SAD municipal tiene 8 horas mensuales (sin sustitución de vacaciones y con cambios de auxiliar porque son contratos de 6 meses, además de períodos sin servicio desde que finaliza el empieza la siguiente auxiliar) Enrique es una persona con mucha dificultad para la gestión económica y tal y como nos encontramos la vivienda (cocina, nevera, etc) al inicio del SAD tengo mis dudas que sepa gestionarse bien en la realización de comidas y cenas?¿ Es una pena que cierren este centro residencial -y con esta premura- pues contábamos con una buen servicio de comidas para Enrique que facilitaba la permanencia en su domicilio!" ······························ Mi respuesta: "Es una pena que desde el bar no puedan comprometerse a dar este servicio, que por otra parte entiendo. Al igual que tú, también tengo serias dudas sobre que él se maneje bien para preparar las comidas y sobre la gestión del dinero a tal fin… Como ayer acordamos darle esta oportunidad y probar un mes, vamos viendo, y si hay motivos para cambiar de fórmulas en menos del mes, se le explica y se cambia de modo de proceder. Mientras tanto, las compañeras del programa de apoyo comunitario buscarán alternativa de catering/servicio de comidas a domicilios en Plasencia, que no sabemos si hay alguna que haga reparto a otras localidades. La solicitud de activación PIA, ya la hice hace meses. No obstante, intentaré llamar mañana a ver cómo está esta solicitud, a ver si pueden agilizarla. SE pidió para TAD, pero entiendo que no habrá problemas para PV-SAD también, pues sería otra de las prestaciones que le corresponderían. Y esperemos que en este caso funciones con una Auxiliar sola, pues ahí no vamos a tener opción de que vayan dos como con el Ayto. Pero habrá que trabajar también esta cuestión con él de forma previa. Ayer informé también a su Psiquiatra, pues me habían consultado al respecto del comedor, porque Enrique había llamado allí también para decirlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2023-07-26','miguel, llega de la comisión de asistencia juridica gratuita de Badajozel reconocimiento a la tutelada del derecho de asistencia juridica gratuita','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-07-27','Ana: Envio correo a Julio - CTAEx: "oficio solicitante INFORME relativo a ANTONIA BERNARDO PIRIS, para remitir por registro al EQUIPO DE SALUD MENTAL DE PLASENCIA, junto con el Acuerdo de Aceptación del Cargo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='DIAZ'and apellido2='ROMERO'),'2023-07-27','-Amalia , la tia ha vuelto a llamar para solicitar traslado a Badajoz , me encargo de ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-07-27','-Amalia : Buenos días , hoy se traslada a Santiago P.G. desde el centro ASPACEBA a plaza residencial en Plena Inclusión Cabeza del Buey. Irá en transporte del centro y se llevan todas sus pertenencias . Va acompañado de un monitor. No sé si en la base aparece como en domicilio familiar , en ASPACEBA ha estado residiendo de manera provisional sin resolución de plaza , sólo acudía a Centro de Dia . La sentencia de medidas de apoyo también es provisional , a la espera de que el juzgado resuelva la definitiva. Este chico vivía con su hermano , y tras una agresión se tuvo que proceder para que saliese del domicilio. Tere , de momento y hasta que pase un tiempo de adaptación como hacemos en todos los casos , continuo yo con él . Quería comentarte si este centro que es de tu zona tiene la autorización general de autorización de salidas . La TS que está ahora cubriendo las vacaciones de la otra compañera no sabe si la tienen. La hermana ha solicitado poder llevárselo algún fin de semana a Badajoz , en las últimas semanas ha retomado contacto con él y parece interesada . Un saludo. -------------------------------- He enviado a P.I. toda la documentación solicitada y firmada , si falta algo me lo pedirán. Falta que me digan el pto. de gastos mensuales y el Nº cuenta del centro donde hay que ingresarlo . El copago lo cargarán en la cuenta de Santi , ya se lo he pasado a la TS . La tia solicita poder sacarlo , he preguntado lo de la autorización general a Tere y quedo pte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2023-07-27','REMISIÓN PIA Se remite PIA (solicitud del servicio), debidamente firmado y sellado por el Dr. Gerente, a través de SIREX, a dependencia Zafra. Tal y como se quedó con ellos en comunicación telefónica mantenida al efecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES MARIA'and edp.apellido1='ALVAREZ'and apellido2='CARRASCO'),'2023-07-27','Amalia : email del CSS Merida y respuesta de MIguel . Como era de esperar la hermana de Inés M.ª Álvarez Carrasco ha vuelto a disponer de los bienes de la paciente a su antojo. Adjunto os remito los movimientos bancarios. En dicho documento podréis ver que el día 17 de julio Montserrat realizó dos transferencias internas por los siguientes importes 9400€ y 2000€. Además, os remito el informe social y los escritos que envié tanto al Jdo. como a la Fiscalía solicitando la remoción de tutela. ------------------------------------------- Buenos días Maria de los Angeles, hasta que no sea firme la resolución judicial de nombramiento a la Comisión Tutelar de Adultos, ves comunicando a fiscalía y al juzgado cualquier transferencia que siga realizando incluyendo las dos que mencionas del día 17-7-23, y en el mismo escrito solicita que intervengan de oficio con urgencia ya que se le está produciendo un importante desamparo a Inés, y un perjuicio irreparable en su patrimonio. M.ª Ángeles Galindo Barrena. Trabajadora Social. ​Centro Sociosanitario de Mérida Ctra. de Valverde Km. 2. 06800 Mérida. 924388182. Ext. 24006.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-07-27','Ana: Hablo con Raquel Gómez, Enfermera de la Secc. Acceso a RR de S.M., me confirma que hay plazas en el CRR de Plas. Ha hablado también ella con Pilar Martín y le ha confirmado que Doroteo Podría ingresar allí. ························· Llamo a Doroteo (609 928 621): sigue convencido de querer cambiar de aires y acepta Plas. Le informo de que el traslado a CC no podría pedirlo hasta que llevara un año allí, le parece mucho, pero lo acepta. Cuando pregunta por el coste del centro y le digo que no tendría que abonar nada, se queda más convencido del todo. ······································ Llamo a Pilar Martín (54612): le confirmo que Doroteo acepta el ingreso en Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-07-27','-Amalia : email de Cati : Hoy han llamado y dicen que todavía no han ido al pueblo, pero que van a ir. Según nos ha contado un familiar de un usuario, vecino el problema es que como no han pagado la casa donde viven, se la van a quitar. cual era exactamente el sitio donde querían marcharse ? C Hernán Cortes nº 20 La Morera. Ya he pasado a los asesores jurídicos la documentación para solicitar internamiento involuntario en centro de discapacidad . OK. Nosotros nos vamos de vacaciones hasta septiembre. Ha la vuelta si hay novedades, pues lo comunicamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2023-07-27','Ana: correo de Alberto, Jefe secc. ecca.: "HEMOS TENIDO CONOCIMIENTO DE QUE TUTELADO ESTÁ INTENTANDO UTILIZAR TARJETA---DESCONOCEMOS SI PARA PAGO X INTERNET O PARA PAGO EN TIENDA....LA COMPRA ES X UN IMPORTE PEQUEÑO Y NO SE LA HA AUTORIZADO EL BANCO. XFA, QUE HABLEN CON EL Y QUE TENGA EN CUENTA QUE PUEDE TENER CONSECUENCIAS COMO LA BAJADA DE LA ASIGNACIÓN---ACTUALMENTE 80 €/SEMANA." ······························· Lo reenvío a Toni-Futuex para que la Ed. del programa pueda abordar este asunto con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-07-24','Ana: Correo de Pilar Martín, TS ESM-CC (pilar.martinp@salud-juntaex.es): "Ana tengo a Francisco Cacho Garrido, me dice que se encuentra en situación de calle, le indico que vaya al albergue de Ríos Verdes pero no quiere ir, vuelvo a insistir para que desde allí le diriven a Centro Vida. Además, no tiene móvil y dice que se encuentra durmiendo en la estación de autobuses. Me dice que hoy inicia tratamiento en el EC.a a i Solicitado PS con anterioridad y con alta voluntaria a petición suya en Almendralejo. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-07-27','Ana: En Centro Vida no hay plazas. ················· Envío correo a Pedro Pablo Garvi, Coordinador del CES - Caritas (pgarvi.cdcoriacaceres@caritas.es): "Me pongo en contacto contigo para preguntarte acerca de FRANCISCO CACHO GARRIDO. Sabemos que abandonó Centro Vida y que ahora está en situación de calle. La compañera de Salud Mental le indicó la semana pasada que fuera al Centro de Emergencia Social de Cáritas, así que quería preguntarte si ha llegado a acudir para pernoctar allí alguna en esta última semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-07-27','Ana: Envío correo a Toni-Futuex: "En relación a ÁNGEL FÉLIX MAILLO SANTIBAÑEZ, no sé si habéis vuelto a visitarle, ni si tenéis información sobre cómo sigue. Por nuestra parte, según carta que él mismo ha enviado, comunicaros que ha vuelto a abandonar el Albergue de Cáritas, de nuevo está en situación de calle y retoma la idea y la solicitud de buscar alguna vivienda de alquiler en algún pueblo, lejos de Plasencia, dice incluso. Atendiendo a su voluntad y preferencias, ¿Podríais retomar de nuevo el seguimiento y apoyarle en la búsqueda de alojamiento? Ya nos vais informando al respecto." ··································· Respuesta de Toni: "se le ha llamado en algunas ocasiones, algunas con exito y otras no. Lo último que nos constaba es que estaba residiendo en Piornal, no se, si es alli donde se encuentra en situación de calle o es que ha regresado a Plasencia. En el ultimo contacto se le ofrecio prestarle apoyo, o visitarle incluso en esa localidad, lo rechazo. Y ya en esta ocasion solicitaba informacion sobre pisos de alquiler de la zona, se le indica que se consultarian paginas webs y se le informaria (más en torno a ese particular, no podemos hacer, sobre alquileres en Piornal o alrededores). A los pocos dias se le llama para decirte, que no hemos encontrado nada que le pudiera interesar, que alomejor el puede preguntar, puesto que alli funciona el boca a boca (en pueblos pequeños) no le gusta la respuesta y cuelga el telefono. Se ha intentado el contacto en mayo y junio, pero sin éxito. En sus peticiones, casi siempre esta presente la exigencia, "teneis que hacerme tal cosa" o "la junta no puede tenerme asi" y cosas parecidas, en las que obviamente tiene cierta confusión sobre según que cosas, eximiendose de responsabilidades que son individuales, a nuestro entender. No obstante, se le volvera a llamar, a ver si conseguimos algo esta vez. Te adjunnto el historico de las ultimas gestiones con el" ····················· Guardo correo en PDF en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-07-27','Ana: Correo de MªPaz Casado Rabasot, Psicóloga Clínica - UHDAC (mariapaz.casado@salud-juntaex.es): "En relación a situación ya informada de prealta de los pacientes (Alejandro, Aaron y Cristofer) ingresados en la UHDAC, que están a la espera de que el SEPAD les asigne plaza residencial comunitaria para proceder al alta, tras evolución favorable y presentar estabilidad tanto a nivel psicopatológico como conductual, y ante la obligación de informar periódicamente al Juzgado para mantener ingreso involuntario, se informa que se va a proceder a comunicar de tal situación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='VELASCO'and apellido2='CAPERUZA'),'2023-07-28','Buenas , este señor está en la residencia Mixta de Monesterio . Hago yo el Plan de Intervencion inicial . No tiene seguro decesos , tiene 68 años y tiene demencia y consumos de alcohol . No sé si se le podrá solicitar un seguro . De momento no se le va a enviar dinero para gastos de bolsillo a peticion de la Dtra. para que no consuma alcohol. Tiene deudas pendientes con bancos . Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-07-28','Ana: Correo de ayer de Alberto: "ICIAR: SUBIMOS ASIGNACIÓN A 150€/QUINCENA. ANA: NO SE PUEDE DECIDIR SI VAMOS A MANTENER ESTA SUBIDA O HABRÁ QUE BAJARLA. MOTIVOS: • TENGO FACTURA DE FARMACIA EN JULIO X MÁS DE 80 € ----- EVIDENTEMENTE, SI VAMOS A TENER ESTE NUEVO GASTO NO PODREMOS SUBIR LA ASIGNACIÓN O EN MUY POCO IMPORTE. PUEDES AVERIGUARLO??? • NUEVOS GASTOS PERMANENTES QUE VA A ASUMIR: LOS IMPUESTOS (OAR) RELACIONADOS CON VIVIENDA (IBI, OTROS...)" ··································· Llamo a José Manuel para informarle, no se muestra nada conforme con la subida, quiere que se lo suban a 165€, como la vez anterior que tuvo el Catering del IMAS. ······································································· Mi respuesta al correo del Alberto: "La factura de farmacia, si no me equivoco, corresponde a varios meses. Son relativas a cremas que le prescribió el médico (no entran por la seguridad social) para los dolores de rodillas. Esto lo tenía hablado Óscar con la farmacia. Ahora está asistiendo al FISIOTERPAUTA de la Seguridad Social, esperan que mejore y no vuelva a necesitar tantos productos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-07-28','TERESA Vamos a contratar servicio de ayuda a domicilio con la empresa Giamex (residencia sierra pinar de zafra). 20 horas al mes, 1 hora de lunes a viernes. Sería conveniente que la educadora del programa acompañara el primer día a la auxiliar. El servicio va a comenzar el 1 de agosto. No tengo teléfono de contacto de Jose M para comunicarle la contratación y que me indique que horario prefiere…..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2023-07-28','Ana: Ha habido un error, José no tiene tarjeta ni ha intentado nada, ha sido otro tutelado. Lo comunico a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-07-28','Ana: solicito a Toni-Futuex informe actualizado de la situación de Aitor en domicilio de la madre. ································································································································································································································································ Envío correo al Programa de Familias: "Deciros que el miércoles recibí llamada de Felisa, estaba desesperada, la convivencia con Aitor cada día es más insostenible, ella lo está pasando muy mal. Me dice que al parecer está consumiendo también cocaína y que todas las semanas tiene que darle entre 40-50 €, pues si no se los da le monta un buen escándalo con gritos, insultos y golpes en puertas y ella pasa mucho miedo. Dice que no quiere poner denuncia, no se atreve por miedo y también le cuesta por ser su hijo, a pesar de conocer la conveniencia de hacerlo, la insistencia de Jesús y mis intentos para animarle a hacerlo. ¿Sería posible que vosotras abordaseis esta cuestión en persona con ella? Así mismo, una vez más, quisiéramos pediros otro informe, aunque sea breve, de la situación actual y del riesgo que supone para el propio Aitor su conducta y para Felisa la convivencia en estas condiciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-07-26','Ana: Llamada de Felisi, madre de Aitor, muy desesperada. No puede con Aitor, todas las semanas le pide entre 40-50 € y si no se los da le monta un escándalo, con gritos y golpes a las puertas y otro muebles. A Felisi le da tanto miedo que acaba dándoselo. *Aitor está de nuevo consumiendo, ahora, según les han informado, también cocaína.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2023-07-17','TERESA ENVIO SOLICITUD ELECCION DE CENTRO DISCAPACIDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-07-28','Amalia : os paso hoja de derivación de un caso nuevo de Zafra + sentencia + informe social SSASB para que cuando se pueda se realice una primera visita. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-07-28','Ana: Llamo a Pedro Garvi, Coord. CES - Caritas (673 303 677): me informa que Francisco, desde que abandonó voluntariamente C. Vida, para irse a Madrid, volvió a los 4-5 días, y desde entonces ha pernoctado noches puntuales en el CES (C. Emergencia Social). Estas últimas noches, según ha manifestado el propio Francisco, ha estado pernoctando en la estación de autobuses, pues en al CES están acudiendo otros dos hermanos problemáticos con los que no se quiere relacionar. No obstante, no lo ve muy estable, está "desbocado" y es difícil intervenir con él. ···· Le han dicho que vuelve a pasar por C. Vida el lunes por si quedara alguna plaza libre, que es lo que demanda ahora. ························ *Me informa también que han tenido visita de la Fiscal Carmen Barquilla y reunión con ella y otros recursos (Cruz Roja entre otros) en relación a las personas sin hogar. ······ *Tras esto, Pedro plantea, en el caso de Francisco, que se pueda solicitar internamiento involuntario. ·········· *Pedro me enviará un breve informe en que indique la fecha en que abandonó C. Vida de forma voluntaria y las pernoctas puntuales en el CES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-07-28','Ana: Correo de Gema Morato, Directora de la RR.MM. La Hermandad - Grupo Asoma, de la localidad de Cedillo (gemamg.asoma@gmail.com): "Adjunto remito la carta que he recibido hoy de la agencia tributaria de Victor" ···· Se trata de PROVIDENCIA DE APREMIO por no abonar una deuda notificada anteriormente. Con recargo asciende a 72€. ····························································Lo reenvío a Alberto, Jefe Secc. Ecca. ····························································································································································································· El nº de Gema = 639 694 905 y el fijo de la residencia el 927 590 145.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-07-28','miguel, Quedé con Maite en llamar a la juez Patricia hoy. Me llama y hablamos sobre este caso y me confirma que los informes forense y del Ministerio Fiscal (Carmen Barquilla) entienden que no es necesario internamiento en unidad de psiquiatría por no haber alteración de conducta. Hace un año dictó internamiento similar y no se cumplió tampoco. Le explico tipos de recursos que tenemos básicamente y que para un internamiento neceistamos que el auto recoja expresamente unidad de psiquiatría. Me indica que si es un requisito para el acceso a los mismos tal como le digo, que dónde viene eso recogido, le digo que el lunes la llamará Maite por tener más conocimientos de los social a su teléfono particular (porque la juez teletrabajará el lunes) Tras comentarlo con Maite, me comenta que hablará con Soraya para que la informe bien d dónde se recogen dichos requisitos para entrar en esas unidades psiquiátricas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-07-27','miguel, tras hablar con Maite vemos que el jzdo nº2 de Trujillo finalmente ha dictado Auto ordenando ingreso en centro adecuado, que no es en Unidad de psiquiatría UHB o UME que es lo que necesitamos. Llamo al jzdo para buscar soluciones pero la juez no viene hasta mañana. La envío email a p.gutierrez@poderjudicial.es: "Buenos días Patricia, hemos intentado desde la Comisión Tutelar de Adultos sin éxito hablar contigo acerca de este Auto autorizando el internamiento involuntario en Centro adecuado o Piso. Pero para su ingreso se exigen una serie de requisitos. Por ello se hace necesario que previo al acceso a un centro, ingrese en un Unidad de Psiquiatría, inicialmente de estancia breve en el Hospital (UHB),y posteriormente en la Unidad de Media Estancia del Centro Socio Sanitario de Plasencia (UME), con el fin de que tras el tratamiento médico adecuado pueda acceder a un Centro. Es por ello que se debe recoger en el Auto su ingreso en la Unidad de Psiquiatría de la UHB y de la UME. Quedamos a tu disposición para aclarar cualquier duda".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2023-07-25','miguel, envíamos por sirex contestación en trámite de audiencia a la multa que le han puesto por tener cerdos sin registrar. Tras comentarlo con la Consejería de Agricultura me piden les envíe la sentencia de incapacitación para ver si pueden reducir o archivar o eliminar dicha multa, aunque me avisa que no es seguro hasta lo vea su compañero que está de vacaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-07-28','Ana: Envío correo al Programa de Familias: "Deciros que el miércoles recibí llamada de Felisa, estaba desesperada, la convivencia con Aitor cada día es más insostenible, ella lo está pasando muy mal. Me dice que al parecer está consumiendo también cocaína y que todas las semanas tiene que darle entre 40-50 €, pues si no se los da le monta un buen escándalo con gritos, insultos y golpes en puertas y ella pasa mucho miedo. Dice que no quiere poner denuncia, no se atreve por miedo y también le cuesta por ser su hijo, a pesar de conocer la conveniencia de hacerlo, la insistencia de Jesús y mis intentos para animarle a hacerlo. ¿Sería posible que vosotras abordaseis esta cuestión en persona con ella? Así mismo, una vez más, quisiéramos pediros otro informe, aunque sea breve, de la situación actual y del riesgo que supone para el propio Aitor su conducta y para Felisa la convivencia en estas condiciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-07-28','TERESA ARCHIVO COMUNICADO DE PNC TRASLADO A CASTILLA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-07-28','-Amalia ; recibo email del centro se lo paso a sección eco y a Tere. Amalia si no te importa nos podíais enviar de nuevo la autorización general ya que desde el 2015, hemos cambiado varias veces de trabajadora social y también hemos cambiado de directora de residencia y ahora mismo no la localizamos. Además en 2015 éramos Aprosuba11 y ahora somos Plena inclusión CABEZA DEL BUEY, también vendría bien tenerla actualiza. Por otro lado, referente a la asignación mensual para gastos de bolsillo podríais comenzar a ingresar 100€, comenzaríamos ahora a primeros de Agosto, para gastos del mes de agosto. Sí luego vemos que hay que aumentas o reducir, depende de los gastos, pues luego más adelante ajustamos la cuota. El número de cuenta al que lo tenéis que abonar mensualmente es: IBAN: ES73 2103 7123 31 0010015170 En concepto: Gastos bolsillo SANTIAGO XXXX (MES TAL) En relación a su cuota mensual para la financiación de su plaza de residencia, le pasaremos nosotros mensualmente el cargo a mes vencido, en decir, en agosto le cobraremos los 5 días que va a estar de julio, en septiembre le cobraremos el mes completo de agosto, y así sucesivamente. Como sus ingresos son : 832.80 +679.90=1512.70€ mensuales El 75% de 1512.70 = 1134.53€ CUOTA MENSUAL MES COMPLETO. JULIO: 31 DÍAS. 1134.53 / 31 = 36.59€/DÍA *5 = 182.98€ De Julio se le cobra 182.98€ correspondiente a los días 27, 28, 29, 30 y 31 de Julio. De agosto en adelante se le cobrará 1134.53€ mensuales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-07-31','-Amalia : no tenemos el DNI escaneado , la persona no abre la puerta y el SSASB no lo tiene . Tampoco tiene dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-07-24','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "trasladarte una incidencia ocurrida la semana pasada con la persona usuaria Juan José Bergantiño Gónzalez: La semana pasada, las compañeras se encontraron una maleta cerrada con candado en su habitación. Se le pide que la abra, a lo que en un inicio se niega afirmando que no recuerda el código del candado e indicando que se la va a llevar al domicilio familiar. Tras conocer, por algunas personas usuarias, el posible contenido de la maleta, le indicamos que antes de llevarse la maleta, tenemos que ver el interior. Finalmente, abre la maleta con Cristina, psicóloga, encontrando en su interior lo que adjuntamos en foto. Tras este hecho, plantemos que, como medida preventiva y consecuencia de haber introducido este tipo de objetos en el centro sabiendo que no están permitidos, una expulsión temporal, de una semana. Sabiendo que no puede ir al domicilio familiar, tendríamos que buscarle un sitio dónde quedarse esta semana. La idea es iniciar esta expulsión este viernes 28 de julio de 2023. A la espera de vuestra respuesta para indicarle a Juan José las consecuencias por lo ocurrido." ····················· Mi respuesta: "...la incidencia ocurrida con JUAN JOSÉ BERGANTIÑO GONZÁLEZ, ya se lo había comentado Raquel Gómez, compañera de la Sección de acceso a los recursos de Salud Mental, a Maite la semana pasada, teníamos pendiente llamaros, pero la vuelta de vacaciones aquí siempre se hace complicada y no he llegado a todo. Y en relación con las consecuencias que debe haber por lo hechos ocurridos, nos parece bien la expulsión temporal de una semana que proponéis, se han mirado sus cuentas y puede asumir una estancia en un hostal o similar. No obstante, nos preguntábamos si os planteáis alguna otra consecuencia a su regreso al centro, algo que le note en su día a día y le haga reflexionar en un futuro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2023-07-20','TERESA EMPIEZA NUEVO SERVICO CON DEPENENCIA EN EXTREMADURA TRAS ABANDONO DEL SERVICIO LA AXULIAR DE LA EMRPESA SERVICIOS DEL FRESNO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-07-31','Ana: recibimos breve informe SOAP de MAP, Ana Belén Soria Iglesias: "Diagnóstico de hipotiroidismo, dislipemia en tratamiento con Simvastatina 10mg" e HISTORIA CLÍNICA RESUMIDA. ··················· Escaneo y guardo en el expedientes antes de enviárselo a Ángel, A. Jurídico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-07-28','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Tal y como hablamos, vamos a proceder a realizar la expulsión temporal de Juan José Bergantiño. Adjunto remitimos documento para su revisión y posterior confirmación, antes de hablar con Juan José." ............. En el documento adjunto, detallan todo lo relativo a incidencia, con imagen de la maleta cuando la abrieron, así como las consecuencias y la información sobre los hoteles que han consultado para su estancia durante la expulsión. ····················· Se lo remito a Alberto, Jefe Secc. Ecca. ·········· Comunico a Sheila que se ha aceptado el más económico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-07-31','Ana: Conversaciones varias con Sheila (676 668 793): Finalmente Juan José desayunará en el hotel (precio final: 266€), comerá en casa de su hermana y cenará en un restaurante cercano al hotel (12€/cena). Abonará ambas cosas en efectivo el primer día. ················· Estrella, Secc. Ecca., realiza y envía al banco Autorización de retirada de efectivo: 350 €. ························· *Hablo con Toni-Futuex: Patricia, Ed. está por el Centro de Cáceres, tenía previsto acompañar a Juan José a las 11:30 h al E.CA. (esto no lo sabían en el CRR y nosotros tampoco), Toni le dirá que intente acompñarle antes también al banco a retirar el efectivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-07-31','Amalia , escribo a P.I. C del Buey. de la autorización general para todos los usuarios/as te la va a facilitar Tere. Cómo se va adaptando Santiago ? Todo bien ? Un par de cosas pendientes : -Hay que empadronar a Santi en el centro y en esa localidad . Si hay que firmar algún documento como Rpte. legal por favor , remítemelo y lo pongo a firma . Esto es urgente ,porque su hermano con el que convivía no tiene acceso a ningún tipo de prestación mientras Santi siga empadronado con él. -Desde ASPACEBA consideran favorable que pueda tener un móvil básico , las terapuetas indican que podría utilizarlo correctamente para poder seguír manteniendo contacto con los profesionales y compañeros del centro . Tenemos dos opciones , podéis comprarlo desde el centro y enviarnos la factura para abonarlo , o hacemos un reintegro extra para eso . Otra opción es que una delegada tutelar le ayude en esta gestión . Ya me decís y lo vemos . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-07-31','Amalia : llamo a la sobrina , hija de su hermana : Amanda 610057309','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-07-31','-Desde el centro nos informan que se adaptando bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-07-31','Ana: Correo del PAF (programafamilia@tajosalor.es): "la situación de Felisi es bastante dura pero las versiones son variantes, depende del día y del momento. Sabemos que Aitor está consumiendo porque nos lo ha dicho él, incluso en momentos puntuales nos pide ayuda y quiere ir a CEDEX, pero cuando le intentamos ayudar se echa atrás. Por otra parte, Felisi nos dice que Aitor le pide 5- 10€ y se los devuelve, pero delante de Jesús tiene que decir que le pide mucho más porque Jesús también le pide. Ahora Jesús está viviendo con ella otra vez. No sabemos realmente lo que le pide o no Aitor, pero es muy posible que cuando tenga mono de voces y golpes, hace tiempo nos contó algo pero no volvió a decirnos nada, cuando le volvimos a preguntar nos decía que bastante bien, pero claro, ahora ha vuelto a aparecer Jesús y todo cambia. Así que, la verdad, no sé muy bien qué poner en el informe… Si te parece esta semana cuando hagamos la compra hablamos con ella y lo que nos cuente lo ponemos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-07-31','Ana: Correo del PAF (programafamilia@tajosalor.es): "la situación de Felisi es bastante dura pero las versiones son variantes, depende del día y del momento. Sabemos que Aitor está consumiendo porque nos lo ha dicho él, incluso en momentos puntuales nos pide ayuda y quiere ir a CEDEX, pero cuando le intentamos ayudar se echa atrás. Por otra parte, Felisi nos dice que Aitor le pide 5- 10€ y se los devuelve, pero delante de Jesús tiene que decir que le pide mucho más porque Jesús también le pide. Ahora Jesús está viviendo con ella otra vez. No sabemos realmente lo que le pide o no Aitor, pero es muy posible que cuando tenga mono de voces y golpes, hace tiempo nos contó algo pero no volvió a decirnos nada, cuando le volvimos a preguntar nos decía que bastante bien, pero claro, ahora ha vuelto a aparecer Jesús y todo cambia. Así que, la verdad, no sé muy bien qué poner en el informe… Si te parece esta semana cuando hagamos la compra hablamos con ella y lo que nos cuente lo ponemos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-07-31','Ana: Raquel, Enfermera Secc. Acceso RR. Salud Mental, le entrega a Maite la RESOLUCIÓN APROBATORIA DE PLAZA EN CRR-PLAS. ··················· Lo comunico a Doroteo. ···························· Ana: Llamo a Julia, Casa Misericordia Alcuéscar (927 12 00 24): le informo de la concesión de plaza en CRR para Doroteo. Le informo que tiene que llamarle para hacerle una entrevista previa al ingreso. ·········· A Julia le da pena, pues dice que allí en el centro está bien y cuando comenzó a estar peor fue cuando retomó contacto con la ciudad de Cáceres. *Elaborarán un breve informe al respecto y nos lo harán llegar. *No cree que sea conveniente que en el futuro regrese a vivir a Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-07-28','Ana: llamada de Julia (644 89 73 39 / 644 876 893): en relación al cumplimiento de medida de Servicios a la Comunidad, está muy contenta, pues le han dicho que en lugar de 2h/día durante 16 días, puede hacer 4 h/día durante 8 días. *Patricia, Ed.-Futuex les ha acompañado y la semana que viene les acompañará a hablar con la TS de los SSASB de su pueblo. Tiene que comenzar la medida el 28 de agosto. Aún no sabe donde. Es posible que en el Ayto. de su pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-07-31','Ana: Recibimos la factura de taxi: 264,96 €. ·································· Llamada de Julia: pregunta si se le puede dar un extra para hacer un regalo a su madre por el cumpleaños. *Le explico que dado el gasto elevado en taxis para acudir a citas en los Juzgados durante los dos últimos meses, no puede permitirse más gastos extraordinaros por el momento. *Dice entenderlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='GUERA'and apellido2='CASTAÑEDA'),'2023-07-31','AMALIA : envio email a Julio para ver si podemos hacernos de los cdo. defunción de sus padres para pedir PFHC +P ORFANDAD .Actualmente tiene PNC y desde el CSS Merida nos indican que es necesario aumentar ingresos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-06-15','Ana: Recibimos NOTIFICACIÓN del IMAS, RESUELVE otorgar una puntuación de 43 puntos, quedando en LISTA DE ESPERA para recibir el TAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-07-31','Ana: En relación a la RESOLUCIÓN del INSS comunicando la BAJA de la PFHC por "causa TUTELA", con fecha de efectos: 01/10/2023. ································ Llamo al INSS (927 620 828): han recibido nuevo expediente con nueva sentencia judicial a nombre de Jose Emilio Parra Díaz. Entendemos que es el hermano. En este caso todo estaría bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-07-31','miguel, me llama por teléfono la hermana de la curatelada, Ana Isabel Lozano, insistiendo que tenemos que hacer un papel de los coches son de ella porque se lo ha dicho su abogado. Envío email a la parte económica y la social: Buenas tardes, retomamos el asunto de los coches. Me ha llamado la hermana tlfno 681166315 Ana Isabel Lozano por el tema de los coches. Insistente que su abogado le ha dicho que tenemos que firmarle un documento que acredite que los coches son uno suyo y el otro en cuanto se pague también. Parte económica: necesitamos nos acreditéis qué ingresos ha ido haciendo la hermana y desde cuándo Parte social: Al ser un acuerdo al que llegaron las hermanas y desconocemos no vamos a firmar nada. En todo caso, si acredita los pagos que comenta, haríamos un documento a firmar por la curatelada indicando que los coches son de la hermana Ana Isabel Lozano y lógicamente dicho documento recogerá que los gastos lo asuma dicha hermana. Esto suena a que se han estado acogiendo al beneficio de la minusvalía. Si os llama o me llama debemos decirle: 1.-Que estamos viendo los pagos que ha realizado (si son anteriores a la aceptación del cargo de curadores, tendrá que acreditarlos ella) 2.-Si todo estuviera correcto prepararíamos un documento de transmisión (cesión, compraventa…hay que estudiarlo) que sería firmado por la curatelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-05-16','miguel, mi contestación al email de Amalia del día 8, con copia a parte social y económica: Buenos días, hace falta nos remita la documentación del vehículo y la del préstamo que firmó. Desconozco todo este asunto con lo que necesitaría saber también desde la parte económica todo lo que esté relacionado con la compra, mantenimiento y préstamos del vehículo. ------------------------------------------------------------ Contestación de Amalia: Buenas, de momento la hermana está averiguando , vamos a esperar a ver qué soluciona ella. ------------------------------------------ Envío email a Oscar: Hola Oscar, a ver si puedes averiguar viendo los movimiento de cuenta de la tutelada, qué gastos tiene que esté relacionado con el vehículo (compra, mantenimiento, seguros, préstamo) ------------------------------------------------------------ email de Amalia: Este inventario lo lleva Iciar (le pongo en copia por si tiene que decir algo). Aún no tenemos acceso online a su cuenta. Te mando los movimientos que ha pedido','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-06-13','miguel, email de Iciar a Angel y a mi: Por otra parte, tiene otro vehículo a su nombre que ya está pagado completamente y que utiliza y se encarga de todos sus pagos el suegro de la hermana, Carmelo Najarro Becerra 08790238-Y, sería cuestión de cambiar la titularidad a nombre del suegro de la hermana. También solicita un escrito en el que exprese su consentimiento. Datos: Ford Focus 1.6 Sedán 1205 BGW. Os adjunto documento que nos envió la hermana firmado por Antonia para que echéis un vistazo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-07-31','miguel, recibo email de Amalia con la decisión de éste de vender mediante documento de compromiso firmado. Buenas , os paso la decisión que firma Damián . Alberto veía mejor la opción de vender y es la que él también solicita . Supongo que ahora desde la S. jurídica se tendría que proceder a solicitar autorización de venta . Se deja aparcado el tema de reformar el piso para alquilar . Cómo lo veis ? Por mi parte me parece buena opción, hacer seguimiento de un alquiler en Málaga no es abordable desde la CTAEX . Vender y luego ya veremos si compra en Mérida o se le deja ahorrado , que es lo que considero mejor . ------------------------------------------------------ recibo email de la prima Alicia y la contesto que la factura del cerrajero la remita a email ctutelar: Muy buenas, comparto totalmente la dificultad de llegar a decisiones con Damian. En espera de que la Comisión decida lo que le parezca oportuno, me gustaría recibir el coste de la cerradura que como le comenté en anterior correo, he cambiado para prevenir nuevas okupaciones. Trataré de enviarle la factura a la mayor brevedad si es ese el procedimiento que debo seguir. Espero sus noticias ------------------------------------------------------- Contesto a Amalia-parte social y parte económica: Perfecto. Pues si estais de acuerdo lo ponemos en marcha. Por otro lado os adjunto email debajo que he recibido de su prima Alicia. Ya le he contestado que envíe la factura del cerrajero la remita al email de ctutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2023-07-31','Ana: Correo de Pilar Cortijo, Residencia Santiago Apóstol - Navezuelas (pilarcortcer@gmail.com): "Buenas tardes, nos informan del hospital que Juan José ya está en fase terminal, ya los hemos informado del número de póliza de decesos. No sé si tenemos que hacer algún otro trámite, un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-07-31','Ana: Correo de Sara García Martín, TS Residencial Banium, Baños de Montemayor (TrabajadoraSocialBanium@hotmail.com): envía declaración jurada de acompañamientos a citas médicas. También informa "En 30 días, volverán a citar a Concepción Barbero para una radiografía y revisión en el Hospital Virgen del Puerto. No os puedo decir el importe exacto. Aunque sepa el horario de consulta y de recogida de la ambulancia, no sé cuánto van a tardar en atender a nuestra usuaria en el Hospital." ·············· Le solicito nos envíe los informe médicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='COLIN'and apellido2='PEREZ'),'2023-08-01','-Amalia : les paso a los jurídicos una denuncia de un trabajador del CSS por hurto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2023-08-01','Ana: En relación al correo de Alberto, Jefe Secc. Ecca., sobre las múltiples peticiones de Jesús, sus ingresos, gastos y saldo, indicando que él no subiría la asignación y aceptaría como mucho un solo gasto extra para lo que queda de año, respondo: "Es cierto que son muchas cosas las que solicita, y como él mismo dice, son cosas sensatas (nada descabellado), pero demasiado gastos para él teniendo en cuenta los ingresos con los que cuenta. Si bien, al no adjuntar las facturas/presupuestos no puedo ver los gastos que supone cada petición. Entiendo perfectamente lo que dices de que aún es joven y que no veas conveniente hacer gastos excesivos o dejar de ahorrar la media anual que viene ahorrando. Pero por otra parte, desde la CTAEx hay cuestiones en las que tenemos que trabajar y por las que tenemos que velar, como son, además de sus necesidades básicas, por supuesto, la buena relación con los familiares cuando ésta sea posible, significativa y positiva, así como el desarrollo personal de las personas por las que trabajamos. Por ello, veo necesario aceptar al menos algunas de sus peticiones: - Viaje en noviembre a visitar a su padre (No sé qué gasto supone) - Tampoco sé ahora mismo desde cuándo no se le da dinero para ropa, cuestión que a todos nos hace falta comprar de vez en cuando. ¿Podríamos mirar, y si no todo lo que pide, que no es mucho, darle una parte? - La factura relativa al gato, tampoco sé de cuánto es, pero el amigo que le ha prestado el dinero siempre está ahí para ayudarle y colaborar, al menos desde que yo estoy aquí trabajando y creo que sería de recibo devolvérselo. - Con respecto a la subida de asignación, tod@s conocemos el incremento de precios que ha experimentado todo… pide una subida razonable de 25€ quincenales, que si no es asumible, me pregunto si al menos se le pudiera subir 25€/mes. ¿Cómo quedarían sus cuenta? - En cuanto al resto de gastos como el del ordenador, habrá que decirle que en este momento no es asumible y que tendrá que esperar a más adelante, pues necesario que mantenga un mínimo nivel de ahorro. Y gastos como el de la farmacia y la sartén que tendrá que intentar abonarlos de su asignación, pues como decimos, es necesario seguir ahorrando algo de dinero para cuando surja una necesidad imperiosa que tenga que abonar sí o sí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2023-08-01','Ana: Correo de Pilar Cortijo, Residencia Santiago Apóstol - Navezuelas (pilarcortcer@gmail.com): "ya ha fallecido Juan Jose Horneros" ·············· Lo comunico al ctutelar@','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-08-01','Ana: correo de Toni-Futuex: "Hemos hablado con Beatriz de CRR, conocen el programa por otros tutelados y se ha puesto en contacto, para la entrevista previa que realizan. Hemos considerado si os parece bien, ya que cuadraba en agenda para acudir con el, que fuera este viernes, y gestionarle un taxi, desde Alcuescar a Plasencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-08-01','Ana: Correo del PAF (programafamilia@tajosalor.es): "Nos ha pedido de nuevo ir a CEDEX. Le hemos explicado los pasos que tiene que dar y va a pedir cita a su médico de familia. Nosotras le acompañaremos cuando tenga la cita."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2023-08-01','Ana: Correo de Sheila, Directora del CRR-CC (crr@grupociudadjardin.com): "en relación a la persona usuaria del CRR de Cáceres Juan Mario San Román Blasco y con motivo de la actividad del CRR de Cáceres, excursión anual; solicitamos la autorización de retirada del banco del importe de la misma 400€, para el pago solicitado por parte de la agencia de viajes. Dicha excursión se realizará en el mes de Septiembre (18-22)." ····················· Confirmo a Sheila y a la Secc. Ecca. el OK por parte de la Secc. Soc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2023-08-02','Buenos días Amalia, soy Lola trabajadora social del Centro Penitenciario de Huelva, Rafael Faus Lemus esta en mi módulo, me dice que ponga en contacto contigo para que le envíes más dinero, necesita ama comprarse una serie de cosas que le hace falta. Te envió instancia del interno solicitándolo. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-08-02','Ana: Reenvío a Alberto correo de Toni-Futuex, con las siguientes aclaraciones: "Se le ha concedido un total de 2 h de servicio de ayuda a domicilio del IMAS (Ayto. de Cáceres), el coste no es significativo en absoluto 0,75 €/h. Pero sí que hay que comprar los productos de limpieza. Por lo que en mí opinión, sí que hay que reintegrarle el gasto del tique que adjunta Toni y aumentárselo en la diferencia hasta el total que habían pedido a tal fin. Aún estamos pendiente de que envíen presupuesto de reparación de lavadora (había pedido comprar una porque dejó de funcionar la que tenía, pero es posible que tenga arreglo y sea mucho más económico que comprar otra. Por otra parte, se dio de baja el contrato de telefonía y se pasó a prepago (lo podéis comprobar, por si acaso se lo sigan pasando o algo). Sería bueno aumentarle un poco la asignación en este concepto. Además como ves, más muy justo estos días para alimentos (y no por mal uso del dinero)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-08-02','miguel, tras conversación con Ana Isabel, 681166315 (hermana de la curatelada asistencial)quedamos en que: 1.-Pediré información del préstamo personal del Bbva para saber las condiciones del mismo, saldo pendiente a fecha actual y si se debe o no algo. 2.-Prepararé un documento para remitirlo a la hermana para que ésta lo firme. De los coches: 1.-Ford Focus que está pagado, escrito a firmar por la curatelada reconociendo que el vehículo es de la hermana 2.-Dacia documento a firmar por la curatelada indicando que aunque el saldo pendiente del préstamo es de unos 9.000€, el mismo lo está abonando la hermana Ana Isabel, y una vez que lo finalice, será ésta la que se lo quede. Envío email a la parte económica y social sobre la conversación con la hermana Ana Isabel. ------------------------------------------------------------ Envío email a bbva a emails que me da la hermana Ana Isabel: cacfinan@bbva.com y esperanza.gonzalez@bbva.com. (me facilita además tle´fono de bbva 900108587 e email de Banca Pueyo servicicatncioncliente@bancapueyo.es: Buenos días, en relación a una persona sometida a curatela y cuyo testimonio de firmeza de auto de medidas de apoyo conforme la actual ley 8/21, junto al testimonio de aceptación del cargo por esta Comisión Tutelar de Adultos de la Junta de Extremadura se adjuntan, solicito nos remitan las condiciones del préstamo personal del Bbva 01828693830000028778 (principal, deuda pendiente y si se deben o no más recibos, así como los titulares y participes del mismo) Si existiese algún otro préstamo ruego me lo comuniquen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-08-02','TERESA TOD@S: TENEMOS CONOCIMIENTO DE QUE EL TUTELADO ESTÁ INTENTANDO SACAR DINERO DE SU CCC EN IBERCAJA - SALDO HOY 14.000 € APROX.. PARA ELLO CUENTA CON LA AYUDA DE UN TAL MIGUEL ANGEL DELGADO (VER INFORME SOCIAL), AL CUAL CONOCIÓ EN LA CARCEL. SE ADJUNTA TAMBIÉN LA FALSIFICACIÓN DE FIRMA DEL DIRECTOR GERENTE QUE HA PRESENTADO PARA SACAR DINERO SIN AUTORIZACIÓN. CONCLUSIÓN: VA A SER MUY DIFÍCIL QUE ESTA PERSONA NO CONSIGA SACAR DINERO SIN AUTRIZACIÓN YA QUE CUANTA CON AYUDA DE ESTA OTRA PERSONA Y ADEMÁS CUENTA CON VEHÍCULO. AREA JURÍDICA: COMUNICAMOS ESTO AL JUZGADO URGENTEMENTE??? + SE OS OCURRE ALGUNA CUESTIÓN MÁS??? + IBERCAJA TIENE CONOCIMIENTO PERO TARDE O TEMPRANO VAN A DAR CON ALGUIEN NUEVO QUE NO CAIGA EN QUE SE TRATA DE UN ENGAÑOY EL DAÑO ESTARÁ HECHO MARIA: XFAVOR, HABLAS URGENTEMENTE CON IBERCAJA Y BUSCAMOS UNA OPCIÓN (FORMALIZACIÓN DE UN DEPÓSITO O FONDO (ALGO QUE PODAMOS REVERTIR LO MÁS RÁPIDO POSIBLE X SI HICIESE FALTA ESE DINERO))---SI NO PUEDE SER EN IBERCAJA, EN UNICAJA --- TRASPASARÍAMOS UN MÍNIMO DE 13.000€ (LO HABLAMOS ANTES TU Y YO) --- HABLA TB CON ICIAR XQUE CREO QUE YA HEMOS HECHO ALGO PARECIDO ANTES CON OTROS TUTELADOS. ICIAR: HA ABIERTO UNA CCC EN B.SANTANDER SIN AUTORIZACIÓN...HAY QUE ENTRAR EN ESA CCC (VER INFORME SOCIAL) ---','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-08-02','Maite: desde Mentalia Arévalo han solicitado salida de José María a su domicilio. Les hemos manifestado nuestras reservas dada la tayectoria de José María, y de su entorno familiar. Han enviado un informe sobre su evolución, y ponen de manifiesto lo beneficioso que sería para él poder ir a casa. Hemos hablado con la psicóloga ( Viriginia)y nos ha dicho que está muy estable, sin presentar conductas disruptivas y tomando consciencia de su trayectoria, con una mejora en su gestión de la frustración. Cumple las normas en todo momento, participa en todas las actividades y terapias. Tiene un grupo de amigos con los que se lleva muy bien. Manifiesta querer ir a su casa y se muestra muy ilusionado con la idea. Hemos acordado con la psicóloga que la estancia será de 4 días , no de 7 como proponían incialmente. Y en días laborales, para que se pueda hacer seguimiento de la estancia a través de FUTUEX. La trabjadora social enviará presupuesto del taxi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-08-11','Ana: Conversación con Pedro Garvi, Coord. CES - Caritas (673 303 677): anoche Francisco, por primera vez después de muchos días pernoctó en el CES. ··········· Tiene pendiente elaborar informe para enviármelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-08-02','Ana: Conversación con Pedro Garvi, Coord. CES - Caritas (673 303 677): Miguel Ángel ha acudido a su despacho, quiere hablar conmigo. Me lo pasa. Vuelve a preguntar sobre todas prestaciones de las que hablamos ayer. Intento que quede aún más claro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-08-02','Ana: Ana Benavente, TS ESM-Plas., me remite documento de TMG, en el mismo se indica: "Como se ha pactado con el CRR, si consigue estabilidad de 6 meses sin realizar intentos o conductas autolesivas, se gestionará su paso a piso supervisado" ······· "Mientras persistan los actos auto o heteroagresivos (al menos cercanía en el tiempo de un mes), y en aras de salvaguardar su integridad física y evitar la exposición a situaciones que motivan nuevas conductas autolesivas, se propondrá a través de la CTAEx la limitación de los viajes a su localidad de origen."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-08-02','Ana: Envío a Cristina, Ed. Vera (educadorasocial@asociacionvera.com) la AUTORIZACIÓN PARA VACACIONES en Conil de la Fra. en el mes de octubre junto con el compromiso de pago, debidamente firmados y sellados por el D. Gerente.','2');
