insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-08-03','Ana: En relación a las distintas llamadas y correos-e de Isabel, comunicando que el Psiquiatra considera que puede ir al pueblo y solicitando ir del 14 - 16 de agosto, respondo con un mail: "Ya he visto el documento que ha enviado el Psiquiatra. Aún tengo que hablarlo con la Jefa de Sección y las Profesionales del CRR, a quienes pongo en copia para su conocimiento. Así pues, te pido que tengas paciencia." ···························································· Llamo a Paula, TO del CRR-Plas (','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-08-03','Ana: En relación al correo de Alberto Árias Bueso, T.O. EVD - Brozas(alberto.arias@salud-juntaex.es): "El señor ocupa plaza municipal en la residencia de Alcántara. Ha obtenido grado 1 y la plaza no está subvencionada por el SEPAD por lo que no se puede hacer mantenimiento. Debemos cerrarlo con una no aprobación PIA por lo que os remito por correo certificado aceptación PIA de ayuda a domicilio teóricamente para marcar que no la acepta", envío a REGISTRO (oac.merida.san@juntaex.es) la NO ACEPTACIÓN del PIA pendiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-04-26','Ana: Correo de Juan Manuel Cañas Lozano (jmcl1966@hotmail.com) al ctutelar@: "Buenos días Ana, soy Juan Manuel Cañas, hermano de José Blas Cañas. Sólo escribía para informar de un par de novedades. Me comentaste que ibas a meter a José en algún tipo de programa de seguimiento - no recuerdo exactamente el nombre - y la semana pasada ya recibió la visita de una trabajadora, Virginia, el primer contacto fue bastante positivo, tratará de estar encima de él para que su comportamiento en casa mejore. Por otro lado, justo uno o dos días después de hablar por teléfono contigo recibimos una llamada de Mérida que nos asustó, ofreciendo plaza a Jose en un centro residencial en Mérida. El asunto es que 2-3 años antes de iniciarse este proceso judicial por el cual la comisión tutelar se ha hecho cargo de Jose, nuestra madre ya había solicitado por vía administrativa al SEPAD plaza en residencia para José - sabiendo que las cosas de palacio... - y - casualidades de la vida - justo ahora quedaba plaza libre, hablé tanto con la trabajadora del SEPAD como con la directora del centro de Mérida, les puse al día y les hablé de la situación personal de José y entendieron perfectamente que buscáramos solución en Cáceres, pero quería informarte. Sigo al habla con el centro Down viendo la viabilidad de un piso compartido, surgió la posibilidad de que, en vez de compartirlo con un grupo más amplio, sea simplemente con su novia Fátima, cuyo grado de independencia es bastante similar al de José."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-05-16','Ana: Óscar me reenvía, correo de Juan Manuel, hermano de José Blas (jmcl1966@hotmail.com): "Buenos días, el viernes sacamos la cantidad acordada pero no vamos a volver a sacar dinero de esta cuenta ni vamos a presentar facturas de ningún gasto extra. Cuando nosotros iniciamos este proceso lo hicimos para conseguir una solución "residencial" para José Blas, no para que nos dieran dinero. Cuando Virginia nos visitó y nos habló de que "iba a pedir que a Jose le dieran un dinero para ayudar con su manutención" nuestra madre al momento dijo que eso no era lo que ella necesitaba, pero yo le dije que adelante porque interpreté que se refería a que iba a solicitar una ayuda económica y teniendo en cuenta que mi madre cobra una pensión modesta, no le viene mal. Pero, salvo que estéis metiendo dinero en la cuenta de José - y no es el caso ¿no? - lo único que estamos haciendo es quitar dinero de la cuenta de Jose y eso no tiene sentido. Ni mi madre ni yo queremos eso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-08-03','Ana: Envío correo a Toni-Futuex, solicitando Informe de seguimiento/situación acutal. ······························ Toni envía correo con la información de las últimas visitas. *Guardo en PDF en el expte. digital. ···· Tanto la madre como el hermano, han cambiado de opinión y consideran que José Blas debería ingresar en un centro, después de haber rechazado la plaza en AP-7. ················ El dinero para manutención no lo han estado sacando, por decisión de la propia madre, que decía que no quería cobrarle a su hijo. Pero ahora se lo ha pensado mejor, no sólo quire retirarlo sino que quieres que se le aumente a 300 - 400 €, pues tamibé ha comprado ropa y José Blas tiene otra serie de gastos que cubre ella. ······················ La educadora ha abordado ciertas cuestiones relacionadas con la convivencia y con su responsabiliadades (tanto asistencia a CO como colaboracion con tareas en hogar) que parece haber aceptado: Limpieza de su cuarto, hacer su cama, tirar la basura y recoger la cocina tras la cena. Ha habido a avances. ··· Con respecto a CO, como cierra en agosto, el acuerdo es no tener faltas de asistencia a partir de septiembre. ······················· En relación al ingreso en C. Residencial: "tras argumentarle todos estos beneficios expresa que se lo va a pensar y que le gustaría estar en la residencia de NOVAFORMA." ············································ María, Secc. Ecca, comprueba con los movimientos bancarios que la última vez que retiraron la asignación fue el mes de mayo. NO han retirado ni en junio ni julio. Agosto, de momento, tampoco. ·······················','2');
