insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-08-03','Ana: Llamo a la Residencia de Mayores de Riolobos (927 45 30 15): el teléfono no da señal. ··········· Envío correo a Ana Montaña Álamo, Gerente de las Res. de Riolobos (alamoseras@gmail.com): "sólo quería interesarme por JOSÉ MANUEL MORENO CARLOS, preguntar qué tal ha ido su proceso de adaptación y cómo se encuentra a día de hoy."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-07-03','Ana: Correo de Ana Montaña Álamo, Gerente de las Res. de Riolobos (alamoseras@gmail.com): "me pongo en contacto contigo, para confirmar el ingreso en la Residencia de Riolobos de José Manuel Moreno Carlos con fecha de mañana 4 de Julio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-06-30','Ana: Correo de Amalia, CTAEx, a Paula - CRR: "Te escribo a petición de mi compañera Ana para comentarte sobre Isabel Cano . Ha hablado con ella y con su madre. Al parecer , Isabel lo ha tomado fatal y la madre ha respondido con una invitación de 2 días a un hostal en Plasencia para que pernocte con ella por su cumpleaños ( días 13 y 14 ) , cómo valoráis esta salida ?" ············································································· Respuesta de Paula: "Respecto a la pregunta, acabamos de recibir el acta de la subcomisión y hoy no está Carolina que es la actual directora y psicóloga de Isa para poder revisarla mas detalladamente, aunque creo que la respuesta está en el propio acta y en la decisión que se tomó en ese momento. Si queréis que lo hablemos de forma más extensa, podemos hacerlo el martes que regresa Carol y ya vemos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2023-08-03','Amalia, ya he modificado la transferencia permanente de José María, a partir del próximo mes 400 €, y le he hecho en agosto una transferencia puntual de 160 € pues ya había recibido los 240 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSE'and edp.apellido1='MOLINA'and apellido2='SALAZAR'),'2023-08-03','Me comenta la doctora que le van a proponer a M.ª José Molina Salazar anticonceptivos, ya que mantiene una relación muy estrecha con otro paciente. Se trataría de inyecciones trimestrales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-08-03','Ana: Correo de Miguel, A. Jurídico: "hasta el 18-9-23 no será firme la sentencia de 18-7-23 de Joaquina Mayoral, al ser el mes de Agosto inhábil a los efectos del cómputo de plazos" ······················· Lo reenvío a Anabel, TS SSASB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-08-03','Ana: Correo de Sheila, Directora CRR, con INCIDENCIA: "Informar de que la persona usuaria Juan José Bergantiño Gómez ha acudido al centro en la mañana de hoy dos veces al centro, sabiendo que tiene una expulsión temporal. En ambas ocasiones, tanto Cristina como yo hemos apreciado evidentes signos de consumo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2023-08-03','Muy buenas, Este correo es a modo informativo, ya que realmente no deseamos tocar nada de la comisión, pero porque conozcáis la situación económica en caso de ser necesario. Llevamos meses trabajando con Sonia su gran problemática con la alteración del sueño, siendo en gran medida permisivos por la comprensión y empatía que alcanzamos tener sobre sus limitaciones, pero ésta ya hace caso omiso de las indicaciones del turno de noche (pasando toda la noche en el patio, fumando, gritando, con llamadas a altas horas de la madrugada, entrando en habitaciones ajenas gritando, despertando, pidiendo café…), por lo que se han tomado las siguientes medidas para poder conciliar el sueño de los demás usuarios: de volver a faltar a las normas de sueño y convivencia, al día siguiente 1) su asignación diaria pasará de ser de 9 euros a 4 ; y 2) la noche siguiente tendrá que pasarla en el hostal Herederos y costeárselo con su propio dinero, pudiendo hacer todas las comidas en el centro para evitar mayor gastos. Por el día su habitación permanecerá cerrada para evitar que se acueste y regular en cierta medida la higiene del sueño. Hemos calculado y le daría para 3 noches. En principio ESPEREMOS no llegar a ello, pero entre el calor y la sintomatología que se acentúa en los mismos durante estas fechas, el sueño es imprescindible y necesitamos mirar por el descanso de todos, estando algunos de ellos sensibles a desajustes psicosomáticos. Únicamente para que estéis informadas y sepáis de ello si hay mayor gasto de la cuenta. Un saludo. CaserResidencialC_P_RGB','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2023-08-03','Muy buenas, Este correo es a modo informativo, ya que realmente no deseamos tocar nada de la comisión, pero porque conozcáis la situación económica en caso de ser necesario. Llevamos meses trabajando con Sonia su gran problemática con la alteración del sueño, siendo en gran medida permisivos por la comprensión y empatía que alcanzamos tener sobre sus limitaciones, pero ésta ya hace caso omiso de las indicaciones del turno de noche (pasando toda la noche en el patio, fumando, gritando, con llamadas a altas horas de la madrugada, entrando en habitaciones ajenas gritando, despertando, pidiendo café…), por lo que se han tomado las siguientes medidas para poder conciliar el sueño de los demás usuarios: de volver a faltar a las normas de sueño y convivencia, al día siguiente 1) su asignación diaria pasará de ser de 9 euros a 4 ; y 2) la noche siguiente tendrá que pasarla en el hostal Herederos y costeárselo con su propio dinero, pudiendo hacer todas las comidas en el centro para evitar mayor gastos. Por el día su habitación permanecerá cerrada para evitar que se acueste y regular en cierta medida la higiene del sueño. Hemos calculado y le daría para 3 noches. En principio ESPEREMOS no llegar a ello, pero entre el calor y la sintomatología que se acentúa en los mismos durante estas fechas, el sueño es imprescindible y necesitamos mirar por el descanso de todos, estando algunos de ellos sensibles a desajustes psicosomáticos. Únicamente para que estéis informadas y sepáis de ello si hay mayor gasto de la cuenta. Un saludo.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-08-04','Ana: Correo de Ceferino: "quisiera ahí a la discoteca masía que está en Castellón y pasar un día allí y venirme al día siguiente solamente ir a la fiesta y ver a los DJs ya que nunca los he visto en vivo y en directo espero tu respuesta" ································ Mi respuesta: "Es una cuestión que habría que valorar con el equipo técnico del CRR y con la Jefa de Sección de la Comisión Tutelar. Pongo en copia a las compañeras para que estén al corriente y puedan valorarlo ante de hablarlo entre las dos partes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-08-04','TERESA Hola Tere, la trabajadora ha ido al domicilio de José María con Esperanza(FUTUEX ) para conocerlo y que le explicará lo que tenía que hacer. Me ha llamado para ver si es posible que pueda ir una empresa de limpieza y limpie sobre todo el cuarto de baño, porque hay una suciedad extrema, acumulada de meses... Es verdad que las demás dependencias del piso también están muy sucias y desordenadas según ella , pero ella hace hincapié en el cuarto de baño. Tú me dices si es posible o no, espero tu respuesta. CONTACTO CON LA EMPRESA LIMPIEZA EXTREMA PARA QUE SE CORDINE CON FUTUEX Y VAYAN A ELBABORAR PRESUPUESTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-08-04','Ana: Envío correo a Inmaculada Gómez, Psicóloga del ECA-CC (inmaculada.gomezm@salud-juntaex.es): "Mi nombre es Ana, soy Trabajadora Social del Gabinete Técnico de la Comisión Tutelar de Adultos, me pongo en contacto contigo en relación a MIGUEL ÁNGEL RAMOS ANDRÉS, cuyo cargo de CURATELA REPRESENTATIVA ejerce la Comisión Tutelar de Adultos de la Junta de Extremadura. Con motivo de la SOLICITUD DE INGRESO EN CRR, queríamos pedirle un INFORME DE ASISTENCIA Y TRATAMIENTO EN EL EQUIPO DE CONDUCTAS ADICTIVAS relativo a Miguel Ángel, para poder aportarlo en la Comisión de Valoración y lo tengan en cuenta para poder darle plaza en recurso adecuado a su patología mental. Adjunto Testimonio de Aceptación del Cargo. Agradecería que nos lo remitieras a la mayor brevedad tanto a Pilar Martín, compañera del Equipo de Salud Mental de Cáceres (pilar.martinp@salud-juntaex.es), como a mí. Ante cualquier cuestión, no dudes en contactar."','2');
