insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-07-31','Ana: Datos de contacto Residencia Grupo Asoma de Cedillo: 927 590 145. Gema - Directora = 639 694 905 / gemamg.asoma@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-08-04','Ana: Envío a registro (oac.merida.san@juntaex.es): "En relación a D. JULIÁN RAMÓN CIVANTOS FERNÁNDEZ, cuyo cargo ejerce la Comisión Tutelar de Adultos de Extremadura, remito la siguiente documentación: - Aceptación PIA Servicio de Atención Residencial - Aceptación PIA – Prestación Económica Vinculada al Servicio de Atención Residencial. - Alta de Terceros Que ser deberá remitir por registro a: S.E.P.A.D. GERENCIA TERRITORIAL DE CÁCERES Sección de Dependencia I Pza. Hernán Cortés, 1 C.P. 10001 CÁCERES Código de registro SIREX: A11030403"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-08-04','-Amalia : Solicitaré VPP . En archivo adjunto se envía la solicitud facilitada por la Oficina Comarcal de Vivienda de Badajoz Servicio Territorial Consejería de Fomento Gobierno de Extremadura para poder acceder a viviendas de alquiler social en Badajoz. Se incluyen números de las trabajadoras sociales por si existe alguna duda con la documentación a entregar 924 01 06 09 / 924 01 06 49. La solicitud cumplimentada junto a toda la documentación que piden hay que enviarla por registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-08-04','Ana: En relación al correo de Leyre, TS de la RR.MM.: "ME COMUNICA SU SOBRINA CARMEN QUE LE ESTÁN PASANDO RECIBOS DE AGUA DE APROXIMADAMENTE 60 EUROS , ME DICE QUE ME PONGA EN CONTACTO CON VOSOTROS PARA QUE LO DEIS DE BAJA, YO SE QUE EL RECIBO DE LA LUZ Y TELEFONO SE DIO DE BAJA, PERO NO SE SI DIO EL DEL AGUA, POR SI LO PODEÍS VER." ···························· Respondo: "No sé si mis compañeras llegaron a darte respuesta sobre esto durante mis vacaciones, así que, por si acaso te adjunto el documento. La cuantía no es la que dice la sobrina, hay dos meses que ha debido haber consumo en el domicilio porque la cuantía es más alta, pero el resto está en torno a 20 €. No obstante, les solicito, que en cuanto sea posible, lo den de baja. Lo mismo lo intentaron ya, pero no sé por qué con este suministro siempre suele haber más dificultades."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-08-04','Ana: Con respecto al correo del PAF, Aitor solicita dinero para comprar el abono de los Toros y pregunto cómo hacer para comprar ropa. ············· Correo de Tere, TS, CTAEx: "Hemos pensado en hacerle una recarga por ese importe y que saque le dinero y compre el abono. Para asegurarnos que se lo gasta en el bono y no en otra cosa podrías acompañarle a sacar el dinero y comprar le bono? Hoy toca hacerle la recarga de los 20€ semanales, si os parece bien le hacemos recarga de 60€? Con respecto a la compra de la ropa creo que lo más fácil es hacer lo mismo una recarga extra por el importe que necesite para comprar la ropa y que luego aporte los tikets." ····················· Respuesta PAF: "nos parece perfecto. Nosotros le acompañaremos luego. Aprovecho para deciros que la próxima semana estaremos de vacaciones, nos incorporamos el día 16. Nos hemos coordinado con la compañera de FUTUEX para que vaya ella a hacer la compra semanal con Aitor y os envíe el ticket." ······································································· Nuevo correo del PAF: "He acompañado a Aitor a sacarlo, cuesta 26€ y otros 8 del novillo que tiene que sacar en ventanilla el mismo día. Le he comentado lo de la ropa pero le he dicho que ya lo vemos a la vuelta de mis vacaciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2022-11-23','-Amalia : Derivado a Ctro. penitenciario de Huelva desde el 23/11/2022. Teléfono de peculio Huelva : 959211670 Nº Cuenta de peculio: ES48-0049-1969-1120-1000-4171','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-08-04','Ana: Correo de Miguel, A. Jurídico: "fue solicitado el testimonio de firmeza al juzgado el día 17-7-23, y el día 19-7-23 fue aceptada esa solicitud. He llamado pero al ser Agosto inhábil para los procedimientos civiles no me lo coge nadie. Hasta que no llegue el testimonio de firmeza no podemos dar por hecho que hemos dejado de ejercer el cargo de curadores representativos. Y seguramente hasta septiembre no nos lo envíen. Si la familia tiene cualquier duda que intenten hablar con el juzgado…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2023-08-03','Ana: correo de Alberto, Jefe Secc. Ecca.: "ASIGNACIÓN: LO QUE PIDE NO ES RAZONABLE (CONFORME A SUS INGRESOS)---AUNQUE TENGA UNA ASIGNACIÓN DE 250 €/MES YA SE LE ESTÁ DANDO UNA MEDIA DE 17 € MÁS CADA MES (267 €/MES DE MEDIA) OTROS GASTOS: NO PUEDE ASUMIRLOS SIN RENUNCIAR A ALGO: SI NO RENUNCIA A ALQUILER, O GIMNASIO, O TELÉFONO O AYUDA A DOMICILIO, NO PUEDE ASUMIR NUEVOS GASTOS ---- LE LASTRA MUCHO EL TRATAMIENTO DENTAL QUE PROPUSO Y SE ACEPTÓ (105 €/MES HASTA 2025) + AUNQUE EL SE PORTE DE FORMA CORRECTA, CUALQUIER DESVIACIÓN (INCREMENTO CONSUMOS, TELEFONÍA, SALUD (GAFAS, ETC), SUPONDRÍA QUE ESE AÑO EL BALANCE SERÍA NEGATIVO. ROPA: ICIAR LE ACABA DE PASAR 150 € PARA ROPA. MASCOTAS: SE HA CONVERTIDO EN UN ARTÍCULO QUE QUIZÁS NO TODO EL MUNDO PUEDA TENER...PRIMERO EL Y DESPUÉS LOS GATOS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2023-08-04','Buenas , Rafael solicita un extra para varias cosas , un total de 900€ . Creo que no se le ha dado extra hace tiempo . Valorarlo y enviarle a peculio lo que se pueda . No sé cómo anda de ahorros. De todo ello pediré que se envíen las facturas justificativas del economato , está en Ctro. Penitenciario de Huelva. Os paso contacto de peculio : Teléfono de peculio : 959211670 Nº Cuenta de peculio: ES48-0049-1969-1120-1000-4171 Actualmente se le pasan 75€ a la semana .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-04','Ana: Envío correo a Ana, TS y Mª Victoria, Psiquiatra - ESM Plas.: "Me pongo en contacto con vosotras, para poner en vuestro conocimiento un nuevo incidente, relativo a ENRIQUE SANTOS GARCÍA-PUENTE, que consideramos grave, y a tener en cuenta también por vuestro equipo. Os reenvío directamente el correo del Veterinario de Salud Pública así como el Acta de la Inspección que realizaron. Por otra parte, ayer estuve hablando con Puerto, compañera del SSASB de Valdeobispo, me relató las distintas incidencias acaecidas con las Auxiliares del Servicio de Ayuda a Domicilio, no sé si sabéis, que acuden dos pues se niegan a ir solas, y con razón, por hecho como abrirles la puerta con el batín abierto, totalmente desnudo o haber encerrado a una de ellas en una habitación. Si sigue habiendo estos sucesos corre el riesgo de que se le suspenda el servicio. En cuanto al servicio de comidas, de momento sigue teniéndolo, pues al no haber podido realojar a todas las personas residentes, aún está abierta la residencia. Me avisarán en cuanto confirmen el cierre. Se procederá a aumentar la asignación en 45€ semanales para comida, pues el bar del pueblo no se compromete a prepararle comida a diario. Y de momento, no hemos encontrado ninguna empresa que haga el reparto a otras localidades. Si lo consideráis, podemos hablar de ello cuando os sea posible. He intentado contactar con Ana y no ha sido posible, entiendo que estará también ocupada. Pongo en copia a Puerto, para su conocimiento." ················································································ Envío correo a Toni-Futuex: "...En relación a ENRIQUE SANTOS GARCÍA PUENTE, dados los últimos incidentes tanto en el Servicio de Ayuda a Domicilio, así como con los Veterinarios de Salud Pública que acudieron ha realizar Inspección por motivo de haber mordido su perro a una vecina (los recibió desnudo, con un batín totalmente abiertos, no los dejaba pasar sin mascarilla y además les propinó una serie de amenazas. Todo con muy malas formas en el trato), os solicitamos, que en la medida de lo posible, INTENSIFIQUÉIS SU SEGUIMIENTO y, en cuanto os sea posible nos hagáis llegar Informe de la situación actualizada...", informo también sobre la subida de asignación cuando cierren la residencia y mientras no haya otra alternativa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-08-04','Ana: Correo de Gema Morato, Directora de la Res. Grupo Asoma (gemamg.asoma@gmail.com) aportando EXTRACTO ACREDITATIVO DE La liquidación del mes de julio ("nómina") según CONTRATO PREJUBILACION IBERDROLA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-08-04','Ana: en relación al correo de Leire Sanz, TS - Centro de Mayores Ciudad Jardín Cánovas (t.socialcanovas@grupociudadjardin.com): "Me pongo en contacto con vosotros, para informaros que Josefa Sánchez Díaz, hace actualmente vida silla de ruedas- sillón y que es incapaz de trasladarse a la sede judicial. Mi teléfono de contacto para la videollamada es el 676404867, si la videollamada es para este mes próximo, comunico que no estoy todos los días en el centro, por concretar y avisar el día y estar allí." ···················· Realizo consulta a Miguel, A. Jurídico, quien responde: "en relación a este procedimiento de revisión de medidas de apoyo, cuya citación es para el 5-10-23, Inés tiene puesto en el cuadro de citaciones judiciales en observaciones "Videoconferencia?? . Se comunica a Escalona. Se comunica a Ana por si se gestiona acompañamiento" Inés: Como la citación es en octubre avisa un mes antes a Ana de si el juzgado autoriza a que la tutelada pueda asistir vía videoconferencia por imposibilidad de trasladarse al juzgado, la hacer su vida diaria en silla de ruedas." ·························· Quedamos a la espera de lo que indiquen a Inés, Area Jurídica CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-08-04','Ana: comunico a Carlos y a Toni-Futuex, que entre el lunes y el viernes podrá retirar 17€ para productos el limpieza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-08-07','TERESA Buenas tardes, me pongo en contacto con usted para hacerle saber que a lo largo del fin de semana María Remedios Chaves Masero, ha hecho dos ingestas la primera de una pila y la segunda un tornillo de una silla, desde el hospital nos piden autorización para realizarle una endoscopia. pónganse en contacto con la mayor brevedad posible para que puedan autorizar dicha intervención. Ernesto Chaparro Coordinador residencia plena inclusión zafra. Número de contacto: 686-466-704','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-08-04','Ana: Envío correo al PAF: "¿Felisa no ha dicho este año si quiere ir a los toros? Lo digo por si fuera así, para que dé tiempo a valorarlo al Jefe de la Secc. Económica y si fuera viable que se le aumentara también la asignación en este concepto." ············· Respuesta del PAF: "Si, Felisi va a comprarlo pero cuenta hacerlo con el dinero de la asignación quincenal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-08-07','Ana: Correo del viernes de Sonia Bernabé - TS y Directora - Asindi (trabajosocial@asindi.e.telefonica.net): "Quería comentarte que me ha llamado la madre de los hermanos Justo y Roberto para decirme que ha tenido que denunciar a su marido y marcharse de casa. Actualmente está viviendo con un hijo suyo en una localidad diferente a la Roca de la Sierra. Estaba previsto que el próximo viernes, Justo y Roberto, viajaran a su domicilio familiar pero la madre me dice que ante esta situación necesita un poco de tiempo para "organizar su vida". Quiere buscar una vivienda,...entonces ya podrían ir los hijos. En resumen, anulamos, si estáis, de acuerdo el viaje previsto para el día 11 de agosto y en Septiembre vemos como está la situación. Aprovecharemos para que la psicóloga aborde este tema con ellos, sobre todo con Justo. Confírmame si consideras que es lo mejor." ···················· Mi respuesta: "Gracias por informar. Por supuesto estamos de acuerdo en que esta decisión es la mejor. En septiembre, según estén la situación, se valoran nuevas fechas para salida a domicilio. Ya nos vais diciendo qué tal lo toman. Estupendo que pueda intervenir con ellos al respecto la psicóloga."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-08-07','Ana: Correo del viernes de Sonia Bernabé - TS y Directora - Asindi (trabajosocial@asindi.e.telefonica.net): "Quería comentarte que me ha llamado la madre de los hermanos Justo y Roberto para decirme que ha tenido que denunciar a su marido y marcharse de casa. Actualmente está viviendo con un hijo suyo en una localidad diferente a la Roca de la Sierra. Estaba previsto que el próximo viernes, Justo y Roberto, viajaran a su domicilio familiar pero la madre me dice que ante esta situación necesita un poco de tiempo para "organizar su vida". Quiere buscar una vivienda,...entonces ya podrían ir los hijos. En resumen, anulamos, si estáis, de acuerdo el viaje previsto para el día 11 de agosto y en Septiembre vemos como está la situación. Aprovecharemos para que la psicóloga aborde este tema con ellos, sobre todo con Justo. Confírmame si consideras que es lo mejor." ···················· Mi respuesta: "Gracias por informar. Por supuesto estamos de acuerdo en que esta decisión es la mejor. En septiembre, según estén la situación, se valoran nuevas fechas para salida a domicilio. Ya nos vais diciendo qué tal lo toman. Estupendo que pueda intervenir con ellos al respecto la psicóloga."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-07','Ana: Correo-respuesta de Toni-Futuex, al correo del viernes: "Pues a ver como lo podemos hacer, porque estas conductas absolutamente deplorables, las tuvo con la educadora. Y por el momento estábamos dejando trascurrir un poco las semanas hasta volver a iniciar algún tipo de intervención, no con la persona que lo venia haciendo, que lógicamente se niega, sino con otra compañera. Fue a través del teléfono, que comenzó a mandarle mensajes, haciendo alusiones muy desafortunadas, sobre su valía, su físico y su persona. De un modo, insidio y repetido, ya que fueron bastante mensajes en sms, hasta que bloqueó su número. Sabemos que tiene una patología y también sabemos que esto sucede, por desgracia en ocasiones, pero para garantizar la seguridad de la compañera, se interrumpieron los seguimientos. Lo peor de todo, es que por lo que comentas, no es algo puntual, sino que esta teniendo estas acciones con otras personas, por lo que me temo que las tendria también con otra miembro del equipo, de todos modos le daremos una vuelta, a ver como podemos plantear algun seguimiento. Esto resumido, pero le daremos un poco de forma para trasladarlo, en la que por el momento se hace imposible cualquier intervención con Enrique." ················································· Mi respuesta: "No sabía que también había tenido estas conductas con la educadora. Siendo así, y viendo lo visto, os agradecería que nos enviéis, ahora sí que sí, INFORME FIRMADO con las incidencias ocurridas. Y para situaciones similares que puedan ocurrir en el futuro, por favor, intentad comunicárnoslo a la mayor brevedad. Con respecto al seguimiento e intervención con Enrique, ya nos diréis cómo vais a proceder."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-08-07','Ana: Envío correo a Alberto, jefe secc. ecca., con copia Julio, Aux. secc. soc., CTAEx: "En relación a DOROTEO DÍAZ CERRO, te reenvío correo de Toni-Futuex. Se le concedió plaza en CRR de Plasencia la semana pasada. El viernes ya fue a hacer la entrevista previa y como ves, este miércoles día 9 ya se traslada al mismo, todo muy rápido, no suele ser así… Necesita dinero extra para productos de aseo e higiene personal, que en este centro no los facilitan. Consideramos que 20€ está bien. En cuanto a las sábanas y toallas, le he pedido a Toni que nos haga llegar presupuesto y una vez aprobado, se abona desde aquí mediante transferencia. Lo bueno, a nivel eco para él, es que no tendrá que abonar el nuevo centro, eso sí, entiendo que más adelante desde el CRR, nos harán nueva propuesta de asignación para gastos de bolsillo y extra anual (éste último supongo que ya el año que viene, no sé) Julio, porfa, cuando puedas haz el cambio de domicilio en la BASE DE DATOS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-08-07','TERESA me ha llamado la madre de Marta (643 430 944) Esta haciendo salidas de madrugada: El día uno y se ha marchado las 6:30 y llego a las 5 de la tarde El día dos se fue a la misma hora y volvió el siguiente día El día tres salió a las 5:30 y volvió a las 5 de la tarde El día cuatro salió a las 4:25 y volvió al día siguiente Esta mañana ha salido la madre y cuando ha vuelto ya no estaba y no sabe dónde ha ido La madre dice que ya no puede más, que no duerme, que se lo esta advirtiendo y le da igual. Comenta que está saliendo con un tal Iván que vive en Cabeza del Buey, que se quiere ir a Valencia a trabajar y ella dice que se va a ir con él. Teléfono de Marta: 624 24 31 03 Ivan: 666 31 46 46','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-08-07','Ana: Correo de Ceferino al ctutelar@: "Hola buenos días llegó ya más de 6 años en este centro de otros en muchos y ha llegado la hora de comprarme una casa. Tengo la cantidad 88.630,95€ya se tendría que ir excelente estos lugares están robando la vida. Espero tu respuesta Ana" ························· Mi respuesta: "Perdona, pero no acabo de entender muy bien el correo, ¿lo que quieres decir es que quieres comprar una casa para irte a vivir a la misma? Si es así, decirte que se tratan de decisiones trascendentales en la vida de cualquier persona, hay que reflexionar mucho sobre ello y madurar bien las ideas. Además, habría que valorar, con el equipo técnico del centro, si realmente estás preparado tanto para tomar una decisión de tanto calado así como para dar el salto a vivir de forma independiente. Pongo en copia a Paula y Beatriz, para que estén al corriente y por si consideran conveniente que hablemos al respecto esta semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2023-08-01','Ana: nuevo correo de Estrella, secc. ecca., sobre el presupuesto de la Clínica Dental, para Alberto y para mí: "me han llamado de la clínica y me comentan que tengo que pagarlos ahora. También me dicen que si dejara el tratamiento NO DEVUELVEN EL DINERO. TIENEN QUE PAGARLE A LA ORTODONCISTA. Les he dicho que tengo que hablarlo con vosotros, ya lo vemos a la vuelta." ······················· Mi respuesta: "En mi opinión se puede hablar con el centro para que le ayuden a buscar otra clínica que no imponga esas condiciones. En Plasencia hay muchas." ·············· Respuesta de Alberto: "LA OPCIÓN QUE PLANTEA ANA ME PARECE LA CORRECTA...CREO QUE ES MUCHO DINERO PARA ARRIESGARNOS A QUE ABANDONE UN TRATAMIENTO EN UN MOMENTO DADO."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2023-08-07','Ana: Envío correo a Pilar, Directora Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): exponiendo la situación de la clínica dental y proponiendo que acudan a otra clínica a pedir nuevo presupuesto y preguntar ocpiones de pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-08-07','Ana: Nueva llamada de María, hija de Joaquina (871 114 458): Le informo que hasta el día 18/09 el auto no será firme. Llegado el momento, si le han concedido ya plaza residencial, se activará el 112 para el ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-08-02','Ana: Llamada de María, hija de Joaquina (871 114 458): manifiesta que su madre mantiene los mismos delirios recurrentes. ············· Además le ha contado que le han citado del Juzgado de Paz pero "no le ha dado la gana de ir", que si quieren que vaya la guardia civil a buscarla a casa. ······················· En cuanto a la resolución judicial de la revisión de las medidas de apoyo y autorización de internamiento involuntario, consultaré a partir de qué fecha adquiere firmeza. ·········· Me volverá a llamar en unos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-08-04','Ana: Llamo varias veces a lo largo de la mañana a Ana Benavente, TS del ESM-Plas. (74955): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-08-07','Ana: Llamo varias veces a lo largo de la mañana a Ana Benavente, TS del ESM-Plas. (74955):','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-08-07','Ana: Llamada de José Manuel, quiere saber si para el juicio que tiene el día 31 de octubre en el Juzgado de 1ª Instancia e Intrucción nº 6 de CC a las 10 h. (pelea con otro hombre - parte de lesiones), va a ir a acompañarle algún abogado. Dice que cuando tuvo otro juicio por prender fuego a un colchón en el CSS le acompañó Miguel, A. Jurídico. ·············· Por otra parte, dice que quiere ingresar en el CRR de Don Benito. No está bien y está harto de estar solo. ················ Dice que también tiene que comprar productos de limpieza, necesita 20 €. ··················· Por último, quiere comprar otros auriculares, pues dice que se le han roto los que se compró con el dinero que pidió prestado. *Le emplazo a enviar un presupuesto en el mes de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-08-08','Ana: Envío correo a Estrella Durán, TS CSS - está de vacaciones hasta el día 21. ····· "Te reenvío correo de mi compañera Teresa, pues Reme Chaves Masero ha vuelto a realizar ingesta. Y como puedes ver en el hilo, el Dr. Le dijo que desde la UHDAC enviaron una autorización para estos procedimientos médicos sin necesidad de esperar a los consentimientos informados. ¿Podrías confirmarme si eso es así, y en tal caso, enviarme dicho modelo?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-08-08','Ana: Correo-Seguimiento de Toni-Futuex, de ayer a última. Guardo en PDF en el expte. digital.: Felisi ha vuelto a cambiar de nº de teléfono: 682 251 616, Jesús le compró la nueva tarjeta. ······················· "Solicita extra para comprar el abono de los toros para las fiestas locales que comienzan esta semana para ella y para su hijo Aitor, el importe del mismo asciende a 28 euros por persona, 56 euros en total." "La situación en el domicilio continúa siendo conflictiva según comenta Felisa, su hijo sigue sin colaborar en las tareas domésticas, no limpia ni ordena ni siquiera su cuarto y según palabras de su madre el aseo es muy escaso, explica que se ducha algunos días, pero con poca frecuencia. Jesús ha vuelto a la casa de Navas y lleva una semana conviviendo de nuevo con ella, pero explica que pasa gran parte del día fuera de Navas y que acude con frecuencia diaria al domicilio de su familia en Casar de Cáceres" ·············· "En el momento de la visita tanto Aitor como Jesús están acostados y no se puede interactuar con ellos, pero durante la gestión de retirada del dinero recibe varias llamadas de Jesús, controlando las tareas que realiza la tutelada." ·························· Mi respuesta: "...- A Aitor ya se le dio dinero para los toros, desde el Programa de Familia le acompañaron a retirarlo y comprar el bono. - Las compras online intentó hacerlas con la propia tarjeta monedero. - La cuenta que abrió con Mirella intentaron cancelarla en su día desde la Secc. Económica, pero no sé si finalmente fue posible, pues recuerdo que hubo problemas. El compañero que se encargó está de baja. - Con Felisi hablé la semana pasada, y sí me comentó lo de los toros, para ella, le dije que había que valorarlo en la sección económica, que si se podía era probable que se le diera, pero no le confirmé nada. Y que lo hablara con la educadora o el programa de familia, pues no sabía el precio exactamente. Pero el viernes desde el PAF me dijeron que iba a comprarlo con su asignación quincenal, por eso no se ha valorado finalmente el extra… ¿podríais aclarar/confirmar esto? Si finalmente hay que pedir extra, por favor, envíalo directamente al ctutelar@. Las compañeras del PAF están de vacas esta semana. - Con respecto a Jesús, en ningún momento me dijeron que estaba allí pernoctando de continuo, que sólo se quedaba de vez en cuando..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2023-08-08','Ana: Reenvío a Alberto, Jefe Secc. Ecca., la respuesta de Pilar, Directora del Centro: "Ya he hablado con la clínica dental. Le van a cobrar como suelen hacer normalmente, la mitad al inicio del tratamiento y la mitad al finalizar el mismo. El hecho de ir a esta clínica es porque Mª Carmen ya conoce al dentista y se encuentra cómoda a la hora de que le realicen cualquier tratamiento. En cuanto a que termine el tratamiento, estaremos pendientes para que vaya acudiendo regularmente y lo lleve a término, porque le hace muchísima falta." ························ Alberto da OK y se lo envía a Estrella, Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2023-08-08','Ana: recibo llamada de Rosa, Adtvo. del CSS-Plas.: Me comunica que, después de varias "peleas" con el banco y con al sucursal de Málaga, ya está solucionada la deuda de 5.000 € con el centro. Han acudido con él a la sucursal de Plasencia y han sacado el dinero. Todavía deben quedarle entorno a unos 3.000 € en la cuenta, por lo que, de momento, seguirán retirando el dinero de la misma para abonar el centro hasta que se agote el saldo. ········ Lo ideal es solicitar el cambio de la pensión a otra cuenta bancaria. Cree que ya tiene otra abierta. ········································ *Envío a Icíar correo con esta información y pido que me facilite el nº de la otra cuenta para solicitar el cambio de la PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-08-08','Ana: Correo de Pilar Martín, TS del ESM (pilar.martinp@salud-juntaex.es): "he llamado hoy a Centro Vida y me dicen que ya no esta con ellos, ahora se encuentra al parecer durmiendo en la estación de autobuses. La verdad , ¿ ahora que hacemos ?" ··························· Mi respuesta: "Pues sinceramente, no sé qué vamos a hacer con este chico… así es imposible… mira que la semana pasada hablé varios días con él y con Pedro y parecía mínimamente centrado y pidiendo que le tuvieran en cuenta los informes que hablamos para poder tener opción a CRR, que lo iba a hacer bien esta vez… "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-08','Ana: Llamo varias veces a Ana Benavente, TS ESM-Plas (74955): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-08-08','Ana: Correo de Maite, Jefa Secc., a Miguel Medina, Psiquiatra (miguel.medinab@salud-juntaex.es) y María Sol Tafur, TS (mariasoledad.tafur@salud-juntaex.es): "Nos ponemos en contacto con vosotros para informaros de las gestiones realizadas, tras lo acordado en la reunión que tuvimos relativa a la situación de Guadalupe Gil Cabello. Solicitamos al juzgado de Trujillo la autorización de internamiento, adjuntando el informe que realizamos el día de la reunión, informe de servicios sociales e informe realizado desde aquí. Hablamos con el juzgado para insistir en la gravedad de la situación. La jueza, Patricia, fue a visitarla a domicilio el 4 de julio. No entendió por qué no estaba en un centro, ya que cuando dictó las medidas de apoyo recogió en la sentencia la autorización para hacerlo. En el auto que ha dictado en Julio , autoriza de nuevo ‘’ el internamiento en centro o piso tutelado, adecuado, para su patología’’., lo mismo que en la sentencia de medidas de apoyo. Hablamos con la jueza, y nos dijo que no podía autorizar el internamiento en UHB o UME ( sociosanitario) pq el informe del médico forense recogía que no está descompensada para dicho ingreso. Entendemos que la única vía que nos queda es la derivación a través de una subcomisión de casos. No sé si estáis de vacaciones, en ese caso lo hablamos a vuestra vuelta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-08-08','Ana: correo de Ana Benavente, TS ESM (anamaria.benavente@salud-juntaex.es): "He vuelto a hablar con el Dr. Mora y me dice que hay que premiar a Isabel y autorizar la visita (ya lo hablamos si te parece )." ······································· Contesto a Ana y envío correo a Paula, TO, y Bea, Psicóloga, del CRR: "En base a criterio del facultativo, por pare de la sección social del Gabinete Técnico de la CTAEx, NO hay inconveniente en autorizar dicha salida, que Isabel tanto demanda, del 14 al 16 de agosto. Agradeceríamos se lo transmitieseis a ella, por favor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-08-09','TERESA Remedios se encuentra bien, ya le ha extraído la pila y el tornillo y afortunadamente no le ha producido ninguna perforación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2023-08-09','TERESA ARCHIVO RESOLUCION ATP','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-08-09','Ana: Llamada de Isabel de Cáceres, madre de Alfonso (680 784 490): dice que hay una asesora jurídica que se quiere poner en contacto con la CTAEx: Priscila Benítez: 621 20 24 00 ···· Se lo comunicaré a A. Jurídicos CTAEx para que se pongan en contacto. ······················· Por otra parte, quieren pedir 2 extras: Uno para viajar a Leganés de vacaciones, a finales de agosto o principios de septiembre, y otro para la compra de una consola. Para esto último le indico que tienen que enviar presupuesto. **Lo enviarán todo a través de Patricia, Ed. Futuex. ···················· Envío correo a A. Jurídicos: "envío correo a los A. Jurídicos - CTAEx: "Me ha llamado Isabel Marín, madre de Alfonso Marín de Cáceres. Dice que le ha llamado ya varias veces una tal PRISCILA BENÍTEZ – de una Asesoría Jurídica: 621 20 24 00, dice que a ella no le puede informar de nada, pero cree que le llama por una herencia del padre de Alfonso y le ha pedido que desde la CTAEx nos pongamos en contacto con ella. ¿Podríais llamarla?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-08-09','Ana: Tras recibir llamada de Isabel, madre de Alfonso (680 78 44 90), envío correo a los A. Jurídicos - CTAEx: "Me ha llamado Isabel Marín, madre de Alfonso Marín de Cáceres. Dice que le ha llamado ya varias veces una tal PRISCILA BENÍTEZ – de una Asesoría Jurídica: 621 20 24 00, dice que a ella no le puede informar de nada, pero cree que le llama por una herencia del padre de Alfonso y le ha pedido que desde la CTAEx nos pongamos en contacto con ella. ¿Podríais llamarla?"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2023-08-09','Ana: Correo de Icíar: "ya he enviado yo el cambio de pensión, no sé si fue un día que tú estabas de vacaciones. Sorry!. El caso es que Marina, de PNC, nos pidió en un correo un alta a terceros, fuimos al banco y le respondí a ese mismo correo ya con el número de la nueva cuenta, ahora habría que comprobar si este mes le entra ya la pensión, me lo tengo apuntado para el 25 y si no fuera así, ya te digo para ver si ha habido algún problema."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-08-09','Ana: Tras consulta de Alberto, jefe secc. ecca., en relación al cobro indebido de PNC, reenvío a Alberto los correos ya enviados en junio y octubre de 2022. ·························· Envío nuevo correo a Alberto: "A parte de los dos correos que te he reenviado (que eso igual ya está resuelto), al parecer tenía también otros cobros indebidos de la Ley de Dependnecia, ya no me acordaba. Pero esto es lo que tengo anotado en la INTRANET a fecha de 16/02/23. ... Así pues, se los pasé a Óscar. Con respecto a la transferencia que se le hace a la madre, se autorizaron en concepto de de gasto de suministros. Por lo que entiendo que hay que mantenerla."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-08-09','Ana: Llamada de Ana Benavente, TS ESM-Plas (74955): Flora quiere saber cómo va lo de su herencia y le recuerda que quiere vender su piso. ····················· Informo a Ana que Miguel, A. Jurídico, está con trámites/gestines con la Notaria de Plasencia. Etas cuestiones van lentas. ···· Las hermanas han renunciado a la herencia. ···· Debe tener paciencia. En septiembre Ana volverá a preguntarnos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-09','Ana: Llamada de Ana Benavente, TS ESM-Plas (74955): Enrique le ha llamado y lo nota muy alterado y se muestra muy enfada también despotricando de la CTAEx, la Educadora, los Veterinarios y todo el mundo. ······ Le pregunta también insistentemente por el tratamiento dental, yo no recuerdo exactamente, sé que envió distintos presupuesto, y pensaba que ya se había aprobado alguno. ········ Desde el EQUIPO DE TRATAMIENTO ASERTIVO COMUNITARIO tiene CITA PROGRAMADA para finales de agosto, para ir a visitarlo. ··········· Le recuerdo también los acuerdos con respecto al servicio de comida y, llegado el momento, el dinero a tal fin. ·································································································································································································· Envío correo a Estrella, Secc. Ecca.: "Ya sé que estarás recién aterrizada de vacaciones y tendrás ya muchos correos y cositas pendientes, pero me preguntan desde el Equipo de Salud mental de Plasencia, qué ha pasado con el tratamiento dental de ENRIQUE SANTOS GARCÍA-PUENTE. Yo no soy capaz de ponerlo en pie y no lo tengo anotado en la Intranet, y eso es raro, por eso te pregunto, para que, cuando puedas, lo mires y me lo aclares que yo sé que esas cosas tú las tienes controladas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2023-08-09','Ana: Llamada de Minerva, TS del CR Cervantes (22237): Mª Luisa quiere irse un par de días con su hija. *NO SE AUTORIZA LA PERNOCTA. *Se autoriza a que pase el día fuera y pueda ir a comer por ahí con ella, pero tiene que volver a pernoctar al centro. *Minerva está de acuerdo, ella tampoco ve pertinente que se vaya unos días, pues hay riesgo de que después no quiera volver. ·················· Las visitas de su hija no han ido mal, pero como es lógico, Mª Luisa se emociona y está algo más alterada esos días, pero sólo eso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2023-08-09','Ana: Envío correo a Rosa Bravo, Adtvo. CSS-Plas. (rosamaria.bravop@salud-juntaex.es): "En relación a ANDRÉS SILVA BONIFACIO, a petición de mi compañero Ángel, A. Jurídicos, te reenvío correo con Cédula de Citación para el día 25/10/23 a las 9:30 h. ¿Podría, por favor, acompañarle alguien desde vuestro centro? Pongo en copia a Estrella, para que lo vea a su vuelta de vacas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2023-08-09','Ana: En relación al correo remitido hace una semana por Sheila, Directora del CRR-CC, envío correo a Ángel y Maite - CTAEx: "Os reenvío correo que tenía pendiente de Sheila, Directora Técnica del CRR de Cáceres, con un escrito con peticiones que realiza la propia Antonia Canelada de Río. Pongo en copia a Sheila y así también le sirve de respuesta, por favor, corregidme y/o añadir lo que sea procedente: Vamos por partes, por orden de sus peticiones: - Según el fallo de su sentencia, aún pendiente de revisar (que yo sepa), Antonia "es total y absolutamente incapaz para gobernarse por sí misma y administrar sus bienes" por ello, y puesto que no había nadie más que pudiera asumir el cargo, nombró a la CTAEx. Por tanto no puede administrar su cartilla. *Esto en todo caso tendría que solicitarlo en el Juzgado que la incapacitó o plantearlo llegado el momento de la revisión de su sentencia (recordad que en base a la Ley 8/21 de 2 de junio, todas deben ser revisadas) - El alta del recurso, debería venir determinado por un ALTA TERAPÉUTICO, por lo que necesitaríamos un INFORME DEL CRR en que se indicara si ella está en disposición del tal alta y de, tal y como pide en el siguiente punto, vivir de forma independiente. - Así mismo, tampoco disponemos de Informe de Psiquiatría sobre su evolución que avale tal alta. - En cuanto irse a vivir con su hermano que se encuentra a día de hoy viviendo en la calle, pudiendo estar en la vivienda que tiene en otra localidad, no creo que sea lo más adecuado, pues no dice mucho a favor de los hábitos y estilo de vida que su hermano y de que pueda ser un buen apoyo para ella. - En cuanto a la herencia de su hermana, emplazo a mis compañeros Jurídicos a que contesten, pues no sé si ha hecho algo ni tan siquiera si hay documentación/información a tal fin. Espero haber aclarado todas las cuestiones. No sé si finalmente, mis compañeros, Maite, Jefa de Sección, o Ángel, Asesor Jurídico, podrán añadir/aclarar/modificar algo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2023-07-18','Ana: Correo de ayer de Sheila, Directora del CRR-CC: comunica incidencias. Ha aparecido en escena su hermano, quien le pide dinero a Antonia (le da 60 y 12 € en sendas veces), el DNI, que Antonia le entrega y no quiere devolver al centro, y la Cartilla Bancaria que no le entregan. Lo exige también a los profesionales del centro de manera agresiva. Desde aquí les reiteran que su hermana está a cargo de la CTAEx e interponen una denuncia de los hechos en la policía. ···················· Estos hechos están afectando al estado psicopatológico de Antonia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-07-11','Ana: Correo del día 14 de Sheila Rguez., Directora Técnica CRR-CC (crr@grupociudadjardin.com): "informar del ingreso en la UHB en la tarde de ayer la persona usuaria Félix Valle Simón."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-08-07','Ana: Correo de Sheila, Directora del CRR-CC (crr@grupociudadjardin.com), guardo en expte. digital: Juan José regresará mañana al centro tras la expulsión. Ha mantenido reunión con la Psicóloga. "Se muestra tranquilo, colaborador y no se objetiva descompensación" ····· "se le propone la posibilidad de traslado al CRR de Plasencia para posterior posibilidad de traslado a pisos supervisado. Expresando no querer, no estar interesado en dicha posibilidad, ya que su deseo es volver a pisos supervisados o un piso social con seguimiento de la CTAEX, expresando que para pasar por otro CRR se queda ya en Cáceres." ····· "Mañana junto con Terapeuta Ocupacional acudirán en taxi (debido a la cantidad existente e imposibilidad de transportar sin vehículo) a un punto limpio para depositar los objetos acumulados. Y su familia acudirá en los próximos días para retirar del centro pertenencias acumuladas." ······· "dentro de la intervención planteada se encuentra la disminución temporal del dinero semanal disponible, se muestra de acuerdo en el planteamiento y se trasladará a la comisión dicho acuerdo una vez se establezca con él el dinero exacto. De igual forma se detecta la necesidad de compra de ropa, que se trasladará igualmente a la CTAEX una vez se realice inventario de necesidades." ····· "Queda pendiente abordar el asunto de los pagos no autorizados, ver a qué responden y qué metodología ha utilizado o a través de qué aplicación está realizando la compra. En cuanto los abordemos os contamos también"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2023-08-09','-Amalia : no se le concende extra en verano : ENTRE EXTRAS QUE SE LE CONCEDEN Y NECESIDADES QUE SURJEN: MUEBLES, HIJOS, ETC: -1.436 € EL ULTIMO AÑO. LA GESTIÓN ECO NO ES ADECUADA NI CORRECTA: SERÍA IMPOSIBLE ATENDER CUALQUIER IMPREVISTO QUE PUDIERA SURGIR DE RELEVANCIA ECONÓMICA (EL ÚLTIMO AÑO EL BALANCE FUÉ NEGATIVO). DEBERIAMOS CONSEGUIR TENER UN AHORRO MÁS ELEVADO (7.000 € - 10.000 €) QUE NOS PERMITIERA ATENDER A IMPREVISTOS SERIOS Y NO PERPETUAR LA SITUACIÓN ACTUAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-08-09','Ana: Envío correo a Ana Benavente, TS ESM-Plas (anamaria.benavente@salud-juntaex.es): "Necesitamos que nos informéis sobre si acudió a su cita en la Consulta de Psiquiatría del día 31 de agosto y nos digáis si ha vuelto a pasar por ahí, pues de nuevo se encuentra en paradero desconocido… hemos de comunicar al Juzgado, que además y nos ha hecho un requerimiento. Como veis la intervención con él es muy difícil pues no para de abandonar recursos y cambiar de localidad de forma impulsiva y sin previo aviso." ····························· Respuesta de Ana: "Sí que acudió a la cita y hasta donde yo sabía seguía en Plasencia. Yo le tengo citado pronto. Ya hemos enviado la solicitud de CRR por Emergencia Social, a la espera de que se reúna la Comisión de Acceso a Recursos Residenciales."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-07-12','NUEVA RESOLUCIÓN DENEGATORIA DE PNC: "No reúne requisito de estar afectado por una discapacidad...igual o superior al 65%"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2023-08-10','-Amalia : registrado a PNC declaracion anual de 2023','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-08-10','Ana: Envío correo a Sonia y María, compañeras de María y Raquel del Programa de Familia (programafamilia@tajosalor.es) con copia a Toni-Futuex: "Finalmente mi compañera de la sección económica podrá hacer hoy mismo la recarga de la Tarjeta Monedero de Felisi. Puesto que la siguiente retirada de efectivo le correspondería para el día 15, que es festivo, y dado que mi compañera se va de vacaciones la semana que viene (estamos al mínimo en estas fechas, jeje), van a recargarle todo hoy: - Asignación Quincenal habitual: 160€ - Extra: 50 € para el Abono de los Toros y la Peluquería Si podéis acompañarle a retirarlo entre hoy y mañana perfecto (no sé qué día exactamente empiezan las fiestas y los toros). Quedo a vuestro criterio si, con vuestro apoyo e indicación, lo retira todo hoy o si retira de momento los 50€ y el resto la semana que viene que es cuando en teoría le corresponde. Lo digo más que nada por sus dificultades actuales en la administración del mismo por las continuas peticiones/exigencias de Aitor y el mayor gasto por la convivencia con Jesús, de nuevo." ························· Hablo con Felisi (682 251 616), le informo de la recarga del extra y de que le van a acompañar a retirarlo. ····· A parte dice "Jesús se está portando muy bien conmigo" y "Aitor está mejor"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-08-09','Ana: Correo de Sonia y María, compañeras de María y Raquel del Programa de Familia (programafamilia@tajosalor.es): "Somos María y Sonia, compañeras de Raquel y María, ellas están de vacaciones, esta mañana nos ha llamado Aitor para comentar si a su madre no se le va dar una asignación extra para el bono de los toros, nos ha comentado que el que quiere comprar su madre cuesta 35€, aparte nos comenta que su madre quiere ir a la peluquería y necesitaría dinero. Las fiestas empezaría mañana, entendemos que os avisamos con muy poco tiempo , pero es que lo han comentado hoy." ······················· Mi respuesta: "Vuestras compañeras me dijeron que Felisa iba a comprar el bono de los toros con su asignación periódica quincenal, por eso no se autorizó ningún extra. Lo de la peluquería no sabíamos nada, normalmente ella se administra bien y tiene para ese gasto, si bien es cierto, por lo visto ahora Aitor le pide (más bien exige) todas las semanas dinero a su madre, a pesar de tener su propia asignación para sus gastos, así pues a Felisi no le llega… Mañana a primera hora lo hablo con mis compañeras de la secc. ecca. si es posible, mañana mismo se le recargará la tarjeta monedero que tiene con un importe de 50€ para ambas cosas, no obstante se la llamará para confirmar. También es verdad que va siempre acompañada para retirar el dinero, así que consultaré si pueden acompañarle desde el Programa de Apoyo Comunitario que gestiona Futuex." ··········································· Responden del Progr. Familia: "no habría problema para sacar el dinero, nosotras podríamos acompañarla en un momento"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-08-10','Ana: Envío correo a Paula, TO del CRR-Plas: "Finalmente hoy ya puede firmar la Directora-Gerente, por tanto se va a proceder ha realizar la autorización de un extra de 17€ para productos de aseo e higiene personal, que es lo que se acordó. Por otra parte, tiene una asignación semanal de 30€ para sus gastos de bolsillo, en Alcuéscar se ha estado manejando bien con esta cantidad y el equipo técnico no vería conveniente aumentárselo más. Entiendo que en Plasencia puede tener un nivel de gastos un poco más elevado, pero no creo tampoco que deba gastar mucho más (sobre todo según el uso que vaya a hacer del dinero). NO obstante, cuando valoréis este aspecto ya nos indicáis si consideráis aumentárselo y qué cuantía acordáis con él en tal caso. Puesto que la cuenta la tiene en UNICAJA, sendas autorizaciones se van a enviar a la oficina de la C/Alfonso VIII, nº 24. Entre mañana y el día 18 podrá retirar el extra. Y la asignación semanal a partir del lunes próximo, día 14 (él suele ir todos los lunes. De hecho el lunes pasado retiró sus 30 € en Alcuéscar)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2022-08-09','Ana: Recibimos de PLACEAT Registro de Evaluaciones mensuales del Serv. de C.O. de los meses abril - julio, con la indicación de las pequeñas gratificaciones eccas. obtenidas en función del logro de los objetivos marcados. ·········· Así mismo, adjuntan el registro de sus gastos del mismo periodo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-08-08','Ana: Correo de Julia, Coordinadora Casa Misericordia de Alcuéscar (casadelamisericordia.alcuescar@gmail.com) remitiendo Informe de Baja del Recurso. ············· Guardo en expte. digital. ···················· *Ha tenido momentos de descompensación relacionados con juego a máquinas tragaperras y consumo de alcohol. El resto del tiempo ha tenido buen comportamiento. Aunque nunca ha participado en los talleres del recurso por falta de interés/motivación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2023-08-10','Ana: Llamada de Abraham, hijo de Pilar (927 234 706): quiere pedir una cita con todas la áreas de la CTAEx porque dique que "su madre ya no quiere que la comisión sea su tutora". Le explico que para eso no necestian venir aquí. Tiene que dirigirse al Juzgado que incapacitó a su madre y pedir la remoción del cargo. Allí le indicarán los pasos a seguir. ····················· Por otra parte, quieren cambiar de piso de alquiler. En el que están tienen un CONTRATO VERBAL desde hace muchos años y, según dice la dueña es "muy agarrada" y no quiere encargarse de los arreglos como grifos rotos. *Le indico que para ello deben buscar, si quieren con el apoyo de la Ed.- Futuex, otro piso de alquiler de precio similar y enviar la información a la CTAEx para valoración tanto de los A. Jurídicos para el contrato, como por la Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2023-08-10','Ana: Llamo a María, TS de la Res. (927 38 32 58 / serviciossociales@centrodemayoressierradesanpedro.es): Tomasa necesita una silla de ruedas nueva, la suya está fatal. Me enviarán la prescripción médica y solicitud de material ortoprotesico del SES así como presupuesto de la ortopedia. Cuando se apruebe éste último y se abone la silla, enviaré los documentos a la Gerencia de Salud del SES de CC, junto con la factura para solicitar la subvención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-08-10','Ana: Llamada de Carlos (644 949 205): Está en la Clínica Veterinaria, pues ha fallecido su perrito esta noche. Desde la clínica se encargan de las gestiones con la empreas del Casar de Cáceres para el traslado y la incineración. El precio ronda los 90€. ··············· Me pasa con Pedro Aº, de la clínica, nos enviará un correo electrónico con el nº de cuenta para realizar la transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2023-08-10','-Amalia : pregunto a la empesa SAD por el estado de Rosa. Rosa la verdad que muy bien, Isa la auxiliar titular ha estado de baja casi un mes, y con la sustituta ha estado estupenda, que no es fácil, ya volvió Isa y todo igual, ha estado pasando mucho calor y hasta que hemos podido enganchar a algún técnico , pero por lo de más bien, come bien, esta sana, limpia y atendida, creo que poco mas se puede mejorar, el servicio de los festivos nos da seguridad y tranquilidad, seguimos en contacto y Gracias por vuestro trabajo , un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-08-10','tf. Antonia 656236029','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-08-10','TERESA JOSE MARIA HA VISITADO EL DOMICILIO FAMILIAR DEL 8 AL 11 DE AGOSTO Jose Maria Morón, que se le ha visto está mañana está bien, se vuelve mañana, se le veia bien y le ha contado a la compañera que ha estado recogiendo cosas de la casa, dice que él es muy ordenado y no le gusta verla así (no sabemos como se habra organizado en la casa asi como estabas)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2023-08-11','Ana: En relación al correo de ayer de Agustina Martín - Ayto. de la Haba (ayuntamiento@lahaba.es): "Mediante el presente, le comunicamos que la puerta trasera de la vivienda que tiene en esta localidad en C/ Dos Pozos nº 7, FELIPE BLANCO GUISADO, está abierta. Para evitar que nadie entre, necesitamos que se hagan cargo y coloquen una cerradura nueva, o lo que consideren. Tengan en cuenta el peligro que supone que alguien ocupe ilegalmente la vivienda. En otra ocasión, nosotros cambiamos la cerradura de la puerta delantera porque estaba abierta y ustedes autorizaron a este Ayuntamiento para que se cambiase y posteriormente ustedes pagaron a la persona que realizó el trabajo (una llave se encuentra custodiada en este Ayuntamiento por requerimiento de ustedes). ", respondo: "Muchas gracias por informar. ¿Sería mucho pedir que el Ayto. colaborara una vez más con nosotros encargándose de esta gestión o al menos facilitándonos el contacto de la persona autónoma o la empresa que pueda realizar este trabajo para ponernos en contacto y encargárselo? Sería de gran ayuda, pues en este momento nos quedamos sin el Programa de Apoyo conveniado por la Consejería que nos ayudaba en este tipo de gestiones. Por supuesto el trabajo se abonaría mediante transferencia, como se hizo en la otra ocasión. Pongo en copia a mi compañero Ángel, Asesor Jurídico y conocedor del expediente de Felipe, por si tuviera algo que añadir." ·································································································································································································· Nuevo correo de Agustina - Ayto.: "Le paso el teléfono de Hermanos Plomache, una empresa de construcción con quien pueden contactar para tapiar o poner cerradura en la puerta trasera abierta. El teléfono es: Antonio 678-735-913" ··············· Llano a Antonio, la semana que viene, cuando haya ido a ver la casa y haga valoración, me llamará para informar e indicar coste aproximado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-08-11','TERESA tenemos una información confidencial detectada tras la analítica de ingreso que se les hace a los nuevos Te adjunto copia que me ha pasado el enfermero Hemos informado a salud pública, como es el protocolo, y ahora a vosotros que sois sus tutores Queda por determinar quien informa a Santiago, si lo hacéis vosotros y pensáis que es mejor que se haga desde el centro. Si este es el caso nos tenéis que firmar una autorización para transmitir esa información tan delicada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-08-11','TF DE DÑA. FCA. DUEÑA DEL PISO QUE TIENE ALQUILADO 695535644 TF DE LA HIJA DE LA DUEÑA LOURDES 665572559 He llamado a la Sra. para firmar el documento para la ayuda al alquiler ,hasta principios de septiembre no viene de la playa . quedaré con ella la primera semana ,presento hoy si llega firmada la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-08-11','TF DE CHITI 628688654 Es la mujer del que Antonia considera que es el padre de su hijo . Quiere que el chico se haga la prueba de paternidad , hablaré con ella para que nos informe bien de la clínica y de todo. Cada parte abonará 147€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-08-11','-Amalia , mantengo conversación con Antonia . Va a por comida al comedor , se lleva las bolsas con comida pero no come allí . Le dan de todo y va cada 15 dias . Su pareja no vive con ella , ha solicitado el subsideo para +52años , tiene 20 años cotizados. La PNC ya la tiene activada . Ha enviado el cdo de empadronamiento a Gloria de Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-08-11','Ana: en relación a la solicitud del Serv. de Catering del IMAS, llamo a Guadalupe Cortés, TS SAD-IMAS CC (guadalupe.cortes@ayto-caceres.es // 927212335 Ext. 4422), como no obtengo respuesta llamo a Lourdes (Ext. 4425 // lourdes.perez@ayto-caceres.es), como tampoco obtengo respuesta, envío un correo a ambas, añadiendo también a Angélica, TS IMAS (angelica.nunez@ayto-caceres.es): "Espero que estéis bien. No sé si estaréis alguna/s de vacaciones, como no consigo contactar por teléfono, os realizo la consulta por aquí, y así ya lo veis y contestáis cuando podáis. En relación a CARLOS GONZÁLEZ LEO, usuario de Ayuda a Domicilio del IMAS y cuyo cargo de CURADOR REPRESENTATIVO ostenta la CTAEx, se registró solicitud de Servicio de Cáterin Municipal a fecha de 25 de julio. Sé que no ha pasado mucho tiempo, pero pregunta constantemente por este recurso. ¿Podrías decirme en qué situación ha quedad su solicitud? Lo cierto es que le hace falta el servicio." ····································································································································································································· Respuesta de Lourdes, TS IMAS: "Hola ,si te iba a escribir para decirte que es favorable , la empresa les llama para decirles el día y la hora , pero lo normal es que inicien este lunes . El reparto esta semana, será el lunes y jueves" ·························· Se lo comunico a Carlos, se pone muy contento porque dice que va a poder "comer sano".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-08-11','Ana: Tras llamada de Carlos (644 949 205): envío correo a Toni-Futuex: "...cuando puedas, envíame unos documentos que dice Carlos haber entregado a Patricia, Educadora, en relación a una cartilla bancaria y herencia de su madre. Ya me ha preguntado en varias ocasiones por ello y hoy vuelve a insistir." ···································· Respuesta de Toni: "lo de Carlos no es exactamente como el te ha dicho, ahora te paso lo que tenemos (nada de herencia ni de cartilla) : Carta recibida por Carlos González Leo a nombre de Juana Leo Carlos recibe una carta en su domicilio, preguntan por su madre, la cual ya ha muerto. En la carta pone que no le conceden (a su madre) cierta ayuda/servicio que ella solicitó en vida por superar económicamente los baremos establecidos. Debido a que en dicha carta habla sobre el dinero de su madre, Carlos cree que es algo en referencia a la herencia y que ese dinero se lo tienen que dar a él. Se le intenta explicar lo que realmente significa lo que pone en la carta, pero Carlos no hace caso. En este día estaba ausente totalmente y no quería hablar con la educadora, al no medicarse, tiene delirios y alucinaciones constantes, este día decía que la educadora era del bando de las personas que le quieren hacer daño, que le quería sacar información, y no se consigue que lo entienda. No ha entregado nada en referencia a una cartilla bancaria, solo muestra la carta, además de unos documentos en referencia al servicio de ayuda a domicilio que no tienen nada que ver."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-08-11','Ana: Correo del día 14 de Sheila Rguez., Directora Técnica CRR-CC (crr@grupociudadjardin.com): "Comunicar que la persona usuaria Félix Valle Simón, terminó con las extracciones dentales previstas, se acudió a la clínica dental según periodo transcurrido pautado opr la misma para iniciar el molde de la dentadura, sin embargo la encía aún no está totalmente cicatrizada motivo por el cual aún no se ha realizado. Se tendrá nueva cita en el mes de Septiembre. Y será entonces cuando haya que realizar el pago del presupuesto acordado. Estaremos en contacto para ello y saber como proceder." ···································································································································································································· Envío a Sheila, citación para revisión de las Medidas Judiciales de Apoyo para el día 4/09/23. Y pregunto si pueden acompañarle. ···························· Sheila confirma el acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-08-11','Ana: Correo del día 14 de Sheila Rguez., Directora Técnica CRR-CC (crr@grupociudadjardin.com): Informar que la persona usuaria, Martin Moguel Miranda Hernández, ha estado en tratamiento médico para infección dental, que ha requerido finalmente la extracción de todas las piezas existentes. Aún está en tratamiento farmacológico de la encía y se preveé que no se pueda realizar molde para dentadura hasta dentro de dos o tres meses según evolución. Una vez se pueda, se procederá a solicitar presupuestos para valorar por vuestra parte. Por otra parte, trasladar información recogida por el equipo, de haber recibido llamada telefónica en relación al interés de continuar en inclusión de posibilidad de acceder a residencia del cuartillo de Cáceres, siendo afirmativa la respuesta a dicha llamada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-08-11','TERESA he estado hablando con Pili, la anterior psicóloga de Marta, y me comenta que desde que entró en centro ocupacional no ha tenido citas en salud mental. La última cita fue con psicólogo o psiquiatra infanto-juvenil cuando estaba en el centro de menores, pero no tenemos los informes aunque Pili los solicitó. Le van a programar la cita con psiquiatría en el área de adultos de Don Benito a partir de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-08-11','Ana: Envío correo a Sheila, Directora del CRR-CC (crr@grupociudadjardin.com) con citación para revisión de las Medidas Judiciales de Apoyo para el día 4/09/23. Y pregunto si pueden acompañarle. ···························· Sheila confirma el acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-08-11','ANA: Correo de Inmaculada Gómez, Psicóloga del ECA-CC (inmaculada.gomezm@salud-juntaex.es): "Adjunto el informe solicitado. Con copia a Pilar Martín". ················ Guardo en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-08-11','Ana: Envío correo a Toni-Futuex: "En relación a JUAN JOSÉ GLEZ CARRERO, se ACEPTA EL PRESUPUESTO DE CÁTERIN. No sé si os dará tiempo a hacer las gestiones hoy para formalizarlo, lo veo complicado. Si fuera así, perfecto. Sino, por favor, al menos enviarme la información del Cáterin, que no indicabais que empresa era ni nada en el correo, para que pueda llamar yo el lunes y terminar las gestiones pendientes. Sino tendrá que esperar a septiembre." ··················· Respuesta de Toni: "se envía la solicitud del catering y se adjunta la información de la empresa. CATERING SOL Información: 927 27 82 36 Tienda: 927 03 32 31 Correo: info@solcatering.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-08-14','Ana: Correo de Ceferino: "quisiera coger un local para alquilarlo para poder hacer mis sesiones y meter a gente allí para que baile ya que tengo muchos seguidores en jarandilla de la Vera los cuales me los encontré el otro día en Plasencia y ya quiero pinchar delante la gente. A ver si es posible por favor espero tu respuesta" ··················· Mi respuesta: "Esta cuestión también tendrás que plantearla con las profesionales del equipo técnico del CRR. Si fuera necesario ya hablaremos con ellas al respecto. Pongo en copia a Paula y Bea." ····················· Respuesta de Paula: "Buenas, gracias por ponernos en copia. Hablaremos y trataremos de recoger estas inquietudes y otras con Ceferino, para poder trabajarlas. Como podéis ver por los correos, las demandas van cambiando casi cada semana, por lo que trataremos de apoyar la reflexión acerca de las mismas, para que pueda ir orientando y canalizando sus deseos en alguna dirección. Si es así podremos poner objetivos y trabajar de manera planificada su consecución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='GARRIDO'and apellido2='DURAN'),'2023-08-14','Ana: Correo del sábado al ctutelar de M.Luz Romero Furones - Médico Somático (marialuz.romerof@salud-juntaex.es): "El paciente José Luis Garrido Durán será derivado al hospital de Mérida a lo largo de la mañana del día de hoy."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2023-08-11','Ana: Correo de Sheila, Directora Técnica - CRR CC: Esteve ha protagonizado varios hurtos a un compañera del CRR. Se había puesto de acuerdo con un tercero, con el que se repartía el dinero. ············ Envían escrito, firmado por el propio Esteve, reconociendo los hecho y con el acuerdo de devolver el dinero y no disponer de extras en agosto y septiembre. ············ Si vuelve a ocurrir un hecho similar, desde el propio CRR acudirán a denunciar. ············ Guardo el documento en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2023-08-14','Ana: Envío escaeado al CAMP, CONSENTIMIENTO INFORMADO para procedimiento con anestesia, firmado y sellado por la nueva Vicepresidenta de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-08-14','Ana: Tras recibir correo de Laura, TS ONCE, le envío correo a Alberto, Jefe Secc. Ecca.: "Te reenvío correo de la compañera de la ONCE. Como bien dice ella, finalmente no se ha autorizado el viaje a CUNTIS (PONTEVEDRA), pues hasta que Lourdes volvería no revisaría si finalmente se ha dado de bajas los recibos de telefonía (está pendiente también el catering privado) Por otra parte, lo que sí considero a nivel técnico que hay que aprobar, es el viaje de Navidad, tal y como ya se hizo el año pasado. Entiendo que es muy beneficioso y necesario para él. En el documento adjunto está TODA LA INFORMACIÓN relativa a dicho viaje."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-08-14','Ana: Cristina, Psicóloga CRR (crr@grupociudadjardin.com): remite por mail PLAN DE TRABAJO EN EL PROCESO DE RECUPERACIÓN de Juan José, firmado por éste, Cristina, TO y la Directora Técnica. ············ Establecen los compromisos y cuestiones a abordar en los próximos meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-08-14','Ana: Llamo varias veces al Catering Sol (Información: 927 27 82 36 // Tienda: 927 03 32 31), sin obtener respuesta. Por lo que finalmente remito un correo (info@solcatering.es): "Me pongo en contacto con ustedes en relación a una solicitud del servicio de catering para JUAN JOSÉ GLEZ. CARRERO, cuyo cargo ostenta la COMISIÓN TUTELAR DE ADULTOS de Extremadura. Desde el programa de apoyo comunitario acudieron a su empresa para pedir información para valorar la posibilidad de contratar el servicio. Adjunto documento facilitado desde el mismo con la información. Desde la sección económica se aprueba este “presupuesto” y se acepta la contratación del catering. Pero, desafortunadamente este programa que indico, quedará en suspenso durante al menos un par de meses y no contamos con el apoyo de la educadora para terminar de formalizar la contratación. Agradecería que me indiquen qué necesitan para formalizar la contratación del servicio para poder comenzar lo antes posible."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='CAMPOS'and apellido2='GALAN'),'2023-08-14','Ana: llamada del CSS, hablo con Cristina, TS que cubre a Estrella, y con el Dr. Eduardo Cubero, Médico Somático UME (39436), me indican que Andrés está en urgencias del Hptal. Virgen del Puerto, le han trasladado esta mañana con una infección. Está grave. ········ Me indican que llame al Cirujano de Guardia. ······················ Hablo con éste, me informa que llegó con una Información Perineal y una GANGRENA muy grave. Presenta Shock Séptico. Teniendo en cuenta el estado y características del paciente, no se puede revertir la situación pues no está indicada la cirugía. *No cree que dure muchas horas. ················· Considera que lo mejor es que regrese al CSS y que pase en "su casa" las últims horas que le quedan. ······ Estoy de acuerdo. ························ *Puesto que no tiene seguro de decesos, pero sí saldo en cuenta más que suficiente para el sepelio, con el Dr. Cuberos, CSS, acuerdo que se trabajará con la Funeraria San Lázaro, que es la que suelen contratar en estos casos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-08-16','Ana: Correo de ayer de Leyre, TS de la Res. (t.socialcanovas@grupociudadjardin.com): "Os comunico que me han llamado desde la Residencia, que ha fallecido esta madrugada Josefa Sánchez Diaz, se le ha derivado al Tanatorio del San Pedro de Alcántara, y la quedaran en la cámara a la espera de que ustedes nos digan mañana como proceder. Se le entrega al Tanatorio toda la documentación de ella COPIA EL DNI,TARJETA SANITARIA, Nº NICHO. Les agradezco que se ponga en contacto con nosotras por la mañana." ······················ Gracias por comunicar la triste noticia. Descanse en paz. Dado que Josefa no tenía seguro de decesos, pero sí cuenta con saldo suficiente, pueden contratar en una funeraria un sepelio digno. Después, desde la propia funeraria, o a través vuestra, remitís a esta misma dirección de correo la factura con número de cuenta, para abonarla mediante transferencia. Si os facilitasen Certificado de Defunción, agradeceríamos que también nos lo hicierais llegar, pues la relación de la CTAEx con la persona a cargo finaliza con la defunción, pero sí que realiza los pagos pendientes justificados y la rendición final de cuentas al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2023-08-16','Ana: EXITUS. ·········· Comunican desde la residencia el fallecimiento acaecido esta misma madrugada. ················ Puesto que no haber Cementerio en su localidad de origen, que es una pedanía de Coria, se enterrará en Coria. ····························· Entregarán los objetos personales (no son de gran valor) a su hermano. No constan más familiares. ·············· Quedan pendientes los gastos de farmacia y el abono del mes que cargarán en cuenta como habitualmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-08-16','miguel, envío de nuevo email a Fiscalía de Badajoz: Buenos días, el día 14 del pasado mes de Julio se comunicó por esta vía a esta fiscalía la solicitud de urgente intervención de esta, debido a que una persona tutelada por la Comisión Tutelar de Adultos había abandonado el centro. Se le ha concedido el traslado a otro centro en Olivenza ante las denuncias por las amenazas y agresión sufridas por trabajadoras, y otros usuarios. Dichas personas como pueden ver en la documentación que se adjuntó y en el email remitido por la trabajadora social de la Comisión Tutelar, Amalia, que figura debajo, podrán comprobar la alarma social que está provocando el echo que deambulan por Badajoz en silla de ruedas, negándose ir al nuevo centro en Olivenza, y donde la policía local no puede intervenir sin orden judicial. Estas incidencias fueron comunicadas por la Comisión Tutelar vía email a esta fiscalía, sin haber obtenido respuesta alguna. También les adjunto resguardo remitido vía Lexnet al juzgado que le corresponde, el Juzgado de 1º instancia e instrucción nº4 de Badajoz, sin que hasta la fecha tampoco hayan contestado nada al respecto. Aunque van en silla de ruedas la tutelada Joaquina Salguero Capote y su pareja, tienen actitudes agresivas. Desde el Centro residencial la Granadilla y desde la Comisión Tutelar de Adultos no se pueden establecer las medidas de apoyo que la Ley 8/21 exige y ante la imposibilidad de actuar de los cuerpos de seguridad del estado sin orden judicial, les rogamos actúen con la diligencia necesaria para que sean trasladados al centro residencial de Olivenza, Nuestra Señora de Guadalupe sito en Avda Villarreal 0. ------------------------------------------------------------ Recibo email de Amalia del 11-8-23: Buenas , os informo de la situación actual de este caso . Como sabéis el 14 de julio , Miguel reenvió a la Fiscalía y al Jgdo. nº 4 de Badajoz solicitud de internamiento involuntario para esta señora , con el objetivo de que ingrese en la plaza que tiene asignada en la R.M. de Olivenza . Esa misma semana , ella y su pareja , abandonaron el C. R . La Granadilla en Badajoz del que tenían expediente de expulsión. Se informó de toda la situación y se solicitaba la orden de ingreso involuntario de caracter urgente indicando que se les había visto por la zona del parque Castelar en Badajoz. Acabo de hablar con Inmaculada Merino , TS del SSASB de Badajoz . Están muy preocupados por la situación. Me asegura que están dia y noche en el parque de San Fco. Desayunan por la plaza de la Soledad y van a comer al comedor social . La policia local ya los ha localizado pero les dicen que sin la Orden Judicial no pueden hacer nada . La prensa ya está detrás también , ya están averiguando sobre el caso. Por favor Ángel , no puedes preguntar en Fiscalía /juzgado si ya está esa Orden ?? En cuanto se la pasen a la policia la podrían trasladar . Son días de mucho calor y no pueden estar en esas condiciones , aunque haya sido una decisión voluntaria. Un saludo ---------------------------------------------------- email de Maite: Buenas, Bienvenido. Amalia no está esta semana y yo tampoco. Por fa llama para ver que pasa con esto. Angel lo ha hecho y dicen que no tienen nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2023-08-16','Ana: Se le ha autorizado un extra de 150€, que retirará hoy mismo, para poder ir de vacaciones a su pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='CAMPOS'and apellido2='GALAN'),'2023-08-16','Ana: Llamada de Adela, Admisión del CSS. Comunica que Andrés falleció el día de ayer, a las 23 h. en el propio CSS. ················ Desde la funeraria piden se firme la AUTORIZACIÓN para la INCINERACIÓN. Me la remitirá por mail para que pueda recabar la firma de la Vicepresidenta de la CTAEx. ···································· Envío correo a Adela Rueda, Aux. Adtvo. CSS Plas (adela.rueda@salud-juntaex.es) con la solicitud/Autorización de INCINERACIÓN y resto de documentación pertinente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-08-16','miguel, tras el envío de mi email llamo a fiscalía donde no saben nada y me dicen le envíe el email a Antonio Luengo, también me dicen que hable con el jzdo de 1º instancia nº4 Badajoz, donde me dicen que al ser un escrito dirigido a fiscalía unicamente enviaron a fiscalía oficio el 19-7-23 ---------------------------------------------------------- email que envío a antonio.luengo@fiscal.es: Buenos días Don Antonio, nos comunican desde fiscalía le remitamos estos emails de solicitud de intervención urgente de fiscalía. Se comunicó vía email el 14-7-23 a esta fiscalía (tlfno 924-284244) y al juzgado nº4 de Badajoz que le corresponde vía Lexnet que también le adjunto. He llamado al juzgado de 1º instancia e instrucción de Badajoz nº4 (924-284254) y me confirman que al ser un escrito dirigido a fiscalía ellos lo único que hicieron fue remitir a fiscalía el 19-7-23 oficio de comunicación a esta fiscalía. Por tanto rogamos la actuación de esta fiscalía con la premura mayor posible. Quedamos a su disposición para aclarar cualquier duda. ------------------------------------------------------- Envío email a Maite, Amalia y Angel: Hola compañeros, tras hablar con fiscalía y ésta no saber nada y remitirme al email de Antonio Luengo que esta de vacaciones, he enviado email y documentación adjunta a éste, que ya la verá en septiembre. Desde el jzdo 1º instancia nº4 Badajoz tampoco han hecho más que comunicarlo a fiscalía. Os adjunto email enviado en su día a fiscalía, el email que les envío esta mañana añadiendo el email de Amalia y por último el email enviado a Antonio Luengo. En conclusión, que hasta septiembre no creo que esto se ponga en marcha, más no podemos hacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-08-16','miguel, me llama Damian y me deja claro que para vender tenemos que asegurarle que podrá comprar posteriormente en Mérida. Envío email a Amalia y comentaré mañana de palabra a Alberto: Buenos días, me ha llamado Damian preguntándome los trámites para la venta del piso. Le he explicado que su abogada de Málaga nos indica que elijamos uno en Mérida por si tuviese alguna preferencia, me ha dicho que no que lo elijamos nosotros, que él quiere al menos 150.000€ y que quería darte a ti el tlfno de Tecnocasa la inmobiliaria que quiere que se la venda. Con la prima dice no tener buena relación y que le pide además del pago de la cerradura que ya dio el visto bueno la parte económica, un viaje creo que a Plasencia…ya le he dicho que lo pida por los cauces que le indicastes. Me comenta que la condición para vender el piso es que después pueda comprarse uno en Mérida, que te lo trasmita. Ya le he dicho que tendrá que reflejarlo en un papel. Dice que no puede utilizar los canales habituales por que el director está de vacaciones y tardará en darle cita. Por tanto hay que evitar tramitar la venta si no le podemos garantizar la compra de vivienda en Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-08-16','Ana: Correo de la farmacia al ctutelar@ (farmaciamromano@hotmail.com): "Les adjunto un informe medico de José Manuel en el que se le prescribe Movicol y Almax en sobres. Quedamos a la espera de su aprobación por vuestra parte." ··················· Mi respuesta: "Como ya se indicara en su día, al ser medicamentos con prescripción médica, se autoriza la compra de los mismos por JOSÉ MANUEL ROMERO MEDIAVILLA. El abono se efectuará como se viene haciendo habitualmente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-08-16','Ana: Envío a registro (oac.merida.san@juntaex.es): "Adjunto la siguiente documentación relativa a D. JOSÉ BLAS CAÑA LOZANO, para registrar UNIDAD DE GESTIÓN DE VALORACIÓN DE DEPENDENCIA DE LOS SERVICIOS CENTRALES DEL SEPAD: - Solicitud Revisión PIA - Decreto Nombramiento de la Directora Gerente del SEPAD - Resolución de Delegación de Competencias y Firma - DNI de la Directora Gerente del SEPAD"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2023-08-17','Ana: Recibo comunicación de error detectado en el procedimiento de gestión de la PNC. Guardo en el expte. digital y envío correo a Alberto, Jefe secc. ecca: "Remito Comunicación del PNC relativa a ALFONSO CÁMARA MORENO, sólo para vuestro conocimiento y, si lo consideráis, aclaración en su ficha eco. Proceden a abonarle 969,22€ en concepto de atrasos por error en la gestión, junto con la nómina de agosto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2023-08-17','Ana: En relación a las llamadas de Yolanda Camarero, Aux. del CAMF (652 07 67 60) ofreciendo acompañamiento para el viaje del IMSERSO de septiembre, llamo a Felisa Custodio, TS CAMF (927 38 41 25): me informa que esta Aux. es muy conflictiva y manipuadora con los residentes. Quiere sacar unos ingresos extras. ·········· Además el acompañamiento ya se ha gestionado con ADIEX, empresa de CC con Cuidadores Profesionales. Se aprobó el presupuesto desde la Secc. Ecca. ···················· Llamo a Yolanda, Aux. y explico que ya hay un contrato con una empresa y aunque se agracece el interés, no es posible su propuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2023-08-17','Ana: En relación a las llamadas de Yolanda Camarero, Aux. del CAMF (652 07 67 60) ofreciendo acompañamiento para el viaje del IMSERSO de septiembre, llamo a Felisa Custodio, TS CAMF (927 38 41 25): me informa que esta Aux. es muy conflictiva y manipuadora con los residentes. Quiere sacar unos ingresos extras. ·········· Además el acompañamiento ya se ha gestionado con ADIEX, empresa de CC con Cuidadores Profesionales. Se aprobó el presupuesto desde la Secc. Ecca. ···················· Llamo a Yolanda, Aux. y explico que ya hay un contrato con una empresa y aunque se agracece el interés, no es posible su propuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-08-16','Ana: Llamada de Ana Benavente, TS ESM-Plas: Javier está con ella en el despacho. Hablo con ambos. Él manifiesta que está viviendo en un piso compartido que él mismo ha gestionado en la C/ Pedro Sánchez de Grimaldo, nº 6, 3º F - Plas. ·········· Dice abonar por la habitación 150€/mes. ·········· Ha cambiado de número de teléfono (Javier: 744 72 98 74). ········· Está acudiendo a comer al comedor social de Cáritas. ·· Le explico que dado sus ingresos (3 pensiones) él no tiene esta necesidad, el comedor social es para quien no tiene recursos y él podría permitirse abonar un catering privado. *Acepta que busquemos y contratemos uno. ··················· Por otra parte, narra una preocupación: "un gitano le ha quitado una factura del buzón de su casa del pueblo y con sus datos ha dado de alta un contrato de Luz de Iberdrola a su nombre en la C/ Velázquez de Miajadas. Y le están pasando a él las facturas" ············ *Pediré a las secc. ecca. que verifique el cobro de las facturas que menciona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-08-17','Ana: Envío correo a Alberto, jefe secc. ecca. y a Miguel, A. Jurídico, informando de la conversación mantenida ayer con Javier y añado: "...Alberto: 1. Por favor, ¿podéis comprobar si realmente le están cargando en cuenta facturas de Luz de esa dirección? Sinceramente, no me extrañaría que fuera fruto de uno de sus delirios, pero tampoco descarto nada. En caso de que sea cierto lo que dice, habrá que devolver recibos y solicitar baja/cancelación o lo que consideréis, de dicho contrato. No sé si en este caso los Jurídicos tendrán que hacer algo al respecto (denuncia por suplantación de identidad, contratación ilegal, o no sé qué). 2. Está retirando 500€/mes, si no me equivoco. Con eso abona el alquiler y resto de gastos, pero voy a pedir presupuesto de cáterin que ya os facilitaré. Él puede permitírselo. 3. Con el cambio de localidades (se fue, de nuevo sin previo aviso, a Cáceres, su pueblo, Navalmoral de la Mata y después a Plasencia) se ha gastado el dinero. ¿Sería posible autorizarle un extra de 100€ para lo que queda de mes? Por favor, confirmarle si a él mismo si se le autoriza y cuándo puede ir a retirarlo. Miguel: a parte delo subrayado en azul, ahí tiene su nueva dirección. Voy a pedir informes tanto a C. Vida – Cáritas de Cáceres, como al Equipo de Salud Mental y, en cuanto podamos si quieres redactamos el escrito para responder al requerimiento del Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2023-08-17','Ana: llamada de Esther, TS de la Mancomunidad de Riberos del Tajo (927 45 00 36), su compañera Tensi-TS es la que lleva el caso, pero está de vacaciones (Mancomunidad: 927 300 400): Isidro, residente en los PP.TT. de Casas de Millán, con Grado II de Dependencia, presenta ESQUIZOFRENIA, lleva una temporada muy alterado y agresivo. Ha protagonizado ya incluso agresiones a profesinales del recurso, por lo que han denunciado ante la Guardia Civil. ··· Temen que pueda agredir también a residentes. ···· Este año ha ingresado al menos 2 veces en la UHB, no sabe las fechas. Han sido ingresos breves, le han estabilizado y dado el alta. ···· No saben qué más hacer, ni si podemos agilizar el ingreso en otro centro (está en listas de espera). ········· Le indico que las personas a cargo de la CTAEx no tiene prioridad en los ingresos. Y dado las alteraciones de conducta y posible descompensación psicopatológica, no van a autorizar el ingreso en C. Mayores. ············· *Ambas coincidimos en que lo más recomendable sería ingreso en UME antes de ingresar en C. Mayores. ············ Recomiendo que no duden en activar el 112 ante cualquier alteración/agresión y que vuelvan a poner denuncias cada vez que sea necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-08-17','Ana: Envío correo a Alberto, Jefe Secc. Ecca: "En relación a CONCEPCION FERNÁNDEZ MUÑOZ, he recibido llamada de Maribel Fdez. Muñoz, una de sus hermanas residentes en Trujillo (682 733 187). Acuden a visitarla periódicamente cada 15/20 días desde hace 10 años al CRR, actualmente al CSS pues está allí ingresada temporalmente. Expresan que les supone mucho gasto tener que abonar la gasolina cada vez que van a verla y solicitan, si es posible, que Conchi les ayude con unos 20-30 €/mes para sostener este gasto, pues su situación económica actual no es buena. No sé qué posibilidades económicas tiene “Conchi”, ya me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-08-17','Ana: Llamada de Sergio (640 654 897): dice "me han dicho que no estáis haciendo el ingreso de la pensión al centro", no me especifica quien. Le digo que si realmente hay algún problema con la transferencia para abonar el centro así como con su asignación, Julia, Coordinadora, se pondrían en contacto con nosotros. ···································· María, compañera de la secc. ecca., comprueba que la transferencia al centro está OK.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-08-17','miguel, contestación a Ana y Alberto: Buenos días, perfecto Ana cuando tengas los tres informes del Centro Vida, de Cáritas Cáceres y del equipo de salud mental, al que unamos si la parte económica encuentra recibos no contratados, y con ello preparamos un escrito con las incidencias (con una relación de fechas y hechos) para remitir la correspondiente comunicación al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-08-17','Ana: Llamo al CENTRO ODONTOLOGICO AVANZADO MONREAL & ROMAN (927 42 74 10): hablo con Natalia, me dice que quién habló con Estrella, secc. ecca., es el Director, César, que está de vacaciones y se incorpora el lunes 21. ······ No les importa llegar a un acuerdo para fraccionar el abono del tratamiento. ········ Le facilito el nº de Estrella y la dirección de correo: ctutelar@ ············· César se pondrá en contacto a mediados de la semana que viene. ··························································································································································································································································· Ana: Llamo a Mª Antonia (927 095 795): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-08-17','Ana: Correo de Paula, TO del CRR-Plas (tocupacional.crrplasencia@grupo5.net): "en relación a Isabel Cano y Ceferino. Ambos han hablado con mi compañera de su deseo de hacer una salida de una noche a un hostal. Como era algo pendiente, lo han planificado para este fin de semana y a nosotras nos parece que pueden realizarla. Si por vuestra parte no hay problema, se pasarán la noche de mañana viernes día 18 de agosto al sábado 19 fuera." ····································· Mi respuesta: "De acuerdo. Por parte de la sección social del Gabinete Técnico de la CTAEx, no hay inconveniente en que pasen una noche juntos en un hostal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-08-17','Ana: Correo de Paula, TO del CRR-Plas (tocupacional.crrplasencia@grupo5.net): "en relación a Isabel Cano y Ceferino. Ambos han hablado con mi compañera de su deseo de hacer una salida de una noche a un hostal. Como era algo pendiente, lo han planificado para este fin de semana y a nosotras nos parece que pueden realizarla. Si por vuestra parte no hay problema, se pasarán la noche de mañana viernes día 18 de agosto al sábado 19 fuera." ····································· Mi respuesta: "De acuerdo. Por parte de la sección social del Gabinete Técnico de la CTAEx, no hay inconveniente en que pasen una noche juntos en un hostal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2023-08-18','Ana: correo de Sonia, TS/Directora Asindi: "ya tenemos presupuesto para la visita de Ignacio e Isabel Rodriguez Alcántara a su hermano, que es con el que mantienen más contacto. El coste es de 161,12 €, cada viaje, es decir, el total de la ida a Plasencia y el regreso a Alcántara es de 322,24 €. Estoy llamando a Estrella para saber si se autoriza el pago entre los dos hermanos, pero no sé si está porque no me coge el teléfono. La idea es que fueran el domingo 27 a Plasencia. Ese día es el que puede el hermano. ¿Puedes hacer la consulta para saber si autorizan el viaje y luego les pasamos la factura?" ················ Lo envío a Alberto, jefe secc. ecca. ··················· Alberto lo autoriza. Lourdes se encargará de la getión ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2023-08-18','Ana: correo de Sonia, TS/Directora Asindi: "ya tenemos presupuesto para la visita de Ignacio e Isabel Rodriguez Alcántara a su hermano, que es con el que mantienen más contacto. El coste es de 161,12 €, cada viaje, es decir, el total de la ida a Plasencia y el regreso a Alcántara es de 322,24 €. Estoy llamando a Estrella para saber si se autoriza el pago entre los dos hermanos, pero no sé si está porque no me coge el teléfono. La idea es que fueran el domingo 27 a Plasencia. Ese día es el que puede el hermano. ¿Puedes hacer la consulta para saber si autorizan el viaje y luego les pasamos la factura?" ················ Lo envío a Alberto, jefe secc. ecca. ··················· Alberto lo autoriza. Lourdes se encargará de la getión ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2023-08-18','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "la persona usuaria Antonia Canelada del Río mantiene desde hace meses la petición que se adjunta, siendo esta cada vez mas sólida y sostenida en el tiempo, no respondiendo a fluctuaciones de su estado clínico." *Solicita Solicitud de Plaza y traslado a C. Mayores próximo a su zona de procedencia, Comarca de Las Villuercas. ····································· Mi respuesta: "Gracias por comunicárnoslo. Antonia tiene reconocido Grado I de Dependencia, por lo que no podría acceder a Centros de Mayores por esta vía. ¿Consideráis que en una revisión podría dar más grado? Si es así podríamos solicitar revisión por empeoramiento. Si no, habría que hacer la solicitud por la Vía del Decreto 88/1996, las antiguas solicitudes de acceso a centro que siguen vigentes para aquellas personas que no alcanzan grado II de dependencia. En función de lo que me digáis comenzamos los trámites de solicitud por una u otra vía y os solicitaré que la acompañéis al médico de atención primaria para solicitar el Informe de Salud correspondiente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2023-08-18','Ana: A las 8:05 acude Ramón al SEPAD. Solicita 50 € para "visitar a su madre, recargar el teléfono, champú y otra cosas personales". ··············· Alberto, Jefe Secc. Ecca. autoriza el extra. Retirará el efectivo hoy mismo en la oficina bancaria de Mérida (Pza. España).','2');
