insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-08-18','Ana: Envío a registro (oac.merida.san@juntaex.es): "En representación de MIGUEL ÁNGEL RAMOS ANDRÉS, cuyo cargo de CURATELA REPRESENTATIVA ostenta la Comisión Tutelar de Adultos de Extremadura, adjunto: - Solicitud de Prestación Familiar por Hijo a Cargo - DNI escaneado del interesado - Decreto Nombramiento de la Directora Gerente del SEPAD - Resolución de Delegación de Competencias y Firma - DNI de la Directora Gerente del SEPAD (Vicepresidenta de la CTAEx) Para remitir por registro a la DIRECCIÓN PROVINCIAL DEL INSS de Cáceres Avda. de España, 14 10001 – Cáceres"','2');
