insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-08-18','Ana: Llamo al C. Penitenciario de Ba (924 28 91 17): hablo con Beatriz, TS. Alberto ingresó el día 16. Está en el Módulo Terapéutico (Modulo 3). La compañera de este módulo estás de vacaciones hasta el día 4/09. ··········· Beatriz expresa que allí "cuanto menos dinero tengan mejor". El máximo que pueden retirar de la cuenta peculio son 100€/semana. No obstante, tanto a ella como a mí nos parece mucho. Necesitará para costear las llamadas, tabaco, café y alguna cosa que pueda necesitar del economato. ······ Si más adelante necesitara ropa o alguna cosa del demandadero, nos lo podrían comunicar para solicitar un extra. ······················· Consideramos que 60€/semana estaría bien. ·········· Para que no pueda retirar más de esta cuantía a la semana habría que ponerse en contacto con la Subdirectora de Tratamiento del centro, que ahora está de vacaciones, cree que se incorpora la semana que viene. Llamaré el lunes. ····················· Envío correo a Alberto, Secc. Ecca. y Amalia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-08-17','Ana: Correo de Juan Ramos, padre de Alberto (ramosnj_56@hotmail.com) al ctutelar@: "Les comunico que mi hijo Alberto Ramos Blanco ha ingresado en la penitenciaria de Badajoz, por lo cual, las transferencias que se estaban haciendose a su cuenta de Ibercaja, deben anularlas, puesto que él no podrá ir a recogerlas. Esto debieran hacerlo lo antes posible. Por otra parte deben cambiarlas a la siguiente direccion: PENITENCIARIA DE BADAJOZ BS-PECULIO(ES23-0049-0373-6729-1079-0309 concepto N.I.S. 2023011587 ORDENANTE : Conserjeria de Sanidad y Asuntos Sociales de la junta de Extremadura (departemento economico). En otro orden de cosas, quiero indicarles que llevo solicitando,desde hace mucho tiempo, una cita, bien con el Sr. Oscar Gonzalez o , en el caso que siguiera dado de baja, la cita fuera con el Sr. Alberto Martín. Nadie contesta al respecto. Tenemos pendiente la solución al problema del adelanto de una cantidad de dinero a mi hijo. Ya aclaré que tuve la autorización de Oscar Gonzalez y fuerton entregadas, por registro, todas las facturas correspondientes a los gastos efectuados. Les solicito que de este email tenga conocimiento tanto Oscar Gonzalez, Alberto Martin y Amalia Diaz"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-18','Ana: Correo de de Puerto, TS SSASB (ssb5@mancomunidadvalledelalagon.es): "Buenos días: te comunico que el Ayuntamiento me acaba de decir que a partir de mañana se finaliza el servicio de comida y cena con Enrique Santos García-Puente. Es decir, hoy recibirá la comida y la cena, pero mañana no...." ······················· Mi respuesta: "gracias por comunicárnoslo, La verdad es que podían haber avisado con un poco más de margen desde el ayuntamiento. Ya lo he hablado con la Sección Económica, van a intentar que el lunes ya pueda retirar los 145€/semanales que aprobó el Jefe de dicha sección. Iremos viendo cómo los resultados. De momento seguimos sin tener otra alternativa." ················································· Llamo a Enrique (662 56 78 32) varias veces. Finalmente dejo mensaje en el buzón de voz indicándole la subida de asignación a partir del próximo lunes. ································································································································································································ Correo-respuesta de Puerto, TS: "De momento sigue sin SAD, las auxiliares se incorporan el día 22 agosto al domicilio de ENRIQUE, son dos horas semanales... intentad que active el SAD por dependencia para poder tener una hora todos los días ya que ahora necesita apoyo para realización de comidas además de las demás ABVD. Saludos, P.D. Según me informa el Alcalde se le ha dado comida y cena para todo el fin de semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2023-08-18','Ana: Correo de Pilar, Directora del Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "nos ponemos en contacto con ustedes para informarles que este año realizaremos la actividad "Vacaciones en la Playa" los días 13 al 23 de Septiembre. El coste de la actividad, este año, asciende a 700,00 €, cantidad que deben abonar en la Cuenta del Hogar San Vicente donde, normalmente, realizan el ingreso mensual de la estancia en nuestro centro de Mª del Carmen." ····················· Ya se lo han pasado a Alberto, jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-08-18','Ana: Hablo con Amadora Pérez, Gerente del Cáterin Sol (927 278 236) ····································· Llamo a Juan José (643 641 375): le informo que el martes a partir de media mañana (sobre 12:30 h) comienzan el reparto de la comida para toda la semana. Va termosellada para que se conserve bien en la nevera. ·························· Envío correo a Amadora - Catering (amadora@solcatering.es): "Tal y como hemos acordado mediante conversación telefónica, te anoto los siguientes datos para formalizar el servicio de cáterin a partir del martes de la semana que viene y para la facturación: Usuario del servicio de catering: JUAN JOSÉ GONZÁLEZ CARRERO Domicilio: C/ CRISTU BENDITU DNI: 28948986J Teléfono: 643 641 375 Email para el envío de las facturas: ctutelar@salud-juntaex.es Comunicarte también que ya se lo he confirmado al propio Juan José, que el martes comenzaréis el reparto. Me pregunta si hay platos entre los que pueda elegir, como eso no he caído en preguntártelo, dice que el lunes os llamará él para que le expliquéis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-21','Ana: Correo-respuesta de Puerto, TS Valdeobispo: "yo sí pude hablar con él, de hecho tengo llamadas perdidas en el teléfono del trabajo a deshoras porque Enrique se queda con el número de teléfono y luego te llama por la tarde-noche... sin control... y el Ayuntamiento también le ha dado comida (no perecedera) y me comentaba que tenía la nevera llena."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-08-21','Ana: Envío correo a Daniel Rodríguez, propietario del piso de alquiler en que reside Jesús Manuel (danieltrans@hotmail.com / 659 682 474 ): "Comunicarte que hemos valorado, en el equipo social del Gabinete Técnico de la Comisión Tutelar de Adultos, la situación que nos planteas en tu correo anterior. Lamentablemente, lo único que podemos hacer desde aquí es hablar con él al respecto, pero eso no garantiza que vaya a hacernos caso ni a cambiar ciertas conductas ni hábitos. Esta misma mañana le llamaré. Aclarar así mismo, que la Resolución Judicial de nombramiento de la Comisión Tutelar, expresa en el fallo que el cargo se extiende "únicamente" a la administración de sus bienes y lo relacionado con su medicación, nada más. En principio se trata de un problema de convivencia y conductas inadecuadas en la comunidad de vecinos, por lo que, entendemos que os corresponde actuar como propietario y como como comunidad y, si fuera necesario, denunciar los hechos ante la policía. Por otra parte, iba a pedir a la Educadora del Programa de Apoyo Comunitario que le visita de vez en cuando para hacer seguimiento, que intensifique el mismo y aborde con él este tema en persona, pero por desgracias, el Programa en el que trabaja (conveniado con la Junta) no se va a renovar ahora, tal y como estaba previsto y, según nos dicen, hasta noviembre no volverá entrar en funcionamiento. Ante cualquier otra incidencia o cuestión, no dudes en volver a contactar." ································································································································································································· Llamo de Jesús Manuel (635 336 539): enseguida se pone dar voces y a soltar improperios, acusando a la CTAEx de no haberle cambiado de vivienda hace 8 años cuando dice haber enviado un listado de 300 viviendas más centricas y económicas que en la que vive. ·········· Cuando comienzo a trasladarle las quejas por parte de la comunidad de vecinos, se altera más aún, dice que "todo es mentira" y que le estoy molestando con esas acusaciones. Cuando continua dando más voces le advierto que como siga dando voces se va a terminar la convesación. Finalmente corto la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-08-04','Ana: Correo de Daniel Rodríguez, propietario del piso de alquiler en que reside Jesús Manuel (danieltrans@hotmail.com / 659 682 474) al ctutelar@: "Hola Iciar, qué tal? te escribo para exponerte la siguiente situación. En el bloque donde reside vuestro tutelado en C/ Nidos 15A en Cáceres se han vendido dos viviendas en los últimos meses. Los nuevos dueños y nosotros hemos acordado una junta a principios de Septiembre para nombrar nuevo presidente, abordar alguna mejora y solucionar algunos problemas. Hoy concretamente se han reparado las barandillas de las escaleras y la puerta del portal que se abría porque la forzaron hace un tiempo. Hemos creado un grupo de whatsapp para estar en contacto y estar más pendiente de todo lo que acaece en dicha comunidad. Los nuevos dueños son jóvenes y se preocupan e intentan que su bloque esté bien y no tener problemas como es de comprender. Ayer, en dicho grupo, me trasladaron una serie de quejas de Jesús, las cuáles trataremos en la reunión pero quieren obviamente que se vayan solucionando cuanto antes. Jesús siempre os llama para de algún modo quejarse de alguna deficiencia o necesidad y lo comparto perfectamente pero en esta situación me ha obligado a escribiros para reconducir todo y pediros si podéis mediar y entre todos podamos normalizar la convivencia en ese bloque. No sé en estos casos quien tiene la potestad u obligación de hacérselo saber y advertirle, vosotros como tutelado o nosotros como inquilino pero prefiero que lo tengáis en cuenta y de paso poder ayudarme en este caso. A lo mejor a nosotros, nos miente y no nos hace caso. Nosotros no tenemos problemas con él pero las quejas si nos afectan. Te adjunto tres pantallazos de la conversación de ayer en el mencionado grupo y lo que me escribieron." ············· Guardo en su expte. digital las capturas de pantalla de WhatsApp que nos remite Daniel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-08-21','Ana: Llamda de José Manuel muy alterado, ha acudido al banco y no le han querido dar los 100€ que ha pedido (no tenía autorización para ello ni le correspondía sacer hoy su asignación), ya le ha gastado todo lo que retiró hace una semana. Dice que se lo ha gastado "tontamente" en cigarrillos electrónicos "porque quería dejar de fumar con eso". Dice que está harto de la Tutela y que va a ir al Juzgado. Le facilito nº de Juzgado, de Procedimiento y de Sentencia. ······················ Hablo con Alberto, se le concede un extra de 50€ para que tenga algo de aquí hasta la próxima retirada (día 1). Se le hará transferencia al hermano para que se lo administre. ··············· Llamo a José Luis, hermano(687 581 061) y se lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2023-08-21','Ana: Llamada de Mª Eugenia (633 578 274), ha estado en casa de su madre, con la familia, unos días de vacaciones, pero quiere irse a vivir a un centro más cerca de su pueblo, Arroyo de la Luz, pues le echa mucho de menos. ············· Volverá a llamar en Septiembre para hablarlo con Teresa, TS de referencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-08-21','Ana: llamada de Javier (744 729 874): dice que el Gitano le robó 1500€ hace 3 años y que intentó poner la denuncia en la Guardia Civil, pero no quisieron poner nada por escrito... ············· Pregunta por el extra de 100€ que pidió. *Aún no tengo respuesta de Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-08-21','Ana: Llamo al C. Penitenciario de Ba (924 289 100), no me pasan con la Subdirectora de Tratamiento, pero me facilitan una dirección de correo para solicitar la limitación: GestionBadajoz@dgip.mir.es Envío el correo: "En relación al interno ALBERTO RAMOS BLANCO, con NIF: 2023011587, cuyo cargo de CURATELA ostenta la Comisión Tutelar de Adultos de Extremadura, solicitamos se limite la Tarjeta Monedero asociada a su Cuenta de Peculio a 60€ semanales, de modo que no pueda retirar mayor cuantía a la semana. Adjunto: - Testimonio de Incapacitación y nombramiento - Acuerdo de Aceptación del Cargo Ante cualquier cuestión, no duden en contactar. Pongo en copia a la Trabajadora Social de Referencia así como al Jefe de Sección Económica de la Comisión Tutelar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-08-21','miguel, solicito internamiento involuntario al jzdo Decano de Badajoz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2023-08-21','Ana: Envío correo a Sonia Bernabé, ASINDI: "Adjunto los siguientes documentos: - Ficha Solicitud Viaje IMSERSO – Justo Hernández Castaño - Ficha Solicitud viaje IMSERSO – Ignacio Rodríguez Alcántara - DNI – Nueva Directora Gerente del SEPAD - Decreto Nombramiento de la misma - Resolución de Delegación de Competencias y Firma Creo que mis compañeras de la sección económica ya han procedido a realizar el abono."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-08-21','Ana: Envío correo a Sonia Bernabé, ASINDI: "Adjunto los siguientes documentos: - Ficha Solicitud Viaje IMSERSO – Justo Hernández Castaño - Ficha Solicitud viaje IMSERSO – Ignacio Rodríguez Alcántara - DNI – Nueva Directora Gerente del SEPAD - Decreto Nombramiento de la misma - Resolución de Delegación de Competencias y Firma Creo que mis compañeras de la sección económica ya han procedido a realizar el abono."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-08-21','Ana: Llamada de Paula, TO - CRR: Este fin de semana un compañero ha acudido a llevarle a Flora una botella de agua a su habitación por la noche, como es habitual. Pero en esta ocasión el compañero comenzó a besarle sin su consentimiento e incluso hacer tocamientos. El compañero ha reconocido parte de los hechos. ················ A parte de la exploración Psicológica de Flora, también ha pedido valoración psiquiatrica del compañero, para descartar que estuviera descompensado. Como centro acudirá a denunciar los hechos. ······· Le paso a este respecto a Miguel, sobre la posibilidad de denuncia por parte de la propia Flora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-08-22','Ana: Amadora Pérez, Gerente de Sol Catering (amadora@solcatering.es) me remite factura de la semana del 23-29 agosto. Reenvío a ctutelar@ y contesto: "Muchas gracias. Reenvío la factura a mis compañeras de la sección económica para que procedan al abono en cuanto les sea posible. Agradecería que, a partir de ahora, las facturas las dirijas directamente a la dirección de correo-e que aparece en copia: ctutelar@salud-juntaex.es , a la atención de la Sección Económica. Ante cualquier cuestión, no dudes en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-08-22','Ana: llamo a Javier (744 729 874) para confirmarle que se le ha aprobado el extra de 100€ y que puede ir a retirarlo hoy mismo. Como no responde y salta el buzón de voz, le dejo un mensaje explicándoselo. ··········· Más tarde me devuelve la llamada y se lo explico. Irá mañana al banco, pues ya es tarde. *Le informo también de que no les etán pansando, al menos de momento ninguna factura de otra dirección que no sea la suya. En septiembre se volveré a comprobar. Se queda más tranquilo. ······································································································································································································ Envío correo a Pedro Garvi, Coord. Progr. Personas sin Hogar de Cáritas (pgarvi.cdcoriacaceres@caritas.es) solicitando Cerficado con fechas de estancias de Javier en Centro Vida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-08-22','Ana: Llamada de Francisco (641 569 490). Pregunta por el dinero de las pagas extras, su madre le ha dicho que se le están pasando a su hija y que le parece bien. Le indico que no está establecido como tal, pero sí se le ha dado en otras ocasiones para comprar los libros escolares y otras cuestioens.···················· Me informa de las próximas citas pendientes: El 22 sep tiene cita con la enfermera del ECA para control de consumo de sustancias, para verificar que continúa sin consumir. ······················· En el ESM tiene citas con el Psicólogo 28/08 y con Cristina, Psiquiatra: 26/09 La cita para el inyectable: 12/09. ··········· Tiene pendiente nueva cita con Pilar Martín, TS, pero hasta que ésta no vuelva de vacaciones no se la darán. ········· Quiere solicitar de nuevo ingreso en el PP.SS. de Almendralejo. Expresa enconrarse bien y estable. Quiere hacer las cosas mejor. ·········· También le gustaría poder ver a su hija, pero su prima de momento no lo permite. ······················· Le pronogo, que si hace las cosas bien y funciona en el Piso Supervisado, a no ser que haya informes que desaconsejen estas visitas para su hija (pues también hay que mirar por su bienestar) ni ninguna resolución judicial que lo impida y si ella quiere, intentaré ponerme en contacto con su prima e intentaré mediar para programar alguna visita. No descartamos la opción en punto de encuentro familiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2023-06-27','miguel, email de Oscar: pregunta cómo va el tema de la cancelación registral de Ibercaja, ante la pregunta de la compradora Ana María Muñoz Toro >anamariamt99@gmail.com> : Pongo email a Ibercaja con copia a atención al cliente de Ibercaja: Buenas tardes Maria Elena, seguimos pendientes desde hace más de 1 año, de que nos remitáis un modelo de provisión de fondos y autorización para la gestión de la cancelación de hipoteca de vuestra gestoría tal y como se habló y se quedó con Dolores (antigua Directora de la sucursal) Pongo en copia a atención al cliente como requisito previo a la reclamación ante el banco de España. Si no es posible la tramitación por vuestra parte, deberéis indicarnos cómo hemos de proceder para el levantamiento de la carga registral ya que económicamente quedó cancelada el préstamo hipotecario cuando se firmó. Adjunto nota simple, copia simple de la venta, datos del préstamo y el certificado de deuda pendiente en aquel momento. Esperamos contestación. ***************************************************** Reenvío email a la compradora Ana, anamariamt99@gmail.com y a Oscar: Buenos días Ana, adjunto email remitido a Ibercaja solicitando nos remitan el modelo de encargo y provisión de fondos para el levantamiento de la carga registral, solicitado en reiteradas ocasiones. Esta vez pongo en copia al servicio de atención al cliente de ibercaja como paso previo a la reclamación ante el Banco de España. Disculpe las molestias, la mantendremos informada y seguiremos insistiendo en dicho levantamiento','2');
